import { BrowserRouter, Routes, Route, useLocation } from 'react-router-dom';
import { Toaster } from '@/components/ui/sonner';
import { useAuth } from 'zite-auth-sdk';
import { useEffect, useState, useRef, Component, ErrorInfo, ReactNode } from 'react';
import { AppDataProvider } from '@/contexts/AppDataContext';
import { useAppData } from '@/contexts/AppDataContext';
import { toast } from 'sonner';
import Header from '@/components/Header';
import NewsTicker from '@/components/NewsTicker';
import PromoBanner from '@/components/PromoBanner';
import BottomNav from '@/components/BottomNav';
import ProfileSetupModal from '@/components/ProfileSetupModal';
import ChatPage from '@/pages/ChatPage';
import MediaLabPage from '@/pages/MediaLabPage';
import WalletPage from '@/pages/WalletPage';
import VIPPage from '@/pages/VIPPage';
import AdminPage from '@/pages/AdminPage';
import AIDashboardPage from '@/pages/AIDashboardPage';
import GeneralChatPage from '@/pages/GeneralChatPage';
import SpiritualPage from '@/pages/SpiritualPage';
import VideoCreatorPage from '@/pages/VideoCreatorPage';
import DailyTasksPage from '@/pages/DailyTasksPage';
import PullToRefresh from '@/components/PullToRefresh';
import MagicCalendarStrip from '@/components/MagicCalendarStrip';
import PrayerAlertOverlay from '@/components/PrayerAlertOverlay';
import FloatingSocialBar from '@/components/FloatingSocialBar';
import { setupUserProfile, checkDevice, linkDevice, checkUserStatus } from 'zite-endpoints-sdk';
import BlockedOverlay from '@/components/BlockedOverlay';
import {
  saveDeviceSession,
  loadDeviceSession,
  clearDeviceSession,
  hasDeviceCookie,
  getOrCreateDeviceId,
} from '@/lib/deviceSession';

// ══════════════════════════════════════════════════════════════════
// REFERRAL CAPTURE — fires at module load (before React mounts)
// Saves ?ref= code to localStorage so it survives auth redirects.
// ══════════════════════════════════════════════════════════════════
(function captureReferralCode() {
  try {
    const ref = new URLSearchParams(window.location.search).get('ref');
    if (ref && /^[a-zA-Z0-9_-]{3,12}$/.test(ref)) {
      localStorage.setItem('pending_ref_code', ref);
    }
  } catch { /* ignore */ }
})();

// ── Per-tab flag to prevent redirect loops ─────────────────────
const AUTO_LOGIN_FLAG = '_hai_al_tried';

// ── Global clean Urdu location resolver (no timezone codes ever) ──
import { resolveAndSetLocation } from '@/lib/urduLocation';
resolveAndSetLocation();

// ── Dynamic OG/Twitter meta tags ───────────────────────────────
function MetaTagsInjector() {
  const { aiName } = useAppData();
  useEffect(() => {
    const name = aiName || 'Hussain AI - Master Engine';
    const desc =
      'Hussain AI - Master Engine: Advanced AI tools & earning platform by Hussain Digital Studio. Powerful AI features with real earning opportunities.';
    const url = window.location.origin;
    const setMeta = (attr: string, val: string, content: string) => {
      const sel = `meta[${attr}="${val}"]`;
      let el = document.querySelector(sel) as HTMLMetaElement | null;
      if (!el) { el = document.createElement('meta'); el.setAttribute(attr, val); document.head.appendChild(el); }
      el.content = content;
    };
    document.title = name;
    // Set AI circuit-board favicon
    let link = document.querySelector('link[rel="icon"]') as HTMLLinkElement | null;
    if (!link) { link = document.createElement('link'); link.rel = 'icon'; document.head.appendChild(link); }
    link.href = 'data:image/svg+xml,<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 100 100"><rect rx="20" width="100" height="100" fill="%230ea5e9"/><path d="M50 20v60M20 50h60M30 30l40 40M70 30L30 70" stroke="white" stroke-width="4" stroke-linecap="round"/><circle cx="50" cy="50" r="10" fill="white"/><circle cx="30" cy="30" r="5" fill="white"/><circle cx="70" cy="30" r="5" fill="white"/><circle cx="30" cy="70" r="5" fill="white"/><circle cx="70" cy="70" r="5" fill="white"/><circle cx="50" cy="20" r="4" fill="white"/><circle cx="50" cy="80" r="4" fill="white"/><circle cx="20" cy="50" r="4" fill="white"/><circle cx="80" cy="50" r="4" fill="white"/></svg>';
    link.type = 'image/svg+xml';
    setMeta('name',     'description',      desc);
    setMeta('name',     'application-name', name);
    setMeta('property', 'og:type',          'website');
    setMeta('property', 'og:site_name',     name);
    setMeta('property', 'og:title',         name);
    setMeta('property', 'og:description',   desc);
    setMeta('property', 'og:url',           url);
    setMeta('name',     'twitter:card',     'summary');
    setMeta('name',     'twitter:title',    name);
    setMeta('name',     'twitter:description', desc);
  }, [aiName]);
  return null;
}

// ══════════════════════════════════════════════════════════════════
// DEVICE RECOGNITION BANNER
// Shows when the device fingerprint is registered but user is not
// currently logged in. Lets them tap to resume their session.
// ══════════════════════════════════════════════════════════════════
interface DeviceAccount { maskedEmail: string; name?: string }

function DeviceRecognitionBanner({
  account,
  onLogin,
  onDismiss,
}: {
  account: DeviceAccount;
  onLogin: () => void;
  onDismiss: () => void;
}) {
  return (
    <div className="fixed bottom-20 left-0 right-0 z-50 px-3 pointer-events-none">
      <div className="pointer-events-auto bg-card border border-primary/35 rounded-2xl p-3 flex items-center gap-3 shadow-2xl animate-in slide-in-from-bottom-4 duration-300">
        <div className="text-2xl shrink-0">🔒</div>
        <div className="flex-1 min-w-0">
          <p className="text-[11px] font-bold text-foreground leading-tight">
            Device Recognized
          </p>
          <p className="text-[9px] text-muted-foreground truncate mt-0.5">
            {account.name ? `${account.name} · ` : ''}{account.maskedEmail}
          </p>
        </div>
        <button
          onClick={onLogin}
          className="shrink-0 text-[10px] font-bold bg-primary text-primary-foreground px-3 py-1.5 rounded-lg hover:bg-primary/90 transition-colors"
        >
          Log In →
        </button>
        <button
          onClick={onDismiss}
          className="shrink-0 text-muted-foreground hover:text-foreground text-xs p-1"
        >
          ✕
        </button>
      </div>
    </div>
  );
}

// ══════════════════════════════════════════════════════════════════
// ADMIN SHELL
// ══════════════════════════════════════════════════════════════════
function AdminShell() {
  return (
    <div className="fixed inset-0 bg-background text-foreground flex flex-col overflow-hidden">
      <div className="flex-1 overflow-y-auto overscroll-contain">
        <AdminPage />
      </div>
      <Toaster richColors />
    </div>
  );
}

// ══════════════════════════════════════════════════════════════════
// MAIN APP CONTENT
// ══════════════════════════════════════════════════════════════════
function AppContent() {
  const { user, isLoading, loginWithRedirect } = useAuth();
  const { lcdColorPreset } = useAppData();
  const [showSetup, setShowSetup] = useState(false);
  const [deviceAccount, setDeviceAccount] = useState<DeviceAccount | null>(null);
  const [isBlocked, setIsBlocked] = useState(false);
  const referralProcessedRef = useRef(false);
  const deviceLinkedRef      = useRef(false);
  const deviceCheckedRef     = useRef(false);

  // ── 1. SAVE device session on every authenticated render ─────────
  useEffect(() => {
    if (!user) return;
    saveDeviceSession(
      user.id,
      user.email,
      user.firstName ?? (user as any).name ?? undefined,
    );
  }, [user]);

  // ── 2. LINK device to account after login (for server recognition)
  //    Runs once per session after user is confirmed authenticated.
  //    Silently links the hardware fingerprint → Users.deviceId in DB.
  useEffect(() => {
    if (!user || deviceLinkedRef.current) return;
    deviceLinkedRef.current = true;
    const deviceId = getOrCreateDeviceId();
    linkDevice({ deviceId })
      .then(result => {
        if (result.conflict) {
          // Device was registered to another account — warn the user
          toast.warning(
            '⚠️ This device is linked to a different account. Contact support if you need access.',
            { duration: 7000 }
          );
        }
      })
      .catch(() => { /* Silent fail — non-critical */ });
  }, [user]);

  // ── 3. AUTO-LOGIN: Restore session on return visits ──────────────
  //    Checks localStorage + cookie for a saved device session.
  //    Calls loginWithRedirect() — if the auth cookie is still valid,
  //    the user is re-authenticated instantly (zero steps).
  useEffect(() => {
    if (isLoading || user) return;
    const alreadyTried = sessionStorage.getItem(AUTO_LOGIN_FLAG);
    if (alreadyTried) return;

    const session = loadDeviceSession();
    const hasCookie = hasDeviceCookie();

    if (session || hasCookie) {
      sessionStorage.setItem(AUTO_LOGIN_FLAG, '1');
      // ── FIX: Use clean origin URL to avoid 404 on malformed redirects ──
      loginWithRedirect({ redirectUrl: window.location.origin + '/' });
    }
  }, [isLoading, user, loginWithRedirect]);

  // ── 4. DEVICE RECOGNITION: Check server for a known device ───────
  //    Fires when user is definitely NOT logged in.
  //    Looks up the hardware fingerprint in Users.deviceId via checkDevice.
  //    If found AND auto-login wasn't tried yet → auto-login immediately.
  //    If auto-login was already tried (session flag) → show banner as fallback.
  useEffect(() => {
    if (isLoading || user || deviceCheckedRef.current) return;
    deviceCheckedRef.current = true;
    const deviceId = getOrCreateDeviceId();
    checkDevice({ deviceId })
      .then(result => {
        if (result.registered && result.maskedEmail) {
          const alreadyTried = sessionStorage.getItem(AUTO_LOGIN_FLAG);
          if (!alreadyTried) {
            // Auto-login: device is known, try instant session restore
            sessionStorage.setItem(AUTO_LOGIN_FLAG, '1');
            loginWithRedirect({ redirectUrl: window.location.origin + '/' });
          } else {
            // Fallback: show banner if auto-login already attempted
            setDeviceAccount({
              maskedEmail: result.maskedEmail,
              name: result.name,
            });
          }
        }
      })
      .catch(() => { /* Silent fail */ });
  }, [isLoading, user, loginWithRedirect]);

  // ── 5. REAL-TIME BLOCK STATUS POLLING ──────────────────────────────
  //    Polls every 3 seconds to detect if admin blocked the user,
  //    or if auto-block triggered from wrong prompts.
  useEffect(() => {
    if (!user) return;
    // Check immediately on load
    if (user.status === 'Blocked') { setIsBlocked(true); return; }

    const poll = setInterval(() => {
      checkUserStatus({}).then(r => {
        if (r.blocked) setIsBlocked(true);
        else setIsBlocked(false);
      }).catch(() => { /* silent */ });
    }, 3000);
    return () => clearInterval(poll);
  }, [user]);

  // ── 6. PROFILE SETUP for new users (renumbered) ───────────────────────────────
  useEffect(() => {
    if (!isLoading && user && !user.referralCode) setShowSetup(true);
  }, [isLoading, user]);

  // ── 6. SILENT REFERRAL PROCESSING ────────────────────────────────
  //    Fires on first login for new users (no referralCode yet).
  //    Reads ?ref= code saved before auth redirect by IIFE.
  useEffect(() => {
    if (!user || user.referralCode) return;
    if (referralProcessedRef.current) return;

    const pendingRef = localStorage.getItem('pending_ref_code');
    if (!pendingRef) return;

    referralProcessedRef.current = true;

    setupUserProfile({
      referredByCode: pendingRef,
      deviceId: getOrCreateDeviceId(),
    })
      .then(result => {
        try { localStorage.removeItem('pending_ref_code'); } catch { /* ignore */ }
        if (result.coinsAwarded > 0) {
          toast.success(
            `🎁 Referral bonus activated! +${result.coinsAwarded} coins credited!`,
            { duration: 5000 }
          );
        }
      })
      .catch(err => {
        // If device conflict, show the error toast from the server
        if (err?.message?.includes('device')) {
          toast.error(err.message, { duration: 8000 });
        }
        referralProcessedRef.current = false;
      });
  }, [user]);

  const handleDeviceLogin = () => {
    setDeviceAccount(null);
    // ── FIX: Use clean origin URL — ref code already saved in localStorage ──
    loginWithRedirect({ redirectUrl: window.location.origin + '/' });
  };

  const bgStyle = lcdColorPreset ? { backgroundColor: lcdColorPreset } : undefined;

  return (
    <div
      className="fixed inset-0 text-foreground flex flex-col overflow-x-hidden overflow-y-hidden"
      style={{ ...(bgStyle ?? { background: 'var(--background)' }), width: '100vw', maxWidth: '100vw' }}
    >
      <MetaTagsInjector />

      {/* ── Fixed chrome ── */}
      <Header onLogout={clearDeviceSession} />
      <NewsTicker />
      <MagicCalendarStrip />
      <PrayerAlertOverlay />
      <PromoBanner />

      {/* ── Page area ── */}
      <PullToRefresh />
      <main className="flex-1 min-h-0 overflow-hidden flex flex-col">
        <Routes>
          <Route path="/"          element={<ChatPage />} />
          <Route path="/media"     element={<div className="flex-1 h-full overflow-y-auto overscroll-contain"><MediaLabPage /></div>} />
          <Route path="/wallet"    element={<div className="flex-1 h-full overflow-y-auto overscroll-contain pb-6"><WalletPage /></div>} />
          <Route path="/vip"       element={<div className="flex-1 h-full overflow-y-auto overscroll-contain pb-6"><VIPPage /></div>} />
          <Route path="/ai"        element={<div className="flex-1 h-full overflow-y-auto overscroll-contain pb-6"><AIDashboardPage /></div>} />
          <Route path="/ai/general" element={<div className="flex-1 h-full overflow-y-auto overscroll-contain pb-6"><GeneralChatPage /></div>} />
          <Route path="/ai/coding" element={<div className="flex-1 h-full overflow-y-auto overscroll-contain pb-6"><GeneralChatPage /></div>} />
          <Route path="/ai/tasks"  element={<div className="flex-1 h-full overflow-y-auto overscroll-contain pb-6"><DailyTasksPage /></div>} />
          <Route path="/ai/spiritual" element={<div className="flex-1 h-full overflow-y-auto overscroll-contain pb-6"><SpiritualPage /></div>} />
          <Route path="/ai/video"  element={<div className="flex-1 h-full overflow-y-auto overscroll-contain pb-6"><VideoCreatorPage /></div>} />
          {/* Catch-all: redirect unknown paths to home — prevents 404 errors */}
          <Route path="*" element={<ChatPage />} />
        </Routes>
      </main>

      <BottomNav />
      <FloatingSocialBar />

      {/* ── Footer Branding ── */}
      <div className="shrink-0 bg-card/50 border-t border-border/30 py-1 text-center">
        <p className="text-[8px] text-muted-foreground/60 leading-tight">
          Powered by <span className="font-semibold text-muted-foreground/80">Hussain Digital Studio</span> | Developed by Ghulam Hussain Pakistan Punjab
        </p>
      </div>

      {/* ── Blocked Overlay — unclosable, full-screen freeze ── */}
      {isBlocked && <BlockedOverlay />}

      {/* ── Modals & overlays ── */}
      {showSetup && !isBlocked && <ProfileSetupModal onClose={() => setShowSetup(false)} />}

      {/* ── Device Recognition Banner (shown when not logged in but device known) ── */}
      {deviceAccount && !user && !isLoading && (
        <DeviceRecognitionBanner
          account={deviceAccount}
          onLogin={handleDeviceLogin}
          onDismiss={() => setDeviceAccount(null)}
        />
      )}

      <Toaster richColors />
    </div>
  );
}

// ══════════════════════════════════════════════════════════════════
// ROUTER SWITCH
// ══════════════════════════════════════════════════════════════════
function RouterSwitch() {
  const location = useLocation();
  const isAdmin =
    location.pathname === '/admin' ||
    location.pathname.startsWith('/admin/') ||
    location.pathname === '/ghulam-admin-control' ||
    location.pathname.startsWith('/ghulam-admin-control/');

  if (isAdmin) return <AdminShell />;
  return <AppContent />;
}

// ══════════════════════════════════════════════════════════════════
// GLOBAL ERROR BOUNDARY — catches any unhandled React errors,
// prevents white-screen crashes, and shows a clean recovery UI.
// Deeply embedded: wraps the entire app tree so no future update
// can bypass it.
// ══════════════════════════════════════════════════════════════════
interface EBState { hasError: boolean; error?: Error }

class GlobalErrorBoundary extends Component<{ children: ReactNode }, EBState> {
  constructor(props: { children: ReactNode }) {
    super(props);
    this.state = { hasError: false };
  }

  static getDerivedStateFromError(error: Error): EBState {
    return { hasError: true, error };
  }

  componentDidCatch(error: Error, info: ErrorInfo) {
    // Silent log — never crashes the app
    try { console.error('[ErrorBoundary]', error.message, info.componentStack); } catch { /* */ }
  }

  handleRecover = () => {
    this.setState({ hasError: false, error: undefined });
  };

  handleReload = () => {
    window.location.href = window.location.origin + '/';
  };

  render() {
    if (this.state.hasError) {
      return (
        <div style={{
          position: 'fixed', inset: 0, display: 'flex', flexDirection: 'column',
          alignItems: 'center', justifyContent: 'center', padding: '24px',
          background: '#0a0a0a', color: '#e5e5e5', fontFamily: '-apple-system, BlinkMacSystemFont, sans-serif',
          zIndex: 99999,
        }}>
          <div style={{
            maxWidth: 380, width: '100%', textAlign: 'center',
            background: '#171717', border: '1px solid #2a2a2a', borderRadius: 20, padding: 32,
          }}>
            <div style={{ fontSize: 48, marginBottom: 16 }}>🛡️</div>
            <h2 style={{ fontSize: 18, fontWeight: 800, marginBottom: 8 }}>
              Something went wrong
            </h2>
            <p style={{ fontSize: 13, color: '#888', marginBottom: 20, lineHeight: 1.5 }}>
              The safety system caught an error before it could affect your experience. Your data is safe.
            </p>
            <div style={{ display: 'flex', gap: 10, justifyContent: 'center' }}>
              <button
                onClick={this.handleRecover}
                style={{
                  background: '#22c55e', color: '#fff', border: 'none', borderRadius: 10,
                  padding: '10px 20px', fontSize: 13, fontWeight: 700, cursor: 'pointer',
                }}
              >
                Try Again
              </button>
              <button
                onClick={this.handleReload}
                style={{
                  background: '#333', color: '#ccc', border: '1px solid #444', borderRadius: 10,
                  padding: '10px 20px', fontSize: 13, fontWeight: 700, cursor: 'pointer',
                }}
              >
                Reload App
              </button>
            </div>
            <p style={{ fontSize: 9, color: '#555', marginTop: 16 }}>
              Hussain AI — Anti-Crash Guardrails v2.0
            </p>
          </div>
        </div>
      );
    }
    return this.props.children;
  }
}

export default function App() {
  return (
    <GlobalErrorBoundary>
      <BrowserRouter>
        <AppDataProvider>
          <RouterSwitch />
        </AppDataProvider>
      </BrowserRouter>
    </GlobalErrorBoundary>
  );
}

