@import url('https://fonts.googleapis.com/css2?family=Noto+Nastaliq+Urdu:wght@400;500;600;700&display=swap');

@tailwind base;
@tailwind components;
@tailwind utilities;

:root {
  --header-height: 3.5rem;
  --bottom-nav-height: 4rem;
}

@layer base {
  :root {
    /* Auto-restored theme variables */
    --font-sans: 'Inter', 'Helvetica Neue', sans-serif;
    --font-mono: 'Courier New', monospace;
    --shadow-x: 0px;
    --shadow-y: 1px;
    --shadow-blur: 4px;
    --shadow-spread: 0px;
    --shadow-opacity: 0.2;
    --shadow-color: #000000;
    --shadow-2xs: var(--shadow-x) var(--shadow-y) color-mix(in srgb, var(--shadow-color) calc(var(--shadow-opacity) * 100%), transparent);
    --shadow-xs: var(--shadow-x) var(--shadow-y) var(--shadow-blur) var(--shadow-spread) color-mix(in srgb, var(--shadow-color) calc(var(--shadow-opacity) * 100%), transparent);
    --shadow-sm: var(--shadow-x) var(--shadow-y) calc(var(--shadow-blur) * 1.5) var(--shadow-spread) color-mix(in srgb, var(--shadow-color) calc(var(--shadow-opacity) * 100%), transparent);
    --shadow-md: calc(var(--shadow-x) * 2) calc(var(--shadow-y) * 2) calc(var(--shadow-blur) * 3) calc(var(--shadow-spread) - 1px) color-mix(in srgb, var(--shadow-color) calc(var(--shadow-opacity) * 100%), transparent);
    --shadow-lg: calc(var(--shadow-x) * 4) calc(var(--shadow-y) * 4) calc(var(--shadow-blur) * 5) calc(var(--shadow-spread) - 3px) color-mix(in srgb, var(--shadow-color) calc(var(--shadow-opacity) * 100%), transparent);
    --shadow-xl: calc(var(--shadow-x) * 6) calc(var(--shadow-y) * 6) calc(var(--shadow-blur) * 7) calc(var(--shadow-spread) - 5px) color-mix(in srgb, var(--shadow-color) calc(var(--shadow-opacity) * 100%), transparent);
    --shadow-2xl: calc(var(--shadow-x) * 8) calc(var(--shadow-y) * 8) calc(max(0px, var(--shadow-blur) * 9 - 8px)) calc(var(--shadow-spread) - 12px) color-mix(in srgb, var(--shadow-color) calc(var(--shadow-opacity) * 250%), transparent);
    --shadow: var(--shadow-md);

    --background: 224 50% 4%;
    --foreground: 40 20% 90%;
    --card: 224 45% 7%;
    --card-foreground: 40 20% 90%;
    --popover: 224 45% 8%;
    --popover-foreground: 40 20% 90%;
    --primary: 43 92% 52%;
    --primary-foreground: 224 50% 5%;
    --secondary: 271 55% 45%;
    --secondary-foreground: 0 0% 98%;
    --muted: 224 40% 11%;
    --muted-foreground: 224 15% 55%;
    --accent: 271 55% 45%;
    --accent-foreground: 0 0% 98%;
    --destructive: 0 70% 50%;
    --destructive-foreground: 0 0% 98%;
    --border: 224 40% 15%;
    --input: 224 40% 11%;
    --ring: 43 92% 52%;
    --radius: 0.75rem;
    --chart-1: 43 92% 52%;
    --chart-2: 271 55% 55%;
    --chart-3: 195 80% 50%;
    --chart-4: 142 60% 45%;
    --chart-5: 0 70% 55%;
    --sidebar-background: 224 50% 4%;
    --sidebar-foreground: 40 20% 90%;
    --sidebar-primary: 43 92% 52%;
    --sidebar-primary-foreground: 224 50% 5%;
    --sidebar-accent: 224 40% 11%;
    --sidebar-accent-foreground: 40 20% 90%;
    --sidebar-border: 224 40% 15%;
    --sidebar-ring: 43 92% 52%;
  }
}

@layer base {
  * { @apply border-border; }
  html, body {
    /* ── ABSOLUTE VIEWPORT LOCK (چاروں کونوں سے فکس) ──────────────
       Locks the entire app to exactly 100vw × 100vh — prevents any
       horizontal drift, overflow, or stretching on mobile screens.
       Works from all four corners (top/right/bottom/left) on Android
       Chrome, iOS Safari, and all modern mobile browsers.           */
    width: 100%;
    width: 100vw;
    max-width: 100vw;
    height: 100%;
    height: 100dvh;        /* dynamic viewport height: adjusts for mobile toolbar */
    overflow: hidden;
    overflow-x: hidden;
    overscroll-behavior: none;
    touch-action: pan-x pan-y;
    position: fixed;       /* prevents bounce/shift on virtual keyboard open */
    /* iOS safe-area insets (iPhone notch / Dynamic Island) */
    padding-top: env(safe-area-inset-top, 0px);
    padding-bottom: env(safe-area-inset-bottom, 0px);
  }
  body {
    @apply bg-background text-foreground;
    font-family: 'Inter', system-ui, -apple-system, sans-serif;
    /* Prevent iOS/Android font-size inflation */
    -webkit-text-size-adjust: 100%;
    text-size-adjust: 100%;
  }
}

/* ── Light Mode Theme Override ───────────────────────────────────────────── */
html.light {
  --background: 40 30% 97%;
  --foreground: 224 40% 8%;
  --card: 0 0% 100%;
  --card-foreground: 224 40% 8%;
  --popover: 0 0% 100%;
  --popover-foreground: 224 40% 8%;
  --primary: 38 85% 36%;
  --primary-foreground: 0 0% 100%;
  --secondary: 271 50% 42%;
  --secondary-foreground: 0 0% 100%;
  --muted: 220 18% 93%;
  --muted-foreground: 224 18% 40%;
  --accent: 271 50% 42%;
  --accent-foreground: 0 0% 100%;
  --destructive: 0 65% 44%;
  --destructive-foreground: 0 0% 100%;
  --border: 220 18% 86%;
  --input: 220 18% 93%;
  --ring: 38 85% 36%;
  --chart-1: 38 85% 36%;
  --chart-2: 271 50% 50%;
  --chart-3: 195 75% 42%;
  --chart-4: 142 55% 38%;
  --chart-5: 0 65% 48%;
  --sidebar-background: 40 30% 97%;
  --sidebar-foreground: 224 40% 8%;
  --sidebar-primary: 38 85% 36%;
  --sidebar-primary-foreground: 0 0% 100%;
  --sidebar-accent: 220 18% 93%;
  --sidebar-accent-foreground: 224 40% 8%;
  --sidebar-border: 220 18% 86%;
  --sidebar-ring: 38 85% 36%;
}

/* Light mode: override hardcoded dark card classes */
html.light .card-dark {
  background: hsl(0 0% 100%);
  border: 1px solid hsl(220 18% 86%);
}
html.light .card-gold {
  background: linear-gradient(135deg, hsl(0 0% 100%), hsl(43 40% 97%));
  border: 1px solid hsl(43 35% 78%);
}
html.light .card-purple {
  background: linear-gradient(135deg, hsl(0 0% 100%), hsl(271 35% 96%));
  border: 1px solid hsl(271 25% 80%);
}
html.light .chat-bubble-ai {
  background: hsl(220 18% 95%);
  border: 1px solid hsl(220 18% 86%);
}
html.light .glow-gold { box-shadow: 0 0 20px hsl(38 85% 36% / 0.25); }
html.light .glow-purple { box-shadow: 0 0 20px hsl(271 50% 42% / 0.25); }

/* Urdu Nastaliq Typography */
.font-urdu {
  font-family: 'Noto Nastaliq Urdu', 'Jameel Noori Nastaleeq', serif;
  direction: rtl;
  line-height: 2.2;
  letter-spacing: 0;
}

/* Custom scrollbar */
::-webkit-scrollbar { width: 4px; }
::-webkit-scrollbar-track { background: hsl(var(--background)); }
::-webkit-scrollbar-thumb { background: hsl(var(--border)); border-radius: 2px; }
::-webkit-scrollbar-thumb:hover { background: hsl(var(--muted-foreground)); }

/* ── Seamless 4× infinite ticker loop ──────────────────────────────── */
/* 4 identical copies rendered; translating -25% = exactly 1 copy's width */
@keyframes ticker-loop {
  0%   { transform: translateX(0); }
  100% { transform: translateX(-25%); }
}
.ticker-infinite {
  display: inline-flex;
  white-space: nowrap;
  will-change: transform;
  animation: ticker-loop var(--ticker-dur, 30s) linear infinite;
}
.ticker-infinite:hover { animation-play-state: paused; }

/* Reverse-direction ticker for Line 2 */
@keyframes ticker-loop-reverse {
  0%   { transform: translateX(-25%); }
  100% { transform: translateX(0); }
}
.ticker-infinite-reverse {
  display: inline-flex;
  white-space: nowrap;
  will-change: transform;
  animation: ticker-loop-reverse var(--ticker-dur, 30s) linear infinite;
}
.ticker-infinite-reverse:hover { animation-play-state: paused; }

/* Legacy single-pass ticker (kept for backward compat) */
@keyframes ticker-scroll {
  0%   { transform: translateX(100vw); }
  100% { transform: translateX(-100%); }
}
.ticker-animate {
  animation: ticker-scroll 55s linear infinite;
  white-space: nowrap;
  display: inline-block;
}
.ticker-animate:hover { animation-play-state: paused; }

/* Gold gradient text */
.gold-gradient {
  background: linear-gradient(135deg, hsl(43 92% 42%), hsl(43 92% 65%), hsl(35 95% 55%));
  -webkit-background-clip: text;
  background-clip: text;
  -webkit-text-fill-color: transparent;
}

/* VIP gradient */
.vip-gradient {
  background: linear-gradient(135deg, hsl(271 55% 35%), hsl(271 70% 55%), hsl(300 70% 55%));
}

/* Glow */
.glow-gold { box-shadow: 0 0 24px hsl(43 92% 52% / 0.35); }
.glow-purple { box-shadow: 0 0 24px hsl(271 55% 55% / 0.35); }

/* Card variants */
.card-dark { background: hsl(224 45% 7%); border: 1px solid hsl(224 40% 15%); }
.card-gold { background: linear-gradient(135deg, hsl(224 45% 8%), hsl(43 50% 10%)); border: 1px solid hsl(43 60% 25%); }
.card-purple { background: linear-gradient(135deg, hsl(224 45% 8%), hsl(271 40% 12%)); border: 1px solid hsl(271 40% 22%); }

/* Level badge colors */
.level-bronze { background: linear-gradient(135deg, hsl(25 80% 35%), hsl(25 80% 50%)); }
.level-silver { background: linear-gradient(135deg, hsl(220 10% 45%), hsl(220 10% 65%)); }
.level-gold { background: linear-gradient(135deg, hsl(43 80% 38%), hsl(43 92% 55%)); }
.level-platinum { background: linear-gradient(135deg, hsl(195 60% 45%), hsl(195 80% 65%)); }
.level-diamond { background: linear-gradient(135deg, hsl(220 80% 50%), hsl(260 90% 70%)); }

/* ── Header Clock: Premium Glowing Spectrum Effect ──────────────────────
   Cycles Gold → Cyan → Purple → Gold every 5s with text-shadow glow.
   Matches the luminous quality of the gold-gradient AI brand name.       */
@keyframes clock-spectrum {
  0%   { color: hsl(43 92% 68%);  text-shadow: 0 0 8px hsl(43 92% 55%),  0 0 22px hsl(43 80% 38%);  }
  33%  { color: hsl(185 80% 68%); text-shadow: 0 0 8px hsl(185 80% 52%), 0 0 22px hsl(185 60% 36%); }
  66%  { color: hsl(271 70% 74%); text-shadow: 0 0 8px hsl(271 60% 60%), 0 0 22px hsl(271 55% 42%); }
  100% { color: hsl(43 92% 68%);  text-shadow: 0 0 8px hsl(43 92% 55%),  0 0 22px hsl(43 80% 38%);  }
}
.clock-glow {
  animation: clock-spectrum 5s ease-in-out infinite;
}

/* ── Weather Animations (MagicCalendarStrip) ─────────────────────────────
   Used for live background effects: stars, rain, snow, sun glow, clouds, lightning
   Low-opacity, pointer-events: none — never obscures ticker text              */
@keyframes mc-twinkle {
  0%, 100% { opacity: 0.12; transform: scale(0.75); }
  50%       { opacity: 0.95; transform: scale(1.2);  }
}
@keyframes mc-rain-fall {
  0%   { transform: translateY(-10px) translateX(0);  opacity: 0; }
  35%  { opacity: 0.55; }
  100% { transform: translateY(68px)  translateX(-5px); opacity: 0; }
}
@keyframes mc-snow-fall {
  0%   { transform: translateY(-8px) translateX(0);   opacity: 0; }
  50%  { opacity: 0.72; }
  100% { transform: translateY(68px) translateX(9px); opacity: 0; }
}
@keyframes mc-sun-pulse {
  0%, 100% { opacity: 0.09;  transform: scale(0.93); }
  50%       { opacity: 0.27; transform: scale(1.07); }
}
@keyframes mc-cloud-float {
  0%       { transform: translateX(-40px); opacity: 0;    }
  20%, 80% { opacity: 0.17; }
  100%     { transform: translateX(40px);  opacity: 0;    }
}
@keyframes mc-lightning {
  0%, 100%   { opacity: 0; }
  10%, 12%   { opacity: 0.4; }
  11%        { opacity: 0; }
  50%, 52%   { opacity: 0.22; }
  51%        { opacity: 0; }
}

/* Pulse animation for pending */
@keyframes pulse-glow {
  0%, 100% { box-shadow: 0 0 8px hsl(43 92% 52% / 0.3); }
  50% { box-shadow: 0 0 20px hsl(43 92% 52% / 0.7); }
}
.pulse-gold { animation: pulse-glow 2s ease-in-out infinite; }

/* Chat bubble */
.chat-bubble-user {
  background: linear-gradient(135deg, hsl(43 80% 48%), hsl(43 92% 58%));
  color: hsl(224 50% 5%);
}
.chat-bubble-ai {
  background: hsl(224 45% 10%);
  border: 1px solid hsl(224 40% 18%);
}

/* ── Mobile-Optimized Code Blocks (OMNISCIENT AI) ─────────────────── */
/* Scrollable, readable code on Android WebView / mobile browsers */
.mobile-code-block pre,
.mobile-code-block code {
  font-size: 13px !important;
  line-height: 1.6 !important;
  overflow-x: auto !important;
  -webkit-overflow-scrolling: touch !important;
  white-space: pre !important;
  word-break: normal !important;
  max-width: 100% !important;
  display: block !important;
}
.mobile-code-block pre {
  padding: 12px !important;
  border-radius: 10px !important;
  margin: 8px 0 !important;
  background: hsl(224 50% 4%) !important;
  border: 1px solid hsl(224 40% 18%) !important;
  position: relative !important;
}
/* Make all touch targets minimum 44px for mobile developers */
button, [role="button"] {
  min-height: 32px;
}

/* Urdu text in chat — increase line height for Nastaliq readability */
[dir="rtl"] .text-sm,
[dir="rtl"] p {
  line-height: 2.0;
}

/* ── Mobile Safe-Area: Login/Signup dialog & overlays ──────────── */
/* Prevent modals/dialogs from hiding under the device status bar   */
/* on iOS notch phones and Android edge-to-edge screens.            */
[data-radix-dialog-content],
[data-radix-alert-dialog-content] {
  margin-top: max(0.75rem, env(safe-area-inset-top, 0px)) !important;
  max-height: calc(100dvh - env(safe-area-inset-top, 0px) - env(safe-area-inset-bottom, 0px) - 1.5rem) !important;
  overflow-y: auto !important;
}

/* Android horizontal scroll fix for code */
.code-scroll-mobile {
  overflow-x: auto;
  -webkit-overflow-scrolling: touch;
  scrollbar-width: thin;
}
.code-scroll-mobile::-webkit-scrollbar {
  height: 4px;
}
.code-scroll-mobile::-webkit-scrollbar-thumb {
  background: hsl(var(--primary) / 0.4);
  border-radius: 2px;
}

/* ══════════════════════════════════════════════════════════════════
   SKY VIEWPORT BACKGROUND ANIMATIONS
   ══════════════════════════════════════════════════════════════════ */
@keyframes sky-sun-pulse {
  0%, 100% { transform: scale(1); filter: brightness(1); }
  50% { transform: scale(1.08); filter: brightness(1.15); }
}
@keyframes sky-twinkle {
  0%, 100% { opacity: 0.15; transform: scale(0.7); }
  50% { opacity: 0.9; transform: scale(1.3); }
}
@keyframes sky-cloud-drift {
  0% { transform: translateX(-150px); opacity: 0; }
  10% { opacity: 1; }
  90% { opacity: 1; }
  100% { transform: translateX(calc(100vw + 150px)); opacity: 0; }
}
@keyframes sky-rain-fall {
  0% { transform: translateY(-20px); opacity: 0; }
  20% { opacity: 0.5; }
  100% { transform: translateY(100vh); opacity: 0; }
}
@keyframes sky-fog-pulse {
  0%, 100% { opacity: 0.25; }
  50% { opacity: 0.45; }
}

/* ══════════════════════════════════════════════════════════════════
   PRAYER ALERT OVERLAY ANIMATIONS
   ══════════════════════════════════════════════════════════════════ */
@keyframes prayer-wave {
  0% { height: 6px; }
  100% { height: 28px; }
}

/* Hide scrollbar for prayer strip */
.scrollbar-hide {
  -ms-overflow-style: none;
  scrollbar-width: none;
}
.scrollbar-hide::-webkit-scrollbar { display: none; }

