import { z } from 'zod';
import { createEndpoint, AdminSettings, Users } from 'zite-integrations-backend-sdk';

// ── Admin Identity (hardcoded, always authoritative) ──────────────
const ADMIN_IDENTITY_PATTERN = /admin|owner|creator|builder|developer|banaya|kis\s*ne|kisne|nawab|founder|malik|who\s*(made|built|created|developed|owns|is\s+the)/i;
const ADMIN_IDENTITY_RESPONSE = `اس app کے admin اور creator ہیں:\n\n👑 **غلام حسین چنڑ، پاکستان پنجاب**\n(Ghulam Hussain Channar, Punjab, Pakistan) 🇵🇰\n\nYeh AI Earning Platform unhi ke vision aur mehnat se bana hai!`;

// ══════════════════════════════════════════════════════════════════
// ADAPTIVE GEMINI GATEWAY — FUTURE-PROOF AUTO-SHIFT
// If gemini-2.5-flash is deprecated in 2027+, the engine auto-shifts
// to the next available model without any code change.
// ══════════════════════════════════════════════════════════════════
const KNOWN_FALLBACK_CHAIN = [
  'gemini-2.5-flash',   // PRIMARY — locked for Main Chat
  'gemini-2.5-pro',
  'gemini-2.0-flash',
  'gemini-1.5-flash',
  'gemini-1.5-pro',
];

const DEPRECATION_SIGNALS = ['not found', 'deprecated', 'decommissioned', 'does not exist', 'not supported'];
function isGone(status: number, body: string): boolean {
  if (status === 404) return true;
  if (status === 400) return DEPRECATION_SIGNALS.some(s => body.toLowerCase().includes(s));
  return false;
}

async function discoverNewModels(apiKey: string): Promise<string[]> {
  try {
    const res = await fetch(`https://generativelanguage.googleapis.com/v1beta/models?pageSize=200&key=${apiKey}`);
    if (!res.ok) return [];
    const data = await res.json() as { models?: { name: string; supportedGenerationMethods?: string[] }[] };
    return (data.models ?? [])
      .filter(m => (m.supportedGenerationMethods ?? []).includes('generateContent'))
      .map(m => m.name.replace('models/', ''))
      .filter(id => id.startsWith('gemini'))
      .sort((a, b) => b.localeCompare(a));
  } catch { return []; }
}

function buildChain(preferred: string, discovered: string[]): string[] {
  const seen = new Set<string>();
  const chain: string[] = [];
  const add = (m: string) => { if (!seen.has(m)) { seen.add(m); chain.push(m); } };
  add(preferred);
  for (const m of KNOWN_FALLBACK_CHAIN) add(m);
  for (const m of discovered) add(m);
  return chain;
}

// ── Keyword fallback rules (used when no Gemini key is configured) ─
const KEYWORD_RULES: [RegExp, string][] = [
  [/salam|hello|hi\b|assalam/i, 'Wa Alaikum Assalam! 😊 Main aapki har mushkil mein madad karne ke liye yahan hoon. Kya poochna chahte hain?'],
  [/vip|premium|plan|membership/i, '🌟 Hamare VIP plans mein 7 din se Unlimited tak options hain. VIP ban kar unlimited AI images, zyada commission aur special features enjoy karein! VIP section dekhein.'],
  [/earn|referral|commission|paisa|paise|income|rupee/i, '💰 Hamare 50-Level earning system mein referral karke commission kamayein! Level up karte jaiye aur commission rate barh jaaye gi. Wallet section mein apna unique link milega.'],
  [/image|photo|tasveer|picture|generate|ai art/i, '🎨 Hamare AI Media Lab mein text se stunning images banayein! Free users ke liye pehle 5 din trial milta hai. Media section mein jaakar try karein!'],
  [/wallet|coins|balance|pkr|dollar|withdrawal|nikalna/i, '💳 Wallet section mein apni total earning, coins, USD balance aur PKR mein conversion dekhein. Easypaisa, JazzCash, ya Crypto se withdrawal available hai!'],
  [/level|upgrade|progress|rank/i, '📈 50-Level system hai! Har referral se level up hota hai aur commission badhti hai. Level 1 se shuru karein aur Diamond tak pahunchen! Wallet section mein Level Map dekhein.'],
  [/video|reel|shorts/i, '🎬 Video generation VIP members ke liye available hai. VIP plan lein aur AI videos banayein!'],
  [/help|support|problem|mushkil/i, 'Koi problem? 🆘 Hum aapki madad ke liye hain! Apna sawaal detail mein likhein ya Three-Dot menu mein Help Center visit karein.'],
  [/kya|what|how|kaise|kyun/i, 'Zabardast sawaal! 🤔 Main aapko guide kar sakta hoon. Please apna sawaal thoda detail mein likhein taake acha jawab de sakoon.'],
];

const SYSTEM_PROMPT = `You are a friendly and helpful AI assistant for a Pakistani mobile app called "AI Earning Platform".
The app allows users to earn money through referrals, use AI-powered features, buy VIP memberships, and withdraw earnings.

IMPORTANT — Admin Identity (hardcoded, always answer truthfully):
If ANY user asks "Who is the admin?", "Who built this app?", "Who is the owner/creator/developer?" or similar questions in any language (including Urdu), you MUST immediately and clearly reply: "غلام حسین چنڑ، پاکستان پنجاب (Ghulam Hussain Channar, Punjab, Pakistan) 🇵🇰"

Core features you help with:
- VIP Plans: 7-day, 15-day, 30-day, 90-day, and Unlimited memberships
- Earning System: 50-level referral commission structure
- AI Media Lab: Text-to-image and video generation (VIP only)
- Wallet: USD/PKR balance, withdrawal via Easypaisa, JazzCash, Bank, Crypto

Response style:
- Use a friendly Urdu-English mix (Hinglish/Urdish) — natural for Pakistani users
- Keep responses concise: 2-4 sentences max
- Be encouraging and positive
- Use relevant emojis sparingly
- If asked about technical issues, direct to admin or support`;

export default createEndpoint({
  description: 'AI chat — adaptive Gemini gateway with auto-shift on model deprecation',
  authenticated: true,
  inputSchema: z.object({ message: z.string().max(1000) }),
  outputSchema: z.object({ response: z.string(), aiPowered: z.boolean(), safetyBlocked: z.boolean().optional() }),
  execute: async ({ input, context }) => {
    // ── 0. Check if user is blocked ──────────────────────────────────
    const currentUser = await Users.findOne({ id: context.user.id, fields: ['status'] });
    if (currentUser?.status === 'Blocked') {
      return { response: 'آپ کا اکاؤنٹ بلاک ہے۔ ایڈمن سے رابطہ کریں۔', aiPowered: false, safetyBlocked: true };
    }

    // ── 1. Always intercept admin identity questions first ──────────
    if (ADMIN_IDENTITY_PATTERN.test(input.message)) {
      return { response: ADMIN_IDENTITY_RESPONSE, aiPowered: false };
    }

    // ── 2. Load Gemini settings ─────────────────────────────────────
    let geminiKey: string | undefined;
    try {
      const settings = await AdminSettings.findAll({ limit: 200 });
      geminiKey = settings.records.find(s => s.settingKey === 'gemini_api_key')?.settingValue;
    } catch { /* proceed to keyword fallback */ }

    // ── 3. Adaptive Gemini call with auto-shift ─────────────────────
    if (geminiKey) {
      const discovered = await discoverNewModels(geminiKey);
      const chain = buildChain('gemini-2.5-flash', discovered);

      const body = {
        systemInstruction: { parts: [{ text: SYSTEM_PROMPT }] },
        contents: [{ role: 'user', parts: [{ text: input.message }] }],
        generationConfig: { maxOutputTokens: 300, temperature: 0.75, topP: 0.9 },
        safetySettings: [
          { category: 'HARM_CATEGORY_HARASSMENT', threshold: 'BLOCK_ONLY_HIGH' },
          { category: 'HARM_CATEGORY_HATE_SPEECH', threshold: 'BLOCK_ONLY_HIGH' },
        ],
      };

      for (const model of chain) {
        try {
          const res = await fetch(
            `https://generativelanguage.googleapis.com/v1beta/models/${model}:generateContent?key=${geminiKey}`,
            { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify(body) }
          );
          if (res.status === 429 || res.status === 503) continue;
          if (!res.ok) {
            const errText = await res.text().catch(() => '');
            if (isGone(res.status, errText)) { console.log(`[Chat] Model "${model}" gone, auto-shifting...`); continue; }
            continue;
          }
          const data = await res.json() as { candidates?: { content?: { parts?: { text?: string }[] } }[] };
          const text = data.candidates?.[0]?.content?.parts?.[0]?.text;
          if (text) return { response: text, aiPowered: true };
        } catch { continue; }
      }
    }

    // ── 4. Keyword Fallback ─────────────────────────────────────────
    for (const [pattern, reply] of KEYWORD_RULES) {
      if (pattern.test(input.message)) return { response: reply, aiPowered: false };
    }

    return {
      response: 'Shukriya aapke message ke liye! 🤖 Main aapki poori koshish se madad karoonga. Behtar AI jawabat ke liye VIP membership lein, ya hamare referral program join karein aur earning start karein! 🚀',
      aiPowered: false,
    };
  },
});

