import { z } from 'zod';
import { createEndpoint, NewsTickers, AdminSettings } from 'zite-integrations-backend-sdk';

export default createEndpoint({
  description: 'Get public app data: tickers, banner, rates, AI settings, image limits, withdrawal limit, color presets, global notification',
  inputSchema: z.object({}),
  outputSchema: z.object({
    // ── App Shell ──────────────────────────────────────────────────────────
    tickers:            z.array(z.object({ id: z.string(), content: z.string() })),
    bannerText:         z.string().nullable(),
    bannerUrl:          z.string().nullable(),
    tickerEnabled:      z.boolean(),
    tickerColorPreset:  z.string().nullable(),
    tickerSpeed:        z.number(),
    lcdColorPreset:     z.string().nullable(),
    globalNotification: z.object({ seq: z.string(), message: z.string() }).nullable(),

    // ── AI Engines ─────────────────────────────────────────────────────────
    aiName:            z.string(),
    codingRestricted:  z.boolean(),

    // ── Wallet / Exchange ──────────────────────────────────────────────────
    usdToPkr:          z.number(),
    minWithdrawUsd:    z.number(),
    referralCoins:     z.number(),

    // ── Image Studio Limits (exposed so media pages can react without extra call)
    imgLimitFreeD1:    z.number(),
    imgLimitFreeD2:    z.number(),
    imgLimitFreeD3:    z.number(),
    imgLimitVip:       z.number(),   // 0 = unlimited

    // ── Video Studio ────────────────────────────────────────────────────────
    vidLimitVip:       z.number(),

    // ── Weather/Maps API Key (for 4-module quad-link) ──────────────────────
    weatherApiKey:     z.string().nullable(),
  }),
  execute: async () => {
    const [tickersRes, settingsRes] = await Promise.all([
      NewsTickers.findAll({ filters: { isActive: true }, limit: 20 }),
      AdminSettings.findAll({ limit: 500 }),
    ]);

    const cfg = Object.fromEntries(
      settingsRes.records.map(r => [r.settingKey ?? '', r.settingValue ?? ''])
    );

    const notifSeq = cfg['global_notification_seq'];
    const notifMsg = cfg['global_notification_message'];
    const globalNotification = notifSeq && notifMsg
      ? { seq: notifSeq, message: notifMsg }
      : null;

    return {
      // App Shell
      tickers: tickersRes.records
        .sort((a, b) => (a.sortOrder ?? 0) - (b.sortOrder ?? 0))
        .map(t => ({ id: t.id, content: t.content ?? '' })),
      bannerText:          cfg['banner_text']         || null,
      bannerUrl:           cfg['banner_url']          || null,
      tickerEnabled:       cfg['ticker_enabled']      !== 'false',
      tickerColorPreset:   cfg['ticker_color_preset'] || null,
      tickerSpeed:         Math.min(10, Math.max(1, parseInt(cfg['ticker_speed'] ?? '5') || 5)),
      lcdColorPreset:      cfg['lcd_color_preset']    || null,
      globalNotification,

      // AI Engines
      aiName:           cfg['ai_name']               || 'Hussain AI - Master Engine',
      codingRestricted: cfg['code_engine_free_mode'] === 'false',

      // Wallet / Exchange
      usdToPkr:       parseFloat(cfg['usd_to_pkr']          ?? '280') || 280,
      minWithdrawUsd: parseFloat(cfg['min_withdraw_usd']     ?? '1')   || 1,
      referralCoins:  parseFloat(cfg['referral_coins']       ?? '10')  || 10,

      // Image Studio
      imgLimitFreeD1: parseInt(cfg['img_limit_free_d1'] ?? '3') || 3,
      imgLimitFreeD2: parseInt(cfg['img_limit_free_d2'] ?? '2') || 2,
      imgLimitFreeD3: parseInt(cfg['img_limit_free_d3'] ?? '1') || 1,
      imgLimitVip:    parseInt(cfg['img_limit_vip']     ?? '0') || 0,

      // Video Studio
      vidLimitVip:    parseInt(cfg['vid_limit_vip']    ?? '1') || 1,

      // Weather/Maps API Key
      weatherApiKey:  cfg['google_weather_maps_key'] || null,
    };
  },
});

