import { useEffect, useState, useCallback, useRef } from 'react';
import { useAuth } from 'zite-auth-sdk';
import { getVIPPlans, expireUserVip, GetVIPPlansOutputType } from 'zite-endpoints-sdk';
import VIPCard from '@/components/vip/VIPCard';
import PaymentModal from '@/components/vip/PaymentModal';
import { Skeleton } from '@/components/ui/skeleton';
import { Crown, Sparkles, Star, Zap, Shield, TrendingUp, Timer, Lock } from 'lucide-react';
import { useAppData } from '@/contexts/AppDataContext';

type Plan = GetVIPPlansOutputType['plans'][0];

const VIP_BENEFITS = [
  { icon: '🤖', title: 'Unlimited AI Chat', desc: 'Ask anything, get expert answers instantly' },
  { icon: '🎨', title: 'Unlimited AI Images', desc: 'Generate stunning visuals without limits' },
  { icon: '🎬', title: 'Video Script AI', desc: 'Create viral video scripts & storyboards' },
  { icon: '💰', title: 'Double Earnings', desc: 'Higher referral commissions at every level' },
  { icon: '⚡', title: 'Priority Processing', desc: 'Faster AI responses, no queues' },
  { icon: '👑', title: 'VIP Badge', desc: 'Exclusive badge on your profile & wallet' },
];

// ── Live Countdown Timer ──────────────────────────────────────────
function VipCountdown({ expiresAt, onExpire }: { expiresAt: string; onExpire?: () => void }) {
  const calcTime = () => {
    const remaining = new Date(expiresAt).getTime() - Date.now();
    if (remaining <= 0) return { days: 0, hours: 0, mins: 0, secs: 0, expired: true };
    return {
      days: Math.floor(remaining / 86400000),
      hours: Math.floor((remaining % 86400000) / 3600000),
      mins: Math.floor((remaining % 3600000) / 60000),
      secs: Math.floor((remaining % 60000) / 1000),
      expired: false,
    };
  };

  const [time, setTime] = useState(calcTime);
  const [expireCalled, setExpireCalled] = useState(false);

  useEffect(() => {
    const interval = setInterval(() => {
      const t = calcTime();
      setTime(t);
      if (t.expired && !expireCalled) {
        setExpireCalled(true);
        clearInterval(interval);
        onExpire?.();
      }
    }, 1000);
    return () => clearInterval(interval);
  }, [expiresAt, onExpire, expireCalled]);

  if (time.expired) return null;

  const pad = (n: number) => String(n).padStart(2, '0');

  return (
    <div className="mt-3">
      <p className="text-[10px] text-muted-foreground mb-2 flex items-center gap-1">
        <Timer size={10} /> VIP Membership Expires In
      </p>
      <div className="grid grid-cols-4 gap-1.5">
        {[
          { label: 'Days', val: time.days },
          { label: 'Hours', val: time.hours },
          { label: 'Mins', val: time.mins },
          { label: 'Secs', val: time.secs },
        ].map(({ label, val }) => (
          <div key={label} className="bg-primary/15 border border-primary/30 rounded-xl p-2 text-center">
            <p className="text-lg font-black text-primary tabular-nums">{pad(val)}</p>
            <p className="text-[9px] text-muted-foreground uppercase tracking-wide">{label}</p>
          </div>
        ))}
      </div>
    </div>
  );
}

export default function VIPPage() {
  const { user, isLoading, loginWithRedirect } = useAuth();
  const { refreshCount } = useAppData();
  const [data, setData] = useState<GetVIPPlansOutputType | null>(null);
  const [loading, setLoading] = useState(true);
  const [selectedPlan, setSelectedPlan] = useState<Plan | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [vipExpiredClient, setVipExpiredClient] = useState(false);
  // Track last refreshCount to detect admin changes
  const lastRefreshCountRef = useRef(refreshCount);

  const loadPlans = useCallback(() => {
    setLoading(true);
    setError(null);
    getVIPPlans({})
      .then(setData)
      .catch(e => setError(e?.message ?? 'Failed to load plans'))
      .finally(() => setLoading(false));
  }, []);

  // Initial load
  useEffect(() => { loadPlans(); }, [loadPlans]);

  // Re-fetch when admin makes changes (detected via AppDataContext refreshCount)
  useEffect(() => {
    if (refreshCount !== lastRefreshCountRef.current && refreshCount > 0) {
      lastRefreshCountRef.current = refreshCount;
      // Re-fetch payment info + plans when admin changes settings
      getVIPPlans({}).then(setData).catch(console.error);
    }
  }, [refreshCount]);

  // Reset client expiry when user VIP status changes
  useEffect(() => {
    if (user?.vipStatus !== 'VIP') setVipExpiredClient(false);
  }, [user?.vipStatus]);

  const handleVipExpire = useCallback(async () => {
    setVipExpiredClient(true);
    try {
      await expireUserVip({});
    } catch (_) { /* silently fail */ }
  }, []);

  const handleBuy = (id: string) => {
    if (!user) { loginWithRedirect({ redirectUrl: window.location.href }); return; }
    const plan = data?.plans.find(p => p.id === id);
    if (plan) setSelectedPlan(plan);
  };

  // Determine effective VIP state
  const isActiveVip = user?.vipStatus === 'VIP' && !vipExpiredClient &&
    (!user.vipExpiresAt || new Date(user.vipExpiresAt) > new Date());

  return (
    <div className="p-4 space-y-4 max-w-lg mx-auto pb-8">
      {/* Hero Header */}
      <div className="text-center py-4">
        <div className="flex items-center justify-center gap-2 mb-2">
          <Crown size={28} className="text-primary" />
          <h1 className="text-2xl font-black gold-gradient">VIP Membership</h1>
          <Crown size={28} className="text-primary" />
        </div>
        <p className="text-sm text-muted-foreground flex items-center justify-center gap-1">
          <Sparkles size={13} className="text-primary" />
          Unlock unlimited AI power + higher referral earnings
        </p>
      </div>

      {/* VIP Status Banner — with live animated countdown */}
      {!isLoading && isActiveVip && (
        <div className="bg-primary/10 border border-primary/30 rounded-2xl p-4 glow-gold">
          <div className="text-center">
            <p className="text-lg font-black text-primary">👑 You are VIP!</p>
            {user?.vipPlan && (
              <p className="text-sm text-muted-foreground mt-1">
                Plan: <span className="text-foreground font-bold">{user.vipPlan}</span>
              </p>
            )}
          </div>
          {user?.vipExpiresAt && (
            <VipCountdown
              expiresAt={user.vipExpiresAt}
              onExpire={handleVipExpire}
            />
          )}
        </div>
      )}

      {/* VIP Expired — timer hit zero */}
      {!isLoading && user?.vipStatus === 'VIP' && vipExpiredClient && (
        <div className="bg-destructive/10 border border-destructive/30 rounded-2xl p-4 text-center">
          <Lock size={22} className="mx-auto text-destructive mb-2" />
          <p className="text-base font-bold text-destructive">🔒 VIP Access Expired</p>
          <p className="text-xs text-muted-foreground mt-1">
            Your VIP plan has ended. Purchase a new plan to continue enjoying premium features.
          </p>
        </div>
      )}

      {/* Admin Revoked */}
      {!isLoading && user?.vipStatus === 'Free' && user?.vipExpiresAt && new Date(user.vipExpiresAt).getFullYear() === 1970 && (
        <div className="bg-destructive/10 border border-destructive/30 rounded-2xl p-3 text-center">
          <p className="text-xs text-destructive font-semibold">⚠️ Your VIP was revoked by admin. Contact support for details.</p>
        </div>
      )}

      {!isLoading && user?.vipStatus === 'Pending' && (
        <div className="bg-yellow-500/10 border border-yellow-500/30 rounded-2xl p-4 text-center">
          <p className="text-base font-bold text-yellow-400">⏳ Verification In Progress</p>
          <p className="text-xs text-muted-foreground mt-1">Admin is reviewing your payment. Usually within 24hrs.</p>
        </div>
      )}

      {/* Benefits Grid */}
      <div className="card-dark rounded-2xl p-4">
        <p className="text-sm font-bold flex items-center gap-2 mb-3">
          <Star size={14} className="text-primary" /> VIP Benefits
        </p>
        <div className="grid grid-cols-2 gap-2">
          {VIP_BENEFITS.map(b => (
            <div key={b.title} className="bg-muted/40 rounded-xl p-3">
              <p className="text-base">{b.icon}</p>
              <p className="text-xs font-bold mt-1">{b.title}</p>
              <p className="text-[10px] text-muted-foreground mt-0.5">{b.desc}</p>
            </div>
          ))}
        </div>
      </div>

      {/* Plans */}
      {error && (
        <div className="card-dark rounded-2xl p-4 text-center border border-destructive/30">
          <p className="text-sm text-destructive">⚠️ {error}</p>
          <button onClick={loadPlans} className="mt-2 text-xs text-primary hover:underline">Retry</button>
        </div>
      )}

      {loading ? (
        <div className="space-y-3">
          {[1, 2, 3, 4, 5].map(i => <Skeleton key={i} className="h-52 w-full rounded-2xl" />)}
        </div>
      ) : (
        <div className="space-y-3">
          {(data?.plans ?? []).map(plan => (
            <VIPCard
              key={plan.id}
              {...plan}
              saleEndTime={data?.saleEndTime ?? null}
              usdToPkr={data?.usdToPkr ?? 280}
              onBuy={(id) => handleBuy(id)}
            />
          ))}
          {!data?.plans.length && !error && (
            <div className="card-dark rounded-2xl p-6 text-center space-y-3">
              <Crown size={40} className="mx-auto text-primary opacity-50" />
              <p className="text-sm font-bold">Plans are loading...</p>
              <p className="text-xs text-muted-foreground">VIP plans are being set up. Please try again in a moment.</p>
              <button onClick={loadPlans} className="text-xs text-primary hover:underline">Refresh</button>
            </div>
          )}
        </div>
      )}

      {/* How It Works */}
      <div className="card-dark rounded-2xl p-4 space-y-3">
        <p className="text-sm font-bold flex items-center gap-2">
          <Shield size={14} className="text-primary" /> How VIP Activation Works
        </p>
        {[
          { step: '1', text: 'Select your preferred VIP plan below' },
          { step: '2', text: 'Choose a payment method (Easypaisa, JazzCash, Bank, Crypto)' },
          { step: '3', text: 'Send the exact amount and upload your payment screenshot' },
          { step: '4', text: 'Admin verifies within 24 hours — VIP unlocked! 🎉' },
        ].map(s => (
          <div key={s.step} className="flex items-start gap-3">
            <div className="w-5 h-5 rounded-full bg-primary/20 border border-primary/30 flex items-center justify-center shrink-0 mt-0.5">
              <span className="text-[10px] font-bold text-primary">{s.step}</span>
            </div>
            <p className="text-xs text-muted-foreground">{s.text}</p>
          </div>
        ))}
      </div>

      {/* Earnings Info */}
      <div className="card-gold rounded-2xl p-4 space-y-2">
        <p className="text-sm font-bold flex items-center gap-2">
          <TrendingUp size={14} className="text-primary" /> VIP Earning Advantage
        </p>
        <div className="grid grid-cols-2 gap-2 text-center">
          <div className="bg-muted/30 rounded-xl p-3">
            <p className="text-xs text-muted-foreground">Free Referral</p>
            <p className="text-lg font-black text-muted-foreground">1x</p>
          </div>
          <div className="bg-primary/15 border border-primary/25 rounded-xl p-3">
            <p className="text-xs text-primary">VIP Referral</p>
            <p className="text-lg font-black text-primary">2x <Zap size={12} className="inline" /></p>
          </div>
        </div>
        <p className="text-[10px] text-muted-foreground text-center">VIP members earn double commission on all 50 referral levels</p>
      </div>

      {/* Login CTA for guests */}
      {!isLoading && !user && (
        <div className="card-dark rounded-2xl p-4 text-center space-y-3 border border-primary/20">
          <p className="text-sm font-bold">🔐 Login to Purchase</p>
          <p className="text-xs text-muted-foreground">Create your account to buy a VIP plan and start earning</p>
          <button
            onClick={() => loginWithRedirect({ redirectUrl: window.location.href, initialView: 'signup' })}
            className="w-full bg-primary text-primary-foreground text-sm font-bold py-2.5 rounded-xl hover:bg-primary/90 transition-colors"
          >
            Get Started — Create Account
          </button>
        </div>
      )}

      {selectedPlan && data && (
        <PaymentModal
          open={!!selectedPlan}
          onClose={() => setSelectedPlan(null)}
          planId={selectedPlan.id}
          planName={selectedPlan.planName}
          priceUsd={selectedPlan.priceUsd}
          usdToPkr={data.usdToPkr}
          paymentInfo={data.paymentInfo}
          usdBalance={user?.usdBalance ?? 0}
          onSuccess={() => setSelectedPlan(null)}
        />
      )}
    </div>
  );
}

