function cleanForCoding(text: string): string {
  const parts = text.split(/(```[\s\S]*?```)/);
  return parts.map((part, i) => {
    if (i % 2 === 1) return part;
    return part
      .replace(/\*{1,3}([^*\n]+)\*{1,3}/g, '$1')
      .replace(/\*+/g, '')
      .replace(/^#{1,6}\s+([^\n]+)/gm, '$1')
      .replace(/~~([^~]+)~~/g, '$1')
      .replace(/\[([^\]]+)\]\([^)]+\)/g, '$1')
      .replace(/^[-*]\s+/gm, '• ')
      .replace(/_{1,2}([^_\n]+)_{1,2}/g, '$1');
  }).join('');
}

export default createEndpoint({
  description: 'OMNISCIENT AI — adaptive Gemini gateway, coding engine locked to 1.5-pro with future-proof auto-shift',
  inputSchema: z.object({
    message: z.string().max(3000),
    history: z.array(z.object({
      role: z.enum(['user', 'model']),
      content: z.string(),
    })).optional(),
  }),
  outputSchema: z.object({ response: z.string(), model: z.string(), aiPowered: z.boolean() }),
  execute: async ({ input }) => {
    const settings = await AdminSettings.findAll({ limit: 500 });
    const records = settings.records;

    const freeModeStr = records.find(s => s.settingKey === FREE_PUBLIC_MODE_KEY)?.settingValue;
    const FREE_PUBLIC_MODE = freeModeStr !== 'false';
    void FREE_PUBLIC_MODE;

    const geminiKey = records.find(s => s.settingKey === 'gemini_api_key')?.settingValue;
    const adminAiName = records.find(s => s.settingKey === 'ai_name')?.settingValue?.trim();
    const dynamicSystemPrompt = adminAiName
      ? SYSTEM_PROMPT.replace(/OMNISCIENT AI/g, adminAiName.toUpperCase())
      : SYSTEM_PROMPT;

    if (!geminiKey) {
      return {
        response: 'No API key configured. Please add your Gemini API key in Admin Panel → Settings → Universal Master API Key.',
        model: 'none',
        aiPowered: false,
      };
    }

    const body = {
      systemInstruction: { parts: [{ text: dynamicSystemPrompt }] },
      contents: [
        ...(input.history ?? []).slice(-10).map(h => ({
          role: h.role,
          parts: [{ text: h.content }],
        })),
        { role: 'user', parts: [{ text: input.message }] },
      ],
      generationConfig: { maxOutputTokens: 8192, temperature: 0.55, topP: 0.92 },
    };

    // ── Adaptive auto-shift: discover new models + fallback chain ──
    const discovered = await discoverNewModels(geminiKey);
    const chain = buildChain('gemini-1.5-pro', discovered);

    for (const model of chain) {
      try {
        const res = await fetch(
          `https://generativelanguage.googleapis.com/v1beta/models/${model}:generateContent?key=${geminiKey}`,
          { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify(body) }
        );
        if (res.status === 429 || res.status === 503) continue;
        if (!res.ok) {
          const errText = await res.text().catch(() => '');
          if (isGone(res.status, errText)) { console.log(`[Coding] Model "${model}" gone, auto-shifting...`); continue; }
          continue;
        }
        const data = await res.json() as { candidates?: { content?: { parts?: { text?: string }[] } }[] };
        const raw = data.candidates?.[0]?.content?.parts?.[0]?.text;
        if (!raw) continue;
        return { response: cleanForCoding(raw), model, aiPowered: true };
      } catch { continue; }
    }

    // ── Last resort: no systemInstruction ───────────────────────────
    try {
      const lastResortModel = discovered[0] ?? 'gemini-1.5-flash';
      const fb = {
        contents: [{ role: 'user', parts: [{ text: dynamicSystemPrompt + '\n\n---\nUser:\n' + input.message }] }],
        generationConfig: { maxOutputTokens: 8192, temperature: 0.55 },
      };
      const res = await fetch(
        `https://generativelanguage.googleapis.com/v1beta/models/${lastResortModel}:generateContent?key=${geminiKey}`,
        { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify(fb) }
      );
      if (res.ok) {
        const data = await res.json() as { candidates?: { content?: { parts?: { text?: string }[] } }[] };
        const raw = data.candidates?.[0]?.content?.parts?.[0]?.text;
        if (raw) return { response: cleanForCoding(raw), model: `${lastResortModel}-fallback`, aiPowered: true };
      }
    } catch {}

    throw new Error('AI service temporarily unavailable. Please try again in a moment.');
  },
});

