// ══════════════════════════════════════════════════════════════════
// ISLAMIC PRAYER TIMES ENGINE — Astronomical Calculation
// Calculates 6 prayer times from GPS coordinates using sun position
// Tahajjud · Fajr · Dhuhr · Asr · Maghrib · Isha
// ══════════════════════════════════════════════════════════════════

export interface PrayerTime {
  name: string;
  nameAr: string;
  nameUr: string;
  time: Date;
  hours: number;
  minutes: number;
}

export interface PrayerSchedule {
  tahajjud: PrayerTime;
  fajr: PrayerTime;
  dhuhr: PrayerTime;
  asr: PrayerTime;
  maghrib: PrayerTime;
  isha: PrayerTime;
  nextPrayer: PrayerTime | null;
  minutesUntilNext: number;
}

const RAD = Math.PI / 180;
const DEG = 180 / Math.PI;

// Sun declination & equation of time
function sunPosition(jd: number) {
  const D = jd - 2451545.0;
  const g = ((357.529 + 0.98560028 * D) % 360) * RAD;
  const q = (280.459 + 0.98564736 * D) % 360;
  const L = (q + 1.915 * Math.sin(g) + 0.020 * Math.sin(2 * g)) % 360;
  const e = 23.439 - 0.00000036 * D;
  const decl = Math.asin(Math.sin(e * RAD) * Math.sin(L * RAD)) * DEG;
  const RA = Math.atan2(Math.cos(e * RAD) * Math.sin(L * RAD), Math.cos(L * RAD)) * DEG;
  const EqT = (q - RA + 360) % 360;
  return { decl, eqt: EqT > 180 ? EqT - 360 : EqT };
}

function julianDate(y: number, m: number, d: number): number {
  if (m <= 2) { y--; m += 12; }
  const A = Math.floor(y / 100);
  const B = 2 - A + Math.floor(A / 4);
  return Math.floor(365.25 * (y + 4716)) + Math.floor(30.6001 * (m + 1)) + d + B - 1524.5;
}

// Hour angle for sun at given angle below horizon
function hourAngle(lat: number, decl: number, angle: number): number {
  const cos_ha = (Math.sin(angle * RAD) - Math.sin(lat * RAD) * Math.sin(decl * RAD)) /
    (Math.cos(lat * RAD) * Math.cos(decl * RAD));
  if (cos_ha > 1 || cos_ha < -1) return NaN;
  return Math.acos(cos_ha) * DEG / 15;
}

// Asr shadow factor (Hanafi = 2, Standard/Shafi = 1)
function asrTime(lat: number, decl: number, factor: number): number {
  const a = Math.atan(1 / (factor + Math.tan(Math.abs(lat - decl) * RAD)));
  const cos_ha = (Math.sin(a) - Math.sin(lat * RAD) * Math.sin(decl * RAD)) /
    (Math.cos(lat * RAD) * Math.cos(decl * RAD));
  if (cos_ha > 1 || cos_ha < -1) return NaN;
  return Math.acos(cos_ha) * DEG / 15;
}

export function calculatePrayerTimes(
  lat: number, lon: number, date: Date, tzOffsetHours: number
): PrayerSchedule {
  const y = date.getFullYear();
  const m = date.getMonth() + 1;
  const d = date.getDate();
  const jd = julianDate(y, m, d);
  const { decl, eqt } = sunPosition(jd);

  // Dhuhr (solar noon)
  const dhuhrT = 12 + tzOffsetHours - lon / 15 - eqt / 15;

  // Fajr angle: -18° (University of Islamic Sciences, Karachi)
  const fajrHA = hourAngle(lat, decl, -18);
  const fajrT = dhuhrT - fajrHA;

  // Sunrise angle: -0.833° (standard atmospheric refraction)
  const sunriseHA = hourAngle(lat, decl, -0.833);
  const sunriseT = dhuhrT - sunriseHA;

  // Asr: Hanafi method (shadow = 2x object + noon shadow)
  const asrHA = asrTime(lat, decl, 1); // Standard Shafi
  const asrT = dhuhrT + asrHA;

  // Maghrib (sunset)
  const maghribT = dhuhrT + sunriseHA;

  // Isha angle: -18° (Karachi method)
  const ishaHA = hourAngle(lat, decl, -18);
  const ishaT = dhuhrT + ishaHA;

  // Tahajjud: Last third of the night (between Isha and Fajr next day)
  const nightDuration = (fajrT + 24 - ishaT) % 24;
  const tahajjudT = (ishaT + nightDuration * (2 / 3)) % 24;

  const makePT = (name: string, nameAr: string, nameUr: string, t: number): PrayerTime => {
    const h = Math.floor(((t % 24) + 24) % 24);
    const min = Math.round((((t % 24) + 24) % 24 - h) * 60);
    const time = new Date(y, m - 1, d, h, min, 0);
    return { name, nameAr, nameUr, time, hours: h, minutes: min };
  };

  const prayers = {
    tahajjud: makePT('Tahajjud', 'تهجد', 'تہجد', tahajjudT),
    fajr: makePT('Fajr', 'الفجر', 'فجر', fajrT),
    dhuhr: makePT('Dhuhr', 'الظهر', 'ظہر', dhuhrT),
    asr: makePT('Asr', 'العصر', 'عصر', asrT),
    maghrib: makePT('Maghrib', 'المغرب', 'مغرب', maghribT),
    isha: makePT('Isha', 'العشاء', 'عشاء', ishaT),
  };

  // Find next prayer
  const now = date;
  const ordered = [prayers.fajr, prayers.dhuhr, prayers.asr, prayers.maghrib, prayers.isha, prayers.tahajjud];
  let nextPrayer: PrayerTime | null = null;
  let minutesUntilNext = Infinity;

  for (const p of ordered) {
    const diff = (p.time.getTime() - now.getTime()) / 60000;
    if (diff > -1 && diff < minutesUntilNext) {
      minutesUntilNext = diff;
      nextPrayer = p;
    }
  }

  if (!nextPrayer) {
    // All prayers passed today — next is tomorrow's Fajr
    const tomorrowFajr = new Date(prayers.fajr.time);
    tomorrowFajr.setDate(tomorrowFajr.getDate() + 1);
    nextPrayer = { ...prayers.fajr, time: tomorrowFajr };
    minutesUntilNext = (tomorrowFajr.getTime() - now.getTime()) / 60000;
  }

  return { ...prayers, nextPrayer, minutesUntilNext: Math.round(minutesUntilNext) };
}

