  description: 'Self-healing one-click initialization — seeds VIP plans, levels, settings, tickers, AND video gateway rows. Never overwrites existing data.',
  inputSchema: z.object({ adminToken: z.string() }),
  outputSchema: z.object({
    success: z.boolean(),
    seeded: z.object({ vipPlans: z.number(), levels: z.number(), settings: z.number(), tickers: z.number(), videoGateways: z.number() }),
    skipped: z.object({ vipPlans: z.number(), levels: z.number(), settings: z.number(), tickers: z.number(), videoGateways: z.number() }),
    message: z.string(),
    nextStep: z.string(),
    gatewayStatus: z.array(z.object({ name: z.string(), status: z.string(), synced: z.boolean() })),
  }),
  execute: async ({ input }) => {
    const pwdCheck = await AdminSettings.findOne({ filters: { settingKey: 'admin_password' } });
    const correctPwd = pwdCheck?.settingValue ?? 'admin@2024';
    if (input.adminToken !== correctPwd) throw new ZiteError({ code: 'UNAUTHORIZED', message: 'Incorrect admin password' });

    const [existingPlans, existingLevels, existingSettings, existingTickers, existingVideoKeys] = await Promise.all([
      VipPlans.findAll({ limit: 100 }),
      LevelConfig.findAll({ limit: 100 }),
      AdminSettings.findAll({ limit: 500 }),
      NewsTickers.findAll({ limit: 100 }),
      VideoApiKeys.findAll({ limit: 20 }),
    ]);

    const existingPlanNames      = new Set(existingPlans.records.map(p => p.planName));
    const existingLevelNums      = new Set(existingLevels.records.map(l => l.levelNumber));
    const existingSettingKeys    = new Set(existingSettings.records.map(s => s.settingKey));
    const existingTickerContents = new Set(existingTickers.records.map(t => t.content));
    const existingGatewayIds     = new Set(existingVideoKeys.records.map(k => k.keyIdentifier));

    // ── Seed VIP Plans ──
    const plansToCreate = DEFAULT_VIP_PLANS.filter(p => !existingPlanNames.has(p.planName));
    if (plansToCreate.length > 0) await VipPlans.bulkCreate({ records: plansToCreate });

    // ── Seed Level Config ──
    const levelsToCreate = DEFAULT_LEVELS.filter(l => !existingLevelNums.has(l.levelNumber));
    if (levelsToCreate.length > 0) await LevelConfig.bulkCreate({ records: levelsToCreate });

    // ── Seed Admin Settings ──
    const settingsToCreate = DEFAULT_SETTINGS.filter(s => !existingSettingKeys.has(s.settingKey));
    if (settingsToCreate.length > 0) {
      for (let i = 0; i < settingsToCreate.length; i += 50) {
        await AdminSettings.bulkCreate({ records: settingsToCreate.slice(i, i + 50) });
      }
    }

    // ── Seed News Tickers ──
    const tickersToCreate = DEFAULT_TICKERS.filter(t => !existingTickerContents.has(t.content));
    if (tickersToCreate.length > 0) await NewsTickers.bulkCreate({ records: tickersToCreate });

    // ── Seed Video API Gateway Rows (SELF-HEALING) ──
    const gatewaysToCreate = DEFAULT_VIDEO_GATEWAYS.filter(g => !existingGatewayIds.has(g.keyIdentifier));
    if (gatewaysToCreate.length > 0) await VideoApiKeys.bulkCreate({ records: gatewaysToCreate });

    // ── Build gateway status report ──
    const finalVideoKeys = gatewaysToCreate.length > 0
      ? (await VideoApiKeys.findAll({ limit: 20 })).records
      : existingVideoKeys.records;

    const gatewayStatus = DEFAULT_VIDEO_GATEWAYS.map(g => {
      const rec = finalVideoKeys.find(k => k.keyIdentifier === g.keyIdentifier);
      const hasKey = Boolean(rec?.gatewayKey);
      const isActive = rec?.status === 'Active' && hasKey;
      return {
        name: g.gatewayName,
        status: isActive ? '100% Synced & Active (Auto-Managed)' : hasKey ? `Key present — status: ${rec?.status}` : 'Row ready — paste API key in Video tab',
        synced: isActive,
      };
    });

    const seededPlans = plansToCreate.length;
    const seededLevels = levelsToCreate.length;
    const seededSettings = settingsToCreate.length;
    const seededTickers = tickersToCreate.length;
    const seededGateways = gatewaysToCreate.length;
    const totalSeeded = seededPlans + seededLevels + seededSettings + seededTickers + seededGateways;

    const hasApiKey = existingSettingKeys.has('gemini_api_key') || settingsToCreate.some(s => s.settingKey === 'gemini_api_key');

    return {
      success: true,
      seeded: { vipPlans: seededPlans, levels: seededLevels, settings: seededSettings, tickers: seededTickers, videoGateways: seededGateways },
      skipped: { vipPlans: existingPlanNames.size, levels: existingLevelNums.size, settings: existingSettingKeys.size, tickers: existingTickerContents.size, videoGateways: existingGatewayIds.size },
      message: totalSeeded === 0
        ? '✅ Database already fully initialized — all 5 modules + 3 video gateways synced & ready'
        : `✅ Initialized: ${seededPlans} plans, ${seededLevels} levels, ${seededSettings} settings, ${seededTickers} tickers, ${seededGateways} video gateways`,
      nextStep: hasApiKey
        ? '👉 Go to Settings → paste Gemini API key. Then go to Video tab → paste HuggingFace & Stability keys.'
        : '✅ API key set — all AI modules active',
      gatewayStatus,
    };
  },
});

