import { z } from 'zod';
import { createEndpoint, AdminSettings } from 'zite-integrations-backend-sdk';

export default createEndpoint({
  description: 'Read/write system safety settings (APK URL, anti-crash toggle)',
  inputSchema: z.object({
    action: z.enum(['get', 'save_apk', 'save_anti_crash']),
    adminToken: z.string().optional(),
    apkUrl: z.string().optional(),
    apkVersion: z.string().optional(),
    apkFilename: z.string().optional(),
    antiCrashEnabled: z.boolean().optional(),
  }),
  outputSchema: z.object({
    success: z.boolean(),
    apkUrl: z.string().optional(),
    apkVersion: z.string().optional(),
    apkFilename: z.string().optional(),
    antiCrashEnabled: z.boolean().optional(),
  }),
  execute: async ({ input }) => {
    // Verify admin token for write actions
    if (input.action !== 'get') {
      const pwdRow = await AdminSettings.findOne({ filters: { settingKey: 'admin_password' } });
      const adminPwd = pwdRow?.settingValue ?? 'admin@2024';
      if (input.adminToken !== adminPwd) {
        return { success: false };
      }
    }

    if (input.action === 'get') {
      const [apkUrlRow, apkVerRow, apkFileRow, antiCrashRow] = await Promise.all([
        AdminSettings.findOne({ filters: { settingKey: 'system_apk_url' } }),
        AdminSettings.findOne({ filters: { settingKey: 'system_apk_version' } }),
        AdminSettings.findOne({ filters: { settingKey: 'system_apk_filename' } }),
        AdminSettings.findOne({ filters: { settingKey: 'system_anti_crash' } }),
      ]);
      return {
        success: true,
        apkUrl: apkUrlRow?.settingValue ?? '',
        apkVersion: apkVerRow?.settingValue ?? '',
        apkFilename: apkFileRow?.settingValue ?? '',
        antiCrashEnabled: antiCrashRow?.settingValue !== 'false',
      };
    }

    if (input.action === 'save_apk') {
      const upsert = async (key: string, value: string, desc: string) => {
        const existing = await AdminSettings.findOne({ filters: { settingKey: key } });
        if (existing) {
          await AdminSettings.update({ id: existing.id, record: { settingValue: value, description: desc } });
        } else {
          await AdminSettings.create({ record: { settingKey: key, settingValue: value, description: desc } });
        }
      };
      await Promise.all([
        upsert('system_apk_url', input.apkUrl ?? '', 'Uploaded APK permanent URL'),
        upsert('system_apk_version', input.apkVersion ?? '', 'Uploaded APK version tag'),
        upsert('system_apk_filename', input.apkFilename ?? '', 'Uploaded APK filename'),
      ]);
      return {
        success: true,
        apkUrl: input.apkUrl,
        apkVersion: input.apkVersion,
        apkFilename: input.apkFilename,
      };
    }

    if (input.action === 'save_anti_crash') {
      const val = input.antiCrashEnabled ? 'true' : 'false';
      const existing = await AdminSettings.findOne({ filters: { settingKey: 'system_anti_crash' } });
      if (existing) {
        await AdminSettings.update({ id: existing.id, record: { settingValue: val, description: 'Anti-crash guardrails toggle' } });
      } else {
        await AdminSettings.create({ record: { settingKey: 'system_anti_crash', settingValue: val, description: 'Anti-crash guardrails toggle' } });
      }
      return { success: true, antiCrashEnabled: input.antiCrashEnabled };
    }

    return { success: false };
  },
});

