// ─── Admin Login ──────────────────────────────────────────────────────
function AdminLogin({ onLogin }: { onLogin: (pwd: string) => void }) {
  const [pwd, setPwd] = useState('');
  const [show, setShow] = useState(false);
  const [loading, setLoading] = useState(false);

  const handleLogin = async () => {
    if (!pwd.trim()) return;
    setLoading(true);
    try {
      const r = await adminLogin({ password: pwd.trim() });
      if (r.success) {
        sessionStorage.setItem('admin_token', pwd.trim());
        onLogin(pwd.trim());
        toast.success('🔓 Admin access granted');
      } else {
        toast.error('Incorrect password. Please try again.');
      }
    } catch (e: any) { toast.error(e?.message ?? 'Login failed'); }
    finally { setLoading(false); }
  };

  return (
    <div className="flex flex-col items-center justify-center min-h-[80vh] p-6">
      <div className="card-dark rounded-3xl p-8 w-full max-w-sm text-center space-y-5 border border-destructive/20">
        <div className="bg-destructive/10 rounded-2xl p-4 inline-flex mx-auto">
          <Shield size={36} className="text-destructive" />
        </div>
        <div>
          <h1 className="text-2xl font-black">Admin Panel</h1>
          <p className="text-sm text-muted-foreground mt-1">Secure access — enter your admin password</p>
        </div>
        <div className="relative text-left">
          <Lock size={14} className="absolute left-3 top-1/2 -translate-y-1/2 text-muted-foreground" />
          <Input type={show ? 'text' : 'password'} placeholder="Admin password..." value={pwd}
            onChange={e => setPwd(e.target.value)} onKeyDown={e => e.key === 'Enter' && handleLogin()}
            className="bg-muted border-border pl-9 pr-10" />
          <button onClick={() => setShow(s => !s)} className="absolute right-3 top-1/2 -translate-y-1/2 text-muted-foreground hover:text-foreground">
            {show ? <EyeOff size={16} /> : <Eye size={16} />}
          </button>
        </div>
        <Button onClick={handleLogin} disabled={loading || !pwd.trim()} className="w-full bg-primary text-primary-foreground font-bold gap-2">
          {loading ? 'Verifying...' : <><Lock size={14} /> Access Admin Panel</>}
        </Button>
        <p className="text-xs text-muted-foreground">Default: <code className="text-primary font-mono bg-primary/10 px-1.5 py-0.5 rounded">admin@2024</code></p>

        {/* ── Owner Quick-Access Info ── */}
        <div className="mt-2 rounded-xl bg-muted/40 border border-border p-3 text-left space-y-2">
          <p className="text-[10px] font-bold text-muted-foreground uppercase tracking-wide">🔗 Direct Admin URLs</p>
          <div className="space-y-1">
            {['/admin', '/ghulam-admin-control'].map(path => (
              <div key={path} className="flex items-center gap-1.5">
                <code className="text-[10px] text-primary bg-primary/10 px-1.5 py-0.5 rounded font-mono flex-1 truncate">
                  {typeof window !== 'undefined' ? window.location.origin : ''}
                  {path}
                </code>
              </div>
            ))}
          </div>
          <div className="border-t border-border/50 pt-2 space-y-1">
            <p className="text-[10px] text-muted-foreground"><span className="text-foreground font-semibold">Default Password:</span> admin@2024</p>
            <p className="text-[9px] text-muted-foreground">Change password anytime in Settings → Change Admin Password</p>
          </div>
        </div>
      </div>
    </div>
  );
}

// ─── VIP Purchases Tab ────────────────────────────────────────────────
function VIPTab({ token }: { token: string }) {
  const [data, setData] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [filter, setFilter] = useState('All');
  const [notes, setNotes] = useState<Record<string, string>>({});
  const [busy, setBusy] = useState<string | null>(null);

  const load = useCallback(async () => {
    setLoading(true);
    try {
      const r = await adminGetData({ tab: 'vip', adminToken: token });
      setData((r.data as any[]).sort((a, b) => new Date(b.submittedAt || 0).getTime() - new Date(a.submittedAt || 0).getTime()));
    } catch (e: any) { toast.error(e?.message ?? 'Failed to load'); }
    finally { setLoading(false); }
  }, [token]);

  useEffect(() => { load(); }, [load]);

  const doAction = async (id: string, act: 'approve_vip' | 'reject_vip' | 'revoke_vip') => {
    setBusy(id + act);
    try {
      await adminAction({ action: act, id, data: { notes: notes[id] ?? '' }, adminToken: token });
      const msg = act === 'approve_vip' ? '✅ VIP Approved & activated!' :
                  act === 'revoke_vip'  ? '⚠️ VIP Access Revoked — user locked out immediately!' :
                  '❌ Request rejected';
      toast.success(msg);
      load();
    } catch (e: any) { toast.error(e?.message ?? 'Action failed'); }
    finally { setBusy(null); }
  };

  const counts = { All: data.length, Pending: data.filter(p => p.status === 'Pending').length, Approved: data.filter(p => p.status === 'Approved').length, Rejected: data.filter(p => p.status === 'Rejected').length };
  const filtered = filter === 'All' ? data : data.filter(p => p.status === filter);

  if (loading) return <div className="space-y-2">{[1,2].map(i => <Skeleton key={i} className="h-28 rounded-xl" />)}</div>;

  return (
    <div className="space-y-3">
      <div className="flex items-center gap-2 flex-wrap">
        {(['All', 'Pending', 'Approved', 'Rejected'] as const).map(f => (
          <button key={f} onClick={() => setFilter(f)}
            className={`text-xs px-3 py-1 rounded-full border transition-colors ${filter === f ? 'bg-primary/20 text-primary border-primary/40' : 'border-border text-muted-foreground hover:text-foreground'}`}>
            {f} ({counts[f]})
          </button>
        ))}
        <button onClick={load} className="ml-auto flex items-center gap-1 text-xs text-muted-foreground hover:text-foreground"><RefreshCw size={11} /> Refresh</button>
      </div>

      {filtered.length === 0 && <div className="text-center py-12 text-muted-foreground"><Crown size={28} className="mx-auto mb-2 opacity-30" /><p className="text-sm">No requests found</p></div>}

      {filtered.map((p: any) => (
        <div key={p.id} className="card-dark rounded-xl p-4 space-y-2.5">
          <div className="flex justify-between items-start gap-2">
            <div className="min-w-0 flex-1">
              <p className="text-sm font-semibold truncate">{p.userEmail}</p>
              <p className="text-xs text-muted-foreground">{p.planName} · <span className="text-primary font-bold">${p.amountUsd}</span> · {p.paymentMethod}</p>
              <p className="text-xs text-muted-foreground">{p.submittedAt ? new Date(p.submittedAt).toLocaleString() : ''}</p>
            </div>
            <StatusBadge s={p.status} />
          </div>
          {p.tidOrHash && (
            <div className="bg-muted/50 rounded-lg px-3 py-2">
              <p className="text-[10px] text-muted-foreground uppercase tracking-wide mb-0.5">TID / Hash</p>
              <p className="text-xs font-mono select-all break-all">{p.tidOrHash}</p>
            </div>
          )}
          {p.sendingAddress && <p className="text-xs text-muted-foreground">📤 Sent from: <span className="font-mono">{p.sendingAddress}</span></p>}
          {p.paymentScreenshot?.[0]?.url && (
            <a href={p.paymentScreenshot[0].url} target="_blank" rel="noreferrer" className="block rounded-lg overflow-hidden border border-border">
              <img src={p.paymentScreenshot[0].url} alt="Payment proof" className="w-full max-h-48 object-contain bg-muted/30" />
              <p className="text-xs text-primary text-center py-1 bg-muted/20">🔍 Tap to view full size</p>
            </a>
          )}
          {p.adminNotes && <div className="bg-muted/30 rounded-lg px-3 py-1.5 text-xs text-muted-foreground">📝 {p.adminNotes}</div>}
          {/* ── Post-Approval Revocation Power ── */}
          {p.status === 'Approved' && (
            <div className="pt-2 border-t border-border/50 space-y-1.5">
              <div className="flex items-center gap-2 bg-destructive/5 border border-destructive/20 rounded-lg px-2.5 py-1.5">
                <AlertTriangle size={11} className="text-destructive shrink-0" />
                <p className="text-[10px] text-muted-foreground">Admin Override — revoke even after approval</p>
              </div>
              <Input placeholder="Reason for revocation (optional)..." value={notes[p.id] ?? ''} onChange={e => setNotes(n => ({ ...n, [p.id]: e.target.value }))} className="bg-muted border-border text-xs h-8" />
              <Button size="sm" variant="destructive" onClick={() => doAction(p.id, 'revoke_vip')} disabled={busy === p.id + 'revoke_vip'} className="w-full gap-1 text-xs h-9">
                {busy === p.id + 'revoke_vip' ? <Loader2 size={12} className="animate-spin" /> : <X size={12} />} ⚠️ Revoke VIP Access Now
              </Button>
              <p className="text-[9px] text-muted-foreground text-center">Immediately removes user's VIP — status updates live on their screen</p>
            </div>
          )}
          {p.status === 'Pending' && (
            <div className="space-y-2 pt-1 border-t border-border/50">
              <Input placeholder="Admin note (optional)..." value={notes[p.id] ?? ''} onChange={e => setNotes(n => ({ ...n, [p.id]: e.target.value }))} className="bg-muted border-border text-xs h-8" />
              <div className="grid grid-cols-2 gap-2">
                <Button size="sm" onClick={() => doAction(p.id, 'approve_vip')} disabled={busy === p.id + 'approve_vip'} className="bg-green-600 hover:bg-green-600/90 text-white gap-1 text-xs h-9">
                  <Check size={12} /> Approve VIP
                </Button>
                <Button size="sm" variant="destructive" onClick={() => doAction(p.id, 'reject_vip')} disabled={busy === p.id + 'reject_vip'} className="gap-1 text-xs h-9">
                  <X size={12} /> Reject
                </Button>
              </div>
            </div>
          )}
        </div>
      ))}
    </div>
  );
}

// ─── Withdrawals Tab ──────────────────────────────────────────────────
function WithdrawalsTab({ token }: { token: string }) {
  const [data, setData] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [filter, setFilter] = useState('All');
  const [busy, setBusy] = useState<string | null>(null);
  const [copiedId, setCopiedId] = useState<string | null>(null);

  const load = useCallback(async () => {
    setLoading(true);
    try {
      const r = await adminGetData({ tab: 'withdrawals', adminToken: token });
      setData((r.data as any[]).sort((a, b) => new Date(b.requestedAt || 0).getTime() - new Date(a.requestedAt || 0).getTime()));
    } catch (e: any) { toast.error(e?.message); }
    finally { setLoading(false); }
  }, [token]);

  useEffect(() => { load(); }, [load]);

  const doAction = async (id: string, act: string) => {
    setBusy(id + act);
    try {
      await adminAction({ action: act, id, adminToken: token });
      const msg = act === 'approve_withdrawal' ? '✅ Marked as paid' :
                  act === 'hold_withdrawal' ? '⏸️ Request put on Hold' :
                  act === 'restore_withdrawal' ? '↩️ Restored to Pending' :
                  act === 'revoke_withdrawal' ? '⚠️ Revoked! Balance instantly refunded to user wallet.' :
                  '❌ Rejected & refunded';
      toast.success(msg);
      load();
    } catch (e: any) { toast.error(e?.message ?? 'Action failed'); }
    finally { setBusy(null); }
  };

  const copyText = (text: string, uid: string) => {
    navigator.clipboard.writeText(text).then(() => {
      setCopiedId(uid); toast.success('Copied!');
      setTimeout(() => setCopiedId(null), 2000);
    });
  };

  const counts = {
    All: data.length,
    Pending: data.filter(p => p.status === 'Pending').length,
    Approved: data.filter(p => p.status === 'Approved').length,
    Rejected: data.filter(p => p.status === 'Rejected').length,
    Hold: data.filter(p => p.status === 'Hold').length,
  };
  const filtered = filter === 'All' ? data : data.filter(p => p.status === filter);

  if (loading) return <div className="space-y-2">{[1,2].map(i => <Skeleton key={i} className="h-12 rounded-xl" />)}</div>;

  return (
    <div className="space-y-3">
      <div className="flex items-center justify-between">
        <p className="text-sm font-bold">📋 Withdrawal Requests</p>
        <button onClick={load} className="flex items-center gap-1 text-xs text-muted-foreground hover:text-foreground"><RefreshCw size={11} /> Refresh</button>
      </div>
      <div className="flex items-center gap-1.5 flex-wrap">
        {(['All', 'Pending', 'Approved', 'Rejected', 'Hold'] as const).map(f => (
          <button key={f} onClick={() => setFilter(f)}
            className={`text-xs px-2.5 py-1 rounded-full border transition-colors ${filter === f ? 'bg-primary/20 text-primary border-primary/40' : 'border-border text-muted-foreground hover:text-foreground'}`}>
            {f} <span className="opacity-70">({counts[f]})</span>
          </button>
        ))}
      </div>

      {filtered.length === 0 && (
        <div className="text-center py-10 text-muted-foreground">
          <Banknote size={28} className="mx-auto mb-2 opacity-30" /><p className="text-sm">No withdrawal requests</p>
        </div>
      )}

      {filtered.length > 0 && (
        <div className="overflow-x-auto rounded-xl border border-border">
          <table className="w-full min-w-[720px] text-xs">
            <thead>
              <tr className="bg-muted/50 border-b border-border">
                {['User ID / Email', 'Gateway', 'Account Title', 'Account No.', 'Amount', 'Date', 'Status', 'Actions'].map(h => (
                  <th key={h} className="text-left px-3 py-2.5 font-semibold text-muted-foreground whitespace-nowrap">{h}</th>
                ))}
              </tr>
            </thead>
            <tbody>
              {filtered.map((w: any, idx: number) => (
                <tr key={w.id} className={`border-b border-border/40 ${idx % 2 === 0 ? '' : 'bg-muted/10'}`}>
                  <td className="px-3 py-2.5 max-w-[140px]">
                    <p className="font-medium truncate">{w.userEmail}</p>
                    <p className="text-[9px] text-muted-foreground font-mono truncate">{w.id?.slice(0, 12)}...</p>
                  </td>
                  <td className="px-3 py-2.5 whitespace-nowrap">
                    <span className="bg-muted border border-border rounded-full px-2 py-0.5 text-[10px] font-semibold">{w.method}</span>
                  </td>
                  <td className="px-3 py-2.5 font-medium">{w.accountName || '—'}</td>
                  <td className="px-3 py-2.5">
                    <div className="flex items-center gap-1">
                      <span className="font-mono">{w.accountNumber || '—'}</span>
                      {w.accountNumber && (
                        <button onClick={() => copyText(w.accountNumber, w.id + '_num')}
                          className={`p-1 rounded transition-colors shrink-0 ${copiedId === w.id + '_num' ? 'text-primary' : 'text-muted-foreground hover:text-foreground'}`}>
                          {copiedId === w.id + '_num' ? <Check size={10} /> : <Copy size={10} />}
                        </button>
                      )}
                    </div>
                  </td>
                  <td className="px-3 py-2.5 whitespace-nowrap">
                    <span className="font-bold text-green-400">${(w.amountUsd ?? 0).toFixed(2)}</span>
                  </td>
                  <td className="px-3 py-2.5 text-muted-foreground whitespace-nowrap text-[10px]">
                    {w.requestedAt ? new Date(w.requestedAt).toLocaleDateString('en-PK', { day: '2-digit', month: 'short' }) : '—'}
                    {w.requestedAt && <><br />{new Date(w.requestedAt).toLocaleTimeString('en-PK', { hour: '2-digit', minute: '2-digit' })}</>}
                  </td>
                  <td className="px-3 py-2.5"><StatusBadge s={w.status} /></td>
                  <td className="px-3 py-2.5">
                    {w.status === 'Pending' && (
                      <div className="flex flex-col gap-1">
                        <Button size="sm" onClick={() => doAction(w.id, 'approve_withdrawal')} disabled={!!busy}
                          className="h-6 text-[10px] px-2 bg-green-600 hover:bg-green-600/90 text-white gap-1 whitespace-nowrap">
                          <Check size={9} /> Approve
                        </Button>
                        <Button size="sm" variant="destructive" onClick={() => doAction(w.id, 'reject_withdrawal')} disabled={!!busy}
                          className="h-6 text-[10px] px-2 gap-1 whitespace-nowrap">
                          <X size={9} /> Reject
                        </Button>
                        <Button size="sm" onClick={() => doAction(w.id, 'hold_withdrawal')} disabled={!!busy}
                          className="h-6 text-[10px] px-2 bg-yellow-600 hover:bg-yellow-600/90 text-white gap-1 whitespace-nowrap">
                          <Pause size={9} /> Hold
                        </Button>
                      </div>
                    )}
                    {w.status === 'Hold' && (
                      <div className="flex flex-col gap-1">
                        <Button size="sm" onClick={() => doAction(w.id, 'restore_withdrawal')} disabled={!!busy}
                          className="h-6 text-[10px] px-2 bg-blue-600 hover:bg-blue-600/90 text-white gap-1 whitespace-nowrap">
                          <Play size={9} /> Restore
                        </Button>
                        <Button size="sm" variant="destructive" onClick={() => doAction(w.id, 'reject_withdrawal')} disabled={!!busy}
                          className="h-6 text-[10px] px-2 gap-1 whitespace-nowrap">
                          <X size={9} /> Reject
                        </Button>
                      </div>
                    )}
                    {w.status === 'Approved' && (
                      <div className="flex flex-col gap-1">
                        <span className="text-[10px] text-green-400 font-bold">✓ Paid</span>
                        <Button size="sm" variant="destructive" onClick={() => doAction(w.id, 'revoke_withdrawal')} disabled={!!busy}
                          className="h-6 text-[10px] px-2 gap-0.5 whitespace-nowrap">
                          <X size={9} /> Revoke
                        </Button>
                      </div>
                    )}
                    {w.status === 'Rejected' && (
                      <span className="text-[10px] text-muted-foreground italic">Rejected</span>
                    )}
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}
    </div>
  );
}

// ─── Milestone Tier Helper ────────────────────────────────────────────
function getMilestoneTier(level: number): { name: string; color: string; emoji: string } {
  if (level >= 46) return { name: 'Diamond',  color: 'text-blue-400',         emoji: '💎' };
  if (level >= 36) return { name: 'Platinum', color: 'text-cyan-400',         emoji: '🌊' };
  if (level >= 26) return { name: 'Gold',     color: 'text-yellow-400',       emoji: '🥇' };
  if (level >= 16) return { name: 'Silver',   color: 'text-gray-300',         emoji: '🥈' };
  if (level >= 6)  return { name: 'Bronze',   color: 'text-orange-400',       emoji: '🥉' };
  return             { name: 'Starter',  color: 'text-muted-foreground', emoji: '🌱' };
}

// ─── Mini VIP Countdown (for Admin Users Tab) ─────────────────────────
function MiniVipCountdown({ expiresAt }: { expiresAt: string }) {
  const calc = () => {
    const ms = new Date(expiresAt).getTime() - Date.now();
    if (ms <= 0) return null;
    const d = Math.floor(ms / 86400000);
    const h = Math.floor((ms % 86400000) / 3600000);
    const m = Math.floor((ms % 3600000) / 60000);
    const s = Math.floor((ms % 60000) / 1000);
    return { d, h, m, s };
  };
  const [t, setT] = useState(calc);
  useEffect(() => {
    const id = setInterval(() => setT(calc()), 1000);
    return () => clearInterval(id);
  }, [expiresAt]);
  if (!t) return (
    <div className="text-[9px] text-destructive font-bold flex items-center gap-0.5">
      <Timer size={8} /> EXPIRED
    </div>
  );
  const pad = (n: number) => String(n).padStart(2, '0');
  return (
    <div className="flex items-center gap-1 text-[9px] text-primary font-mono">
      <Timer size={8} className="shrink-0" />
      <span>{t.d}d {pad(t.h)}:{pad(t.m)}:{pad(t.s)}</span>
    </div>
  );
}

// ─── Users Tab ────────────────────────────────────────────────────────
function UsersTab({ token }: { token: string }) {
  const { usdToPkr } = useAppData();
  const [data, setData] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState('');
  const [viewMode, setViewMode] = useState<'cards' | 'table'>('cards');
  type EditState = { usdBalance: string; coins: string; level: string; marginPercent: string; pkrAdjust: string; pkrMode: 'add' | 'deduct' };
  const [editing, setEditing] = useState<Record<string, EditState>>({});
  const [saving, setSaving] = useState<string | null>(null);
  const [expandedReferrals, setExpandedReferrals] = useState<string | null>(null);

  const load = useCallback(async () => {
    setLoading(true);
    try {
      const r = await adminGetData({ tab: 'users', adminToken: token });
      setData(r.data as any[]);
    } catch (e: any) { toast.error(e?.message); }
    finally { setLoading(false); }
  }, [token]);

  useEffect(() => { load(); }, [load]);

  const startEdit = (u: any) => setEditing(e => ({
    ...e,
    [u.id]: {
      usdBalance: String(u.usdBalance ?? 0),
      coins: String(u.coins ?? 0),
      level: String(u.level ?? 1),
      marginPercent: String(u.marginPercent ?? 0),
      pkrAdjust: '',
      pkrMode: 'add',
    },
  }));
  const cancelEdit = (id: string) => setEditing(e => { const c = { ...e }; delete c[id]; return c; });

  const saveUser = async (id: string) => {
    const ed = editing[id];
    if (!ed) return;
    setSaving(id);
    try {
      await adminAction({
        action: 'update_user',
        id,
        data: {
          usdBalance: parseFloat(ed.usdBalance) || 0,
          pkrAdjust: ed.pkrAdjust ? ed.pkrAdjust : undefined,
          pkrMode: ed.pkrMode,
          usdToPkr: String(usdToPkr),
          coins: parseFloat(ed.coins) || 0,
          level: parseInt(ed.level) || 1,
          marginPercent: parseFloat(ed.marginPercent) || 0,
        },
        adminToken: token,
      });
      toast.success('✅ User updated!');
      cancelEdit(id);
      load();
    } catch (e: any) { toast.error(e?.message); }
    finally { setSaving(null); }
  };

  const filtered = data.filter(u =>
    !search ||
    u.email?.toLowerCase().includes(search.toLowerCase()) ||
    u.name?.toLowerCase().includes(search.toLowerCase()) ||
    u.phone?.includes(search) ||
    u.deviceId?.toLowerCase().includes(search.toLowerCase())
  );

  const totalUSD = data.reduce((s, u) => s + (u.usdBalance ?? 0), 0);
  const vipCount = data.filter(u => u.vipStatus === 'VIP').length;

  if (loading) return <div className="space-y-2">{[1,2,3].map(i => <Skeleton key={i} className="h-16 rounded-xl" />)}</div>;

  return (
    <div className="space-y-3">
      {/* Stats Bar */}
      <div className="grid grid-cols-3 gap-2">
        <div className="bg-muted/40 border border-border rounded-xl p-2 text-center">
          <p className="text-sm font-black text-primary">{data.length}</p>
          <p className="text-[9px] text-muted-foreground">Total Users</p>
        </div>
        <div className="bg-muted/40 border border-border rounded-xl p-2 text-center">
          <p className="text-sm font-black text-yellow-400">{vipCount}</p>
          <p className="text-[9px] text-muted-foreground">VIP Members</p>
        </div>
        <div className="bg-muted/40 border border-border rounded-xl p-2 text-center">
          <p className="text-sm font-black text-green-400">{totalUSD.toFixed(2)}</p>
          <p className="text-[9px] text-muted-foreground">Total USD</p>
        </div>
      </div>

      <div className="flex items-center gap-2">
        <div className="relative flex-1">
          <Search size={13} className="absolute left-3 top-1/2 -translate-y-1/2 text-muted-foreground" />
          <Input placeholder="Search name, email, phone, device ID..." value={search} onChange={e => setSearch(e.target.value)} className="bg-muted border-border text-sm pl-8 h-9" />
        </div>
        <div className="flex border border-border rounded-lg overflow-hidden shrink-0">
          <button onClick={() => setViewMode('cards')} className={`text-[10px] px-2 py-1 font-bold transition-colors ${viewMode === 'cards' ? 'bg-primary text-primary-foreground' : 'bg-muted text-muted-foreground'}`}>Cards</button>
          <button onClick={() => setViewMode('table')} className={`text-[10px] px-2 py-1 font-bold transition-colors ${viewMode === 'table' ? 'bg-primary text-primary-foreground' : 'bg-muted text-muted-foreground'}`}>Table</button>
        </div>
        <button onClick={load} className="flex items-center gap-1 text-xs text-muted-foreground hover:text-foreground shrink-0"><RefreshCw size={11} /></button>
      </div>
      <p className="text-xs text-muted-foreground">{filtered.length} of {data.length} users</p>

      {/* TABLE VIEW */}
      {viewMode === 'table' && (
        <div className="overflow-x-auto rounded-xl border border-border">
          <table className="w-full min-w-[800px] text-xs">
            <thead>
              <tr className="bg-muted/50 border-b border-border">
                {['Name / ID', 'Email', 'Phone', 'Device ID', 'USD Balance', 'Level / Tier', 'Referrals', 'VIP / Timer', 'Status', 'Joined'].map(h => (
                  <th key={h} className="text-left px-3 py-2.5 font-semibold text-muted-foreground whitespace-nowrap">{h}</th>
                ))}
              </tr>
            </thead>
            <tbody>
              {filtered.map((u: any, idx: number) => {
                const tier = getMilestoneTier(u.level ?? 1);
                return (
                  <tr key={u.id} className={`border-b border-border/40 ${idx % 2 === 0 ? '' : 'bg-muted/10'}`}>
                    <td className="px-3 py-2.5">
                      <p className="font-medium">{u.name || '—'}</p>
                      <p className="text-[9px] text-muted-foreground font-mono">{u.id?.slice(0, 14)}...</p>
                    </td>
                    <td className="px-3 py-2.5 max-w-[160px]"><p className="truncate">{u.email}</p></td>
                    <td className="px-3 py-2.5 font-mono whitespace-nowrap">{u.phone || '—'}</td>
                    <td className="px-3 py-2.5">
                      <span className="text-[9px] font-mono text-primary">{u.deviceId || '—'}</span>
                    </td>
                    <td className="px-3 py-2.5 whitespace-nowrap">
                      <span className="text-green-400 font-bold">${(u.usdBalance ?? 0).toFixed(2)}</span>
                    </td>
                    <td className="px-3 py-2.5 whitespace-nowrap">
                      <div className="flex items-center gap-1">
                        <span className={`font-bold ${tier.color}`}>{tier.emoji} L{u.level ?? 1}</span>
                        <span className={`text-[9px] ${tier.color}`}>{tier.name}</span>
                      </div>
                    </td>
                    <td className="px-3 py-2.5 text-center font-bold">{u.totalReferrals ?? 0}</td>
                    <td className="px-3 py-2.5">
                      <StatusBadge s={u.vipStatus ?? 'Free'} />
                      {u.vipStatus === 'VIP' && u.vipExpiresAt && new Date(u.vipExpiresAt).getFullYear() !== 1970 && (
                        <div className="mt-0.5"><MiniVipCountdown expiresAt={u.vipExpiresAt} /></div>
                      )}
                    </td>
                    <td className="px-3 py-2.5">
                      <div className="flex flex-col gap-1">
                        {u.status === 'Blocked' ? (
                          <span className="text-[9px] font-bold text-destructive">🚫 Blocked</span>
                        ) : (
                          <span className="text-[9px] font-bold text-green-400">✅ Active</span>
                        )}
                        {u.wrongPromptCount > 0 && (
                          <span className="text-[8px] text-yellow-400">⚠️ {u.wrongPromptCount}</span>
                        )}
                      </div>
                    </td>
                    <td className="px-3 py-2.5 text-muted-foreground whitespace-nowrap text-[10px]">
                      {u.joinedAt ? new Date(u.joinedAt).toLocaleDateString('en-PK', { day: '2-digit', month: 'short', year: '2-digit' }) : '—'}
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      )}

      {/* CARDS VIEW */}
      {viewMode === 'cards' && filtered.map((u: any) => {
        const ed = editing[u.id];
        const pkrEquiv = (u.usdBalance ?? 0) * usdToPkr;
        const tier = getMilestoneTier(u.level ?? 1);
        return (
          <div key={u.id} className="card-dark rounded-xl p-3 space-y-2">
            <div className="flex items-center justify-between gap-2">
              <div className="min-w-0 flex-1">
                <div className="flex items-center gap-2 flex-wrap">
                  <p className="text-sm font-semibold truncate">{u.name || '(no name)'}</p>
                  <span className={`text-[10px] font-bold ${tier.color}`}>{tier.emoji} {tier.name}</span>
                </div>
                <p className="text-xs text-muted-foreground truncate">{u.email}</p>
                {u.phone && (
                  <p className="text-[10px] text-muted-foreground flex items-center gap-1">
                    <Phone size={9} /> {u.phone}
                  </p>
                )}
                <div className="flex items-center gap-2 flex-wrap mt-0.5">
                  <p className="text-[9px] text-muted-foreground font-mono">ID: {u.id?.slice(0, 16)}...</p>
                  {u.deviceId && (
                    <p className="text-[9px] text-primary font-mono flex items-center gap-0.5">
                      <Smartphone size={8} /> {u.deviceId}
                    </p>
                  )}
                </div>
              </div>
              <div className="flex flex-col items-end gap-1.5 shrink-0">
                <StatusBadge s={u.vipStatus ?? 'Free'} />
                {u.vipStatus === 'VIP' && u.vipExpiresAt && new Date(u.vipExpiresAt).getFullYear() !== 1970 && (
                  <MiniVipCountdown expiresAt={u.vipExpiresAt} />
                )}
                {/* Block/Unblock Status */}
                {u.status === 'Blocked' ? (
                  <span className="text-[9px] font-bold bg-destructive/15 text-destructive border border-destructive/30 px-2 py-0.5 rounded-full">🚫 BLOCKED</span>
                ) : (
                  <span className="text-[9px] font-bold bg-green-500/15 text-green-400 border border-green-500/30 px-2 py-0.5 rounded-full">✅ Active</span>
                )}
                {u.wrongPromptCount > 0 && (
                  <span className="text-[9px] text-yellow-400">⚠️ Wrong: {u.wrongPromptCount}</span>
                )}
                {!ed ? (
                  <button onClick={() => startEdit(u)} className="text-xs text-primary hover:underline">Edit</button>
                ) : (
                  <div className="flex gap-1.5">
                    <button onClick={() => saveUser(u.id)} disabled={saving === u.id} className="text-xs text-green-400 hover:underline disabled:opacity-50">{saving === u.id ? 'Saving...' : 'Save'}</button>
                    <button onClick={() => cancelEdit(u.id)} className="text-xs text-muted-foreground hover:underline">Cancel</button>
                  </div>
                )}
              </div>
            </div>
            {!ed ? (
              <>
                <div className="grid grid-cols-3 gap-2 bg-muted/30 rounded-xl p-2">
                  <div className="text-center">
                    <p className="text-green-400 font-bold text-xs">${(u.usdBalance ?? 0).toFixed(2)}</p>
                    <p className="text-[9px] text-muted-foreground">~Rs.{Math.round(pkrEquiv).toLocaleString()}</p>
                  </div>
                  <div className="text-center">
                    <p className="text-primary font-bold text-xs">Lv.{u.level ?? 1}</p>
                    <p className="text-[9px] text-muted-foreground">🪙{u.coins ?? 0}</p>
                  </div>
                  <div className="text-center">
                    <button
                      onClick={() => setExpandedReferrals(expandedReferrals === u.id ? null : u.id)}
                      className="w-full hover:opacity-80 transition-opacity"
                    >
                      <p className="text-secondary font-bold text-xs flex items-center justify-center gap-0.5">
                        {u.totalReferrals ?? 0}
                        <GitBranch size={9} className="text-secondary" />
                      </p>
                      <p className="text-[9px] text-primary underline">View History</p>
                    </button>
                  </div>
                </div>
                {expandedReferrals === u.id && (
                  <UserReferralHistory token={token} userEmail={u.email ?? ''} />
                )}
                {/* Block / Unblock Buttons */}
                <div className="flex gap-2 mt-1">
                  {u.status !== 'Blocked' ? (
                    <button
                      onClick={async () => {
                        setSaving(u.id + '_block');
                        try {
                          await adminAction({ action: 'block_user', id: u.id, adminToken: token });
                          toast.success('🚫 User blocked instantly!');
                          load();
                        } catch (e: any) { toast.error(e?.message ?? 'Failed'); }
                        finally { setSaving(null); }
                      }}
                      disabled={saving === u.id + '_block'}
                      className="flex-1 h-8 rounded-lg bg-destructive/20 text-destructive border border-destructive/30 text-[10px] font-bold hover:bg-destructive/30 transition-colors flex items-center justify-center gap-1"
                    >
                      {saving === u.id + '_block' ? '...' : '🚫 Block User'}
                    </button>
                  ) : (
                    <button
                      onClick={async () => {
                        setSaving(u.id + '_unblock');
                        try {
                          await adminAction({ action: 'unblock_user', id: u.id, adminToken: token });
                          toast.success('✅ User unblocked! Wrong prompt count reset to 0.');
                          load();
                        } catch (e: any) { toast.error(e?.message ?? 'Failed'); }
                        finally { setSaving(null); }
                      }}
                      disabled={saving === u.id + '_unblock'}
                      className="flex-1 h-8 rounded-lg bg-green-600/20 text-green-400 border border-green-500/30 text-[10px] font-bold hover:bg-green-600/30 transition-colors flex items-center justify-center gap-1"
                    >
                      {saving === u.id + '_unblock' ? '...' : '✅ Unblock User'}
                    </button>
                  )}
                </div>
              </>
            ) : (
              <div className="space-y-3 pt-1">
                {/* USD + Coins + Level row */}
                <div className="grid grid-cols-3 gap-2">
                  {[
                    { key: 'usdBalance', label: '💵 USD Balance' },
                    { key: 'coins', label: '🪙 Coins' },
                    { key: 'level', label: '📈 Level' },
                  ].map(({ key, label }) => (
                    <div key={key} className="space-y-0.5">
                      <Label className="text-[10px] text-muted-foreground">{label}</Label>
                      <Input value={ed[key as keyof EditState] as string}
                        onChange={e => setEditing(prev => ({ ...prev, [u.id]: { ...prev[u.id], [key]: e.target.value } }))}
                        className="bg-muted border-border h-7 text-xs" type="number" step="0.01" />
                    </div>
                  ))}
                </div>

                {/* PKR Adjustment */}
                <div className="bg-muted/40 rounded-xl p-2.5 space-y-2">
                  <Label className="text-[10px] text-muted-foreground">
                    Rs. PKR Balance Adjustment (rate: {usdToPkr})
                  </Label>
                  <div className="flex gap-2">
                    <div className="flex rounded-lg overflow-hidden border border-border shrink-0">
                      <button
                        onClick={() => setEditing(prev => ({ ...prev, [u.id]: { ...prev[u.id], pkrMode: 'add' } }))}
                        className={`px-2.5 py-1 text-[10px] font-bold transition-colors ${ed.pkrMode === 'add' ? 'bg-green-600 text-white' : 'bg-muted text-muted-foreground'}`}>
                        + Add
                      </button>
                      <button
                        onClick={() => setEditing(prev => ({ ...prev, [u.id]: { ...prev[u.id], pkrMode: 'deduct' } }))}
                        className={`px-2.5 py-1 text-[10px] font-bold transition-colors ${ed.pkrMode === 'deduct' ? 'bg-destructive text-white' : 'bg-muted text-muted-foreground'}`}>
                        − Deduct
                      </button>
                    </div>
                    <Input
                      value={ed.pkrAdjust}
                      onChange={e => setEditing(prev => ({ ...prev, [u.id]: { ...prev[u.id], pkrAdjust: e.target.value } }))}
                      placeholder="Amount in PKR (e.g. 500)"
                      className="bg-muted border-border h-7 text-xs flex-1" type="number" min="0" step="1"
                    />
                  </div>
                  {ed.pkrAdjust && parseFloat(ed.pkrAdjust) > 0 && (
                    <p className="text-[10px] text-primary">
                      = {(parseFloat(ed.pkrAdjust) / usdToPkr).toFixed(4)} USD will be {ed.pkrMode === 'add' ? 'added to' : 'deducted from'} balance
                    </p>
                  )}
                </div>

                {/* Margin % */}
                <div className="space-y-0.5">
                  <Label className="text-[10px] text-muted-foreground">📊 Profit Margin % (personal rate)</Label>
                  <Input
                    value={ed.marginPercent}
                    onChange={e => setEditing(prev => ({ ...prev, [u.id]: { ...prev[u.id], marginPercent: e.target.value } }))}
                    className="bg-muted border-border h-7 text-xs" type="number" step="0.01" min="0" max="100"
                    placeholder="e.g. 15"
                  />
                </div>
              </div>
            )}
          </div>
        );
      })}
    </div>
  );
}

// ─── System Initialize Section ───────────────────────────────────────
function SystemInitSection({ token }: { token: string }) {
  const [loading, setLoading] = useState(false);
  type GatewayInfo = { name: string; status: string; synced: boolean };
  type SeedResult = { success: boolean; seeded: Record<string, number>; skipped: Record<string, number>; message: string; nextStep?: string; gatewayStatus?: GatewayInfo[] };
  const [result, setResult] = useState<SeedResult | null>(null);

  const runSeed = async () => {
    setLoading(true);
    try {
      const res = await seedDatabase({ adminToken: token });
      setResult(res as SeedResult);
      const total = Object.values(res.seeded).reduce((a, b) => a + b, 0);
      if (total === 0) toast.info('ℹ️ Database already fully initialized — nothing to seed');
      else toast.success('🚀 System initialized! ' + total + ' records seeded — all 5 modules connected');
      if ((res as any).nextStep) toast.info((res as any).nextStep);
    } catch (e: any) {
      toast.error(e?.message ?? 'Initialization failed');
    } finally { setLoading(false); }
  };

  const total = result ? Object.values(result.seeded).reduce((a, b) => a + b, 0) : -1;

  return (
    <div className="rounded-2xl border-2 border-primary/40 bg-primary/5 p-4 space-y-3">
      {/* Header */}
      <div className="flex items-center gap-2">
        <div className="w-8 h-8 rounded-xl bg-primary/15 border border-primary/30 flex items-center justify-center shrink-0">
          <Zap size={16} className="text-primary" />
        </div>
        <div>
          <p className="font-black text-sm text-foreground">🚀 Initialize System</p>
          <p className="text-[10px] text-muted-foreground">One-click setup for new deployment — seeds all default data</p>
        </div>
        {result && (
          <span className={`ml-auto text-[9px] font-bold px-2 py-1 rounded-full border ${total === 0 ? 'bg-muted text-muted-foreground border-border' : 'bg-green-500/15 text-green-400 border-green-500/30'}`}>
            {total === 0 ? 'READY' : `+${total} SEEDED`}
          </span>
        )}
      </div>

      {/* What will be seeded */}
      <div className="grid grid-cols-2 gap-1.5">
        {[
          { icon: '👑', label: '7 VIP Plans', sub: 'Starter → Lifetime' },
          { icon: '📈', label: '5 Level Configs', sub: 'L1 Starter → L5 Diamond' },
          { icon: '⚙️', label: '39 Default Settings', sub: 'AI keys + all 5 modules wired' },
          { icon: '📢', label: '4 News Tickers', sub: 'Welcome messages' },
          { icon: '🎬', label: '3 Video Gateways', sub: 'HuggingFace → Stability → Veo' },
          { icon: '🔄', label: 'Self-Healing', sub: 'Auto-creates missing rows' },
        ].map(item => (
          <div key={item.label} className="flex items-start gap-2 bg-muted/40 border border-border rounded-xl px-2.5 py-2">
            <span className="text-sm shrink-0">{item.icon}</span>
            <div className="min-w-0">
              <p className="text-[10px] font-bold truncate">{item.label}</p>
              <p className="text-[9px] text-muted-foreground truncate">{item.sub}</p>
            </div>
          </div>
        ))}
      </div>

      {/* Result summary */}
      {result && (
        <div className={`rounded-xl border px-3 py-2.5 text-xs space-y-1 ${total === 0 ? 'border-border bg-muted/30 text-muted-foreground' : 'border-green-500/30 bg-green-950/20 text-green-400'}`}>
          <p className="font-bold">{result.message}</p>
          {result.nextStep && (
            <p className="text-yellow-300 font-semibold text-[10px] mt-1">{result.nextStep}</p>
          )}
          {total > 0 && (
            <div className="grid grid-cols-5 gap-1 mt-1">
              {Object.entries(result.seeded).map(([k, v]) => (
                <div key={k} className="text-center">
                  <p className="text-sm font-black text-green-400">{v}</p>
                  <p className="text-[8px] text-muted-foreground capitalize">{k.replace(/([A-Z])/g, ' $1')}</p>
                </div>
              ))}
            </div>
          )}
          {/* Gateway sync status */}
          {result.gatewayStatus && result.gatewayStatus.length > 0 && (
            <div className="mt-2 space-y-1 border-t border-border/40 pt-2">
              <p className="text-[10px] font-bold text-foreground">🎬 Video Gateway Status:</p>
              {result.gatewayStatus.map(g => (
                <div key={g.name} className="flex items-center gap-2">
                  <span className={`w-2 h-2 rounded-full shrink-0 ${g.synced ? 'bg-green-500' : 'bg-yellow-500'}`} />
                  <span className="text-[10px] font-semibold flex-1">{g.name}</span>
                  <span className={`text-[9px] ${g.synced ? 'text-green-400' : 'text-yellow-400'}`}>{g.status}</span>
                </div>
              ))}
            </div>
          )}
        </div>
      )}

      <Button onClick={runSeed} disabled={loading}
        className="w-full bg-primary text-primary-foreground font-bold h-10 gap-2 text-sm">
        {loading ? <><Loader2 size={15} className="animate-spin" /> Initializing Database...</> : <><Zap size={15} /> Initialize System Now</>}
      </Button>

      <p className="text-[9px] text-muted-foreground text-center">
        Safe to run multiple times — only missing records are created, existing data is never overwritten
      </p>
    </div>
  );
}

// ─── AI Name Section ──────────────────────────────────────────────────
function AINameSection({ cfg, setCfg, saving, save }: { cfg: Record<string, string>; setCfg: any; saving: string | null; save: (k: string, d: string, v?: string) => void }) {
  const [justSaved, setJustSaved] = useState(false);

  const handleSave = async () => {
    await save('ai_name', 'AI display name');
    setJustSaved(true);
    setTimeout(() => setJustSaved(false), 2500);
  };

  const currentName = cfg['ai_name'] ?? 'Hussain AI - Master Engine';

  return (
    <div className="rounded-2xl border-2 border-primary/40 bg-primary/5 p-4 space-y-3">
      {/* Header */}
      <div className="flex items-center gap-2">
        <div className="w-8 h-8 rounded-xl bg-primary/15 border border-primary/30 flex items-center justify-center shrink-0">
          <Bot size={16} className="text-primary" />
        </div>
        <div className="flex-1 min-w-0">
          <p className="font-black text-sm">🤖 AI Identity & Branding</p>
          <p className="text-[10px] text-muted-foreground">Global AI name — updates live across all sections instantly</p>
        </div>
        {justSaved && (
          <span className="text-[9px] font-bold bg-green-500/15 text-green-400 border border-green-500/30 px-2 py-0.5 rounded-full flex items-center gap-0.5 shrink-0">
            <Check size={8} /> Updated!
          </span>
        )}
      </div>

      {/* Editable input — fully open, no locks */}
      <div className="space-y-1.5">
