// ─── Ticker Manager ────────────────────────────────────────────────────
function TickerManager({ token }: { token: string }) {
  const { refresh: refreshAppData } = useAppData();
  const [tickers, setTickers] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [newText, setNewText] = useState('');
  const [adding, setAdding] = useState(false);
  const [deleting, setDeleting] = useState<string | null>(null);

  const load = useCallback(async () => {
    setLoading(true);
    try {
      const r = await adminGetData({ tab: 'tickers', adminToken: token });
      setTickers((r.data as any[]).sort((a, b) => (a.sortOrder ?? 0) - (b.sortOrder ?? 0)));
    } catch (e: any) { toast.error(e?.message ?? 'Failed to load'); }
    finally { setLoading(false); }
  }, [token]);

  useEffect(() => { load(); }, [load]);

  const addTicker = async () => {
    if (!newText.trim()) return;
    setAdding(true);
    try {
      await adminAction({ action: 'save_ticker', data: { content: newText.trim(), isActive: true, sortOrder: tickers.length }, adminToken: token });
      setNewText('');
      toast.success('✅ Ticker added! Updating live ticker...');
      await load();
      refreshAppData(); // immediately push to front-end ticker
    } catch (e: any) { toast.error(e?.message); }
    finally { setAdding(false); }
  };

  const deleteTicker = async (id: string) => {
    setDeleting(id);
    try {
      await adminAction({ action: 'delete_ticker', id, adminToken: token });
      toast.success('Ticker deleted');
      await load();
      refreshAppData(); // immediately update front-end ticker
    } catch (e: any) { toast.error(e?.message); }
    finally { setDeleting(null); }
  };

  return (
    <div className="card-dark rounded-xl p-4 space-y-3 border border-border">
      <p className="text-sm font-bold flex items-center gap-2">
        <Megaphone size={14} className="text-primary" /> News Ticker Messages
        <button onClick={load} className="ml-auto text-xs text-muted-foreground hover:text-foreground flex items-center gap-1"><RefreshCw size={10} /></button>
      </p>
      <p className="text-[10px] text-muted-foreground">Add/remove scrolling messages shown in the header ticker. Changes appear instantly.</p>

      <div className="flex gap-2">
        <Input
          value={newText}
          onChange={e => setNewText(e.target.value)}
          placeholder="Type your ticker message here..."
          className="bg-muted border-border text-xs h-8 flex-1"
          onKeyDown={e => e.key === 'Enter' && addTicker()}
        />
        <Button size="sm" onClick={addTicker} disabled={adding || !newText.trim()} className="h-8 px-3 text-xs gap-1 bg-primary text-primary-foreground">
          {adding ? <Loader2 size={10} className="animate-spin" /> : <Plus size={10} />} Add
        </Button>
      </div>

      {loading ? (
        <div className="space-y-1.5">{[1,2].map(i => <Skeleton key={i} className="h-8 rounded-lg" />)}</div>
      ) : tickers.length === 0 ? (
        <div className="text-center py-4 text-muted-foreground text-xs">No ticker messages. Add one above.</div>
      ) : (
        <div className="space-y-1.5 max-h-48 overflow-y-auto">
          {tickers.map((t: any, i) => (
            <div key={t.id} className="flex items-center gap-2 bg-muted/50 border border-border rounded-lg px-2.5 py-1.5">
              <span className="text-[10px] text-muted-foreground shrink-0">{i + 1}.</span>
              <p className="text-xs flex-1 truncate">{t.content}</p>
              <button onClick={() => deleteTicker(t.id)} disabled={deleting === t.id}
                className="text-destructive/60 hover:text-destructive transition-colors shrink-0 p-1">
                {deleting === t.id ? <Loader2 size={10} className="animate-spin" /> : <Trash2 size={10} />}
              </button>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

