// ─── Settings Tab ─────────────────────────────────────────────────────
function SettingsTab({ token, onPasswordChange }: { token: string; onPasswordChange: (p: string) => void }) {
  const { refresh: refreshAppData } = useAppData();
  const [cfg, setCfg] = useState<Record<string, string>>({});
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState<string | null>(null);
  const [newPwd, setNewPwd] = useState('');
  const [confirmPwd, setConfirmPwd] = useState('');
  const [apiKey, setApiKey] = useState('');
  const [showKey, setShowKey] = useState(false);
  const [validating, setValidating] = useState(false);
  type KeyStatus = { valid: boolean; tier?: string; bestModel?: string; bestModelLabel?: string; error?: string };
  const [keyStatus, setKeyStatus] = useState<KeyStatus | null>(null);
  type EngineStatus = { id: string; name: string; emoji: string; status: 'ok' | 'warning' | 'error'; message: string };
  type GatewayStatus = { id: string; name: string; emoji: string; status: 'synced' | 'inactive' | 'error'; message: string };
  const [systemStatus, setSystemStatus] = useState<{ allOk: boolean; engines: EngineStatus[]; gateways?: GatewayStatus[]; autoHealed?: number } | null>(null);
  const [checking, setChecking] = useState(false);

  const load = useCallback(async () => {
    setLoading(true);
    try {
      const r = await adminGetData({ tab: 'settings', adminToken: token });
      const map: Record<string, string> = {};
      (r.data as any[]).forEach((s: any) => { if (s.settingKey) map[s.settingKey] = s.settingValue ?? ''; });
      setCfg(map);
      if (map['gemini_tier']) {
        setKeyStatus({ valid: true, tier: map['gemini_tier'], bestModel: map['gemini_best_model'], bestModelLabel: map['gemini_best_model_label'] });
        if (map['gemini_api_key']) setApiKey('••••••••••••••••••••');
      }
    } catch (e: any) { toast.error(e?.message); }
    finally { setLoading(false); }
  }, [token]);

  useEffect(() => { load(); }, [load]);

  const save = async (key: string, desc: string, value?: string) => {
    const val = value !== undefined ? value : (cfg[key] ?? '');
    setSaving(key);
    try {
      await adminAction({ action: 'upsert_setting', data: { key, value: val, desc }, adminToken: token });
      setCfg(c => ({ ...c, [key]: val }));
      toast.success('✅ Saved!');
      // Refresh global app data so UI (ticker, banner, colors) updates immediately
      refreshAppData();
    } catch (e: any) { toast.error(e?.message); }
    finally { setSaving(null); }
  };

  const runSystemCheck = async () => {
    setChecking(true);
    try {
      const res = await systemCheck({ adminToken: token });
      setSystemStatus(res as any);
      if (res.allOk) toast.success('✅ 100% System OK & Connected!');
      else toast.info('System check complete — some engines need API key');
    } catch (e: any) { toast.error(e?.message ?? 'System check failed'); }
    finally { setChecking(false); }
  };

  const handleValidateKey = async () => {
    if (!apiKey.trim() || apiKey.startsWith('•')) { toast.error('Paste a new API key to validate'); return; }
    setValidating(true);
    try {
      const result = await validateGeminiKey({ apiKey: apiKey.trim(), adminToken: token });
      setKeyStatus(result);
      if (result.valid) {
        toast.success('✅ Activated! ' + result.tier + ' tier — using ' + (result.bestModelLabel ?? result.bestModel));
        setApiKey('••••••••••••••••••••');
        load();
        runSystemCheck();
      } else {
        toast.error(result.error ?? 'Invalid API key');
      }
    } catch (e: any) { toast.error(e?.message ?? 'Validation failed'); }
    finally { setValidating(false); }
  };

  const changePassword = async () => {
    if (newPwd.length < 6) { toast.error('Minimum 6 characters required'); return; }
    if (newPwd !== confirmPwd) { toast.error('Passwords do not match'); return; }
    setSaving('admin_password');
    try {
      await adminAction({ action: 'upsert_setting', data: { key: 'admin_password', value: newPwd, desc: 'Admin panel password' }, adminToken: token });
      sessionStorage.setItem('admin_token', newPwd);
      onPasswordChange(newPwd);
      toast.success('🔐 Password updated!');
