    { title: '💚 SadaPay', items: [{ key: 'payment_sadapay_number', label: 'Phone', placeholder: '0300-0000000' }, { key: 'payment_sadapay_name', label: 'Name', placeholder: 'Account Name' }] },
    { title: '🟣 NayaPay', items: [{ key: 'payment_nayapay_number', label: 'Phone', placeholder: '0300-0000000' }, { key: 'payment_nayapay_name', label: 'Name', placeholder: 'Account Name' }] },
