      {/* Display Settings */}
      <div className="card-dark rounded-xl p-4 space-y-4 border border-border">
        <p className="text-sm font-bold flex items-center gap-2"><Palette size={14} className="text-primary" /> Display Settings</p>

        <div className="flex items-center justify-between">
