            {keyStatus?.valid && ts && <span className={`text-[10px] ${ts.bg} ${ts.text} border ${ts.border} px-2 py-0.5 rounded-full font-bold flex items-center gap-1`}><ShieldCheck size={9} /> ACTIVE</span>}
