          </div>
          {systemStatus && (
            <div className="space-y-2">
              {systemStatus.autoHealed != null && systemStatus.autoHealed > 0 && (
                <div className="bg-green-500/10 border border-green-500/25 rounded-lg px-2.5 py-1.5 text-[10px] text-green-400 font-bold">
                  🔄 Auto-healed {systemStatus.autoHealed} missing records (self-healing active)
