              )}
              {systemStatus.engines.map((e: EngineStatus) => (
                <div key={e.id} className="flex items-start gap-2.5">
                  <span className="text-sm shrink-0">{e.emoji}</span>
                  <div className="flex-1 min-w-0">
                    <div className="flex items-center gap-1.5">
                      <div className={`w-1.5 h-1.5 rounded-full shrink-0 ${e.status === 'ok' ? 'bg-green-500' : e.status === 'warning' ? 'bg-yellow-500' : 'bg-destructive'}`} />
                      <p className="text-xs font-semibold">{e.name}</p>
                    </div>
                    <p className="text-[10px] text-muted-foreground pl-3 truncate">{e.message}</p>
                  </div>
                  <span className={`text-[9px] font-bold px-1.5 py-0.5 rounded-full shrink-0 ${e.status === 'ok' ? 'bg-green-500/15 text-green-400' : 'bg-yellow-500/15 text-yellow-400'}`}>
                    {e.status === 'ok' ? 'OK' : 'WARN'}
