                </div>
              ))}
              {/* Video Gateway Sync Status */}
              {systemStatus.gateways && systemStatus.gateways.length > 0 && (
                <div className="border-t border-border/40 pt-2 mt-2 space-y-2">
                  <p className="text-[10px] font-bold text-foreground">🎬 Video Gateway Sync Status:</p>
                  {systemStatus.gateways.map((g: GatewayStatus) => (
                    <div key={g.id} className="flex items-start gap-2.5">
                      <span className="text-sm shrink-0">{g.emoji}</span>
                      <div className="flex-1 min-w-0">
                        <div className="flex items-center gap-1.5">
