                      </div>
                      <span className={`text-[9px] font-bold px-1.5 py-0.5 rounded-full shrink-0 ${g.status === 'synced' ? 'bg-green-500/15 text-green-400' : g.status === 'error' ? 'bg-destructive/15 text-destructive' : 'bg-yellow-500/15 text-yellow-400'}`}>
                        {g.status === 'synced' ? 'SYNCED' : g.status === 'error' ? 'ERROR' : 'INACTIVE'}
                      </span>
                    </div>
                  ))}
                </div>
              )}
            </div>
          )}
        </div>
      )}

      {/* Password Change */}
      <div className="card-dark rounded-xl p-4 space-y-3 border border-destructive/20">
        <p className="text-sm font-semibold flex items-center gap-1.5 text-destructive"><Shield size={14} /> Change Admin Password</p>
        <Input type="password" placeholder="New password (min 6 chars)" value={newPwd} onChange={e => setNewPwd(e.target.value)} className="bg-muted border-border text-sm h-8" />
        <Input type="password" placeholder="Confirm new password" value={confirmPwd} onChange={e => setConfirmPwd(e.target.value)} className="bg-muted border-border text-sm h-8" />
        <Button size="sm" onClick={changePassword} disabled={saving === 'admin_password' || !newPwd || !confirmPwd} className="w-full h-8 text-xs bg-destructive/80 hover:bg-destructive text-white">
          {saving === 'admin_password' ? 'Saving...' : '🔐 Update Password'}
        </Button>
      </div>

      {/* Other settings */}
      {GROUPS.map(({ title, items }) => (
        <div key={title} className="card-dark rounded-xl p-4 space-y-3">
          <p className="text-sm font-semibold">{title}</p>
          {items.map(({ key, label, placeholder }) => (
            <div key={key} className="space-y-1">
