              <div className="flex gap-2">
                <Input value={cfg[key] ?? ''} onChange={e => setCfg(c => ({ ...c, [key]: e.target.value }))} placeholder={placeholder} className="bg-muted border-border text-xs h-8 font-mono flex-1" />
                <Button size="sm" onClick={() => save(key, label)} disabled={saving === key} className="h-8 text-xs bg-primary/20 text-primary border border-primary/30 hover:bg-primary/30 px-3">
                  {saving === key ? '...' : 'Save'}
                </Button>
