// ─── Supabase Config Tab ──────────────────────────────────────────
function SupabaseConfigSection({ token }: { token: string }) {
  const [configs, setConfigs] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [formOpen, setFormOpen] = useState(false);
  const [migrationResults, setMigrationResults] = useState<Record<string, any>>({});
  const [activeMigrationId, setActiveMigrationId] = useState<string | null>(null);
  const [showSql, setShowSql] = useState(false);
  const [copiedSql, setCopiedSql] = useState(false);
  const [busy, setBusy] = useState<string | null>(null);

  const [form, setForm] = useState({
    id: '', projectName: '', projectUrl: '', anonKey: '', serviceRoleKey: '', notes: '',
  });

  const load = useCallback(async () => {
    setLoading(true);
    try {
      const r = await supabaseMigrate({ action: 'get_config', adminToken: token });
      setConfigs((r.data as any[]) ?? []);
    } catch (e: any) { toast.error(e?.message); }
    finally { setLoading(false); }
  }, [token]);

  useEffect(() => { load(); }, [load]);

  const resetForm = () => setForm({ id: '', projectName: '', projectUrl: '', anonKey: '', serviceRoleKey: '', notes: '' });

  const saveConfig = async () => {
    if (!form.projectUrl || !form.serviceRoleKey) { toast.error('Project URL and Service Role Key are required'); return; }
    setBusy('save');
    try {
      await supabaseMigrate({ action: 'save_config', adminToken: token, data: form });
      toast.success('✅ Supabase config saved!');
      resetForm(); setFormOpen(false); load();
    } catch (e: any) { toast.error(e?.message); }
    finally { setBusy(null); }
  };

  const runMigration = async (id: string) => {
    setBusy('migrate_' + id);
    setActiveMigrationId(id);
    setMigrationResults(prev => ({ ...prev, [id]: null }));
    try {
      const r = await supabaseMigrate({ action: 'run_migration', adminToken: token, data: { id } });
      setMigrationResults(prev => ({ ...prev, [id]: r }));
      if (r.data?.autoExecuted) toast.success('🚀 ' + (r.message ?? 'Migration complete!'));
      else toast.info('📋 Auto-SQL failed — use options below to connect manually');
      load();
    } catch (e: any) { toast.error(e?.message); }
    finally { setBusy(null); }
  };

  const verifyTables = async (id: string) => {
    setBusy('verify_' + id);
    setActiveMigrationId(id);
    try {
      const r = await supabaseMigrate({ action: 'verify_tables', adminToken: token, data: { id } });
      setMigrationResults(prev => ({ ...prev, [id]: r }));
      if (r.data?.autoExecuted) {
        toast.success('✅ All tables verified — connection marked as ACTIVE!');
        load();
      } else {
        toast.warning('⚠️ Some tables missing — run the SQL first');
      }
    } catch (e: any) { toast.error(e?.message); }
    finally { setBusy(null); }
  };

  const forceConnect = async (id: string) => {
    setBusy('force_' + id);
    try {
      const r = await supabaseMigrate({ action: 'force_connect', adminToken: token, data: { id } });
      setMigrationResults(prev => ({ ...prev, [id]: r }));
      toast.success('✅ Status set to CONNECTED!');
      load();
    } catch (e: any) { toast.error(e?.message); }
    finally { setBusy(null); }
  };

  const deleteConfig = async (id: string) => {
    setBusy('del_' + id);
    try {
      await supabaseMigrate({ action: 'delete_config', adminToken: token, data: { id } });
      toast.success('Deleted');
      load();
    } catch (e: any) { toast.error(e?.message); }
    finally { setBusy(null); }
  };

  const copySql = (sql: string) => {
    navigator.clipboard.writeText(sql);
    setCopiedSql(true); toast.success('SQL copied!');
    setTimeout(() => setCopiedSql(false), 2500);
  };

  return (
    <div className="space-y-3">
      {/* Header */}
      <div className="rounded-2xl border-2 border-sky-500/30 bg-sky-950/20 p-4 space-y-2">
        <div className="flex items-center gap-2">
          <div className="w-8 h-8 rounded-xl bg-sky-500/15 border border-sky-500/30 flex items-center justify-center shrink-0">
            <Database size={16} className="text-sky-400" />
          </div>
          <div className="flex-1 min-w-0">
            <p className="font-black text-sm">🗄️ Supabase Integration</p>
            <p className="text-[10px] text-muted-foreground">Isolated credential vault — zero mixing with operational tables</p>
          </div>
          <button onClick={() => { resetForm(); setFormOpen(f => !f); }}
            className="shrink-0 flex items-center gap-1 text-xs bg-sky-500/20 text-sky-400 border border-sky-500/30 rounded-xl px-3 py-1.5 font-bold hover:bg-sky-500/30 transition-colors">
            <Plus size={11} /> Add
          </button>
        </div>

        {/* How auto-migration works */}
        <div className="bg-sky-950/30 border border-sky-500/20 rounded-lg px-3 py-2 text-[9px] text-sky-300 space-y-1">
          <p className="font-bold text-sky-400">🔄 3-Step Auto-Migration Cascade:</p>
          <p>① exec_sql RPC → ② Supabase Management API → ③ Verify existing tables</p>
          <p className="text-muted-foreground">If you already ran the SQL manually, click <strong className="text-sky-400">"Verify Tables"</strong> or <strong className="text-sky-400">"Mark as Connected"</strong> below.</p>
        </div>

        {/* Security notice */}
        <div className="bg-green-950/30 border border-green-500/20 rounded-lg px-3 py-2 text-[9px] text-green-400 flex items-start gap-1.5">
          <span className="shrink-0">🔒</span>
          <span>Service Role Keys are stored encrypted in an isolated table. Never included in public-facing responses.</span>
        </div>
      </div>

      {/* Add Config Form */}
      {formOpen && (
        <div className="card-dark rounded-xl p-4 space-y-3 border border-sky-500/30">
          <p className="text-xs font-bold text-sky-400 flex items-center gap-1.5"><Server size={11} /> New Supabase Connection</p>
          <div className="space-y-2">
            {[
              { key: 'projectName',    label: '📛 Project Name',         placeholder: 'My Supabase Project',       type: 'text',     },
              { key: 'projectUrl',     label: '🌐 Project URL',          placeholder: 'https://abcxyz.supabase.co', type: 'url',      },
              { key: 'anonKey',        label: '🔑 Anon / Public Key',    placeholder: 'eyJhbG...',                 type: 'password', },
              { key: 'serviceRoleKey', label: '🛡️ Service Role Key',     placeholder: 'eyJhbG...',                 type: 'password', },
              { key: 'notes',          label: '📝 Notes (optional)',      placeholder: 'e.g. Production DB',        type: 'text',     },
            ].map(f => (
              <div key={f.key} className="space-y-0.5">
                <Label className="text-[10px] text-muted-foreground">{f.label}</Label>
                <Input
                  type={f.type as any}
                  value={(form as any)[f.key]}
                  onChange={e => setForm(p => ({ ...p, [f.key]: e.target.value }))}
                  placeholder={f.placeholder}
                  className="bg-muted border-border text-xs h-8 font-mono"
                />
              </div>
            ))}
          </div>
          <div className="flex gap-2">
            <Button size="sm" onClick={saveConfig} disabled={busy === 'save'}
              className="flex-1 h-8 text-xs bg-sky-600 hover:bg-sky-600/90 text-white gap-1">
              {busy === 'save' ? <Loader2 size={10} className="animate-spin" /> : <Database size={10} />} Save Config
            </Button>
            <Button size="sm" variant="ghost" onClick={() => setFormOpen(false)}
              className="h-8 text-xs text-muted-foreground">
              Cancel
            </Button>
          </div>
        </div>
      )}

      {/* Config list */}
      {loading ? (
        <Skeleton className="h-20 rounded-xl" />
      ) : configs.length === 0 ? (
        <div className="text-center py-8 text-muted-foreground">
          <Database size={28} className="mx-auto mb-2 opacity-30" />
          <p className="text-xs">No Supabase configurations yet. Add one above.</p>
        </div>
      ) : (
        <div className="space-y-3">
          {configs.map((cfg: any) => {
            const result = migrationResults[cfg.id];
            const isActive = cfg.status === 'Active';
            return (
              <div key={cfg.id} className={`card-dark rounded-xl p-3 space-y-2.5 border ${isActive ? 'border-green-500/30' : 'border-border'}`}>
                <div className="flex items-start justify-between gap-2">
                  <div className="min-w-0 flex-1">
                    <p className="text-xs font-bold truncate">{cfg.projectName || 'Unnamed Project'}</p>
                    <p className="text-[10px] text-muted-foreground font-mono truncate">{cfg.projectUrl}</p>
                    <p className="text-[10px] text-muted-foreground">Anon: {cfg.anonKey}</p>
                    <p className="text-[10px] text-muted-foreground">Key: ••••••••••••••••••••</p>
                    {cfg.lastSyncedAt && (
                      <p className="text-[9px] text-muted-foreground mt-0.5">
                        Last sync: {new Date(cfg.lastSyncedAt).toLocaleString()}
                      </p>
                    )}
                  </div>
                  <div className="flex flex-col items-end gap-1.5 shrink-0">
                    <span className={`text-[9px] font-bold px-2 py-0.5 rounded-full border ${
                      isActive ? 'bg-green-500/15 text-green-400 border-green-500/30' :
                      cfg.status === 'Error' ? 'bg-destructive/15 text-destructive border-destructive/30' :
                      'bg-yellow-500/15 text-yellow-400 border-yellow-500/30'
                    }`}>{cfg.status || 'Pending'}</span>
                    <button onClick={() => deleteConfig(cfg.id)} disabled={!!busy}
                      className="text-[9px] text-destructive/60 hover:text-destructive transition-colors">
                      Delete
                    </button>
                  </div>
                </div>

                {cfg.tablesCreated && (
                  <p className="text-[9px] text-emerald-400 font-mono">✅ Tables: {cfg.tablesCreated}</p>
                )}

                {/* Action buttons */}
                <div className="grid grid-cols-2 gap-1.5">
                  <Button size="sm" onClick={() => runMigration(cfg.id)} disabled={!!busy}
                    className="h-8 text-[10px] bg-sky-600/20 text-sky-400 border border-sky-500/30 hover:bg-sky-600/30 gap-1">
                    {busy === 'migrate_' + cfg.id
                      ? <><Loader2 size={9} className="animate-spin" /> Running...</>
                      : <><RefreshCcw size={9} /> Auto-Migrate</>}
                  </Button>
                  <Button size="sm" onClick={() => verifyTables(cfg.id)} disabled={!!busy}
                    className="h-8 text-[10px] bg-emerald-600/20 text-emerald-400 border border-emerald-500/30 hover:bg-emerald-600/30 gap-1">
                    {busy === 'verify_' + cfg.id
                      ? <><Loader2 size={9} className="animate-spin" /> Verifying...</>
                      : <><Check size={9} /> Verify Tables</>}
                  </Button>
                </div>

                {/* Force Connect — always visible for non-Active configs */}
                {!isActive && (
                  <div className="rounded-xl bg-yellow-950/20 border border-yellow-500/25 p-2.5 space-y-1.5">
                    <p className="text-[9px] text-yellow-400 font-bold flex items-center gap-1">
                      <AlertTriangle size={9} /> Already ran the SQL manually?
                    </p>
                    <p className="text-[9px] text-muted-foreground">
                      If you executed the migration SQL in Supabase SQL Editor and all 5 tables were created, click below to mark this connection as active.
                    </p>
                    <Button size="sm" onClick={() => forceConnect(cfg.id)} disabled={!!busy}
                      className="w-full h-7 text-[10px] bg-green-600/20 text-green-400 border border-green-500/30 hover:bg-green-600/30 gap-1 font-bold">
                      {busy === 'force_' + cfg.id
                        ? <><Loader2 size={9} className="animate-spin" /> Updating...</>
                        : <><Check size={9} /> ✅ Tables Already Created — Mark as CONNECTED</>}
                    </Button>
                  </div>
                )}

                {/* Per-config migration result */}
                {result && activeMigrationId === cfg.id && (
                  <div className={`rounded-xl border p-3 space-y-2 text-xs ${result.data?.autoExecuted ? 'border-green-500/30 bg-green-950/15' : 'border-yellow-500/30 bg-yellow-950/10'}`}>
                    <div className="flex items-start gap-1.5">
                      <span className="shrink-0">{result.data?.autoExecuted ? '✅' : '⚠️'}</span>
                      <p className="font-semibold flex-1 text-[10px]">{result.message}</p>
                    </div>

                    {result.data?.existingTables && (
                      <div className="text-[9px] text-emerald-400 font-mono">
                        Found: {result.data.existingTables.join(', ')}
                      </div>
                    )}
                    {result.data?.missingTables?.length > 0 && (
                      <div className="text-[9px] text-destructive font-mono">
                        Missing: {result.data.missingTables.join(', ')}
                      </div>
                    )}

                    {result.sql && !result.data?.autoExecuted && (
                      <>
                        <button onClick={() => setShowSql(s => !s)}
                          className="flex items-center gap-1 text-[10px] text-primary font-semibold">
                          {showSql ? <ChevronUp size={10} /> : <ChevronDown size={10} />}
                          {showSql ? 'Hide' : 'Show'} SQL ({result.data?.tablesCount} tables)
                        </button>
                        {showSql && (
                          <div className="space-y-1.5">
                            <div className="bg-muted/70 border border-border rounded-lg p-2.5 max-h-48 overflow-y-auto">
                              <pre className="text-[8px] font-mono text-muted-foreground whitespace-pre-wrap leading-relaxed">
                                {result.sql}
                              </pre>
                            </div>
                            <Button size="sm" onClick={() => copySql(result.sql)}
                              className="w-full h-7 text-[10px] bg-primary/20 text-primary border border-primary/30 hover:bg-primary/30 gap-1">
                              {copiedSql ? <><Check size={9} /> Copied!</> : <><Copy size={9} /> Copy SQL</>}
                            </Button>
                            <p className="text-[8px] text-muted-foreground text-center">
                              Supabase Dashboard → SQL Editor → New Query → Paste → Run → then click "Mark as CONNECTED"
                            </p>
                          </div>
                        )}
                      </>
                    )}
                  </div>
                )}
              </div>
            );
          })}
        </div>
      )}
    </div>
  );
}

// ─── Video API Keys Tab ──────────────────────────────────────────────
type VideoKeyInfo = GetVideoKeysOutputType['keys'][0];

const GATEWAY_META: Record<string, { emoji: string; color: string; desc: string }> = {
  huggingface_api_key: { emoji: '🟢', color: 'text-green-400',   desc: 'Priority 1 — HuggingFace — ByteDance / Stability / Alibaba engines' },
  stability_api_key:   { emoji: '🔵', color: 'text-blue-400',    desc: 'Priority 2 — Stability AI Engine — failover backup' },
  google_veo_key:      { emoji: '🔴', color: 'text-red-400',     desc: 'Priority 3 (Last Resort) — Legacy — currently locked/unpaid' },
};

// Force display order: HuggingFace → Stability → Google Veo
const GATEWAY_DISPLAY_ORDER = ['huggingface_api_key', 'stability_api_key', 'google_veo_key'];

// ─── Universal AI Gateway Card ──────────────────────────────────────
function UniversalGatewayCard({ token, keys, onRefresh }: { token: string; keys: any[]; onRefresh: () => void }) {
  const [uniKey, setUniKey] = useState('');
  const [endpointUrl, setEndpointUrl] = useState('');
  const [payloadJson, setPayloadJson] = useState('');
  const [showKey, setShowKey] = useState(false);
  const [saving, setSaving] = useState(false);
  const [loaded, setLoaded] = useState(false);

  // Load existing config from any key row that has universal fields
  useEffect(() => {
    if (loaded || keys.length === 0) return;
    const row = keys.find((k: any) => k.hasUniversalKey);
    if (row) {
      setEndpointUrl(row.modelEndpointUrl ?? '');
      setPayloadJson(row.payloadMappingJson ?? '');
      setUniKey('••••••••••••••••••••');
    }
    setLoaded(true);
  }, [keys, loaded]);

  const hasConfig = keys.some((k: any) => k.hasUniversalKey);

  const handleSave = async () => {
    setSaving(true);
    try {
      const payload: any = {
        adminToken: token,
        targetKeyIdentifier: 'huggingface_api_key',
        modelEndpointUrl: endpointUrl,
        payloadMappingJson: payloadJson,
      };
      if (uniKey && !uniKey.startsWith('•')) payload.universalApiKey = uniKey;
      const r = await saveUniversalGateway(payload);
      if (r.success) {
        toast.success(r.message);
        setUniKey('••••••••••••••••••••');
        onRefresh();
      } else {
        toast.error('Save failed');
      }
    } catch (e: any) { toast.error(e?.message ?? 'Save failed'); }
    finally { setSaving(false); }
  };

  return (
    <div className={`rounded-2xl border-2 overflow-hidden ${hasConfig ? 'border-green-500/40' : 'border-dashed border-primary/40'}`}>
      <div className={`px-4 py-3 flex items-center gap-2 ${hasConfig ? 'bg-green-500/10' : 'bg-primary/5'}`}>
        <span className="text-lg">🌐</span>
        <div className="flex-1 min-w-0">
          <span className="font-black text-sm">Universal AI Video Gateway</span>
          <p className="text-[9px] text-muted-foreground">Priority 0 — Self-Healing, Never-Fail — Lifetime model support</p>
        </div>
        {hasConfig ? (
          <span className="text-[9px] bg-green-500/15 text-green-400 border border-green-500/30 px-2 py-0.5 rounded-full font-bold flex items-center gap-1">
            <Check size={9} /> ARMED
          </span>
        ) : (
          <span className="text-[9px] bg-muted text-muted-foreground px-2 py-0.5 rounded-full font-semibold">NOT CONFIGURED</span>
        )}
      </div>

      <div className="p-4 space-y-3">
        <div className="bg-primary/5 border border-primary/15 rounded-xl px-3 py-2.5 text-[10px] text-muted-foreground space-y-1">
          <p className="font-bold text-foreground">🔗 How it works:</p>
          <p>This gateway fires <strong>BEFORE</strong> all other engines (Priority 0). Paste any AI model's API key and endpoint URL — Canva, OpenAI, Claude, Runway, Pika, or any future API. The self-healing engine catches all errors silently and falls through to existing gateways.</p>
          <div className="grid grid-cols-3 gap-1.5 mt-1.5">
            {[
              { icon: '🔑', label: 'Universal API Key', sub: 'Any model\'s key' },
              { icon: '🎯', label: 'Model Endpoint URL', sub: 'Dynamic target API' },
              { icon: '📦', label: 'Payload Mapping', sub: 'Custom JSON overrides' },
            ].map(m => (
              <div key={m.label} className="bg-muted/40 border border-border rounded-lg px-2 py-1.5 text-center">
                <span className="text-sm">{m.icon}</span>
                <p className="text-[8px] font-bold mt-0.5">{m.label}</p>
                <p className="text-[7px] text-muted-foreground">{m.sub}</p>
              </div>
            ))}
          </div>
        </div>

        {/* Universal API Key */}
        <div className="space-y-1.5">
          <Label className="text-[10px] text-muted-foreground">🔑 Universal API Key (any AI model)</Label>
          <div className="relative">
            <Key size={11} className="absolute left-2.5 top-1/2 -translate-y-1/2 text-muted-foreground" />
            <input
              type={showKey ? 'text' : 'password'}
              value={uniKey}
              onChange={e => setUniKey(e.target.value)}
              placeholder="Paste any AI model's API key..."
              className="w-full bg-muted border border-border rounded-lg pl-8 pr-8 py-1.5 text-xs font-mono focus:outline-none focus:ring-1 focus:ring-primary"
            />
            <button onClick={() => setShowKey(s => !s)} className="absolute right-2 top-1/2 -translate-y-1/2 text-muted-foreground hover:text-foreground">
              {showKey ? <EyeOff size={12} /> : <Eye size={12} />}
            </button>
          </div>
        </div>

        {/* Model Endpoint URL */}
        <div className="space-y-1.5">
          <Label className="text-[10px] text-muted-foreground">🎯 Model Endpoint URL</Label>
          <Input
            value={endpointUrl}
            onChange={e => setEndpointUrl(e.target.value)}
            placeholder="https://api.canva.com/v1/video/generate"
            className="bg-muted border-border text-xs h-8 font-mono"
          />
        </div>

        {/* Payload Mapping JSON */}
        <div className="space-y-1.5">
          <Label className="text-[10px] text-muted-foreground">📦 Payload Mapping JSON (optional — custom key-value overrides)</Label>
          <Textarea
            value={payloadJson}
            onChange={e => setPayloadJson(e.target.value)}
            placeholder={'{\n  "video_duration": "30s",\n  "resolution": "1080p",\n  "style": "cinematic"\n}'}
            className="bg-muted border-border text-xs font-mono resize-none"
            rows={4}
          />
          <p className="text-[9px] text-muted-foreground">These key-values are merged into the API payload alongside the prompt. Must be valid JSON.</p>
        </div>

        <Button onClick={handleSave} disabled={saving || (!uniKey.trim() && !endpointUrl.trim())}
          className={`w-full font-bold text-sm h-10 gap-2 ${hasConfig ? 'bg-green-600 hover:bg-green-600/90 text-white' : 'bg-primary text-primary-foreground'}`}>
          {saving ? <><Loader2 size={14} className="animate-spin" /> Saving...</> : hasConfig ? <><Check size={14} /> Update Universal Gateway</> : <><Zap size={14} /> Arm Universal Gateway</>}
        </Button>

        <div className="bg-green-950/20 border border-green-500/20 rounded-xl px-3 py-2 text-[9px] text-green-400 space-y-0.5">
          <p className="font-bold">🛡️ Self-Healing Protection:</p>
          <p>If the universal key fails, expires, or the endpoint is down, the system silently falls through to HuggingFace → Stability → Google Veo. The app NEVER crashes.</p>
        </div>
      </div>
    </div>
  );
}

function VideoApiKeysTab({ token }: { token: string }) {
  const [keys, setKeys] = useState<VideoKeyInfo[]>([]);
  const [loading, setLoading] = useState(true);
  const [inputs, setInputs] = useState<Record<string, string>>({});
  const [showKey, setShowKey] = useState<Record<string, boolean>>({});
  const [verifying, setVerifying] = useState<string | null>(null);

  const load = useCallback(async () => {
    setLoading(true);
    try {
      const r = await getVideoKeys({ adminToken: token });
      setKeys(r.keys);
    } catch (e: any) { toast.error(e?.message ?? 'Failed to load'); }
    finally { setLoading(false); }
  }, [token]);

  useEffect(() => { load(); }, [load]);

  const handleVerify = async (keyId: string) => {
    const val = inputs[keyId]?.trim();
    if (!val) { toast.error('Paste an API key first'); return; }
    setVerifying(keyId);
    try {
      const r = await verifyVideoKey({ adminToken: token, keyIdentifier: keyId as any, apiKey: val });
      if (r.success) {
        toast.success(r.message);
        setInputs(p => ({ ...p, [keyId]: '' }));
      } else {
        toast.error(r.message);
      }
      load();
    } catch (e: any) { toast.error(e?.message ?? 'Verification failed'); }
    finally { setVerifying(null); }
  };

  if (loading) return <div className="space-y-3">{[1,2,3,4].map(i => <Skeleton key={i} className="h-32 rounded-xl" />)}</div>;

  return (
    <div className="space-y-4">
      {/* Header */}
      <div className="rounded-2xl border-2 border-secondary/30 bg-secondary/5 p-4 space-y-2">
        <div className="flex items-center gap-2">
          <div className="w-8 h-8 rounded-xl bg-secondary/15 border border-secondary/30 flex items-center justify-center shrink-0">
            <Key size={16} className="text-secondary" />
          </div>
          <div>
            <p className="font-black text-sm">🎬 Video API Gateway Keys</p>
            <p className="text-[10px] text-muted-foreground">Isolated table — zero collision with Google/Gemini settings</p>
          </div>
          <button onClick={load} className="ml-auto text-xs text-muted-foreground hover:text-foreground flex items-center gap-1"><RefreshCw size={10} /></button>
        </div>

        <div className="bg-secondary/5 border border-secondary/15 rounded-xl px-3 py-2 text-[10px] text-muted-foreground space-y-1">
          <p className="font-bold text-foreground">🔗 Sequential Failover Chain (Waterfall):</p>
          <div className="flex items-center gap-1 flex-wrap">
            {[...keys].sort((a, b) => (GATEWAY_DISPLAY_ORDER.indexOf(a.keyIdentifier) === -1 ? 99 : GATEWAY_DISPLAY_ORDER.indexOf(a.keyIdentifier)) - (GATEWAY_DISPLAY_ORDER.indexOf(b.keyIdentifier) === -1 ? 99 : GATEWAY_DISPLAY_ORDER.indexOf(b.keyIdentifier))).map((k, i) => (
              <span key={k.keyIdentifier} className="flex items-center gap-1">
                <span className={`font-bold ${k.status === 'Active' ? 'text-green-400' : 'text-muted-foreground'}`}>
                  {GATEWAY_META[k.keyIdentifier]?.emoji} {k.gatewayName}
                </span>
                {i < keys.length - 1 && <span className="text-muted-foreground/50 mx-0.5">→</span>}
              </span>
            ))}
          </div>
          <p>Keys execute in strict waterfall order. If Gateway 1 fails, it falls to Gateway 2, then 3, then 4. <strong>Never parallel — zero collision.</strong></p>
        </div>
      </div>

      {/* ═══ UNIVERSAL AI GATEWAY — Priority 0 ═══ */}
      <UniversalGatewayCard token={token} keys={keys} onRefresh={load} />

      {/* Key Cards — sorted: HuggingFace → Stability → Google Veo */}
      {[...keys].sort((a, b) => (GATEWAY_DISPLAY_ORDER.indexOf(a.keyIdentifier) === -1 ? 99 : GATEWAY_DISPLAY_ORDER.indexOf(a.keyIdentifier)) - (GATEWAY_DISPLAY_ORDER.indexOf(b.keyIdentifier) === -1 ? 99 : GATEWAY_DISPLAY_ORDER.indexOf(b.keyIdentifier))).map((k, idx) => {
        const meta = GATEWAY_META[k.keyIdentifier] ?? { emoji: '⚪', color: 'text-muted-foreground', desc: '' };
        const statusCls = k.status === 'Active' ? 'bg-green-500/15 text-green-400 border-green-500/30' :
                          k.status === 'Error' ? 'bg-destructive/15 text-destructive border-destructive/30' :
                          'bg-yellow-500/15 text-yellow-400 border-yellow-500/30';
        return (
          <div key={k.keyIdentifier} className="card-dark rounded-xl p-4 space-y-3 border border-border">
            <div className="flex items-start justify-between gap-2">
              <div>
                <div className="flex items-center gap-2">
                  <span className="text-sm">{meta.emoji}</span>
                  <p className="text-sm font-bold">{k.gatewayName}</p>
                  <span className="text-[10px] bg-muted px-2 py-0.5 rounded-full text-muted-foreground">#{idx + 1} Priority</span>
                </div>
                <p className={`text-[10px] ${meta.color} mt-0.5`}>{meta.desc}</p>
              </div>
              <span className={`text-[9px] font-bold px-2 py-0.5 rounded-full border ${statusCls}`}>{k.status}</span>
            </div>

            {/* Current key status */}
            {k.hasKey && (
              <div className="bg-muted/40 rounded-lg px-3 py-2 space-y-1">
                <div className="flex items-center justify-between">
                  <p className="text-[10px] text-muted-foreground font-mono">{k.maskedKey}</p>
                  <span className={`w-2 h-2 rounded-full ${k.status === 'Active' ? 'bg-green-500' : k.status === 'Error' ? 'bg-destructive' : 'bg-yellow-500'}`} />
                </div>
                <p className="text-[10px] text-muted-foreground">{k.lastVerificationMessage}</p>
                {k.lastVerifiedAt && (
                  <p className="text-[9px] text-muted-foreground">Last verified: {new Date(k.lastVerifiedAt).toLocaleString()}</p>
                )}
              </div>
            )}

            {/* Input + Verify */}
            <div className="space-y-1.5">
              <Label className="text-[10px] text-muted-foreground">{k.hasKey ? 'Replace Key' : 'Paste API Key'}</Label>
              <div className="flex gap-2">
                <div className="relative flex-1">
                  <Key size={11} className="absolute left-2.5 top-1/2 -translate-y-1/2 text-muted-foreground" />
                  <input
                    type={showKey[k.keyIdentifier] ? 'text' : 'password'}
                    value={inputs[k.keyIdentifier] ?? ''}
                    onChange={e => setInputs(p => ({ ...p, [k.keyIdentifier]: e.target.value }))}
                    placeholder={k.keyIdentifier === 'google_veo_key' ? 'AIza...' : k.keyIdentifier === 'huggingface_api_key' ? 'hf_xxxxxxxx' : 'sk-xxxxxxxx'}
                    className="w-full bg-muted border border-border rounded-lg pl-8 pr-8 py-1.5 text-xs font-mono focus:outline-none focus:ring-1 focus:ring-primary"
                  />
                  <button onClick={() => setShowKey(p => ({ ...p, [k.keyIdentifier]: !p[k.keyIdentifier] }))}
                    className="absolute right-2 top-1/2 -translate-y-1/2 text-muted-foreground hover:text-foreground">
                    {showKey[k.keyIdentifier] ? <EyeOff size={12} /> : <Eye size={12} />}
                  </button>
                </div>
                <Button
                  size="sm"
                  onClick={() => handleVerify(k.keyIdentifier)}
                  disabled={verifying === k.keyIdentifier || !inputs[k.keyIdentifier]?.trim()}
                  className="h-8 px-3 text-[10px] bg-secondary text-secondary-foreground font-bold gap-1 shrink-0"
                >
                  {verifying === k.keyIdentifier
                    ? <><Loader2 size={10} className="animate-spin" /> Verifying</>
                    : <><ShieldCheck size={10} /> Verify & Save</>}
                </Button>
              </div>
            </div>
          </div>
        );
      })}

      {/* Footer Info */}
      <div className="rounded-xl border border-secondary/20 bg-secondary/5 px-3 py-2.5 space-y-1 text-[10px] text-muted-foreground">
        <p className="font-bold text-foreground">⚡ How the Failover Pipeline Works:</p>
        <ul className="space-y-0.5 list-disc pl-4">
          <li>When user clicks "Generate Video", the engine tries <strong>Gateway 1 (HuggingFace)</strong> first</li>
          <li>HuggingFace rotates: <strong>ByteDance/AnimateDiff → Stability SVD → Alibaba text-to-video</strong> (5s timeout)</li>
          <li>If HuggingFace fails/overloaded → instantly routes to <strong>Gateway 2 (Stability AI)</strong></li>
          <li>If Stability fails → falls to <strong>Gateway 3 (Google Veo)</strong> as last resort</li>
          <li>Keys <strong>NEVER execute simultaneously</strong> — strict waterfall, zero collision</li>
          <li>Each key is stored in an <strong>isolated database table</strong> (not in Admin Settings)</li>
        </ul>
      </div>
    </div>
  );
}

// ─── System APK & Application Safety Control (Persistent, DB-backed) ─
function SystemSafetyControlPanel({ token }: { token: string }) {
  const [apkVersion, setApkVersion] = useState('');
  const [apkUrl, setApkUrl] = useState('');
  const [apkFilename, setApkFilename] = useState('');
  const [antiCrash, setAntiCrash] = useState(true);
  const [uploading, setUploading] = useState(false);
  const [loading, setLoading] = useState(true);
  const [copied, setCopied] = useState(false);
  const [togglingCrash, setTogglingCrash] = useState(false);
  const fileRef = useRef<HTMLInputElement>(null);

  // Load persisted state from DB on mount
  const load = useCallback(async () => {
    setLoading(true);
    try {
      const r = await systemSafety({ action: 'get' });
      if (r.success) {
        setApkUrl(r.apkUrl ?? '');
        setApkVersion(r.apkVersion ?? '');
        setApkFilename(r.apkFilename ?? '');
        setAntiCrash(r.antiCrashEnabled !== false);
      }
    } catch { /* silent */ }
    finally { setLoading(false); }
  }, []);

  useEffect(() => { load(); }, [load]);

  // Real APK upload via zite-file-upload-sdk
  const handleFileSelect = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    if (!file.name.endsWith('.apk')) {
      toast.error('Please select a valid .apk file');
      return;
    }
    setUploading(true);
    try {
      const { uploadFile } = await import('zite-file-upload-sdk');
      const { fileUrl } = await uploadFile({ data: file, filename: file.name });
      const ver = `v${new Date().getFullYear() % 100}.${new Date().getMonth() + 1}.${new Date().getDate()}`;
      // Persist to DB
      await systemSafety({
        action: 'save_apk',
        adminToken: token,
        apkUrl: fileUrl,
        apkVersion: ver,
        apkFilename: file.name,
      });
      setApkUrl(fileUrl);
      setApkVersion(ver);
      setApkFilename(file.name);
      toast.success(`✅ APK ${ver} uploaded & saved permanently!`);
    } catch (err: any) {
      toast.error(err?.message ?? 'Upload failed — please try again');
    } finally {
      setUploading(false);
      if (fileRef.current) fileRef.current.value = '';
    }
  };

  // Toggle anti-crash and persist
  const toggleAntiCrash = async () => {
    const newVal = !antiCrash;
    setTogglingCrash(true);
    try {
      await systemSafety({
        action: 'save_anti_crash',
        adminToken: token,
        antiCrashEnabled: newVal,
      });
      setAntiCrash(newVal);
      toast.success(newVal ? '✅ Anti-Crash guardrails enabled & saved' : '⚠️ Anti-Crash guardrails disabled & saved');
    } catch {
      toast.error('Failed to save anti-crash state');
    } finally { setTogglingCrash(false); }
  };

  const copyUrl = () => {
    if (!apkUrl) return;
    navigator.clipboard.writeText(apkUrl);
    setCopied(true);
    toast.success('📋 APK URL copied!');
    setTimeout(() => setCopied(false), 2500);
  };

  if (loading) return <Skeleton className="h-48 rounded-2xl" />;

  return (
    <div className="rounded-2xl border-2 border-accent/40 bg-accent/5 p-4 space-y-4">
      {/* Hidden file input */}
      <input ref={fileRef} type="file" accept=".apk" className="hidden" onChange={handleFileSelect} />

      {/* Header */}
      <div className="flex items-center gap-3">
        <div className="w-10 h-10 rounded-xl bg-accent/15 border border-accent/30 flex items-center justify-center shrink-0">
          <Shield size={20} className="text-accent" />
        </div>
        <div className="flex-1 min-w-0">
          <p className="font-black text-sm">🛡️ System APK & Application Safety Control</p>
          <p className="text-[10px] text-muted-foreground">Persistent — all states saved to database permanently</p>
        </div>
      </div>

      {/* Table */}
      <div className="rounded-xl border border-border overflow-hidden">
        {/* Row 1: APK Upload */}
        <div className="bg-card px-4 py-3.5 border-b border-border">
          <div className="flex items-center justify-between gap-3">
            <div className="flex items-center gap-3 min-w-0 flex-1">
              <div className="w-8 h-8 rounded-lg bg-primary/10 border border-primary/20 flex items-center justify-center shrink-0">
                <Upload size={14} className="text-primary" />
              </div>
              <div className="min-w-0 flex-1">
                <div className="flex items-center gap-2 flex-wrap">
                  <p className="text-xs font-bold">APK Upload File</p>
                  {apkVersion && <span className="text-[9px] bg-primary/15 text-primary border border-primary/25 rounded-full px-2 py-0.5 font-bold">{apkVersion}</span>}
                </div>
                {apkFilename ? (
                  <p className="text-[10px] text-muted-foreground mt-0.5 font-mono truncate">{apkFilename}</p>
                ) : (
                  <p className="text-[10px] text-muted-foreground mt-0.5 italic">No APK uploaded yet</p>
                )}
              </div>
            </div>
            <button
              onClick={() => fileRef.current?.click()}
              disabled={uploading}
              className="shrink-0 text-[10px] font-bold bg-primary text-primary-foreground px-3 py-2 rounded-lg hover:bg-primary/90 transition-colors disabled:opacity-50 flex items-center gap-1.5"
            >
              {uploading ? <><Loader2 size={10} className="animate-spin" /> Uploading...</> : <><Upload size={10} /> Upload Social App APK</>}
            </button>
          </div>

          {/* Live URL output */}
          {apkUrl && (
            <div className="mt-2.5 bg-green-500/5 border border-green-500/20 rounded-lg px-3 py-2 space-y-1">
              <p className="text-[9px] text-green-400 font-bold uppercase tracking-wide">✅ Permanent Live URL</p>
              <div className="flex items-center gap-2">
                <code className="text-[10px] text-primary font-mono bg-primary/10 px-2 py-1 rounded flex-1 truncate select-all">{apkUrl}</code>
                <button onClick={copyUrl} className="shrink-0 text-[10px] font-bold bg-primary/20 text-primary border border-primary/30 px-2 py-1 rounded-lg hover:bg-primary/30 transition-colors flex items-center gap-1">
                  {copied ? <><Check size={9} /> Copied!</> : <><Copy size={9} /> Copy</>}
                </button>
              </div>
            </div>
          )}
        </div>

        {/* Row 2: Anti-Crash Status */}
        <div className="bg-card/60 px-4 py-3.5">
          <div className="flex items-center justify-between gap-3">
            <div className="flex items-center gap-3 min-w-0 flex-1">
              <div className={`w-8 h-8 rounded-lg border flex items-center justify-center shrink-0 ${
                antiCrash ? 'bg-green-500/10 border-green-500/25' : 'bg-destructive/10 border-destructive/25'
              }`}>
                <ShieldCheck size={14} className={antiCrash ? 'text-green-500' : 'text-destructive'} />
              </div>
              <div className="min-w-0 flex-1">
                <p className="text-xs font-bold">Anti-Crash Guardrails</p>
                <div className="flex items-center gap-1.5 mt-0.5">
                  <span className={`inline-flex items-center gap-1 text-[9px] font-bold rounded-full px-2 py-0.5 ${
                    antiCrash
                      ? 'bg-green-500/10 text-green-500 border border-green-500/25'
                      : 'bg-destructive/10 text-destructive border border-destructive/25'
                  }`}>
                    <span className={`w-1.5 h-1.5 rounded-full ${antiCrash ? 'bg-green-500 animate-pulse' : 'bg-destructive'}`} />
                    {antiCrash ? 'ACTIVE — Saved to DB ✓' : 'DISABLED — System unprotected'}
                  </span>
                </div>
              </div>
            </div>
            <button
              onClick={toggleAntiCrash}
              disabled={togglingCrash}
              className={`shrink-0 relative w-11 h-6 rounded-full transition-colors ${
                antiCrash ? 'bg-green-500' : 'bg-muted-foreground/30'
              } ${togglingCrash ? 'opacity-50' : ''}`}
            >
              <span className={`absolute top-0.5 w-5 h-5 rounded-full bg-white shadow transition-transform ${
                antiCrash ? 'translate-x-[22px]' : 'translate-x-0.5'
              }`} />
            </button>
          </div>
        </div>
      </div>

      {/* Footer */}
      <div className="bg-accent/5 border border-accent/15 rounded-xl px-3 py-2 text-[10px] text-muted-foreground space-y-0.5">
        <p className="font-bold text-foreground">🔐 Hardened & Persistent Widget</p>
        <p>APK uploads use permanent cloud storage — URLs never expire. Anti-crash state is saved to the Admin Settings database and persists across all sessions and deployments.</p>
      </div>
    </div>
  );
}

// ─── Social Links Manager (Isolated Table) ───────────────────────────
function SocialLinksManager({ token }: { token: string }) {
  type LinkItem = { id: string; platformName: string; urlLink: string; isActive: boolean };
  const [links, setLinks] = useState<LinkItem[]>([]);
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);

  const load = useCallback(async () => {
    setLoading(true);
    try {
      const r = await socialLinksConfig({ action: 'get' });
      setLinks(r.links);
    } catch (e: any) { toast.error(e?.message ?? 'Failed to load social links'); }
    finally { setLoading(false); }
  }, []);

  useEffect(() => { load(); }, [load]);

  const setField = (idx: number, key: keyof LinkItem, val: string | boolean) =>
    setLinks(prev => prev.map((l, i) => i === idx ? { ...l, [key]: val } : l));

  const handleSave = async () => {
    setSaving(true);
    try {
      const r = await socialLinksConfig({ action: 'save', adminToken: token, links });
      if (r.success) {
        setLinks(r.links);
        toast.success('✅ Social links saved! Floating bar updated instantly.');
      } else {
        toast.error('Save failed — check admin token');
      }
    } catch (e: any) { toast.error(e?.message ?? 'Save failed'); }
    finally { setSaving(false); }
  };

  const PLATFORM_ICONS: Record<string, { emoji: string; color: string; placeholder: string }> = {
    YouTube:  { emoji: '🔴', color: 'border-red-500/30',  placeholder: 'https://youtube.com/@yourchannel' },
    Facebook: { emoji: '🔵', color: 'border-blue-500/30', placeholder: 'https://facebook.com/yourpage' },
    TikTok:   { emoji: '⬛', color: 'border-gray-500/30', placeholder: 'https://tiktok.com/@yourhandle' },
  };

  return (
    <div className="rounded-2xl border-2 border-secondary/30 bg-secondary/5 p-4 space-y-3">
      <div className="flex items-center gap-2">
        <div className="w-8 h-8 rounded-xl bg-secondary/15 border border-secondary/30 flex items-center justify-center shrink-0">
          <Share2 size={16} className="text-secondary" />
        </div>
        <div className="flex-1 min-w-0">
          <p className="font-black text-sm">🔗 Social Media Links</p>
          <p className="text-[10px] text-muted-foreground">Isolated table — controls the floating social bar on the right side</p>
        </div>
        <button onClick={load} className="text-xs text-muted-foreground hover:text-foreground flex items-center gap-1 shrink-0"><RefreshCw size={10} /></button>
      </div>

      <div className="bg-secondary/5 border border-secondary/15 rounded-xl px-3 py-2 text-[10px] text-muted-foreground space-y-1">
        <p className="font-bold text-foreground">🛡️ Completely Isolated Data Store</p>
        <p>This section reads/writes ONLY to the <code className="text-secondary font-mono bg-secondary/10 px-1 rounded">social_links_config</code> table. Zero contact with Users, Admin Settings, or any other table.</p>
      </div>

      {loading ? (
        <div className="space-y-2">{[1,2,3].map(i => <Skeleton key={i} className="h-16 rounded-xl" />)}</div>
      ) : (
        <div className="space-y-3">
          {links.map((link, idx) => {
            const meta = PLATFORM_ICONS[link.platformName] ?? { emoji: '🔗', color: 'border-border', placeholder: 'https://...' };
            return (
              <div key={link.id} className={`rounded-xl border-2 ${meta.color} bg-card p-3 space-y-2`}>
                <div className="flex items-center justify-between">
                  <div className="flex items-center gap-2">
                    <span className="text-lg">{meta.emoji}</span>
                    <span className="font-bold text-sm">{link.platformName}</span>
                  </div>
                  <button
                    onClick={() => setField(idx, 'isActive', !link.isActive)}
                    className={`relative inline-flex h-6 w-11 shrink-0 cursor-pointer rounded-full border-2 transition-colors ${link.isActive ? 'bg-green-500 border-green-500' : 'bg-muted border-border'}`}>
                    <span className={`pointer-events-none inline-block h-4 w-4 transform rounded-full bg-white shadow-lg ring-0 transition-transform mt-0.5 ${link.isActive ? 'translate-x-5' : 'translate-x-0.5'}`} />
                  </button>
                </div>
                <div className="space-y-1">
                  <Label className="text-[10px] text-muted-foreground">Channel / Page URL</Label>
                  <Input
                    value={link.urlLink}
                    onChange={e => setField(idx, 'urlLink', e.target.value)}
                    placeholder={meta.placeholder}
                    className="bg-muted border-border text-xs h-8 font-mono"
                  />
                </div>
                <div className="flex items-center gap-2 text-[9px]">
                  <span className={`font-bold ${link.isActive ? 'text-green-400' : 'text-muted-foreground'}`}>
                    {link.isActive ? '🟢 VISIBLE in floating bar' : '⚫ HIDDEN from floating bar'}
                  </span>
                </div>
              </div>
            );
          })}
        </div>
      )}

      <Button onClick={handleSave} disabled={saving || loading}
        className="w-full bg-secondary text-secondary-foreground font-bold h-10 gap-2 text-sm">
        {saving ? <><Loader2 size={14} className="animate-spin" /> Saving Links...</> : <><Check size={14} /> Save Links</>}
      </Button>

      <p className="text-[9px] text-muted-foreground text-center">
        Changes go live immediately on the right-side floating social bar for all users
      </p>
    </div>
  );
}

