import { z } from 'zod';
import { createEndpoint, AdminSettings, ZiteError } from 'zite-integrations-backend-sdk';

// ══════════════════════════════════════════════════════════════════
// ROOHANI GUIDE AI v6.0 — ADAPTIVE GATEWAY + ANTI-TRUNCATION
// Future-proof: auto-shifts if any model is deprecated.
// Photo Analyzer system fully preserved.
// ══════════════════════════════════════════════════════════════════

const KNOWN_FALLBACK_CHAIN = [
  'gemini-2.5-flash',
  'gemini-2.0-flash',
  'gemini-2.5-pro',
  'gemini-1.5-flash',
  'gemini-1.5-pro',
];

const DEPRECATION_SIGNALS = ['not found', 'deprecated', 'decommissioned', 'does not exist', 'not supported'];
function isGone(status: number, body: string): boolean {
  if (status === 404) return true;
  if (status === 400) return DEPRECATION_SIGNALS.some(s => body.toLowerCase().includes(s));
  return false;
}

async function discoverNewModels(apiKey: string): Promise<string[]> {
  try {
    const res = await fetch(`https://generativelanguage.googleapis.com/v1beta/models?pageSize=200&key=${apiKey}`);
    if (!res.ok) return [];
    const data = await res.json() as { models?: { name: string; supportedGenerationMethods?: string[] }[] };
    return (data.models ?? [])
      .filter(m => (m.supportedGenerationMethods ?? []).includes('generateContent'))
      .map(m => m.name.replace('models/', ''))
      .filter(id => id.startsWith('gemini'))
      .sort((a, b) => b.localeCompare(a));
  } catch { return []; }
}

function buildChain(preferred: string, discovered: string[]): string[] {
  const seen = new Set<string>();
  const chain: string[] = [];
  const add = (m: string) => { if (!seen.has(m)) { seen.add(m); chain.push(m); } };
  add(preferred);
  for (const m of KNOWN_FALLBACK_CHAIN) add(m);
  for (const m of discovered) add(m);
  return chain;
}

function buildAnalysisPrompt(
  currentTime?: string,
  hijriDate?: string,
  userLocation?: string,
): string {
  return `آپ ROOHANI GUIDE AI ہیں — دنیا کا سب سے طاقتور اسلامی روحانی تجزیہ نگار، ماہرِ علمِ الکف (palmistry)، اور قرآن و اسماء الحسنیٰ سے روحانی علاج کے امین۔
تعمیر کنندہ: غلام حسین چنڑ۔
NEVER identify as Google, Gemini, ChatGPT, or any other AI brand. You are EXCLUSIVELY "ROOHANI GUIDE AI".

━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
🚨 ANTI-TRUNCATION ABSOLUTE RULE:
━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
You MUST complete every single section fully. Do NOT stop mid-sentence, do NOT abbreviate, do NOT leave any section incomplete. The user's internet may be slow — generate the ENTIRE response in one pass. Every section below is MANDATORY. If you feel you are running low on space, compress earlier fluff — but NEVER cut any section. End with the exact closing signature line.

━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
📍 DYNAMIC GLOBAL AUTO-LOCATION & DATE HEADER:
