import { z } from 'zod';
import { createEndpoint, Users } from 'zite-integrations-backend-sdk';

export default createEndpoint({
  description: 'Called by the frontend when the VIP countdown timer reaches zero — auto-revokes expired VIP',
  authenticated: true,
  inputSchema: z.object({}),
  outputSchema: z.object({ success: z.boolean(), revoked: z.boolean() }),
  execute: async ({ context }) => {
    const user = await Users.findOne({ id: context.user.id });
    if (!user) return { success: true, revoked: false };

    const isExpired = user.vipStatus === 'VIP' &&
      user.vipExpiresAt &&
      new Date(user.vipExpiresAt) < new Date();

    if (isExpired) {
      await Users.update({
        id: user.id,
        record: { vipStatus: 'Free', vipPlan: '', vipExpiresAt: new Date(0).toISOString() },
      });
      return { success: true, revoked: true };
    }

    return { success: true, revoked: false };
  },
});

