import { useEffect, useState, useRef, useCallback } from 'react';
import { useAuth } from 'zite-auth-sdk';
import { getWalletData, GetWalletDataOutputType } from 'zite-endpoints-sdk';
import { useAppData } from '@/contexts/AppDataContext';
import WalletStats from '@/components/wallet/WalletStats';
import ReferralSection from '@/components/wallet/ReferralSection';
import TeamList from '@/components/wallet/TeamList';
import LevelMap from '@/components/wallet/LevelMap';
import WithdrawalModal from '@/components/wallet/WithdrawalModal';
import TransactionLedger from '@/components/wallet/TransactionLedger';
import { Button } from '@/components/ui/button';
import { Skeleton } from '@/components/ui/skeleton';
import { ArrowDownCircle, Coins, Wifi, RefreshCw, Crown, Timer } from 'lucide-react';
import { toast } from 'sonner';

// Live sync interval — refreshes balance every 30 seconds
const LIVE_SYNC_INTERVAL_MS = 30_000;

function VipCountdownBadge({ expiresAt }: { expiresAt: string }) {
  const calc = () => {
    const ms = new Date(expiresAt).getTime() - Date.now();
    if (ms <= 0) return null;
    const d = Math.floor(ms / 86400000);
    const h = Math.floor((ms % 86400000) / 3600000);
    const m = Math.floor((ms % 3600000) / 60000);
    const s = Math.floor((ms % 60000) / 1000);
    return { d, h, m, s };
  };
  const [t, setT] = useState(calc);
  useEffect(() => {
    const id = setInterval(() => setT(calc()), 1000);
    return () => clearInterval(id);
  }, [expiresAt]);
  if (!t) return <span className="text-xs text-destructive font-bold">EXPIRED</span>;
  const pad = (n: number) => String(n).padStart(2, '0');
  return (
    <div className="flex items-center gap-1 text-[10px] text-primary font-mono">
      <Timer size={9} />
      <span>{t.d}d {pad(t.h)}:{pad(t.m)}:{pad(t.s)}</span>
    </div>
  );
}

export default function WalletPage() {
  const { user, isLoading, loginWithRedirect } = useAuth();
  const { refreshCount } = useAppData();
  const [data, setData] = useState<GetWalletDataOutputType | null>(null);
  const [loading, setLoading] = useState(true);
  const [syncing, setSyncing] = useState(false);
  const [lastSync, setLastSync] = useState<Date | null>(null);
  const [showTeam, setShowTeam] = useState(false);
  const [showLevels, setShowLevels] = useState(false);
  const [showWithdraw, setShowWithdraw] = useState(false);
  const [ledgerRefresh, setLedgerRefresh] = useState(0);
  const lastRefreshCountRef = useRef(refreshCount);
  const liveTimerRef = useRef<ReturnType<typeof setInterval> | null>(null);

  const fetchWallet = useCallback(async (silent = false) => {
    if (!silent) setLoading(true);
    else setSyncing(true);
    try {
      const d = await getWalletData({});
      setData(d);
      setLastSync(new Date());
    } catch (e: any) {
      if (!silent) toast.error(e?.message ?? 'Failed to load wallet');
    } finally {
      if (!silent) setLoading(false);
      else setSyncing(false);
    }
  }, []);

  // Initial load
  useEffect(() => {
    if (!isLoading && !user) { loginWithRedirect({ redirectUrl: window.location.href }); return; }
    if (user) fetchWallet(false);
  }, [isLoading, user]);

  // ── REAL-TIME LIVE SYNC — polls every 30 seconds ──────────────
  useEffect(() => {
    if (!user) return;
    liveTimerRef.current = setInterval(() => {
      fetchWallet(true); // silent = no loading spinner
    }, LIVE_SYNC_INTERVAL_MS);
    return () => {
      if (liveTimerRef.current) clearInterval(liveTimerRef.current);
    };
  }, [user, fetchWallet]);

  // Re-sync when admin changes settings
  useEffect(() => {
    if (!user) return;
    if (refreshCount !== lastRefreshCountRef.current && refreshCount > 0) {
      lastRefreshCountRef.current = refreshCount;
      fetchWallet(true);
    }
  }, [refreshCount, user, fetchWallet]);

  const reload = () => fetchWallet(true);

  if (isLoading || !user) return null;

  if (loading) return (
    <div className="p-4 space-y-4">
      <Skeleton className="h-28 w-full rounded-2xl" />
      <Skeleton className="h-32 w-full rounded-2xl" />
      <Skeleton className="h-40 w-full rounded-2xl" />
      <Skeleton className="h-20 w-full rounded-2xl" />
    </div>
  );

  if (!data) return <div className="p-8 text-center text-muted-foreground">Failed to load wallet data.</div>;

  const minUsd = data.minWithdrawUsd ?? 1;
  const canWithdraw = data.usdBalance >= minUsd;
  const isVip = data.vipStatus === 'VIP';

  return (
    <>
      <div className="space-y-3 pb-6">
        {/* ── Live Sync Status Bar ── */}
        <div className="mx-4 flex items-center justify-between bg-muted/30 border border-border/50 rounded-xl px-3 py-1.5">
          <div className="flex items-center gap-1.5">
            <span className={`w-1.5 h-1.5 rounded-full ${syncing ? 'bg-yellow-400 animate-pulse' : 'bg-green-400'}`} />
            <Wifi size={10} className="text-muted-foreground" />
            <span className="text-[10px] text-muted-foreground">
              {syncing ? 'Syncing...' : 'Live sync active'}
            </span>
          </div>
          <div className="flex items-center gap-2">
            {lastSync && (
              <span className="text-[9px] text-muted-foreground/60">
                {lastSync.toLocaleTimeString('en-PK', { hour: '2-digit', minute: '2-digit', second: '2-digit' })}
              </span>
            )}
            <button onClick={reload} disabled={syncing}
              className="text-muted-foreground hover:text-primary transition-colors disabled:opacity-40">
              <RefreshCw size={11} className={syncing ? 'animate-spin' : ''} />
            </button>
          </div>
        </div>

        {/* ── VIP Banner (if active) ── */}
        {isVip && data.vipPlan && (
          <div className="mx-4 flex items-center gap-2 bg-primary/10 border border-primary/30 rounded-xl px-3 py-2">
            <Crown size={14} className="text-primary shrink-0" />
            <div className="flex-1 min-w-0">
              <p className="text-xs font-bold text-primary truncate">👑 {data.vipPlan}</p>
              {data.vipExpiresAt && new Date(data.vipExpiresAt).getFullYear() !== 1970 && (
                <VipCountdownBadge expiresAt={data.vipExpiresAt} />
              )}
            </div>
            <span className="text-[9px] bg-primary/20 text-primary px-1.5 py-0.5 rounded-full font-bold">VIP</span>
          </div>
        )}

        <WalletStats coins={data.coins} usdBalance={data.usdBalance} usdToPkr={data.usdToPkr} vipStatus={data.vipStatus} />

        {/* Referral Coin Bonus info */}
        {data.referralRewardCoins > 0 && (
          <div className="mx-4 flex items-center gap-2 bg-primary/5 border border-primary/20 rounded-xl px-3 py-2">
            <Coins size={13} className="text-primary shrink-0" />
            <p className="text-[11px] text-muted-foreground">
              Invite friends → both get{' '}
              <span className="text-primary font-bold">{Math.floor(data.referralRewardCoins / 2)} coins</span>{' '}
              each (50-50 split of {data.referralRewardCoins} total)
            </p>
          </div>
        )}

        {/* Withdraw Button */}
        <div className="px-4">
          <Button
            onClick={() => setShowWithdraw(true)}
            className="w-full bg-green-600 hover:bg-green-600/90 text-white font-bold gap-2"
            disabled={!canWithdraw}
          >
            <ArrowDownCircle size={16} /> Withdraw Earnings
          </Button>
          {!canWithdraw && (
            <p className="text-xs text-muted-foreground text-center mt-1.5">
              Minimum <span className="text-primary font-semibold">${minUsd.toFixed(2)}</span> required to withdraw
            </p>
          )}
        </div>

        {/* Transaction Ledger */}
        <TransactionLedger refreshTrigger={ledgerRefresh} />

        <ReferralSection
          referralCode={data.referralCode}
          totalReferrals={data.totalReferrals}
          level={data.level}
          totalCommissionEarned={data.totalCommissionEarned}
          onViewTeam={() => setShowTeam(true)}
          onViewLevels={() => setShowLevels(true)}
        />
      </div>

      {showTeam && <TeamList referrals={data.referrals} onBack={() => setShowTeam(false)} />}
      {showLevels && (
        <LevelMap
          levels={data.levels}
          currentLevel={data.level}
          totalReferrals={data.totalReferrals}
          onBack={() => setShowLevels(false)}
        />
      )}
      {showWithdraw && (
        <WithdrawalModal
          open={showWithdraw}
          onClose={() => setShowWithdraw(false)}
          usdBalance={data.usdBalance}
          onSuccess={() => { reload(); setLedgerRefresh(r => r + 1); }}
          minWithdrawUsd={minUsd}
        />
      )}
    </>
  );
}

