import { z } from 'zod';
import { createEndpoint, VideoApiKeys, AdminSettings, ZiteError } from 'zite-integrations-backend-sdk';

// ═══════════════════════════════════════════════════════════════════════════
// ISOLATED ASYNC VERIFICATION — 3 gateways (Fal.ai removed)
// ═══════════════════════════════════════════════════════════════════════════

async function verifyGoogleVeo(key: string): Promise<{ ok: boolean; message: string }> {
  try {
    const res = await fetch(`https://generativelanguage.googleapis.com/v1beta/models?key=${key}`, {
      signal: AbortSignal.timeout(10000),
    });
    if (!res.ok) return { ok: false, message: `HTTP ${res.status} — key rejected by Google API` };
    const data = await res.json() as { models?: { name: string }[] };
    const veoModels = (data.models ?? []).filter(m => m.name.includes('veo'));
    if (veoModels.length > 0) {
      return { ok: true, message: `🟢 100% Success: Route Verified — ${veoModels.length} Veo model(s) available` };
    }
    return { ok: true, message: '🟡 Key valid but no Veo models found — enable Veo at aistudio.google.com' };
  } catch (e) {
    return { ok: false, message: `Connection failed: ${String(e)}` };
  }
}

async function verifyHuggingFace(key: string): Promise<{ ok: boolean; message: string }> {
  try {
    const res = await fetch('https://huggingface.co/api/whoami-v2', {
      headers: { 'Authorization': `Bearer ${key}` },
      signal: AbortSignal.timeout(10000),
    });
    if (!res.ok) return { ok: false, message: `HTTP ${res.status} — HuggingFace token rejected` };
    const data = await res.json() as { name?: string };
    return { ok: true, message: `🟢 100% Success: Route Verified — HF user: ${data.name ?? 'verified'} · Engines: ByteDance, Stability, Alibaba` };
  } catch (e) {
    return { ok: false, message: `Connection failed: ${String(e)}` };
  }
}

async function verifyStabilityAi(key: string): Promise<{ ok: boolean; message: string }> {
  try {
    const res = await fetch('https://api.stability.ai/v1/user/account', {
      headers: { 'Authorization': `Bearer ${key}` },
      signal: AbortSignal.timeout(10000),
    });
    if (!res.ok) return { ok: false, message: `HTTP ${res.status} — Stability AI key rejected` };
    return { ok: true, message: '🟢 100% Success: Route Verified — Stability account connected' };
  } catch (e) {
    return { ok: false, message: `Connection failed: ${String(e)}` };
  }
}

export default createEndpoint({
  description: 'Verify and save/update a single video API gateway key (3 gateways: Veo, HuggingFace, Stability)',
  inputSchema: z.object({
    adminToken: z.string(),
    keyIdentifier: z.enum(['google_veo_key', 'huggingface_api_key', 'stability_api_key']),
    apiKey: z.string().min(1),
  }),
  outputSchema: z.object({
    success: z.boolean(),
    message: z.string(),
    status: z.string(),
  }),
  execute: async ({ input }) => {
    const pwdRow = await AdminSettings.findOne({ filters: { settingKey: 'admin_password' } });
    const pwd = pwdRow?.settingValue ?? 'admin@2024';
    if (input.adminToken !== pwd) {
      throw new ZiteError({ code: 'UNAUTHORIZED', message: 'Invalid admin token' });
    }

    const NAMES: Record<string, { name: string; priority: number }> = {
      huggingface_api_key: { name: 'HuggingFace (ByteDance/Stability/Alibaba)', priority: 1 },
      stability_api_key:   { name: 'Stability AI Engine',                   priority: 2 },
      google_veo_key:      { name: 'Google Veo (Legacy)',                    priority: 3 },
    };

    let result: { ok: boolean; message: string } = { ok: false, message: 'Unknown gateway' };
    switch (input.keyIdentifier) {
      case 'google_veo_key':      result = await verifyGoogleVeo(input.apiKey); break;
      case 'huggingface_api_key': result = await verifyHuggingFace(input.apiKey); break;
      case 'stability_api_key':   result = await verifyStabilityAi(input.apiKey); break;
    }

    const status = result.ok ? 'Active' : 'Error';
    const info = NAMES[input.keyIdentifier];

    const existing = await VideoApiKeys.findOne({ filters: { keyIdentifier: input.keyIdentifier } });
    if (existing) {
      await VideoApiKeys.update({
        id: existing.id,
        record: {
          gatewayName: info.name,
          gatewayKey: input.apiKey,
          status,
          priorityOrder: info.priority,
          lastVerificationMessage: result.message,
          lastVerifiedAt: new Date().toISOString(),
        },
      });
    } else {
      await VideoApiKeys.create({
        record: {
          gatewayName: info.name,
          gatewayKey: input.apiKey,
          keyIdentifier: input.keyIdentifier,
          status,
          priorityOrder: info.priority,
          lastVerificationMessage: result.message,
          lastVerifiedAt: new Date().toISOString(),
        },
      });
    }

    return { success: result.ok, message: result.message, status };
  },
});

