import { z } from 'zod';
import { createEndpoint, Users, MediaGenerations, AdminSettings, VideoApiKeys, ZiteError } from 'zite-integrations-backend-sdk';

// ══════════════════════════════════════════════════════════════════
// ISOLATED BOX: GOOGLE VEO
// This endpoint has ZERO dependency on HuggingFace or Stability AI.
// It uses only the Google Veo / Gemini API key.
// If Veo fails (no credits, bad key), it fails quietly inside its
// own box — no cross-engine contamination.
// ══════════════════════════════════════════════════════════════════

// ── Content Safety Filter ────────────────────────────────────────
const BLOCKED = [
  'nude','nudity','naked','sexy','seductive','erotic','intimate','sensual',
  'undress','lingerie','bikini','provocative','obscene','porn','pornography',
  'nsfw','xxx','adult content','hentai','fetish','bondage','bdsm',
  'sexual','intercourse','orgasm','masturbat','stripper','prostitut',
  'anti-government','hate speech','propaganda','terrorism','terrorist',
  'extremist','riot','revolution against','overthrow','sedition',
  'kill','murder','assassination','genocide','ethnic cleansing',
  'racial slur','racist','bigot','supremacist',
];
function isSafe(prompt: string): boolean {
  const lower = prompt.toLowerCase();
  return !BLOCKED.some(w => lower.includes(w));
}

// ── Watermark ────────────────────────────────────────────────────
const WATERMARK = 'Powered by Hussain AI';

// ── Veo model chain ──────────────────────────────────────────────
const VEO_MODELS = [
  'veo-3.0-generate-preview',
  'veo-3.0-fast-generate-preview',
  'veo-2.0-generate-001',
];
const API_BASE = 'https://generativelanguage.googleapis.com/v1beta';

export default createEndpoint({
  description: 'ISOLATED Google Veo video engine. No cross-engine dependencies.',
  authenticated: true,
  inputSchema: z.object({
    prompt: z.string().min(5),
    durationSeconds: z.number().min(5).max(60).default(8),
    aspectRatio: z.enum(['16:9', '9:16']).default('16:9'),
  }),
  outputSchema: z.object({
    success: z.boolean(),
    operationId: z.string().optional(),
    videoUrl: z.string().optional(),
    videoBase64: z.string().optional(),
    mimeType: z.string().optional(),
    engine: z.string(),
    watermark: z.string().optional(),
    pipelineLog: z.array(z.string()),
  }),
  execute: async ({ input, context }) => {
    if (!isSafe(input.prompt)) {
      throw new ZiteError({ code: 'BAD_REQUEST', message: 'یہ مواد پالیسی کے خلاف ہے!' });
    }

    const user = await Users.findOne({ id: context.user.id });
    const isVIP = user?.vipStatus === 'VIP' && (!user.vipExpiresAt || new Date(user.vipExpiresAt) > new Date());
    if (!isVIP) throw new ZiteError({ code: 'FORBIDDEN', message: '🔒 VIP membership required.' });

    const today = new Date().toISOString().slice(0, 10);
    const [usageRes, limitSetting] = await Promise.all([
      MediaGenerations.findAll({ filters: { userEmail: context.user.email, date: today, type: 'Video' }, limit: 10 }),
      AdminSettings.findOne({ filters: { settingKey: 'vid_limit_vip' } }),
    ]);
    const dailyLimit = parseInt(limitSetting?.settingValue ?? '3') || 3;
    const usedToday = usageRes.records.reduce((s, r) => s + (r.count ?? 0), 0);
    if (usedToday >= dailyLimit) throw new ZiteError({ code: 'RATE_LIMITED', message: '⏰ Daily video limit reached.' });

    // ── Only fetch Google Veo / Gemini key — no other keys ──
    const veoKeyRecord = await VideoApiKeys.findOne({ filters: { keyIdentifier: 'google_veo_key', status: 'Active' } });
    let veoKey = veoKeyRecord?.gatewayKey;
    if (!veoKey) {
      const geminiSetting = await AdminSettings.findOne({ filters: { settingKey: 'gemini_api_key' } });
      veoKey = geminiSetting?.settingValue;
    }
    if (!veoKey) throw new ZiteError({ code: 'BAD_REQUEST', message: '⚙️ Google Veo / Gemini key not configured.' });

    const pipelineLog: string[] = [];
    const safePrompt = input.prompt.replace(/\b(nsfw|explicit|nude|naked)\b/gi, '').trim() + ', cinematic quality, SFW';

    for (const model of VEO_MODELS) {
      pipelineLog.push(`⏳ Trying ${model}...`);
      try {
        console.log(`[Hussain AI: Google Veo — trying ${model}]`);
        const res = await fetch(`${API_BASE}/models/${model}:generateVideos?key=${veoKey}`, {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({
            prompt: safePrompt,
            aspectRatio: input.aspectRatio,
            durationSeconds: input.durationSeconds,
            sampleCount: 1,
          }),
          signal: AbortSignal.timeout(25000),
        });

        if (res.status === 402) { pipelineLog[pipelineLog.length - 1] = `❌ ${model} — Payment required`; return { success: false, engine: model, pipelineLog }; }
        if (res.status === 429) { pipelineLog[pipelineLog.length - 1] = `⏭ ${model} — Rate limited`; continue; }
        if (res.status === 404 || res.status === 400) { pipelineLog[pipelineLog.length - 1] = `⏭ ${model} — Not available`; continue; }
        if (!res.ok) { pipelineLog[pipelineLog.length - 1] = `⏭ ${model} — HTTP ${res.status}`; continue; }

        const data = await res.json() as any;

        // LRO operation
        if (data.name) {
          await MediaGenerations.create({ record: { userEmail: context.user.email, date: today, type: 'Video', count: 1 } });
          pipelineLog[pipelineLog.length - 1] = `✅ ${model} — Job submitted`;
          return { success: true, operationId: data.name, engine: model, watermark: WATERMARK, pipelineLog };
        }

        // Inline video
        const samples: any[] = data.videos ?? data.generatedSamples ?? [];
        if (samples.length > 0) {
          const vid = samples[0]?.video ?? samples[0];
          const videoUrl = vid?.uri ?? vid?.url;
          const videoBase64 = vid?.encodedContent ?? vid?.data;
          if (videoUrl || videoBase64) {
            await MediaGenerations.create({ record: { userEmail: context.user.email, date: today, type: 'Video', count: 1 } });
            pipelineLog[pipelineLog.length - 1] = `✅ ${model} — Video ready`;
            return { success: true, videoUrl, videoBase64, mimeType: vid?.mimeType ?? 'video/mp4', engine: model, watermark: WATERMARK, pipelineLog };
          }
        }

        pipelineLog[pipelineLog.length - 1] = `⏭ ${model} — No video in response`;
      } catch (err: any) {
        pipelineLog[pipelineLog.length - 1] = `⏭ ${model} — ${err?.name === 'TimeoutError' ? 'Timeout' : 'Error'}`;
        continue;
      }
    }

    return { success: false, engine: 'Google Veo', pipelineLog };
  },
});

