    if (usedToday >= dailyLimit) throw new ZiteError({ code: 'RATE_LIMITED', message: '⏰ Daily video limit reached.' });

    // ── Stability AI key from environment variable (dedicated, isolated) ──
    const STABILITY_KEY = process.env.ZITE_STABILITY_API_KEY;
    if (!STABILITY_KEY) throw new ZiteError({ code: 'BAD_REQUEST', message: '⚙️ Stability AI key not configured. Set ZITE_STABILITY_API_KEY in environment.' });

