      }
      if (data.video) {
        await MediaGenerations.create({ record: { userEmail: context.user.email, date: today, type: 'Video', count: 1 } });
        pipelineLog[0] = '✅ Stability AI — Video ready';
        return { success: true, videoBase64: data.video, mimeType: 'video/mp4', engine: 'Stability AI v2', watermark: WATERMARK, pipelineLog };
      }

      pipelineLog[0] = '❌ Stability AI — Unexpected response';
    } catch (err: any) {
      pipelineLog[0] = `❌ Stability AI — ${err?.name === 'TimeoutError' ? 'Timeout' : 'Error'}`;
    }

    return { success: false, engine: 'Stability AI', pipelineLog };
  },
});

