import { useAuth } from 'zite-auth-sdk';
import { useNavigate } from 'react-router-dom';
import { HelpCircle, Wallet, Bot, LogOut, Sun, Moon, Share2, Bell } from 'lucide-react';
import { useAppData } from '@/contexts/AppDataContext';
import { Avatar, AvatarFallback } from '@/components/ui/avatar';
import { DropdownMenu, DropdownMenuContent, DropdownMenuItem, DropdownMenuTrigger } from '@/components/ui/dropdown-menu';
import ThreeDotMenu from './ThreeDotMenu';
import SocialShare from './SocialShare';
import HelpCenterModal from './HelpCenterModal';
import { toast } from 'sonner';
import { useState, useEffect, useCallback } from 'react';

// Removed: location & weatherApiKey from LiveMiniClock — location is shown in MagicCalendarStrip only

function useTheme() {
  const [theme, setTheme] = useState<'dark' | 'light'>(() => {
    if (typeof window !== 'undefined') {
      const saved = (localStorage.getItem('app_theme') as 'dark' | 'light') ?? 'dark';
      if (saved === 'light') document.documentElement.classList.add('light');
      else document.documentElement.classList.remove('light');
      return saved;
    }
    return 'dark';
  });

  useEffect(() => {
    const root = document.documentElement;
    if (theme === 'light') root.classList.add('light');
    else root.classList.remove('light');
    localStorage.setItem('app_theme', theme);
  }, [theme]);

  return { theme, toggle: () => setTheme(t => t === 'dark' ? 'light' : 'dark') };
}

// ── Live Mini Digital Clock — single clean ticking clock ──
function LiveMiniClock() {
  const [time, setTime] = useState('');

  useEffect(() => {
    const tick = () => {
      setTime(new Date().toLocaleTimeString('en-US', {
        hour: '2-digit', minute: '2-digit', second: '2-digit', hour12: true, timeZone: Intl.DateTimeFormat().resolvedOptions().timeZone,
      }));
    };
    tick();
    const id = setInterval(tick, 1000);
    return () => clearInterval(id);
  }, []);

  if (!time) return null;
  return (
    <span className="text-[10px] font-mono font-bold tracking-wider tabular-nums leading-none select-none clock-glow">
      ⏰ {time}
    </span>
  );
}

// ── Notification Bell ────────────────────────────────────────────────
function NotificationBell() {
  const { globalNotification } = useAppData();
  const [hasUnread, setHasUnread] = useState(false);
  const [showPopup, setShowPopup] = useState(false);

  useEffect(() => {
    if (!globalNotification) return;
    const lastSeen = localStorage.getItem('last_notification_seq') ?? '';
    if (lastSeen !== globalNotification.seq) setHasUnread(true);
  }, [globalNotification]);

  const handleBellClick = useCallback(() => {
    if (!globalNotification) { toast.info('No new notifications'); return; }
    setShowPopup(v => !v);
    if (hasUnread) {
      setHasUnread(false);
      localStorage.setItem('last_notification_seq', globalNotification.seq);
    }
  }, [globalNotification, hasUnread]);

  return (
    <div className="relative">
      <button
        onClick={handleBellClick}
        className="p-1.5 rounded-full hover:bg-muted transition-colors relative"
        title={hasUnread ? 'New notification' : 'Notifications'}
      >
        <Bell size={17} className={hasUnread ? 'text-primary' : 'text-muted-foreground'} />
        {hasUnread && (
          <span className="absolute top-1 right-1 w-2 h-2 bg-destructive rounded-full border-2 border-card animate-pulse" />
        )}
      </button>

      {showPopup && globalNotification && (
        <>
          <div className="fixed inset-0 z-40" onClick={() => setShowPopup(false)} />
          <div className="absolute right-0 top-11 z-50 w-72 bg-card border border-primary/30 rounded-2xl shadow-2xl overflow-hidden animate-in slide-in-from-top-2 duration-200">
            <div className="bg-primary/10 border-b border-primary/20 px-4 py-2.5 flex items-center gap-2">
              <Bell size={13} className="text-primary" />
              <span className="text-xs font-black text-primary">📢 Admin Notification</span>
            </div>
            <div className="px-4 py-3">
              <p className="text-sm leading-relaxed text-foreground">{globalNotification.message}</p>
            </div>
            <div className="px-4 pb-3">
              <button
                onClick={() => setShowPopup(false)}
                className="w-full text-xs text-muted-foreground bg-muted rounded-lg py-1.5 hover:text-foreground transition-colors"
              >
                Dismiss
              </button>
            </div>
          </div>
        </>
      )}
    </div>
  );
}

export default function Header({ onLogout }: { onLogout?: () => void }) {
  const { user, isLoading, loginWithRedirect, logout } = useAuth();
  const navigate = useNavigate();
  const { theme, toggle } = useTheme();
  const { aiName } = useAppData();
  const [shareOpen, setShareOpen] = useState(false);
  const [helpOpen, setHelpOpen] = useState(false);

  const handleWallet = () => {
    if (!user) { loginWithRedirect({ redirectUrl: window.location.origin + '/wallet' }); return; }
    navigate('/wallet');
  };

  const handleHelp = () => {
    if (!user) {
      loginWithRedirect({ redirectUrl: window.location.origin + '/', initialView: 'signup' });
      toast.info('Please log in to submit a support ticket');
      return;
    }
    setHelpOpen(true);
  };

  return (
    <>
      {/*
        ── HEADER ALIGNMENT FIX ────────────────────────────────────────
        • Left + Right sections: flex-shrink-0  → never compress/push inward
        • Center: flex-1 + justify-center        → always stays between L/R
        • px-3 + no justify-between              → consistent edge-flush layout
          across all browsers (Chrome, Safari, Firefox, external WebView)
        ───────────────────────────────────────────────────────────────── */}
      <header className="sticky top-0 z-50 bg-card/80 backdrop-blur-xl border-b border-border/50 flex items-center px-3 py-2 gap-0">

        {/* ── Left — flex-shrink-0 prevents it from ever compressing ── */}
        <div className="flex-shrink-0">
          <button
            onClick={handleHelp}
            className="p-1.5 rounded-full hover:bg-muted transition-colors"
            title="Help Center — Submit Support Ticket"
          >
            <HelpCircle size={19} className="text-muted-foreground hover:text-primary transition-colors" />
          </button>
        </div>

        {/* ── Center — flex-1 fills remaining space, content centered ── */}
        <button
          onClick={() => navigate('/')}
          className="flex-1 flex flex-col items-center justify-center gap-px min-w-0 py-0.5"
        >
          <div className="flex items-center gap-1.5">
            <div className="bg-primary/20 rounded-xl p-1.5 shrink-0">
              <Bot size={17} className="text-primary" />
            </div>
            <span className="text-base font-bold gold-gradient leading-tight truncate">
              {aiName || 'Hussain AI'}
            </span>
          </div>
          {/* Digital clock — placed right beneath the AI name */}
          <LiveMiniClock />
        </button>

        {/* ── Right — flex-shrink-0: always flush with right edge ────── */}
        <div className="flex-shrink-0 flex items-center gap-0">

          {/* Theme Toggle */}
          <button
            onClick={toggle}
            title={theme === 'dark' ? 'Light Mode' : 'Dark Mode'}
            className="p-1.5 rounded-full hover:bg-muted transition-colors"
          >
            {theme === 'dark'
              ? <Sun size={17} className="text-yellow-400" />
              : <Moon size={17} className="text-primary" />}
          </button>

          {/* Notification Bell */}
          <NotificationBell />

          {/* Share Button */}
          <button
            onClick={() => setShareOpen(true)}
            title="Share App"
            className="p-1.5 rounded-full hover:bg-muted transition-colors"
          >
            <Share2 size={17} className="text-muted-foreground hover:text-primary transition-colors" />
          </button>

          {/* Wallet */}
          <button onClick={handleWallet} className="p-1.5 rounded-full hover:bg-muted transition-colors">
            <Wallet size={17} className="text-muted-foreground hover:text-primary transition-colors" />
          </button>

          <ThreeDotMenu />

          {/* Avatar / Login */}
          {!isLoading && (
            user ? (
              <DropdownMenu>
                <DropdownMenuTrigger asChild>
                  <button className="ml-0.5 shrink-0">
                    <Avatar className="w-7 h-7 border-2 border-primary/50">
                      <AvatarFallback className="bg-primary/20 text-primary text-[10px] font-bold">
                        {(user.name || user.email)?.[0]?.toUpperCase() ?? 'U'}
