                    </Avatar>
                  </button>
                </DropdownMenuTrigger>
                <DropdownMenuContent align="end" className="bg-card border-border w-48">
                  <div className="px-3 py-2">
                    <p className="text-sm font-medium truncate">{user.name || 'User'}</p>
                    <p className="text-xs text-muted-foreground truncate">{user.email}</p>
                    {user.phone && <p className="text-[10px] text-muted-foreground">{user.phone}</p>}
                  </div>
                  <DropdownMenuItem onClick={() => setHelpOpen(true)} className="gap-2 cursor-pointer">
                    <HelpCircle size={14} /> Help Center
                  </DropdownMenuItem>
                  <DropdownMenuItem onClick={() => setShareOpen(true)} className="gap-2 cursor-pointer">
                    <Share2 size={14} /> Share App & Earn
                  </DropdownMenuItem>
                  <DropdownMenuItem
                    onClick={() => { onLogout?.(); logout({ returnTo: window.location.origin }); }}
