          )}
        </div>
      </header>

      <SocialShare
        open={shareOpen}
        onClose={() => setShareOpen(false)}
        referralCode={user?.referralCode}
      />

      <HelpCenterModal
        open={helpOpen}
        onClose={() => setHelpOpen(false)}
        userEmail={user?.email}
      />
    </>
  );
}

