import { useState, useEffect, useRef, useCallback } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from 'zite-auth-sdk';
import { generateImage, checkMediaLimit, generateHashtags, processImageToImage } from 'zite-endpoints-sdk';
import { Button } from '@/components/ui/button';
import { Textarea } from '@/components/ui/textarea';
import { toast } from 'sonner';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Image, Video, Wand2, MapPin, Loader2, Download, Film, FolderOpen, Camera, Hash, Sparkles, RefreshCw, X } from 'lucide-react';
import { Skeleton } from '@/components/ui/skeleton';
import { CheckMediaLimitOutputType } from 'zite-endpoints-sdk';
import SocialHashtagCards from '@/components/hashtag/SocialHashtagCards';

interface LocationData { lat: number; lng: number; label: string; }

// ── Compress + convert File to base64 (max 512px, JPEG 72%) ────
// Keeping payload small (<120 KB base64) prevents Worker payload errors
// and speeds up Gemini Vision ingestion.
function fileToBase64(file: File, maxSize = 512): Promise<string> {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = (e) => {
      const img = new window.Image() as HTMLImageElement;
      img.onload = () => {
        const canvas = document.createElement('canvas');
        const scale = Math.min(1, maxSize / Math.max(img.width, img.height));
        canvas.width  = Math.round(img.width  * scale);
        canvas.height = Math.round(img.height * scale);
        const ctx = canvas.getContext('2d');
        if (!ctx) { reject(new Error('Canvas not supported')); return; }
        ctx.drawImage(img, 0, 0, canvas.width, canvas.height);
        resolve(canvas.toDataURL('image/jpeg', 0.72).split(',')[1]);
      };
      img.onerror = reject;
      img.src = e.target?.result as string;
    };
    reader.onerror = reject;
    reader.readAsDataURL(file);
  });
}

export default function MediaLabPage() {
  const navigate = useNavigate();
  const { user, isLoading, loginWithRedirect } = useAuth();

  const [prompt, setPrompt]               = useState('');
  const [selectedModel, setSelectedModel] = useState<'flux-schnell' | 'sdxl' | 'google'>('flux-schnell');
  const [imageUrl, setImageUrl]           = useState('');
  const [generating, setGenerating]       = useState(false);
  const [imageLoaded, setImageLoaded]     = useState(false);
  const [limitInfo, setLimitInfo]         = useState<CheckMediaLimitOutputType | null>(null);
  const [hashtags, setHashtags]           = useState<string[]>([]);
  const [loadingTags, setLoadingTags]     = useState(false);
  const [location, setLocation]           = useState<LocationData | null>(null);
  const [locLoading, setLocLoading]       = useState(false);

  const [uploadedFile, setUploadedFile]         = useState<File | null>(null);
  const [uploadedFromDevice, setUploadedFromDevice] = useState(false);
  const [transformEnhancedPrompt, setTransformEnhancedPrompt] = useState('');
  const [renderingImage, setRenderingImage]     = useState(false);

  const galleryRef = useRef<HTMLInputElement>(null);
  const cameraRef  = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (!isLoading && !user) { loginWithRedirect({ redirectUrl: window.location.href }); return; }
    if (user) checkMediaLimit({}).then(setLimitInfo).catch(console.error);
  }, [isLoading, user]);

  const captureLocation = useCallback(() => {
    if (!navigator.geolocation) { toast.error('Location not supported'); return; }
    setLocLoading(true);
    navigator.geolocation.getCurrentPosition(
      async (pos) => {
        const { latitude: lat, longitude: lng } = pos.coords;
        let label = `${lat.toFixed(4)}°N, ${lng.toFixed(4)}°E`;
        try {
          const r = await fetch(`https://nominatim.openstreetmap.org/reverse?lat=${lat}&lon=${lng}&format=json`);
          const d = await r.json();
          const city  = d.address?.city || d.address?.town || d.address?.village || '';
          const state = d.address?.state || '';
          const country = d.address?.country || '';
          if (city) label = `${city}, ${state}, ${country}`;
        } catch { /* use coords label */ }
        setLocation({ lat, lng, label });
        setLocLoading(false);
      },
      () => { toast.error('Location access denied — please allow location permission'); setLocLoading(false); }
    );
  }, []);

  // ── Clear all state ───────────────────────────────────────────
  const clearAll = () => {
    if (imageUrl.startsWith('blob:')) URL.revokeObjectURL(imageUrl);
    setUploadedFile(null);
    setUploadedFromDevice(false);
    setImageUrl('');
    setHashtags([]);
    setImageLoaded(false);
    setRenderingImage(false);
    setTransformEnhancedPrompt('');
    setPrompt('');
  };

  // ── Text-to-Image ─────────────────────────────────────────────
  const handleGenerate = async () => {
    if (!prompt.trim()) { toast.error('Please enter a prompt'); return; }
    if (limitInfo?.locked) { toast.error('Free trial ended! Get VIP for unlimited images.'); return; }
    setGenerating(true); setImageLoaded(false); setImageUrl('');
    setHashtags([]); setTransformEnhancedPrompt(''); setRenderingImage(false);
    setUploadedFile(null); setUploadedFromDevice(false);
    try {
      const timeoutMs = selectedModel === 'google' ? 35_000 : 90_000;
      const timeout = new Promise<never>((_, reject) =>
        setTimeout(() => reject(new Error('Generation timed out — please try again')), timeoutMs)
      );
      const result = await Promise.race([generateImage({ prompt: prompt.trim(), model: selectedModel }), timeout]);
      setGenerating(false);
      setImageUrl(result.imageUrl);
      // Base64 images (HuggingFace) load instantly; URL images (Google) need render phase
      if (result.imageUrl.startsWith('data:')) {
        setImageLoaded(true);
        setRenderingImage(false);
      } else {
        setRenderingImage(true);
      }
      setLimitInfo(prev => prev ? { ...prev, remaining: result.remaining } : null);
      setLoadingTags(true);
      try {
        const tagRes = await generateHashtags({ prompt: prompt.trim() });
        setHashtags(tagRes.hashtags);
      } catch { /* silent */ }
      setLoadingTags(false);
      if (!location) captureLocation();
    } catch (err: any) {
      toast.error(err?.message ?? 'Generation failed. Try again.');
      setGenerating(false);
    }
  };

  // ── Image-to-Image (face-lock + prompt re-design) ─────────────
  const handleTransformImage = async () => {
    if (!uploadedFile) { handleGenerate(); return; }
    if (!prompt.trim()) {
      toast.error('Describe the transformation — e.g. "Dubai skyline background", "Forest setting, cinematic"');
      return;
    }
    if (limitInfo?.locked) { toast.error('Free trial ended! Get VIP for unlimited transformations.'); return; }

    setGenerating(true); setImageLoaded(false); setRenderingImage(false);
    setHashtags([]); setTransformEnhancedPrompt('');

    try {
      const base64 = await fileToBase64(uploadedFile);
      const mimeType = uploadedFile.type || 'image/jpeg';

      const timeout = new Promise<never>((_, reject) =>
        setTimeout(() => reject(new Error('⏱ Transform timed out — please try again')), 55_000)
      );
      const result = await Promise.race([
        processImageToImage({ imageData: base64, prompt: prompt.trim(), mimeType }),
        timeout,
      ]);

      if (imageUrl.startsWith('blob:')) URL.revokeObjectURL(imageUrl);

      setGenerating(false);
      setRenderingImage(true);
      setImageUrl(result.imageUrl);
      setTransformEnhancedPrompt(result.enhancedPrompt);
      setLimitInfo(prev => prev ? { ...prev, remaining: result.remaining } : null);

      // Transition to result state — no longer in upload mode
      setUploadedFile(null);
      setUploadedFromDevice(false);

      // Auto-generate hashtags from the enhanced prompt
      setLoadingTags(true);
      try {
        const tagRes = await generateHashtags({ prompt: result.enhancedPrompt.slice(0, 200) });
        setHashtags(tagRes.hashtags);
      } catch { /* silent */ }
      setLoadingTags(false);
      if (!location) captureLocation();
    } catch (err: any) {
      toast.error(err?.message ?? 'Image transformation failed. Try again.');
      setGenerating(false);
    }
  };

  // ── Hashtags only (no image transformation) ──────────────────
  const handleHashtagsOnly = async () => {
    if (!prompt.trim()) {
      toast.error('Type a caption or description above first');
      return;
    }
    setLoadingTags(true);
    try {
      const tagRes = await generateHashtags({ prompt: prompt.trim() });
      setHashtags(tagRes.hashtags);
      if (!location) captureLocation();
      toast.success('Hashtags generated!');
    } catch {
      toast.error('Hashtag generation failed. Please try again.');
    } finally {
      setLoadingTags(false);
    }
  };

  // ── File selected ─────────────────────────────────────────────
  const handleFileSelected = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    if (!file.type.startsWith('image/')) { toast.error('Please select an image file'); return; }
    if (imageUrl.startsWith('blob:')) URL.revokeObjectURL(imageUrl);

    const objectUrl = URL.createObjectURL(file);
    setImageUrl(objectUrl);
    setImageLoaded(false);
    setRenderingImage(true);
    setHashtags([]);
    setTransformEnhancedPrompt('');
    setUploadedFile(file);
    setUploadedFromDevice(true);
    toast.success('📸 Photo ready! Describe your background change below, then tap Transform Image.');
    e.target.value = '';
  };

  if (isLoading || !user) return null;

  const isTransformMode = uploadedFromDevice && !!uploadedFile;

  return (
    <div className="p-4 space-y-4 max-w-lg mx-auto pb-8">

      {/* Header */}
      <div className="text-center">
        <h1 className="text-xl font-black flex items-center justify-center gap-2 text-foreground">
          <Image size={18} className="text-primary" /> 🎨 Image Studio
        </h1>
        <p className="text-xs text-muted-foreground mt-1">AI Generation · Gallery · Camera · Viral Hashtags</p>
      </div>

      {/* Trial limits */}
      {limitInfo && !limitInfo.isVIP && (
        limitInfo.locked ? (
          <div className="rounded-xl border border-destructive/30 bg-destructive/10 p-3 text-center space-y-1.5">
            <p className="text-xs font-bold text-destructive">🔒 3-Day Free Trial Ended</p>
            <p className="text-[10px] text-destructive/70">Upgrade to VIP for unlimited AI image generation!</p>
            <button onClick={() => navigate('/vip')} className="text-[10px] font-bold underline text-destructive">Get VIP Now →</button>
          </div>
        ) : (
          <div className="rounded-xl border border-primary/30 bg-primary/5 px-3 py-2.5 space-y-1">
            <div className="flex items-center justify-between">
              <span className="text-[10px] font-bold text-primary uppercase tracking-wide">
                🎁 Free Trial — Day {limitInfo.trialDay ?? limitInfo.daysSinceJoined + 1} of 3
              </span>
              <span className="text-[10px] text-primary font-mono">{limitInfo.remaining} left today</span>
            </div>
            <div className="flex gap-1">
              {[1, 2, 3].map(d => (
                <div key={d} className={`flex-1 h-1.5 rounded-full transition-colors ${d <= (limitInfo.trialDay ?? limitInfo.daysSinceJoined + 1) ? 'bg-primary/60' : 'bg-muted'}`} />
              ))}
            </div>
            <p className="text-[9px] text-muted-foreground">Day 1: 3 images · Day 2: 2 · Day 3: 1 · After: VIP required</p>
          </div>
        )
      )}
      {limitInfo?.isVIP && (
        <div className="text-center text-xs text-primary bg-primary/10 rounded-xl px-3 py-2 border border-primary/30">
          👑 VIP Member — Unlimited AI image generation!
        </div>
      )}

      {/* ── Transform mode banner ── */}
      {isTransformMode && (
        <div className="rounded-xl border border-secondary/40 bg-secondary/8 px-3 py-3 flex items-start gap-2.5">
          <Sparkles size={14} className="text-secondary shrink-0 mt-0.5" />
          <div className="flex-1 min-w-0 space-y-0.5">
            <p className="text-xs font-bold text-secondary">🔒 Face-Lock Active — Image Transform Mode</p>
            <p className="text-[10px] text-muted-foreground leading-relaxed">
              Your face is <strong>100% locked</strong>. Type a new background or style below — e.g. <em>"Dubai rooftop at night"</em>, <em>"Forest sunset, cinematic"</em>, <em>"Oil painting style"</em>
            </p>
          </div>
          <button onClick={clearAll} className="shrink-0 text-muted-foreground hover:text-destructive transition-colors p-0.5">
            <X size={14} />
          </button>
        </div>
      )}

      {/* ── Prompt Input ── */}
      <div className="space-y-2">
        <Textarea
          placeholder={
            isTransformMode
              ? '🎨 Describe the new background or style — e.g. "Eiffel Tower at night", "Studio portrait, white background"'
              : "Describe your image... e.g. 'Sunset over Pakistani mountains, photorealistic, 8K, cinematic' — unlimited length supported"
          }
          value={prompt}
          onChange={e => setPrompt(e.target.value)}
          className="bg-muted border-border text-sm resize-vertical min-h-[72px]"
          rows={3}
        />

        {/* ── Model Selector (only in text-to-image mode) ── */}
        {!isTransformMode && (
          <div className="space-y-1">
            <p className="text-[10px] font-semibold text-muted-foreground uppercase tracking-wide px-0.5">🔧 AI Engine</p>
            <Select value={selectedModel} onValueChange={v => setSelectedModel(v as any)}>
              <SelectTrigger className="bg-muted border-border text-sm h-10">
                <SelectValue />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="flux-schnell">
                  <span className="flex items-center gap-2">
                    <span className="text-sm">⚡</span>
                    <span>
                      <span className="font-bold">Flux.1 [schnell]</span>
                      <span className="text-[10px] text-muted-foreground ml-1.5">— Hyper-realistic faces & text</span>
                    </span>
                  </span>
                </SelectItem>
                <SelectItem value="sdxl">
                  <span className="flex items-center gap-2">
                    <span className="text-sm">🎬</span>
                    <span>
                      <span className="font-bold">SDXL</span>
                      <span className="text-[10px] text-muted-foreground ml-1.5">— Cinematic scenes & landscapes</span>
                    </span>
                  </span>
                </SelectItem>
                <SelectItem value="google">
                  <span className="flex items-center gap-2">
                    <span className="text-sm">🌐</span>
                    <span>
                      <span className="font-bold">Google Image Engine</span>
                      <span className="text-[10px] text-muted-foreground ml-1.5">— Cloud API powered</span>
                    </span>
                  </span>
                </SelectItem>
              </SelectContent>
            </Select>
          </div>
        )}

        {/* Primary action row */}
        <div className="grid grid-cols-2 gap-2">
          <Button
            onClick={isTransformMode ? handleTransformImage : handleGenerate}
            disabled={generating || !!limitInfo?.locked}
            className="bg-primary text-primary-foreground font-bold gap-1.5"
          >
            {isTransformMode
              ? <><Sparkles size={14} />{generating ? 'Applying...' : '✨ Transform Image'}</>
              : <><Wand2 size={14} />{generating ? 'Generating...' : '✨ AI Generate'}</>
            }
          </Button>
          <Button variant="outline" onClick={() => navigate('/ai/video')} className="border-secondary/40 text-secondary gap-1.5">
            <Film size={14} /> Video Studio
          </Button>
        </div>

        {/* Gallery / Camera */}
        <input ref={galleryRef} type="file" accept="image/*" className="hidden" onChange={handleFileSelected} />
        <input ref={cameraRef}  type="file" accept="image/*" capture="environment" className="hidden" onChange={handleFileSelected} />

        <div className="grid grid-cols-2 gap-2">
          <button
            onClick={() => galleryRef.current?.click()}
            className="flex items-center justify-center gap-2 border border-border rounded-xl px-3 py-2.5 text-sm font-semibold text-foreground hover:bg-muted/60 transition-colors active:scale-95"
          >
            <FolderOpen size={15} className="text-primary" />
            📁 Gallery
          </button>
          <button
            onClick={() => cameraRef.current?.click()}
            className="flex items-center justify-center gap-2 border border-border rounded-xl px-3 py-2.5 text-sm font-semibold text-foreground hover:bg-muted/60 transition-colors active:scale-95"
          >
            <Camera size={15} className="text-secondary" />
            📷 Camera
          </button>
        </div>

        {/* Hashtags-only subtle link — visible whenever a prompt is typed */}
        {prompt.trim() && !generating && (
          <div className="flex justify-center">
            <button
              onClick={handleHashtagsOnly}
              disabled={loadingTags}
              className="flex items-center gap-1.5 text-[11px] text-muted-foreground hover:text-primary transition-colors py-1"
            >
              {loadingTags
                ? <><Loader2 size={11} className="animate-spin" /> Generating hashtags...</>
                : <><Hash size={11} /> Generate hashtags only (no image change)</>
              }
            </button>
          </div>
        )}
      </div>

      {/* Phase 1: API call in progress */}
      {generating && (
        <div className="space-y-2">
          <Skeleton className="w-full aspect-square rounded-2xl" />
          <div className="flex items-center justify-center gap-2 text-xs text-muted-foreground">
            <Loader2 size={13} className="animate-spin text-primary" />
            <span className="animate-pulse">
              {isTransformMode
                ? '🔒 Analyzing face & applying your prompt...'
                : selectedModel === 'flux-schnell' ? '⚡ Flux.1 [schnell] is generating your image...'
                : selectedModel === 'sdxl' ? '🎬 SDXL is rendering your cinematic scene...'
                : '🌐 Google Engine is generating your image...'}
            </span>
          </div>
          {isTransformMode && (
            <p className="text-[10px] text-center text-muted-foreground/60">
              Locking facial identity · Redesigning background per your prompt · 15–30 seconds
            </p>
          )}
        </div>
      )}

      {/* Phase 2: Waiting for image to render */}
      {renderingImage && !imageLoaded && imageUrl && (
        <div className="space-y-2">
          <Skeleton className="w-full aspect-square rounded-2xl" />
          <div className="flex items-center justify-center gap-2 text-xs text-muted-foreground">
            <Loader2 size={13} className="animate-spin text-secondary" />
            <span className="animate-pulse">🖼️ Rendering your image — almost ready...</span>
          </div>
          <p className="text-[10px] text-center text-muted-foreground/50">This may take 10–20 seconds</p>
          <img
            src={imageUrl}
            alt=""
            className="hidden"
            onLoad={() => { setImageLoaded(true); setRenderingImage(false); }}
            onError={() => { toast.error('Image render failed — please try again'); setRenderingImage(false); }}
          />
        </div>
      )}

      {/* ── Image Output ── */}
      {imageUrl && !generating && imageLoaded && (
        <div className="space-y-3">

          {/* Image preview */}
          <div className="relative rounded-2xl overflow-hidden border border-border shadow-lg">
            <img
              src={imageUrl}
              alt={prompt || 'Generated image'}
              onLoad={() => { setImageLoaded(true); setRenderingImage(false); }}
              onError={() => { toast.error('Image load failed — try again'); setRenderingImage(false); }}
              className="w-full object-contain bg-muted/30"
            />
            {/* Save */}
            <a href={imageUrl} download="photo.jpg" target="_blank" rel="noreferrer"
              className="absolute bottom-3 right-3 bg-black/60 backdrop-blur rounded-xl px-3 py-1.5 flex items-center gap-1.5 text-xs text-white hover:bg-black/80 transition-colors">
              <Download size={12} /> Save
            </a>
            {/* New / Clear */}
            {!uploadedFromDevice && (
              <button
                onClick={clearAll}
                className="absolute top-3 right-3 bg-black/60 backdrop-blur rounded-xl px-3 py-1.5 flex items-center gap-1.5 text-xs text-white hover:bg-black/80 transition-colors"
              >
                <RefreshCw size={11} /> New
