      )}

      {/* Video CTA */}
      <div className="flex flex-col items-center gap-3 p-5 text-center border border-dashed border-secondary/30 rounded-2xl bg-secondary/5">
        <Video size={28} className="text-secondary opacity-70" />
        <div>
          <p className="font-bold text-sm">🎬 Video Creator Studio</p>
          <p className="text-xs text-muted-foreground mt-1">AI-powered scripts, storyboards &amp; viral hashtags</p>
