}

src/api/generateHashtags.ts.content:
import { z } from 'zod';
import { createEndpoint, AdminSettings } from 'zite-integrations-backend-sdk';

// ══════════════════════════════════════════════════════════════════
// ADAPTIVE GATEWAY — Fast model for hashtags with auto-shift
// ══════════════════════════════════════════════════════════════════
const KNOWN_FALLBACK_CHAIN = [
  'gemini-2.0-flash',
  'gemini-1.5-flash',
  'gemini-2.5-flash',
  'gemini-2.5-pro',
  'gemini-1.5-pro',
];

const DEPRECATION_SIGNALS = ['not found', 'deprecated', 'decommissioned', 'does not exist', 'not supported'];
function isGone(status: number, body: string): boolean {
  if (status === 404) return true;
  if (status === 400) return DEPRECATION_SIGNALS.some(s => body.toLowerCase().includes(s));
  return false;
}

async function discoverNewModels(apiKey: string): Promise<string[]> {
  try {
    const res = await fetch(`https://generativelanguage.googleapis.com/v1beta/models?pageSize=200&key=${apiKey}`);
    if (!res.ok) return [];
    const data = await res.json() as { models?: { name: string; supportedGenerationMethods?: string[] }[] };
    return (data.models ?? [])
      .filter(m => (m.supportedGenerationMethods ?? []).includes('generateContent'))
      .map(m => m.name.replace('models/', ''))
      .filter(id => id.startsWith('gemini'))
      .sort((a, b) => b.localeCompare(a));
  } catch { return []; }
}

function buildChain(preferred: string, discovered: string[]): string[] {
  const seen = new Set<string>();
  const chain: string[] = [];
  const add = (m: string) => { if (!seen.has(m)) { seen.add(m); chain.push(m); } };
  add(preferred);
  for (const m of KNOWN_FALLBACK_CHAIN) add(m);
  for (const m of discovered) add(m);
  return chain;
}

const STATIC_FALLBACK = [
  '#AIArt', '#DigitalArt', '#Viral', '#Trending', '#Creative',
  '#Aesthetic', '#Photography', '#AI', '#Design', '#Art',
  '#Beautiful', '#Amazing', '#Explore', '#Instagram', '#Pakistan',
  '#Reels', '#TikTok', '#Shorts',
];

export default createEndpoint({
  description: 'Generate viral hashtags — adaptive Gemini gateway with auto-shift',
  inputSchema: z.object({ prompt: z.string().min(3).max(500) }),
  outputSchema: z.object({ hashtags: z.array(z.string()) }),
  execute: async ({ input }) => {
    const settings = await AdminSettings.findAll({ limit: 200 });
    const records = settings.records;
    const geminiKey = records.find(s => s.settingKey === 'gemini_api_key')?.settingValue;
    const sectionModel = records.find(s => s.settingKey === 'gemini_fast_model')?.settingValue
      ?? records.find(s => s.settingKey === 'gemini_best_model')?.settingValue
      ?? 'gemini-2.0-flash';

    if (!geminiKey) {
      const words = input.prompt.split(/\s+/).filter(w => w.length > 3).slice(0, 6)
        .map(w => '#' + w.toLowerCase().replace(/[^a-z0-9]/g, ''));
      return { hashtags: [...words, ...STATIC_FALLBACK].slice(0, 18) };
    }

    const body = {
      contents: [{
        parts: [{
          text: `Generate exactly 18 viral social media hashtags for this content: "${input.prompt}"

Rules:
- Each hashtag starts with #
- Mix: 5 niche-specific, 5 broad trending, 4 community, 4 Pakistani/regional if applicable
- Return ONLY hashtags, one per line, no numbering or explanation`,
        }],
      }],
      generationConfig: { maxOutputTokens: 200, temperature: 0.9 },
    };

    const discovered = await discoverNewModels(geminiKey);
    const chain = buildChain(sectionModel, discovered);

    for (const model of chain) {
      try {
        const res = await fetch(
          `https://generativelanguage.googleapis.com/v1beta/models/${model}:generateContent?key=${geminiKey}`,
          { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify(body) }
        );
        if (res.status === 429 || res.status === 503) continue;
        if (!res.ok) {
          const errText = await res.text().catch(() => '');
          if (isGone(res.status, errText)) { console.log(`[Hashtags] Model "${model}" gone, auto-shifting...`); continue; }
          continue;
        }
        const data = await res.json() as { candidates?: { content?: { parts?: { text?: string }[] } }[] };
        const text = data.candidates?.[0]?.content?.parts?.[0]?.text ?? '';
        const hashtags = text
          .split('\n')
          .map((l: string) => l.trim())
          .filter((l: string) => l.startsWith('#') && l.length > 1)
          .slice(0, 20);
        if (hashtags.length >= 10) return { hashtags };
      } catch { continue; }
    }

    return { hashtags: STATIC_FALLBACK };
  },
});

src/api/setupUserProfile.ts.content:
// ══════════════════════════════════════════════════════════════════
// SETUP USER PROFILE v2.0
// • Generates referral code for new users
// • ATOMIC coin credit: merges referral bonus into the same DB update
//   that sets referralCode — no race condition between two updates
// • Credits BOTH referrer + referee in real-time during sign-up
// • Enforces ONE ACCOUNT PER DEVICE when deviceId is provided
// ══════════════════════════════════════════════════════════════════
import { z } from 'zod';
import { createEndpoint, Users, Referrals, AdminSettings, ZiteError } from 'zite-integrations-backend-sdk';

function makeCode(email: string): string {
  const base = email.split('@')[0].replace(/[^a-zA-Z0-9]/g, '').slice(0, 4).toUpperCase();
  const rand = Math.random().toString(36).slice(2, 6).toUpperCase();
  return (base + rand).slice(0, 8);
}

export default createEndpoint({
  description: 'Initialize new user: generate referral code, track referral chain, instantly credit bonus coins to BOTH referrer and referee atomically.',
  authenticated: true,
  inputSchema: z.object({
    name:           z.string().min(2).optional(),
    phone:          z.string().optional(),
    referredByCode: z.string().optional(),
    deviceId:       z.string().min(4).max(200).optional(),
  }),
  outputSchema: z.object({ referralCode: z.string(), coinsAwarded: z.number() }),
  execute: async ({ input, context }) => {
    const existing = await Users.findOne({ id: context.user.id });

    // ── If user already has a referral code, just update name/phone ──
    if (existing?.referralCode) {
      const updateFields: Record<string, unknown> = {};
      if (input.name)     updateFields.name     = input.name;
      if (input.phone)    updateFields.phone    = input.phone;
      if (input.deviceId) updateFields.deviceId = input.deviceId;
      if (Object.keys(updateFields).length) {
        await Users.update({ id: context.user.id, record: updateFields as any });
      }
      return { referralCode: existing.referralCode, coinsAwarded: 0 };
    }

    // ── NEW USER: enforce one-device-one-account ──────────────────
    if (input.deviceId) {
      const deviceOwner = await Users.findOne({
        filters: { deviceId: input.deviceId },
        fields: ['id', 'email'],
      });
      if (deviceOwner && deviceOwner.id !== context.user.id) {
        throw new ZiteError({
          code: 'CONFLICT',
          message:
            'Ek device per sirf ek account ban sakta hai. ' +
            'This device already has a registered account. ' +
            'Please use your original account to log in.',
        });
      }
    }

    // ── Build the SINGLE update record for the new user ──────────
    const refCode = makeCode(context.user.email);
    const updates: Record<string, unknown> = { referralCode: refCode };
    if (input.name)     updates.name     = input.name;
    if (input.phone)    updates.phone    = input.phone;
    if (input.deviceId) updates.deviceId = input.deviceId;

    let coinsAwarded = 0;
    const referredByCode = input.referredByCode?.trim() || existing?.referredByCode;

    if (referredByCode) {
      updates.referredByCode = referredByCode;

      const [referrer, rewardSetting] = await Promise.all([
        Users.findOne({ filters: { referralCode: referredByCode } }),
        AdminSettings.findOne({ filters: { settingKey: 'referral_reward_coins' } }),
      ]);

      if (referrer && referrer.email !== context.user.email) {
        const existingReferral = await Referrals.findOne({
          filters: { referredEmail: context.user.email },
        });

        if (!existingReferral) {
          const totalRewardCoins = parseInt(rewardSetting?.settingValue ?? '100') || 100;
          const halfCoins = Math.floor(totalRewardCoins / 2);

          // ── ATOMIC: Include referee coins IN the same updates object ──
          updates.coins = (existing?.coins ?? 0) + halfCoins;
          coinsAwarded = halfCoins;

          // Credit referrer + create referral record concurrently
          // The referee update happens below in the single Users.update call
          await Promise.all([
            Referrals.create({
              record: {
                referrerEmail: referrer.email,
                referredEmail: context.user.email,
                referredName:  input.name ?? existing?.name ?? context.user.email,
                commissionRate: 0.05,
                commissionUsd:  0,
                referrerLevel:  referrer.level ?? 1,
              },
            }),
            Users.update({
              id: referrer.id,
              record: {
                totalReferrals: (referrer.totalReferrals ?? 0) + 1,
                coins: (referrer.coins ?? 0) + halfCoins,
              },
            }),
          ]);
        }
      }
    }

    // ── SINGLE atomic update for the new user (includes coins if referral) ──
    await Users.update({ id: context.user.id, record: updates as any });
    return { referralCode: refCode, coinsAwarded };
  },
});

src/api/submitWithdrawal.ts.content:
import { z } from 'zod';
import { createEndpoint, Withdrawals, Users, AdminSettings, ZiteError } from 'zite-integrations-backend-sdk';

export default createEndpoint({
  description: 'Submit withdrawal request and deduct from user balance (uses admin-defined minimum limit)',
  authenticated: true,
  inputSchema: z.object({
    amountUsd: z.number().min(0.01).max(100000),
    method: z.string(),
    accountNumber: z.string().min(3),
    accountName: z.string().min(2),
  }),
  outputSchema: z.object({ success: z.boolean() }),
  execute: async ({ input, context }) => {
    // Load admin-defined minimum withdrawal limit (default $1.00)
    const minSetting = await AdminSettings.findOne({ filters: { settingKey: 'min_withdraw_usd' } });
    const minWithdrawUsd = parseFloat(minSetting?.settingValue ?? '1') || 1;

    const user = await Users.findOne({ id: context.user.id });
    const balance = user?.usdBalance ?? 0;

    if (balance < minWithdrawUsd) {
      throw new ZiteError({
        code: 'BAD_REQUEST',
        message: `Minimum withdrawal is $${minWithdrawUsd.toFixed(2)}. Your balance is insufficient.`,
      });
    }
    if (input.amountUsd < minWithdrawUsd) {
      throw new ZiteError({
        code: 'BAD_REQUEST',
        message: `Minimum withdrawal amount is $${minWithdrawUsd.toFixed(2)}`,
      });
    }
    if (input.amountUsd > balance) {
      throw new ZiteError({ code: 'BAD_REQUEST', message: 'Insufficient balance' });
    }

    await Promise.all([
      Withdrawals.create({
        record: {
          userEmail: context.user.email,
          amountUsd: input.amountUsd,
          method: input.method as any,
          accountNumber: input.accountNumber,
          accountName: input.accountName,
          status: 'Pending',
        },
      }),
      Users.update({ id: context.user.id, record: { usdBalance: balance - input.amountUsd } }),
    ]);
    return { success: true };
  },
});

src/api/videoHuggingFace.ts.content:
import { z } from 'zod';
import { createEndpoint, Users, MediaGenerations, AdminSettings, ZiteError } from 'zite-integrations-backend-sdk';

// ══════════════════════════════════════════════════════════════════
// ISOLATED BOX: HUGGING FACE (FREE ROUTE)
// This endpoint has ZERO dependency on Stability AI or Google Veo.
// It uses only the HuggingFace token and nothing else.
// ══════════════════════════════════════════════════════════════════

// ── Content Safety Filter ────────────────────────────────────────
const BLOCKED = [
  'nude','nudity','naked','sexy','seductive','erotic','intimate','sensual',
  'undress','lingerie','bikini','provocative','obscene','porn','pornography',
  'nsfw','xxx','adult content','hentai','fetish','bondage','bdsm',
  'sexual','intercourse','orgasm','masturbat','stripper','prostitut',
  'anti-government','hate speech','propaganda','terrorism','terrorist',
  'extremist','riot','revolution against','overthrow','sedition',
  'kill','murder','assassination','genocide','ethnic cleansing',
  'racial slur','racist','bigot','supremacist',
];
function isSafe(prompt: string): boolean {
  const lower = prompt.toLowerCase();
  return !BLOCKED.some(w => lower.includes(w));
}

// ── Single Global API Key (STEP 1) ──────────────────────────────
const HF_TOKEN = process.env.ZITE_HUGGING_FACE_API_KEY;

// ── Hardcoded 4-Route Array (STEP 2) ────────────────────────────
const HF_ROUTES = [
  { url: 'https://api-inference.huggingface.co/models/ali-vilab/text-to-video-ms-1.7b',   label: 'Route A — DAMO-ViLab' },
  { url: 'https://api-inference.huggingface.co/models/ByteDance/AnimateDiff-Lightning',    label: 'Route B — AnimateDiff' },
  { url: 'https://api-inference.huggingface.co/models/camenduru/text2-video-zero',         label: 'Route C — Text2Video-Zero' },
  { url: 'https://api-inference.huggingface.co/models/PAIR/text2video-zero-controlnet',    label: 'Route D — ControlNet' },
];

// ── Watermark ────────────────────────────────────────────────────
const WATERMARK = 'Powered by Hussain AI';

export default createEndpoint({
  description: 'ISOLATED HuggingFace video engine — 4-route sequential failover. No cross-engine dependencies.',
  authenticated: true,
  inputSchema: z.object({
    prompt: z.string().min(5),
    durationSeconds: z.number().min(3).max(30).default(5),
  }),
  outputSchema: z.object({
    success: z.boolean(),
    videoUrl: z.string().optional(),
    videoBase64: z.string().optional(),
    mimeType: z.string().optional(),
    engine: z.string(),
    watermark: z.string().optional(),
    pipelineLog: z.array(z.string()),
  }),
  execute: async ({ input, context }) => {
    // ── Safety Guard ──
    if (!isSafe(input.prompt)) {
      throw new ZiteError({ code: 'BAD_REQUEST', message: 'یہ مواد پالیسی کے خلاف ہے! نامناسب مواد کی اجازت نہیں ہے۔' });
    }

    // ── VIP check ──
    const user = await Users.findOne({ id: context.user.id });
    const isVIP = user?.vipStatus === 'VIP' && (!user.vipExpiresAt || new Date(user.vipExpiresAt) > new Date());
    if (!isVIP) throw new ZiteError({ code: 'FORBIDDEN', message: '🔒 VIP membership required.' });

    // ── Daily quota ──
    const today = new Date().toISOString().slice(0, 10);
    const [usageRes, limitSetting] = await Promise.all([
      MediaGenerations.findAll({ filters: { userEmail: context.user.email, date: today, type: 'Video' }, limit: 10 }),
      AdminSettings.findOne({ filters: { settingKey: 'vid_limit_vip' } }),
    ]);
    const dailyLimit = parseInt(limitSetting?.settingValue ?? '3') || 3;
    const usedToday = usageRes.records.reduce((s, r) => s + (r.count ?? 0), 0);
    if (usedToday >= dailyLimit) throw new ZiteError({ code: 'RATE_LIMITED', message: '⏰ آج کی ویڈیو لمٹ پوری ہو گئی۔' });

    // ── Validate HF key exists ──
    if (!HF_TOKEN) {
      throw new ZiteError({ code: 'BAD_REQUEST', message: '⚙️ HuggingFace API key not configured. Set ZITE_HUGGING_FACE_API_KEY in environment.' });
    }

    // ── Build safe prompt ──
    const safePrompt = input.prompt.replace(/\b(nsfw|explicit|nude|naked)\b/gi, '').trim() + ', cinematic quality, SFW, family-friendly';

    // ══════════════════════════════════════════════════════════════
    // STEP 3 — STRICTLY SEQUENTIAL: Model 1 → 2 → 3 → 4
    // Each model gets 2 attempts with a 5-second delay between them.
    // NO parallel calls. Each model must fully finish before the
    // next one is even contacted.
    // ══════════════════════════════════════════════════════════════
    const RETRY_DELAY_MS = 5000; // 5 second wait before retry
    const MAX_ATTEMPTS_PER_MODEL = 2;
    const pipelineLog: string[] = [];

    // Helper: sleep for N ms (synchronous delay inside async)
    const sleep = (ms: number) => new Promise<void>(resolve => setTimeout(resolve, ms));

    // Helper: single attempt against one model URL.
    // Returns: 'success' result | 'busy' | 'auth_fail' | 'fail'
    type AttemptResult =
      | { status: 'success'; videoUrl?: string; videoBase64?: string; mimeType: string }
      | { status: 'busy'; code: number }
      | { status: 'loading' }
      | { status: 'auth_fail'; code: number }
      | { status: 'fail'; reason: string };

    const callModel = async (url: string): Promise<AttemptResult> => {
      const res = await fetch(url, {
        method: 'POST',
        headers: {
          'Authorization': `Bearer ${HF_TOKEN}`,
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({ inputs: safePrompt }),
        signal: AbortSignal.timeout(25000),
      });

      if (res.status === 401 || res.status === 403) return { status: 'auth_fail', code: res.status };
      if (res.status === 503 || res.status === 429 || res.status === 530) return { status: 'busy', code: res.status };
      if (!res.ok) return { status: 'fail', reason: `HTTP ${res.status}` };

      const contentType = res.headers.get('content-type') ?? '';

      // JSON / text response
      if (contentType.includes('json') || contentType.includes('text')) {
        const text = await res.text();
        if (text.toLowerCase().includes('loading') || text.toLowerCase().includes('overloaded') || text.toLowerCase().includes('estimated_time')) {
          return { status: 'loading' };
        }
        try {
          const data = JSON.parse(text);
          const videoUrl = data.url ?? data[0]?.url;
          if (videoUrl) return { status: 'success', videoUrl, mimeType: 'video/mp4' };
        } catch { /* not JSON */ }
        return { status: 'fail', reason: 'Unexpected JSON response' };
      }

      // Binary response
      if (contentType.includes('video') || contentType.includes('octet-stream') || contentType.includes('image')) {
        const buffer = await res.arrayBuffer();
        const bytes = new Uint8Array(buffer);
        let binary = '';
        for (let j = 0; j < bytes.length; j++) binary += String.fromCharCode(bytes[j]);
        const base64 = btoa(binary);
        const mime = contentType.includes('video') ? 'video/mp4' : contentType.includes('image') ? 'image/gif' : 'video/mp4';
        return { status: 'success', videoBase64: base64, mimeType: mime };
      }

      return { status: 'fail', reason: 'Unknown content type' };
    };

    // ── MAIN SEQUENTIAL LOOP: one model at a time ────────────────
    for (let i = 0; i < HF_ROUTES.length; i++) {
      const route = HF_ROUTES[i];
      let modelPassed = false;

      // Each model gets up to MAX_ATTEMPTS_PER_MODEL attempts
      for (let attempt = 1; attempt <= MAX_ATTEMPTS_PER_MODEL; attempt++) {
        const attemptLabel = attempt === 1 ? '1st attempt' : '2nd attempt (retry)';
        pipelineLog.push(`⏳ ${route.label} — ${attemptLabel}...`);
        console.log(`[Hussain AI: ${route.label} — ${attemptLabel}]`);

        try {
          const result = await callModel(route.url);

          if (result.status === 'success') {
            // ── SUCCESS — return immediately, do NOT touch any other model ──
            await MediaGenerations.create({ record: { userEmail: context.user.email, date: today, type: 'Video', count: 1 } });
            pipelineLog[pipelineLog.length - 1] = `✅ ${route.label} — SUCCESS (${attemptLabel})`;
            console.log(`[Hussain AI: ${route.label} SUCCESS — STOPPING chain]`);
            return {
              success: true,
              videoUrl: result.videoUrl,
              videoBase64: result.videoBase64,
              mimeType: result.mimeType,
              engine: route.label,
              watermark: WATERMARK,
              pipelineLog,
            };
          }

          if (result.status === 'auth_fail') {
            // Bad API key — abort the entire chain immediately
            pipelineLog[pipelineLog.length - 1] = `❌ ${route.label} — Auth failed (${result.code})`;
            console.log(`[Hussain AI: Auth failed — aborting entire chain]`);
            return { success: false, engine: 'none', pipelineLog };
          }

          if (result.status === 'busy' || result.status === 'loading') {
            const busyReason = result.status === 'busy' ? `Busy (${result.code})` : 'Model loading';
            pipelineLog[pipelineLog.length - 1] = `⏭ ${route.label} — ${busyReason} (${attemptLabel})`;

            if (attempt < MAX_ATTEMPTS_PER_MODEL) {
              // Wait 5 seconds before retrying the SAME model
              pipelineLog.push(`⏸ Waiting ${RETRY_DELAY_MS / 1000}s before retrying ${route.label}...`);
              console.log(`[Hussain AI: ${route.label} busy — waiting 5s before retry]`);
              await sleep(RETRY_DELAY_MS);
              // Loop continues to attempt 2 for the same model
            } else {
              // Both attempts exhausted for this model → move to next model
              console.log(`[Hussain AI: ${route.label} FAILED both attempts — moving to next model]`);
              modelPassed = true;
            }
            continue;
          }

          // status === 'fail'
          pipelineLog[pipelineLog.length - 1] = `⏭ ${route.label} — ${result.reason} (${attemptLabel})`;
          if (attempt < MAX_ATTEMPTS_PER_MODEL) {
            pipelineLog.push(`⏸ Waiting ${RETRY_DELAY_MS / 1000}s before retrying ${route.label}...`);
            await sleep(RETRY_DELAY_MS);
          } else {
            modelPassed = true;
          }

        } catch (err: any) {
          const reason = err?.name === 'TimeoutError' ? 'Timeout' : 'Network error';
          pipelineLog[pipelineLog.length - 1] = `⏭ ${route.label} — ${reason} (${attemptLabel})`;
          console.log(`[Hussain AI: ${route.label} ${reason}]`);
          if (attempt < MAX_ATTEMPTS_PER_MODEL) {
            pipelineLog.push(`⏸ Waiting ${RETRY_DELAY_MS / 1000}s before retrying ${route.label}...`);
            await sleep(RETRY_DELAY_MS);
          } else {
            modelPassed = true;
          }
        }
      } // end attempts loop

      // If we reach here, this model completely failed → the outer for-loop
      // moves to the NEXT model (strictly sequential, no parallel)
      if (modelPassed) {
        const nextLabel = i < HF_ROUTES.length - 1 ? HF_ROUTES[i + 1].label : 'NONE (all exhausted)';
        console.log(`[Hussain AI: ${route.label} fully failed → next: ${nextLabel}]`);
      }
    } // end models loop

    // All 4 models exhausted after sequential attempts
    pipelineLog.push('❌ All 4 models exhausted. No video generated.');
    return { success: false, engine: 'none', pipelineLog };
  },
});

