// ══════════════════════════════════════════════════════════════════
// SMART VIDEO ROUTER — VIP Plan 4 (90 Days) Exclusive Feature
// ── Reads prompt keywords → routes to the best engine automatically
// ── Priority 0: Universal AI Gateway (dynamic key + endpoint from DB)
// ── Priority 1: Google Veo (cinematic/photorealistic)
// ── Priority 2: Stability AI (fallback for cinematic)
// ── Priority 3: HuggingFace (avatar/explainer)
// ── Self-Healing: NEVER crashes — all failures are caught and routed
// ══════════════════════════════════════════════════════════════════
import { z } from 'zod';
import { createEndpoint, Users, MediaGenerations, AdminSettings, VideoApiKeys, ZiteError } from 'zite-integrations-backend-sdk';

// ── Keyword sets for routing ─────────────────────────────────────
const CINEMATIC_KEYWORDS = [
  'cinematic','photorealistic','movie','film','drone shot','aerial',
  'epic','slow motion','4k','8k','blockbuster','trailer','dramatic',
  'landscape','sunset','sunrise','timelapse','time lapse','nature',
  'realistic','hyper realistic','ultra realistic','hdr','filmic',
];

const AVATAR_KEYWORDS = [
  'avatar','talking','explainer','cartoon','animated','character',
  'anime','2d','3d character','mascot','spokesperson','narrator',
  'talking head','face','person speaking','instructor','teacher',
  'presentation','whiteboard','motion graphics',
];

// ── Eligible plan names (Plan 4 = VIP 90 Days) ──────────────────
const SMART_ROUTER_PLANS = ['VIP 90 Days', 'VIP UNLIMITED'];

// ── Content Safety Filter ────────────────────────────────────────
const BLOCKED = [
  'nude','nudity','naked','sexy','seductive','erotic','intimate','sensual',
  'undress','lingerie','bikini','provocative','obscene','porn','pornography',
  'nsfw','xxx','adult content','hentai','fetish','bondage','bdsm',
  'sexual','intercourse','orgasm','masturbat','stripper','prostitut',
  'anti-government','hate speech','propaganda','terrorism','terrorist',
  'extremist','riot','revolution against','overthrow','sedition',
  'kill','murder','assassination','genocide','ethnic cleansing',
  'racial slur','racist','bigot','supremacist',
];
function isSafe(prompt: string): boolean {
  const lower = prompt.toLowerCase();
  return !BLOCKED.some(w => lower.includes(w));
}

type RouteDecision = 'universal' | 'stability' | 'google-veo' | 'huggingface';

function detectRoute(prompt: string): { route: RouteDecision; reason: string } {
  const lower = prompt.toLowerCase();
  for (const kw of CINEMATIC_KEYWORDS) {
    if (lower.includes(kw)) return { route: 'google-veo', reason: `Keyword "${kw}" → Cinematic engine (Google Veo)` };
  }
  for (const kw of AVATAR_KEYWORDS) {
    if (lower.includes(kw)) return { route: 'huggingface', reason: `Keyword "${kw}" → Avatar/Explainer engine (HuggingFace)` };
  }
  return { route: 'google-veo', reason: 'No specific keywords → Default engine (Google Veo)' };
}

const WATERMARK = 'Powered by Hussain AI';

// ══════════════════════════════════════════════════════════════════
// UNIVERSAL AI GATEWAY — Priority 0 (Self-Healing, Never-Fail)
// ══════════════════════════════════════════════════════════════════
async function processUniversalGateway(
  prompt: string,
  pipelineLog: string[],
): Promise<{ hit: boolean; videoUrl?: string; videoBase64?: string; mimeType?: string; operationId?: string; engine: string }> {
  pipelineLog.push('🌐 Universal AI Gateway — Scanning for active universal config...');

  const { records } = await VideoApiKeys.findAll({ limit: 10 });
  const universalRow = records.find(r => r.universalApiKey && r.universalApiKey.length > 5);

  if (!universalRow) {
    pipelineLog.push('⏭ Universal Gateway — No universal key configured, skipping');
    return { hit: false, engine: 'none' };
  }

  const activeKey = universalRow.universalApiKey!;
  const targetUrl = universalRow.modelEndpointUrl || 'https://api.canva.com/v1/video/generate';
  const gatewayLabel = universalRow.gatewayName ?? 'Universal AI Gateway';

  if (!activeKey.trim()) {
    pipelineLog.push('🛡️ Shield Activated: Universal key is blank — routing to standby safe-mode');
    return { hit: false, engine: 'none' };
  }

  let customPayload: Record<string, unknown> = {};
  if (universalRow.payloadMappingJson) {
    try {
      customPayload = JSON.parse(universalRow.payloadMappingJson);
    } catch {
      pipelineLog.push('⚠️ Universal payload JSON parse error — using defaults');
    }
  }

  const payload = { prompt, ...customPayload };
  pipelineLog.push(`⏳ Trying Universal Gateway → ${targetUrl.slice(0, 60)}...`);

  try {
    const response = await fetch(targetUrl, {
      method: 'POST',
      headers: { 'Authorization': `Bearer ${activeKey}`, 'Content-Type': 'application/json' },
      body: JSON.stringify(payload),
      signal: AbortSignal.timeout(30000),
    });

    if (!response.ok) {
      pipelineLog.push(`⏭ Universal Gateway — HTTP ${response.status} (API Drop Intercepted)`);
      return { hit: false, engine: 'none' };
    }

    const ct = response.headers.get('content-type') ?? '';

    if (ct.includes('video') || ct.includes('octet-stream') || ct.includes('image')) {
      const buffer = await response.arrayBuffer();
      const bytes = new Uint8Array(buffer);
      let binary = '';
      for (let j = 0; j < bytes.length; j++) binary += String.fromCharCode(bytes[j]);
      const base64 = btoa(binary);
      const mime = ct.includes('video') ? 'video/mp4' : ct.includes('image') ? 'image/gif' : 'video/mp4';
      pipelineLog.push(`✅ Universal Gateway — Video/media received (${gatewayLabel})`);
      return { hit: true, videoBase64: base64, mimeType: mime, engine: gatewayLabel };
    }

    const data = await response.json() as any;
    const videoUrl = data.video_url ?? data.videoUrl ?? data.url ?? data.output?.url ?? data.result?.url;
    const opId = data.operation_id ?? data.operationId ?? data.id ?? data.name;
    const b64 = data.video ?? data.videoBase64 ?? data.output?.video;

    if (videoUrl) { pipelineLog.push(`✅ Universal Gateway — Video URL received (${gatewayLabel})`); return { hit: true, videoUrl, mimeType: 'video/mp4', engine: gatewayLabel }; }
    if (b64) { pipelineLog.push(`✅ Universal Gateway — Base64 video received (${gatewayLabel})`); return { hit: true, videoBase64: b64, mimeType: 'video/mp4', engine: gatewayLabel }; }
    if (opId) { pipelineLog.push(`✅ Universal Gateway — Async job submitted: ${opId} (${gatewayLabel})`); return { hit: true, operationId: String(opId), engine: gatewayLabel }; }

    pipelineLog.push(`⏭ Universal Gateway — Response had no recognized video fields`);
    return { hit: false, engine: 'none' };
  } catch (error) {
    pipelineLog.push(`🛡️ Self-Healing Circuit Triggered: Universal Gateway error caught — Lifetime Always-On Protection Active`);
    return { hit: false, engine: 'none' };
  }
}

export default createEndpoint({
  description: 'Smart Video Router — VIP Plan 4 (90 Days) exclusive. Auto-routes prompt to best engine based on keyword analysis.',
  authenticated: true,
  inputSchema: z.object({
    prompt: z.string().min(5),
    durationSeconds: z.number().min(3).max(60).default(8),
    aspectRatio: z.enum(['16:9', '9:16']).default('16:9'),
  }),
  outputSchema: z.object({
    success: z.boolean(),
    routeDecision: z.string(),
    routeReason: z.string(),
    operationId: z.string().optional(),
    videoUrl: z.string().optional(),
    videoBase64: z.string().optional(),
    mimeType: z.string().optional(),
    engine: z.string(),
    watermark: z.string().optional(),
    pipelineLog: z.array(z.string()),
  }),
  execute: async ({ input, context }) => {
    if (!isSafe(input.prompt)) {
      throw new ZiteError({ code: 'BAD_REQUEST', message: 'یہ مواد پالیسی کے خلاف ہے!' });
    }

    const user = await Users.findOne({ id: context.user.id });
    const isVIP = user?.vipStatus === 'VIP' && (!user.vipExpiresAt || new Date(user.vipExpiresAt) > new Date());
    if (!isVIP) throw new ZiteError({ code: 'FORBIDDEN', message: '🔒 VIP membership required.' });

    const userPlan = user?.vipPlan ?? '';
    if (!SMART_ROUTER_PLANS.some(p => userPlan.includes(p))) {
      throw new ZiteError({
        code: 'FORBIDDEN',
        message: '🔒 Smart Video Router is exclusive to VIP 90 Days and VIP UNLIMITED plans. Upgrade to access this feature.',
      });
    }

    const today = new Date().toISOString().slice(0, 10);
    const [usageRes, limitSetting] = await Promise.all([
      MediaGenerations.findAll({ filters: { userEmail: context.user.email, date: today, type: 'Video' }, limit: 10 }),
      AdminSettings.findOne({ filters: { settingKey: 'vid_limit_vip' } }),
    ]);
    const dailyLimit = parseInt(limitSetting?.settingValue ?? '3') || 3;
    const usedToday = usageRes.records.reduce((s, r) => s + (r.count ?? 0), 0);
    if (usedToday >= dailyLimit) throw new ZiteError({ code: 'RATE_LIMITED', message: '⏰ Daily video limit reached.' });

    const { route, reason } = detectRoute(input.prompt);
    const pipelineLog: string[] = [
      `🧠 Smart Router Analysis: ${reason}`,
      `📡 Routing to: ${route.toUpperCase()}`,
    ];
    const safePrompt = input.prompt.replace(/\b(nsfw|explicit|nude|naked)\b/gi, '').trim() + ', cinematic quality, SFW';

    // PRIORITY 0: UNIVERSAL AI GATEWAY
    const universalResult = await processUniversalGateway(safePrompt, pipelineLog);
    if (universalResult.hit) {
      await MediaGenerations.create({ record: { userEmail: context.user.email, date: today, type: 'Video', count: 1 } });
      return {
        success: true, routeDecision: 'universal', routeReason: 'Universal AI Gateway (Priority 0)',
        operationId: universalResult.operationId, videoUrl: universalResult.videoUrl,
        videoBase64: universalResult.videoBase64, mimeType: universalResult.mimeType,
        engine: universalResult.engine, watermark: WATERMARK, pipelineLog,
      };
    }

    // ROUTE: GOOGLE VEO
    if (route === 'google-veo' || route === 'stability') {
      const veoKeyRecord = await VideoApiKeys.findOne({ filters: { keyIdentifier: 'google_veo_key', status: 'Active' } });
      let veoKey = veoKeyRecord?.gatewayKey;
      if (!veoKey) {
        const geminiSetting = await AdminSettings.findOne({ filters: { settingKey: 'gemini_api_key' } });
        veoKey = geminiSetting?.settingValue;
      }

      if (veoKey) {
        const VEO_MODELS = ['veo-3.0-generate-preview', 'veo-3.0-fast-generate-preview', 'veo-2.0-generate-001'];
        for (const model of VEO_MODELS) {
          pipelineLog.push(`⏳ Trying ${model}...`);
          try {
            const res = await fetch(`https://generativelanguage.googleapis.com/v1beta/models/${model}:generateVideos?key=${veoKey}`, {
              method: 'POST',
              headers: { 'Content-Type': 'application/json' },
              body: JSON.stringify({ prompt: safePrompt, aspectRatio: input.aspectRatio, durationSeconds: input.durationSeconds, sampleCount: 1 }),
              signal: AbortSignal.timeout(25000),
            });
            if (res.status === 429 || res.status === 404 || res.status === 400) { pipelineLog[pipelineLog.length - 1] = `⏭ ${model} — Skip (${res.status})`; continue; }
            if (!res.ok) { pipelineLog[pipelineLog.length - 1] = `⏭ ${model} — HTTP ${res.status}`; continue; }
            const data = await res.json() as any;
            if (data.name) {
              await MediaGenerations.create({ record: { userEmail: context.user.email, date: today, type: 'Video', count: 1 } });
              pipelineLog[pipelineLog.length - 1] = `✅ ${model} — Job submitted`;
              return { success: true, routeDecision: route, routeReason: reason, operationId: data.name, engine: model, watermark: WATERMARK, pipelineLog };
            }
            const samples: any[] = data.videos ?? data.generatedSamples ?? [];
            if (samples.length > 0) {
              const vid = samples[0]?.video ?? samples[0];
              if (vid?.uri || vid?.encodedContent) {
                await MediaGenerations.create({ record: { userEmail: context.user.email, date: today, type: 'Video', count: 1 } });
                pipelineLog[pipelineLog.length - 1] = `✅ ${model} — Video ready`;
                return { success: true, routeDecision: route, routeReason: reason, videoUrl: vid.uri, videoBase64: vid.encodedContent, mimeType: vid.mimeType ?? 'video/mp4', engine: model, watermark: WATERMARK, pipelineLog };
              }
            }
            pipelineLog[pipelineLog.length - 1] = `⏭ ${model} — No video`;
          } catch { pipelineLog[pipelineLog.length - 1] = `⏭ ${model} — Error`; }
        }
      } else {
        pipelineLog.push('⚠️ Google Veo key not found — falling back to Stability AI');
      }

      // Stability AI fallback
      const STABILITY_KEY = process.env.ZITE_STABILITY_API_KEY;
      if (STABILITY_KEY) {
        pipelineLog.push('⏳ Trying Stability AI (fallback)...');
        try {
          const res = await fetch('https://api.stability.ai/v2beta/image-to-video', {
            method: 'POST',
            headers: { 'Authorization': 'Bearer ' + STABILITY_KEY, 'Content-Type': 'application/json' },
            body: JSON.stringify({ text_prompts: [{ text: safePrompt, weight: 1 }], cfg_scale: 2.5, motion_bucket_id: 127 }),
            signal: AbortSignal.timeout(25000),
          });
          if (res.ok) {
            const data = await res.json() as any;
            if (data.id) {
              await MediaGenerations.create({ record: { userEmail: context.user.email, date: today, type: 'Video', count: 1 } });
              pipelineLog[pipelineLog.length - 1] = '✅ Stability AI — Job submitted';
              return { success: true, routeDecision: route, routeReason: reason, operationId: `stability:${data.id}`, engine: 'Stability AI v2', watermark: WATERMARK, pipelineLog };
            }
            if (data.video) {
              await MediaGenerations.create({ record: { userEmail: context.user.email, date: today, type: 'Video', count: 1 } });
              pipelineLog[pipelineLog.length - 1] = '✅ Stability AI — Video ready';
              return { success: true, routeDecision: route, routeReason: reason, videoBase64: data.video, mimeType: 'video/mp4', engine: 'Stability AI v2', watermark: WATERMARK, pipelineLog };
            }
          }
          pipelineLog[pipelineLog.length - 1] = `❌ Stability AI — Failed (${res.status})`;
        } catch { pipelineLog[pipelineLog.length - 1] = '❌ Stability AI — Error'; }
      }
    }

    // ROUTE: HUGGINGFACE
    if (route === 'huggingface') {
      const HF_TOKEN = process.env.ZITE_HUGGING_FACE_API_KEY;
      if (!HF_TOKEN) { pipelineLog.push('❌ HuggingFace key not configured'); return { success: false, routeDecision: route, routeReason: reason, engine: 'none', pipelineLog }; }

      const HF_MODELS = [
        { url: 'https://api-inference.huggingface.co/models/ali-vilab/text-to-video-ms-1.7b', label: 'DAMO-ViLab' },
        { url: 'https://api-inference.huggingface.co/models/ByteDance/AnimateDiff-Lightning', label: 'AnimateDiff' },
        { url: 'https://api-inference.huggingface.co/models/camenduru/text2-video-zero', label: 'Text2Video-Zero' },
      ];
      for (const model of HF_MODELS) {
        pipelineLog.push(`⏳ Trying ${model.label}...`);
        try {
          const res = await fetch(model.url, {
            method: 'POST',
            headers: { 'Authorization': `Bearer ${HF_TOKEN}`, 'Content-Type': 'application/json' },
            body: JSON.stringify({ inputs: safePrompt }),
            signal: AbortSignal.timeout(25000),
          });
          if (res.status === 401 || res.status === 403) { pipelineLog[pipelineLog.length - 1] = `❌ ${model.label} — Auth failed`; return { success: false, routeDecision: route, routeReason: reason, engine: 'none', pipelineLog }; }
          if (!res.ok) { pipelineLog[pipelineLog.length - 1] = `⏭ ${model.label} — HTTP ${res.status}`; continue; }

          const ct = res.headers.get('content-type') ?? '';
          if (ct.includes('video') || ct.includes('octet-stream') || ct.includes('image')) {
            const buffer = await res.arrayBuffer();
            const bytes = new Uint8Array(buffer);
            let binary = ''; for (let j = 0; j < bytes.length; j++) binary += String.fromCharCode(bytes[j]);
            const base64 = btoa(binary);
            const mime = ct.includes('video') ? 'video/mp4' : 'image/gif';
            await MediaGenerations.create({ record: { userEmail: context.user.email, date: today, type: 'Video', count: 1 } });
            pipelineLog[pipelineLog.length - 1] = `✅ ${model.label} — Video ready`;
            return { success: true, routeDecision: route, routeReason: reason, videoBase64: base64, mimeType: mime, engine: model.label, watermark: WATERMARK, pipelineLog };
          }

          const text = await res.text();
          if (text.includes('loading') || text.includes('overloaded')) { pipelineLog[pipelineLog.length - 1] = `⏭ ${model.label} — Model loading`; continue; }
          try {
            const data = JSON.parse(text);
            const url = data.url ?? data[0]?.url;
            if (url) {
              await MediaGenerations.create({ record: { userEmail: context.user.email, date: today, type: 'Video', count: 1 } });
              pipelineLog[pipelineLog.length - 1] = `✅ ${model.label} — Video ready`;
              return { success: true, routeDecision: route, routeReason: reason, videoUrl: url, mimeType: 'video/mp4', engine: model.label, watermark: WATERMARK, pipelineLog };
            }
          } catch { /* not json */ }
          pipelineLog[pipelineLog.length - 1] = `⏭ ${model.label} — No video`;
        } catch { pipelineLog[pipelineLog.length - 1] = `⏭ ${model.label} — Error`; continue; }
      }
    }

    pipelineLog.push('❌ All engines exhausted. No video generated.');
    return { success: false, routeDecision: route, routeReason: reason, engine: 'none', pipelineLog };
  },
});

