  const [welcomeMuted, setWelcomeMuted] = useState(false);
  const mountedRef = useRef(true);

  // ── Auto-play welcome TTS on first mount ──
  useEffect(() => {
    mountedRef.current = true;
    const alreadyPlayed = sessionStorage.getItem('spiritual_welcome_played');

    if (!alreadyPlayed && !welcomePlayed) {
      const timer = setTimeout(() => {
        if (!mountedRef.current) return;
        speakText(WELCOME_TEXT, 'ur-PK', () => {
          if (mountedRef.current) setWelcomePlayed(true);
        });
        sessionStorage.setItem('spiritual_welcome_played', '1');
