                روحانی و دینی مرکز
              </p>
              <p className="text-[8px] text-emerald-600/80 truncate leading-none mt-0.5">
                ROOHANI GUIDE AI · Built by Ghulam Hussain Channar
              </p>
            </div>

            <div className="flex items-center gap-2 shrink-0">
              {/* Mute/unmute welcome */}
              <button
                onClick={toggleWelcomeMute}
                className="text-emerald-600 hover:text-emerald-400 p-1 transition-colors"
                title={welcomeMuted ? 'آواز چالو کریں' : 'آواز بند کریں'}
              >
                {welcomeMuted ? <VolumeX size={14} /> : <Volume2 size={14} />}
              </button>
              <div className="flex items-center gap-1">
                <span className="w-1.5 h-1.5 rounded-full bg-emerald-400 animate-pulse" />
                <span className="text-[9px] text-emerald-500 font-mono">LIVE</span>
              </div>
            </div>
          </div>
        </div>

        {/* ── Tab Buttons: Chat + Analysis ── */}
        <div className="relative grid grid-cols-2 gap-2 px-4 pb-3">
          <TabButton
            active={activeTab === 'chat'}
            onClick={() => setActiveTab('chat')}
            icon={<MessageCircle size={18} />}
            urduLabel="روحانی گفتگو"
            enLabel="Islamic AI Chat"
          />
          <TabButton
            active={activeTab === 'analysis'}
