src/api/createVideoScript.ts.content:
import { z } from 'zod';
import { createEndpoint, AdminSettings, Users, MediaGenerations, ZiteError } from 'zite-integrations-backend-sdk';

// ══════════════════════════════════════════════════════════════════
// ADAPTIVE GATEWAY — Video section with future-proof auto-shift
// ══════════════════════════════════════════════════════════════════
const KNOWN_FALLBACK_CHAIN = [
  'gemini-2.5-flash',
  'gemini-2.0-flash',
  'gemini-2.5-pro',
  'gemini-1.5-flash',
  'gemini-1.5-pro',
];

const DEPRECATION_SIGNALS = ['not found', 'deprecated', 'decommissioned', 'does not exist', 'not supported'];
function isGone(status: number, body: string): boolean {
  if (status === 404) return true;
  if (status === 400) return DEPRECATION_SIGNALS.some(s => body.toLowerCase().includes(s));
  return false;
}

async function discoverNewModels(apiKey: string): Promise<string[]> {
  try {
    const res = await fetch(`https://generativelanguage.googleapis.com/v1beta/models?pageSize=200&key=${apiKey}`);
    if (!res.ok) return [];
    const data = await res.json() as { models?: { name: string; supportedGenerationMethods?: string[] }[] };
    return (data.models ?? [])
      .filter(m => (m.supportedGenerationMethods ?? []).includes('generateContent'))
      .map(m => m.name.replace('models/', ''))
      .filter(id => id.startsWith('gemini'))
      .sort((a, b) => b.localeCompare(a));
  } catch { return []; }
}

function buildChain(preferred: string, discovered: string[]): string[] {
  const seen = new Set<string>();
  const chain: string[] = [];
  const add = (m: string) => { if (!seen.has(m)) { seen.add(m); chain.push(m); } };
  add(preferred);
  for (const m of KNOWN_FALLBACK_CHAIN) add(m);
  for (const m of discovered) add(m);
  return chain;
}

const VIDEO_SYSTEM = `You are an elite social media video content strategist and scriptwriter. You create viral, algorithm-optimized video content with perfect hooks, retention arcs, and CTAs. Built by Ghulam Hussain Channar.
Always return pure JSON — no markdown, no code blocks, no explanation outside the JSON.`;

export default createEndpoint({
  description: 'Generate complete video scripts — adaptive Gemini gateway with auto-shift',
  authenticated: true,
  inputSchema: z.object({
    concept: z.string().min(5),
    style: z.enum(['educational', 'entertainment', 'promotional', 'shorts', 'vlog', 'tutorial']),
    platform: z.enum(['YouTube', 'TikTok', 'Instagram Reels', 'Facebook']),
  }),
  outputSchema: z.object({
    script: z.string(),
    scenes: z.array(z.object({ title: z.string(), duration: z.string(), description: z.string(), visuals: z.string() })),
    hashtags: z.array(z.string()),
    title: z.string(),
    description: z.string(),
  }),
  execute: async ({ input, context }) => {
    const user = await Users.findOne({ id: context.user.id });
    const isVIPActive =
      user?.vipStatus === 'VIP' &&
      (!user.vipExpiresAt || new Date(user.vipExpiresAt) > new Date());

    if (!isVIPActive) {
      throw new ZiteError({ code: 'FORBIDDEN', message: '🔒 Video Creator is exclusively for VIP members. Upgrade your plan to unlock this feature!' });
    }

    const today = new Date().toISOString().slice(0, 10);
    const [usageRes, videoLimitSetting] = await Promise.all([
      MediaGenerations.findAll({ filters: { userEmail: context.user.email, date: today, type: 'Video' }, limit: 10 }),
      AdminSettings.findOne({ filters: { settingKey: 'vid_limit_vip' } }),
    ]);
    const dailyVideoLimit = parseInt(videoLimitSetting?.settingValue ?? '1') || 1;
    const usedToday = usageRes.records.reduce((s, r) => s + (r.count ?? 0), 0);

    if (usedToday >= dailyVideoLimit) {
      throw new ZiteError({ code: 'RATE_LIMITED', message: `⏰ Daily limit reached! You can generate ${dailyVideoLimit} video${dailyVideoLimit > 1 ? 's' : ''} per day. Come back tomorrow!` });
    }

    const settings = await AdminSettings.findAll({ limit: 200 });
    const geminiKey = settings.records.find(s => s.settingKey === 'gemini_api_key')?.settingValue;
    const sectionModel = settings.records.find(s => s.settingKey === 'gemini_video_model')?.settingValue
      ?? settings.records.find(s => s.settingKey === 'gemini_best_model')?.settingValue
      ?? 'gemini-2.5-flash';

    const fallback = {
      title: `${input.concept} — ${input.style} video`,
      script: `[HOOK]\nStart with a powerful attention-grabbing hook about: ${input.concept}\n\n[INTRO]\nIntroduce the topic.\n\n[MAIN CONTENT]\nExpand on key points...\n\n[CTA]\nLike, Share & Subscribe!\n\n---\nAdd your Gemini API key in Admin Panel for AI-generated scripts.`,
      scenes: [
        { title: 'Opening Hook', duration: '0-5s', description: 'Attention-grabbing opening', visuals: 'Close-up or text animation' },
        { title: 'Intro', duration: '5-15s', description: 'Topic introduction', visuals: 'Face cam or b-roll' },
        { title: 'Main Content', duration: '15-90s', description: 'Core content delivery', visuals: 'Screen recording / graphics' },
        { title: 'CTA + Outro', duration: '90-120s', description: 'Call to action and closing', visuals: 'Subscribe animation' },
      ],
      hashtags: ['#YouTube', '#Viral', '#Trending', '#Content', '#Creator', '#Video', '#Shorts', '#Reels', '#Social', '#Digital'],
      description: `${input.concept} | ${input.style} content for ${input.platform}`,
    };

    // Record usage before generating
    const existingRecord = usageRes.records.find(r => r.date === today);
    if (existingRecord) {
      await MediaGenerations.update({ id: existingRecord.id, record: { count: (existingRecord.count ?? 0) + 1 } });
    } else {
      await MediaGenerations.create({ record: { userEmail: context.user.email, date: today, type: 'Video', count: 1 } });
    }

    if (!geminiKey) return fallback;

    const prompt = `Create a complete ${input.style} video for ${input.platform} about: "${input.concept}"

Return ONLY valid JSON (no markdown, no code blocks):
{
  "title": "Viral video title (max 60 chars)",
  "description": "SEO-optimized description (150 chars)",
  "script": "Full script with clear sections: [HOOK]\\n\\n[INTRO]\\n\\n[MAIN CONTENT]\\n\\n[CTA]\\n\\n[OUTRO]",
  "scenes": [
    {"title": "Scene name", "duration": "0-5s", "description": "What happens", "visuals": "Camera/visual description"}
  ],
  "hashtags": ["#hashtag1", ... exactly 18 viral hashtags]
}`;

    const body = {
      systemInstruction: { parts: [{ text: VIDEO_SYSTEM }] },
      contents: [{ role: 'user', parts: [{ text: prompt }] }],
      generationConfig: { maxOutputTokens: 3000, temperature: 0.8 },
    };

    // ── Adaptive auto-shift ────────────────────────────────────────
    const discovered = await discoverNewModels(geminiKey);
    const chain = buildChain(sectionModel, discovered);

    for (const model of chain) {
      try {
        const res = await fetch(
          `https://generativelanguage.googleapis.com/v1beta/models/${model}:generateContent?key=${geminiKey}`,
          { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify(body) }
        );
        if (res.status === 429 || res.status === 503) continue;
        if (!res.ok) {
          const errText = await res.text().catch(() => '');
          if (isGone(res.status, errText)) { console.log(`[Video] Model "${model}" gone, auto-shifting...`); continue; }
          continue;
        }
        const data = await res.json() as { candidates?: { content?: { parts?: { text?: string }[] } }[] };
        const raw = data.candidates?.[0]?.content?.parts?.[0]?.text ?? '';

        try {
          const parsed = JSON.parse(raw.replace(/```json|```/g, '').trim());
          return {
            title: parsed.title ?? fallback.title,
            script: parsed.script ?? fallback.script,
            scenes: Array.isArray(parsed.scenes) ? parsed.scenes : fallback.scenes,
            hashtags: Array.isArray(parsed.hashtags) ? parsed.hashtags : fallback.hashtags,
            description: parsed.description ?? fallback.description,
          };
        } catch {
          return { ...fallback, script: raw || fallback.script };
        }
      } catch { continue; }
    }

    return fallback;
  },
});

src/api/reportWrongPrompt.ts.content:
import { z } from 'zod';
import { createEndpoint, Users } from 'zite-integrations-backend-sdk';

export default createEndpoint({
  description: 'Increment wrongPromptCount for the user. On 4th wrong prompt, auto-block.',
  authenticated: true,
  inputSchema: z.object({}),
  outputSchema: z.object({
    wrongPromptCount: z.number(),
    blocked: z.boolean(),
    warning: z.boolean(),
  }),
  execute: async ({ context }) => {
    const u = await Users.findOne({ id: context.user.id, fields: ['wrongPromptCount', 'status'] });
    if (!u) return { wrongPromptCount: 0, blocked: false, warning: false };

    // Already blocked
    if (u.status === 'Blocked') return { wrongPromptCount: u.wrongPromptCount ?? 0, blocked: true, warning: false };

    const newCount = (u.wrongPromptCount ?? 0) + 1;

    if (newCount >= 4) {
      // Auto-block on 4th wrong prompt
      await Users.update({ id: context.user.id, record: { wrongPromptCount: newCount, status: 'Blocked' } });
      return { wrongPromptCount: newCount, blocked: true, warning: false };
    }

    await Users.update({ id: context.user.id, record: { wrongPromptCount: newCount } });
    return {
      wrongPromptCount: newCount,
      blocked: false,
      warning: newCount === 3,
    };
  },
});

src/api/socialLinksConfig.ts.content:
import { z } from 'zod';
import { createEndpoint, SocialLinksConfig, AdminSettings } from 'zite-integrations-backend-sdk';

export default createEndpoint({
  description: 'Isolated CRUD for Social Links Config table — zero touching of any other table',
  inputSchema: z.object({
    action: z.enum(['get', 'save']),
    adminToken: z.string().optional(),
    links: z.array(z.object({
      id: z.string().optional(),
      platformName: z.string(),
      urlLink: z.string(),
      isActive: z.boolean(),
    })).optional(),
  }),
  outputSchema: z.object({
    success: z.boolean(),
    links: z.array(z.object({
      id: z.string(),
      platformName: z.string(),
      urlLink: z.string(),
      isActive: z.boolean(),
    })),
  }),
  execute: async ({ input }) => {
    // GET — public read (floating bar needs this without admin auth)
    if (input.action === 'get') {
      const { records } = await SocialLinksConfig.findAll({});
      // Auto-seed defaults if table is empty
      if (records.length === 0) {
        const defaults = [
          { platformName: 'YouTube', urlLink: '', isActive: false },
          { platformName: 'Facebook', urlLink: '', isActive: false },
          { platformName: 'TikTok', urlLink: '', isActive: false },
        ];
        const { records: created } = await SocialLinksConfig.bulkCreate({ records: defaults });
        return {
          success: true,
          links: created.map(r => ({
            id: r.id,
            platformName: r.fields.platformName ?? '',
            urlLink: r.fields.urlLink ?? '',
            isActive: r.fields.isActive ?? false,
          })),
        };
      }
      return {
        success: true,
        links: records.map(r => ({
          id: r.id,
          platformName: r.platformName ?? '',
          urlLink: r.urlLink ?? '',
          isActive: r.isActive ?? false,
        })),
      };
    }

    // SAVE — admin-only write
    if (input.action === 'save') {
      // Verify admin token
      const pwdRec = await AdminSettings.findOne({ filters: { settingKey: 'admin_password' } });
      const expected = pwdRec?.settingValue ?? 'admin@2024';
      if (input.adminToken !== expected) {
        return { success: false, links: [] };
      }

      const incoming = input.links ?? [];
      for (const link of incoming) {
        if (link.id) {
          await SocialLinksConfig.update({
            id: link.id,
            record: {
              platformName: link.platformName,
              urlLink: link.urlLink,
              isActive: link.isActive,
            },
          });
        } else {
          await SocialLinksConfig.create({
            record: {
              platformName: link.platformName,
              urlLink: link.urlLink,
              isActive: link.isActive,
            },
          });
        }
      }

      const { records } = await SocialLinksConfig.findAll({});
      return {
        success: true,
        links: records.map(r => ({
          id: r.id,
          platformName: r.platformName ?? '',
          urlLink: r.urlLink ?? '',
          isActive: r.isActive ?? false,
        })),
      };
    }

    return { success: false, links: [] };
  },
});

src/api/submitVIPPurchase.ts.content:
import { z } from 'zod';
import { createEndpoint, VipPurchases, VipPlans, Users, ZiteError } from 'zite-integrations-backend-sdk';

export default createEndpoint({
  description: 'Submit VIP purchase request with payment proof screenshot',
  authenticated: true,
  inputSchema: z.object({
    planId: z.string(),
    paymentMethod: z.string(),
    tidOrHash: z.string().min(3),
    sendingAddress: z.string().min(3),
    screenshotUrl: z.string().url(),
  }),
  outputSchema: z.object({ success: z.boolean(), purchaseId: z.string() }),
  execute: async ({ input, context }) => {
    const plan = await VipPlans.findOne({ id: input.planId });
    if (!plan) throw new ZiteError({ code: 'NOT_FOUND', message: 'Plan not found' });

    const pending = await VipPurchases.findOne({ filters: { userEmail: context.user.email, status: 'Pending' } });
    if (pending) throw new ZiteError({ code: 'CONFLICT', message: 'You already have a pending request. Please wait for admin approval.' });

    const purchase = await VipPurchases.create({
      record: {
        userEmail: context.user.email,
        planName: plan.planName,
        amountUsd: plan.priceUsd,
        paymentMethod: input.paymentMethod as any,
        tidOrHash: input.tidOrHash,
        sendingAddress: input.sendingAddress,
        paymentScreenshot: [{ url: input.screenshotUrl }],
        status: 'Pending',
      },
    });
    await Users.update({ id: context.user.id, record: { vipStatus: 'Pending', vipPlan: plan.planName } });
    return { success: true, purchaseId: purchase.id };
  },
});

src/api/validateGeminiKey.ts.content:
import { z } from 'zod';
import { createEndpoint, AdminSettings, ZiteError } from 'zite-integrations-backend-sdk';

// ══════════════════════════════════════════════════════════════════
// GEMINI KEY VALIDATOR v7.0 — ADAPTIVE FUTURE-PROOF GATEWAY
// Never throws 500 on model string changes. Discovers new models
// dynamically and assigns per-section routing from whatever is live.
// ══════════════════════════════════════════════════════════════════

const TIER_MAP = [
  { model: 'gemini-2.5-pro',       tier: 'Ultra',      tierLevel: 5, label: 'Gemini 2.5 Pro'     },
  { model: 'gemini-2.5-flash',     tier: 'Premium',    tierLevel: 4, label: 'Gemini 2.5 Flash'   },
  { model: 'gemini-2.0-flash',     tier: 'Standard',   tierLevel: 2, label: 'Gemini 2.0 Flash'   },
  { model: 'gemini-1.5-pro',       tier: 'Standard+',  tierLevel: 3, label: 'Gemini 1.5 Pro'     },
  { model: 'gemini-1.5-pro-002',   tier: 'Standard+',  tierLevel: 3, label: 'Gemini 1.5 Pro'     },
  { model: 'gemini-1.5-flash',     tier: 'Standard',   tierLevel: 2, label: 'Gemini 1.5 Flash'   },
  { model: 'gemini-1.5-flash-002', tier: 'Standard',   tierLevel: 2, label: 'Gemini 1.5 Flash'   },
  { model: 'gemini-1.0-pro',       tier: 'Basic',      tierLevel: 1, label: 'Gemini 1.0 Pro'     },
];

// Models to live-test in priority order
const LIVE_TEST_ORDER = [
  'gemini-2.5-flash',
  'gemini-2.5-pro',
  'gemini-2.0-flash',
  'gemini-1.5-flash',
  'gemini-1.5-pro',
  'gemini-1.5-flash-002',
  'gemini-1.5-pro-002',
  'gemini-1.0-pro',
];

function pickSectionModels(available: string[], confirmed: string) {
  const has = (m: string) => available.includes(m);

  // SPIRITUAL: locked to 2.5-flash, fallback to pro then older
  const spiritualModel =
    has('gemini-2.5-flash') ? 'gemini-2.5-flash'  :
    has('gemini-2.5-pro')   ? 'gemini-2.5-pro'    :
    has('gemini-2.0-flash') ? 'gemini-2.0-flash'  :
    has('gemini-1.5-pro')   ? 'gemini-1.5-pro'    :
    has('gemini-1.5-flash') ? 'gemini-1.5-flash'  :
    confirmed;

  // GENERAL/MAIN CHAT: locked to 2.5-flash for speed
  const generalModel =
    has('gemini-2.5-flash') ? 'gemini-2.5-flash'  :
    has('gemini-2.0-flash') ? 'gemini-2.0-flash'  :
    has('gemini-1.5-flash') ? 'gemini-1.5-flash'  :
    has('gemini-2.5-pro')   ? 'gemini-2.5-pro'    :
    has('gemini-1.5-pro')   ? 'gemini-1.5-pro'    :
    confirmed;

  // CODING: locked to 1.5-pro (3.5 series), fallback to 2.5-pro
  const codingModel =
    has('gemini-1.5-pro')   ? 'gemini-1.5-pro'    :
    has('gemini-1.5-pro-002') ? 'gemini-1.5-pro-002' :
    has('gemini-2.5-pro')   ? 'gemini-2.5-pro'    :
    has('gemini-2.5-flash') ? 'gemini-2.5-flash'  :
    confirmed;

  // VIDEO SCRIPTS: creativity + structured output
  const videoModel =
    has('gemini-2.5-flash') ? 'gemini-2.5-flash'  :
    has('gemini-2.5-pro')   ? 'gemini-2.5-pro'    :
    has('gemini-2.0-flash') ? 'gemini-2.0-flash'  :
    has('gemini-1.5-pro')   ? 'gemini-1.5-pro'    :
    has('gemini-1.5-flash') ? 'gemini-1.5-flash'  :
    confirmed;

  // FAST (hashtags/image prompts): pure speed
  const fastModel =
    has('gemini-2.0-flash') ? 'gemini-2.0-flash'  :
    has('gemini-1.5-flash') ? 'gemini-1.5-flash'  :
    has('gemini-2.5-flash') ? 'gemini-2.5-flash'  :
    confirmed;

  return { spiritualModel, generalModel, codingModel, videoModel, fastModel };
}

async function upsertSetting(
  records: { id: string; settingKey?: string; settingValue?: string }[],
  key: string, value: string,
) {
  const existing = records.find(s => s.settingKey === key);
  if (existing) {
    await AdminSettings.update({ id: existing.id, record: { settingValue: value } });
  } else {
    await AdminSettings.create({ record: { settingKey: key, settingValue: value } });
  }
}

async function liveTest(key: string, model: string): Promise<boolean> {
  try {
    const res = await fetch(
      `https://generativelanguage.googleapis.com/v1beta/models/${model}:generateContent?key=${key}`,
      {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          contents: [{ role: 'user', parts: [{ text: 'ACTIVE' }] }],
          generationConfig: { maxOutputTokens: 3, temperature: 0 },
        }),
      }
    );
    return res.ok;
  } catch { return false; }
}

export default createEndpoint({
  description: 'Validate Gemini API key — adaptive future-proof discovery, never throws 500 on model deprecation',
  inputSchema: z.object({ apiKey: z.string().min(1), adminToken: z.string() }),
  outputSchema: z.object({
    valid: z.boolean(),
    tier: z.string().optional(),
    tierLevel: z.number().optional(),
    bestModel: z.string().optional(),
    bestModelLabel: z.string().optional(),
    availableModels: z.array(z.string()).optional(),
    sectionModels: z.object({
      spiritual: z.string(), general: z.string(), coding: z.string(), video: z.string(), fast: z.string(),
    }).optional(),
    error: z.string().optional(),
  }),
  execute: async ({ input }) => {
    // ── Auth check ─────────────────────────────────────────────────
    const allSettings = await AdminSettings.findAll({ limit: 200 });
    const records = allSettings.records;
    const storedPwd = records.find(s => s.settingKey === 'admin_password')?.settingValue ?? 'admin@2024';
    if (input.adminToken !== storedPwd) throw new ZiteError({ code: 'UNAUTHORIZED', message: 'Invalid admin token' });

    const key = input.apiKey.trim();

    // ── Step 1: Discover ALL models on this key (future-proof) ─────
    let discoveredModelIds: string[] = [];
    try {
      const listRes = await fetch(
        `https://generativelanguage.googleapis.com/v1beta/models?pageSize=200&key=${key}`
      );
      if (listRes.status === 400 || listRes.status === 401 || listRes.status === 403) {
        const body = await listRes.json().catch(() => ({})) as any;
        return { valid: false, error: `API key rejected: ${body?.error?.message ?? listRes.status}` };
      }
      if (listRes.ok) {
        const listData = await listRes.json() as { models?: { name: string; supportedGenerationMethods?: string[] }[] };
        discoveredModelIds = (listData.models ?? [])
          .filter(m => (m.supportedGenerationMethods ?? []).includes('generateContent'))
          .map(m => m.name.replace('models/', ''))
          .filter(id => id.startsWith('gemini'));
      }
    } catch {
      // Network error — continue to live testing
    }

    // ── Step 2: Build combined test list (known + discovered) ──────
    const allCandidates = [...new Set([...LIVE_TEST_ORDER, ...discoveredModelIds])];

    // ── Step 3: Live-test models ───────────────────────────────────
    let confirmedModel = '';
    for (const modelId of allCandidates) {
      const ok = await liveTest(key, modelId);
      if (ok) { confirmedModel = modelId; break; }
    }

    if (!confirmedModel) {
      return {
        valid: false,
        error: 'API key is valid but no Gemini model responds. Enable the Gemini API in Google Cloud Console.',
      };
    }

    // ── Step 4: Resolve tier metadata ─────────────────────────────
    const tierEntry = TIER_MAP.find(e => e.model === confirmedModel) ?? {
      model: confirmedModel, tier: 'Next-Gen', tierLevel: 6, label: confirmedModel,
    };

    // Build available list from live-testable + discovered
    const knownAvailable = [...new Set([...discoveredModelIds, confirmedModel])]
      .filter(id => id.startsWith('gemini'));

    // ── Step 5: Pick per-section models ────────────────────────────
    const { spiritualModel, generalModel, codingModel, videoModel, fastModel } = pickSectionModels(knownAvailable, confirmedModel);

    // ── Step 6: Persist ────────────────────────────────────────────
    await upsertSetting(records, 'gemini_api_key',           key);
    await upsertSetting(records, 'gemini_tier',              tierEntry.tier);
    await upsertSetting(records, 'gemini_tier_level',        String(tierEntry.tierLevel));
    await upsertSetting(records, 'gemini_best_model',        confirmedModel);
    await upsertSetting(records, 'gemini_best_model_label',  tierEntry.label);
    await upsertSetting(records, 'gemini_spiritual_model',   spiritualModel);
    await upsertSetting(records, 'gemini_general_model',     generalModel);
    await upsertSetting(records, 'gemini_coding_model',      codingModel);
    await upsertSetting(records, 'gemini_tasks_model',       generalModel);
    await upsertSetting(records, 'gemini_video_model',       videoModel);
    await upsertSetting(records, 'gemini_fast_model',        fastModel);

    return {
      valid: true,
      tier: tierEntry.tier,
      tierLevel: tierEntry.tierLevel,
      bestModel: confirmedModel,
      bestModelLabel: tierEntry.label,
      availableModels: knownAvailable,
      sectionModels: { spiritual: spiritualModel, general: generalModel, coding: codingModel, video: videoModel, fast: fastModel },
    };
  },
});

