src/api/processImageToImage.ts.content:
import { z } from 'zod';
import { createEndpoint, AdminSettings, MediaGenerations, Users, ZiteError } from 'zite-integrations-backend-sdk';

// ── FACE IDENTITY LOCK PROTOCOL ───────────────────────────────────────────────
// When Gemini Vision is available: it reads the actual face and writes an
// exhaustive descriptor prompt (eyes, nose, jaw, skin tone, etc.) so Flux
// regenerates the SAME person in the new background.
//
// When Gemini is unavailable or slow: buildFaceLockPrompt() constructs a
// strong face-preservation instruction from the user's text alone — no vision
// analysis, but Flux is explicitly told to preserve every facial feature.
// ─────────────────────────────────────────────────────────────────────────────

const FACE_LOCK_VISION_SYSTEM = `You are an elite image-to-image prompt engineer with a MANDATORY FACE IDENTITY LOCK protocol.

## FACE LOCK RULE — NEVER VIOLATE:
If the image contains a human face, extract and reproduce ALL of these features with exact precision:
- EYES: exact shape (almond/round/hooded/monolid), iris color (amber/brown/green/hazel/blue/gray), pupil size, eyelid fold, inner/outer corner shape, lash density, eyebrow arch, thickness, spacing
- NOSE: bridge width (narrow/medium/wide), bridge height, tip shape (rounded/bulbous/pointed/upturned), nostril width
- LIPS: cupid's bow shape, upper/lower lip fullness ratio, lip width, corner position, vermilion border definition
- JAW & FACE SHAPE: jaw angle (sharp/soft/square/rounded), chin projection, cheekbone prominence, face width-to-height ratio
- SKIN: exact tone (e.g. "deep warm brown", "fair rosy beige", "medium golden olive"), texture, any freckles, moles, birthmarks — specify location
- HAIR: color, texture (straight/wavy/curly/coily), length, part placement, density at hairline
- IDENTITY: reproduce all the above so the AI generates the SAME person — not a similar one

## TRANSFORMATION SCOPE:
ONLY change: background, scenery, clothing, lighting, color grade, artistic style, environment.
NEVER change: the face, facial features, or identity.

## TASK:
1. Analyze the uploaded image thoroughly
2. Lock every facial feature described above
3. Apply the user transformation: "{userInstruction}"
4. Write a 180–250 word photorealistic prompt with ALL locked facial descriptors embedded
5. End with: photorealistic, 8K UHD, sharp focus, professional DSLR photography, natural HDR lighting, face identity preserved

## SAFETY RULES — ABSOLUTE:
- NEVER generate romantic, intimate, kissing, hugging, nude, or any inappropriate content.
- Output must be 100% family-friendly, professional, and clean.
- If the user's instruction implies anything inappropriate, override it with a clean professional portrait transformation.

Return ONLY the final prompt. No explanation, no preamble.`;

// ── Fallback: strong face-preservation without vision ────────────────────────
function buildFaceLockPrompt(userInstruction: string): string {
  return [
    'Professional portrait photograph of a real person.',
    'ABSOLUTE RULE — IDENTITY PRESERVATION: The person\'s face must remain 100% identical to the original photograph.',
    'Preserve without any alteration: facial bone structure, eye shape and iris color, nose bridge and tip shape, lip contour and fullness, jaw angle, chin shape, cheekbone placement, skin tone and complexion, any birthmarks or moles, hair color and texture and style.',
    'Do NOT alter, soften, ghost, blend, or reinterpret any facial feature.',
    `TRANSFORMATION INSTRUCTION: ${userInstruction}.`,
    'Apply the transformation ONLY to the background, environment, scenery, and lighting.',
    'The subject\'s face and head must look exactly as in the original — same person, same identity, same proportions.',
    'photorealistic, 8K UHD, sharp focus, professional DSLR photography, natural HDR lighting, high facial detail, no distortion, face identity preserved',
  ].join(' ');
}

export default createEndpoint({
  description: 'AI Image-to-Image: Face Identity Lock + HD 1024×1024 output via Pollinations Flux',
  authenticated: true,
  inputSchema: z.object({
    imageData: z.string().min(10),   // base64-encoded image (no data: prefix)
    prompt: z.string().min(3).max(600),
    mimeType: z.string().default('image/jpeg'),
  }),
  outputSchema: z.object({
    imageUrl: z.string(),
    enhancedPrompt: z.string(),
    remaining: z.number(),
  }),
  execute: async ({ input, context }) => {

    // ── Step 1: Quota check ───────────────────────────────────────
    let remaining = 999;
    let cfg: Record<string, string> = {};

    try {
      const [user, settings] = await Promise.all([
        Users.findOne({ id: context.user.id }),
        AdminSettings.findAll({ limit: 50 }),
      ]);

      cfg = Object.fromEntries(settings.records.map(r => [r.settingKey ?? '', r.settingValue ?? '']));

      const isVIP = user?.vipStatus === 'VIP' &&
        (!user.vipExpiresAt || new Date(user.vipExpiresAt) > new Date());

      if (isVIP) {
        const vipDaily = parseInt(cfg['img_limit_vip'] ?? '0') || 0;
        if (vipDaily > 0) {
          const today = new Date().toISOString().slice(0, 10);
          const usage = await MediaGenerations.findAll({ filters: { userEmail: context.user.email, date: today, type: 'Image' }, limit: 50 });
          const used = usage.records.reduce((s, r) => s + (r.count ?? 0), 0);
          if (used >= vipDaily) {
            throw new ZiteError({ code: 'FORBIDDEN', message: `⏰ Today's VIP image limit of ${vipDaily} reached!` });
          }
          remaining = vipDaily - used - 1;
        }
      } else {
        const freeLimits = [
          parseInt(cfg['img_limit_free_d1'] ?? '3') || 3,
          parseInt(cfg['img_limit_free_d2'] ?? '2') || 2,
          parseInt(cfg['img_limit_free_d3'] ?? '1') || 1,
        ];
        const joinedAt = user?.joinedAt ? new Date(user.joinedAt) : new Date();
        const daysSinceJoined = Math.floor((Date.now() - joinedAt.getTime()) / 86400000);
        const limit = daysSinceJoined < freeLimits.length ? freeLimits[daysSinceJoined] : 0;

        if (limit === 0) {
          throw new ZiteError({ code: 'FORBIDDEN', message: '🔒 Your free trial has ended. Get VIP for unlimited image transformations!' });
        }
        const today = new Date().toISOString().slice(0, 10);
        const usage = await MediaGenerations.findAll({ filters: { userEmail: context.user.email, date: today, type: 'Image' }, limit: 50 });
        const used = usage.records.reduce((s, r) => s + (r.count ?? 0), 0);
        if (used >= limit) {
          throw new ZiteError({ code: 'FORBIDDEN', message: `⏰ Today's limit of ${limit} images reached. Upgrade to VIP!` });
        }
        remaining = limit - used - 1;
      }
    } catch (e) {
      // Re-throw ZiteErrors (quota limits) — swallow DB errors so generation proceeds
      if (e instanceof ZiteError) throw e;
      console.error('[processImageToImage] quota check error:', e);
    }

    // ── Step 2: Build the face-lock enhanced prompt ───────────────
    // Try Gemini Vision first (12-second hard timeout to prevent Worker kill).
    // On any failure, fall back to a strong template prompt.
    let enhancedPrompt = buildFaceLockPrompt(input.prompt);

    const geminiKey = cfg['gemini_api_key'] ?? '';
    if (geminiKey) {
      const rawModel = cfg['gemini_best_model'] ?? 'gemini-1.5-flash';
      // Avoid 1.0 models — they don't support system instructions reliably
      const visionModel = (rawModel.includes('1.0') || rawModel.includes('1-0'))
        ? 'gemini-1.5-flash'
        : rawModel;

      const systemText = FACE_LOCK_VISION_SYSTEM.replace('{userInstruction}', input.prompt);

      try {
        // Hard 12-second timeout — Gemini can be slow; don't let it kill the Worker
        const controller = new AbortController();
        const geminiTimer = setTimeout(() => controller.abort(), 12_000);

        const visionRes = await fetch(
          `https://generativelanguage.googleapis.com/v1beta/models/${visionModel}:generateContent?key=${geminiKey}`,
          {
            signal: controller.signal,
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({
              systemInstruction: { parts: [{ text: systemText }] },
              contents: [{
                role: 'user',
                parts: [
                  { text: `Apply this transformation: "${input.prompt}"\n\nAnalyze the face, lock all features, generate the prompt:` },
                  { inlineData: { mimeType: input.mimeType, data: input.imageData } },
                ],
              }],
              generationConfig: { maxOutputTokens: 500, temperature: 0.15 },
            }),
          }
        );
        clearTimeout(geminiTimer);

        if (visionRes.ok) {
          const vd = await visionRes.json() as any;
          const aiText = vd.candidates?.[0]?.content?.parts?.[0]?.text?.trim() ?? '';
          // Only use Gemini output if it's substantive (> 50 chars and contains face-related words)
          if (aiText.length > 50) {
            enhancedPrompt = aiText;
            console.log('[processImageToImage] Gemini face-lock succeeded, prompt length:', aiText.length);
          }
        } else {
          const errBody = await visionRes.text().catch(() => '');
          console.warn('[processImageToImage] Gemini non-OK status:', visionRes.status, errBody.slice(0, 200));
        }
      } catch (geminiErr: any) {
        // AbortError = timeout, any other error = API issue
        const reason = geminiErr?.name === 'AbortError' ? 'timeout (>12s)' : String(geminiErr?.message ?? geminiErr);
        console.warn('[processImageToImage] Gemini skipped:', reason, '— using fallback face-lock prompt');
        // enhancedPrompt already set to buildFaceLockPrompt() above — continue normally
      }
    } else {
      console.log('[processImageToImage] No Gemini key configured — using template face-lock prompt');
    }

    // ── Step 3: Record usage ──────────────────────────────────────
    try {
      await MediaGenerations.create({
        record: {
          userEmail: context.user.email,
          date: new Date().toISOString().slice(0, 10),
          type: 'Image',
          count: 1,
        },
      });
    } catch (dbErr) {
      // Don't fail the generation if usage recording fails
      console.error('[processImageToImage] usage record error:', dbErr);
    }

    // ── Step 4: Safety filter + Realism enforcement ────────────────
    const BLOCKED_RE = /\b(kiss(ing|es)?|hug(ging|s)?|nud(e|ity)|naked|sexy|seductive|erotic|intimate|sensual|romantic\s*couple|love\s*scene|bedroom|undress|lingerie|bikini|provocative|obscen|porn|nsfw|xxx|adult\s*content|making\s*love|seduc)\b/i;

    enhancedPrompt = enhancedPrompt.replace(BLOCKED_RE, '').replace(/\s{2,}/g, ' ').trim();

    // Append realism tags if not already present
    if (!enhancedPrompt.toLowerCase().includes('photorealistic')) {
      enhancedPrompt += ', photorealistic, ultra-detailed 8k, natural lighting, shot on 35mm lens, realistic textures, cinematic color grading, no cartoon, no anime, no illustration, family-friendly, SFW';
    }

    const NEGATIVE_PROMPT = 'cartoon, anime, illustration, drawing, painting, nudity, nsfw, kissing, intimate, romantic, inappropriate';

    const seed = Date.now() % 999999;
    const imageUrl = [
      'https://image.pollinations.ai/prompt/',
      encodeURIComponent(enhancedPrompt),
      `?model=flux&width=1024&height=1024&nologo=true&enhance=false&seed=${seed}&negative=${encodeURIComponent(NEGATIVE_PROMPT)}`,
    ].join('');

    console.log('[processImageToImage] Returning Pollinations URL, seed:', seed);
    return { imageUrl, enhancedPrompt, remaining };
  },
});

src/api/submitSupportTicket.ts.content:
import { z } from 'zod';
import { createEndpoint, SupportTickets } from 'zite-integrations-backend-sdk';

export default createEndpoint({
  description: 'Submit a user support ticket to the Help Center',
  authenticated: true,
  inputSchema: z.object({
    title: z.string().min(3).max(200),
    message: z.string().min(10).max(3000),
  }),
  outputSchema: z.object({ success: z.boolean(), id: z.string() }),
  execute: async ({ input, context }) => {
    const ticket = await SupportTickets.create({
      record: {
        ticketTitle: input.title,
        userEmail: context.user.email,
        userId: context.user.id,
        message: input.message,
        status: 'Open',
      },
    });
    return { success: true, id: ticket.id };
  },
});

