import { useAppData } from '@/contexts/AppDataContext';
import { X } from 'lucide-react';
import { useState, useEffect } from 'react';

export default function PromoBanner() {
  const { bannerText, bannerUrl } = useAppData();
  const [closed, setClosed] = useState(false);

  useEffect(() => {
    const saved = sessionStorage.getItem('banner_closed');
    if (saved === 'true') setClosed(true);
  }, []);

  const handleClose = () => {
    setClosed(true);
    sessionStorage.setItem('banner_closed', 'true');
  };

  if (closed || (!bannerText && !bannerUrl)) return null;

  return (
    <div className="relative bg-gradient-to-r from-secondary/80 to-primary/40 border-b border-border">
      {bannerUrl && (
        <img src={bannerUrl} alt="Banner" className="w-full max-h-28 object-cover" />
      )}
      {bannerText && (
        <div className="px-10 py-2 text-center text-sm font-medium text-foreground">
          {bannerText}
        </div>
      )}
      <button
        onClick={handleClose}
        className="absolute right-2 top-1/2 -translate-y-1/2 text-muted-foreground hover:text-foreground p-1 rounded"
      >
        <X size={16} />
      </button>
    </div>
  );
}

