import { useEffect, useState } from 'react';
import { Crown, Zap, Check, Flame, Star, Infinity } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';

interface Props {
  id: string; planName: string; durationDays: number;
  priceUsd: number; originalPrice: number; features: string | null;
  saleEndTime: string | null; usdToPkr: number;
  onBuy: (id: string) => void;
}

function useCountdown(endTime: string | null): string {
  const [text, setText] = useState('');
  useEffect(() => {
    if (!endTime) return;
    const update = () => {
      const diff = new Date(endTime).getTime() - Date.now();
      if (diff <= 0) { setText(''); return; }
      const h = Math.floor(diff / 3600000);
      const m = Math.floor((diff % 3600000) / 60000);
      const s = Math.floor((diff % 60000) / 1000);
      setText(`${h}h ${m}m ${s}s`);
    };
    update();
    const id = setInterval(update, 1000);
    return () => clearInterval(id);
  }, [endTime]);
  return text;
}

function getTier(days: number) {
  if (days >= 36500) return {
    label: 'UNLIMITED', badge: 'BEST VALUE', badgeIcon: <Infinity size={9} />,
    badgeCls: 'bg-primary/20 text-primary border-primary/30',
    headerCls: 'bg-gradient-to-br from-primary/25 via-yellow-500/10 to-primary/10',
    ringCls: 'ring-2 ring-primary glow-gold',
    topBar: 'bg-gradient-to-r from-primary via-yellow-300 to-primary',
    btnCls: 'bg-primary text-primary-foreground glow-gold',
    btnLabel: '⚡ Get Unlimited Access',
    crownCls: 'text-primary',
  };
  if (days >= 90) return {
    label: '90 DAYS', badge: 'PREMIUM', badgeIcon: <Star size={9} />,
    badgeCls: 'bg-secondary/20 text-secondary border-secondary/30',
    headerCls: 'bg-gradient-to-br from-secondary/20 to-purple-500/5',
    ringCls: 'ring-1 ring-secondary/40',
    topBar: 'bg-gradient-to-r from-secondary to-purple-400',
    btnCls: 'bg-secondary text-secondary-foreground',
    btnLabel: `Buy ${days} Days VIP`,
    crownCls: 'text-secondary',
  };
  if (days >= 30) return {
    label: '30 DAYS', badge: 'POPULAR', badgeIcon: <Flame size={9} />,
    badgeCls: 'bg-emerald-500/20 text-emerald-400 border-emerald-500/30',
    headerCls: 'bg-gradient-to-br from-emerald-500/15 to-teal-500/5',
    ringCls: 'ring-1 ring-emerald-500/40',
    topBar: 'bg-gradient-to-r from-emerald-500 to-teal-400',
    btnCls: 'bg-emerald-600 hover:bg-emerald-600/90 text-white',
    btnLabel: `Buy ${days} Days VIP`,
    crownCls: 'text-emerald-400',
  };
  if (days >= 15) return {
    label: '15 DAYS', badge: '',
    badgeCls: '', headerCls: 'bg-gradient-to-br from-sky-500/10 to-blue-500/5',
    ringCls: 'ring-1 ring-sky-500/30',
    topBar: 'bg-gradient-to-r from-sky-500 to-blue-400',
    btnCls: 'bg-sky-600 hover:bg-sky-600/90 text-white',
    btnLabel: `Buy ${days} Days VIP`,
    crownCls: 'text-sky-400',
  };
  return {
    label: '7 DAYS', badge: '',
    badgeCls: '', headerCls: 'bg-muted/30',
    ringCls: '',
    topBar: 'bg-muted-foreground/40',
    btnCls: 'bg-muted text-foreground hover:bg-muted/80 border border-border',
    btnLabel: `Buy ${days} Days VIP`,
    crownCls: 'text-muted-foreground',
  };
}

export default function VIPCard({ id, planName, durationDays, priceUsd, originalPrice, features, saleEndTime, usdToPkr, onBuy }: Props) {
  const countdown = useCountdown(saleEndTime);
  const savings = originalPrice - priceUsd;
  const savingsPct = originalPrice > 0 ? Math.round((savings / originalPrice) * 100) : 0;
  const tier = getTier(durationDays);
  const featureList = features?.split('\n').filter(Boolean) ?? ['Unlimited AI Chat', 'Unlimited Images', 'Video Generation', 'Priority Support'];
  const pkrPrice = Math.round(priceUsd * usdToPkr);

  return (
    <div className={`card-dark rounded-2xl overflow-hidden flex flex-col transition-transform hover:scale-[1.01] relative ${tier.ringCls}`}>
      {/* Top color bar */}
      <div className={`h-1 w-full ${tier.topBar}`} />

      {/* Discount badge */}
      {savingsPct > 0 && (
        <div className="absolute top-3 right-3 z-10">
          <Badge className="bg-destructive text-white text-[10px] font-bold shadow-lg">-{savingsPct}% OFF</Badge>
        </div>
      )}

      {/* Header */}
      <div className={`p-4 pb-3 ${tier.headerCls}`}>
        <div className="flex items-center gap-2 mb-3">
          <Crown size={17} className={tier.crownCls} />
          <span className="font-black text-base">{planName}</span>
          {tier.badge && (
            <Badge className={`text-[9px] font-bold border flex items-center gap-0.5 ${tier.badgeCls}`}>
              {tier.badgeIcon} {tier.badge}
            </Badge>
          )}
        </div>
        <div className="flex items-end gap-2">
          <p className="text-3xl font-black text-foreground leading-none">${priceUsd}</p>
          {originalPrice > priceUsd && (
            <p className="text-sm text-muted-foreground line-through pb-0.5">${originalPrice}</p>
          )}
        </div>
        <p className="text-xs text-muted-foreground mt-1">≈ ₨{pkrPrice.toLocaleString()} PKR</p>

        {countdown && (
          <div className="mt-2.5 flex items-center gap-1.5 bg-destructive/10 border border-destructive/20 rounded-lg px-2.5 py-1.5">
            <Zap size={10} className="text-destructive shrink-0" />
            <span className="text-[10px] text-destructive font-semibold">Flash sale ends: {countdown}</span>
          </div>
        )}
      </div>

      {/* Features */}
      <div className="px-4 py-3 flex-1 space-y-1.5">
        {featureList.map((f, i) => (
          <div key={i} className="flex items-start gap-2">
            <Check size={12} className={`mt-0.5 shrink-0 ${tier.crownCls}`} />
            <span className="text-xs text-muted-foreground">{f}</span>
          </div>
        ))}
      </div>

      {/* CTA */}
      <div className="px-4 pb-4">
        <Button onClick={() => onBuy(id)}
          className={`w-full font-bold text-sm h-10 ${tier.btnCls}`}>
          {tier.btnLabel}
        </Button>
      </div>
    </div>
  );
}

