import { useState, useEffect, useRef, useCallback } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from 'zite-auth-sdk';
import {
  createVideoScript, checkVideoQuota, pollVideoOperation,
  videoHuggingFace, videoStability, videoGoogleVeo, videoSmartRouter,
  CheckVideoQuotaOutputType, CreateVideoScriptOutputType,
  VideoHuggingFaceOutputType, VideoStabilityOutputType, VideoGoogleVeoOutputType,
} from 'zite-endpoints-sdk';
import {
  ArrowLeft, Loader2, Film, Lock, Crown, Timer, Wand2, Copy, Check,
  FileText, Video, Hash, Clock, Upload, PlayCircle, ChevronRight, Shield,
} from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Textarea } from '@/components/ui/textarea';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import { Badge } from '@/components/ui/badge';
import { Skeleton } from '@/components/ui/skeleton';
import { Progress } from '@/components/ui/progress';
import { toast } from 'sonner';

type ScriptResult = CreateVideoScriptOutputType;
type QuotaInfo = CheckVideoQuotaOutputType;

// ══════════════════════════════════════════════════════════════════
// ENGINE DEFINITIONS — 4 separate video engines
// ══════════════════════════════════════════════════════════════════
type EngineId = 'huggingface' | 'stability' | 'google-veo' | 'premium';
interface Engine {
  id: EngineId;
  name: string;
  subtitle: string;
  icon: string;
  models: string;
  disabled?: boolean;
  disabledLabel?: string;
}

const ENGINES: Engine[] = [
  {
    id: 'huggingface',
    name: 'HuggingFace AI',
    subtitle: '4-Model Rotation',
    icon: '🤗',
    models: 'DAMO-ViLab · AnimateDiff · Zeroscope · SVD',
  },
  {
    id: 'stability',
    name: 'Stability AI',
    subtitle: 'Stable Video Diffusion',
    icon: '🎯',
    models: 'Stability AI v2 Beta',
  },
  {
    id: 'google-veo',
    name: 'Google Veo',
    subtitle: 'Veo 3.0 / 2.0',
    icon: '🔮',
    models: 'Veo 3.0 Preview · Veo 2.0',
  },
  {
    id: 'premium',
    name: 'VIP Premium Engine',
    subtitle: 'Coming Soon',
    icon: '👑',
    models: 'Runway Gen-3 · Sora (Paid Slot)',
    disabled: true,
    disabledLabel: 'Coming Soon',
  },
];

const DURATION_OPTIONS = [
  { value: '5', label: '5 Seconds' },
  { value: '10', label: '10 Seconds' },
  { value: '30', label: '30 Seconds' },
  { value: '60', label: '1 Minute' },
  { value: '300', label: '5 Minutes' },
  { value: '7200', label: '2 Hours (VIP Unlimited)' },
];

const STYLES = ['educational', 'entertainment', 'promotional', 'shorts', 'vlog', 'tutorial'] as const;
const PLATFORMS = ['YouTube', 'TikTok', 'Instagram Reels', 'Facebook'] as const;
const STYLE_ICONS: Record<string, string> = { educational: '📚', entertainment: '🎉', promotional: '📢', shorts: '⚡', vlog: '📹', tutorial: '🔧' };
const PLATFORM_ICONS: Record<string, string> = { YouTube: '▶️', TikTok: '🎵', 'Instagram Reels': '📸', Facebook: '📘' };

// ── Small helpers ─────────────────────────────────────────────────
function CopyBtn({ text }: { text: string }) {
  const [copied, setCopied] = useState(false);
  return (
    <button onClick={() => { navigator.clipboard.writeText(text); setCopied(true); toast.success('Copied!'); setTimeout(() => setCopied(false), 2000); }}
      className="p-1.5 rounded-lg text-muted-foreground hover:text-primary transition-colors">
      {copied ? <Check size={12} className="text-primary" /> : <Copy size={12} />}
    </button>
  );
}

// ── Watermarked Video Player ──────────────────────────────────────
function WatermarkedPlayer({ src, mime }: { src: string; mime: string }) {
  return (
    <div className="relative w-full rounded-xl overflow-hidden bg-black">
      <video src={src} controls autoPlay playsInline className="w-full max-h-72" />
      {/* Branded watermark overlay */}
      <div className="absolute bottom-10 right-3 pointer-events-none select-none">
        <span className="text-[10px] font-bold text-white/60 bg-black/30 backdrop-blur-sm rounded px-2 py-0.5 tracking-wide">
          Powered by Hussain AI
        </span>
      </div>
    </div>
  );
}

// ── VIP Lock Screen ──────────────────────────────────────────────
function VIPLockScreen({ reason, onLogin }: { reason: string; onLogin: () => void }) {
  return (
    <div className="flex flex-col items-center justify-center min-h-[60vh] p-6 text-center space-y-5">
      <div className="w-20 h-20 rounded-3xl bg-primary/10 border-2 border-primary/30 flex items-center justify-center">
        <Lock size={36} className="text-primary" />
      </div>
      <h2 className="text-xl font-black">Video Creator Locked</h2>
      <p className="text-sm text-muted-foreground max-w-xs">{reason}</p>
      <Button onClick={() => window.location.href = '/vip'} className="w-full max-w-xs bg-primary text-primary-foreground font-bold gap-2">
        <Crown size={14} /> Upgrade to VIP
      </Button>
      <Button variant="outline" onClick={onLogin} className="w-full max-w-xs text-sm gap-2">Already VIP? Sign In</Button>
    </div>
  );
}

// ── Engine Selector Cards ────────────────────────────────────────
function EngineSelector({ selected, onSelect }: { selected: EngineId; onSelect: (id: EngineId) => void }) {
  return (
    <div className="grid grid-cols-2 gap-2">
      {ENGINES.map(eng => {
        const active = selected === eng.id;
        return (
          <button
            key={eng.id}
            onClick={() => !eng.disabled && onSelect(eng.id)}
            disabled={eng.disabled}
            className={`relative text-left rounded-xl border p-3 transition-all ${
              eng.disabled
                ? 'opacity-50 cursor-not-allowed border-border bg-muted/30'
                : active
                  ? 'border-primary bg-primary/10 ring-1 ring-primary/30'
                  : 'border-border bg-card hover:border-primary/40'
            }`}
          >
            <div className="text-xl mb-1">{eng.icon}</div>
            <p className="text-xs font-bold leading-tight">{eng.name}</p>
            <p className="text-[9px] text-muted-foreground">{eng.subtitle}</p>
            <p className="text-[8px] text-muted-foreground/60 mt-1 leading-tight">{eng.models}</p>
            {eng.disabled && eng.disabledLabel && (
              <Badge className="absolute top-2 right-2 text-[8px] bg-muted text-muted-foreground border-border">
                {eng.disabledLabel}
              </Badge>
            )}
            {active && !eng.disabled && (
              <div className="absolute top-2 right-2 w-2.5 h-2.5 rounded-full bg-primary animate-pulse" />
            )}
          </button>
        );
      })}
    </div>
  );
}

// ══════════════════════════════════════════════════════════════════
// MAIN PAGE
// ══════════════════════════════════════════════════════════════════
export default function VideoCreatorPage() {
  const navigate = useNavigate();
  const { user, isLoading, loginWithRedirect } = useAuth();
  const [quota, setQuota] = useState<QuotaInfo | null>(null);
  const [quotaLoading, setQuotaLoading] = useState(true);

  // Smart Router state (VIP Plan 4 exclusive)
  const [smartRouterEnabled, setSmartRouterEnabled] = useState(true);

  // Engine state
  const [selectedEngine, setSelectedEngine] = useState<EngineId>('huggingface');
  const [duration, setDuration] = useState('5');
  const [concept, setConcept] = useState('');
  const [style, setStyle] = useState<typeof STYLES[number]>('educational');
  const [platform, setPlatform] = useState<typeof PLATFORMS[number]>('YouTube');

  // Video generation state
  const [generating, setGenerating] = useState(false);
  const [progress, setProgress] = useState({ message: '', percent: 0 });
  const [pipelineLog, setPipelineLog] = useState<string[]>([]);
  const [videoSrc, setVideoSrc] = useState('');
  const [videoMime, setVideoMime] = useState('video/mp4');
  const [resultEngine, setResultEngine] = useState('');

  // Script mode
  const [mode, setMode] = useState<'video' | 'script'>('video');
  const [scriptLoading, setScriptLoading] = useState(false);
  const [scriptResult, setScriptResult] = useState<ScriptResult | null>(null);

  // Gallery upload
  const videoFileRef = useRef<HTMLInputElement>(null);
  const [uploadedVideo, setUploadedVideo] = useState<{ url: string; name: string } | null>(null);

  // Auth gate
  useEffect(() => {
    if (!isLoading && user) {
      checkVideoQuota({}).then(setQuota).catch(() => setQuota(null)).finally(() => setQuotaLoading(false));
    } else if (!isLoading && !user) {
      setQuotaLoading(false);
    }
  }, [isLoading, user]);

  // Cleanup
  useEffect(() => {
    return () => {
      if (videoSrc.startsWith('blob:')) URL.revokeObjectURL(videoSrc);
      if (uploadedVideo?.url.startsWith('blob:')) URL.revokeObjectURL(uploadedVideo.url);
    };
  }, []);

  const base64ToBlobUrl = useCallback((b64: string, mime: string): string => {
    try {
      const byteChars = atob(b64);
      const byteArr = new Uint8Array(byteChars.length);
      for (let i = 0; i < byteChars.length; i++) byteArr[i] = byteChars.charCodeAt(i);
      return URL.createObjectURL(new Blob([byteArr], { type: mime }));
    } catch {
      return `data:${mime};base64,${b64}`;
    }
  }, []);

  // ── Generate Video ─────────────────────────────────────────────
  const handleGenerate = async () => {
    if (!concept.trim()) { toast.error('Enter your video concept first'); return; }
    if (videoSrc.startsWith('blob:')) URL.revokeObjectURL(videoSrc);

    setVideoSrc('');
    setPipelineLog([]);
    setResultEngine('');
    setGenerating(true);
    setProgress({ message: smartRouterEnabled && quota?.hasSmartRouter
      ? '🧠 Smart Router: Analyzing prompt...'
      : `🚀 Connecting to ${ENGINES.find(e => e.id === selectedEngine)?.name}...`, percent: 10 });

    try {
      const dur = parseInt(duration) || 5;

      // ── SMART ROUTER: VIP Plan 4 exclusive auto-routing ────────
      if (smartRouterEnabled && quota?.hasSmartRouter) {
        const aspect = ['TikTok', 'Instagram Reels'].includes(platform) ? '9:16' as const : '16:9' as const;
        setProgress({ message: '🧠 Smart Router analyzing prompt keywords...', percent: 15 });
        const res = await videoSmartRouter({ prompt: concept.trim(), durationSeconds: Math.min(dur, 60), aspectRatio: aspect });
        setPipelineLog(res.pipelineLog);
        setResultEngine(res.engine);
        if (res.success) {
          let url = res.videoUrl ?? '';
          if (!url && res.videoBase64 && res.mimeType) url = base64ToBlobUrl(res.videoBase64, res.mimeType);
          if (url) { setVideoSrc(url); setVideoMime(res.mimeType ?? 'video/mp4'); toast.success(`🎬 Smart Router: Video via ${res.engine}!`); }
          else if (res.operationId) {
            toast.success(`✅ Smart Router: Job submitted via ${res.engine} — polling...`);
            await pollForResult([res.operationId]);
          }
          else { toast.error('Smart Router succeeded but no video data returned'); }
        } else {
          toast.error('Smart Router: All engines failed. Try manual engine selection.');
        }
        return; // Skip manual engine logic
      }

      if (selectedEngine === 'huggingface') {
        setProgress({ message: '🤗 Cycling through 4 HuggingFace models...', percent: 20 });
        const res = await videoHuggingFace({ prompt: concept.trim(), durationSeconds: Math.min(dur, 30) });
        setPipelineLog(res.pipelineLog);
        setResultEngine(res.engine);
        if (res.success) {
          let url = res.videoUrl ?? '';
          if (!url && res.videoBase64 && res.mimeType) url = base64ToBlobUrl(res.videoBase64, res.mimeType);
          if (url) { setVideoSrc(url); setVideoMime(res.mimeType ?? 'video/mp4'); toast.success(`🎬 Video generated via ${res.engine}!`); }
          else { toast.error('Video generation succeeded but no video data returned'); }
        } else {
          toast.error('All 4 HuggingFace models failed. Check API key or try another engine.');
        }
      }

      else if (selectedEngine === 'stability') {
        setProgress({ message: '🎯 Connecting to Stability AI...', percent: 30 });
        const res = await videoStability({ prompt: concept.trim(), durationSeconds: Math.min(dur, 30) });
        setPipelineLog(res.pipelineLog);
        setResultEngine(res.engine);
        if (res.success) {
          if (res.videoBase64 && res.mimeType) {
            setVideoSrc(base64ToBlobUrl(res.videoBase64, res.mimeType));
            setVideoMime(res.mimeType);
            toast.success('🎬 Video generated via Stability AI!');
          } else if (res.operationId) {
            toast.success('✅ Job submitted to Stability AI — polling for result...');
            // Poll via existing pollVideoOperation
            await pollForResult([res.operationId]);
          }
        } else {
          toast.error('Stability AI failed. Check API key in Admin Panel.');
        }
      }

      else if (selectedEngine === 'google-veo') {
        const aspect = ['TikTok', 'Instagram Reels'].includes(platform) ? '9:16' as const : '16:9' as const;
        setProgress({ message: '🔮 Connecting to Google Veo...', percent: 30 });
        const res = await videoGoogleVeo({ prompt: concept.trim(), durationSeconds: Math.min(dur, 60), aspectRatio: aspect });
        setPipelineLog(res.pipelineLog);
        setResultEngine(res.engine);
        if (res.success) {
          if (res.videoUrl) { setVideoSrc(res.videoUrl); setVideoMime(res.mimeType ?? 'video/mp4'); toast.success(`🎬 Video generated via ${res.engine}!`); }
          else if (res.videoBase64 && res.mimeType) { setVideoSrc(base64ToBlobUrl(res.videoBase64, res.mimeType)); setVideoMime(res.mimeType); toast.success(`🎬 Video ready via ${res.engine}!`); }
          else if (res.operationId) {
            toast.success('✅ Veo job submitted — polling...');
            await pollForResult([res.operationId]);
          }
        } else {
          toast.error('Google Veo failed. Check API key configuration.');
        }
      }
    } catch (e: any) {
      toast.error(e?.message?.split('\n')[0] ?? '❌ Video generation failed');
    } finally {
      setGenerating(false);
      setProgress({ message: '', percent: 100 });
      checkVideoQuota({}).then(setQuota).catch(() => {});
    }
  };

  // ── Poll for LRO results ──────────────────────────────────────
  const pollForResult = async (opIds: string[]) => {
    let attempts = 0;
    const maxAttempts = 60;
    const poll = async (): Promise<void> => {
      attempts++;
      if (attempts > maxAttempts) { toast.error('⏰ Polling timed out'); return; }
      setProgress({ message: `⚙️ Processing... (${attempts}/${maxAttempts})`, percent: Math.min(90, 30 + attempts) });
      try {
        const res = await pollVideoOperation({ operationIds: opIds });
        if (res.allComplete) {
          const completed = res.results.find(r => r.status === 'complete');
          if (completed?.videoUrl) { setVideoSrc(completed.videoUrl); setVideoMime(completed.mimeType ?? 'video/mp4'); toast.success('🎬 Video ready!'); return; }
          if (completed?.videoBase64 && completed?.mimeType) { setVideoSrc(base64ToBlobUrl(completed.videoBase64, completed.mimeType)); setVideoMime(completed.mimeType); toast.success('🎬 Video ready!'); return; }
          toast.error('Video processing complete but no data returned');
          return;
        }
      } catch { /* transient */ }
      await new Promise(r => setTimeout(r, 6000));
      return poll();
    };
    await poll();
  };

  // ── Script Generation ─────────────────────────────────────────
  const generateScript = async () => {
    if (!concept.trim()) { toast.error('Enter your video concept first'); return; }
    setScriptLoading(true); setScriptResult(null);
    try {
      const res = await createVideoScript({ concept: concept.trim(), style, platform });
      setScriptResult(res);
      toast.success('✅ Script generated!');
    } catch (e: any) { toast.error(e?.message ?? 'Script generation failed'); }
    finally { setScriptLoading(false); }
  };

  // ── Gallery Upload ────────────────────────────────────────────
  const handleVideoUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file?.type.startsWith('video/')) { toast.error('Please select a video file'); return; }
    if (uploadedVideo?.url.startsWith('blob:')) URL.revokeObjectURL(uploadedVideo.url);
    setUploadedVideo({ url: URL.createObjectURL(file), name: file.name });
    if (!concept.trim()) setConcept(file.name.replace(/\.[^.]+$/, '').replace(/[-_]/g, ' '));
    toast.success('🎬 Video loaded!');
    e.target.value = '';
  };

  // ── Loading / Auth / VIP gates ────────────────────────────────
  if (isLoading || (user && quotaLoading)) {
    return <div className="p-4 space-y-3 max-w-lg mx-auto"><Skeleton className="h-14 rounded-xl" /><Skeleton className="h-48 rounded-xl" /><Skeleton className="h-24 rounded-xl" /></div>;
  }
  if (!user) {
    return (
      <div className="flex flex-col min-h-screen">
        <StudioHeader onBack={() => navigate('/ai')} />
        <VIPLockScreen reason="Sign in to access the Video Creator." onLogin={() => loginWithRedirect({ redirectUrl: window.location.href })} />
      </div>
    );
  }
  if (quota && !quota.isVIP) {
    return (
      <div className="flex flex-col min-h-screen">
        <StudioHeader onBack={() => navigate('/ai')} />
        <VIPLockScreen reason={quota.lockReason ?? 'VIP membership required.'} onLogin={() => loginWithRedirect()} />
      </div>
    );
  }

  // ── Main UI ───────────────────────────────────────────────────
  return (
    <div className="flex flex-col min-h-screen pb-8">
      <StudioHeader onBack={() => navigate('/ai')} quota={quota} />

      <div className="p-3 space-y-3 max-w-lg mx-auto w-full">
        {/* VIP Bar */}
        {quota && (
          <div className="flex items-center gap-2 bg-primary/5 border border-primary/15 rounded-xl px-3 py-2">
            <Crown size={12} className="text-primary shrink-0" />
            <p className="text-xs text-primary font-semibold">{quota.vipPlan ?? 'VIP'}</p>
            <span className="text-muted-foreground/50 text-xs">·</span>
            <p className="text-xs text-muted-foreground">{quota.daysLeft} days left</p>
          </div>
        )}

        {/* ── Smart Router Badge (VIP Plan 4+ exclusive) ── */}
        {quota?.hasSmartRouter && (
          <div className="rounded-xl border border-primary/25 bg-gradient-to-r from-primary/5 via-primary/10 to-primary/5 p-2.5">
            <div className="flex items-center justify-between">
              <div className="flex items-center gap-2 min-w-0">
                <div className="w-7 h-7 rounded-lg bg-primary/15 border border-primary/25 flex items-center justify-center shrink-0">
                  <span className="text-sm">🧠</span>
                </div>
                <div className="min-w-0">
                  <p className="text-[11px] font-black text-foreground leading-tight">Universal Video Mode</p>
                  <p className="text-[9px] text-muted-foreground leading-tight">
                    {smartRouterEnabled ? 'AI auto-routes your prompt to the best engine' : 'Manual engine selection active'}
                  </p>
                </div>
              </div>
              <button
                onClick={() => setSmartRouterEnabled(!smartRouterEnabled)}
                className={`relative w-10 h-5 rounded-full transition-colors shrink-0 ${
                  smartRouterEnabled ? 'bg-primary' : 'bg-muted-foreground/30'
                }`}
              >
                <span className={`absolute top-0.5 w-4 h-4 rounded-full bg-white shadow transition-transform ${
                  smartRouterEnabled ? 'translate-x-5' : 'translate-x-0.5'
                }`} />
              </button>
            </div>
            {smartRouterEnabled && (
              <div className="flex flex-wrap gap-1 mt-2">
                <span className="text-[8px] bg-primary/10 text-primary border border-primary/20 rounded-full px-2 py-0.5 font-semibold">🎬 Cinematic → Veo/Stability</span>
                <span className="text-[8px] bg-primary/10 text-primary border border-primary/20 rounded-full px-2 py-0.5 font-semibold">🗣️ Avatar → HuggingFace</span>
                <span className="text-[8px] bg-primary/10 text-primary border border-primary/20 rounded-full px-2 py-0.5 font-semibold">🔮 Default → Google Veo</span>
              </div>
            )}
          </div>
        )}

        {/* ── Mode Toggle ── */}
        <div className="flex rounded-xl border border-border overflow-hidden">
          <button onClick={() => setMode('video')}
            className={`flex-1 flex items-center justify-center gap-1.5 py-2.5 text-xs font-bold transition-colors ${mode === 'video' ? 'bg-primary text-primary-foreground' : 'bg-muted/50 text-muted-foreground'}`}>
            <Film size={13} /> Video Generator
          </button>
          <button onClick={() => setMode('script')}
            className={`flex-1 flex items-center justify-center gap-1.5 py-2.5 text-xs font-bold transition-colors ${mode === 'script' ? 'bg-primary text-primary-foreground' : 'bg-muted/50 text-muted-foreground'}`}>
            <FileText size={13} /> Script Writer
          </button>
        </div>

        {mode === 'video' ? (
          <>
            {/* ── Engine Selector ── */}
            <div>
              <p className="text-[10px] text-muted-foreground uppercase tracking-widest font-bold mb-2">Select Video Engine</p>
              <EngineSelector selected={selectedEngine} onSelect={setSelectedEngine} />
            </div>

            {/* ── Concept + Duration ── */}
            <div className="rounded-2xl border border-border bg-card p-3 space-y-3">
              <p className="text-[10px] text-muted-foreground uppercase tracking-widest font-bold">🎬 Video Prompt</p>
              <Textarea
                value={concept} onChange={e => setConcept(e.target.value)}
                placeholder="Describe your video... e.g. 'A cinematic drone shot flying over green fields in Punjab at sunset'"
                className="bg-muted border-border text-sm resize-none" rows={4}
              />
              <div className="grid grid-cols-2 gap-2">
                <div>
                  <p className="text-[10px] text-muted-foreground mb-1">⏱ Duration</p>
                  <Select value={duration} onValueChange={setDuration}>
                    <SelectTrigger className="bg-muted border-border h-9 text-xs"><SelectValue /></SelectTrigger>
                    <SelectContent className="bg-card border-border">
                      {DURATION_OPTIONS.map(o => <SelectItem key={o.value} value={o.value}>{o.label}</SelectItem>)}
                    </SelectContent>
                  </Select>
                </div>
                <div>
                  <p className="text-[10px] text-muted-foreground mb-1">📺 Platform</p>
                  <Select value={platform} onValueChange={(v) => setPlatform(v as typeof platform)}>
                    <SelectTrigger className="bg-muted border-border h-9 text-xs"><SelectValue /></SelectTrigger>
                    <SelectContent className="bg-card border-border">
                      {PLATFORMS.map(p => <SelectItem key={p} value={p}>{PLATFORM_ICONS[p]} {p}</SelectItem>)}
                    </SelectContent>
                  </Select>
                </div>
              </div>

              <Button onClick={handleGenerate} disabled={generating || !concept.trim()} className="w-full bg-primary text-primary-foreground font-bold gap-2">
                {generating ? <><Loader2 size={15} className="animate-spin" /> Generating...</> : <><Film size={15} /> Generate Video</>}
              </Button>
            </div>

            {/* ── Progress ── */}
            {generating && (
              <div className="rounded-2xl border border-primary/20 bg-card p-4 space-y-3">
                <div className="flex items-center gap-2">
                  <Loader2 size={14} className="animate-spin text-primary" />
                  <p className="text-xs text-muted-foreground animate-pulse">{progress.message}</p>
                </div>
                <Progress value={progress.percent} className="h-2" />
              </div>
            )}

            {/* ── Pipeline Log ── */}
            {pipelineLog.length > 0 && !generating && (
              <div className="rounded-xl border border-border bg-muted/30 p-3 space-y-1">
                <p className="text-[10px] font-bold text-muted-foreground uppercase tracking-wider mb-1">Pipeline Log</p>
                {pipelineLog.map((step, i) => (
                  <p key={i} className={`text-[11px] ${step.startsWith('✅') ? 'text-green-500' : step.startsWith('❌') ? 'text-destructive' : 'text-muted-foreground'}`}>{step}</p>
                ))}
              </div>
            )}

            {/* ── Video Result with Watermark ── */}
            {videoSrc && !generating && (
              <div className="rounded-2xl border border-primary/20 overflow-hidden bg-card space-y-0">
                <div className="flex items-center justify-between px-3 py-2 bg-primary/5 border-b border-border">
                  <div className="flex items-center gap-2">
                    <PlayCircle size={14} className="text-primary" />
                    <p className="text-xs font-bold text-primary">Generated Video</p>
                  </div>
                  {resultEngine && <Badge className="text-[9px] bg-primary/10 text-primary border-primary/20">{resultEngine}</Badge>}
                </div>
                <WatermarkedPlayer src={videoSrc} mime={videoMime} />
                <p className="text-[10px] text-muted-foreground text-center py-2">
                  🎬 Download via browser menu · Watermark: Powered by Hussain AI
                </p>
              </div>
            )}
          </>
        ) : (
          /* ═══════════ SCRIPT MODE ═══════════ */
          <>
            <div className="rounded-2xl border border-border bg-card p-3 space-y-3">
              <p className="text-[10px] text-muted-foreground uppercase tracking-widest font-bold">📝 Script Concept</p>
              <Textarea value={concept} onChange={e => setConcept(e.target.value)}
                placeholder="Describe your video idea... e.g. 'How to make money online in Pakistan, step by step guide'"
                className="bg-muted border-border text-sm resize-none" rows={3} />
              <div className="grid grid-cols-2 gap-2">
                <div>
                  <p className="text-[10px] text-muted-foreground mb-1">Style</p>
                  <Select value={style} onValueChange={(v) => setStyle(v as typeof style)}>
                    <SelectTrigger className="bg-muted border-border h-9 text-xs"><SelectValue /></SelectTrigger>
                    <SelectContent className="bg-card border-border">
                      {STYLES.map(s => <SelectItem key={s} value={s}>{STYLE_ICONS[s]} {s.charAt(0).toUpperCase() + s.slice(1)}</SelectItem>)}
                    </SelectContent>
                  </Select>
                </div>
                <div>
                  <p className="text-[10px] text-muted-foreground mb-1">Platform</p>
                  <Select value={platform} onValueChange={(v) => setPlatform(v as typeof platform)}>
                    <SelectTrigger className="bg-muted border-border h-9 text-xs"><SelectValue /></SelectTrigger>
                    <SelectContent className="bg-card border-border">
                      {PLATFORMS.map(p => <SelectItem key={p} value={p}>{PLATFORM_ICONS[p]} {p}</SelectItem>)}
                    </SelectContent>
                  </Select>
                </div>
              </div>
              <Button onClick={generateScript} disabled={scriptLoading || !concept.trim()} className="w-full bg-primary text-primary-foreground font-bold gap-2">
                {scriptLoading ? <><Loader2 size={15} className="animate-spin" /> Generating...</> : <><Wand2 size={15} /> Generate Script</>}
              </Button>
            </div>

            {scriptLoading && (
              <div className="rounded-2xl border border-border bg-card p-6 text-center space-y-3">
                <div className="flex justify-center gap-1">
                  {[0,1,2,3,4].map(i => <div key={i} className="w-2 h-6 bg-primary/60 rounded-full animate-bounce" style={{ animationDelay: `${i * 100}ms` }} />)}
                </div>
                <p className="text-sm text-muted-foreground animate-pulse">Writing your {style} script for {platform}...</p>
              </div>
            )}

            {scriptResult && <ScriptResultView result={scriptResult} platform={platform} />}
          </>
        )}

        {/* ── Gallery Upload ── */}
        <input ref={videoFileRef} type="file" accept="video/*" className="hidden" onChange={handleVideoUpload} />
        <button onClick={() => videoFileRef.current?.click()}
          className="w-full flex items-center justify-center gap-2 border border-border rounded-xl px-4 py-2.5 text-sm font-semibold text-foreground hover:bg-muted/60 transition-colors">
          <Upload size={15} className="text-primary" /> 📁 Upload Video from Gallery
        </button>

        {uploadedVideo && (
          <div className="rounded-2xl border border-border overflow-hidden bg-card">
            <div className="flex items-center justify-between px-3 py-2 bg-muted/50 border-b border-border">
              <div className="flex items-center gap-2 min-w-0">
                <PlayCircle size={14} className="text-primary shrink-0" />
                <p className="text-xs font-semibold truncate">{uploadedVideo.name}</p>
              </div>
              <button onClick={() => { URL.revokeObjectURL(uploadedVideo.url); setUploadedVideo(null); }}
                className="text-[10px] text-destructive/60 hover:text-destructive shrink-0 ml-2">Remove</button>
            </div>
            <video src={uploadedVideo.url} controls playsInline className="w-full max-h-64 bg-black" />
          </div>
        )}

        {/* Footer */}
        <div className="text-center pt-2">
          <div className="flex items-center justify-center gap-1.5">
            <Shield size={10} className="text-muted-foreground/40" />
            <p className="text-[9px] text-muted-foreground/40">Content Safety Filter Active · All engines filtered</p>
          </div>
        </div>
      </div>
    </div>
  );
}

// ── Studio Header ────────────────────────────────────────────────
function StudioHeader({ onBack, quota }: { onBack: () => void; quota?: QuotaInfo | null }) {
  return (
    <div className="flex items-center gap-3 px-3 py-3 border-b border-border bg-card/80 backdrop-blur sticky top-0 z-10">
      <button onClick={onBack} className="text-muted-foreground hover:text-foreground"><ArrowLeft size={18} /></button>
      <div className="w-8 h-8 rounded-xl bg-primary/10 border border-primary/20 flex items-center justify-center">
        <Film size={15} className="text-primary" />
      </div>
      <div className="flex-1 min-w-0">
        <p className="font-black text-sm">Video Creator Studio</p>
        <p className="text-[10px] text-muted-foreground">4 Engines · Content Safety · Watermark</p>
      </div>
      {quota && (
        <div className="flex items-center gap-1 bg-primary/10 border border-primary/20 rounded-full px-2 py-0.5 shrink-0">
          <Timer size={9} className="text-primary" />
          <span className="text-[10px] text-primary font-bold">{quota.dailyLimit - quota.usedToday}/{quota.dailyLimit}</span>
        </div>
      )}
    </div>
  );
}

// ── Script Result View ──────────────────────────────────────────
function ScriptResultView({ result, platform }: { result: ScriptResult; platform: string }) {
  return (
    <div className="space-y-3">
      <div className="rounded-2xl border border-border bg-card p-3 space-y-2">
        <div className="flex items-center justify-between">
          <p className="text-xs font-semibold text-muted-foreground">📌 Title</p>
          <CopyBtn text={result.title} />
        </div>
        <p className="font-bold text-sm">{result.title}</p>
        <div className="flex items-center justify-between mt-2">
          <p className="text-xs font-semibold text-muted-foreground">📝 Description</p>
          <CopyBtn text={result.description} />
        </div>
        <p className="text-xs text-muted-foreground">{result.description}</p>
      </div>

      <Tabs defaultValue="script">
        <TabsList className="grid grid-cols-3 bg-muted border border-border w-full">
          <TabsTrigger value="script" className="text-xs gap-1 data-[state=active]:bg-primary data-[state=active]:text-primary-foreground"><FileText size={11} /> Script</TabsTrigger>
          <TabsTrigger value="scenes" className="text-xs gap-1 data-[state=active]:bg-primary data-[state=active]:text-primary-foreground"><Video size={11} /> Scenes</TabsTrigger>
          <TabsTrigger value="hashtags" className="text-xs gap-1 data-[state=active]:bg-primary data-[state=active]:text-primary-foreground"><Hash size={11} /> Tags</TabsTrigger>
        </TabsList>

        <TabsContent value="script" className="mt-3">
          <div className="rounded-2xl border border-border bg-card p-3 space-y-2">
            <div className="flex items-center justify-between">
              <p className="text-xs font-semibold text-muted-foreground flex items-center gap-1"><FileText size={11} /> Full Script</p>
              <CopyBtn text={result.script} />
            </div>
            <pre className="text-xs whitespace-pre-wrap leading-relaxed bg-muted/50 rounded-xl p-3 border border-border max-h-96 overflow-y-auto">{result.script}</pre>
          </div>
        </TabsContent>

        <TabsContent value="scenes" className="mt-3 space-y-2">
          {result.scenes.map((scene, i) => (
            <div key={i} className="rounded-xl border border-border bg-card p-3 space-y-1.5">
              <div className="flex items-center gap-2">
                <div className="w-6 h-6 rounded-full bg-primary/20 border border-primary/30 flex items-center justify-center">
                  <span className="text-[10px] font-bold text-primary">{i + 1}</span>
                </div>
                <p className="font-semibold text-sm flex-1">{scene.title}</p>
                <Badge className="bg-primary/10 text-primary border-primary/20 text-[9px] gap-1"><Clock size={8} /> {scene.duration}</Badge>
              </div>
              <p className="text-xs text-muted-foreground pl-8">{scene.description}</p>
              <p className="text-[11px] text-primary/80 italic pl-8">🎥 {scene.visuals}</p>
            </div>
          ))}
        </TabsContent>

        <TabsContent value="hashtags" className="mt-3">
          <div className="rounded-2xl border border-border bg-card p-3 space-y-3">
            <div className="flex items-center justify-between">
              <p className="text-xs font-semibold text-muted-foreground"># Hashtags ({result.hashtags.length})</p>
              <button onClick={() => { navigator.clipboard.writeText(result.hashtags.join(' ')); toast.success('All hashtags copied!'); }}
                className="text-xs text-primary flex items-center gap-1 hover:underline"><Copy size={10} /> Copy All</button>
            </div>
            <div className="flex flex-wrap gap-1.5">
              {result.hashtags.map(tag => (
                <span key={tag} className="inline-flex items-center gap-1 bg-primary/10 border border-primary/20 rounded-full px-2.5 py-1 text-xs text-primary">
                  {tag}
                  <button onClick={() => { navigator.clipboard.writeText(tag); toast.success('Copied!'); }} className="hover:text-primary/70"><Copy size={9} /></button>
                </span>
              ))}
            </div>
          </div>
        </TabsContent>
      </Tabs>
    </div>
  );
}

