import { useState, useEffect } from 'react';
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuSeparator,
  DropdownMenuTrigger,
} from '@/components/ui/dropdown-menu';
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
} from '@/components/ui/dialog';
import {
  MoreVertical,
  Share2,
  HelpCircle,
  Crown,
  Wallet,
  BrainCircuit,
  MessageCircle,
  Image,
  Settings2,
  Save,
  Trash2,
  Loader2,
} from 'lucide-react';
import { useAuth } from 'zite-auth-sdk';
import { useNavigate } from 'react-router-dom';
import { Badge } from '@/components/ui/badge';
import { Button } from '@/components/ui/button';
import { toast } from 'sonner';

const MASTER_RULES_KEY = 'ghulam_ai_master_rules';

/** Read master rules from localStorage — always returns full string, never truncated */
export function getMasterRules(): string {
  try { return localStorage.getItem(MASTER_RULES_KEY) ?? ''; } catch { return ''; }
}

export default function ThreeDotMenu() {
  const { user, loginWithRedirect } = useAuth();
  const navigate = useNavigate();
  const [fixerOpen, setFixerOpen] = useState(false);

  const statusColor =
    user?.vipStatus === 'VIP'
      ? 'bg-primary/20 text-primary border-primary/30'
      : user?.vipStatus === 'Pending'
      ? 'bg-yellow-500/20 text-yellow-400 border-yellow-500/40'
      : 'bg-muted text-muted-foreground border-border';

  const handleReferral = () => {
    if (!user) { loginWithRedirect({ redirectUrl: window.location.href }); return; }
    const cleanOrigin = window.location.origin;
    const refCode = user.referralCode ?? '';
    const link = refCode ? `${cleanOrigin}?ref=${refCode}` : cleanOrigin;
    navigator.clipboard.writeText(link).then(() => toast.success('✅ Referral link copied!'));
  };

  const gate = (fn: () => void) => {
    if (!user) { loginWithRedirect({ redirectUrl: window.location.href }); return; }
    fn();
  };

  return (
    <>
      <DropdownMenu>
        <DropdownMenuTrigger asChild>
          <button className="p-2 rounded-full hover:bg-muted transition-colors">
            <MoreVertical size={20} className="text-foreground" />
          </button>
        </DropdownMenuTrigger>
        <DropdownMenuContent align="end" className="w-64 bg-card border-border">
          {user && (
            <>
              <div className="px-3 py-2.5 flex items-center justify-between">
                <div>
                  <p className="text-xs font-medium truncate max-w-[130px]">{user.name || user.email}</p>
                  <p className="text-[10px] text-muted-foreground">Account Status</p>
                </div>
                <Badge className={`text-[10px] border ${statusColor}`}>
                  {user.vipStatus === 'VIP' ? '👑 VIP' : user.vipStatus === 'Pending' ? '⏳ Pending' : '🆓 Free'}
                </Badge>
              </div>
              <DropdownMenuSeparator />
            </>
          )}

          <DropdownMenuItem onClick={() => navigate('/')} className="gap-2 cursor-pointer">
            <MessageCircle size={15} className="text-primary" />
            <span className="font-medium">Chat</span>
          </DropdownMenuItem>

          <DropdownMenuItem onClick={() => gate(() => navigate('/media'))} className="gap-2 cursor-pointer">
            <Image size={15} className="text-secondary" />
            <span className="font-medium">AI Media Lab</span>
          </DropdownMenuItem>

          <DropdownMenuSeparator />

          <DropdownMenuItem onClick={() => gate(() => navigate('/ai'))} className="gap-2 cursor-pointer">
            <BrainCircuit size={15} className="text-emerald-400" />
            <span>AI Hub</span>
          </DropdownMenuItem>

          <DropdownMenuItem onClick={() => gate(() => navigate('/wallet'))} className="gap-2 cursor-pointer">
            <Wallet size={15} className="text-green-400" />
            <span>My Wallet & Earnings</span>
          </DropdownMenuItem>

          <DropdownMenuItem onClick={() => gate(() => navigate('/vip'))} className="gap-2 cursor-pointer">
            <Crown size={15} className="text-primary" />
            <span>VIP Plans</span>
          </DropdownMenuItem>

          <DropdownMenuSeparator />

          {/* ── Hussain AI Engine Fixer ── */}
          <DropdownMenuItem onClick={() => setFixerOpen(true)} className="gap-2 cursor-pointer">
            <Settings2 size={15} className="text-primary" />
            <span className="font-medium">Hussain AI Engine Fixer</span>
          </DropdownMenuItem>

          <DropdownMenuSeparator />

          <DropdownMenuItem onClick={handleReferral} className="gap-2 cursor-pointer">
            <Share2 size={15} className="text-blue-400" />
            <span>Free Earning (Referral Link)</span>
          </DropdownMenuItem>

          <DropdownMenuItem onClick={() => toast.info('Help: Type your question in the chat!')} className="gap-2 cursor-pointer">
            <HelpCircle size={15} className="text-muted-foreground" />
            <span>Help Center</span>
          </DropdownMenuItem>
        </DropdownMenuContent>
      </DropdownMenu>

      {/* ── Engine Fixer Dialog ── */}
      {fixerOpen && (
        <EngineFixerDialog open={fixerOpen} onClose={() => setFixerOpen(false)} />
      )}
    </>
  );
}

// ══════════════════════════════════════════════════════════════════
// ENGINE FIXER DIALOG — Unlimited master rules text area
// ══════════════════════════════════════════════════════════════════
function EngineFixerDialog({ open, onClose }: { open: boolean; onClose: () => void }) {
  const [rules, setRules] = useState('');
  const [saving, setSaving] = useState(false);
  const [charCount, setCharCount] = useState(0);

  useEffect(() => {
    if (open) {
      const saved = getMasterRules();
      setRules(saved);
      setCharCount(saved.length);
    }
  }, [open]);

  const handleChange = (val: string) => {
    setRules(val);
    setCharCount(val.length);
  };

  const handleSave = () => {
    setSaving(true);
    try {
      localStorage.setItem(MASTER_RULES_KEY, rules);
      toast.success('✅ Master Rules saved successfully!');
    } catch {
      toast.error('Storage error — try clearing browser data');
    } finally {
      setSaving(false);
    }
  };

  const handleClear = () => {
    setRules('');
    setCharCount(0);
    localStorage.removeItem(MASTER_RULES_KEY);
    toast.success('🗑️ Master Rules cleared');
  };

  return (
    <Dialog open={open} onOpenChange={v => { if (!v) onClose(); }}>
      <DialogContent className="max-w-lg w-[95vw] max-h-[90vh] flex flex-col bg-card border-border p-0 gap-0">
        <DialogHeader className="px-4 pt-4 pb-2 shrink-0">
          <DialogTitle className="flex items-center gap-2 text-base">
            <Settings2 size={18} className="text-primary" />
            Hussain AI Engine Fixer
          </DialogTitle>
          <p className="text-xs text-muted-foreground mt-1">
            ماسٹر رولز — ان لمیٹڈ پرامپٹ · کوئی حد نہیں
          </p>
        </DialogHeader>

        {/* Unlimited text area — no maxLength, fully scrollable & resizable */}
        <div className="flex-1 px-4 py-2 min-h-0 overflow-hidden flex flex-col">
          <textarea
            value={rules}
            onChange={e => handleChange(e.target.value)}
            placeholder={`Enter your master configuration rules here...\n\nیہاں اپنے ماسٹر رولز لکھیں — کوئی الفاظ یا حروف کی حد نہیں ہے۔\n\nExamples:\n• System prompt overrides\n• Style modifiers (cinematic, documentary, etc.)\n• Safety filter extensions\n• Multi-line generation chains\n• Custom engine routing rules`}
            className="w-full flex-1 min-h-[200px] max-h-[50vh] bg-muted border border-border rounded-xl p-3 text-sm leading-relaxed outline-none resize-y placeholder:text-muted-foreground/50 focus:border-primary/50 transition-colors"
            style={{ overflow: 'auto' }}
            spellCheck={false}
          />
          <div className="flex items-center justify-between mt-2">
            <p className="text-[10px] text-muted-foreground/60">
              {charCount > 0 ? `${charCount.toLocaleString()} characters · ${rules.split(/\s+/).filter(Boolean).length.toLocaleString()} words` : 'No limits — type freely'}
            </p>
            <p className="text-[10px] text-muted-foreground/40">
              ∞ Unlimited
            </p>
          </div>
        </div>

        {/* Action buttons */}
        <div className="px-4 pb-4 pt-2 flex items-center gap-2 shrink-0 border-t border-border">
          <Button onClick={handleSave} disabled={saving} className="flex-1 bg-primary text-primary-foreground font-bold gap-2">
            {saving ? <Loader2 size={14} className="animate-spin" /> : <Save size={14} />}
            Save Master Rules
          </Button>
          <Button variant="outline" onClick={handleClear} className="gap-1.5 text-destructive border-destructive/30 hover:bg-destructive/10">
            <Trash2 size={13} />
            Clear
          </Button>
        </div>
      </DialogContent>
    </Dialog>
  );
}

