// ══════════════════════════════════════════════════════════════════
// PULL-TO-HOME GESTURE
// Detects downward pull from the top of any inner screen and
// navigates back to the main Home page on release.
// ══════════════════════════════════════════════════════════════════
import { useRef, useEffect, useState } from 'react';
import { useNavigate, useLocation } from 'react-router-dom';

const THRESHOLD = 95; // px of pull needed to trigger navigation

export default function PullToRefresh() {
  const navigate   = useNavigate();
  const { pathname } = useLocation();
  const [pullY, setPullY]   = useState(0);
  const startYRef   = useRef(0);
  const activeRef   = useRef(false);
  const pullYRef    = useRef(0);

  // Only activate on inner pages — not home or admin
  const isHome = pathname === '/' || pathname.startsWith('/admin') || pathname.startsWith('/ghulam-admin');

  useEffect(() => {
    if (isHome) { setPullY(0); activeRef.current = false; return; }

    /** Walk up DOM to find nearest scrolled ancestor */
    const getScrollTop = (el: HTMLElement | null): number => {
      let e = el;
      while (e && e !== document.body) {
        if (e.scrollTop > 2) return e.scrollTop;
        e = e.parentElement;
      }
      return 0;
    };

    const onStart = (e: TouchEvent) => {
      if (getScrollTop(e.target as HTMLElement) > 2) {
        activeRef.current = false;
        return;
      }
      startYRef.current = e.touches[0].clientY;
      activeRef.current = true;
    };

    const onMove = (e: TouchEvent) => {
      if (!activeRef.current) return;
      const dy = e.touches[0].clientY - startYRef.current;
      if (dy <= 0) {
        activeRef.current = false;
        pullYRef.current = 0;
        setPullY(0);
        return;
      }
      const v = Math.min(dy * 0.52, 130);
      pullYRef.current = v;
      setPullY(v);
    };

    const onEnd = (e: TouchEvent) => {
      if (!activeRef.current) return;
      activeRef.current = false;
      const dy  = e.changedTouches[0].clientY - startYRef.current;
      const dist = pullYRef.current;
      pullYRef.current = 0;
      setPullY(0);
      if (dy >= THRESHOLD * 1.8 || dist >= THRESHOLD) navigate('/');
    };

    document.addEventListener('touchstart', onStart, { passive: true });
    document.addEventListener('touchmove',  onMove,  { passive: true });
    document.addEventListener('touchend',   onEnd,   { passive: true });

    return () => {
      document.removeEventListener('touchstart', onStart);
      document.removeEventListener('touchmove',  onMove);
      document.removeEventListener('touchend',   onEnd);
    };
  }, [isHome, navigate]);

  if (isHome || pullY < 8) return null;

  const ready = pullY >= THRESHOLD;

  return (
    <div
      className="fixed top-0 left-0 right-0 z-[60] flex justify-center items-end pointer-events-none"
      style={{ height: `${Math.min(pullY + 20, 145)}px` }}
    >
      <div className={`mb-2 flex items-center gap-2 px-5 py-2 rounded-full text-xs font-bold shadow-2xl border transition-all duration-100 ${
        ready
          ? 'bg-primary text-primary-foreground border-primary scale-110'
          : 'bg-card/95 text-muted-foreground border-border'
      }`}>
        <span className={ready ? 'text-base' : 'animate-bounce inline-block'}>
          {ready ? '🏠' : '↓'}
        </span>
        <span>{ready ? 'Release — Go Home' : 'Pull down to go home'}</span>
      </div>
    </div>
  );
}

src/components/SkyBackground.tsx.content:
// ══════════════════════════════════════════════════════════════════
// CINEMATIC SKY VIEWPORT BACKGROUND
// Full-viewport animated sky synced to GPS solar position & weather
// Sun orbit, floating clouds, rain/fog overlays
// ══════════════════════════════════════════════════════════════════

import { useState, useEffect, memo, type CSSProperties } from 'react';
import { useAppData } from '@/contexts/AppDataContext';

type TOD = 'dawn' | 'day' | 'evening' | 'night';

function getTOD(h: number): TOD {
  if (h >= 5 && h < 7) return 'dawn';
  if (h >= 7 && h < 17) return 'day';
  if (h >= 17 && h < 20) return 'evening';
  return 'night';
}

function getSkyGradient(tod: TOD, wmo: number | null): string {
  const isRain = wmo !== null && ((wmo >= 51 && wmo <= 67) || (wmo >= 80 && wmo <= 82));
  const isStorm = wmo !== null && wmo >= 95;
  const isSnow = wmo !== null && wmo >= 71 && wmo <= 86;
  const isFog = wmo !== null && (wmo >= 45 && wmo <= 48);
  const isOvercast = wmo !== null && wmo === 3;

  if (tod === 'night') {
    if (isRain || isStorm) return 'linear-gradient(180deg, #020617 0%, #0c1222 30%, #0f172a 60%, #020617 100%)';
    return 'linear-gradient(180deg, #020617 0%, #0a0f1f 25%, #111827 55%, #0a0f1f 80%, #020617 100%)';
  }
  if (tod === 'dawn') {
    return 'linear-gradient(180deg, #1e1b4b 0%, #312e81 15%, #4338ca 30%, #f97316 55%, #fbbf24 70%, #fef3c7 90%, #fffbeb 100%)';
  }
  if (tod === 'evening') {
    if (isRain) return 'linear-gradient(180deg, #1e1b4b 0%, #312e81 20%, #581c87 40%, #92400e 60%, #451a03 80%, #0c0a09 100%)';
    return 'linear-gradient(180deg, #1e1b4b 0%, #4c1d95 15%, #7c3aed 25%, #ea580c 40%, #f97316 55%, #fbbf24 70%, #92400e 85%, #1c1917 100%)';
  }
  // Day
  if (isStorm) return 'linear-gradient(180deg, #111827 0%, #1f2937 20%, #374151 40%, #1f2937 60%, #111827 80%, #0a0f1a 100%)';
  if (isRain) return 'linear-gradient(180deg, #1e3a5f 0%, #1e40af 25%, #3b82f6 45%, #60a5fa 60%, #1e40af 80%, #1e3a5f 100%)';
  if (isSnow) return 'linear-gradient(180deg, #e2e8f0 0%, #cbd5e1 25%, #94a3b8 45%, #cbd5e1 70%, #e2e8f0 100%)';
  if (isFog) return 'linear-gradient(180deg, #94a3b8 0%, #9ca3af 30%, #6b7280 60%, #9ca3af 85%, #94a3b8 100%)';
  if (isOvercast) return 'linear-gradient(180deg, #475569 0%, #64748b 25%, #94a3b8 50%, #64748b 75%, #475569 100%)';
  return 'linear-gradient(180deg, #0c4a6e 0%, #0369a1 15%, #0284c7 30%, #0ea5e9 45%, #38bdf8 60%, #0284c7 80%, #0c4a6e 100%)';
}

// Pre-computed cloud shapes
const CLOUDS = [
  { w: 120, h: 32, top: '8%', speed: 45, delay: 0, opacity: 0.12 },
  { w: 90, h: 24, top: '15%', speed: 55, delay: 8, opacity: 0.10 },
  { w: 140, h: 36, top: '22%', speed: 65, delay: 15, opacity: 0.08 },
  { w: 70, h: 20, top: '12%', speed: 50, delay: 22, opacity: 0.14 },
  { w: 100, h: 28, top: '30%', speed: 70, delay: 30, opacity: 0.09 },
];

const RAIN_DROPS = Array.from({ length: 40 }, (_, i) => ({
  left: `${(i * 2.5 + Math.random() * 2) % 100}%`,
  delay: `${(i * 0.12) % 2}s`,
  dur: `${0.4 + Math.random() * 0.3}s`,
}));

const STARS = Array.from({ length: 40 }, (_, i) => ({
  left: `${(i * 23 + 7) % 100}%`,
  top: `${(i * 17 + 3) % 80}%`,
  size: i % 5 === 0 ? 2.5 : i % 3 === 0 ? 2 : 1.5,
  delay: `${(i * 0.6) % 3}s`,
  dur: `${1.5 + (i * 0.4) % 2}s`,
}));

const SkyBackground = memo(function SkyBackground() {
  const { weatherApiKey } = useAppData();
  const [hour, setHour] = useState(() => new Date().getHours());
  const [minute, setMinute] = useState(() => new Date().getMinutes());
  const [wmo, setWmo] = useState<number | null>(null);
  const [cloudCover, setCloudCover] = useState<number>(0);

  useEffect(() => {
    const tick = () => {
      const n = new Date();
      setHour(n.getHours());
      setMinute(n.getMinutes());
    };
    tick();
    const id = setInterval(tick, 30000);
    return () => clearInterval(id);
  }, []);

  // Fetch weather once
  useEffect(() => {
    let alive = true;
    (async () => {
      try {
        const pos = await new Promise<GeolocationPosition>((ok, fail) =>
          navigator.geolocation.getCurrentPosition(ok, fail, { timeout: 4000, maximumAge: 300000 })
        ).catch(() => null);
        const lat = pos?.coords.latitude ?? 30;
        const lon = pos?.coords.longitude ?? 71;
        const res = await fetch(
          `https://api.open-meteo.com/v1/forecast?latitude=${lat}&longitude=${lon}&current=weather_code,cloud_cover&forecast_days=1`,
          { signal: AbortSignal.timeout(5000) }
        );
        const d = await res.json();
        if (alive) {
          setWmo(d.current?.weather_code ?? null);
          setCloudCover(d.current?.cloud_cover ?? 0);
        }
      } catch { /* silent */ }
    })();
    return () => { alive = false; };
  }, []);

  const tod = getTOD(hour);
  const hourFrac = hour + minute / 60;
  const gradient = getSkyGradient(tod, wmo);
  const showClouds = cloudCover > 20 || (wmo !== null && wmo >= 2 && wmo <= 48);
  const showRain = wmo !== null && ((wmo >= 51 && wmo <= 67) || (wmo >= 80 && wmo <= 99));
  const showStars = tod === 'night' && (wmo === null || wmo < 45);
  const showFog = wmo !== null && (wmo >= 45 && wmo <= 48);

  // Sun position
  const isSunTime = tod === 'dawn' || tod === 'day' || tod === 'evening';
  const sunX = isSunTime ? Math.max(5, Math.min(95, ((hourFrac - 5) / 15) * 100)) : 50;
  const t = sunX / 100;
  const sunY = 15 + 50 * (1 - 4 * (t - 0.5) ** 2);

  return (
    <div
      className="fixed inset-0 pointer-events-none"
      style={{
        zIndex: -1,
        background: gradient,
        transition: 'background 10s ease',
        overflow: 'hidden',
      }}
      aria-hidden="true"
    >
      {/* Sun */}
      {isSunTime && (
        <div
          style={{
            position: 'absolute',
            left: `${sunX}%`,
            top: `${sunY}%`,
            width: tod === 'evening' ? 50 : 40,
            height: tod === 'evening' ? 50 : 40,
            marginLeft: -20,
            marginTop: -20,
            borderRadius: '50%',
            background: tod === 'evening'
              ? 'radial-gradient(circle, #fbbf24 0%, #f97316 40%, #ea580c 70%, transparent 85%)'
              : tod === 'dawn'
              ? 'radial-gradient(circle, #fef3c7 0%, #fbbf24 40%, #f97316 70%, transparent 85%)'
              : 'radial-gradient(circle, #fef9c3 0%, #fde047 30%, #facc15 55%, #eab308 70%, transparent 85%)',
            boxShadow: tod === 'evening'
              ? '0 0 60px 20px rgba(251,146,60,0.25), 0 0 120px 40px rgba(234,88,12,0.12)'
              : '0 0 50px 15px rgba(250,204,21,0.2), 0 0 100px 30px rgba(234,179,8,0.08)',
            animation: 'sky-sun-pulse 5s ease-in-out infinite',
            opacity: cloudCover > 70 ? 0.25 : cloudCover > 40 ? 0.5 : 0.8,
            transition: 'left 120s linear, top 120s linear, opacity 8s ease',
          }}
        />
      )}

      {/* Moon */}
      {tod === 'night' && (
        <div
          style={{
            position: 'absolute',
            left: `${30 + ((hourFrac - 18 + 24) % 24) / 12 * 40}%`,
            top: '12%',
            width: 28,
            height: 28,
            borderRadius: '50%',
            background: 'radial-gradient(circle at 35% 35%, #e0e7ff 0%, #a5b4fc 50%, #6366f1 100%)',
            boxShadow: '0 0 20px 8px rgba(165,180,252,0.25), 0 0 40px 16px rgba(99,102,241,0.1)',
            opacity: 0.9,
          }}
        />
      )}

      {/* Stars */}
      {showStars && STARS.map((s, i) => (
        <div
          key={`star-${i}`}
          style={{
            position: 'absolute',
            left: s.left,
            top: s.top,
            width: s.size,
            height: s.size,
            background: '#c7d2fe',
            borderRadius: '50%',
            animation: `sky-twinkle ${s.dur} ${s.delay} ease-in-out infinite`,
          }}
        />
      ))}

      {/* Floating Clouds */}
      {(showClouds || tod === 'day') && CLOUDS.map((c, i) => (
        <div
          key={`cloud-${i}`}
          style={{
            position: 'absolute',
            top: c.top,
            width: c.w,
            height: c.h,
            background: tod === 'night' ? `rgba(100,116,139,${c.opacity})` : `rgba(255,255,255,${c.opacity + (showClouds ? 0.06 : 0)})`,
            borderRadius: '50%',
            filter: 'blur(3px)',
            animation: `sky-cloud-drift ${c.speed}s ${c.delay}s linear infinite`,
          }}
        />
      ))}

      {/* Rain */}
      {showRain && RAIN_DROPS.map((r, i) => (
        <div
          key={`rain-${i}`}
          style={{
            position: 'absolute',
            left: r.left,
            top: 0,
            width: 1,
            height: 14,
            background: 'rgba(147,197,253,0.45)',
            animation: `sky-rain-fall ${r.dur} ${r.delay} linear infinite`,
          }}
        />
      ))}

      {/* Fog overlay */}
      {showFog && (
        <div style={{
          position: 'absolute',
          inset: 0,
          background: 'rgba(148,163,184,0.35)',
          backdropFilter: 'blur(2px)',
          animation: 'sky-fog-pulse 8s ease-in-out infinite',
        }} />
      )}
    </div>
  );
});

export default SkyBackground;

