import { useState } from 'react';
import { Dialog, DialogContent, DialogHeader, DialogTitle } from '@/components/ui/dialog';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Textarea } from '@/components/ui/textarea';
import { Label } from '@/components/ui/label';
import { toast } from 'sonner';
import { submitSupportTicket } from 'zite-endpoints-sdk';
import { HelpCircle, MessageSquare, CheckCircle, Loader2, Shield } from 'lucide-react';

interface Props {
  open: boolean;
  onClose: () => void;
  userEmail?: string;
}

const QUICK_TOPICS = [
  '💰 Withdrawal not processed',
  '👑 VIP not activated after payment',
  '🔗 Referral commission missing',
  '💳 Deposit / payment issue',
  '🤖 AI not responding',
  '🔐 Account access issue',
];

export default function HelpCenterModal({ open, onClose, userEmail }: Props) {
  const [title, setTitle] = useState('');
  const [message, setMessage] = useState('');
  const [loading, setLoading] = useState(false);
  const [submitted, setSubmitted] = useState(false);
  const [ticketId, setTicketId] = useState('');

  const handleSubmit = async () => {
    if (!title.trim() || !message.trim()) {
      toast.error('Please fill in all fields');
      return;
    }
    if (message.trim().length < 10) {
      toast.error('Message must be at least 10 characters');
      return;
    }
    setLoading(true);
    try {
      const res = await submitSupportTicket({ title: title.trim(), message: message.trim() });
      setTicketId(res.id.slice(0, 8).toUpperCase());
      setSubmitted(true);
      toast.success('✅ Support ticket submitted!');
    } catch (e: any) {
      toast.error(e?.message ?? 'Failed to submit ticket. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  const handleClose = () => {
    setTitle('');
    setMessage('');
    setSubmitted(false);
    setTicketId('');
    onClose();
  };

  return (
    <Dialog open={open} onOpenChange={handleClose}>
      <DialogContent className="bg-card border-border max-w-sm mx-4 rounded-2xl">
        <DialogHeader>
          <DialogTitle className="flex items-center gap-2">
            <div className="bg-primary/20 rounded-xl p-1.5">
              <HelpCircle size={18} className="text-primary" />
            </div>
            Help Center
          </DialogTitle>
        </DialogHeader>

        {submitted ? (
          <div className="text-center py-6 space-y-4">
            <div className="bg-green-500/10 rounded-full w-16 h-16 flex items-center justify-center mx-auto">
              <CheckCircle size={32} className="text-green-400" />
            </div>
            <div>
              <p className="font-bold text-lg">Ticket Submitted!</p>
              <p className="text-sm text-muted-foreground mt-1">
                Our admin team will review your request and reply soon.
              </p>
            </div>
            <div className="bg-muted/50 rounded-xl px-4 py-3 border border-border">
              <p className="text-[10px] text-muted-foreground">Ticket Reference</p>
              <p className="font-mono text-primary font-bold text-lg">#{ticketId}</p>
            </div>
            <div className="bg-primary/5 border border-primary/15 rounded-xl px-3 py-2.5 text-xs text-muted-foreground">
              <Shield size={11} className="inline mr-1 text-primary" />
              Admin reviews all tickets within 24 hours
            </div>
            <Button onClick={handleClose} className="w-full bg-primary text-primary-foreground font-bold">
              Done
            </Button>
          </div>
        ) : (
          <div className="space-y-4">
            {userEmail && (
              <div className="bg-muted/50 rounded-xl px-3 py-2 text-xs text-muted-foreground border border-border">
                📧 Submitting as: <span className="text-foreground font-medium">{userEmail}</span>
              </div>
            )}

            {/* Quick topics */}
            <div className="space-y-1.5">
              <Label className="text-xs text-muted-foreground">Quick Topic (tap or type below)</Label>
              <div className="grid grid-cols-2 gap-1.5">
                {QUICK_TOPICS.map(topic => (
                  <button
                    key={topic}
                    onClick={() => setTitle(topic)}
                    className={`text-left text-[10px] px-2.5 py-2 rounded-lg border transition-colors leading-tight ${
                      title === topic
                        ? 'bg-primary/20 text-primary border-primary/40'
                        : 'bg-muted/40 border-border text-muted-foreground hover:border-primary/30 hover:text-foreground'
                    }`}
                  >
                    {topic}
                  </button>
                ))}
              </div>
            </div>

            <div className="space-y-1.5">
              <Label className="text-xs text-muted-foreground">Subject / Issue Title *</Label>
              <Input
                placeholder="Describe your issue briefly..."
                value={title}
                onChange={e => setTitle(e.target.value)}
                className="bg-muted border-border text-sm h-9"
                maxLength={200}
              />
            </div>

            <div className="space-y-1.5">
              <Label className="text-xs text-muted-foreground flex items-center justify-between">
                <span>Full Message / Details *</span>
                <span className="text-[10px] text-muted-foreground/60">{message.length}/3000</span>
              </Label>
              <Textarea
                placeholder="Explain your issue in detail. Include any relevant IDs, amounts, dates, or screenshots..."
                value={message}
                onChange={e => setMessage(e.target.value)}
                className="bg-muted border-border text-sm resize-none"
                rows={5}
                maxLength={3000}
