            >
              {loading
                ? <><Loader2 size={15} className="animate-spin" /> Submitting...</>
                : <><MessageSquare size={15} /> Submit Support Ticket</>}
            </Button>

            <p className="text-[10px] text-muted-foreground text-center">
              🔒 Your ticket is private and only visible to admins
            </p>
          </div>
        )}
      </DialogContent>
    </Dialog>
  );
}

