// ══════════════════════════════════════════════════════════════════
// LIVE STATUS STRIP — Ultra-thin seamless context bar
// Shows: Live clock (every second) + Auto-detected location + Weather
// No API key needed — uses ipapi.co + Open-Meteo (both free/open)
// ══════════════════════════════════════════════════════════════════
import { useState, useEffect } from 'react';
import { MapPin, Clock } from 'lucide-react';
import { useAppData } from '@/contexts/AppDataContext';

// Open-Meteo WMO weather code → readable label
const WMO: Record<number, string> = {
  0: 'Sunny ☀️', 1: 'Clear 🌤️', 2: 'Partly Cloudy ⛅', 3: 'Overcast ☁️',
  45: 'Foggy 🌫️', 48: 'Icy Fog 🌫️',
  51: 'Light Drizzle 🌦️', 53: 'Drizzle 🌦️', 55: 'Dense Drizzle 🌧️',
  61: 'Light Rain 🌧️', 63: 'Rain 🌧️', 65: 'Heavy Rain 🌧️',
  71: 'Light Snow ❄️', 73: 'Snow ❄️', 75: 'Heavy Snow ❄️',
  77: 'Snow Grains 🌨️',
  80: 'Showers 🌦️', 81: 'Showers 🌦️', 82: 'Violent Showers ⛈️',
  85: 'Snow Showers 🌨️', 86: 'Heavy Snow Showers 🌨️',
  95: 'Thunderstorm ⛈️', 96: 'Hail ⛈️', 99: 'Heavy Hail 🌩️',
};

function getConditionLabel(code: number): string {
  return WMO[code] ?? 'Weather';
}

interface StatusData {
  city: string;
  region: string;
  temp: number | null;
  conditionCode: number | null;
}

// Cache in module scope — survives component re-mounts within the session
let _cachedStatus: StatusData | null = null;
let _fetchPromise: Promise<StatusData> | null = null;

async function fetchStatusData(): Promise<StatusData> {
  if (_cachedStatus) return _cachedStatus;
  if (_fetchPromise) return _fetchPromise;

  _fetchPromise = (async () => {
    try {
      // 1. IP-based location (city, lat, lon) — no key needed
      const ip = await fetch('https://ipapi.co/json/', { signal: AbortSignal.timeout(4000) });
      const loc = await ip.json();
      const city: string = loc.city || 'Your City';
      const region: string = loc.region || '';
      const lat: number = parseFloat(loc.latitude) || 30.0;
      const lon: number = parseFloat(loc.longitude) || 71.0;

      // 2. Current weather via Open-Meteo — free, no API key
      const wx = await fetch(
        `https://api.open-meteo.com/v1/forecast?latitude=${lat}&longitude=${lon}&current_weather=true&temperature_unit=celsius`,
        { signal: AbortSignal.timeout(4000) }
      );
      const wxData = await wx.json();
      const cw = wxData.current_weather;
      const temp: number = Math.round(cw?.temperature ?? 0);
      const conditionCode: number = cw?.weathercode ?? 0;

      _cachedStatus = { city, region, temp, conditionCode };
      return _cachedStatus;
    } catch {
      // Fallback: just show city if possible
      try {
        const ip = await fetch('https://ipapi.co/json/', { signal: AbortSignal.timeout(3000) });
        const loc = await ip.json();
        _cachedStatus = { city: loc.city || 'Pakistan', region: loc.region || '', temp: null, conditionCode: null };
      } catch {
        _cachedStatus = { city: 'Detecting...', region: '', temp: null, conditionCode: null };
      }
      return _cachedStatus!;
    }
  })();

  return _fetchPromise;
}

export default function LiveStatusStrip() {
  const [now, setNow] = useState(() => new Date());
  const [status, setStatus] = useState<StatusData | null>(_cachedStatus);
  const [loading, setLoading] = useState(!_cachedStatus);
  const { weatherApiKey } = useAppData();
  const [microLocation, setMicroLocation] = useState('');

  // ── Live clock: tick every second ────────────────────────────────
  useEffect(() => {
    const id = setInterval(() => setNow(new Date()), 1000);
    return () => clearInterval(id);
  }, []);

  // ── Fetch location + weather once; refresh every 10 min ──────────
  useEffect(() => {
    let alive = true;

    const load = async () => {
      setLoading(true);
      try {
        const data = await fetchStatusData();
        if (alive) { setStatus(data); setLoading(false); }
      } catch {
        if (alive) setLoading(false);
      }
    };

    load();
    const interval = setInterval(() => {
      // Bust cache and re-fetch every 10 minutes
      _cachedStatus = null;
      _fetchPromise = null;
      load();
    }, 10 * 60 * 1000);

    return () => { alive = false; clearInterval(interval); };
  }, []);

  // ── Micro-location via Google Geocoding (ward, street, boundary) ──
  useEffect(() => {
    if (!weatherApiKey) return;
    let alive = true;
    const fetchMicro = () => {
      navigator.geolocation.getCurrentPosition(async (pos) => {
        try {
          const res = await fetch(
            `https://maps.googleapis.com/maps/api/geocode/json?latlng=${pos.coords.latitude},${pos.coords.longitude}&key=${weatherApiKey}&result_type=street_address|sublocality|neighborhood`,
            { signal: AbortSignal.timeout(5000) }
          );
          const data = await res.json();
          if (!alive || !data.results?.[0]) return;
          const comps = data.results[0].address_components || [];
          const parts: string[] = [];
          const neighborhood = comps.find((c: any) => c.types.includes('neighborhood'))?.long_name;
          const sublocality = comps.find((c: any) => c.types.includes('sublocality'))?.long_name;
          const route = comps.find((c: any) => c.types.includes('route'))?.long_name;
          if (neighborhood) parts.push(neighborhood);
          else if (sublocality) parts.push(sublocality);
          if (route && route !== neighborhood) parts.push(route);
          if (parts.length > 0) setMicroLocation(parts.join(', '));
        } catch { /* silent */ }
      }, () => {}, { timeout: 5000, maximumAge: 60000, enableHighAccuracy: true });
    };
    fetchMicro();
    const id = setInterval(fetchMicro, 60000); // Update every minute for "on change" tracking
    return () => { alive = false; clearInterval(id); };
  }, [weatherApiKey]);

  // Format clock: "11:08:42 AM"
  const timeStr = now.toLocaleTimeString('en-PK', {
    hour: '2-digit', minute: '2-digit', second: '2-digit',
    hour12: true, timeZone: Intl.DateTimeFormat().resolvedOptions().timeZone,
  });

  const hasWeather = status && status.temp !== null && status.conditionCode !== null;

  return (
    <div
      className="shrink-0 bg-muted/30 border-b border-border/40 flex items-center justify-between px-3"
      style={{ height: '26px' }}
    >
      {/* LEFT — Live digital clock */}
      <div className="flex items-center gap-1.5">
        <Clock size={9} className="text-primary shrink-0" />
        <span className="text-[10px] font-mono font-bold text-primary tracking-tight">
          {timeStr}
        </span>
      </div>

      {/* RIGHT — Location + weather */}
      <div className="flex items-center gap-1 text-[9px] font-mono min-w-0">
        <MapPin size={8} className="text-primary/70 shrink-0" />
        {loading ? (
          <span className="text-muted-foreground/50 animate-pulse">Locating...</span>
        ) : hasWeather ? (
          <span className="text-muted-foreground truncate">
            <span className="text-foreground font-semibold">
              {microLocation || status!.city}
              {!microLocation && status!.region && status!.region !== status!.city ? `, ${status!.region.slice(0, 12)}` : ''}
            </span>
            {' · '}
            <span className="text-primary font-bold">{status!.temp}°C</span>
            {' '}
            <span className="text-muted-foreground">{getConditionLabel(status!.conditionCode!)}</span>
          </span>
        ) : (
          <span className="text-foreground font-semibold">
            {microLocation || status?.city || '—'}
          </span>
        )}
      </div>
    </div>
  );
}

