    userBubble: 'bg-emerald-800/60 text-emerald-100 border border-emerald-700/40', aiBubble: 'bg-card border-emerald-900/30',
    dotColor: 'bg-emerald-400', defaultLang: 'ur-PK',
    placeholder: 'دینی سوال پوچھیں — اردو، عربی، یا انگریزی میں',
    suggestions: ['کالے جادو کا علاج', 'سورۃ البقرہ فضیلت', 'اللہ کے ننانوے (99) نام', 'استخارہ طریقہ'],
    markdown: false, rtl: true,
    lockMicLang: false,
  },
};

// ── Get current time string for task/spiritual context ────────────
function getLiveTime(locale: string, tz: string): string {
  return new Date().toLocaleString(locale, {
    weekday: 'long', year: 'numeric', month: 'long', day: 'numeric',
    hour: '2-digit', minute: '2-digit', hour12: true, timeZone: tz,
  });
}

// ══════════════════════════════════════════════════════════════════
// CHAT HISTORY
// ══════════════════════════════════════════════════════════════════
interface HistorySession {
  id: number; engine: EngineType; messages: ChatMsg[]; savedAt: string; preview: string;
}

function loadActiveMsgs(engine: EngineType): ChatMsg[] {
  try { const raw = sessionStorage.getItem(`chat_msgs_${engine}`); return raw ? JSON.parse(raw) : []; } catch { return []; }
}
function saveActiveMsgs(engine: EngineType, msgs: ChatMsg[]): void {
  try { sessionStorage.setItem(`chat_msgs_${engine}`, JSON.stringify(msgs.slice(-120))); } catch {}
}
function getHistorySessions(): HistorySession[] {
  try { return JSON.parse(localStorage.getItem('chat_history') || '[]'); } catch { return []; }
}
function pushToHistory(session: Omit<HistorySession, 'id'>): void {
  try {
    const existing = getHistorySessions();
    localStorage.setItem('chat_history', JSON.stringify(
      [{ ...session, id: Date.now() }, ...existing].slice(0, 20)
    ));
  } catch {}
}

function stripProseMarkdown(text: string): string {
  const parts = text.split(/(```[\s\S]*?```|`[^`\n]+`)/);
  return parts.map((part, i) => {
    if (i % 2 === 1) return part;
    return part
      .replace(/\*{1,3}([^*\n]+)\*{1,3}/g, '$1')
      .replace(/\*+/g, '')
      .replace(/^#{1,6}\s+([^\n]+)/gm, '$1')
      .replace(/~~([^~]+)~~/g, '$1')
      .replace(/\[([^\]]+)\]\([^)]+\)/g, '$1');
  }).join('');
}

// ── Live App Preview ──────────────────────────────────────────────
function LivePreviewButton({ content }: { content: string }) {
  const [open, setOpen] = useState(false);
  const htmlMatch = content.match(/```(?:html|HTML)\n([\s\S]*?)\n```/);
  const html = htmlMatch?.[1]?.trim() ?? '';
  const isFullApp = html.toLowerCase().includes('<html') || html.toLowerCase().includes('<!doctype');
  if (!isFullApp) return null;
  return (
    <>
      <button onClick={() => setOpen(true)}
        className="flex items-center gap-1 text-[9px] text-secondary border border-secondary/30 bg-secondary/10 px-2 py-0.5 rounded-md hover:bg-secondary/20 transition-colors">
        Preview
      </button>
      {open && (
        <div className="fixed inset-0 z-50 bg-black/90 flex flex-col">
          <div className="flex items-center justify-between px-4 py-2.5 bg-card border-b border-border shrink-0">
            <span className="text-xs font-bold">🔴 Live Preview</span>
            <button onClick={() => setOpen(false)} className="text-muted-foreground hover:text-foreground p-1"><X size={16} /></button>
          </div>
          <iframe srcDoc={html} sandbox="allow-scripts allow-forms" className="flex-1 w-full bg-white" title="Live App Preview" />
        </div>
      )}
    </>
  );
}

// ── History Panel ──────────────────────────────────────────────
function HistoryPanel({ currentEngine, onRestore, onClose }: {
  currentEngine: EngineType; onRestore: (msgs: ChatMsg[]) => void; onClose: () => void;
}) {
  const [sessions, setSessions] = useState<HistorySession[]>(() => getHistorySessions());
  const deleteSession = (id: number) => {
    const updated = sessions.filter(s => s.id !== id);
    localStorage.setItem('chat_history', JSON.stringify(updated));
    setSessions(updated);
  };
  const EMOJI: Record<EngineType, string> = { coding: '🧠', tasks: '📅', spiritual: '🌙' };
  return (
    <div className="fixed inset-0 z-40 flex">
      <div className="flex-1 bg-black/50" onClick={onClose} />
      <div className="w-72 max-w-[85vw] bg-card border-l border-border flex flex-col h-full">
        <div className="flex items-center justify-between px-4 py-3 border-b border-border shrink-0">
          <div className="flex items-center gap-2"><History size={14} className="text-primary" /><span className="font-bold text-sm">Chat History</span></div>
          <button onClick={onClose} className="text-muted-foreground hover:text-foreground p-1"><X size={16} /></button>
        </div>
        <div className="flex-1 overflow-y-auto overscroll-contain">
          {sessions.length === 0 ? (
            <div className="flex flex-col items-center justify-center h-full text-center p-6 text-muted-foreground">
              <History size={32} className="mb-3 opacity-30" />
              <p className="text-sm">No saved sessions yet</p>
            </div>
          ) : (
            <div className="p-2 space-y-1.5">
              {sessions.map(s => (
                <div key={s.id}
                  className={cn('rounded-xl border p-3 cursor-pointer transition-colors group',
                    s.engine === currentEngine ? 'border-primary/30 bg-primary/5' : 'border-border bg-muted/30'
                  )}
                  onClick={() => { onRestore(s.messages); onClose(); }}
                >
                  <div className="flex items-start justify-between gap-2">
                    <div className="flex items-center gap-1.5 min-w-0">
                      <span className="text-sm shrink-0">{EMOJI[s.engine]}</span>
                      <p className="text-xs font-semibold truncate">{s.preview || 'Chat session'}</p>
                    </div>
                    <button onClick={e => { e.stopPropagation(); deleteSession(s.id); }}
                      className="text-muted-foreground/40 hover:text-destructive opacity-0 group-hover:opacity-100 shrink-0 p-0.5">
                      <Trash2 size={10} />
                    </button>
                  </div>
                  <div className="flex items-center gap-1.5 mt-1">
                    <Clock size={9} className="text-muted-foreground/60" />
                    <span className="text-[9px] text-muted-foreground/60">
                      {new Date(s.savedAt).toLocaleDateString('en-PK', { month: 'short', day: 'numeric', hour: '2-digit', minute: '2-digit' })}
                    </span>
                    <span className="text-[9px] text-muted-foreground/50 ml-auto">{s.messages.length} msgs</span>
                    <ChevronRight size={9} className="text-muted-foreground/40" />
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

// ── Mic Hook ──────────────────────────────────────────────────────
// ── Clean STT output: strip *, #, ~, stray symbols ──────────────
const cleanStt = (text: string): string =>
  text.replace(/[*#~_`^\\|<>{}[\]]/g, '').replace(/\s{2,}/g, ' ').trim();

function useMic(defaultLang: string) {
  const [listening, setListening] = useState(false);
  const [lang, setLang] = useState(defaultLang);
  const rRef = useRef<any>(null);

  const start = useCallback((onResult: (text: string) => void) => {
    const SR = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (!SR) { toast.error('Voice input not supported. Use Chrome browser.'); return; }
    if (listening) { rRef.current?.stop(); return; }
    const r = new SR();
    // language: "auto" — do NOT set r.lang so the browser auto-detects
    // the spoken language dynamically (Urdu, Punjabi, Saraiki, Sindhi, Hindi, English, etc.)
    r.continuous = true; r.interimResults = false; r.maxAlternatives = 1;
    r.onresult = (e: any) => {
      const raw = e.results[e.results.length - 1][0].transcript;
      const cleaned = cleanStt(raw);
      if (cleaned) onResult(cleaned);
    };
    r.onerror = (e: any) => {
      if (e.error !== 'aborted') {
        const msgs: Record<string, string> = {
          'no-speech': 'No speech detected. Speak clearly and try again.',
          'not-allowed': 'Mic blocked! Allow microphone access in browser settings.',
          'audio-capture': 'Microphone not found.',
          'network': 'Network error. Check connection.',
        };
        toast.error(msgs[e.error] ?? `Mic error: ${e.error}`);
      }
      setListening(false);
    };
    r.onend = () => setListening(false);
    rRef.current = r;
    try { r.start(); setListening(true); } catch { toast.error('Could not start microphone.'); }
  }, [listening]);

  const stop = useCallback(() => { rRef.current?.stop(); setListening(false); }, []);
  return { listening, lang, setLang, start, stop };
}

// ── Mobile-Optimized Copy Button ─────────────────────────────────
function CopyBtn({ text, className, mobile }: { text: string; className?: string; mobile?: boolean }) {
  const [copied, setCopied] = useState(false);
  const handleCopy = () => {
    navigator.clipboard.writeText(text).catch(() => {
      // Fallback for Android WebView
      const ta = document.createElement('textarea');
      ta.value = text; ta.style.position = 'fixed'; ta.style.opacity = '0';
      document.body.appendChild(ta); ta.focus(); ta.select();
      document.execCommand('copy'); document.body.removeChild(ta);
    });
    setCopied(true); setTimeout(() => setCopied(false), 2000);
    toast.success('📋 Copied!');
  };
  if (mobile) {
    return (
      <button onClick={handleCopy}
        className={cn(
          'flex items-center gap-2 text-xs font-bold rounded-xl border transition-all active:scale-95',
          'min-h-[40px] px-4 py-2',
          copied
            ? 'bg-primary/20 text-primary border-primary/40'
            : 'bg-muted/60 text-foreground border-border hover:bg-primary/10 hover:border-primary/30',
          className
        )}>
        {copied ? <Check size={14} className="text-primary" /> : <Copy size={14} />}
        {copied ? 'Copied!' : 'Copy Code'}
      </button>
    );
  }
  return (
    <button onClick={handleCopy}
      className={cn('p-1 rounded text-muted-foreground hover:text-foreground transition-colors', className)}>
      {copied ? <Check size={11} className="text-primary" /> : <Copy size={11} />}
    </button>
  );
}

// ─────────────────────────────────────────────────────────────────
// Main ChatEngine Component
// ─────────────────────────────────────────────────────────────────
interface ChatEngineProps { engine: EngineType; onCycleEngine?: () => void; }

// ── VIP Gate Banner (shown when restricted mode is on) ───────────
function VIPGateBanner({ onGoVIP }: { onGoVIP: () => void }) {
  return (
    <div className="mx-3 my-4 rounded-2xl border-2 border-primary/40 bg-gradient-to-br from-primary/10 to-secondary/5 p-5 text-center space-y-3">
      <div className="w-14 h-14 rounded-2xl bg-primary/15 border border-primary/30 flex items-center justify-center mx-auto">
        <Lock size={24} className="text-primary" />
      </div>
      <div>
        <p className="font-black text-base flex items-center justify-center gap-1.5">
          <Crown size={14} className="text-yellow-400" /> RESTRICTED MODE ACTIVE
        </p>
        <p className="text-xs text-muted-foreground mt-1">
          OMNISCIENT AI Coding Engine is currently in VIP-only mode. Upgrade to unlock unlimited access.
        </p>
      </div>
      <button
        onClick={onGoVIP}
        className="w-full bg-primary text-primary-foreground font-bold text-sm py-2.5 rounded-xl hover:bg-primary/90 transition-colors flex items-center justify-center gap-2"
      >
        <Crown size={14} /> Get VIP — Unlock Now
      </button>
      <p className="text-[10px] text-muted-foreground">Admin can disable this gate from the Admin Panel → Settings</p>
    </div>
  );
}

export default function ChatEngine({ engine, onCycleEngine }: ChatEngineProps) {
  const cfg = CONFIGS[engine];
  const Icon = engine === 'coding' ? Brain : engine === 'tasks' ? CalendarCheck : Moon;
  const navigate = useNavigate();
  const { codingRestricted, aiName } = useAppData();
  const { user } = useAuth();
  const isVIPGated = engine === 'coding' && codingRestricted && user?.vipStatus !== 'VIP';
  // Use admin-configured AI name for the coding engine; other engines keep their own identity
  const engineDisplayName = engine === 'coding' && aiName ? aiName.toUpperCase() : cfg.name;

  const [messages, setMessages] = useState<ChatMsg[]>(() => {
    const prev = loadActiveMsgs(engine);
    if (prev.length >= 2) {
      pushToHistory({ engine, messages: prev.slice(0, 60), savedAt: new Date().toISOString(),
        preview: prev.find(m => m.role === 'user')?.content.slice(0, 80) || 'Previous session' });
    }
    sessionStorage.removeItem(`chat_msgs_${engine}`);
    return [];
  });
  const [input, setInput]         = useState('');
  const [loading, setLoading]     = useState(false);
  const [muted, setMuted]         = useState(false);
  const [ttsActive, setTtsActive] = useState(false);
  const [showHistory, setShowHistory] = useState(false);
  const [showWrongPromptWarning, setShowWrongPromptWarning] = useState(false);
  const { listening, lang, setLang, start: startMic, stop: stopMic } = useMic(cfg.defaultLang);
  const bottomRef = useRef<HTMLDivElement>(null);

  useEffect(() => { saveActiveMsgs(engine, messages); }, [messages, engine]);
  useEffect(() => { bottomRef.current?.scrollIntoView({ behavior: 'smooth' }); }, [messages]);

  const prevEngineRef = useRef(engine);
  useEffect(() => {
    if (prevEngineRef.current !== engine) {
      prevEngineRef.current = engine;
      setMessages(loadActiveMsgs(engine));
    }
  }, [engine]);

  const send = useCallback(async (text?: string) => {
    const msg = (text ?? input).trim();
    if (!msg || loading) return;
    // VIP gate for coding engine when restricted mode is active
    if (engine === 'coding' && codingRestricted && user?.vipStatus !== 'VIP') {
      toast.error('🔒 VIP required — upgrade to access the Coding Engine in Restricted Mode');
      navigate('/vip');
      return;
    }
    setInput('');
    stopTTS(); setTtsActive(false);

    const userMsg: ChatMsg = { id: `u${Date.now()}`, role: 'user', content: msg };
    setMessages(prev => [...prev, userMsg]);
    setLoading(true);

    // ── Section 1 Rule: Tasks engine must redirect spiritual/religious queries ──
    if (engine === 'tasks' && isSpiritualQuery(msg)) {
      const aiMsg: ChatMsg = { id: `a${Date.now()}`, role: 'model', content: SPIRITUAL_REDIRECT_MSG };
      setMessages(prev => [...prev, aiMsg]);
      setLoading(false);
      if (!muted) {
        setTtsActive(true);
        speakText(SPIRITUAL_REDIRECT_MSG, 'ur-PK', () => setTtsActive(false));
      }
      return;
    }

    try {
      const history = messages.slice(-10).map(m => ({ role: m.role as 'user' | 'model', content: m.content }));
      let response = '';

      if (engine === 'coding') {
        const r = await generalChat({ message: msg, history });
        response = r.response;
      } else if (engine === 'tasks') {
        // Inject live clock for time-aware responses
        const currentTime = getLiveTime('ur-PK', Intl.DateTimeFormat().resolvedOptions().timeZone);
        const r = await dailyTasksChat({ message: msg, history, currentTime });
        response = r.response;
      } else {
        // Spiritual: inject time + clean Urdu location (no timezone codes)
        const currentTime = getLiveTime('ur-PK', Intl.DateTimeFormat().resolvedOptions().timeZone);
        const userLocation = getGlobalUrduLocation();
        const r = await spiritualChat({ message: msg, history, currentTime, userLocation });
        response = r.response;
      }

      const aiMsg: ChatMsg = { id: `a${Date.now()}`, role: 'model', content: response };
      setMessages(prev => [...prev, aiMsg]);

      if (!muted) {
        const ttsLang = detectLangFromText(response) ?? lang;
        setTtsActive(true);
        speakText(response, ttsLang, () => setTtsActive(false));
      }
    } catch (e: any) {
      toast.error(e?.message ?? 'AI error — please try again');
      // Report wrong prompt on API errors (safety blocks, invalid prompts)
      try {
        const result = await reportWrongPrompt({});
        if (result.warning) {
          setShowWrongPromptWarning(true);
        }
        // If blocked, the polling in App.tsx will catch it and show BlockedOverlay
      } catch { /* silent */ }
    } finally {
      setLoading(false);
    }
  }, [input, loading, messages, muted, lang, engine, codingRestricted, user, navigate]);

  const clearChat = useCallback(() => {
    if (messages.length >= 2) {
      pushToHistory({ engine, messages: messages.slice(0, 60), savedAt: new Date().toISOString(),
        preview: messages.find(m => m.role === 'user')?.content.slice(0, 80) || 'Chat session' });
    }
    setMessages([]); sessionStorage.removeItem(`chat_msgs_${engine}`);
    stopTTS(); setTtsActive(false);
  }, [messages, engine]);

  const restoreSession = useCallback((msgs: ChatMsg[]) => {
    setMessages(msgs); saveActiveMsgs(engine, msgs);
    toast.success('✅ Session restored!');
  }, [engine]);

  const handleMic = () => {
    if (listening) { stopMic(); return; }
    startMic(text => setInput(text));
  };

  // Language cycling — disabled for coding engine (locked to en-US)
  const LANG_OPTIONS = [
    { code: 'ur-PK', flag: '🇵🇰', label: 'UR' },
    { code: 'en-US', flag: '🇬🇧', label: 'EN' },
    { code: 'ar-SA', flag: '🇸🇦', label: 'AR' },
  ];
  const currentLang = LANG_OPTIONS.find(l => l.code === lang) ?? LANG_OPTIONS[1];
  const cycleLang = () => {
    if (cfg.lockMicLang) return; // coding engine: locked to en-US
    const idx = LANG_OPTIONS.findIndex(l => l.code === lang);
    setLang(LANG_OPTIONS[(idx + 1) % LANG_OPTIONS.length].code);
  };

  const showSuggestions = messages.length === 0 && !input && !listening;

  return (
    <div className="flex flex-col h-full">
      {/* ── Minimal top bar — engine label removed per user request ── */}
      <div className="flex items-center justify-end px-3 py-0.5 border-b border-border/20 shrink-0 min-h-[28px]">
        {isVIPGated && (
          <span className="mr-auto flex items-center gap-0.5 text-[9px] font-black text-destructive bg-destructive/15 border border-destructive/30 px-1.5 py-0.5 rounded-full">
            <Lock size={8} /> RESTRICTED
          </span>
        )}
        <button
          onClick={() => setShowHistory(true)}
          className="text-muted-foreground/40 hover:text-muted-foreground p-1 rounded-md transition-colors"
          title="Chat History"
        >
          <History size={12} />
        </button>
      </div>

      {/* ── VIP Gate ── */}
      {isVIPGated && <VIPGateBanner onGoVIP={() => navigate('/vip')} />}

      {/* ── Messages ── */}
      <div className="flex-1 overflow-y-auto px-3 py-4 space-y-3" dir={cfg.rtl ? 'rtl' : 'ltr'}>
        {showSuggestions && (
          <div className="flex flex-col items-center justify-center h-full text-center gap-4 pb-8" dir="ltr">
            <div className={cn('w-16 h-16 rounded-2xl border flex items-center justify-center', cfg.bg)}>
              <Icon size={28} className={cfg.color} />
            </div>
            <div>
              <p className="font-black text-lg">{cfg.emoji} {engineDisplayName}</p>
              <p className="text-xs text-muted-foreground mt-1">Tap a suggestion or type below</p>
            </div>
            <div className={cn('grid grid-cols-2 gap-2 w-full max-w-xs', cfg.rtl && 'text-right')}>
              {cfg.suggestions.map(s => (
                <button key={s} onClick={() => send(s)}
                  className={cn('text-xs bg-muted/50 border border-border rounded-xl px-3 py-2.5 hover:border-primary/30 transition-colors text-left leading-snug min-h-[44px]', cfg.rtl && 'text-right font-urdu')}>
                  {s}
                </button>
              ))}
            </div>
          </div>
        )}

        {messages.map(msg => {
          const isUser = msg.role === 'user';
          const project = (!isUser && engine === 'coding') ? parseProjectFiles(msg.content) : null;
          const proseAbove = project ? msg.content.split(/===\s*PROJECT:/)[0].trim() : null;
          const displayContent = engine === 'coding' && !isUser ? stripProseMarkdown(msg.content) : msg.content;

          return (
            <div key={msg.id} className={cn('flex gap-2 items-end', isUser ? 'flex-row-reverse' : 'flex-row')}>
              {!isUser && (
                <div className={cn('w-7 h-7 rounded-full border flex items-center justify-center shrink-0 mb-1', cfg.bg)}>
                  <Icon size={13} className={cfg.color} />
                </div>
              )}
              {project ? (
                <div className="flex-1 min-w-0 space-y-2">
                  {proseAbove && (
                    <div className={cn('rounded-2xl rounded-bl-sm border px-3.5 py-2.5', cfg.aiBubble)}>
                      <p className="text-sm whitespace-pre-wrap">{proseAbove}</p>
                    </div>
                  )}
                  <CodeProjectView project={project} msgId={msg.id} />
                </div>
              ) : (
                <div className={cn(
                  'max-w-[88%] rounded-2xl px-3.5 py-2.5',
                  isUser ? cn(cfg.userBubble, 'rounded-br-sm') : cn('border', cfg.aiBubble, 'rounded-bl-sm')
                )}>
                  {isUser ? (
                    <p className={cn('text-sm whitespace-pre-wrap', cfg.rtl && 'font-urdu leading-loose text-right')}>{msg.content}</p>
                  ) : cfg.markdown ? (
                    <div className="text-sm prose prose-invert prose-sm max-w-none leading-relaxed mobile-code-block">
                      <Markdown>{displayContent}</Markdown>
                    </div>
                  ) : (
                    <p className={cn('text-sm whitespace-pre-wrap leading-relaxed', cfg.rtl && 'font-urdu leading-loose text-right')} dir={cfg.rtl ? 'rtl' : undefined}>
                      {displayContent}
                    </p>
                  )}
                  {!isUser && (
                    <div className="flex items-center justify-between mt-2 flex-wrap gap-1.5">
                      {/* 🔊 TTS — every AI response gets a voice button */}
                      <MultiLingualTTSButton text={displayContent} size="sm" showLangSelector />
                      <div className="flex items-center gap-1.5">
                        {engine === 'coding' && <LivePreviewButton content={msg.content} />}
                        <CopyBtn text={displayContent} mobile />
                      </div>
                    </div>
                  )}
                </div>
              )}
            </div>
          );
        })}

        {loading && (
          <div className="flex items-end gap-2" dir="ltr">
            <div className={cn('w-7 h-7 rounded-full border flex items-center justify-center', cfg.bg)}>
              <Icon size={13} className={cfg.color} />
            </div>
            <div className={cn('border rounded-2xl rounded-bl-sm px-4 py-3', cfg.aiBubble)}>
              <div className="flex gap-1">
                {[0, 1, 2].map(i => (
                  <div key={i} className={cn('w-1.5 h-1.5 rounded-full animate-bounce', cfg.dotColor)}
                    style={{ animationDelay: `${i * 150}ms` }} />
                ))}
              </div>
            </div>
          </div>
        )}
        <div ref={bottomRef} />
      </div>

      {/* ── TTS active indicator ── */}
      {ttsActive && (
        <div className="mx-3 mb-1 flex items-center gap-2 bg-muted/50 border border-border rounded-xl px-3 py-1.5 shrink-0">
          <Volume2 size={12} className={cn(cfg.color, 'animate-pulse')} />
          <span className="text-xs text-muted-foreground flex-1">🔊 Speaking...</span>
          <button onClick={() => { stopTTS(); setTtsActive(false); }} className="text-[10px] text-destructive hover:underline">Stop</button>
        </div>
      )}

      {/* ════════════════════════════════════════════════════════════
          INPUT BAR
          ════════════════════════════════════════════════════════════ */}
      <div className={cn("px-3 py-2.5 border-t border-border bg-card/95 backdrop-blur shrink-0", isVIPGated && "opacity-50 pointer-events-none")}>
        <div className="flex gap-1.5 items-end bg-muted rounded-2xl px-2.5 py-2 border border-border focus-within:border-primary/40 transition-colors">
          {/* LEFT GROUP */}
          <div className="flex items-center gap-0.5 shrink-0 pb-0.5">
            <button onClick={handleMic} title={listening ? 'Stop listening' : 'Start voice input'}
              className={cn('p-1.5 rounded-xl transition-colors min-h-[40px] min-w-[40px] flex items-center justify-center',
                listening ? 'text-destructive bg-destructive/10 animate-pulse' : 'text-muted-foreground hover:text-foreground hover:bg-muted/80'
              )}>
              {listening ? <MicOff size={18} /> : <Mic size={18} />}
            </button>
            <button onClick={onCycleEngine} title={`Current: ${cfg.name} — tap to switch`}
              className={cn('p-1.5 rounded-xl transition-all hover:bg-muted/80 flex items-center gap-0.5 min-h-[40px]', cfg.color)}>
              <span className="text-base leading-none">{cfg.emoji}</span>
            </button>
            <button onClick={() => navigate('/media')} title="AI Media Lab"
              className="p-1.5 rounded-xl text-secondary hover:text-secondary/80 transition-colors hover:bg-secondary/10 min-h-[40px] min-w-[40px] flex items-center justify-center">
              <Image size={18} />
            </button>
          </div>

          {/* CENTER: textarea */}
          <textarea
            className={cn(
              'flex-1 bg-transparent resize-none text-sm outline-none placeholder:text-muted-foreground min-h-[20px] max-h-28 leading-5 py-1',
              cfg.rtl && 'text-right font-urdu'
            )}
            placeholder={listening
              ? `🎤 Listening (${cfg.lockMicLang ? '🇬🇧 EN' : `${currentLang.flag} ${currentLang.label}`})...`
              : cfg.placeholder}
            value={input}
            onChange={e => setInput(e.target.value)}
            onKeyDown={e => { if (e.key === 'Enter' && !e.shiftKey) { e.preventDefault(); send(); } }}
            rows={1}
            disabled={loading}
            dir={cfg.rtl ? 'rtl' : undefined}
          />

          {/* RIGHT: Send */}
          <button onClick={() => send()} disabled={!input.trim() || loading}
            className="p-1.5 rounded-xl bg-primary text-primary-foreground disabled:opacity-40 hover:bg-primary/90 transition-all shrink-0 self-end mb-0.5 min-h-[40px] min-w-[40px] flex items-center justify-center">
            {loading ? <Loader2 size={15} className="animate-spin" /> : <Send size={15} />}
          </button>
        </div>

        {/* ── Secondary controls ── */}
        <div className="flex items-center justify-between mt-1.5 px-1">
          <div className="flex items-center gap-2">
            {/* Language selector: hidden for coding engine (locked to en-US) */}
            {!cfg.lockMicLang && (
              <button onClick={cycleLang}
                className="flex items-center gap-1 text-[9px] text-muted-foreground/70 hover:text-muted-foreground transition-colors px-1.5 py-0.5 rounded-md hover:bg-muted/60">
                <span>{currentLang.flag}</span>
                <span className="font-semibold uppercase">{currentLang.label}</span>
              </button>
            )}
            {cfg.lockMicLang && (
              <span className="text-[9px] text-muted-foreground/50 px-1.5 py-0.5">🇬🇧 EN — Voice locked</span>
            )}
            <button
              onClick={() => { const next = !muted; setMuted(next); if (next) { stopTTS(); setTtsActive(false); } }}
              className={cn(
                'flex items-center gap-1 text-[9px] px-1.5 py-0.5 rounded-md transition-colors hover:bg-muted/60',
                !muted ? cfg.color : 'text-muted-foreground/50 hover:text-muted-foreground'
              )}>
              {muted ? <VolumeX size={9} /> : <Volume2 size={9} />}
              <span>{muted ? 'Muted' : 'Voice'}</span>
            </button>
            {listening && <span className="text-[9px] text-destructive animate-pulse font-medium">● Listening...</span>}
          </div>
          {messages.length > 0 && (
            <button onClick={clearChat} className="text-[9px] text-muted-foreground/50 hover:text-muted-foreground transition-colors">
              Clear chat
            </button>
          )}
        </div>
      </div>

      {showHistory && (
        <HistoryPanel currentEngine={engine} onRestore={restoreSession} onClose={() => setShowHistory(false)} />
      )}

      {/* Wrong Prompt Warning Modal — shown on 3rd consecutive wrong prompt */}
      {showWrongPromptWarning && (
        <WrongPromptWarning onClose={() => setShowWrongPromptWarning(false)} />
      )}
    </div>
  );
}

