import { ArrowLeft, Lock, CheckCircle2, Star } from 'lucide-react';

interface Level { levelNumber: number; levelTitle: string | null; minReferrals: number; commissionRate: number; bonusCoins: number; }
interface Props { levels: Level[]; currentLevel: number; totalReferrals: number; onBack: () => void; }

function getTier(n: number): string {
  if (n <= 10) return 'level-bronze';
  if (n <= 20) return 'level-silver';
  if (n <= 30) return 'level-gold';
  if (n <= 40) return 'level-platinum';
  return 'level-diamond';
}

// Generate default levels if none configured
function buildLevels(configured: Level[]): Level[] {
  if (configured.length > 0) return configured;
  return Array.from({ length: 50 }, (_, i) => ({
    levelNumber: i + 1,
    levelTitle: i < 10 ? 'Bronze' : i < 20 ? 'Silver' : i < 30 ? 'Gold' : i < 40 ? 'Platinum' : 'Diamond',
    minReferrals: i === 0 ? 0 : Math.ceil(Math.pow(i, 1.5)),
    commissionRate: 0.03 + i * 0.002,
    bonusCoins: (i + 1) * 100,
  }));
}

export default function LevelMap({ levels, currentLevel, totalReferrals, onBack }: Props) {
  const allLevels = buildLevels(levels);
  const current = allLevels.find(l => l.levelNumber === currentLevel);
  const next = allLevels.find(l => l.levelNumber === currentLevel + 1);

  return (
    <div className="fixed inset-0 z-50 bg-background flex flex-col">
      <div className="flex items-center gap-3 px-4 py-3 border-b border-border bg-card/95 backdrop-blur-md sticky top-0">
        <button onClick={onBack} className="p-1.5 rounded-xl hover:bg-muted"><ArrowLeft size={20} /></button>
        <div className="flex-1">
          <h2 className="font-bold text-lg">50-Level Map</h2>
          {next && <p className="text-xs text-muted-foreground">{next.minReferrals - totalReferrals} more referrals to Level {next.levelNumber}</p>}
        </div>
        <div className="text-right"><p className="text-sm font-bold text-primary">Level {currentLevel}</p><p className="text-xs text-muted-foreground">{(current?.commissionRate ?? 0) * 100}% commission</p></div>
      </div>
      <div className="flex-1 overflow-y-auto p-4">
        <div className="grid grid-cols-5 gap-2">
          {allLevels.map(level => {
            const unlocked = level.levelNumber <= currentLevel;
            const isCurrent = level.levelNumber === currentLevel;
            return (
              <div key={level.levelNumber}
                className={`relative rounded-xl p-2 text-center transition-all ${isCurrent ? 'ring-2 ring-primary ring-offset-1 ring-offset-background scale-105' : ''} ${unlocked ? getTier(level.levelNumber) : 'bg-muted/40 opacity-50'}`}>
                {isCurrent && <Star size={10} className="absolute -top-1 -right-1 text-primary fill-primary" />}
                <p className="text-xs font-bold text-white/90">{level.levelNumber}</p>
                {unlocked ? <CheckCircle2 size={10} className="mx-auto mt-0.5 text-white/70" /> : <Lock size={10} className="mx-auto mt-0.5 text-white/40" />}
                <p className="text-[9px] text-white/70 mt-0.5">{(level.commissionRate * 100).toFixed(1)}%</p>
              </div>
            );
          })}
        </div>
        {current && (
          <div className="mt-4 card-gold rounded-2xl p-4 text-center">
            <p className="text-lg font-bold gold-gradient">Level {currentLevel} — {current.levelTitle}</p>
            <p className="text-sm text-muted-foreground mt-1">Commission: <span className="text-primary font-bold">{(current.commissionRate * 100).toFixed(1)}%</span></p>
            <p className="text-xs text-muted-foreground">Bonus Coins: {current.bonusCoins?.toLocaleString()}</p>
          </div>
        )}
      </div>
    </div>
  );
}

