import { ArrowLeft, Search, Users, DollarSign, GitBranch } from 'lucide-react';
import { Input } from '@/components/ui/input';
import { useState } from 'react';

interface Referral {
  id: string;
  referredEmail: string;
  referredName: string | null;
  commissionUsd: number;
  commissionRate?: number;
  referrerLevel?: number;
  joinedAt: string | null;
}

interface Props { referrals: Referral[]; onBack: () => void; }

function maskEmail(email: string): string {
  const [user, domain] = email.split('@');
  return user.slice(0, 2) + '***@' + domain;
}

export default function TeamList({ referrals, onBack }: Props) {
  const [search, setSearch] = useState('');
  const filtered = referrals.filter(r => {
    const q = search.toLowerCase();
    return !q || (r.referredName?.toLowerCase().includes(q)) || r.referredEmail.toLowerCase().includes(q);
  });

  const totalCommission = referrals.reduce((s, r) => s + r.commissionUsd, 0);

  return (
    <div className="fixed inset-0 z-50 bg-background flex flex-col">
      {/* Header */}
      <div className="flex items-center gap-3 px-4 py-3 border-b border-border bg-card/95 backdrop-blur-md sticky top-0">
        <button onClick={onBack} className="p-1.5 rounded-xl hover:bg-muted"><ArrowLeft size={20} /></button>
        <h2 className="font-bold text-lg flex-1">My Referral Team</h2>
        <span className="text-xs bg-primary/20 text-primary px-2.5 py-1 rounded-full font-semibold">
          {referrals.length} Members
        </span>
      </div>

      {/* Summary bar */}
      {referrals.length > 0 && (
        <div className="grid grid-cols-2 gap-2 px-4 py-2 border-b border-border/50 bg-muted/20">
          <div className="flex items-center gap-1.5 text-xs">
            <Users size={12} className="text-primary" />
            <span className="text-muted-foreground">Total Invited:</span>
            <span className="text-primary font-bold">{referrals.length}</span>
          </div>
          <div className="flex items-center gap-1.5 text-xs">
            <DollarSign size={12} className="text-green-400" />
            <span className="text-muted-foreground">Commission:</span>
            <span className="text-green-400 font-bold">${totalCommission.toFixed(4)}</span>
          </div>
        </div>
      )}

      {/* Search */}
      <div className="px-4 py-3">
        <div className="relative">
          <Search size={14} className="absolute left-3 top-1/2 -translate-y-1/2 text-muted-foreground" />
          <Input
            placeholder="Search by name or email..."
            value={search}
            onChange={e => setSearch(e.target.value)}
            className="pl-8 bg-muted border-border text-sm"
          />
        </div>
      </div>

      {/* List */}
      <div className="flex-1 overflow-y-auto px-4 pb-4 space-y-2">
        {filtered.length === 0 ? (
          <div className="flex flex-col items-center justify-center h-48 gap-3 text-center">
            <Users size={36} className="text-muted-foreground" />
            <p className="text-muted-foreground text-sm">
              {search ? 'No results found' : 'No referrals yet — share your link!'}
            </p>
          </div>
        ) : filtered.map((r, i) => (
          <div key={r.id} className="card-dark rounded-xl p-3 flex items-center gap-3">
            <div className="w-9 h-9 rounded-full bg-primary/20 flex items-center justify-center text-primary font-bold text-sm shrink-0">
              {(r.referredName || r.referredEmail)[0]?.toUpperCase()}
            </div>
            <div className="flex-1 min-w-0">
              <div className="flex items-center gap-1.5 flex-wrap">
                <p className="text-sm font-medium truncate">{r.referredName || 'User #' + (i + 1)}</p>
                {r.referrerLevel != null && r.referrerLevel > 1 && (
                  <span className="text-[9px] bg-primary/10 text-primary px-1.5 py-0.5 rounded-full font-bold flex items-center gap-0.5">
                    <GitBranch size={7} /> L{r.referrerLevel}
                  </span>
                )}
              </div>
              <p className="text-xs text-muted-foreground">{maskEmail(r.referredEmail)}</p>
              {r.joinedAt && (
                <p className="text-[9px] text-muted-foreground/60">
                  Joined {new Date(r.joinedAt).toLocaleDateString('en-PK', { day: '2-digit', month: 'short', year: '2-digit' })}
                </p>
              )}
            </div>
            <div className="text-right shrink-0">
              <p className="text-xs font-semibold text-green-400">+${r.commissionUsd.toFixed(4)}</p>
              {r.commissionRate != null && (
                <p className="text-[9px] text-muted-foreground">{(r.commissionRate * 100).toFixed(0)}% rate</p>
              )}
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}

