import { useState, useRef } from 'react';
import { Dialog, DialogContent, DialogHeader, DialogTitle } from '@/components/ui/dialog';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { uploadFile } from 'zite-file-upload-sdk';
import { submitVIPPurchase } from 'zite-endpoints-sdk';
import { toast } from 'sonner';
import { Upload, CheckCircle2, ChevronRight, Wallet, Copy, Check } from 'lucide-react';

const METHODS = [
  { id: 'Easypaisa', label: 'Easypaisa', icon: '📱', infoKey: 'payment_easypaisa', color: 'text-emerald-400' },
  { id: 'JazzCash', label: 'JazzCash', icon: '🔴', infoKey: 'payment_jazzcash', color: 'text-rose-400' },
  { id: 'SadaPay', label: 'SadaPay (Int\'l)', icon: '💜', infoKey: 'payment_sadapay', color: 'text-purple-400' },
  { id: 'Bank Transfer', label: 'Bank Transfer', icon: '🏦', infoKey: 'payment_bank', color: 'text-sky-400' },
  { id: 'Trust Wallet', label: 'Trust Wallet', icon: '🔷', infoKey: 'payment_trust', color: 'text-blue-400' },
  { id: 'Binance', label: 'Binance', icon: '🟡', infoKey: 'payment_binance', color: 'text-yellow-400' },
  { id: 'App Wallet', label: 'App Wallet Balance', icon: '💰', infoKey: '', color: 'text-primary' },
];

interface Props {
  open: boolean; onClose: () => void; planId: string; planName: string;
  priceUsd: number; usdToPkr: number; paymentInfo: Record<string, string>;
  usdBalance?: number; onSuccess: () => void;
}

function CopyButton({ value }: { value: string }) {
  const [copied, setCopied] = useState(false);
  const handleCopy = async () => {
    try {
      await navigator.clipboard.writeText(value);
      setCopied(true);
      toast.success('Copied!');
      setTimeout(() => setCopied(false), 2000);
    } catch {
      toast.error('Copy failed — select manually');
    }
  };
  return (
    <button onClick={handleCopy}
      className={`shrink-0 flex items-center gap-1 px-2.5 py-1 rounded-lg text-xs font-semibold transition-all ${copied ? 'bg-green-500/20 text-green-400 border border-green-500/30' : 'bg-primary/20 hover:bg-primary/30 text-primary border border-primary/30'}`}>
      {copied ? <><Check size={11} /> Copied!</> : <><Copy size={11} /> Copy</>}
    </button>
  );
}

function PayDetailRow({ label, value, copyable }: { label: string; value: string; copyable?: boolean }) {
  return (
    <div className="bg-muted/60 rounded-xl p-3 border border-border/50 space-y-1.5">
      <p className="text-[10px] font-semibold uppercase tracking-widest text-muted-foreground">{label}</p>
      <div className="flex items-center justify-between gap-2">
        <p className="text-sm font-bold font-mono text-foreground break-all leading-snug select-all">{value}</p>
        {copyable && <CopyButton value={value} />}
      </div>
    </div>
  );
}

export default function PaymentModal({ open, onClose, planId, planName, priceUsd, usdToPkr, paymentInfo, usdBalance = 0, onSuccess }: Props) {
  const [step, setStep] = useState<'method' | 'proof'>('method');
  const [method, setMethod] = useState('');
  const [tid, setTid] = useState('');
  const [address, setAddress] = useState('');
  const [screenshot, setScreenshot] = useState<File | null>(null);
  const [uploading, setUploading] = useState(false);
  const [loading, setLoading] = useState(false);
  const fileRef = useRef<HTMLInputElement>(null);

  const methodInfo = METHODS.find(m => m.id === method);
  const infoKey = methodInfo?.infoKey ?? '';

  const paymentDetails: { label: string; value: string; copyable: boolean }[] = infoKey ? [
    { label: 'Account Number / Address', value: paymentInfo[`${infoKey}_number`] || paymentInfo[`${infoKey}_address`] || '', copyable: true },
    { label: 'Account Name', value: paymentInfo[`${infoKey}_name`] || '', copyable: false },
    { label: 'Bank Name', value: paymentInfo[`${infoKey}_bank`] || '', copyable: false },
  ].filter(d => d.value) : [];

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) setScreenshot(file);
  };

  const handleSubmit = async () => {
    if (!screenshot && method !== 'App Wallet') { toast.error('Please upload payment screenshot'); return; }
    if (!tid.trim() && method !== 'App Wallet') { toast.error('Enter TID / Transaction Hash'); return; }
    if (!address.trim() && method !== 'App Wallet') { toast.error('Enter your sending number/address'); return; }
    if (method === 'App Wallet' && usdBalance < priceUsd) { toast.error(`Insufficient wallet balance. Need $${priceUsd}`); return; }

    setLoading(true);
    try {
      let screenshotUrl = 'app_wallet_payment';
      if (screenshot) {
        setUploading(true);
        const { fileUrl } = await uploadFile({ data: screenshot, filename: screenshot.name });
        screenshotUrl = fileUrl;
        setUploading(false);
      }
      await submitVIPPurchase({ planId, paymentMethod: method, tidOrHash: tid.trim() || 'APP_WALLET', sendingAddress: address.trim() || 'APP_WALLET', screenshotUrl });
      toast.success('✅ VIP request submitted! Admin will verify within 24hrs.');
      onSuccess();
      onClose();
    } catch (err: any) {
      toast.error(err?.message ?? 'Submission failed');
    } finally {
      setLoading(false); setUploading(false);
    }
  };

  return (
    <Dialog open={open} onOpenChange={onClose}>
      <DialogContent className="bg-card border-border max-w-sm max-h-[90vh] overflow-y-auto">
        <DialogHeader>
          <DialogTitle className="text-center">Buy {planName}</DialogTitle>
          <p className="text-center text-sm text-muted-foreground">
            <span className="font-bold text-primary text-base">${priceUsd}</span>
            <span className="text-xs ml-1 text-muted-foreground">≈ ₨{Math.round(priceUsd * usdToPkr).toLocaleString()}</span>
          </p>
        </DialogHeader>

        {step === 'method' ? (
          <div className="space-y-2 mt-2">
            <p className="text-xs text-muted-foreground text-center mb-3">Select your payment method</p>
            {METHODS.map(m => (
              <button key={m.id} onClick={() => { setMethod(m.id); setStep('proof'); }}
                className="w-full flex items-center gap-3 p-3 card-dark rounded-xl hover:border-primary/40 transition-colors text-left group">
                <span className="text-xl">{m.icon}</span>
                <span className={`flex-1 text-sm font-semibold ${m.color}`}>{m.label}</span>
                <ChevronRight size={14} className="text-muted-foreground group-hover:text-primary transition-colors" />
              </button>
            ))}
          </div>
        ) : (
          <div className="space-y-3 mt-2">
            <button onClick={() => setStep('method')} className="text-xs text-primary flex items-center gap-1 hover:underline">
              ← Change method
            </button>

            {/* Payment Details Card */}
            <div className="rounded-xl border border-border overflow-hidden">
              <div className={`px-3 py-2 bg-muted/50 border-b border-border flex items-center gap-2`}>
                <span className="text-base">{methodInfo?.icon}</span>
                <p className={`text-sm font-bold ${methodInfo?.color ?? 'text-foreground'}`}>
                  {method} Payment Details
                </p>
              </div>
              <div className="p-3 space-y-2">
                {method === 'App Wallet' ? (
                  <div className="flex items-center gap-2 py-1">
                    <Wallet size={16} className="text-primary shrink-0" />
                    <div>
                      <p className="text-xs text-muted-foreground">Your wallet balance</p>
                      <p className="text-lg font-black text-primary">${usdBalance.toFixed(2)}</p>
                    </div>
                  </div>
                ) : paymentDetails.length > 0 ? (
                  paymentDetails.map(d => (
                    <PayDetailRow key={d.label} label={d.label} value={d.value} copyable={d.copyable} />
                  ))
                ) : (
                  <p className="text-xs text-muted-foreground py-2 text-center">Contact admin for payment details</p>
                )}
                <div className="bg-primary/10 border border-primary/20 rounded-xl p-3 mt-2">
                  <p className="text-xs text-muted-foreground">Send exactly this amount:</p>
                  <p className="text-xl font-black text-primary">${priceUsd}
                    <span className="text-xs font-normal text-muted-foreground ml-2">
                      ≈ ₨{Math.round(priceUsd * usdToPkr).toLocaleString()}
                    </span>
                  </p>
                </div>
              </div>
            </div>

            {method !== 'App Wallet' && (
              <>
                <div className="space-y-1.5">
                  <Label className="text-xs">TID / Transaction Hash <span className="text-destructive">*</span></Label>
                  <Input placeholder="Transaction ID or Hash..." value={tid} onChange={e => setTid(e.target.value)} className="bg-muted border-border text-sm" />
                </div>
                <div className="space-y-1.5">
                  <Label className="text-xs">Your Sending Number / Address <span className="text-destructive">*</span></Label>
                  <Input placeholder="The number/address you sent from..." value={address} onChange={e => setAddress(e.target.value)} className="bg-muted border-border text-sm" />
                </div>
                <div className="space-y-1.5">
                  <Label className="text-xs">Payment Screenshot <span className="text-destructive">*</span></Label>
                  <div onClick={() => fileRef.current?.click()} className="border-2 border-dashed border-border rounded-xl p-4 text-center cursor-pointer hover:border-primary/40 transition-colors">
                    {screenshot
                      ? <div className="flex items-center justify-center gap-2 text-green-400"><CheckCircle2 size={16} /><span className="text-sm font-medium">{screenshot.name}</span></div>
                      : <div className="flex flex-col items-center gap-1"><Upload size={20} className="text-muted-foreground" /><span className="text-xs text-muted-foreground">Tap to upload screenshot</span></div>}
                  </div>
                  <input ref={fileRef} type="file" accept="image/*" onChange={handleFileChange} className="hidden" />
                </div>
              </>
            )}

            <Button onClick={handleSubmit} disabled={loading || uploading} className="w-full bg-primary text-primary-foreground font-bold glow-gold text-sm">
              {uploading ? '⏫ Uploading...' : loading ? '⏳ Submitting...' : '✅ Submit VIP Request'}
            </Button>
            <p className="text-[10px] text-muted-foreground text-center">
              Your request will be reviewed within 24 hours. VIP status remains Pending until verified.
            </p>
          </div>
        )}
      </DialogContent>
    </Dialog>
  );
}

