import { useState } from 'react';
import { Dialog, DialogContent } from '@/components/ui/dialog';
import { Input } from '@/components/ui/input';
import { Button } from '@/components/ui/button';
import { setupUserProfile } from 'zite-endpoints-sdk';
import { toast } from 'sonner';
import { User, Phone, Sparkles, Gift } from 'lucide-react';
import { getOrCreateDeviceId } from '@/lib/deviceSession';
import InternationalPhoneInput from '@/components/InternationalPhoneInput';

interface Props { onClose: () => void; }

// ── Read pending ref code (URL → localStorage fallback) ──────────
function getPendingRefCode(): string {
  try {
    const urlRef = new URLSearchParams(window.location.search).get('ref') ?? '';
    if (urlRef && /^[a-zA-Z0-9_-]{3,12}$/.test(urlRef)) return urlRef;
    const stored = localStorage.getItem('pending_ref_code') ?? '';
    if (stored && /^[a-zA-Z0-9_-]{3,12}$/.test(stored)) return stored;
  } catch { /* ignore */ }
  return '';
}

export default function ProfileSetupModal({ onClose }: Props) {
  const [name, setName]   = useState('');
  const [phone, setPhone] = useState('');
  const [loading, setLoading] = useState(false);

  const pendingRef = getPendingRefCode();

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!name.trim() || name.trim().length < 2) {
      toast.error('Please enter your full name');
      return;
    }
    setLoading(true);
    try {
      await setupUserProfile({
        name: name.trim(),
        phone: phone.trim() || undefined,
        referredByCode: pendingRef || undefined,
        deviceId: getOrCreateDeviceId(),
      });
      try { localStorage.removeItem('pending_ref_code'); } catch { /* ignore */ }
      toast.success('🎉 Profile setup complete! Welcome to Hussain AI!');
      onClose();
      window.location.reload();
    } catch (err: any) {
      toast.error(err?.message ?? 'Setup failed. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <Dialog open onOpenChange={() => {}}>
      <DialogContent
        className="p-0 border-0 bg-transparent shadow-none max-w-[320px] w-[92vw]"
        onPointerDownOutside={e => e.preventDefault()}
      >
        <div className="bg-card border border-border rounded-2xl overflow-hidden shadow-xl">

          {/* ── Header band ── */}
          <div className="bg-primary/10 border-b border-border/60 px-5 py-4 flex flex-col items-center gap-1.5">
            <div className="bg-primary/20 rounded-xl p-2 border border-primary/30">
              <Sparkles size={20} className="text-primary" />
            </div>
            <h2 className="text-base font-black text-center leading-tight">Assalam-o-Alaikum! 👋</h2>
            <p className="text-[11px] text-muted-foreground text-center leading-snug">
              Profile complete karein aur earning shuru karein
            </p>

            {pendingRef && (
              <div className="flex items-center gap-1.5 bg-green-500/10 border border-green-500/25 rounded-full px-3 py-1 mt-0.5">
                <Gift size={10} className="text-green-400" />
                <span className="text-[10px] text-green-400 font-bold">
                  🎁 Referral bonus auto-applied — 2× coins on signup!
                </span>
              </div>
            )}
          </div>

          {/* ── Form body ── */}
          <form onSubmit={handleSubmit} className="px-4 py-3.5 space-y-3">

            {/* Full Name */}
            <div className="space-y-1">
              <label className="flex items-center gap-1 text-[11px] font-semibold text-muted-foreground">
                <User size={10} /> Full Name <span className="text-destructive">*</span>
              </label>
              <Input
                placeholder="Apna poora naam likhein"
                value={name}
                onChange={e => setName(e.target.value)}
                className="bg-muted border-border h-9 text-sm px-3"
                autoComplete="name"
                autoFocus
              />
            </div>

            {/* International Phone */}
            <div className="space-y-1">
              <label className="flex items-center gap-1 text-[11px] font-semibold text-muted-foreground">
                <Phone size={10} /> Phone Number
                <span className="text-[10px] text-muted-foreground/60 ml-1">(optional)</span>
              </label>
              <InternationalPhoneInput
                value={phone}
                onChange={setPhone}
              />
            </div>

            {/* Submit */}
            <Button
              type="submit"
              disabled={loading}
              className="w-full h-9 bg-primary text-primary-foreground font-bold text-sm"
            >
              {loading ? 'Setting up...' : '🚀 Start Earning Now!'}
            </Button>

            <p className="text-[9px] text-muted-foreground/60 text-center">
              By continuing you agree to our Terms &amp; Privacy Policy
            </p>
          </form>
        </div>
      </DialogContent>
    </Dialog>
  );
}

