// ══════════════════════════════════════════════════════════════════
// BOX 1: Enterprise Multi-Database Configuration Grid
// Isolated admin card — zero contact with core Supabase logic
// ══════════════════════════════════════════════════════════════════
import { useState, useEffect, useCallback } from 'react';
import { multiDbConfig } from 'zite-endpoints-sdk';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Skeleton } from '@/components/ui/skeleton';
import { toast } from 'sonner';
import {
  Database, Server, Plus, Trash2, Loader2, Check, X,
  RefreshCw, Zap, ShieldCheck, AlertTriangle, Eye, EyeOff, ChevronDown,
} from 'lucide-react';

const DB_TYPES = [
  { value: 'PostgreSQL', label: 'PostgreSQL', emoji: '🐘', color: 'border-blue-500/30', bg: 'bg-blue-500/10' },
  { value: 'Firebase',   label: 'Firebase',   emoji: '🔥', color: 'border-orange-500/30', bg: 'bg-orange-500/10' },
  { value: 'MongoDB',    label: 'MongoDB',    emoji: '🍃', color: 'border-green-500/30', bg: 'bg-green-500/10' },
  { value: 'MySQL',      label: 'MySQL',      emoji: '🐬', color: 'border-cyan-500/30', bg: 'bg-cyan-500/10' },
  { value: 'Oracle',     label: 'Oracle',     emoji: '🔴', color: 'border-red-500/30', bg: 'bg-red-500/10' },
] as const;

type DbConfig = {
  id: string; dbType: string; host: string; port: string;
  databaseName: string; label: string; status: string; lastTestedAt: string;
};

export default function MultiDbGrid({ token }: { token: string }) {
  const [configs, setConfigs] = useState<DbConfig[]>([]);
  const [loading, setLoading] = useState(true);
  const [formOpen, setFormOpen] = useState(false);
  const [busy, setBusy] = useState<string | null>(null);
  const [showPwd, setShowPwd] = useState(false);
  const [selectedType, setSelectedType] = useState('PostgreSQL');

  const [form, setForm] = useState({
    host: '', port: '', username: '', password: '',
    connectionString: '', databaseName: '', label: '',
  });

  const load = useCallback(async () => {
    setLoading(true);
    try {
      const r = await multiDbConfig({ action: 'list', adminToken: token });
      setConfigs(r.configs ?? []);
    } catch (e: any) { toast.error(e?.message ?? 'Failed to load'); }
    finally { setLoading(false); }
  }, [token]);

  useEffect(() => { load(); }, [load]);

  const resetForm = () => setForm({ host: '', port: '', username: '', password: '', connectionString: '', databaseName: '', label: '' });

  const saveConfig = async () => {
    if (!form.host && !form.connectionString) { toast.error('Host or Connection String required'); return; }
    setBusy('save');
    try {
      await multiDbConfig({
        action: 'save', adminToken: token,
        config: { dbType: selectedType as any, ...form },
      });
      toast.success(`✅ ${selectedType} configuration saved!`);
      resetForm(); setFormOpen(false); load();
    } catch (e: any) { toast.error(e?.message); }
    finally { setBusy(null); }
  };

  const testConnection = async (id: string) => {
    setBusy('test_' + id);
    try {
      const r = await multiDbConfig({ action: 'test_connection', adminToken: token, config: { id } });
      if (r.testResult?.connected) {
        toast.success(`✅ Connected! Latency: ${r.testResult.latencyMs}ms — ${r.testResult.message}`);
      } else {
        toast.error(`❌ ${r.testResult?.message ?? 'Connection failed'}`);
      }
      load();
    } catch (e: any) { toast.error(e?.message); }
    finally { setBusy(null); }
  };

  const deleteConfig = async (id: string) => {
    setBusy('del_' + id);
    try {
      await multiDbConfig({ action: 'delete', adminToken: token, config: { id } });
      toast.success('Removed'); load();
    } catch (e: any) { toast.error(e?.message); }
    finally { setBusy(null); }
  };

  const typeMeta = DB_TYPES.find(t => t.value === selectedType) ?? DB_TYPES[0];

  return (
    <div className="rounded-2xl border-2 border-violet-500/30 bg-violet-950/10 p-4 space-y-4">
      {/* Header */}
      <div className="flex items-center gap-3">
        <div className="w-10 h-10 rounded-xl bg-violet-500/15 border border-violet-500/30 flex items-center justify-center shrink-0">
          <Server size={20} className="text-violet-400" />
        </div>
        <div className="flex-1 min-w-0">
          <p className="font-black text-sm">🗄️ Enterprise Multi-Database Grid</p>
          <p className="text-[10px] text-muted-foreground">ملٹی ڈیٹا بیس چابیوں والا باکس — Isolated from core Supabase</p>
        </div>
        <button onClick={() => { resetForm(); setFormOpen(f => !f); }}
          className="shrink-0 flex items-center gap-1 text-xs bg-violet-500/20 text-violet-400 border border-violet-500/30 rounded-xl px-3 py-1.5 font-bold hover:bg-violet-500/30 transition-colors">
          <Plus size={11} /> Add DB
        </button>
      </div>

      {/* Isolation notice */}
      <div className="bg-green-950/30 border border-green-500/20 rounded-xl px-3 py-2 text-[9px] text-green-400 flex items-start gap-1.5">
        <ShieldCheck size={10} className="shrink-0 mt-0.5" />
        <span>100% Isolated — All configs stored separately in AdminSettings. Zero mixing with operational Supabase tables.</span>
      </div>

      {/* Supported DBs */}
      <div className="grid grid-cols-5 gap-1.5">
        {DB_TYPES.map(db => (
          <div key={db.value} className={`text-center rounded-lg border px-1 py-2 ${db.color} ${db.bg}`}>
            <span className="text-lg">{db.emoji}</span>
            <p className="text-[8px] font-bold mt-0.5 text-foreground">{db.label}</p>
          </div>
        ))}
      </div>

      {/* Add Form */}
      {formOpen && (
        <div className="card-dark rounded-xl p-4 space-y-3 border border-violet-500/30">
          <p className="text-xs font-bold text-violet-400 flex items-center gap-1.5"><Database size={11} /> New Database Connection</p>

          {/* DB Type Selector */}
          <div className="space-y-1">
            <Label className="text-[10px] text-muted-foreground">Database Engine</Label>
            <div className="grid grid-cols-5 gap-1.5">
              {DB_TYPES.map(db => (
                <button key={db.value} onClick={() => setSelectedType(db.value)}
                  className={`rounded-lg border-2 px-1 py-2 text-center transition-all ${
                    selectedType === db.value ? `${db.color} ${db.bg} border-2` : 'border-border hover:border-border/80'
                  }`}>
                  <span className="text-base">{db.emoji}</span>
                  <p className="text-[8px] font-bold mt-0.5">{db.label}</p>
                </button>
              ))}
            </div>
          </div>

          {/* Connection Fields */}
          <div className="space-y-2">
            <div className="space-y-0.5">
              <Label className="text-[10px] text-muted-foreground">🔗 API Key / Connection String</Label>
              <div className="relative">
                <Input type={showPwd ? 'text' : 'password'} value={form.connectionString}
                  onChange={e => setForm(f => ({ ...f, connectionString: e.target.value }))}
                  placeholder="postgres://user:pass@host:5432/db or API key..."
                  className="bg-muted border-border text-xs h-8 font-mono pr-9" />
                <button onClick={() => setShowPwd(s => !s)} className="absolute right-2 top-1/2 -translate-y-1/2 text-muted-foreground hover:text-foreground">
                  {showPwd ? <EyeOff size={12} /> : <Eye size={12} />}
                </button>
              </div>
            </div>

            <div className="grid grid-cols-2 gap-2">
              <div className="space-y-0.5">
                <Label className="text-[10px] text-muted-foreground">🌐 Host</Label>
                <Input value={form.host} onChange={e => setForm(f => ({ ...f, host: e.target.value }))}
                  placeholder="db.example.com" className="bg-muted border-border text-xs h-8 font-mono" />
              </div>
              <div className="space-y-0.5">
                <Label className="text-[10px] text-muted-foreground">🔌 Port</Label>
                <Input value={form.port} onChange={e => setForm(f => ({ ...f, port: e.target.value }))}
                  placeholder="5432" className="bg-muted border-border text-xs h-8 font-mono" />
              </div>
            </div>

            <div className="grid grid-cols-2 gap-2">
              <div className="space-y-0.5">
                <Label className="text-[10px] text-muted-foreground">👤 Username</Label>
                <Input value={form.username} onChange={e => setForm(f => ({ ...f, username: e.target.value }))}
                  placeholder="admin" className="bg-muted border-border text-xs h-8" />
              </div>
              <div className="space-y-0.5">
                <Label className="text-[10px] text-muted-foreground">🔒 Password</Label>
                <Input type="password" value={form.password} onChange={e => setForm(f => ({ ...f, password: e.target.value }))}
                  placeholder="••••••••" className="bg-muted border-border text-xs h-8" />
              </div>
            </div>

            <div className="grid grid-cols-2 gap-2">
              <div className="space-y-0.5">
                <Label className="text-[10px] text-muted-foreground">📂 Database Name</Label>
                <Input value={form.databaseName} onChange={e => setForm(f => ({ ...f, databaseName: e.target.value }))}
                  placeholder="production_db" className="bg-muted border-border text-xs h-8" />
              </div>
              <div className="space-y-0.5">
                <Label className="text-[10px] text-muted-foreground">📛 Label</Label>
                <Input value={form.label} onChange={e => setForm(f => ({ ...f, label: e.target.value }))}
                  placeholder="My Production DB" className="bg-muted border-border text-xs h-8" />
              </div>
            </div>
          </div>

          <div className="flex gap-2">
            <Button size="sm" onClick={saveConfig} disabled={busy === 'save'}
              className="flex-1 h-9 text-xs bg-violet-600 hover:bg-violet-600/90 text-white gap-1 font-bold">
              {busy === 'save' ? <><Loader2 size={10} className="animate-spin" /> Saving...</> : <><Zap size={10} /> Deploy & Synchronize</>}
            </Button>
            <Button size="sm" variant="ghost" onClick={() => setFormOpen(false)} className="h-9 text-xs text-muted-foreground">Cancel</Button>
          </div>
        </div>
      )}

      {/* Config List */}
      {loading ? (
        <div className="space-y-2">{[1, 2].map(i => <Skeleton key={i} className="h-20 rounded-xl" />)}</div>
      ) : configs.length === 0 ? (
        <div className="text-center py-8 text-muted-foreground">
          <Database size={28} className="mx-auto mb-2 opacity-30" />
          <p className="text-xs">No external databases configured yet.</p>
          <p className="text-[10px] mt-1">Click "Add DB" above to register a new database connection.</p>
        </div>
      ) : (
        <div className="space-y-2.5">
          {configs.map(cfg => {
            const meta = DB_TYPES.find(d => d.value === cfg.dbType) ?? DB_TYPES[0];
            const isConnected = cfg.status === 'Connected';
            const isError = cfg.status === 'Error';
            return (
              <div key={cfg.id} className={`card-dark rounded-xl p-3 space-y-2 border ${isConnected ? 'border-green-500/30' : isError ? 'border-destructive/30' : 'border-border'}`}>
                <div className="flex items-start justify-between gap-2">
                  <div className="flex items-center gap-2 min-w-0">
                    <span className="text-lg shrink-0">{meta.emoji}</span>
                    <div className="min-w-0 flex-1">
                      <p className="text-xs font-bold truncate">{cfg.label || cfg.dbType}</p>
                      <p className="text-[10px] text-muted-foreground font-mono truncate">{cfg.host}{cfg.port ? `:${cfg.port}` : ''}</p>
                      {cfg.databaseName && <p className="text-[9px] text-muted-foreground">DB: {cfg.databaseName}</p>}
                    </div>
                  </div>
                  <div className="flex flex-col items-end gap-1 shrink-0">
                    <span className={`text-[9px] font-bold px-2 py-0.5 rounded-full border ${
                      isConnected ? 'bg-green-500/15 text-green-400 border-green-500/30' :
                      isError ? 'bg-destructive/15 text-destructive border-destructive/30' :
                      'bg-yellow-500/15 text-yellow-400 border-yellow-500/30'
                    }`}>{cfg.status || 'Pending'}</span>
                    {cfg.lastTestedAt && (
                      <p className="text-[8px] text-muted-foreground">
                        {new Date(cfg.lastTestedAt).toLocaleString('en-PK', { month: 'short', day: '2-digit', hour: '2-digit', minute: '2-digit' })}
                      </p>
                    )}
                  </div>
                </div>
                <div className="flex gap-1.5">
                  <Button size="sm" onClick={() => testConnection(cfg.id)} disabled={!!busy}
                    className="flex-1 h-7 text-[10px] bg-violet-600/20 text-violet-400 border border-violet-500/30 hover:bg-violet-600/30 gap-1">
                    {busy === 'test_' + cfg.id ? <><Loader2 size={9} className="animate-spin" /> Testing...</> : <><Zap size={9} /> Test Connection</>}
                  </Button>
                  <Button size="sm" onClick={() => deleteConfig(cfg.id)} disabled={!!busy}
                    variant="ghost" className="h-7 text-[10px] text-destructive/60 hover:text-destructive gap-1">
                    <Trash2 size={9} /> Remove
                  </Button>
                </div>
              </div>
            );
          })}
        </div>
      )}

      {/* Architecture Info */}
      <div className="bg-violet-950/20 border border-violet-500/15 rounded-xl px-3 py-2.5 space-y-1 text-[9px] text-muted-foreground">
        <p className="font-bold text-foreground">⚙️ How Multi-DB Routing Works:</p>
        <ul className="space-y-0.5 list-disc pl-4">
          <li>Configs stored in isolated <code className="text-violet-400 font-mono bg-violet-500/10 px-1 rounded">AdminSettings</code> rows — zero mixing with app data</li>
          <li>Firebase & MongoDB Atlas testable via REST API — PostgreSQL via Supabase REST</li>
          <li>MySQL & Oracle require REST API proxy for edge runtime compatibility</li>
          <li>Core Supabase connection is <strong className="text-green-400">NEVER touched</strong> — 100% fallback safe</li>
        </ul>
      </div>
    </div>
  );
}

