import { useEffect, useRef } from 'react';
import { Bot, User } from 'lucide-react';
import { cn } from '@/lib/utils';
import MultiLingualTTSButton from '@/components/MultiLingualTTSButton';

export type Message = { id: string; role: 'user' | 'assistant'; content: string; ts: number };

interface Props { messages: Message[]; loading?: boolean; }

function TypingDots() {
  return (
    <div className="flex gap-1 px-1 py-0.5">
      {[0, 1, 2].map(i => (
        <div key={i} className="w-2 h-2 rounded-full bg-primary animate-bounce" style={{ animationDelay: `${i * 0.15}s` }} />
      ))}
    </div>
  );
}

export default function ChatMessages({ messages, loading }: Props) {
  const bottomRef = useRef<HTMLDivElement>(null);
  useEffect(() => { bottomRef.current?.scrollIntoView({ behavior: 'smooth' }); }, [messages, loading]);

  if (messages.length === 0 && !loading) {
    return (
      <div className="flex flex-col items-center justify-center h-full text-center p-8 gap-4">
        <div className="bg-primary/10 rounded-3xl p-5 pulse-gold">
          <Bot size={40} className="text-primary" />
        </div>
        <div>
          <p className="text-xl font-bold gold-gradient">Hussain AI</p>
          <p className="text-muted-foreground text-sm mt-1">Aapka AI assistant tayyar hai — kuch bhi poochein!</p>
        </div>
        <div className="grid grid-cols-2 gap-2 w-full max-w-xs mt-2">
          {['💰 Earning kaise karein?', '🎨 Image banayein', '👑 VIP plans dekhein', '📈 Level system'].map(s => (
            <div key={s} className="bg-muted rounded-xl px-3 py-2 text-xs text-muted-foreground border border-border">{s}</div>
          ))}
        </div>
      </div>
    );
  }

  return (
    <div className="flex flex-col gap-3 p-4">
      {messages.map(msg => (
        <div key={msg.id} className={cn('flex gap-2.5 max-w-[85%]', msg.role === 'user' ? 'self-end flex-row-reverse' : 'self-start')}>
          <div className={cn('shrink-0 w-8 h-8 rounded-full flex items-center justify-center text-xs font-bold',
            msg.role === 'user' ? 'bg-primary text-primary-foreground' : 'bg-muted border border-border')}>
            {msg.role === 'user' ? <User size={14} /> : <Bot size={14} className="text-primary" />}
          </div>
          <div className="flex flex-col gap-1">
            <div className={cn('px-4 py-2.5 rounded-2xl text-sm leading-relaxed whitespace-pre-wrap',
              msg.role === 'user' ? 'chat-bubble-user rounded-tr-sm' : 'chat-bubble-ai rounded-tl-sm')}>
              {msg.content}
            </div>
            {/* TTS button — only on assistant messages */}
            {msg.role === 'assistant' && msg.content.length > 10 && (
              <div className={cn('flex', 'ml-1')}>
                <MultiLingualTTSButton
                  text={msg.content}
                  showLangSelector
                  size="sm"
                />
              </div>
            )}
          </div>
        </div>
      ))}
      {loading && (
        <div className="flex gap-2.5 self-start">
          <div className="shrink-0 w-8 h-8 rounded-full flex items-center justify-center bg-muted border border-border">
            <Bot size={14} className="text-primary" />
          </div>
          <div className="chat-bubble-ai rounded-tl-sm px-4 py-3"><TypingDots /></div>
        </div>
      )}
      <div ref={bottomRef} />
    </div>
  );
}

