// ════════════════════════════════════════════════════════════════════
// MAGIC CALENDAR STRIP — Double-Line Ticker with Live Sky Engine
// ════════════════════════════════════════════════════════════════════
// HEIGHT: 62px — two independent scrolling strata
// LINE 1: Time (AM/PM) · Gregorian · Hijri (sunset-shift) · Desi Month
// LINE 2: Urdu GPS micro-location · District · Weather
// BACKGROUND: Live sky with sun arc / moon / stars / rain / snow
// ════════════════════════════════════════════════════════════════════

import { useState, useEffect, useRef, memo, type CSSProperties } from 'react';
import { useAppData } from '@/contexts/AppDataContext';

// ── Divider ──────────────────────────────────────────────────────────
function Sep({ color }: { color: string }) {
  return <span style={{ margin: '0 8px', color, fontSize: '7px', opacity: 0.85 }}>◈</span>;
}

// ══════════════════════════════════════════════════════════════════════
// HIJRI CALENDAR ENGINE  (1 Muharram 1447 AH = 27 June 2025 CE)
// ══════════════════════════════════════════════════════════════════════
const H_REF = { y: 2025, m: 6, d: 27, hy: 1447 };
const H_LEAP_POS = new Set([2, 5, 7, 10, 13, 16, 18, 21, 24, 26, 29]);
const isHLeap = (y: number) => H_LEAP_POS.has(((y - 1) % 30) + 1);
const hML = (y: number, m: number) => m % 2 === 1 ? 30 : m === 12 && isHLeap(y) ? 30 : 29;

const HM = [
  { en: 'Muharram',        ur: 'محرم'        },
  { en: 'Safar',           ur: 'صفر'         },
  { en: "Rabi' al-Awwal",  ur: 'ربیع الاول'  },
  { en: "Rabi' al-Thani",  ur: 'ربیع الثانی' },
  { en: 'Jumada al-Awwal', ur: 'جمادی الاول' },
  { en: 'Jumada al-Thani', ur: 'جمادی الثانی'},
  { en: 'Rajab',           ur: 'رجب'         },
  { en: "Sha'ban",         ur: 'شعبان'       },
  { en: 'Ramadan',         ur: 'رمضان'       },
  { en: 'Shawwal',         ur: 'شوال'        },
  { en: "Dhul-Qa'dah",     ur: 'ذوالقعدہ'   },
  { en: 'Dhul-Hijjah',     ur: 'ذوالحجہ'    },
] as const;

function getHijri(date: Date): { d: number; m: number; y: number; en: string; ur: string } {
  const utcMs = (y: number, mo: number, da: number) => Date.UTC(y, mo - 1, da);
  let diff = Math.round(
    (utcMs(date.getUTCFullYear(), date.getUTCMonth() + 1, date.getUTCDate())
    - utcMs(H_REF.y, H_REF.m, H_REF.d)) / 86400000
  );
  let hy = H_REF.hy, hm = 1, hd = 1;
  while (diff > 0) {
    const ml = hML(hy, hm);
    if (diff < ml) { hd += diff; diff = 0; }
    else { diff -= ml; hd = 1; if (++hm > 12) { hm = 1; hy++; } }
  }
  while (diff < 0) {
    if (--hm < 1) { hm = 12; hy--; }
    diff += hML(hy, hm);
  }
  return { d: hd, m: hm, y: hy, en: HM[hm - 1].en, ur: HM[hm - 1].ur };
}

// ══════════════════════════════════════════════════════════════════════
// PUNJABI / BIKRAMI CALENDAR
// ══════════════════════════════════════════════════════════════════════
function getPunjabiMonth(date: Date): { n: string; s: string } {
  const mo = date.getUTCMonth() + 1;
  const d  = date.getUTCDate();
  if ((mo===3&&d>=14)||(mo===4&&d<=13))  return { n:'چیت',    s:'🌸 بہار'         };
  if ((mo===4&&d>=14)||(mo===5&&d<=14))  return { n:'ویساکھ', s:'🌼 وساکھی'        };
  if ((mo===5&&d>=15)||(mo===6&&d<=14))  return { n:'جیٹھ',   s:'🌞 گرمی'         };
  if ((mo===6&&d>=15)||(mo===7&&d<=15))  return { n:'ہاڑ',    s:'☀️ ہاڑ گرمی'     };
  if ((mo===7&&d>=16)||(mo===8&&d<=15))  return { n:'ساون',   s:'🌧️ ساون برسات'   };
  if ((mo===8&&d>=16)||(mo===9&&d<=14))  return { n:'بھادوں', s:'🌦️ برسات'        };
  if ((mo===9&&d>=15)||(mo===10&&d<=14)) return { n:'اسو',    s:'🍂 خزاں'         };
  if ((mo===10&&d>=15)||(mo===11&&d<=13))return { n:'کتک',    s:'🍁 کتک'          };
  if ((mo===11&&d>=14)||(mo===12&&d<=13))return { n:'مگھر',   s:'❄️ مگھر سردی'    };
  if ((mo===12&&d>=14)||(mo===1&&d<=12)) return { n:'پوہ',    s:'🌨️ سخت سردی'    };
  if ((mo===1&&d>=13) ||(mo===2&&d<=11)) return { n:'ماگھ',   s:'❄️ ماگھ'         };
  return { n:'پھگن', s:'🌺 پھگن' };
}

