// ══════════════════════════════════════════════════════════════════════
// WEATHER + CELESTIAL ANIMATION LAYER
// ══════════════════════════════════════════════════════════════════════
const SkyAnimationLayer = memo(function SkyAnimationLayer({ tod, wmo, hourFrac, cloudCover }: {
  tod: TOD; wmo: number | null; hourFrac: number; cloudCover: number | null;
}) {
  const abs: CSSProperties = { position: 'absolute', inset: 0, overflow: 'hidden', pointerEvents: 'none', zIndex: 0 };

  // Sun/Moon arc position: map 6-18 (day) or 18-6 (night) to 0-100% horizontal, parabolic vertical
  const isSunVisible = tod === 'day' || tod === 'evening';
  const celestialX = isSunVisible
    ? Math.max(0, Math.min(100, ((hourFrac - 6) / 12) * 100))
    : Math.max(0, Math.min(100, hourFrac >= 18 ? ((hourFrac - 18) / 12) * 100 : ((hourFrac + 6) / 12) * 100));
  // Parabolic arc: highest at center (50%), lowest at edges
  const t = celestialX / 100;
  const arcY = 5 + 35 * (1 - 4 * (t - 0.5) ** 2); // peaks at ~40% from top
  // Cloud opacity overlay for overcast/rain
  const cloudOpacity = (wmo !== null && (wmo >= 51)) ? Math.min(0.7, (cloudCover ?? 80) / 100 * 0.75) : 0;

  return (
    <div style={abs}>
      {/* ── Cloud / weather overlay that dims sun ── */}
      {cloudOpacity > 0 && (
        <div style={{ position: 'absolute', inset: 0, background: `rgba(30,40,60,${cloudOpacity})`, transition: 'background 5s ease' }} />
      )}

      {/* ── Celestial body: Sun (day/evening) or Moon (night) ── */}
      {isSunVisible && (
        <div style={{
          position: 'absolute',
          left: `${celestialX}%`, top: `${arcY}%`,
          width: 22, height: 22, marginLeft: -11, marginTop: -11,
          borderRadius: '50%',
          background: tod === 'evening'
            ? 'radial-gradient(circle, #fb923c 0%, #ea580c 50%, transparent 75%)'
            : 'radial-gradient(circle, #fef3c7 0%, #fbbf24 40%, #f59e0b 65%, transparent 80%)',
          boxShadow: tod === 'evening'
            ? '0 0 18px 6px rgba(251,146,60,0.5)'
            : '0 0 20px 8px rgba(251,191,36,0.45), 0 0 40px 16px rgba(245,158,11,0.2)',
          opacity: cloudOpacity > 0.4 ? 0.3 : 1,
          filter: cloudOpacity > 0.3 ? `blur(${cloudOpacity * 4}px)` : 'none',
          transition: 'opacity 3s ease, filter 3s ease, left 60s linear, top 60s linear',
          animation: 'mc-sun-pulse 4s ease-in-out infinite',
          zIndex: 1,
        }} />
      )}

      {tod === 'night' && (
        <div style={{
          position: 'absolute',
          left: `${celestialX}%`, top: `${arcY}%`,
          width: 18, height: 18, marginLeft: -9, marginTop: -9,
          borderRadius: '50%',
          background: 'radial-gradient(circle at 35% 35%, #e0e7ff 0%, #a5b4fc 50%, #6366f1 90%)',
          boxShadow: '0 0 12px 4px rgba(165,180,252,0.4), 0 0 24px 8px rgba(99,102,241,0.2)',
          transition: 'left 60s linear, top 60s linear',
          zIndex: 1,
        }} />
      )}

      {/* ── Lightning ── */}
      {wmo !== null && wmo >= 95 && (
        <>
          <div style={{ position: 'absolute', inset: 0, background: 'rgba(255,255,180,0.15)', animation: 'mc-lightning 4.2s .5s ease-in-out infinite' }} />
          {_RAIN.map((r, i) => (
            <div key={`lr${i}`} style={{ position: 'absolute', left: r.l, top: 0, width: '1px', height: '12px', background: 'rgba(147,197,253,.65)', animation: `mc-rain-fall ${r.u} ${r.d} linear infinite` }} />
          ))}
        </>
      )}

      {/* ── Rain ── */}
      {wmo !== null && wmo < 95 && ((wmo >= 51 && wmo <= 67) || (wmo >= 80 && wmo <= 82)) && (
        _RAIN.map((r, i) => (
          <div key={`r${i}`} style={{ position: 'absolute', left: r.l, top: 0, width: '1px', height: '10px', background: 'rgba(147,197,253,.60)', animation: `mc-rain-fall ${r.u} ${r.d} linear infinite` }} />
        ))
      )}

      {/* ── Snow ── */}
      {wmo !== null && wmo >= 71 && wmo <= 86 && (
        _SNOW.map((f, i) => (
          <div key={`s${i}`} style={{ position: 'absolute', left: f.l, top: 0, width: `${f.s}px`, height: `${f.s}px`, background: 'rgba(255,255,255,.80)', borderRadius: '50%', animation: `mc-snow-fall ${f.u} ${f.d} linear infinite` }} />
        ))
      )}

      {/* ── Stars (night, clear/partly) ── */}
      {tod === 'night' && (wmo === null || wmo < 51) && (
        _STARS.map((s, i) => (
          <div key={`st${i}`} style={{ position: 'absolute', left: s.l, top: s.t, width: `${s.s}px`, height: `${s.s}px`, background: '#c7d2fe', borderRadius: '50%', animation: `mc-twinkle ${s.u} ${s.d} ease-in-out infinite` }} />
        ))
      )}

      {/* ── Clouds (overcast/fog, daytime) ── */}
      {tod !== 'night' && wmo !== null && wmo >= 2 && wmo <= 48 && !(wmo >= 51) && (
        <>
          <div style={{ position: 'absolute', top: '12%', left: '8%', width: '90px', height: '18px', background: 'rgba(255,255,255,.14)', borderRadius: '12px', animation: 'mc-cloud-float 9s ease-in-out infinite' }} />
          <div style={{ position: 'absolute', top: '50%', left: '55%', width: '65px', height: '14px', background: 'rgba(255,255,255,.10)', borderRadius: '9px', animation: 'mc-cloud-float 12s 2.5s ease-in-out infinite' }} />
        </>
      )}
    </div>
  );
});

// ══════════════════════════════════════════════════════════════════════
// TIMEZONE HELPERS
// ══════════════════════════════════════════════════════════════════════
function getLocalHour(tz: string, date: Date): number {
  try {
    const h = parseInt(date.toLocaleString('en-US', { hour: '2-digit', hour12: false, timeZone: tz }));
    return isNaN(h) ? date.getHours() : h % 24;
  } catch { return date.getHours(); }
}
function getLocalMinute(tz: string, date: Date): number {
  try {
    const m = parseInt(date.toLocaleString('en-US', { minute: '2-digit', timeZone: tz }));
    return isNaN(m) ? date.getMinutes() : m;
  } catch { return date.getMinutes(); }
}
function getLocalSecond(tz: string, date: Date): number {
  try {
    const s = parseInt(date.toLocaleString('en-US', { second: '2-digit', timeZone: tz }));
    return isNaN(s) ? date.getSeconds() : s;
  } catch { return date.getSeconds(); }
}
function getLocalDate(tz: string, date: Date): Date {
  try {
    const fmt = new Intl.DateTimeFormat('en-US', { year: 'numeric', month: '2-digit', day: '2-digit', timeZone: tz });
    const parts = fmt.formatToParts(date);
    const get = (t: string) => parseInt(parts.find(p => p.type === t)?.value || '1');
    return new Date(Date.UTC(get('year'), get('month') - 1, get('day')));
  } catch { return new Date(date.getTime() + 5 * 3600_000); }
}
function isPastSunset(tz: string, date: Date, sunsetStr: string | null): boolean {
  const localMinutes = getLocalHour(tz, date) * 60 + getLocalMinute(tz, date);
  if (sunsetStr) {
    const [sh, sm] = sunsetStr.split(':').map(Number);
    if (!isNaN(sh) && !isNaN(sm)) return localMinutes >= (sh * 60 + sm);
  }
  return localMinutes >= 18 * 60 + 15;
}

// ══════════════════════════════════════════════════════════════════════
// MAIN COMPONENT — 62px, TWO INDEPENDENT SCROLLING LINES
// ══════════════════════════════════════════════════════════════════════
export default function MagicCalendarStrip() {
  const [now, setNow] = useState(() => new Date());
  const [lw, setLw] = useState<LW | null>(_lwC);
  const [streetLoc, setStreetLoc] = useState<StreetLoc | null>(_streetCache);
  const watchIdRef = useRef<number | null>(null);
  const { weatherApiKey } = useAppData();

  useEffect(() => {
    const id = setInterval(() => setNow(new Date()), 1000);
    return () => clearInterval(id);
  }, []);

  useEffect(() => {
    let alive = true;
    const load = () => fetchLW().then(d => { if (alive) setLw(d); });
    load();
    const id = setInterval(() => { _lwC = null; _lwP = null; load(); }, 600_000);
    return () => { alive = false; clearInterval(id); };
  }, []);

  useEffect(() => {
    if (typeof navigator === 'undefined' || !('geolocation' in navigator)) return;
    const gKey = weatherApiKey || undefined;
    const onPos = (pos: GeolocationPosition) => {
      reverseGeoStreet(pos.coords.latitude, pos.coords.longitude).then(sl => { if (sl) setStreetLoc(sl); });
    };
    try {
      watchIdRef.current = navigator.geolocation.watchPosition(onPos, () => {}, { enableHighAccuracy: true, maximumAge: 0, timeout: 8000 });
    } catch { /* */ }
    return () => { if (watchIdRef.current !== null) navigator.geolocation.clearWatch(watchIdRef.current); };
  }, [weatherApiKey]);

  const tz = lw?.timezone || Intl.DateTimeFormat().resolvedOptions().timeZone || 'Asia/Karachi';
  const hour = getLocalHour(tz, now);
  const minute = getLocalMinute(tz, now);
  const second = getLocalSecond(tz, now);
  const hourFrac = hour + minute / 60;
  const tod: TOD = hour >= 6 && hour < 17 ? 'day' : hour < 20 ? 'evening' : 'night';
  const wmo = lw?.wmo ?? null;
  const skyBG = getSkyBG(tod, wmo);
  const skyBorder = getSkyBorder(tod, wmo);
  const skyType = getSkyType(tod, wmo);
  const clr = SKY_CLR[skyType];

  // ── Time string ────────────────────────────────────────────────
  const ampm = hour >= 12 ? 'PM' : 'AM';
  const h12 = hour % 12 || 12;
  const timeStr = `${h12}:${String(minute).padStart(2, '0')}:${String(second).padStart(2, '0')} ${ampm}`;

  // ── Calendar ──────────────────────────────────────────────────
  const localDate = getLocalDate(tz, now);
  const dateStr = now.toLocaleDateString('en-US', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric', timeZone: tz });
  const pastSunset = isPastSunset(tz, now, lw?.sunset ?? null);
  const hijriInputDate = pastSunset ? new Date(localDate.getTime() + 86400000) : localDate;
  const hijri = getHijri(hijriInputDate);
  const pun = getPunjabiMonth(localDate);

  // ── Weather label ─────────────────────────────────────────────
  const wLabel = wmo != null ? (WMO_LABELS[wmo] ?? '') : '';
  const weatherStr = lw?.temp != null ? `موجودہ موسم: ${lw.temp}°C (${wLabel})` : '';

  // ── Text shadow ───────────────────────────────────────────────
  const txtShadow: string = skyType === 'daySnow' ? 'none' : '0 1px 3px rgba(0,0,0,0.75), 0 0 6px rgba(0,0,0,0.4)';

  // ── LINE 1 builder (×4 copies for zero-gap loop) ──────────────
  const buildLine1 = (k: number) => (
    <span key={k} className="inline-flex items-center flex-shrink-0">
      <span style={{ color: clr.time, fontWeight: 800 }}>⏰&nbsp;{timeStr}</span>
      <Sep color={clr.div} />
      <span style={{ color: clr.l1 }}>📅&nbsp;{dateStr}</span>
      <Sep color={clr.div} />
      <span style={{ color: clr.hij }}>
        ☪️&nbsp;{hijri.d}&nbsp;{hijri.ur}&nbsp;{hijri.y}&nbsp;ہجری
        &nbsp;·&nbsp;{hijri.d}&nbsp;{hijri.en}&nbsp;{hijri.y}&nbsp;AH
        {pastSunset ? ' 🌅' : ''}
      </span>
      <Sep color={clr.div} />
      <span style={{ color: clr.pun }}>{pun.s}&nbsp;·&nbsp;{pun.n}&nbsp;کا مہینہ</span>
      <Sep color={clr.div} />
      <span style={{ color: clr.div, fontSize: '6px', opacity: 0.5, margin: '0 4px' }}>✦✦✦</span>
      <Sep color={clr.div} />
    </span>
  );

  // ── LINE 2 builder (×4 copies for zero-gap loop) ──────────────
  const buildLine2 = (k: number) => (
    <span key={k} className="inline-flex items-center flex-shrink-0" style={{ direction: 'rtl', unicodeBidi: 'embed' }}>
      {streetLoc?.full ? (
        <span style={{ color: clr.l2, fontWeight: 700 }}>🏠&nbsp;{streetLoc.full}</span>
      ) : (
        <span style={{ color: clr.l2, fontWeight: 700 }}>📍&nbsp;{lw?.city || 'مقام تلاش ہو رہا ہے...'}{lw?.region ? `، ${lw.region}` : ''}</span>
      )}
      {weatherStr && (
        <>
          <Sep color={clr.div} />
          <span style={{ color: clr.l1 }}>🌡️&nbsp;{weatherStr}</span>
        </>
      )}
      {lw?.humidity != null && (
        <>
          <Sep color={clr.div} />
          <span style={{ color: clr.hij }}>💦 نمی: {lw.humidity}%</span>
        </>
      )}
      {lw?.rainProb != null && lw.rainProb > 0 && (
        <>
          <Sep color={clr.div} />
          <span style={{ color: clr.pun }}>🌧️ بارش کا امکان: {lw.rainProb}%</span>
        </>
      )}
      {tod === 'night' && (
        <>
          <Sep color={clr.div} />
          <span style={{ color: '#818cf8', fontWeight: 700 }}>🌙 ستاروں بھری رات ✨</span>
        </>
      )}
      {tod === 'evening' && (
        <>
          <Sep color={clr.div} />
          <span style={{ color: '#fdba74', fontWeight: 700 }}>🌅 خوبصورت شام</span>
        </>
      )}
      <Sep color={clr.div} />
      <span style={{ color: clr.div, fontSize: '6px', opacity: 0.5, margin: '0 4px' }}>✦✦✦</span>
      <Sep color={clr.div} />
    </span>
  );

  return (
    <div
      className="shrink-0 select-none"
      style={{
        position: 'relative',
        height: '62px',
        display: 'flex',
        flexDirection: 'column',
        justifyContent: 'space-between',
        padding: '4px 0',
        background: skyBG,
        borderBottom: skyBorder,
        borderTop: skyBorder,
        borderRadius: '0',
        overflow: 'hidden',
        width: '100%',
        maxWidth: '100vw',
        transition: 'background 8s ease, border-color 8s ease',
      }}
      aria-label="Live global calendar, location and weather"
    >
      {/* ── Background: sky animations + sun/moon arc ── */}
      <SkyAnimationLayer tod={tod} wmo={wmo} hourFrac={hourFrac} cloudCover={lw?.cloudCover ?? null} />

      {/* ── LINE 1: Time · Gregorian · Hijri · Desi Month ── */}
      <div className="flex-1 overflow-hidden flex items-center" style={{ position: 'relative', zIndex: 1 }}>
        <div
          className="ticker-infinite text-[10px] font-bold"
          style={{ '--ticker-dur': '55s', textShadow: txtShadow } as CSSProperties}
        >
          {buildLine1(0)}{buildLine1(1)}{buildLine1(2)}{buildLine1(3)}
        </div>
      </div>

      {/* ── LINE 2: Urdu GPS location · Weather · Mood ── */}
      <div className="flex-1 overflow-hidden flex items-center" style={{ position: 'relative', zIndex: 1 }}>
        <div
          className="ticker-infinite-reverse text-[10px] font-semibold"
          style={{ '--ticker-dur': '65s', textShadow: txtShadow } as CSSProperties}
        >
          {buildLine2(0)}{buildLine2(1)}{buildLine2(2)}{buildLine2(3)}
        </div>
      </div>
    </div>
  );
}

src/components/PrayerAlertOverlay.tsx.content:
// ══════════════════════════════════════════════════════════════════
// PRAYER ALERT — Ultra-slim hidden row + full overlay
// 100% HIDDEN by default. Auto-reveals 5 min before Azan.
// Plays: Bismillah → Durood → Azan → Dua → Auto-vanish
// ══════════════════════════════════════════════════════════════════

import { useState, useEffect, useRef, useCallback } from 'react';
import { Volume2, VolumeX, X } from 'lucide-react';
import {
  calculatePrayerTimes,
  type PrayerSchedule,
  AZAN_TEXT_AR, AZAN_TEXT_EN,
  BISMILLAH_AR, BISMILLAH_EN,
  DUROOD_AR, DUROOD_EN,
  POST_AZAN_DUA_AR, POST_AZAN_DUA_EN,
} from '@/lib/prayerTimes';
import { speakText, stopTTS } from '@/lib/tts';
import { useAppData } from '@/contexts/AppDataContext';

type Phase = 'hidden' | 'bismillah' | 'durood' | 'azan' | 'dua' | 'blessing' | 'done';

const PHASE_LABELS: Record<Phase, { en: string; ur: string; icon: string }> = {
  hidden:    { en: '', ur: '', icon: '' },
  bismillah: { en: 'Bismillah-ir-Rahman-ir-Rahim', ur: 'بسم اللہ الرحمٰن الرحیم', icon: '🕌' },
  durood:    { en: 'Durood Shareef', ur: 'درود شریف', icon: '🌹' },
  azan:      { en: 'Azan — Call to Prayer', ur: 'اذان — نماز کی پکار', icon: '📢' },
  dua:       { en: 'Post-Azan Supplication', ur: 'اذان کے بعد کی دعا', icon: '🤲' },
  blessing:  { en: 'May Allah bless you', ur: 'اللہ آپ کو برکت دے', icon: '✨' },
  done:      { en: 'Complete', ur: 'مکمل', icon: '✅' },
};

function useGeoLocation() {
  const [coords, setCoords] = useState<{ lat: number; lon: number } | null>(null);
  useEffect(() => {
    if (!('geolocation' in navigator)) return;
    navigator.geolocation.getCurrentPosition(
      p => setCoords({ lat: p.coords.latitude, lon: p.coords.longitude }),
      () => setCoords({ lat: 30.3753, lon: 69.3451 }),
      { timeout: 5000, maximumAge: 300000, enableHighAccuracy: false }
    );
  }, []);
  return coords;
}

function useLanguageRegion(): 'ur' | 'en' {
  const [lang, setLang] = useState<'ur' | 'en'>('ur');
  useEffect(() => {
    const tz = Intl.DateTimeFormat().resolvedOptions().timeZone || '';
    const isUrdu = tz.includes('Karachi') || tz.includes('Pakistan') ||
      navigator.language.startsWith('ur') || navigator.language.startsWith('ar');
    setLang(isUrdu ? 'ur' : 'en');
  }, []);
  return lang;
}

export default function PrayerAlertOverlay() {
  const coords = useGeoLocation();
  const lang = useLanguageRegion();
  const [schedule, setSchedule] = useState<PrayerSchedule | null>(null);
  const [visible, setVisible] = useState(false);
  const [phase, setPhase] = useState<Phase>('hidden');
  const [activePrayer, setActivePrayer] = useState('');
  const [isSpeaking, setIsSpeaking] = useState(false);
  const [muted, setMuted] = useState(false);
  const [showSlimRow, setShowSlimRow] = useState(false);
  const alertFiredRef = useRef<string>('');
  const phaseRef = useRef<Phase>('hidden');
  phaseRef.current = phase;

  // Recalculate prayer times every 30s
  useEffect(() => {
    if (!coords) return;
    const calc = () => {
      const now = new Date();
      const tzOffset = -now.getTimezoneOffset() / 60;
      setSchedule(calculatePrayerTimes(coords.lat, coords.lon, now, tzOffset));
    };
    calc();
    const id = setInterval(calc, 30000);
    return () => clearInterval(id);
  }, [coords]);

  // Check 5-min trigger
  useEffect(() => {
    if (!schedule) return;
    const check = () => {
      if (!schedule.nextPrayer) return;
      const now = Date.now();
      const prayerTime = schedule.nextPrayer.time.getTime();
      const diffMin = (prayerTime - now) / 60000;
      const alertKey = `${schedule.nextPrayer.name}-${schedule.nextPrayer.time.toISOString().slice(0, 16)}`;

      if (diffMin <= 5 && diffMin > -2 && alertFiredRef.current !== alertKey && phaseRef.current === 'hidden') {
        alertFiredRef.current = alertKey;
        setActivePrayer(schedule.nextPrayer.name);
        setShowSlimRow(true);
        setVisible(true);
        setPhase('bismillah');
      }
    };
    check();
    const id = setInterval(check, 10000);
    return () => clearInterval(id);
  }, [schedule]);

  // Sequential audio phase player
  const playPhase = useCallback((p: Phase) => {
    if (muted || p === 'hidden' || p === 'done') {
      if (p === 'done') {
        setTimeout(() => {
          setVisible(false);
          setShowSlimRow(false);
          setPhase('hidden');
        }, 3000);
      }
      return;
    }

    setIsSpeaking(true);
    let text = '';
    let ttsLang = lang === 'ur' ? 'ar-SA' : 'en-US';

    switch (p) {
      case 'bismillah': text = lang === 'ur' ? BISMILLAH_AR : BISMILLAH_EN; break;
      case 'durood':    text = lang === 'ur' ? DUROOD_AR : DUROOD_EN; break;
      case 'azan':      text = lang === 'ur' ? AZAN_TEXT_AR : AZAN_TEXT_EN; break;
      case 'dua':       text = lang === 'ur' ? POST_AZAN_DUA_AR : POST_AZAN_DUA_EN; break;
      case 'blessing':
        text = lang === 'ur'
          ? `اللہ تعالیٰ آپ کی ${activePrayer} کی نماز قبول فرمائیں۔ آمین`
          : `May Allah accept your ${activePrayer} prayer. Ameen.`;
        ttsLang = lang === 'ur' ? 'ur-PK' : 'en-US';
        break;
    }

    speakText(text, ttsLang, () => {
      setIsSpeaking(false);
      const sequence: Phase[] = ['bismillah', 'durood', 'azan', 'dua', 'blessing', 'done'];
      const idx = sequence.indexOf(p);
      if (idx >= 0 && idx < sequence.length - 1) {
        setTimeout(() => setPhase(sequence[idx + 1]), 800);
      }
    });
  }, [muted, lang, activePrayer]);

  useEffect(() => {
    if (phase !== 'hidden') playPhase(phase);
  }, [phase, playPhase]);

  const handleDismiss = () => {
    stopTTS();
    setIsSpeaking(false);
    setVisible(false);
    setShowSlimRow(false);
    setPhase('hidden');
  };

  const toggleMute = () => {
    if (isSpeaking) stopTTS();
    setMuted(m => !m);
    setIsSpeaking(false);
  };

  // ══════════════════════════════════════════════════════════════
  // 100% HIDDEN when not active — returns nothing
  // ══════════════════════════════════════════════════════════════
  if (!showSlimRow && !visible) return null;

  // ── Ultra-slim prayer row (only visible during 5-min window) ──
  const slimRow = schedule ? (
    <div className="shrink-0 bg-primary/5 border-b border-primary/20 flex items-center gap-1 px-2 overflow-x-auto scrollbar-hide select-none animate-in slide-in-from-top-1 duration-300" style={{ height: '20px' }}>
      <span className="text-[7px] font-black text-primary shrink-0">🕌</span>
      {[schedule.fajr, schedule.dhuhr, schedule.asr, schedule.maghrib, schedule.isha, schedule.tahajjud].map(p => {
        const isNext = schedule.nextPrayer?.name === p.name;
        const timeStr = `${p.hours % 12 || 12}:${String(p.minutes).padStart(2, '0')}`;
        return (
          <span
            key={p.name}
            className={`text-[7px] font-mono shrink-0 px-1 rounded ${isNext ? 'bg-primary/20 text-primary font-black' : 'text-muted-foreground/70'}`}
          >
            {p.nameUr} {timeStr}
          </span>
        );
      })}
      {schedule.nextPrayer && schedule.minutesUntilNext > 0 && (
        <span className="text-[7px] font-black text-secondary shrink-0 ml-auto">
          ⏱{schedule.minutesUntilNext > 60 ? `${Math.floor(schedule.minutesUntilNext / 60)}h${schedule.minutesUntilNext % 60}m` : `${schedule.minutesUntilNext}m`}
        </span>
      )}
      {isSpeaking && (
        <span className="flex items-center gap-px shrink-0 ml-1">
          {[1,2,3,4,5].map(i => (
            <span key={i} className="w-[2px] bg-primary rounded-full" style={{ height: `${4 + Math.random() * 6}px`, animation: `prayer-wave 0.5s ${i * 0.08}s ease-in-out infinite alternate` }} />
          ))}
        </span>
      )}
    </div>
  ) : null;

  const phaseInfo = PHASE_LABELS[phase];

  return (
    <>
      {/* Ultra-slim top row */}
      {slimRow}

      {/* Full overlay when audio is playing */}
      {visible && phase !== 'hidden' && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-background/85 backdrop-blur-xl animate-in fade-in duration-500">
          <div className="w-full max-w-sm mx-4 bg-card border border-primary/30 rounded-3xl shadow-2xl overflow-hidden">
            <div className="bg-primary/10 border-b border-primary/20 px-5 py-4 flex items-center justify-between">
              <div className="flex items-center gap-3">
                <div className="w-10 h-10 rounded-2xl bg-primary/20 flex items-center justify-center text-lg">🕌</div>
                <div>
                  <p className="text-sm font-black text-foreground">{activePrayer} Prayer Alert</p>
                  <p className="text-[10px] text-muted-foreground">
                    {lang === 'ur' ? `${activePrayer} کی نماز کا وقت` : `Time for ${activePrayer} prayer`}
                  </p>
                </div>
              </div>
              <button onClick={handleDismiss} className="p-2 rounded-full hover:bg-muted transition-colors">
                <X size={18} className="text-muted-foreground" />
              </button>
            </div>

            <div className="px-5 py-6 text-center space-y-4">
              <div className="text-4xl">{phaseInfo.icon}</div>
              <div>
                <p className="text-lg font-black text-foreground">{phaseInfo.en}</p>
                <p className="text-base font-bold text-primary/80 mt-1" dir="rtl">{phaseInfo.ur}</p>
              </div>

              {isSpeaking && (
                <div className="flex items-center justify-center gap-1 h-8">
                  {Array.from({ length: 12 }).map((_, i) => (
                    <div
                      key={i}
                      className="w-1 bg-primary rounded-full"
                      style={{
                        height: `${12 + Math.random() * 20}px`,
                        animation: `prayer-wave 0.6s ${i * 0.05}s ease-in-out infinite alternate`,
                      }}
                    />
                  ))}
                </div>
              )}

              <div className="flex items-center gap-1 justify-center">
                {['bismillah', 'durood', 'azan', 'dua', 'blessing'].map((p, i) => (
                  <div
                    key={p}
                    className={`h-1.5 rounded-full transition-all duration-500 ${
                      phase === p ? 'w-8 bg-primary' :
                      ['bismillah', 'durood', 'azan', 'dua', 'blessing'].indexOf(phase) > i ? 'w-4 bg-primary/50' :
                      'w-4 bg-muted'
                    }`}
                  />
                ))}
              </div>
            </div>

            <div className="px-5 pb-5 flex items-center gap-3">
              <button
                onClick={toggleMute}
                className={`flex-1 flex items-center justify-center gap-2 py-2.5 rounded-xl text-sm font-bold transition-all ${
                  muted ? 'bg-muted text-muted-foreground' : 'bg-primary/10 text-primary border border-primary/20'
                }`}
              >
                {muted ? <VolumeX size={16} /> : <Volume2 size={16} />}
                {muted ? 'Unmute' : 'Audio On'}
              </button>
              <button
                onClick={handleDismiss}
                className="flex-1 py-2.5 rounded-xl text-sm font-bold bg-muted text-muted-foreground hover:text-foreground transition-colors"
              >
                Dismiss
              </button>
            </div>
          </div>
        </div>
      )}
    </>
  );
}

