import { useState } from 'react';
import { Download, ExternalLink, Copy, Check, X, FolderOpen, FileCode, Archive } from 'lucide-react';
import { toast } from 'sonner';
import { cn } from '@/lib/utils';

// ─── Types ────────────────────────────────────────────────────────
export interface ProjectFile { filename: string; language: string; code: string; }
export interface ParsedProject { projectName: string; files: ProjectFile[]; }

// ─── Language helpers ─────────────────────────────────────────────
function guessLang(filename: string): string {
  const ext = filename.split('.').pop()?.toLowerCase() ?? '';
  const m: Record<string, string> = {
    html: 'html', css: 'css', js: 'javascript', jsx: 'javascript',
    ts: 'typescript', tsx: 'typescript', py: 'python', php: 'php',
    java: 'java', sql: 'sql', json: 'json', md: 'markdown',
    sh: 'bash', rb: 'ruby', go: 'go', rs: 'rust', dart: 'dart',
    xml: 'xml', yml: 'yaml', yaml: 'yaml',
  };
  return m[ext] ?? 'text';
}

function langBadge(lang: string): string {
  const m: Record<string, string> = {
    html: 'bg-orange-500/20 text-orange-400 border-orange-500/30',
    css: 'bg-blue-500/20 text-blue-400 border-blue-500/30',
    javascript: 'bg-yellow-500/20 text-yellow-400 border-yellow-500/30',
    typescript: 'bg-sky-400/20 text-sky-300 border-sky-400/30',
    python: 'bg-green-500/20 text-green-400 border-green-500/30',
    java: 'bg-red-500/20 text-red-400 border-red-500/30',
    php: 'bg-violet-500/20 text-violet-400 border-violet-500/30',
    sql: 'bg-cyan-500/20 text-cyan-400 border-cyan-500/30',
    json: 'bg-gray-400/20 text-gray-300 border-gray-400/30',
    bash: 'bg-emerald-500/20 text-emerald-400 border-emerald-500/30',
    rust: 'bg-orange-600/20 text-orange-300 border-orange-600/30',
    go: 'bg-teal-500/20 text-teal-400 border-teal-500/30',
  };
  return m[lang] ?? 'bg-muted text-muted-foreground border-border';
}

function extMime(filename: string): string {
  const ext = filename.split('.').pop()?.toLowerCase() ?? '';
  const m: Record<string, string> = {
    html: 'text/html', css: 'text/css', js: 'text/javascript',
    ts: 'text/typescript', json: 'application/json', py: 'text/plain',
    php: 'text/plain', sql: 'text/plain', md: 'text/markdown',
  };
  return m[ext] ?? 'text/plain';
}

function lineCount(code: string): number {
  return (code.match(/\n/g) || []).length + 1;
}

function fileSizeKB(code: string): string {
  return (new TextEncoder().encode(code).length / 1024).toFixed(1);
}

// ─── Parser ───────────────────────────────────────────────────────
export function parseProjectFiles(content: string): ParsedProject | null {
  if (!content.includes('=== FILE')) return null;

  const projectNameMatch = content.match(/===\s*PROJECT:\s*(.+?)\s*===/);
  const projectName = projectNameMatch?.[1]?.trim() ?? 'Generated Project';

  const headerRe = /===\s*FILE\s+\d+:\s*(.+?)\s*===/g;
  const fileHeaders: string[] = [];
  let m: RegExpExecArray | null;
  while ((m = headerRe.exec(content)) !== null) fileHeaders.push(m[1].trim());

  if (fileHeaders.length === 0) return null;

  const segments = content.split(/===\s*FILE\s+\d+:\s*.+?\s*===/);

  const files: ProjectFile[] = fileHeaders.map((name, i) => {
    const raw = (segments[i + 1] ?? '').split(/===\s*END\s*PROJECT\s*===/)[0];
    const hit = raw.match(/```(\w*)?\n?([\s\S]*?)```/);
    const lang = (hit?.[1] ?? '').toLowerCase() || guessLang(name);
    const code = hit ? hit[2].trim() : raw.trim();
    return { filename: name, language: lang, code };
  }).filter(f => f.code.length > 4);

  return files.length > 0 ? { projectName, files } : null;
}

// ─── CRC32 ────────────────────────────────────────────────────────
const CRC_TABLE = (() => {
  const t = new Uint32Array(256);
  for (let i = 0; i < 256; i++) {
    let c = i;
    for (let j = 0; j < 8; j++) c = (c & 1) ? (0xEDB88320 ^ (c >>> 1)) : (c >>> 1);
    t[i] = c;
  }
  return t;
})();

function crc32(data: Uint8Array): number {
  let crc = 0xFFFFFFFF;
  for (const b of data) crc = (crc >>> 8) ^ CRC_TABLE[(crc ^ b) & 0xFF];
  return (crc ^ 0xFFFFFFFF) >>> 0;
}

// ─── ZIP builder (pure TS, no external libs) ──────────────────────
function buildZip(files: { name: string; content: string }[]): Uint8Array {
  const enc = new TextEncoder();
  const locals: Uint8Array[] = [];
  const centrals: Uint8Array[] = [];
  let offset = 0;

  for (const f of files) {
    const nb = enc.encode(f.name);
    const db = enc.encode(f.content);
    const crc = crc32(db);

    const loc = new Uint8Array(30 + nb.length + db.length);
    const lv = new DataView(loc.buffer);
    lv.setUint32(0, 0x04034b50, true); lv.setUint16(4, 20, true);
    lv.setUint16(6, 0, true); lv.setUint16(8, 0, true);
    lv.setUint16(10, 0, true); lv.setUint16(12, 0, true);
    lv.setUint32(14, crc, true); lv.setUint32(18, db.length, true);
    lv.setUint32(22, db.length, true); lv.setUint16(26, nb.length, true);
    lv.setUint16(28, 0, true);
    loc.set(nb, 30); loc.set(db, 30 + nb.length);
    locals.push(loc);

    const cen = new Uint8Array(46 + nb.length);
    const cv = new DataView(cen.buffer);
    cv.setUint32(0, 0x02014b50, true); cv.setUint16(4, 20, true);
    cv.setUint16(6, 20, true); cv.setUint16(8, 0, true);
    cv.setUint16(10, 0, true); cv.setUint16(12, 0, true); cv.setUint16(14, 0, true);
    cv.setUint32(16, crc, true); cv.setUint32(20, db.length, true);
    cv.setUint32(24, db.length, true); cv.setUint16(28, nb.length, true);
    cv.setUint16(30, 0, true); cv.setUint16(32, 0, true); cv.setUint16(34, 0, true);
    cv.setUint16(36, 0, true); cv.setUint32(38, 0, true); cv.setUint32(42, offset, true);
    cen.set(nb, 46);
    centrals.push(cen);
    offset += loc.length;
  }

  const cdSize = centrals.reduce((s, h) => s + h.length, 0);
  const end = new Uint8Array(22);
  const ev = new DataView(end.buffer);
  ev.setUint32(0, 0x06054b50, true); ev.setUint16(4, 0, true);
  ev.setUint16(6, 0, true); ev.setUint16(8, files.length, true);
  ev.setUint16(10, files.length, true); ev.setUint32(12, cdSize, true);
  ev.setUint32(16, offset, true); ev.setUint16(20, 0, true);

  const total = locals.reduce((s, h) => s + h.length, 0) + cdSize + end.length;
  const zip = new Uint8Array(total);
  let pos = 0;
  for (const h of locals) { zip.set(h, pos); pos += h.length; }
  for (const h of centrals) { zip.set(h, pos); pos += h.length; }
  zip.set(end, pos);
  return zip;
}

// ─── HTML bundle (inlines CSS + JS into single file) ─────────────
function buildHtmlBundle(files: ProjectFile[], projectName: string): string {
  const htmlFile = files.find(f => f.language === 'html' || f.filename.endsWith('.html'));
  const cssFiles = files.filter(f => f.language === 'css' || f.filename.endsWith('.css'));
  const jsFiles = files.filter(f =>
    f.language === 'javascript' || f.language === 'typescript' ||
    f.filename.endsWith('.js') || f.filename.endsWith('.ts')
  );

  if (!htmlFile) {
    const escaped = files.map(f =>
      '<h2>' + f.filename + '</h2><pre><code>' +
      f.code.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;') +
      '</code></pre>'
    ).join('');
    return '<!DOCTYPE html><html lang="en"><head>' +
      '<meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1">' +
      '<title>' + projectName + '</title>' +
      '<style>body{font-family:monospace;background:#0d1117;color:#e6edf3;padding:24px}' +
      'h1{color:#58a6ff}h2{color:#7ee787;margin-top:30px}' +
      'pre{background:#161b22;border:1px solid #30363d;border-radius:8px;padding:16px;overflow-x:auto;font-size:13px}</style>' +
      '</head><body><h1>📁 ' + projectName + '</h1>' + escaped + '</body></html>';
  }

  let doc = htmlFile.code;
  for (const css of cssFiles) {
    const re = new RegExp('<link[^>]*href=["\'][^"\']*' + css.filename.replace(/\./g, '\\.') + '["\'][^>]*/?>',  'gi');
    const inlined = '<style>/* ' + css.filename + ' */\n' + css.code + '\n</style>';
    const next = doc.replace(re, inlined);
    doc = next !== doc ? next : doc.replace('</head>', inlined + '\n</head>');
  }
  for (const js of jsFiles) {
    const re = new RegExp('<script[^>]*src=["\'][^"\']*' + js.filename.replace(/\./g, '\\.') + '["\'][^>]*></script>', 'gi');
    const inlined = '<script>/* ' + js.filename + ' */\n' + js.code + '\n</script>';
    const next = doc.replace(re, inlined);
    doc = next !== doc ? next : doc.replace('</body>', inlined + '\n</body>');
  }
  return doc;
}

// ─── Download helper ──────────────────────────────────────────────
function triggerDownload(data: Uint8Array | string, filename: string, mime: string) {
  const blobPart: BlobPart = data instanceof Uint8Array ? (data.buffer as ArrayBuffer) : data;
  const blob = new Blob([blobPart], { type: mime });
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url; a.download = filename; a.click();
  setTimeout(() => URL.revokeObjectURL(url), 5000);
}

// ─── Main Component ───────────────────────────────────────────────
interface Props { project: ParsedProject; msgId: string; }

export function CodeProjectView({ project, msgId }: Props) {
  const [activeTab, setActiveTab] = useState(0);
  const [previewOpen, setPreviewOpen] = useState(false);
  const [copiedId, setCopiedId] = useState<string | null>(null);

  const activeFile = project.files[activeTab];
  const hasWeb = project.files.some(f => f.language === 'html' || f.filename.endsWith('.html'));
  const slug = project.projectName.toLowerCase().replace(/\s+/g, '-').replace(/[^a-z0-9-]/g, '');

  const downloadZip = () => {
    const zip = buildZip(project.files.map(f => ({ name: f.filename, content: f.code })));
    triggerDownload(zip, slug + '.zip', 'application/zip');
    toast.success('📦 ZIP downloaded — ' + project.files.length + ' files ready!');
  };

  const downloadBundle = () => {
    const html = buildHtmlBundle(project.files, project.projectName);
    triggerDownload(html, slug + '-bundle.html', 'text/html');
    toast.success('🌐 HTML bundle downloaded — open in any browser!');
  };

  const downloadFile = (f: ProjectFile) => {
    triggerDownload(f.code, f.filename, extMime(f.filename));
    toast.success('💾 ' + f.filename + ' saved');
  };

  const copyFile = (f: ProjectFile, id: string) => {
    navigator.clipboard.writeText(f.code);
    setCopiedId(id); setTimeout(() => setCopiedId(null), 2000);
    toast.success('📋 ' + f.filename + ' copied');
  };

  const previewHtml = hasWeb ? buildHtmlBundle(project.files, project.projectName) : '';

  return (
    <div className="rounded-2xl border border-primary/25 bg-card overflow-hidden w-full">
      {/* Header */}
      <div className="flex items-center gap-2 px-3 py-2 bg-primary/10 border-b border-primary/15">
        <FolderOpen size={13} className="text-primary shrink-0" />
        <span className="text-xs font-black text-primary truncate flex-1">{project.projectName}</span>
        <span className="text-[9px] text-muted-foreground bg-muted border border-border rounded-full px-2 py-0.5 shrink-0">
          {project.files.length} {project.files.length === 1 ? 'file' : 'files'}
        </span>
        {hasWeb && (
          <button onClick={() => setPreviewOpen(true)}
            className="flex items-center gap-1 text-[9px] font-bold text-secondary border border-secondary/30 bg-secondary/10 px-2 py-1 rounded-lg hover:bg-secondary/20 transition-colors shrink-0">
            <ExternalLink size={9} /> Live Preview
          </button>
        )}
      </div>

      {/* File tabs */}
      <div className="flex overflow-x-auto border-b border-border bg-muted/20" style={{ scrollbarWidth: 'none' }}>
        {project.files.map((f, i) => (
          <button key={msgId + '-tab-' + i} onClick={() => setActiveTab(i)}
            className={cn(
              'flex items-center gap-1.5 px-3 py-2 text-[10px] font-medium whitespace-nowrap border-r border-border/40 transition-colors shrink-0',
              activeTab === i
                ? 'bg-card text-foreground border-b-2 border-b-primary -mb-px'
                : 'text-muted-foreground hover:text-foreground hover:bg-muted/40'
            )}>
            <FileCode size={9} className={activeTab === i ? 'text-primary' : 'text-muted-foreground'} />
            {f.filename}
          </button>
        ))}
      </div>

      {/* Active file */}
      {activeFile && (
        <div>
          <div className="flex items-center justify-between gap-2 px-3 py-1.5 bg-muted/10 border-b border-border/40">
            <div className="flex items-center gap-2">
              <span className={cn('text-[9px] font-bold border rounded-full px-2 py-0.5', langBadge(activeFile.language))}>
                {activeFile.language || 'text'}
              </span>
              <span className="text-[9px] text-muted-foreground">
                {lineCount(activeFile.code)} lines &middot; {fileSizeKB(activeFile.code)}KB
              </span>
            </div>
            <div className="flex items-center gap-1.5">
              {/* Mobile-optimized COPY button — large touch target */}
              <button onClick={() => copyFile(activeFile, msgId + '-copy-' + activeTab)}
                className={`flex items-center gap-1.5 text-xs font-bold px-3 py-2 rounded-lg border transition-all active:scale-95 min-h-[40px] ${
                  copiedId === msgId + '-copy-' + activeTab
                    ? 'bg-primary/20 text-primary border-primary/40'
                    : 'bg-primary/10 text-primary border-primary/30 hover:bg-primary/20'
                }`}>
                {copiedId === msgId + '-copy-' + activeTab
                  ? <Check size={13} className="text-primary" />
                  : <Copy size={13} />}
                {copiedId === msgId + '-copy-' + activeTab ? '✓ Copied!' : '📋 Copy Code'}
              </button>
              <button onClick={() => downloadFile(activeFile)}
                className="flex items-center gap-1 text-xs text-muted-foreground hover:text-foreground px-2.5 py-2 rounded-lg hover:bg-muted/60 transition-colors min-h-[40px] border border-transparent hover:border-border">
                <Download size={12} /> Save
              </button>
            </div>
          </div>

          {/* Code display — mobile-optimized: horizontal scroll, readable size */}
          <div className="overflow-auto max-h-80 bg-black/70" style={{ WebkitOverflowScrolling: 'touch' }}>
            <pre className="p-4 text-[12px] sm:text-[11.5px] font-mono leading-relaxed text-green-100 whitespace-pre select-text" style={{ minWidth: 'max-content' }}>
              <code>{activeFile.code}</code>
            </pre>
          </div>
        </div>
      )}

      {/* Download bar */}
      <div className="flex items-center gap-2 px-3 py-2.5 border-t border-border bg-muted/20 flex-wrap">
        <span className="text-[9px] text-muted-foreground font-semibold">Download:</span>
        <button onClick={downloadZip}
          className="flex items-center gap-1.5 text-[10px] font-bold text-primary border border-primary/40 bg-primary/10 px-3 py-1.5 rounded-lg hover:bg-primary/20 transition-all shadow-sm shadow-primary/20 hover:shadow-primary/40">
          <Archive size={10} /> 📦 Complete ZIP
        </button>
        {hasWeb && (
          <button onClick={downloadBundle}
            className="flex items-center gap-1.5 text-[10px] font-bold text-secondary border border-secondary/30 bg-secondary/10 px-3 py-1.5 rounded-lg hover:bg-secondary/20 transition-colors">
            <Download size={10} /> 🌐 HTML Bundle
          </button>
        )}
        <span className="text-[8px] text-muted-foreground/50 ml-auto hidden sm:block">
          {project.files.map(f => f.filename).join(' · ')}
        </span>
      </div>

      {/* Live Preview Modal */}
      {previewOpen && (
        <div className="fixed inset-0 z-50 bg-black/95 flex flex-col">
          <div className="flex items-center gap-2 px-4 py-2.5 bg-card border-b border-border shrink-0">
            <div className="flex items-center gap-1.5">
              <div className="w-2.5 h-2.5 rounded-full bg-destructive" />
              <div className="w-2.5 h-2.5 rounded-full bg-yellow-400" />
              <div className="w-2.5 h-2.5 rounded-full bg-green-400" />
            </div>
            <span className="text-xs font-bold ml-2 text-primary">Live Preview — {project.projectName}</span>
            <div className="ml-auto flex items-center gap-2">
              <button onClick={downloadBundle}
                className="flex items-center gap-1 text-[10px] font-bold text-primary border border-primary/30 bg-primary/10 px-2.5 py-1 rounded-lg hover:bg-primary/20 transition-colors">
                <Download size={9} /> Bundle
              </button>
              <button onClick={downloadZip}
                className="flex items-center gap-1 text-[10px] font-bold text-secondary border border-secondary/30 bg-secondary/10 px-2.5 py-1 rounded-lg hover:bg-secondary/20 transition-colors">
                <Archive size={9} /> ZIP
              </button>
              <button onClick={() => setPreviewOpen(false)}
                className="text-muted-foreground hover:text-foreground p-1 ml-1">
                <X size={18} />
              </button>
            </div>
          </div>
          <iframe
            srcDoc={previewHtml}
            sandbox="allow-scripts allow-forms allow-same-origin allow-modals"
            className="flex-1 w-full bg-white"
            title="Live App Preview"
          />
        </div>
      )}
    </div>
  );
}

