import { Copy, Share2, Users, TrendingUp, ExternalLink, MessageCircle, Send, DollarSign } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { toast } from 'sonner';

interface Props {
  referralCode: string | null;
  totalReferrals: number;
  level: number;
  totalCommissionEarned?: number;
  onViewTeam: () => void;
  onViewLevels: () => void;
}

export default function ReferralSection({
  referralCode,
  totalReferrals,
  level,
  totalCommissionEarned = 0,
  onViewTeam,
  onViewLevels,
}: Props) {
  // Always point to root so the module-level referral capture IIFE
  // fires before any React mount (survives loginWithRedirect URL wipe)
  const refLink = referralCode ? `${window.location.origin}/?ref=${referralCode}` : '';
  const shareMsg = `🚀 Hussain AI - Master Engine — AI tools + earn real money!\nUse my referral code: *${referralCode}*\nJoin here: ${refLink}`;

  const copyLink = () => {
    if (!refLink) { toast.error('Set up your profile first'); return; }
    navigator.clipboard.writeText(refLink).then(() => toast.success('✅ Referral link copied!'));
  };

  const copyCode = () => {
    if (!referralCode) return;
    navigator.clipboard.writeText(referralCode).then(() => toast.success('✅ Code copied!'));
  };

  const shareWhatsApp = () => {
    if (!refLink) { toast.error('Set up your profile first'); return; }
    window.open(`https://wa.me/?text=${encodeURIComponent(shareMsg)}`, '_blank');
  };

  const shareTelegram = () => {
    if (!refLink) { toast.error('Set up your profile first'); return; }
    window.open(`https://t.me/share/url?url=${encodeURIComponent(refLink)}&text=${encodeURIComponent('🚀 Hussain AI — Join & earn real money!')}`, '_blank');
  };

  const shareNative = () => {
    if (!refLink) { toast.error('Set up your profile first'); return; }
    if (typeof navigator.share === 'function') {
      navigator.share({ title: 'Join Hussain AI!', text: shareMsg, url: refLink })
        .catch(e => { if (e?.name !== 'AbortError') copyLink(); });
    } else {
      copyLink();
    }
  };

  return (
    <div className="px-4 space-y-3">
      {/* Commission earned summary */}
      {totalCommissionEarned > 0 && (
        <div className="flex items-center gap-2 bg-green-500/10 border border-green-500/25 rounded-xl px-3 py-2">
          <DollarSign size={13} className="text-green-400 shrink-0" />
          <p className="text-[11px] text-muted-foreground">
            Total referral commission earned:{' '}
            <span className="text-green-400 font-bold">${totalCommissionEarned.toFixed(4)} USD</span>
          </p>
        </div>
      )}

      <div className="card-gold rounded-2xl p-4 space-y-3">
        <h3 className="font-semibold text-sm flex items-center gap-1.5">
          <Share2 size={14} className="text-primary" /> Your Permanent Referral Link
        </h3>

        {referralCode ? (
          <>
            {/* Full link display */}
            <div className="bg-muted/60 rounded-xl px-3 py-2 flex items-center gap-2 overflow-hidden border border-border">
              <ExternalLink size={11} className="text-muted-foreground shrink-0" />
              <p className="text-xs text-muted-foreground truncate flex-1 font-mono">{refLink}</p>
              <button onClick={copyLink} className="shrink-0 text-primary hover:text-primary/80 p-0.5">
                <Copy size={14} />
              </button>
            </div>

            {/* Code + copy row */}
            <div className="flex gap-2">
              <div className="flex-1 bg-primary/10 border border-primary/30 rounded-xl px-3 py-2 flex items-center justify-between">
                <div>
                  <p className="text-[9px] text-muted-foreground uppercase tracking-wide mb-0.5">Your Code</p>
                  <span className="text-sm font-mono font-black text-primary">{referralCode}</span>
                </div>
                <button onClick={copyCode} className="text-primary hover:text-primary/80 ml-2 p-1 bg-primary/10 rounded-lg">
                  <Copy size={12} />
                </button>
              </div>
              <Button size="sm" onClick={shareNative} className="bg-primary text-primary-foreground gap-1.5 text-xs font-semibold self-stretch">
                <Share2 size={12} /> Share
              </Button>
            </div>

            {/* Quick-share row — WhatsApp + Telegram */}
            <div className="grid grid-cols-2 gap-2">
              <button
                onClick={shareWhatsApp}
                className="flex items-center justify-center gap-1.5 rounded-xl border border-border py-2 text-xs font-semibold text-foreground hover:bg-muted/60 transition-colors"
              >
                <MessageCircle size={13} className="text-green-400" />
                WhatsApp
              </button>
              <button
                onClick={shareTelegram}
                className="flex items-center justify-center gap-1.5 rounded-xl border border-border py-2 text-xs font-semibold text-foreground hover:bg-muted/60 transition-colors"
              >
                <Send size={13} className="text-sky-400" />
                Telegram
              </button>
            </div>

            <p className="text-[10px] text-muted-foreground text-center">
              🔗 Code permanently embedded · Zero manual entry · Coins auto-credited
            </p>
          </>
        ) : (
          <div className="text-center py-3 text-muted-foreground">
            <p className="text-xs">Complete profile setup to get your referral link</p>
          </div>
        )}
      </div>

      {/* Stats grid */}
      <div className="grid grid-cols-2 gap-3">
        <button onClick={onViewTeam} className="card-dark rounded-2xl p-4 text-center hover:border-primary/40 transition-colors">
          <Users size={22} className="text-primary mx-auto mb-1.5" />
          <p className="text-xl font-bold text-primary">{totalReferrals}</p>
          <p className="text-xs text-muted-foreground">Team Members</p>
        </button>
        <button onClick={onViewLevels} className="card-dark rounded-2xl p-4 text-center hover:border-secondary/40 transition-colors">
          <TrendingUp size={22} className="text-secondary mx-auto mb-1.5" />
          <p className="text-xl font-bold text-secondary">Level {level}</p>
          <p className="text-xs text-muted-foreground">View Level Map →</p>
        </button>
      </div>
    </div>
  );
}

src/components/wallet/WithdrawalModal.ts.content:
import { useState } from 'react';
import { Dialog, DialogContent, DialogHeader, DialogTitle } from '@/components/ui/dialog';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Button } from '@/components/ui/button';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { submitWithdrawal } from 'zite-endpoints-sdk';
import { toast } from 'sonner';
import { Banknote, Info } from 'lucide-react';

const METHODS = ['Easypaisa', 'JazzCash', 'NayaPay', 'SadaPay', 'Crypto USDT-TRC20', 'Bank Transfer'];

interface Props {
  open: boolean;
  onClose: () => void;
  usdBalance: number;
  onSuccess: () => void;
  minWithdrawUsd?: number;
}

export default function WithdrawalModal({ open, onClose, usdBalance, onSuccess, minWithdrawUsd = 1 }: Props) {
  const [amount, setAmount] = useState('');
  const [method, setMethod] = useState('');
  const [account, setAccount] = useState('');
  const [name, setName] = useState('');
  const [loading, setLoading] = useState(false);

  const minUsd = minWithdrawUsd;
  const canWithdraw = usdBalance >= minUsd;

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    const amt = parseFloat(amount);
    if (isNaN(amt) || amt < minUsd) {
      toast.error(`Minimum withdrawal is $${minUsd.toFixed(2)}`);
      return;
    }
    if (amt > usdBalance) { toast.error('Insufficient balance'); return; }
    if (!method) { toast.error('Select withdrawal method'); return; }
    if (!account.trim()) { toast.error('Enter account number/address'); return; }
    if (!name.trim()) { toast.error('Enter account name'); return; }

    setLoading(true);
    try {
      await submitWithdrawal({ amountUsd: amt, method, accountNumber: account.trim(), accountName: name.trim() });
      toast.success('✅ Withdrawal request submitted! Admin will process within 24hrs.');
      onSuccess();
      onClose();
    } catch (err: any) {
      toast.error(err?.message ?? 'Submission failed');
    } finally {
      setLoading(false);
    }
  };

  const accountLabel = method.includes('Crypto') ? 'USDT-TRC20 Wallet Address' : method === 'Bank Transfer' ? 'IBAN / Account Number' : 'Account Number (e.g. 0300-0000000)';

  return (
    <Dialog open={open} onOpenChange={onClose}>
      <DialogContent className="bg-card border-border max-w-sm">
        <DialogHeader>
          <div className="flex justify-center mb-2">
            <div className="bg-green-500/20 rounded-2xl p-3">
              <Banknote className="text-green-400" size={28} />
            </div>
          </div>
          <DialogTitle className="text-center">Withdraw Earnings</DialogTitle>
          <p className="text-center text-sm text-muted-foreground">
            Available: <span className="text-green-400 font-bold">${usdBalance.toFixed(2)}</span>
          </p>
        </DialogHeader>

        {/* Min limit info badge */}
        <div className="flex items-center gap-2 bg-primary/5 border border-primary/20 rounded-xl px-3 py-2">
          <Info size={12} className="text-primary shrink-0" />
          <p className="text-[11px] text-muted-foreground">
            Minimum withdrawal: <span className="text-primary font-bold">${minUsd.toFixed(2)}</span>
            {' '}· 1,000 Coins = $1 USD
          </p>
        </div>

        {!canWithdraw ? (
          <div className="text-center py-4 space-y-2">
            <p className="text-sm text-muted-foreground">
              You need at least <span className="text-primary font-bold">${minUsd.toFixed(2)}</span> to withdraw.
            </p>
            <p className="text-xs text-muted-foreground">Keep earning through referrals to reach the minimum!</p>
          </div>
        ) : (
          <form onSubmit={handleSubmit} className="space-y-3 mt-1">
            <div className="space-y-1.5">
              <Label className="text-xs">Amount (USD)</Label>
              <Input
                type="number"
                placeholder={`Min $${minUsd.toFixed(2)}`}
                min={minUsd}
                step="0.01"
                max={usdBalance}
                value={amount}
                onChange={e => setAmount(e.target.value)}
                className="bg-muted border-border"
              />
            </div>
            <div className="space-y-1.5">
              <Label className="text-xs">Payment Method</Label>
              <Select value={method} onValueChange={setMethod}>
                <SelectTrigger className="bg-muted border-border"><SelectValue placeholder="Select method..." /></SelectTrigger>
                <SelectContent className="bg-card border-border">
                  {METHODS.map(m => <SelectItem key={m} value={m}>{m}</SelectItem>)}
                </SelectContent>
              </Select>
            </div>
            {method && (
              <>
                <div className="space-y-1.5">
                  <Label className="text-xs">{accountLabel}</Label>
                  <Input
                    placeholder={method.includes('Crypto') ? 'TRC20 address...' : '03XX-XXXXXXX'}
                    value={account}
                    onChange={e => setAccount(e.target.value)}
                    className="bg-muted border-border text-sm"
                  />
                </div>
                <div className="space-y-1.5">
                  <Label className="text-xs">Account Holder Name (for verification)</Label>
                  <Input
                    placeholder="Apna naam likhein"
                    value={name}
                    onChange={e => setName(e.target.value)}
                    className="bg-muted border-border text-sm"
                  />
                </div>
              </>
            )}
            <Button type="submit" disabled={loading} className="w-full bg-green-600 hover:bg-green-600/90 text-white font-bold">
              {loading ? 'Submitting...' : '💸 Submit Withdrawal Request'}
            </Button>
          </form>
        )}
      </DialogContent>
    </Dialog>
  );
}

