// ── Emoji flag from ISO2 ─────────────────────────────────────────
function isoToFlag(iso: string): string {
  return iso
    .toUpperCase()
    .split('')
    .map(c => String.fromCodePoint(0x1f1e6 + c.charCodeAt(0) - 65))
    .join('');
}

interface Props {
  value: string;
  onChange: (fullNumber: string) => void;
  className?: string;
}

export default function InternationalPhoneInput({ value, onChange, className }: Props) {
  // Parse initial value to find matching country
  const initialCountry = useMemo(() => {
    if (!value) return COUNTRIES[0]; // Pakistan default
    for (const c of COUNTRIES) {
      if (value.startsWith(c[2])) return c;
    }
    return COUNTRIES[0];
  }, []);

  const [country, setCountry] = useState<CountryEntry>(initialCountry);
  const [localNumber, setLocalNumber] = useState(() => {
    if (!value) return '';
    const code = initialCountry[2];
    return value.startsWith(code) ? value.slice(code.length).replace(/\D/g, '') : value.replace(/\D/g, '');
  });
  const [open, setOpen] = useState(false);
  const [search, setSearch] = useState('');
  const dropdownRef = useRef<HTMLDivElement>(null);
  const searchRef = useRef<HTMLInputElement>(null);

  // Close dropdown on outside click
  useEffect(() => {
    if (!open) return;
    const handler = (e: MouseEvent) => {
      if (dropdownRef.current && !dropdownRef.current.contains(e.target as Node)) {
        setOpen(false);
      }
    };
    document.addEventListener('mousedown', handler);
    return () => document.removeEventListener('mousedown', handler);
  }, [open]);

  // Focus search when opened
  useEffect(() => {
    if (open) setTimeout(() => searchRef.current?.focus(), 50);
  }, [open]);

  const filtered = useMemo(() => {
    if (!search) return COUNTRIES;
    const q = search.toLowerCase();
    return COUNTRIES.filter(c =>
      c[1].toLowerCase().includes(q) || c[2].includes(q) || c[0].includes(q)
    );
  }, [search]);

  const handleNumberChange = (raw: string) => {
    const digits = raw.replace(/\D/g, '').slice(0, country[4]); // maxDigits
    setLocalNumber(digits);
    onChange(digits ? `${country[2]}${digits}` : '');
  };

  const handleSelectCountry = (c: CountryEntry) => {
    setCountry(c);
    setOpen(false);
    setSearch('');
    // Re-emit with new country code
    const trimmed = localNumber.slice(0, c[4]);
    setLocalNumber(trimmed);
    onChange(trimmed ? `${c[2]}${trimmed}` : '');
  };

  const isValid = localNumber.length === 0 || (localNumber.length >= country[3] && localNumber.length <= country[4]);

  return (
    <div className={`relative ${className ?? ''}`} ref={dropdownRef}>
      <div className={`flex items-center bg-muted border rounded-md h-9 transition-colors ${
        !isValid ? 'border-destructive' : 'border-border focus-within:border-primary'
      }`}>
        {/* Country selector button */}
        <button
          type="button"
          onClick={() => setOpen(!open)}
          className="flex items-center gap-1 px-2 h-full border-r border-border/60 shrink-0 hover:bg-muted/80 transition-colors rounded-l-md"
        >
          <span className="text-base leading-none">{isoToFlag(country[0])}</span>
          <span className="text-[11px] font-semibold text-foreground">{country[2]}</span>
          <ChevronDown size={10} className="text-muted-foreground" />
        </button>

        {/* Number input */}
        <input
          type="tel"
          inputMode="numeric"
          autoComplete="tel-national"
          placeholder={`${'0'.repeat(country[3])} (${country[3]} digits)`}
          value={localNumber}
          onChange={e => handleNumberChange(e.target.value)}
          className="flex-1 h-full bg-transparent text-sm px-2.5 outline-none placeholder:text-muted-foreground/50 text-foreground"
        />
      </div>

      {/* Validation hint */}
      {localNumber.length > 0 && !isValid && (
        <p className="text-[9px] text-destructive mt-0.5 px-1">
          {country[1]} numbers need {country[3] === country[4] ? country[3] : `${country[3]}-${country[4]}`} digits
        </p>
      )}

      {/* Country dropdown */}
      {open && (
        <div className="absolute top-full left-0 right-0 z-[60] mt-1 bg-card border border-border rounded-lg shadow-xl max-h-[240px] flex flex-col overflow-hidden animate-in fade-in-0 slide-in-from-top-1 duration-150">
          {/* Search */}
          <div className="p-2 border-b border-border/60 shrink-0">
            <div className="flex items-center gap-1.5 bg-muted rounded-md px-2 h-7">
              <Search size={11} className="text-muted-foreground shrink-0" />
              <input
                ref={searchRef}
                type="text"
                placeholder="Search country..."
                value={search}
                onChange={e => setSearch(e.target.value)}
                className="flex-1 bg-transparent text-xs outline-none placeholder:text-muted-foreground/50 text-foreground"
              />
            </div>
          </div>

          {/* Country list */}
          <div className="overflow-y-auto overscroll-contain flex-1">
            {filtered.length === 0 && (
              <p className="text-xs text-muted-foreground text-center py-3">No countries found</p>
            )}
            {filtered.map(c => (
              <button
                key={c[0] + c[2]}
                type="button"
                onClick={() => handleSelectCountry(c)}
                className={`w-full flex items-center gap-2 px-3 py-1.5 text-left hover:bg-muted/80 transition-colors ${
                  c[0] === country[0] ? 'bg-primary/10' : ''
                }`}
              >
                <span className="text-sm leading-none">{isoToFlag(c[0])}</span>
                <span className="text-[11px] text-foreground flex-1 truncate">{c[1]}</span>
                <span className="text-[10px] text-muted-foreground font-mono">{c[2]}</span>
              </button>
            ))}
          </div>
        </div>
      )}
    </div>
  );
}

