import { useEffect, useState } from 'react';
import { getTransactionHistory, GetTransactionHistoryOutputType } from 'zite-endpoints-sdk';
import { format } from 'date-fns';
import { ArrowDownLeft, ArrowUpRight, RefreshCw, Loader2, Clock, CheckCircle2, XCircle, Coins } from 'lucide-react';
import { Badge } from '@/components/ui/badge';
import { Button } from '@/components/ui/button';
import { Skeleton } from '@/components/ui/skeleton';

type Tx = GetTransactionHistoryOutputType['transactions'][0];

function StatusBadge({ status }: { status: string }) {
  if (status === 'Success' || status === 'Approved') {
    return <Badge className="text-[9px] h-4 px-1.5 bg-emerald-500/15 text-emerald-600 border-emerald-500/30 gap-0.5"><CheckCircle2 size={8} /> {status}</Badge>;
  }
  if (status === 'Rejected') {
    return <Badge className="text-[9px] h-4 px-1.5 bg-destructive/15 text-destructive border-destructive/30 gap-0.5"><XCircle size={8} /> {status}</Badge>;
  }
  return <Badge className="text-[9px] h-4 px-1.5 bg-amber-500/15 text-amber-600 border-amber-500/30 gap-0.5"><Clock size={8} /> Pending</Badge>;
}

function TxRow({ tx }: { tx: Tx }) {
  const isCredit = tx.type === 'referral_credit';
  const ts = new Date(tx.timestamp);

  return (
    <div className={`flex items-center gap-3 px-3 py-2.5 rounded-xl border transition-colors ${
      isCredit
        ? 'bg-emerald-500/5 border-emerald-500/15 hover:bg-emerald-500/10'
        : 'bg-card border-border hover:bg-muted/50'
    }`}>
      {/* Icon */}
      <div className={`w-8 h-8 rounded-full flex items-center justify-center shrink-0 ${
        isCredit ? 'bg-emerald-500/20 text-emerald-500' : 'bg-primary/10 text-primary'
      }`}>
        {isCredit ? <ArrowDownLeft size={14} /> : <ArrowUpRight size={14} />}
      </div>

      {/* Details */}
      <div className="flex-1 min-w-0">
        <div className="flex items-center gap-1.5 flex-wrap">
          <p className="text-xs font-medium text-foreground truncate">
            {isCredit ? 'Referral Coin Credit' : 'Withdrawal Request'}
          </p>
          <StatusBadge status={tx.status} />
        </div>
        <p className="text-[10px] text-muted-foreground truncate mt-0.5">{tx.description}</p>
        {tx.referredEmail && (
          <p className="text-[9px] text-muted-foreground/60 truncate">via: {tx.referredEmail}</p>
        )}
      </div>

      {/* Amount + Time */}
      <div className="text-right shrink-0">
        {isCredit ? (
          <p className="text-sm font-bold text-emerald-500">+{tx.coinsAmount} 🪙</p>
        ) : (
          <p className="text-sm font-bold text-primary">-${tx.usdAmount?.toFixed(2)}</p>
        )}
        <p className="text-[9px] text-muted-foreground">{format(ts, 'MMM d, HH:mm')}</p>
      </div>
    </div>
  );
}

interface Props { refreshTrigger?: number; }

export default function TransactionLedger({ refreshTrigger = 0 }: Props) {
  const [data, setData] = useState<GetTransactionHistoryOutputType | null>(null);
  const [loading, setLoading] = useState(true);

  const load = () => {
    setLoading(true);
    getTransactionHistory({}).then(setData).finally(() => setLoading(false));
  };

  useEffect(() => { load(); }, [refreshTrigger]);

  return (
    <div className="mx-4 rounded-2xl border border-border overflow-hidden">
      {/* Header */}
      <div className="flex items-center justify-between px-4 py-3 bg-muted/30 border-b border-border">
        <div className="flex items-center gap-2">
          <Coins size={14} className="text-primary" />
          <span className="text-sm font-semibold">Transaction Ledger</span>
          {data && (
            <Badge variant="secondary" className="text-[9px] h-4 px-1.5">
              {data.transactions.length} entries
            </Badge>
          )}
        </div>
        <Button size="sm" variant="ghost" className="h-7 w-7 p-0" onClick={load} disabled={loading}>
          <RefreshCw size={11} className={loading ? 'animate-spin' : ''} />
        </Button>
      </div>

      {/* Summary strip */}
      {data && data.transactions.length > 0 && (
        <div className="grid grid-cols-2 divide-x divide-border border-b border-border">
          <div className="px-4 py-2 text-center">
            <p className="text-[10px] text-muted-foreground">Total Coins Earned</p>
            <p className="text-sm font-bold text-emerald-500">+{data.totalCoinsEarned} 🪙</p>
          </div>
          <div className="px-4 py-2 text-center">
            <p className="text-[10px] text-muted-foreground">Total Withdrawn</p>
            <p className="text-sm font-bold text-primary">${data.totalWithdrawn.toFixed(2)}</p>
          </div>
        </div>
      )}

      {/* Rows */}
      <div className="p-2 space-y-1.5 max-h-72 overflow-y-auto">
        {loading && (
          <div className="space-y-1.5">
            {[1, 2, 3].map(i => <Skeleton key={i} className="h-14 w-full rounded-xl" />)}
          </div>
        )}

        {!loading && data?.transactions.length === 0 && (
          <div className="py-8 text-center">
            <p className="text-2xl mb-1">📋</p>
            <p className="text-xs text-muted-foreground">No transactions yet</p>
            <p className="text-[10px] text-muted-foreground/60 mt-0.5">Invite friends to earn coins!</p>
          </div>
        )}

        {!loading && data?.transactions.map(tx => (
          <TxRow key={tx.id} tx={tx} />
        ))}
      </div>

      {/* Footer */}
      {data && data.transactions.length > 0 && (
        <div className="px-4 py-2 bg-muted/20 border-t border-border">
          <div className="flex items-center justify-between">
            <p className="text-[9px] text-muted-foreground">🟢 Inbound referral credits &nbsp;|&nbsp; 🔵 Outbound withdrawals</p>
            {loading && <Loader2 size={10} className="animate-spin text-muted-foreground" />}
          </div>
        </div>
      )}
    </div>
  );
}

