import { useState, useEffect } from 'react';
import { Copy, Check, MapPin, Clock, Hash } from 'lucide-react';
import { toast } from 'sonner';
import { cn } from '@/lib/utils';

interface LocationData { lat: number; lng: number; label: string; }

function LiveClock() {
  const [now, setNow] = useState(new Date());
  useEffect(() => { const t = setInterval(() => setNow(new Date()), 1000); return () => clearInterval(t); }, []);
  const day   = now.toLocaleDateString('en-US', { weekday: 'long' });
  const date  = now.toLocaleDateString('en-US', { day: 'numeric', month: 'long', year: 'numeric' });
  const time  = now.toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit', second: '2-digit' });
  return (
    <div className="flex flex-col gap-0.5">
      <span className="text-[10px] font-bold">{day}</span>
      <span className="text-[9px] opacity-90">{date}</span>
      <span className="text-[9px] font-mono opacity-80">{time}</span>
    </div>
  );
}

interface CardProps {
  platform: 'youtube' | 'facebook' | 'tiktok';
  hashtags: string[];
  location: LocationData | null;
  onCopy: () => void;
}

function SocialCard({ platform, hashtags, location, onCopy }: CardProps) {
  const [copied, setCopied] = useState(false);

  const config = {
    youtube: { name: 'YouTube',  emoji: '📺', bg: 'from-red-600 to-red-700',     text: 'text-white', border: 'border-red-500/30'  },
    facebook:{ name: 'Facebook', emoji: '📘', bg: 'from-blue-600 to-blue-700',   text: 'text-white', border: 'border-blue-500/30' },
    tiktok:  { name: 'TikTok',   emoji: '🎵', bg: 'from-gray-900 to-black',      text: 'text-white', border: 'border-gray-700/30' },
  }[platform];

  // ── Build the FULL copy text: hashtags + location + date/time ──
  const buildFullText = () => {
    const now = new Date();
    const day   = now.toLocaleDateString('en-US', { weekday: 'long' });
    const date  = now.toLocaleDateString('en-US', { day: 'numeric' });
    const month = now.toLocaleDateString('en-US', { month: 'long' });
    const year  = now.toLocaleDateString('en-US', { year: 'numeric' });
    const time  = now.toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit', second: '2-digit' });

    const lines: string[] = [];
    lines.push(`${config.emoji} ${config.name} Post`);
    lines.push('');
    if (location) {
      lines.push(`📍 Live Location: ${location.label}`);
    }
    lines.push(`📅 Date: ${day}, ${date} ${month} ${year}`);
    lines.push(`🕐 Time: ${time}`);
    lines.push('');
    lines.push(`#️⃣ Hashtags (${hashtags.length}):`);
    lines.push(hashtags.join(' '));
    return lines.join('\n');
  };

  const handleCopy = () => {
    const fullText = buildFullText();
    navigator.clipboard.writeText(fullText);
    setCopied(true);
    setTimeout(() => setCopied(false), 2500);
    onCopy();
  };

  return (
    <div className={cn('rounded-2xl border p-4 space-y-3 bg-gradient-to-br', config.bg, config.border)}>
      {/* Header */}
      <div className="flex items-center justify-between pb-2 border-b border-white/10">
        <div className="flex items-center gap-2">
          <span className="text-2xl">{config.emoji}</span>
          <div>
            <p className={cn('text-sm font-black', config.text)}>{config.name}</p>
            <p className="text-[9px] text-white/60">Viral Hashtags</p>
          </div>
        </div>
        {/* Copy button — copies FULL package: hashtags + location + date/time */}
        <button
          onClick={handleCopy}
          className={cn(
            'px-3 py-1.5 rounded-lg border border-white/20 hover:border-white/40 transition-all flex items-center gap-1.5 text-xs font-bold',
            config.text
          )}
        >
          {copied
            ? <><Check size={11} /> Copied!</>
            : <><Copy size={11} /> Copy All</>
          }
        </button>
      </div>

      {/* Location */}
      {location && (
        <div className="flex items-start gap-2 bg-white/10 backdrop-blur rounded-lg px-3 py-2">
          <MapPin size={12} className="text-white/80 shrink-0 mt-0.5" />
          <div className="flex-1 min-w-0">
            <p className="text-[9px] text-white/60 uppercase tracking-wide font-semibold mb-0.5">Live Location</p>
            <p className="text-[10px] text-white/90 font-medium truncate">📍 {location.label}</p>
          </div>
        </div>
      )}

      {/* Timestamp */}
      <div className="flex items-start gap-2 bg-white/10 backdrop-blur rounded-lg px-3 py-2">
        <Clock size={12} className="text-white/80 shrink-0 mt-0.5 animate-pulse" />
        <div className="flex-1">
          <p className="text-[9px] text-white/60 uppercase tracking-wide font-semibold mb-1">Post Timestamp</p>
          <LiveClock />
        </div>
      </div>

      {/* Hashtags */}
      <div className="space-y-2">
        <div className="flex items-center gap-1.5">
          <Hash size={11} className="text-white/70" />
          <p className="text-[10px] text-white/70 uppercase tracking-wide font-semibold">
            {hashtags.length} Hashtags
          </p>
        </div>
        <div className="bg-white/10 backdrop-blur rounded-lg px-3 py-2 max-h-32 overflow-y-auto">
          <p className="text-[10px] text-white/90 leading-relaxed break-words">
            {hashtags.join(' ')}
          </p>
        </div>
      </div>

      {/* Copy hint */}
      <p className="text-[9px] text-white/40 text-center">
        Copies: hashtags + location + date, month, year &amp; time
      </p>
    </div>
  );
}

interface Props {
  hashtags: string[];
  location: LocationData | null;
}

export default function SocialHashtagCards({ hashtags, location }: Props) {
  if (hashtags.length === 0) return null;

  const perCard = Math.ceil(hashtags.length / 3);
  const youtubeHashtags  = hashtags.slice(0, perCard);
  const facebookHashtags = hashtags.slice(perCard, perCard * 2);
  const tiktokHashtags   = hashtags.slice(perCard * 2);

  return (
    <div className="space-y-3">
      <div className="flex items-center justify-between pb-1">
        <p className="text-xs font-bold text-foreground">📊 Platform-Optimized Hashtags</p>
        <span className="text-[9px] text-muted-foreground">3 Cards · Tap Copy All</span>
      </div>
      <SocialCard platform="youtube"  hashtags={youtubeHashtags}  location={location}
        onCopy={() => toast.success('✅ YouTube — full package copied!')} />
      <SocialCard platform="facebook" hashtags={facebookHashtags} location={location}
        onCopy={() => toast.success('✅ Facebook — full package copied!')} />
      <SocialCard platform="tiktok"   hashtags={tiktokHashtags}   location={location}
        onCopy={() => toast.success('✅ TikTok — full package copied!')} />
    </div>
  );
}

