// ══════════════════════════════════════════════════════════════════
// ROOHANI GUIDE — PHOTO ANALYSIS VIEW v4.0
// Deep 8-section scanning: name probability, health micro-lines,
// children count, marriage lines, zodiac, fate & financial lines.
// Real-time Hijri date + live location injected into every report.
// ══════════════════════════════════════════════════════════════════
import { useState, useRef, useEffect } from 'react';
import { analyzePhotos } from 'zite-endpoints-sdk';
import {
  Upload, CheckCircle2, Loader2, Sparkles, RotateCcw,
  Copy, Check, Volume2, VolumeX, MapPin, Clock, AlertTriangle,
