  }, []);

  useEffect(() => {
    setLocation(getGlobalUrduLocation());
    if (!isLocationResolved()) {
      resolveAndSetLocation().then(loc => setLocation(loc));
    }
  }, []);

  const userTz = Intl.DateTimeFormat().resolvedOptions().timeZone;
  const gregorian = now.toLocaleDateString('ur-PK', {
    weekday: 'long', year: 'numeric', month: 'long', day: 'numeric',
    timeZone: userTz,
  });
  const timeStr = now.toLocaleTimeString('ur-PK', {
    hour: '2-digit', minute: '2-digit', hour12: true, timeZone: userTz,
  });
  const hijri = toHijri(now);

  return (
    <div className="rounded-xl border border-emerald-800/30 bg-emerald-950/30 px-3 py-2.5 space-y-1" dir="rtl">
      <div className="flex items-center gap-2 flex-wrap">
        <Clock size={11} className="text-emerald-400 shrink-0" />
        <span className="text-[10px] text-emerald-300 font-medium">{gregorian}</span>
        <span className="text-[10px] text-emerald-500">|</span>
        <span className="text-[10px] text-emerald-400 font-semibold">{timeStr}</span>
      </div>
      <div className="flex items-center gap-2 flex-wrap">
        <span className="text-xs">🌙</span>
        <span className="text-[10px] text-amber-400/80 font-medium">{hijri}</span>
        <span className="text-[10px] text-emerald-500">|</span>
        <MapPin size={9} className="text-emerald-500 shrink-0" />
        <span className="text-[10px] text-emerald-600">{location}</span>
      </div>
    </div>
  );
}

export default function PhotoAnalysisView() {
  const [photos, setPhotos]         = useState<Record<string, { file: File; preview: string }>>({});
  const [analyzing, setAnalyzing]   = useState(false);
  const [progress, setProgress]     = useState(0);
  const [result, setResult]         = useState<string | null>(null);
  const [copied, setCopied]         = useState(false);
  const [ttsPlaying, setTtsPlaying] = useState(false);
  const [locationCtx, setLocationCtx] = useState('پاکستان');
  const refs = useRef<Record<string, HTMLInputElement | null>>({});

  // Capture location context — resolve to clean Urdu city name (no timezone codes)
  useEffect(() => {
    setLocationCtx(getGlobalUrduLocation());
    if (!isLocationResolved()) {
      resolveAndSetLocation().then(loc => setLocationCtx(loc));
    }
  }, []);

  const handleUpload = async (key: string, file: File) => {
    const preview = URL.createObjectURL(file);
    setPhotos(prev => ({ ...prev, [key]: { file, preview } }));
    toast.success(`${key === 'rightHand' ? 'دایاں ہاتھ' : key === 'leftHand' ? 'بایاں ہاتھ' : 'چہرہ'} اپلوڈ ہو گیا ✓`);
  };

  const allUploaded = SLOTS.every(s => photos[s.key]);

  const analyze = async () => {
    if (!allUploaded) return;
    setAnalyzing(true);
    setProgress(0);
    setResult(null);
    const timer = setInterval(() => setProgress(p => Math.min(p + 1.5, 91)), 100);
    try {
      const [rightHand, leftHand, face] = await Promise.all([
        compressToBase64(photos.rightHand.file),
        compressToBase64(photos.leftHand.file),
        compressToBase64(photos.face.file),
      ]);

      const now = new Date();
      const userTz = Intl.DateTimeFormat().resolvedOptions().timeZone;
      const currentTime = now.toLocaleString('ur-PK', {
        weekday: 'long', year: 'numeric', month: 'long', day: 'numeric',
        hour: '2-digit', minute: '2-digit', hour12: true, timeZone: userTz,
      });

      const res = await analyzePhotos({
        rightHand, leftHand, face,
        currentTime,
        userLocation: locationCtx,
      });
      setProgress(100);
      setResult(res.analysis);
      if (!res.complete) {
        toast.warning('⚠️ تجزیہ مکمل نہیں ہو سکا — انٹرنیٹ سست ہو سکتا ہے۔ دوبارہ کوشش کریں۔', { duration: 6000 });
      }
    } catch (e: any) {
      toast.error(e?.message ?? 'تجزیہ ناکام — دوبارہ کوشش کریں');
    } finally {
      clearInterval(timer);
      setAnalyzing(false);
    }
  };

  const reset = () => { setPhotos({}); setResult(null); setProgress(0); stopTTS(); setTtsPlaying(false); };

  const copyResult = () => {
    if (!result) return;
    navigator.clipboard.writeText(result).catch(() => {
      const ta = document.createElement('textarea');
      ta.value = result; ta.style.position = 'fixed'; ta.style.opacity = '0';
      document.body.appendChild(ta); ta.focus(); ta.select();
      document.execCommand('copy'); document.body.removeChild(ta);
    });
    setCopied(true); setTimeout(() => setCopied(false), 2500);
    toast.success('📋 نتائج کاپی ہو گئے');
  };

  const speakResult = () => {
    if (!result) return;
    if (ttsPlaying) { stopTTS(); setTtsPlaying(false); return; }
    const lang = detectLangFromText(result);
    speakText(ttsClean(result), lang, () => setTtsPlaying(false), () => setTtsPlaying(true));
  };

  const SCAN_LABELS = [
    'ہتھیلی کی لکیریں پڑھ رہے ہیں...',
    'نام کے حروف تلاش کر رہے ہیں...',
    'صحت کے مخفی اشارے اسکین ہو رہے ہیں...',
    'اولاد و نکاح کی لکیروں کا تجزیہ...',
    'ستاروں کا برج معلوم کیا جا رہا ہے...',
    'روحانی قرآنی حوالے ترتیب دیے جا رہے ہیں...',
    'تجزیہ مکمل ہو رہا ہے...',
  ];
  const scanLabel = SCAN_LABELS[Math.min(Math.floor(progress / 14), SCAN_LABELS.length - 1)];

  return (
    <div className="px-4 py-4 space-y-4" dir="rtl">

      {/* ── Live Context Block ── */}
      <LiveContextBlock />

      {/* ── Page Title ── */}
      <div className="text-center space-y-0.5">
        <p className="font-urdu text-base text-emerald-300 font-bold">🔮 روحانی و جسمانی تجزیہ</p>
        <p className="text-[10px] text-emerald-700/80">12 سیکشن • اسماء الحسنیٰ • 30 سپارے • نماز • صدقہ • نکاح • اولاد</p>
      </div>

      {/* ── CAMERA QUALITY WARNING (PROMINENT) ── */}
      <div className="rounded-xl border border-amber-500/30 bg-amber-500/8 px-3 py-3 flex gap-2.5 items-start">
        <AlertTriangle size={16} className="text-amber-400 shrink-0 mt-0.5" />
        <div className="space-y-1" dir="rtl">
          <p className="text-[10px] font-bold text-amber-300">⚠️ ضروری ہدایت — تصویر کا معیار</p>
          <p className="text-[10px] text-amber-200/80 leading-relaxed font-urdu">
            اپنے ہاتھوں کی ہتھیلی اور چہرے کی رنگت بالکل صاف اور کلوز اپ میں اپلوڈ کریں۔
            یاد رکھیں! جیسا آپ کے موبائل کے کیمرے کا رزلٹ ہوگا، ویسا ہی سچا رزلٹ یہ اے آئی انجن نکال کر دے گا۔
            اگر تصویر دھندلی ہوئی تو سسٹم اسے قبول نہیں کرے گا یا رزلٹ ادھورا ملے گا۔
          </p>
          <p className="text-[9px] text-amber-500/70" dir="rtl">
            ✓ اچھی روشنی  ✓ ہتھیلی قریب سے  ✓ صاف چہرہ  ✗ دھندلاپن نہ ہو
          </p>
        </div>
      </div>

      {/* ── Upload Slots ── */}
      <div className="grid grid-cols-3 gap-3">
        {SLOTS.map(slot => {
          const uploaded = photos[slot.key];
          return (
            <div key={slot.key} className="space-y-1.5">
              <p className="text-center text-[9px] font-urdu text-emerald-600 leading-loose">{slot.urduLabel}</p>
              <button
                onClick={() => refs.current[slot.key]?.click()}
                disabled={analyzing}
                className={`w-full aspect-square rounded-2xl border-2 border-dashed flex flex-col items-center justify-center transition-all overflow-hidden active:scale-95 ${
                  uploaded
                    ? 'border-emerald-600/60 bg-emerald-900/25'
                    : 'border-emerald-900/40 bg-card/40 hover:border-emerald-700/60 hover:bg-emerald-950/30'
                }`}
              >
                {uploaded ? (
                  <div className="relative w-full h-full">
                    <img src={uploaded.preview} alt="" className="w-full h-full object-cover rounded-xl" />
                    <div className="absolute inset-0 bg-emerald-900/50 flex items-center justify-center rounded-xl">
                      <CheckCircle2 size={22} className="text-emerald-400" />
                    </div>
                  </div>
                ) : (
                  <>
                    <span className="text-2xl mb-1">{slot.icon}</span>
                    <Upload size={12} className="text-emerald-700" />
                    <p className="text-[9px] text-emerald-800 mt-0.5 text-center px-1" dir="ltr">{slot.label}</p>
                  </>
                )}
              </button>
              <input
                ref={el => refs.current[slot.key] = el}
                type="file"
                accept="image/*"
                capture="environment"
                className="hidden"
                onChange={e => e.target.files?.[0] && handleUpload(slot.key, e.target.files[0])}
              />
            </div>
          );
        })}
      </div>

      {/* ── Deep Scanning Animation ── */}
      {analyzing && (
        <div className="rounded-2xl border border-emerald-800/30 bg-emerald-950/30 p-5 space-y-3 text-center">
          <div className="flex items-center justify-center gap-2">
            <Sparkles size={15} className="text-emerald-400 animate-pulse" />
            <p className="font-urdu text-sm text-emerald-300 animate-pulse">
              12 پرتوں کا گہرا روحانی اسکین جاری ہے...
            </p>
            <Sparkles size={15} className="text-emerald-400 animate-pulse" />
          </div>

          {/* Progress bar */}
          <div className="w-full bg-emerald-950 rounded-full h-2.5 overflow-hidden border border-emerald-900/40">
            <div
              className="h-full bg-gradient-to-r from-emerald-700 via-emerald-500 to-teal-400 rounded-full transition-all duration-300 relative"
              style={{ width: `${progress}%` }}
            >
              <div className="absolute right-0 top-0 bottom-0 w-5 bg-white/25 animate-pulse rounded-full" />
            </div>
          </div>

          <p className="text-[10px] text-emerald-600 font-urdu">{scanLabel}</p>

          {/* Scanning steps checklist */}
          <div className="grid grid-cols-2 gap-1 text-left" dir="ltr">
            {[
              ['🖐 ہتھیلی اسکین', 10],
              ['👤 چہرہ/جنس شناخت', 20],
              ['🔤 نام اندازہ', 30],
              ['💍 نکاح لکیریں', 40],
              ['👶 اولاد لکیریں', 50],
              ['⭐ ستارے/برج', 58],
              ['🏥 صحت اشارے', 65],
              ['❤️ دل کی لکیر', 72],
              ['🤲 اسماء الحسنیٰ', 80],
              ['📖 قرآنی نسخے', 87],
              ['🕌 نماز/تہجد', 93],
              ['💝 صدقہ و خیرات', 98],
            ].map(([label, threshold]) => (
              <div key={String(label)} className={`flex items-center gap-1.5 text-[9px] transition-colors ${
                progress >= Number(threshold) ? 'text-emerald-400' : 'text-emerald-900'
              }`}>
                <span>{progress >= Number(threshold) ? '✓' : '○'}</span>
                <span>{label}</span>
              </div>
            ))}
          </div>

          <Loader2 size={18} className="text-emerald-500 animate-spin mx-auto" />
        </div>
      )}

      {/* ── Analyze Button ── */}
      {!analyzing && !result && (
        <Button
          onClick={analyze}
          disabled={!allUploaded}
          className="w-full h-12 bg-emerald-700 hover:bg-emerald-600 text-white font-urdu text-base font-bold disabled:opacity-40 gap-2"
        >
          <Sparkles size={16} />
          {allUploaded
            ? 'مکمل 12-سیکشن روحانی تجزیہ شروع کریں'
            : `${SLOTS.length - Object.keys(photos).length} تصویریں باقی ہیں`}
        </Button>
      )}

      {/* ── Results ── */}
      {result && (
        <div className="space-y-3">
          <div className="flex items-center justify-between">
            <p className="font-urdu text-sm text-emerald-400 font-bold">✨ مکمل روحانی تجزیہ</p>
            <button
              onClick={reset}
              className="flex items-center gap-1 text-xs text-emerald-700 hover:text-emerald-400 transition-colors"
            >
              <RotateCcw size={12} /> دوبارہ کریں
            </button>
          </div>

          {/* Result text box */}
          <div className="rounded-2xl border border-emerald-800/30 bg-emerald-950/20 p-4">
            <div
              className="text-sm font-urdu leading-loose text-foreground/90 whitespace-pre-wrap"
              dir="rtl"
              style={{ fontFamily: 'Noto Nastaliq Urdu, serif', lineHeight: '2' }}
            >
              {result}
            </div>
          </div>

          {/* Action Buttons: Copy + TTS */}
          <div className="flex items-center gap-2 flex-wrap" dir="ltr">
            <button
              onClick={copyResult}
              className={`flex items-center gap-2 px-4 py-2.5 rounded-xl border text-xs font-bold transition-all active:scale-95 min-h-[44px] ${
                copied
                  ? 'bg-primary/20 text-primary border-primary/40'
                  : 'bg-card border-border text-foreground hover:bg-muted/60'
              }`}
            >
              {copied ? <Check size={13} className="text-primary" /> : <Copy size={13} />}
              {copied ? 'کاپی ہو گیا ✓' : 'نتائج کاپی کریں'}
            </button>

            {isTTSSupported() && (
              <button
                onClick={speakResult}
                className={`flex items-center gap-2 px-4 py-2.5 rounded-xl border text-xs font-bold transition-all active:scale-95 min-h-[44px] ${
                  ttsPlaying
                    ? 'bg-emerald-500/20 text-emerald-400 border-emerald-500/40'
                    : 'bg-card border-emerald-800/40 text-emerald-500 hover:bg-emerald-900/30'
                }`}
              >
                {ttsPlaying ? <VolumeX size={13} /> : <Volume2 size={13} />}
                {ttsPlaying ? 'آواز بند کریں' : '🔊 نتائج سنیں'}
              </button>
            )}
          </div>
        </div>
      )}
    </div>
  );
}

