}

export default function SpiritualChatView() {
  const [messages, setMessages]   = useState<Message[]>([]);
  const [input, setInput]         = useState('');
  const [loading, setLoading]     = useState(false);
  const [locationCtx, setLocationCtx] = useState('');
  const [listening, setListening] = useState(false);
  const bottomRef    = useRef<HTMLDivElement>(null);
  const textareaRef  = useRef<HTMLTextAreaElement>(null);
  const recognitionRef = useRef<any>(null);
  const tts = useIslamicTTS();

  // ── Use global GPS-first Urdu location ──
  useEffect(() => {
    setLocationCtx(getGlobalUrduLocation());
    // If not yet resolved (GPS still pending), re-resolve and update
    if (!isLocationResolved()) {
      resolveAndSetLocation().then(loc => setLocationCtx(loc));
    }
  }, []);

  useEffect(() => {
    bottomRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  const send = useCallback(async (text?: string) => {
    const q = (text ?? input).trim();
    if (!q || loading) return;
    setInput('');

    const userMsg: Message = { id: newId(), role: 'user', content: q };
    setMessages(prev => [...prev, userMsg]);
    setLoading(true);

    try {
      const history = messages.slice(-12).map(m => ({
        role: m.role === 'user' ? 'user' as const : 'model' as const,
        content: m.content,
      }));

      const now = new Date();
      const userTz = Intl.DateTimeFormat().resolvedOptions().timeZone;
      const currentTime = now.toLocaleString('ur-PK', {
        weekday: 'long', year: 'numeric', month: 'long', day: 'numeric',
        hour: '2-digit', minute: '2-digit', hour12: true, timeZone: userTz,
      });
      const userLocation = locationCtx || 'پاکستان';

      const res = await spiritualChat({ message: q, history, currentTime, userLocation });
      setMessages(prev => [...prev, {
        id: newId(),
        role: 'assistant',
        content: res.response,
        model: res.model,
      }]);
    } catch {
      setMessages(prev => [...prev, {
        id: newId(), role: 'assistant',
        content: 'معذرت — جواب حاصل نہ ہو سکا۔ دوبارہ کوشش کریں۔',
      }]);
    } finally {
      setLoading(false);
    }
  }, [input, loading, messages, locationCtx]);

  const handleKey = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) { e.preventDefault(); send(); }
  };

  // ── Clean STT output: strip *, #, ~, stray symbols ──
  const cleanStt = (text: string): string =>
    text.replace(/[*#~_`^\\|<>{}[\]]/g, '').replace(/\s{2,}/g, ' ').trim();

  // ── STT Mic — Universal auto-detect (single clean implementation) ──
  const toggleMic = () => {
    const SR = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (!SR) {
      toast.error('آواز ان پٹ اس براؤزر میں کام نہیں کرتی۔ Chrome استعمال کریں۔');
      return;
    }
    if (listening) {
      recognitionRef.current?.stop();
      setListening(false);
      return;
    }
    const r = new SR();
    // language: "auto" — do NOT set r.lang so the browser auto-detects
    // the spoken language (Urdu, Punjabi, Saraiki, Sindhi, Hindi, English, Arabic, etc.)
    r.continuous = true;
    r.interimResults = false;
    r.maxAlternatives = 1;
    r.onresult = (e: any) => {
      const transcript = cleanStt(e.results[e.results.length - 1][0].transcript);
      if (transcript) setInput(prev => prev + (prev ? ' ' : '') + transcript);
    };
    r.onerror = (e: any) => {
      if (e.error !== 'aborted') {
        const msgs: Record<string, string> = {
          'no-speech':    'آواز نہیں آئی — واضح بولیں',
          'not-allowed':  'مائیکروفون بلاک ہے — براؤزر سیٹنگز میں اجازت دیں',
          'audio-capture': 'مائیکروفون نہیں ملا',
          'network':       'نیٹ ورک خرابی',
        };
        toast.error(msgs[e.error] ?? `مائیکروفون غلطی: ${e.error}`);
      }
      setListening(false);
    };
    r.onend = () => setListening(false);
    recognitionRef.current = r;
    try { r.start(); setListening(true); } catch { toast.error('مائیکروفون شروع نہ ہو سکا'); }
  };

  const clearChat = () => { tts.stop(); setMessages([]); };

  return (
    <div className="flex flex-col h-full">
      {/* ── Live Context Bar (Gregorian + Hijri + Location) ── */}
      <LiveContextBar locationCtx={locationCtx} />

      {/* ── Messages ── */}
      <div className="flex-1 overflow-y-auto px-3 py-3 space-y-4">
        {messages.length === 0 && (
          <div className="space-y-3 pt-1">
            <p className="text-center text-[10px] text-muted-foreground">سوال پوچھیں — مکمل اسلامی علم حاضر ہے</p>
            <div className="grid grid-cols-1 gap-2">
              {SUGGESTIONS.map((s, i) => (
                <button
                  key={i}
                  onClick={() => send(s)}
                  className="text-right text-[11px] px-3 py-3 rounded-xl bg-emerald-500/10 border border-emerald-500/20 text-emerald-200 hover:bg-emerald-500/20 transition-colors leading-relaxed min-h-[44px] active:scale-[.98]"
                  style={{ direction: 'rtl', fontFamily: 'Noto Nastaliq Urdu, serif' }}
                >
                  {s}
                </button>
              ))}
            </div>
          </div>
        )}

        {messages.map(msg => (
          <IslamicMessageBubble key={msg.id} message={msg} tts={tts} />
        ))}

        {loading && (
          <div className="flex gap-2.5 items-start">
            <div className="w-8 h-8 rounded-full bg-gradient-to-br from-emerald-500 to-teal-600 flex items-center justify-center text-sm shrink-0">🕌</div>
            <div className="bg-card border border-border rounded-2xl rounded-tl-sm px-4 py-3">
              <div className="flex gap-1 items-center">
                <Loader2 size={12} className="animate-spin text-emerald-500" />
                <span className="text-xs text-muted-foreground">4 پرتوں کا تجزیہ جاری ہے...</span>
              </div>
            </div>
          </div>
        )}
        <div ref={bottomRef} />
      </div>

      {/* ── Input Bar ── */}
      <div className="shrink-0 px-3 py-3 border-t border-border bg-background/80 backdrop-blur-sm">
        <div className="flex gap-2 items-end">
          <Textarea
            ref={textareaRef}
            value={input}
            onChange={e => setInput(e.target.value)}
            onKeyDown={handleKey}
            placeholder={listening ? '🎤 سن رہا ہوں... اردو میں بولیں' : 'اپنا سوال اردو میں لکھیں...'}
            rows={2}
            className="resize-none text-sm border-border focus-visible:ring-emerald-500/50 leading-relaxed"
            style={{ direction: 'rtl', fontFamily: 'Noto Nastaliq Urdu, serif' }}
            disabled={loading}
          />

          {/* STT Mic — single clean button */}
          <button
            onClick={toggleMic}
            className={`shrink-0 h-12 w-12 rounded-xl flex items-center justify-center border transition-all active:scale-95 ${
              listening
                ? 'bg-destructive/10 text-destructive border-destructive/30 animate-pulse'
                : 'bg-card border-emerald-800/30 text-emerald-500 hover:bg-emerald-900/30 hover:border-emerald-600/40'
            }`}
            title={listening ? 'سننا بند کریں' : 'آواز سے سوال پوچھیں (اردو)'}
          >
            {listening ? <MicOff size={16} /> : <Mic size={16} />}
          </button>

          {/* Send */}
          <Button
            onClick={() => send()}
            disabled={!input.trim() || loading}
            size="icon"
            className="shrink-0 bg-emerald-600 hover:bg-emerald-700 text-white h-12 w-12 rounded-xl"
          >
            {loading ? <Loader2 size={16} className="animate-spin" /> : <Send size={16} />}
          </Button>
        </div>

        {/* Footer row */}
        <div className="flex items-center justify-between mt-1.5 px-0.5">
          <p className="text-[8px] text-muted-foreground/40">
            ROOHANI GUIDE AI — غلام حسین چنڑ
          </p>
          {messages.length > 0 && (
            <button
              onClick={clearChat}
              className="flex items-center gap-1 text-[9px] text-emerald-800 hover:text-emerald-500 transition-colors"
            >
              <RefreshCw size={9} /> صاف کریں
            </button>
          )}
        </div>
      </div>
    </div>
  );
}

