import { Volume2, VolumeX, Loader2, User, Copy, Check } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { IslamicTTSState } from './useIslamicTTS';
import { useState } from 'react';
import { toast } from 'sonner';

interface Message {
  id: string;
  role: 'user' | 'assistant';
  content: string;
  model?: string;
}

interface Props {
  message: Message;
  tts: IslamicTTSState;
}

export default function IslamicMessageBubble({ message, tts }: Props) {
  const isUser = message.role === 'user';
  const isThisPlaying = tts.activeId === message.id && tts.isPlaying;
  const isThisPreparing = tts.activeId === message.id && tts.isPreparing;
  const [copied, setCopied] = useState(false);

  const handleCopy = () => {
    navigator.clipboard.writeText(message.content).catch(() => {
      // Android WebView fallback
      const ta = document.createElement('textarea');
      ta.value = message.content; ta.style.position = 'fixed'; ta.style.opacity = '0';
      document.body.appendChild(ta); ta.focus(); ta.select();
      document.execCommand('copy'); document.body.removeChild(ta);
    });
    setCopied(true);
    toast.success('📋 متن کاپی ہو گیا');
    setTimeout(() => setCopied(false), 2000);
  };

  return (
    <div className={`flex gap-2.5 ${isUser ? 'flex-row-reverse' : 'flex-row'} items-start`}>
      {/* Avatar */}
      <div className={`w-8 h-8 rounded-full flex items-center justify-center shrink-0 text-xs font-bold ${
        isUser ? 'bg-primary text-primary-foreground' : 'bg-gradient-to-br from-emerald-500 to-teal-600 text-white'
      }`}>
        {isUser ? <User size={14} /> : '🕌'}
      </div>

      {/* Bubble */}
      <div className={`max-w-[85%] ${isUser ? 'items-end' : 'items-start'} flex flex-col gap-2`}>
        <div className={`rounded-2xl px-4 py-3 text-sm leading-relaxed ${
          isUser
            ? 'bg-primary text-primary-foreground rounded-tr-sm'
            : 'bg-card border border-border text-foreground rounded-tl-sm'
        }`}
          style={{ direction: 'rtl', fontFamily: 'Noto Nastaliq Urdu, serif', lineHeight: '2.2' }}
        >
          {message.content}
        </div>

        {/* Action buttons — assistant only */}
        {!isUser && (
          <div className="flex items-center gap-2 px-1 flex-wrap">
            {/* ── AUDIO PLAY BUTTON — HIGH-FIDELITY, PROMINENT ── */}
            <Button
              size="sm"
              variant="ghost"
              className={`h-10 px-4 gap-2 text-sm font-bold rounded-xl border transition-all active:scale-95 ${
                isThisPlaying
                  ? 'bg-emerald-500/20 text-emerald-400 border-emerald-500/40 shadow-emerald-500/20 shadow-md'
                  : isThisPreparing
                  ? 'bg-emerald-900/30 text-emerald-500 border-emerald-700/40'
                  : 'text-emerald-500 border-emerald-700/30 bg-emerald-950/30 hover:bg-emerald-900/40 hover:border-emerald-600/40 hover:text-emerald-300'
              }`}
              onClick={() => tts.speak(message.content, message.id)}
              disabled={isThisPreparing}
            >
              {isThisPreparing ? (
                <>
                  <Loader2 size={14} className="animate-spin" />
                  <span>تیار ہو رہا ہے...</span>
                </>
              ) : isThisPlaying ? (
                <>
                  <VolumeX size={14} className="animate-pulse" />
                  <span>آواز بند کریں</span>
                </>
              ) : (
                <>
                  <Volume2 size={14} />
                  <span>🔊 آواز سنیں</span>
                </>
              )}
            </Button>

            {/* ── COPY TEXT BUTTON — MOBILE FRIENDLY ── */}
            <Button
              size="sm"
              variant="ghost"
              onClick={handleCopy}
              className={`h-10 px-3 gap-2 text-xs font-medium rounded-xl border transition-all active:scale-95 ${
                copied
                  ? 'bg-primary/20 text-primary border-primary/40'
                  : 'text-muted-foreground border-border hover:text-foreground hover:bg-muted/40'
              }`}
            >
              {copied ? <Check size={13} className="text-primary" /> : <Copy size={13} />}
              <span>{copied ? 'کاپی ہو گیا' : 'کاپی'}</span>
            </Button>

            {/* Model badge */}
            {message.model && (
              <span className="text-[9px] text-muted-foreground/40 ml-auto">{message.model}</span>
            )}
          </div>
        )}
      </div>
    </div>
  );
}

