    --sidebar-accent: 224 40% 11%;
    --sidebar-accent-foreground: 40 20% 90%;
    --sidebar-border: 224 40% 15%;
    --sidebar-ring: 43 92% 52%;
  }
}

@layer base {
  * { @apply border-border; }
  html, body {
    /* ── ABSOLUTE VIEWPORT LOCK (چاروں کونوں سے فکس) ──────────────
       Locks the entire app to exactly 100vw × 100vh — prevents any
       horizontal drift, overflow, or stretching on mobile screens.
       Works from all four corners (top/right/bottom/left) on Android
       Chrome, iOS Safari, and all modern mobile browsers.           */
    width: 100%;
    width: 100vw;
    max-width: 100vw;
    height: 100%;
    height: 100dvh;        /* dynamic viewport height: adjusts for mobile toolbar */
    overflow: hidden;
    overflow-x: hidden;
    overscroll-behavior: none;
    touch-action: pan-x pan-y;
    position: fixed;       /* prevents bounce/shift on virtual keyboard open */
    /* iOS safe-area insets (iPhone notch / Dynamic Island) */
    padding-top: env(safe-area-inset-top, 0px);
    padding-bottom: env(safe-area-inset-bottom, 0px);
  }
  body {
    @apply bg-background text-foreground;
    font-family: 'Inter', system-ui, -apple-system, sans-serif;
    /* Prevent iOS/Android font-size inflation */
    -webkit-text-size-adjust: 100%;
    text-size-adjust: 100%;
  }
}

