// ══════════════════════════════════════════════════════════════════
// MULTI-LINGUAL TTS ENGINE v4.0 — CHUNKED SEQUENTIAL SPEAKING
//
// Core fix: Web Speech API (especially Chrome/Android) cuts off long
// utterances after ~15 seconds. This version splits text into small
// sentence-level chunks and chains them sequentially via onend,
// guaranteeing the FULL text is read without interruption.
//
// Supports: English, Urdu (اردو), Arabic (عربي), Punjabi, Hindi
// ══════════════════════════════════════════════════════════════════

export type TTSLanguage = 'en-US' | 'ur-PK' | 'ar-SA' | 'hi-IN' | 'pa-PK';

export const TTS_LANGUAGE_LABELS: Record<TTSLanguage, { label: string; flag: string; native: string }> = {
  'en-US': { label: 'English',  flag: '🇺🇸', native: 'English' },
  'ur-PK': { label: 'Urdu',     flag: '🇵🇰', native: 'اردو'    },
  'ar-SA': { label: 'Arabic',   flag: '🇸🇦', native: 'عربي'    },
  'hi-IN': { label: 'Hindi',    flag: '🇮🇳', native: 'हिन्दी'    },
  'pa-PK': { label: 'Punjabi',  flag: '🇵🇰', native: 'پنجابی'  },
};

// ── Voice priority maps per language ─────────────────────────────
// Voice priorities: Natural/Neural voices always first — these sound closest to a real human.
// On Android: Google voices; on Windows/iOS: Microsoft Natural (Online) voices.
const VOICE_PRIORITY_MAP: Record<string, string[]> = {
  en: [
    // Microsoft Natural (Neural) voices — most human-sounding on desktop/mobile
    'Microsoft Aria Online (Natural) - English (United States)',
    'Microsoft Jenny Online (Natural) - English (United States)',
    'Microsoft Emma Online (Natural) - English (United Kingdom)',
    'Microsoft Guy Online (Natural) - English (United States)',
    'Microsoft Ryan Online (Natural) - English (United Kingdom)',
    // Google TTS — natural on Android
    'Google UK English Female',
    'Google UK English Male',
    'Google US English',
    // Microsoft offline fallbacks
    'Microsoft Zira - English (United States)',
    'Microsoft David - English (United States)',
    'Microsoft Hazel - English (Great Britain)',
  ],
  ur: [
    // Microsoft Neural Urdu — premium Pakistani Urdu voices (natural, crystal-clear)
    'Microsoft Gul Online (Natural) - Urdu (Pakistan)',   // Female — very natural
    'Microsoft Salma Online (Natural) - Urdu (Pakistan)', // Female — soft, clear
    'Microsoft Asad Online (Natural) - Urdu (Pakistan)',  // Male — premium
    'Microsoft Uzma Online (Natural) - Urdu (Pakistan)',  // Female — newer
    'Microsoft Urdu Online (Natural) - Urdu (Pakistan)',
    'Microsoft Urdu Online (Natural)',
    'ur-PK-GulNeural',
    'ur-PK-AsadNeural',
    'ur-PK-UzmaNeural',
    // Google Urdu voices
    'Google اردو',
    'Google Urdu',
    // Microsoft offline fallback
    'Microsoft Urdu (Pakistan)',
  ],
  ar: [
    'Microsoft Zariyah Online (Natural) - Arabic (Saudi Arabia)',
    'Microsoft Hamed Online (Natural) - Arabic (Saudi Arabia)',
    'Microsoft Arabic Online (Natural)',
    'Google العربية',
    'Google Arabic',
    'Microsoft Hamed - Arabic (Saudi Arabia)',
    'Microsoft Naayf - Arabic (Saudi Arabia)',
  ],
  hi: [
    'Microsoft Swara Online (Natural) - Hindi (India)',
    'Microsoft Madhur Online (Natural) - Hindi (India)',
    'Google हिन्दी',
    'Microsoft Kalpana - Hindi (India)',
    'Microsoft Hemant - Hindi (India)',
  ],
  pa: [
    'Google ਪੰਜਾਬੀ',
    'Microsoft Punjabi',
  ],
};

// ── Global cancellation token — set true on stopTTS() ────────────
let _isCancelled = false;

function selectBestVoice(voices: SpeechSynthesisVoice[], lang: string): SpeechSynthesisVoice | null {
  if (!voices.length) return null;
  const base = lang.split('-')[0].toLowerCase();
  const priority = VOICE_PRIORITY_MAP[base] ?? [];
  // 1. Exact priority match
  for (const name of priority) {
    const v = voices.find(v => v.name.toLowerCase() === name.toLowerCase());
    if (v) return v;
  }
  // 2. Partial priority match
  for (const name of priority) {
    const v = voices.find(v => v.name.toLowerCase().includes(name.toLowerCase()));
    if (v) return v;
  }
  // 3. Google voice for language
  const google = voices.find(v =>
    v.name.toLowerCase().includes('google') && v.lang.toLowerCase().startsWith(base)
  );
  if (google) return google;
  // 4. Microsoft Online (Natural)
  const msOnline = voices.find(v =>
    v.name.toLowerCase().includes('microsoft') &&
    v.lang.toLowerCase().startsWith(base) &&
    (v.name.toLowerCase().includes('natural') || v.name.toLowerCase().includes('online'))
  );
  if (msOnline) return msOnline;
  // 5. Any Microsoft
  const ms = voices.find(v =>
    v.name.toLowerCase().includes('microsoft') && v.lang.toLowerCase().startsWith(base)
  );
  if (ms) return ms;
  // 6. Any voice for language
  return voices.find(v => v.lang.toLowerCase().startsWith(base)) ?? null;
}

/** Auto-detect language from text content */
export function detectLangFromText(text: string): TTSLanguage {
  const arabicUrdu = /[\u0600-\u06FF\u0750-\u077F]/;
  const urduSpecific = /[\u06AF\u06BA\u06BE\u06C1\u06C2\u06D2\u06CC\u06F0-\u06F9]/;
  const devanagari  = /[\u0900-\u097F]/;
  const clean = text.replace(/\s/g, '');
  if (!clean.length) return 'en-US';
  const auCount = (text.match(arabicUrdu) || []).length;
  const ratio = auCount / Math.max(clean.length, 1);
  if (ratio > 0.25) {
    const urduCount = (text.match(urduSpecific) || []).length;
    return urduCount > 0 ? 'ur-PK' : 'ar-SA';
  }
  if ((text.match(devanagari) || []).length / Math.max(clean.length, 1) > 0.25) {
    return 'hi-IN';
  }
  return 'en-US';
}

/** Strip markdown / code so TTS reads clean natural text */
export function ttsClean(text: string): string {
  return text
    .replace(/```[\s\S]*?```/g, 'code block. ')
    .replace(/`([^`]+)`/g, '$1')
    .replace(/\*{1,3}([^*\n]+)\*{1,3}/g, '$1')
    .replace(/\*+/g, '')
    .replace(/^#{1,6}\s+/gm, '')
    .replace(/\[([^\]]+)\]\([^)]+\)/g, '$1')
    .replace(/https?:\/\/\S+/g, 'link')
    .replace(/\n{2,}/g, '. ')
    .replace(/\n/g, ' ')
    .replace(/\s{2,}/g, ' ')
    .trim();
}

/** Get speech rate and pitch tuned per language for a natural, human-sounding voice.
 *  - Lower rates (0.78–0.88) sound more natural than the robotic default 1.0
 *  - Pitch near 1.0 (neutral) is more human than elevated values
 *  - Pakistani Urdu benefits from a slightly slower pace and neutral pitch
 */
function getLangParams(lang: string): { rate: number; pitch: number } {
  if (lang.startsWith('ur')) return { rate: 0.82, pitch: 1.02 }; // Pakistani Urdu: slightly warmer pitch, natural conversational pace
  if (lang.startsWith('ar')) return { rate: 0.80, pitch: 0.97 }; // Arabic: measured, slightly lower
  if (lang.startsWith('hi')) return { rate: 0.84, pitch: 1.00 }; // Hindi: natural conversational
  if (lang.startsWith('pa')) return { rate: 0.80, pitch: 1.00 }; // Punjabi: relaxed
  return { rate: 0.87, pitch: 0.97 }; // English: slightly slower + slightly deeper = more human
}

// ══════════════════════════════════════════════════════════════════
// CHUNK SPLITTER
// Splits text at sentence boundaries so each chunk is short enough
// (≤ 140 chars) to avoid the Android Chrome 15-second cutoff.
// Handles Urdu/Arabic sentence endings (۔ ? ؟) as well as Latin.
// ══════════════════════════════════════════════════════════════════
function splitIntoChunks(text: string, maxLen = 120): string[] {
  if (!text.trim()) return [];

  // Split at sentence-ending punctuation
  const sentences = text
    .replace(/([.!?؟۔])\s+/g, '$1\n')
    .split('\n')
    .map(s => s.trim())
    .filter(s => s.length > 0);

  const chunks: string[] = [];
  let buf = '';

  for (const sentence of sentences) {
    if (sentence.length >= maxLen) {
      // Long sentence — flush buffer, then split at commas/semicolons
      if (buf) { chunks.push(buf); buf = ''; }
      const parts = sentence
        .split(/[,،،؛;]+/)
        .map(p => p.trim())
        .filter(p => p.length > 0);
      let sub = '';
      for (const part of parts) {
        if ((sub + part).length > maxLen && sub) {
          chunks.push(sub);
          sub = part;
        } else {
          sub = sub ? `${sub}، ${part}` : part;
        }
      }
      if (sub) chunks.push(sub);
    } else if (buf && (buf + ' ' + sentence).length > maxLen) {
      chunks.push(buf);
      buf = sentence;
    } else {
      buf = buf ? `${buf} ${sentence}` : sentence;
    }
  }
  if (buf) chunks.push(buf);

  return chunks.filter(c => c.trim().length > 0);
}

// ══════════════════════════════════════════════════════════════════
// SPEAK TEXT — Chunked sequential engine
// Each chunk is spoken in sequence via onend chaining.
// No keepalive timer needed — short chunks never hit the cutoff.
// ══════════════════════════════════════════════════════════════════
export function speakText(
  text: string,
  lang: string,
  onEnd: () => void,
  onStart?: () => void,
): void {
  if (!('speechSynthesis' in window)) { onEnd(); return; }

  // Cancel any running speech and reset cancellation flag for this run
  _isCancelled = false;
  window.speechSynthesis.cancel();

  const clean = ttsClean(text);
  if (!clean.trim()) { onEnd(); return; }

  const chunks = splitIntoChunks(clean);
  if (!chunks.length) { onEnd(); return; }

  const { rate, pitch } = getLangParams(lang);
  let started = false;

  const playChunk = (idx: number) => {
    if (_isCancelled) { onEnd(); return; }
    if (idx >= chunks.length) { onEnd(); return; }

    const voices = window.speechSynthesis.getVoices();
    const voice = selectBestVoice(voices, lang);

    const u = new SpeechSynthesisUtterance(chunks[idx]);
    u.lang   = lang;
    u.rate   = rate;
    u.pitch  = pitch;
    u.volume = 1.0;
    if (voice) u.voice = voice;

    // Fire onStart only once (on first chunk)
    u.onstart = () => {
      if (!started) { started = true; onStart?.(); }
    };

    u.onend = () => {
      if (!_isCancelled) {
        // 80ms natural breath-pause between chunks — eliminates robotic rapid-fire
        // and gives the listener a moment to absorb each sentence naturally.
        setTimeout(() => playChunk(idx + 1), 80);
      } else {
        onEnd();
      }
    };

    u.onerror = (e: SpeechSynthesisErrorEvent) => {
      if ((e.error as string) === 'interrupted' || _isCancelled) {
        // Interrupted by stopTTS() — don't continue
        return;
      }
      // On a chunk error (e.g., unsupported char), skip and continue
      setTimeout(() => playChunk(idx + 1), 100);
    };

    window.speechSynthesis.speak(u);
  };

  // Wait for voices to be loaded before speaking
  const voices = window.speechSynthesis.getVoices();
  if (voices.length > 0) {
    playChunk(0);
  } else {
    window.speechSynthesis.addEventListener('voiceschanged', () => playChunk(0), { once: true });
  }
}

/** Stop all TTS audio immediately */
export function stopTTS(): void {
  _isCancelled = true;
  if ('speechSynthesis' in window) {
    window.speechSynthesis.cancel();
  }
}

/** List available voices for a given language base code */
export function getAvailableVoices(lang: string): SpeechSynthesisVoice[] {
  if (!('speechSynthesis' in window)) return [];
  const base = lang.split('-')[0].toLowerCase();
  return window.speechSynthesis.getVoices().filter(v =>
    v.lang.toLowerCase().startsWith(base)
  );
}

/** Check if TTS is supported in current browser */
export function isTTSSupported(): boolean {
  return 'speechSynthesis' in window;
}

