import { z } from 'zod';
import { createEndpoint, AdminSettings } from 'zite-integrations-backend-sdk';

const DEFAULT_PASSWORD = 'admin@2024';

export default createEndpoint({
  description: 'Verify admin panel access password',
  inputSchema: z.object({ password: z.string() }),
  outputSchema: z.object({ success: z.boolean() }),
  execute: async ({ input }) => {
    let setting = await AdminSettings.findOne({ filters: { settingKey: 'admin_password' } });
    if (!setting) {
      await AdminSettings.create({ record: { settingKey: 'admin_password', settingValue: DEFAULT_PASSWORD, description: 'Admin panel access password' } });
      return { success: input.password === DEFAULT_PASSWORD };
    }
    return { success: input.password === (setting.settingValue ?? DEFAULT_PASSWORD) };
  },
});

import { z } from 'zod';
