export default createEndpoint({
  description: 'Get public app data: tickers, banner, rates, AI settings, image limits, withdrawal limit, color presets, global notification',
  inputSchema: z.object({}),
  outputSchema: z.object({
    // ── App Shell ──────────────────────────────────────────────────────────
    tickers:            z.array(z.object({ id: z.string(), content: z.string() })),
    bannerText:         z.string().nullable(),
    bannerUrl:          z.string().nullable(),
    tickerEnabled:      z.boolean(),
    tickerColorPreset:  z.string().nullable(),
    tickerSpeed:        z.number(),
    lcdColorPreset:     z.string().nullable(),
    globalNotification: z.object({ seq: z.string(), message: z.string() }).nullable(),

    // ── AI Engines ─────────────────────────────────────────────────────────
    aiName:            z.string(),
    codingRestricted:  z.boolean(),

    // ── Wallet / Exchange ──────────────────────────────────────────────────
    usdToPkr:          z.number(),
    minWithdrawUsd:    z.number(),
    referralCoins:     z.number(),

    // ── Image Studio Limits (exposed so media pages can react without extra call)
    imgLimitFreeD1:    z.number(),
    imgLimitFreeD2:    z.number(),
    imgLimitFreeD3:    z.number(),
    imgLimitVip:       z.number(),   // 0 = unlimited

    // ── Video Studio ────────────────────────────────────────────────────────
    vidLimitVip:       z.number(),

    // ── Weather/Maps API Key (for 4-module quad-link) ──────────────────────
