  execute: async () => {
    const [tickersRes, settingsRes] = await Promise.all([
      NewsTickers.findAll({ filters: { isActive: true }, limit: 20 }),
      AdminSettings.findAll({ limit: 500 }),
    ]);

    const cfg = Object.fromEntries(
      settingsRes.records.map(r => [r.settingKey ?? '', r.settingValue ?? ''])
