// LINK DEVICE — Authenticated: bind device fingerprint to user account
// Called after every successful login so the server always knows the
// current device ID for this user.
// Enables: device recognition across cache clears + one-device limit.
// ══════════════════════════════════════════════════════════════════
import { z } from 'zod';
import { createEndpoint, Users, ZiteError } from 'zite-integrations-backend-sdk';

export default createEndpoint({
  description: 'Authenticated: link a device fingerprint to the current user account. Enforces one-account-per-device by rejecting if the device is already used by a different account.',
  authenticated: true,
  inputSchema: z.object({
    deviceId: z.string().min(4).max(200),
  }),
  outputSchema: z.object({
    success:  z.boolean(),
    conflict: z.boolean().optional(), // true when device belongs to a different account
  }),
  execute: async ({ input, context }) => {
    // Check if this device is already claimed by a DIFFERENT user
    const existing = await Users.findOne({
      filters: { deviceId: input.deviceId },
      fields: ['id'],
    });

    if (existing && existing.id !== context.user.id) {
      return { success: false, conflict: true };
    }

    // Link (or update) this device to the current user
    // Always update — handles v2→v3 fingerprint migration seamlessly
    const currentUser = await Users.findOne({
      id: context.user.id,
      fields: ['deviceId'],
    });
    if (currentUser?.deviceId !== input.deviceId) {
      await Users.update({
        id: context.user.id,
        record: { deviceId: input.deviceId },
      });
    }

    return { success: true };
  },
});

