import { z } from 'zod';
import { createEndpoint, VipPurchases, Withdrawals, Users, AdminSettings, NewsTickers, LevelConfig, VipPlans, SupportTickets, ZiteError } from 'zite-integrations-backend-sdk';

export default createEndpoint({
  description: 'Admin actions: approve/reject/hold/revoke purchases & withdrawals, manage settings, update users, reply to support tickets (password-protected)',
  inputSchema: z.object({
    action: z.string(),
    id: z.string().optional(),
    data: z.record(z.any()).optional(),
    adminToken: z.string(),
  }),
  outputSchema: z.object({ success: z.boolean() }),
  execute: async ({ input }) => {
    const pwdSetting = await AdminSettings.findOne({ filters: { settingKey: 'admin_password' } });
    const correctPwd = pwdSetting?.settingValue ?? 'admin@2024';
    if (input.adminToken !== correctPwd) throw new ZiteError({ code: 'UNAUTHORIZED', message: 'Incorrect admin password' });

    const { action, id, data } = input;

    // ── VIP Purchases ──────────────────────────────────────────────
    if (action === 'approve_vip') {
      const p = await VipPurchases.findOne({ id });
      if (!p) throw new ZiteError({ code: 'NOT_FOUND', message: 'Purchase not found' });
      const plan = await VipPlans.findOne({ filters: { planName: p.planName } });
      const days = plan?.durationDays ?? 30;
      const expiry = new Date();
