      if (p) {
        const user = await Users.findOne({ filters: { email: p.userEmail } });
        if (user && user.vipStatus === 'Pending') await Users.update({ id: user.id, record: { vipStatus: 'Free', vipPlan: '' } });
      }
      return { success: true };
    }

    // ── POST-APPROVAL: Revoke VIP (even if already Approved/Active) ──
    if (action === 'revoke_vip') {
      const p = await VipPurchases.findOne({ id });
      if (!p) throw new ZiteError({ code: 'NOT_FOUND', message: 'Purchase not found' });
      await VipPurchases.update({ id, record: { status: 'Rejected', adminNotes: data?.notes ?? 'Revoked by admin' } });
      const user = await Users.findOne({ filters: { email: p.userEmail } });
      if (user) {
        await Users.update({ id: user.id, record: { vipStatus: 'Free', vipPlan: '', vipExpiresAt: new Date(0).toISOString() } });
      }
      return { success: true };
    }

    // ── Withdrawals ────────────────────────────────────────────────
    if (action === 'approve_withdrawal') {
      await Withdrawals.update({ id, record: { status: 'Approved' } });
      return { success: true };
    }

    if (action === 'reject_withdrawal') {
      const w = await Withdrawals.findOne({ id });
      if (w) {
        await Withdrawals.update({ id, record: { status: 'Rejected' } });
        const user = await Users.findOne({ filters: { email: w.userEmail } });
        if (user) await Users.update({ id: user.id, record: { usdBalance: (user.usdBalance ?? 0) + (w.amountUsd ?? 0) } });
      }
      return { success: true };
    }

    if (action === 'hold_withdrawal') {
      await Withdrawals.update({ id, record: { status: 'Hold' } });
      return { success: true };
    }

    if (action === 'restore_withdrawal') {
      await Withdrawals.update({ id, record: { status: 'Pending' } });
      return { success: true };
    }

    // ── POST-APPROVAL: Revoke withdrawal & instantly refund balance ──
    if (action === 'revoke_withdrawal') {
      const w = await Withdrawals.findOne({ id });
      if (!w) throw new ZiteError({ code: 'NOT_FOUND', message: 'Withdrawal not found' });
      await Withdrawals.update({ id, record: { status: 'Rejected' } });
      const user = await Users.findOne({ filters: { email: w.userEmail } });
      if (user) {
        await Users.update({ id: user.id, record: { usdBalance: (user.usdBalance ?? 0) + (w.amountUsd ?? 0) } });
      }
      return { success: true };
    }

    // ── Admin Settings ──────────────────────────────────────────────
    if (action === 'upsert_setting') {
      const existing = await AdminSettings.findOne({ filters: { settingKey: data?.key } });
      if (existing) await AdminSettings.update({ id: existing.id, record: { settingValue: data?.value } });
      else await AdminSettings.create({ record: { settingKey: data?.key, settingValue: data?.value, description: data?.desc ?? '' } });
      return { success: true };
    }

    // ── Global Notification (Bell) ───────────────────────────────────
    if (action === 'send_notification') {
      if (!data?.message?.trim()) throw new ZiteError({ code: 'BAD_REQUEST', message: 'Notification message is required' });
      const seq = String(Date.now());
      const [existingMsg, existingSeq] = await Promise.all([
        AdminSettings.findOne({ filters: { settingKey: 'global_notification_message' } }),
        AdminSettings.findOne({ filters: { settingKey: 'global_notification_seq' } }),
      ]);
      if (existingMsg) await AdminSettings.update({ id: existingMsg.id, record: { settingValue: data.message.trim() } });
      else await AdminSettings.create({ record: { settingKey: 'global_notification_message', settingValue: data.message.trim(), description: 'Global notification for bell' } });
      if (existingSeq) await AdminSettings.update({ id: existingSeq.id, record: { settingValue: seq } });
      else await AdminSettings.create({ record: { settingKey: 'global_notification_seq', settingValue: seq, description: 'Notification sequence counter' } });
      return { success: true };
    }

    // ── News Tickers ────────────────────────────────────────────────
    if (action === 'save_ticker') {
      if (id) await NewsTickers.update({ id, record: { content: data?.content, isActive: data?.isActive, sortOrder: data?.sortOrder } });
      else await NewsTickers.create({ record: { content: data?.content, isActive: true, sortOrder: data?.sortOrder ?? 0 } });
      return { success: true };
    }

    if (action === 'delete_ticker') { await NewsTickers.delete({ id: id! }); return { success: true }; }

    // ── Level Config ───────────────────────────────────────────────
    if (action === 'save_level') {
      const lev = await LevelConfig.findOne({ filters: { levelNumber: data?.levelNumber } });
      if (lev) await LevelConfig.update({ id: lev.id, record: data as any });
      else await LevelConfig.create({ record: data as any });
      return { success: true };
    }

    // ── Users: Block / Unblock ──────────────────────────────────────
    if (action === 'block_user') {
      if (!id) throw new ZiteError({ code: 'BAD_REQUEST', message: 'User ID required' });
      await Users.update({ id, record: { status: 'Blocked' } });
      return { success: true };
    }

    if (action === 'unblock_user') {
      if (!id) throw new ZiteError({ code: 'BAD_REQUEST', message: 'User ID required' });
      await Users.update({ id, record: { status: 'Active', wrongPromptCount: 0 } });
      return { success: true };
    }

    // ── Users ──────────────────────────────────────────────────────
    if (action === 'update_user') {
      if (!id) throw new ZiteError({ code: 'BAD_REQUEST', message: 'User ID required' });
      const updateRecord: Record<string, any> = {};

      if (data?.usdBalance !== undefined) updateRecord.usdBalance = parseFloat(data.usdBalance) || 0;

      if (data?.pkrAdjust && parseFloat(data.pkrAdjust) > 0) {
        const rate = parseFloat(data.usdToPkr ?? '280') || 280;
        const usdAdj = parseFloat(data.pkrAdjust) / rate;
        const currentUser = await Users.findOne({ id });
        const currentBalance = currentUser?.usdBalance ?? 0;
        if (data.pkrMode === 'deduct') {
          updateRecord.usdBalance = Math.max(0, currentBalance - usdAdj);
        } else {
          updateRecord.usdBalance = currentBalance + usdAdj;
        }
      }

      if (data?.coins !== undefined) updateRecord.coins = parseFloat(data.coins) || 0;
      if (data?.level !== undefined) updateRecord.level = parseInt(data.level) || 1;
      if (data?.marginPercent !== undefined) updateRecord.marginPercent = parseFloat(data.marginPercent) || 0;
      if (data?.vipStatus !== undefined) updateRecord.vipStatus = data.vipStatus;

      await Users.update({ id, record: updateRecord });
      return { success: true };
    }

    // ── VIP Plans ──────────────────────────────────────────────────
    if (action === 'save_vip_plan') {
      if (!id) throw new ZiteError({ code: 'BAD_REQUEST', message: 'Plan ID required' });

      const planRecord: Record<string, any> = {
        priceUsd: data?.priceUsd !== undefined ? parseFloat(data.priceUsd) || 0 : undefined,
        originalPrice: data?.originalPrice !== undefined ? parseFloat(data.originalPrice) || 0 : undefined,
        features: data?.features,
        isActive: data?.isActive,
      };

      if (data?.timerEndDate && String(data.timerEndDate).trim().length > 0) {
        planRecord.timerEndDate = new Date(data.timerEndDate).toISOString();
      } else if (data?.clearTimer === true) {
        planRecord.timerEndDate = undefined;
      }

      const cleanRecord: Record<string, any> = {};
      Object.entries(planRecord).forEach(([k, v]) => { if (v !== undefined) cleanRecord[k] = v; });

      await VipPlans.update({ id, record: cleanRecord });
      return { success: true };
    }

    // ── Support Tickets ───────────────────────────────────────────
    if (action === 'reply_ticket') {
      if (!id) throw new ZiteError({ code: 'BAD_REQUEST', message: 'Ticket ID required' });
      if (!data?.reply?.trim()) throw new ZiteError({ code: 'BAD_REQUEST', message: 'Reply message required' });
      await SupportTickets.update({ id, record: { adminReply: data.reply.trim(), status: 'Replied' } });
      return { success: true };
    }

    if (action === 'close_ticket') {
      if (!id) throw new ZiteError({ code: 'BAD_REQUEST', message: 'Ticket ID required' });
      await SupportTickets.update({ id, record: { status: 'Closed' } });
      return { success: true };
    }

    throw new ZiteError({ code: 'BAD_REQUEST', message: `Unknown action: ${action}` });
  },
});

