// CHECK DEVICE — Unauthenticated device recognition lookup
// Called on app load when user is NOT logged in.
// Returns masked email/name if the device fingerprint is registered.
// Used to show "Welcome back!" banner and enable one-tap re-login.
// ══════════════════════════════════════════════════════════════════
import { z } from 'zod';
import { createEndpoint, Users } from 'zite-integrations-backend-sdk';

// Simple mask: "john.doe@gmail.com" → "j***@gmail.com"
function maskEmail(email: string): string {
  const [local = '', domain = ''] = email.split('@');
  return local.slice(0, 1) + '***@' + domain;
}

export default createEndpoint({
  description: 'Unauthenticated: look up whether a device fingerprint is already linked to a user account. Returns masked email and name for the device-recognition UI.',
  authenticated: false,
  inputSchema: z.object({
    deviceId: z.string().min(4).max(200),
  }),
  outputSchema: z.object({
    registered:  z.boolean(),
    maskedEmail: z.string().optional(),
    name:        z.string().optional(),
  }),
  execute: async ({ input }) => {
    if (!input.deviceId || input.deviceId.length < 4) {
      return { registered: false };
    }
    const user = await Users.findOne({
      filters: { deviceId: input.deviceId },
      fields: ['email', 'name'],
    });
    if (!user?.email) return { registered: false };

    return {
      registered:  true,
      maskedEmail: maskEmail(user.email),
      name:        user.name || undefined,
    };
  },
});

