      priceUsd: z.number(), originalPrice: z.number(), features: z.string().nullable(), sortOrder: z.number(),
    })),
    saleEndTime: z.string().nullable(),
    usdToPkr: z.number(),
    paymentInfo: z.record(z.string()),
  }),
  execute: async () => {
    const [plansRes, settingsRes] = await Promise.all([
      VipPlans.findAll({ limit: 20 }),
      AdminSettings.findAll({ limit: 500 }),
    ]);

    let plans = plansRes.records.filter(p => p.isActive);

    // Auto-seed if database is empty (migration recovery)
    if (plans.length === 0) {
      for (const p of DEFAULT_PLANS) {
        await VipPlans.create({ record: p });
      }
      const refetch = await VipPlans.findAll({ filters: { isActive: true }, limit: 20 });
      plans = refetch.records;
    }

    const cfg = Object.fromEntries(settingsRes.records.map(r => [r.settingKey ?? '', r.settingValue ?? '']));

    return {
      plans: plans
        .sort((a, b) => (a.sortOrder ?? 0) - (b.sortOrder ?? 0))
        .map(p => ({
          id: p.id, planName: p.planName ?? '', durationDays: p.durationDays ?? 0,
          priceUsd: p.priceUsd ?? 0, originalPrice: p.originalPrice ?? 0,
          features: p.features ?? null, sortOrder: p.sortOrder ?? 0,
        })),
      saleEndTime: cfg['vip_sale_end_time'] ?? null,
      usdToPkr: parseFloat(cfg['usd_to_pkr'] ?? '280') || 280,
      paymentInfo: cfg,
    };
  },
});

