import { useState, useCallback } from 'react';
import ChatEngine, { EngineType } from '@/components/chat/ChatEngine';

const ENGINES: EngineType[] = ['tasks', 'coding', 'spiritual'];

export default function ChatPage() {
  const [active, setActive] = useState<EngineType>('tasks');

  const cycleEngine = useCallback(() => {
    setActive(prev => {
      const idx = ENGINES.indexOf(prev);
      return ENGINES[(idx + 1) % ENGINES.length];
    });
  }, []);

  return (
    <div className="flex flex-col h-full overflow-hidden">
      {/* Engine panels — all mounted to preserve history when switching */}
      <div className="flex-1 min-h-0 overflow-hidden">
        {ENGINES.map(eng => (
          <div key={eng} className={eng === active ? 'h-full flex flex-col' : 'hidden'}>
            <ChatEngine engine={eng} onCycleEngine={cycleEngine} />
          </div>
        ))}
      </div>
    </div>
  );
}

import { z } from 'zod';
import { createEndpoint, VipPurchases, Withdrawals, Users, AdminSettings, NewsTickers, LevelConfig, VipPlans, SupportTickets, Referrals, ZiteError } from 'zite-integrations-backend-sdk';

export default createEndpoint({
  description: 'Admin: fetch data for a specific dashboard tab (password-protected)',
  inputSchema: z.object({
    tab: z.enum(['vip', 'withdrawals', 'users', 'settings', 'tickers', 'levels', 'vip_plans', 'support', 'referrals_for_user']),
    adminToken: z.string(),
    userEmail: z.string().optional(), // for referrals_for_user
  }),
  outputSchema: z.object({ data: z.any() }),
  execute: async ({ input }) => {
    const pwdSetting = await AdminSettings.findOne({ filters: { settingKey: 'admin_password' } });
    const correctPwd = pwdSetting?.settingValue ?? 'admin@2024';
    if (input.adminToken !== correctPwd) throw new ZiteError({ code: 'UNAUTHORIZED', message: 'Incorrect admin password' });

    const { tab } = input;

    if (tab === 'vip') {
      // Paginate to get all VIP purchases
      const all: any[] = [];
      let offset = 0;
      let hasMore = true;
      while (hasMore) {
        const res = await VipPurchases.findAll({ limit: 500, offset });
        all.push(...res.records);
        hasMore = res.hasMore;
        offset += res.records.length;
        if (all.length >= 2000) break; // safety cap
      }
      return { data: all };
    }

    if (tab === 'withdrawals') {
      const all: any[] = [];
      let offset = 0;
      let hasMore = true;
      while (hasMore) {
        const res = await Withdrawals.findAll({ limit: 500, offset });
        all.push(...res.records);
        hasMore = res.hasMore;
        offset += res.records.length;
        if (all.length >= 2000) break;
      }
      return { data: all };
    }

    if (tab === 'users') {
      const all: any[] = [];
      let offset = 0;
      let hasMore = true;
      while (hasMore) {
        const res = await Users.findAll({ limit: 500, offset });
        all.push(...res.records);
        hasMore = res.hasMore;
        offset += res.records.length;
        if (all.length >= 5000) break; // higher cap for users
      }
      return { data: all };
    }

    if (tab === 'settings') {
      const res = await AdminSettings.findAll({ limit: 500 });
      return { data: res.records };
    }

    if (tab === 'tickers') {
      const res = await NewsTickers.findAll({ limit: 100 });
      return { data: res.records };
    }

    if (tab === 'levels') {
      const res = await LevelConfig.findAll({ limit: 60 });
      return { data: res.records };
    }

    if (tab === 'vip_plans') {
      const res = await VipPlans.findAll({ limit: 20 });
      return { data: res.records };
    }

    if (tab === 'support') {
      const all: any[] = [];
      let offset = 0;
      let hasMore = true;
      while (hasMore) {
        const res = await SupportTickets.findAll({ limit: 500, offset });
        all.push(...res.records);
        hasMore = res.hasMore;
        offset += res.records.length;
        if (all.length >= 2000) break;
      }
      const sorted = all.sort((a, b) =>
        new Date(b.submittedAt || 0).getTime() - new Date(a.submittedAt || 0).getTime()
      );
      return { data: sorted };
    }

    if (tab === 'referrals_for_user') {
      if (!input.userEmail) return { data: [] };
      const res = await Referrals.findAll({ filters: { referrerEmail: input.userEmail }, limit: 500 });
      const sorted = res.records.sort((a, b) =>
        new Date(b.joinedAt || 0).getTime() - new Date(a.joinedAt || 0).getTime()
      );
      return { data: sorted };
    }

    return { data: [] };
  },
});

import { z } from 'zod';
