// ── Region/province → Urdu (Pakistan focused) ────────────────────
const REGION_URDU: Record<string, string> = {
  'Punjab': 'پنجاب', 'Sindh': 'سندھ',
  'Khyber Pakhtunkhwa': 'خیبر پختونخوا', 'Balochistan': 'بلوچستان',
