  'Azad Kashmir': 'آزاد کشمیر', 'Gilgit-Baltistan': 'گلگت بلتستان',
};

/**
 * Convert API response (city, region, country) to clean Urdu string.
 */
export function toUrduLocation(city?: string, region?: string, country?: string): string {
  if (!city && !country) return 'پاکستان';
  if (city && CITY_URDU[city]) return CITY_URDU[city];
  const parts: string[] = [];
  if (city) parts.push(city);
  if (region) parts.push(REGION_URDU[region] ?? region);
  if (country) parts.push(COUNTRY_URDU[country] ?? country);
  return parts.join('، ') || 'پاکستان';
}

/**
 * Extract city from timezone string and return Urdu. Offline fallback only.
 */
export function tzToUrduFallback(tz?: string): string {
  if (!tz) return 'پاکستان';
  const city = tz.split('/').pop()?.replace(/_/g, ' ') ?? '';
  return CITY_URDU[city] ?? 'پاکستان';
}

// ── Global location state ────────────────────────────────────────
let _globalUrduLocation = 'پاکستان';
let _resolved = false;

export function setGlobalUrduLocation(loc: string) { _globalUrduLocation = loc; }
export function getGlobalUrduLocation(): string { return _globalUrduLocation; }
export function isLocationResolved(): boolean { return _resolved; }

// ── Reverse geocode from lat/lon using free Nominatim API ────────
async function reverseGeocode(lat: number, lon: number): Promise<string | null> {
  try {
    const res = await fetch(
      `https://nominatim.openstreetmap.org/reverse?lat=${lat}&lon=${lon}&format=json&accept-language=ur&zoom=12`,
      { signal: AbortSignal.timeout(5000), headers: { 'User-Agent': 'RoohaniGuideAI/2.0' } }
    );
    if (!res.ok) return null;
    const data = await res.json() as {
      address?: {
        city?: string; town?: string; village?: string; hamlet?: string;
        county?: string; state_district?: string; district?: string;
        state?: string; country?: string;
      };
    };
    const a = data.address;
    if (!a) return null;

    const cityName = a.city || a.town || a.village || a.hamlet || '';
    const district = a.county || a.state_district || a.district || '';
    const state = a.state || '';
    const country = a.country || '';

    // Check if Nominatim returned Urdu text (it usually does with accept-language=ur)
    const parts = [cityName, district, state, country].filter(Boolean);
    if (parts.length === 0) return null;

    // If parts look English, try our Urdu mapping
    const firstPart = cityName || district;
    if (firstPart && CITY_URDU[firstPart]) return CITY_URDU[firstPart];

    // Nominatim with accept-language=ur often returns Urdu natively for Pakistan/Arab regions
    // Deduplicate adjacent identical parts
    const deduped: string[] = [];
    for (const p of parts) {
      if (deduped.length === 0 || deduped[deduped.length - 1] !== p) deduped.push(p);
    }
    return deduped.join('، ');
  } catch {
    return null;
  }
}

/**
 * Master location resolver — GPS first, then IP fallback.
 * Call once at app startup. Sets the global Urdu location.
 */
export async function resolveAndSetLocation(): Promise<string> {
  // Step 1: Immediate timezone fallback (instant, no network)
  const tz = Intl.DateTimeFormat().resolvedOptions().timeZone;
  _globalUrduLocation = tzToUrduFallback(tz);
  (window as any).__cleanLocation = _globalUrduLocation;

  // Step 2: Try browser Geolocation API (GPS — most accurate)
  const gpsResult = await new Promise<string | null>((resolve) => {
    if (!navigator.geolocation) { resolve(null); return; }
    const timeout = setTimeout(() => resolve(null), 6000);
    navigator.geolocation.getCurrentPosition(
      async (pos) => {
        clearTimeout(timeout);
        const urdu = await reverseGeocode(pos.coords.latitude, pos.coords.longitude);
        resolve(urdu);
      },
      () => { clearTimeout(timeout); resolve(null); },
      { enableHighAccuracy: false, timeout: 5000, maximumAge: 300000 }
    );
  });

  if (gpsResult) {
    _globalUrduLocation = gpsResult;
    _resolved = true;
    (window as any).__cleanLocation = _globalUrduLocation;
    return _globalUrduLocation;
  }

  // Step 3: IP-based fallback (less accurate but no permission needed)
  try {
    const res = await fetch('https://ipapi.co/json/', { signal: AbortSignal.timeout(4000) });
    const d = await res.json();
    if (d?.city) {
      _globalUrduLocation = toUrduLocation(d.city, d.region, d.country_name);
    }
  } catch { /* keep timezone fallback */ }

  _resolved = true;
  (window as any).__cleanLocation = _globalUrduLocation;
  return _globalUrduLocation;
}

