  const [loading, setLoading] = useState(false);

  const handleLogin = async () => {
    if (!pwd.trim()) return;
    setLoading(true);
    try {
      const r = await adminLogin({ password: pwd.trim() });
      if (r.success) {
        sessionStorage.setItem('admin_token', pwd.trim());
        onLogin(pwd.trim());
        toast.success('🔓 Admin access granted');
      } else {
        toast.error('Incorrect password. Please try again.');
