                    <p className="text-[9px] text-muted-foreground font-mono truncate">{w.id?.slice(0, 12)}...</p>
                  </td>
                  <td className="px-3 py-2.5 whitespace-nowrap">
                    <span className="bg-muted border border-border rounded-full px-2 py-0.5 text-[10px] font-semibold">{w.method}</span>
