                          className="h-6 text-[10px] px-2 bg-yellow-600 hover:bg-yellow-600/90 text-white gap-1 whitespace-nowrap">
                          <Pause size={9} /> Hold
                        </Button>
                      </div>
                    )}
                    {w.status === 'Hold' && (
                      <div className="flex flex-col gap-1">
                        <Button size="sm" onClick={() => doAction(w.id, 'restore_withdrawal')} disabled={!!busy}
                          className="h-6 text-[10px] px-2 bg-blue-600 hover:bg-blue-600/90 text-white gap-1 whitespace-nowrap">
                          <Play size={9} /> Restore
