// ─── System Initialize Section ───────────────────────────────────────
function SystemInitSection({ token }: { token: string }) {
  const [loading, setLoading] = useState(false);
  type GatewayInfo = { name: string; status: string; synced: boolean };
  type SeedResult = { success: boolean; seeded: Record<string, number>; skipped: Record<string, number>; message: string; nextStep?: string; gatewayStatus?: GatewayInfo[] };
  const [result, setResult] = useState<SeedResult | null>(null);

  const runSeed = async () => {
    setLoading(true);
    try {
      const res = await seedDatabase({ adminToken: token });
      setResult(res as SeedResult);
      const total = Object.values(res.seeded).reduce((a, b) => a + b, 0);
      if (total === 0) toast.info('ℹ️ Database already fully initialized — nothing to seed');
      else toast.success('🚀 System initialized! ' + total + ' records seeded — all 5 modules connected');
      if ((res as any).nextStep) toast.info((res as any).nextStep);
    } catch (e: any) {
      toast.error(e?.message ?? 'Initialization failed');
    } finally { setLoading(false); }
  };

  const total = result ? Object.values(result.seeded).reduce((a, b) => a + b, 0) : -1;

  return (
    <div className="rounded-2xl border-2 border-primary/40 bg-primary/5 p-4 space-y-3">
      {/* Header */}
      <div className="flex items-center gap-2">
        <div className="w-8 h-8 rounded-xl bg-primary/15 border border-primary/30 flex items-center justify-center shrink-0">
          <Zap size={16} className="text-primary" />
        </div>
        <div>
          <p className="font-black text-sm text-foreground">🚀 Initialize System</p>
          <p className="text-[10px] text-muted-foreground">One-click setup for new deployment — seeds all default data</p>
        </div>
        {result && (
          <span className={`ml-auto text-[9px] font-bold px-2 py-1 rounded-full border ${total === 0 ? 'bg-muted text-muted-foreground border-border' : 'bg-green-500/15 text-green-400 border-green-500/30'}`}>
            {total === 0 ? 'READY' : `+${total} SEEDED`}
          </span>
        )}
      </div>

      {/* What will be seeded */}
      <div className="grid grid-cols-2 gap-1.5">
        {[
          { icon: '👑', label: '7 VIP Plans', sub: 'Starter → Lifetime' },
          { icon: '📈', label: '5 Level Configs', sub: 'L1 Starter → L5 Diamond' },
          { icon: '⚙️', label: '39 Default Settings', sub: 'AI keys + all 5 modules wired' },
          { icon: '📢', label: '4 News Tickers', sub: 'Welcome messages' },
          { icon: '🎬', label: '3 Video Gateways', sub: 'HuggingFace → Stability → Veo' },
          { icon: '🔄', label: 'Self-Healing', sub: 'Auto-creates missing rows' },
        ].map(item => (
          <div key={item.label} className="flex items-start gap-2 bg-muted/40 border border-border rounded-xl px-2.5 py-2">
            <span className="text-sm shrink-0">{item.icon}</span>
            <div className="min-w-0">
              <p className="text-[10px] font-bold truncate">{item.label}</p>
              <p className="text-[9px] text-muted-foreground truncate">{item.sub}</p>
            </div>
          </div>
        ))}
      </div>

      {/* Result summary */}
      {result && (
        <div className={`rounded-xl border px-3 py-2.5 text-xs space-y-1 ${total === 0 ? 'border-border bg-muted/30 text-muted-foreground' : 'border-green-500/30 bg-green-950/20 text-green-400'}`}>
          <p className="font-bold">{result.message}</p>
          {result.nextStep && (
            <p className="text-yellow-300 font-semibold text-[10px] mt-1">{result.nextStep}</p>
          )}
          {total > 0 && (
            <div className="grid grid-cols-5 gap-1 mt-1">
              {Object.entries(result.seeded).map(([k, v]) => (
                <div key={k} className="text-center">
                  <p className="text-sm font-black text-green-400">{v}</p>
                  <p className="text-[8px] text-muted-foreground capitalize">{k.replace(/([A-Z])/g, ' $1')}</p>
                </div>
              ))}
            </div>
          )}
          {/* Gateway sync status */}
          {result.gatewayStatus && result.gatewayStatus.length > 0 && (
            <div className="mt-2 space-y-1 border-t border-border/40 pt-2">
              <p className="text-[10px] font-bold text-foreground">🎬 Video Gateway Status:</p>
              {result.gatewayStatus.map(g => (
                <div key={g.name} className="flex items-center gap-2">
                  <span className={`w-2 h-2 rounded-full shrink-0 ${g.synced ? 'bg-green-500' : 'bg-yellow-500'}`} />
                  <span className="text-[10px] font-semibold flex-1">{g.name}</span>
                  <span className={`text-[9px] ${g.synced ? 'text-green-400' : 'text-yellow-400'}`}>{g.status}</span>
                </div>
              ))}
            </div>
          )}
        </div>
      )}

      <Button onClick={runSeed} disabled={loading}
        className="w-full bg-primary text-primary-foreground font-bold h-10 gap-2 text-sm">
        {loading ? <><Loader2 size={15} className="animate-spin" /> Initializing Database...</> : <><Zap size={15} /> Initialize System Now</>}
      </Button>

      <p className="text-[9px] text-muted-foreground text-center">
        Safe to run multiple times — only missing records are created, existing data is never overwritten
      </p>
    </div>
  );
}

