function GenerationLimitsTab({ token }: { token: string }) {
  const [values, setValues] = useState<Record<string, string>>({});
  const [saving, setSaving] = useState<string | null>(null);
  const [loading, setLoading] = useState(true);

  const LIMIT_FIELDS = [
    {
      group: '📸 Image Studio — Free Trial Limits',
      desc: 'Applies to non-VIP users during their 3-day trial period',
      fields: [
        { key: 'img_limit_free_d1', label: 'Day 1 Image Limit', default: '3', hint: 'Images allowed on Day 1 (default: 3)' },
        { key: 'img_limit_free_d2', label: 'Day 2 Image Limit', default: '2', hint: 'Images allowed on Day 2 (default: 2)' },
        { key: 'img_limit_free_d3', label: 'Day 3 Image Limit', default: '1', hint: 'Images allowed on Day 3 (default: 1)' },
      ],
    },
    {
      group: '👑 Image Studio — VIP Daily Limit',
      desc: 'Set to 0 for unlimited (recommended for VIP members)',
      fields: [
        { key: 'img_limit_vip', label: 'VIP Daily Image Limit', default: '0', hint: '0 = unlimited. Any number > 0 enforces a hard cap per day' },
      ],
    },
    {
      group: '🎬 Video Creator Studio — VIP Daily Limit',
      desc: 'Controls how many videos a VIP member can generate per day',
      fields: [
        { key: 'vid_limit_vip', label: 'VIP Daily Video Limit', default: '1', hint: 'Number of videos per VIP user per day (default: 1)' },
      ],
    },
    {
      group: '🎁 Referral Coin Reward',
      desc: 'Total coins split 50-50 between referrer and referee on signup',
      fields: [
        { key: 'referral_reward_coins', label: 'Total Referral Coins', default: '100', hint: '100 coins = $0.10 USD (1000 coins = $1). Split equally on registration' },
      ],
    },
  ];

  const allKeys = LIMIT_FIELDS.flatMap(g => g.fields.map(f => f.key));

  const load = async () => {
    setLoading(true);
    try {
      const res = await adminGetData({ tab: 'settings', adminToken: token });
      const map: Record<string, string> = {};
      ((res as any).data as any[] ?? []).forEach((s: any) => { if (s.settingKey) map[s.settingKey] = s.settingValue ?? ''; });
      setValues(map);
    } catch { toast.error('Failed to load limits'); }
    setLoading(false);
  };

  useEffect(() => { load(); }, []);

  const save = async (key: string, defaultVal: string) => {
    const val = (values[key] ?? defaultVal).trim();
    if (!/^\d+$/.test(val)) { toast.error('Enter a whole number'); return; }
    setSaving(key);
    try {
      const desc = LIMIT_FIELDS.flatMap(g => g.fields).find(f => f.key === key)?.hint ?? '';
      await adminAction({ action: 'upsert_setting', data: { key, value: val, desc }, adminToken: token });
      toast.success('✅ Limit saved!');
    } catch { toast.error('Save failed'); }
    setSaving(null);
  };

  if (loading) return (
    <div className="flex items-center justify-center py-16 text-muted-foreground">
      <Loader2 size={18} className="animate-spin mr-2" /> Loading limits...
