  );

  return (
    <div className="space-y-4 pb-6">
      <div className="flex items-center gap-2 px-1">
        <Gauge size={14} className="text-primary" />
        <p className="font-black text-sm">Generation Limit Control Panel</p>
      </div>
      <p className="text-[10px] text-muted-foreground px-1 -mt-2">
        Set numeric limits for each generation type. Changes apply instantly — no restart needed. Countdown/lockout only triggers after the full limit is exhausted.
      </p>

      {LIMIT_FIELDS.map(group => (
        <div key={group.group} className="rounded-xl border border-border bg-card overflow-hidden">
          <div className="px-3 py-2 bg-muted/50 border-b border-border/60">
            <p className="text-xs font-black">{group.group}</p>
            <p className="text-[10px] text-muted-foreground">{group.desc}</p>
          </div>
          <div className="p-3 space-y-3">
            {group.fields.map(field => (
              <div key={field.key} className="space-y-1.5">
                <label className="text-[11px] font-bold text-foreground">{field.label}</label>
                <div className="flex gap-2">
                  <input
                    type="number"
                    min="0"
                    step="1"
                    value={values[field.key] ?? field.default}
                    onChange={e => setValues(v => ({ ...v, [field.key]: e.target.value }))}
                    className="flex-1 bg-muted border border-border rounded-lg px-3 py-1.5 text-sm font-mono focus:outline-none focus:border-primary/50 transition-colors"
                    placeholder={field.default}
                  />
                  <button
                    onClick={() => save(field.key, field.default)}
                    disabled={saving === field.key}
                    className="flex items-center gap-1 bg-primary text-primary-foreground font-bold text-xs px-3 rounded-lg hover:bg-primary/90 disabled:opacity-50 transition-colors shrink-0"
                  >
                    {saving === field.key ? <><Loader2 size={11} className="animate-spin" /> Saving</> : <><Check size={11} /> Save</>}
                  </button>
                </div>
                <p className="text-[10px] text-muted-foreground/70">{field.hint}</p>
              </div>
            ))}
          </div>
