      ))}

      <div className="rounded-xl border border-primary/20 bg-primary/5 px-3 py-2.5 space-y-1">
        <p className="text-xs font-bold text-primary flex items-center gap-1.5"><Gauge size={11} /> How limits work</p>
        <ul className="text-[10px] text-muted-foreground space-y-0.5 list-disc pl-4">
