// ─── VIP Plans Tab ────────────────────────────────────────────────────
function VIPPlansTab({ token }: { token: string }) {
  const [plans, setPlans] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [edits, setEdits] = useState<Record<string, any>>({});
  const [savingId, setSavingId] = useState<string | null>(null);

  const load = useCallback(async () => {
    setLoading(true);
    try {
      const r = await adminGetData({ tab: 'vip_plans' as any, adminToken: token });
      const sorted = (r.data as any[]).sort((a: any, b: any) => (a.sortOrder ?? 0) - (b.sortOrder ?? 0));
      setPlans(sorted);
      const init: Record<string, any> = {};
      sorted.forEach((p: any) => {
        init[p.id] = {
          priceUsd: String(p.priceUsd ?? 0),
          originalPrice: String(p.originalPrice ?? 0),
          features: p.features ?? '',
          isActive: p.isActive !== false,
          timerEndDate: p.timerEndDate ? new Date(p.timerEndDate).toISOString().slice(0, 16) : '',
        };
      });
      setEdits(init);
    } catch (e: any) { toast.error(e?.message ?? 'Load failed'); }
    finally { setLoading(false); }
  }, [token]);

  useEffect(() => { load(); }, [load]);

  const setField = (id: string, key: string, val: any) =>
    setEdits(prev => ({ ...prev, [id]: { ...prev[id], [key]: val } }));

  const savePlan = async (id: string, planName: string) => {
    const ed = edits[id];
    if (!ed) return;
    setSavingId(id);
    try {
      await adminAction({
        action: 'save_vip_plan',
        id,
        data: {
          priceUsd: parseFloat(ed.priceUsd) || 0,
          originalPrice: parseFloat(ed.originalPrice) || 0,
          features: ed.features,
          isActive: ed.isActive,
          ...(ed.timerEndDate && ed.timerEndDate.trim() ? { timerEndDate: ed.timerEndDate } : { clearTimer: false }),
        },
        adminToken: token,
      });
      toast.success('✅ "' + planName + '" updated!');
    } catch (e: any) { toast.error(e?.message ?? 'Save failed'); }
    finally { setSavingId(null); }
  };

  const getTierBorder = (days: number) => {
    if (days >= 36500) return 'border-primary/50';
    if (days >= 90) return 'border-secondary/40';
    if (days >= 30) return 'border-emerald-500/30';
    if (days >= 15) return 'border-sky-500/30';
    return 'border-border';
  };

  if (loading) return <div className="space-y-3">{[1,2,3].map(i => <Skeleton key={i} className="h-44 rounded-xl" />)}</div>;

  return (
    <div className="space-y-3">
      <div className="flex items-center justify-between">
        <p className="text-xs text-muted-foreground">Manage prices, features & countdown timers</p>
        <button onClick={load} className="flex items-center gap-1 text-xs text-muted-foreground hover:text-foreground"><RefreshCw size={11} /> Refresh</button>
      </div>
      {plans.map((plan: any) => {
        const ed = edits[plan.id] ?? {};
        const days = plan.durationDays ?? 0;
        const salePct = parseFloat(ed.originalPrice) > 0
          ? Math.round(((parseFloat(ed.originalPrice) - parseFloat(ed.priceUsd)) / parseFloat(ed.originalPrice)) * 100) : 0;
        return (
          <div key={plan.id} className={`card-dark rounded-xl p-4 space-y-3 border ${getTierBorder(days)}`}>
            <div className="flex items-center justify-between gap-2">
              <div className="flex items-center gap-2 flex-wrap">
                <Crown size={14} className="text-primary shrink-0" />
                <span className="font-bold text-sm">{plan.planName}</span>
                <span className="text-[10px] bg-muted px-2 py-0.5 rounded-full text-muted-foreground">
                  {days >= 36500 ? '♾️ Unlimited' : days + ' days'}
                </span>
                {salePct > 0 && <span className="text-[10px] font-bold text-destructive">-{salePct}% OFF</span>}
              </div>
              <div className="flex items-center gap-2 shrink-0">
                <label className="flex items-center gap-1 text-xs text-muted-foreground cursor-pointer select-none">
                  <input type="checkbox" checked={ed.isActive !== false}
                    onChange={e => setField(plan.id, 'isActive', e.target.checked)} className="accent-primary" />
                  Active
                </label>
                <Button size="sm" onClick={() => savePlan(plan.id, plan.planName ?? '')} disabled={savingId === plan.id}
                  className="h-7 px-3 text-xs bg-primary text-primary-foreground">
                  {savingId === plan.id ? 'Saving...' : 'Save'}
                </Button>
              </div>
            </div>
            <div className="grid grid-cols-2 gap-2">
              <div className="space-y-1">
                <Label className="text-[10px] text-muted-foreground">💰 Sale Price (USD)</Label>
                <div className="relative">
                  <span className="absolute left-2.5 top-1/2 -translate-y-1/2 text-primary text-xs font-bold">$</span>
                  <Input value={ed.priceUsd ?? ''} type="number" step="0.01" min="0"
                    onChange={e => setField(plan.id, 'priceUsd', e.target.value)}
                    className="bg-muted border-border h-9 text-sm font-bold text-primary pl-6" />
                </div>
              </div>
              <div className="space-y-1">
                <Label className="text-[10px] text-muted-foreground">🏷 Original Price (USD)</Label>
                <div className="relative">
                  <span className="absolute left-2.5 top-1/2 -translate-y-1/2 text-muted-foreground text-xs">$</span>
                  <Input value={ed.originalPrice ?? ''} type="number" step="0.01" min="0"
                    onChange={e => setField(plan.id, 'originalPrice', e.target.value)}
                    className="bg-muted border-border h-9 text-sm text-muted-foreground pl-6" />
                </div>
              </div>
            </div>
            <div className="space-y-1">
              <Label className="text-[10px] text-muted-foreground flex items-center gap-1">
                <Timer size={9} /> Countdown Timer End Date <span className="text-muted-foreground/50">(optional)</span>
              </Label>
              <Input
                type="datetime-local"
                value={ed.timerEndDate ?? ''}
                onChange={e => setField(plan.id, 'timerEndDate', e.target.value)}
                className="bg-muted border-border h-8 text-xs"
              />
              {ed.timerEndDate && (
                <button onClick={() => setField(plan.id, 'timerEndDate', '')} className="text-[10px] text-destructive hover:underline">
                  × Clear timer
                </button>
              )}
            </div>
            <div className="space-y-1">
              <Label className="text-[10px] text-muted-foreground">✨ Features (one per line)</Label>
              <Textarea value={ed.features ?? ''}
                onChange={e => setField(plan.id, 'features', e.target.value)}
                className="bg-muted border-border text-xs resize-none" rows={3}
                placeholder={'Unlimited AI Chat\nUnlimited Images\nPriority Support'} />
            </div>
          </div>
        );
      })}
      {plans.length === 0 && (
        <div className="text-center py-10 text-muted-foreground">
          <Crown size={32} className="mx-auto mb-3 opacity-30" />
          <p className="text-sm">No VIP plans found.</p>
        </div>
      )}
    </div>
  );
}

// ─── Ticker Speed Control ─────────────────────────────────────────
function TickerSpeedControl({ cfg, setCfg, saving, save }: { cfg: Record<string, string>; setCfg: any; saving: string | null; save: (k: string, d: string, v?: string) => void }) {
  const speed = parseInt(cfg['ticker_speed'] ?? '5') || 5;

  const SPEED_LABELS: Record<number, { label: string; emoji: string; color: string }> = {
    1:  { label: 'Ultra Fast',  emoji: '⚡⚡', color: 'text-red-400' },
    2:  { label: 'Very Fast',   emoji: '⚡',   color: 'text-orange-400' },
    3:  { label: 'Fast',        emoji: '🚀',   color: 'text-yellow-400' },
    4:  { label: 'Brisk',       emoji: '🏃',   color: 'text-lime-400' },
    5:  { label: 'Normal',      emoji: '🚶',   color: 'text-primary' },
    6:  { label: 'Steady',      emoji: '🌊',   color: 'text-sky-400' },
    7:  { label: 'Slow',        emoji: '🐢',   color: 'text-blue-400' },
    8:  { label: 'Very Slow',   emoji: '🌙',   color: 'text-violet-400' },
    9:  { label: 'Ultra Slow',  emoji: '🐌',   color: 'text-purple-400' },
    10: { label: 'Glacial',     emoji: '🧊',   color: 'text-indigo-400' },
  };
  const current = SPEED_LABELS[speed] ?? SPEED_LABELS[5];

  return (
    <div className="card-dark rounded-xl p-4 space-y-3 border border-border">
      <p className="text-sm font-bold flex items-center gap-2">
        <Gauge size={14} className="text-primary" /> Ticker Scroll Speed
      </p>
      <p className="text-[10px] text-muted-foreground">Drag the slider to control how fast the headline ticker scrolls. Changes apply instantly.</p>

      {/* Speed preview badge */}
      <div className="flex items-center justify-between bg-muted/40 rounded-xl px-3 py-2">
        <span className={`text-sm font-black ${current.color}`}>{current.emoji} {current.label}</span>
        <span className="text-[10px] text-muted-foreground font-mono">
          {Math.round(8 + (speed - 1) * 7.7)}s / loop
        </span>
      </div>

      {/* Range slider */}
      <input
        type="range" min={1} max={10} step={1}
        value={speed}
        onChange={e => setCfg((c: any) => ({ ...c, ticker_speed: e.target.value }))}
        className="w-full accent-primary h-2 rounded-full cursor-pointer"
      />
      <div className="flex justify-between text-[8px] text-muted-foreground px-0.5">
        <span>1 — Fastest</span>
        <span>5 — Normal</span>
        <span>10 — Slowest</span>
      </div>

      {/* Speed presets */}
      <div className="grid grid-cols-5 gap-1">
        {[1, 3, 5, 7, 10].map(v => (
          <button key={v} onClick={() => setCfg((c: any) => ({ ...c, ticker_speed: String(v) }))}
            className={`rounded-lg py-1.5 text-[9px] font-bold border transition-all text-center ${speed === v ? 'bg-primary/20 text-primary border-primary/40' : 'border-border text-muted-foreground hover:border-border/80'}`}>
            {SPEED_LABELS[v].emoji}<br />{SPEED_LABELS[v].label.split(' ')[0]}
          </button>
        ))}
      </div>

      <button
        onClick={() => save('ticker_speed', 'Ticker scroll speed', String(speed))}
        disabled={saving === 'ticker_speed'}
        className="w-full h-9 rounded-xl bg-primary text-primary-foreground text-xs font-bold hover:bg-primary/90 transition-colors disabled:opacity-50 flex items-center justify-center gap-2">
        {saving === 'ticker_speed' ? <><RefreshCw size={12} className="animate-spin" /> Applying...</> : <><Gauge size={12} /> Apply Speed</>}
      </button>
    </div>
  );
}

// ─── Support Tickets Tab ─────────────────────────────────────────────
function SupportTab({ token }: { token: string }) {
  const [data, setData] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [filter, setFilter] = useState('All');
  const [replies, setReplies] = useState<Record<string, string>>({});
  const [busy, setBusy] = useState<string | null>(null);
  const [expanded, setExpanded] = useState<string | null>(null);

  const load = useCallback(async () => {
    setLoading(true);
    try {
      const r = await adminGetData({ tab: 'support', adminToken: token });
      setData(r.data as any[]);
    } catch (e: any) { toast.error(e?.message ?? 'Failed to load'); }
    finally { setLoading(false); }
  }, [token]);

  useEffect(() => { load(); }, [load]);

  const doReply = async (id: string) => {
    if (!replies[id]?.trim()) { toast.error('Enter a reply message'); return; }
    setBusy(id + '_reply');
    try {
      await adminAction({ action: 'reply_ticket', id, data: { reply: replies[id].trim() }, adminToken: token });
      toast.success('✅ Reply sent! User will see it in their ticket.');
      setReplies(r => { const c = { ...r }; delete c[id]; return c; });
      load();
    } catch (e: any) { toast.error(e?.message ?? 'Failed to send reply'); }
    finally { setBusy(null); }
  };

  const doClose = async (id: string) => {
    setBusy(id + '_close');
    try {
      await adminAction({ action: 'close_ticket', id, adminToken: token });
      toast.success('Ticket closed');
      load();
    } catch (e: any) { toast.error(e?.message ?? 'Failed to close'); }
    finally { setBusy(null); }
  };

  const counts = {
    All: data.length,
    Open: data.filter(t => t.status === 'Open').length,
    Replied: data.filter(t => t.status === 'Replied').length,
    Closed: data.filter(t => t.status === 'Closed').length,
  };
  const filtered = filter === 'All' ? data : data.filter(t => t.status === filter);

  const statusCls = (s: string) =>
    s === 'Replied' ? 'bg-blue-500/20 text-blue-400 border-blue-500/30' :
    s === 'Closed' ? 'bg-muted text-muted-foreground border-border' :
    'bg-yellow-500/20 text-yellow-400 border-yellow-500/30';

  if (loading) return <div className="space-y-2">{[1,2,3].map(i => <Skeleton key={i} className="h-24 rounded-xl" />)}</div>;

  return (
    <div className="space-y-3">
      {/* Stats */}
      <div className="grid grid-cols-4 gap-2">
        {[
          { k: 'All', icon: '📋', color: 'text-foreground' },
          { k: 'Open', icon: '🔔', color: 'text-yellow-400' },
          { k: 'Replied', icon: '💬', color: 'text-blue-400' },
          { k: 'Closed', icon: '✅', color: 'text-muted-foreground' },
        ].map(({ k, icon, color }) => (
          <button key={k} onClick={() => setFilter(k)}
            className={`bg-muted/40 border rounded-xl p-2 text-center transition-colors ${filter === k ? 'border-primary/40' : 'border-border hover:border-border/80'}`}>
            <p className={`text-sm font-black ${color}`}>{counts[k as keyof typeof counts]}</p>
            <p className="text-[9px] text-muted-foreground">{icon} {k}</p>
          </button>
        ))}
      </div>

      <div className="flex items-center justify-between">
        <p className="text-sm font-bold flex items-center gap-1.5"><MessageCircle size={13} className="text-primary" /> Support Tickets</p>
        <button onClick={load} className="flex items-center gap-1 text-xs text-muted-foreground hover:text-foreground"><RefreshCw size={10} /> Refresh</button>
      </div>

      {filtered.length === 0 && (
        <div className="text-center py-12 text-muted-foreground">
          <MessageCircle size={28} className="mx-auto mb-2 opacity-30" />
          <p className="text-sm">No {filter.toLowerCase()} tickets</p>
        </div>
      )}

      {filtered.map((t: any) => (
        <div key={t.id} className={`card-dark rounded-xl border overflow-hidden ${t.status === 'Open' ? 'border-yellow-500/30' : t.status === 'Replied' ? 'border-blue-500/20' : 'border-border'}`}>
          <div
            className="px-4 py-3 cursor-pointer flex items-start gap-3"
            onClick={() => setExpanded(expanded === t.id ? null : t.id)}
          >
            <div className="flex-1 min-w-0">
              <div className="flex items-center gap-2 flex-wrap">
                <p className="text-sm font-semibold truncate">{t.ticketTitle}</p>
                <Badge className={`text-[9px] border ${statusCls(t.status)}`}>{t.status}</Badge>
              </div>
              <p className="text-xs text-muted-foreground truncate mt-0.5">{t.userEmail}</p>
              <p className="text-[10px] text-muted-foreground mt-0.5">
                {t.submittedAt ? new Date(t.submittedAt).toLocaleString() : ''}
              </p>
            </div>
            {expanded === t.id ? <ChevronUp size={14} className="text-muted-foreground shrink-0 mt-0.5" /> : <ChevronDown size={14} className="text-muted-foreground shrink-0 mt-0.5" />}
          </div>

          {expanded === t.id && (
            <div className="px-4 pb-4 space-y-3 border-t border-border/50 pt-3">
              {/* User Message */}
              <div className="bg-muted/40 rounded-xl p-3">
                <p className="text-[10px] text-muted-foreground uppercase tracking-wide mb-1.5">User Message</p>
                <p className="text-xs leading-relaxed whitespace-pre-wrap">{t.message}</p>
              </div>
              <div className="text-[10px] text-muted-foreground font-mono">
                User ID: {t.userId?.slice(0, 20) ?? '—'}...
              </div>

              {/* Admin Reply */}
              {t.adminReply && (
                <div className="bg-blue-500/10 border border-blue-500/20 rounded-xl p-3">
                  <p className="text-[10px] text-blue-400 uppercase tracking-wide mb-1.5">Admin Reply</p>
                  <p className="text-xs leading-relaxed whitespace-pre-wrap">{t.adminReply}</p>
                </div>
              )}

              {/* Actions */}
              {t.status !== 'Closed' && (
                <div className="space-y-2">
                  <Textarea
                    placeholder="Type your reply to the user..."
                    value={replies[t.id] ?? ''}
                    onChange={e => setReplies(r => ({ ...r, [t.id]: e.target.value }))}
                    className="bg-muted border-border text-xs resize-none"
                    rows={3}
                  />
                  <div className="grid grid-cols-2 gap-2">
                    <Button size="sm" onClick={() => doReply(t.id)} disabled={busy === t.id + '_reply'}
                      className="h-8 text-xs bg-primary text-primary-foreground gap-1">
                      {busy === t.id + '_reply' ? <Loader2 size={10} className="animate-spin" /> : <Send size={10} />} Send Reply
                    </Button>
                    <Button size="sm" variant="outline" onClick={() => doClose(t.id)} disabled={busy === t.id + '_close'}
                      className="h-8 text-xs border-border gap-1">
                      {busy === t.id + '_close' ? <Loader2 size={10} className="animate-spin" /> : <Check size={10} />} Close Ticket
                    </Button>
                  </div>
                </div>
              )}
              {t.status === 'Closed' && (
                <div className="text-center text-[10px] text-muted-foreground italic py-1">Ticket closed</div>
              )}
            </div>
          )}
        </div>
      ))}
    </div>
  );
}

// ─── Notification Sender ──────────────────────────────────────────────
function NotificationSender({ token }: { token: string }) {
  const { refresh: refreshAppData } = useAppData();
  const [message, setMessage] = useState('');
  const [sending, setSending] = useState(false);
  const [lastSent, setLastSent] = useState('');

  const sendNotification = async () => {
    if (!message.trim()) { toast.error('Enter a notification message'); return; }
    setSending(true);
    try {
      await adminAction({ action: 'send_notification', data: { message: message.trim() }, adminToken: token });
      setLastSent(message.trim());
      setMessage('');
      toast.success('🔔 Notification sent! Red dot now visible on all users\' bells.');
      refreshAppData();
    } catch (e: any) { toast.error(e?.message ?? 'Failed to send notification'); }
    finally { setSending(false); }
  };

  return (
    <div className="card-dark rounded-xl p-4 space-y-3 border border-primary/25">
      <p className="text-sm font-bold flex items-center gap-2">
        <Bell size={14} className="text-primary" /> 🔔 Global Push Notification
      </p>
      <p className="text-[10px] text-muted-foreground">
        Send an instant notification to ALL users. A red dot badge will appear on every user's bell icon until they tap to read it.
      </p>

      {lastSent && (
        <div className="bg-green-500/10 border border-green-500/25 rounded-xl px-3 py-2 text-[10px] text-green-400 flex items-start gap-1.5">
          <Bell size={10} className="shrink-0 mt-0.5" />
          <span>Last sent: "{lastSent.slice(0, 80)}{lastSent.length > 80 ? '...' : ''}"</span>
        </div>
      )}

      <Textarea
        placeholder="Type your notification message (e.g. 'New VIP plans available! Limited time offer — upgrade now 🎉')"
        value={message}
        onChange={e => setMessage(e.target.value)}
        className="bg-muted border-border text-sm resize-none"
        rows={3}
        maxLength={500}
      />
      <div className="flex items-center justify-between">
        <span className="text-[10px] text-muted-foreground">{message.length}/500 chars</span>
        <Button size="sm" onClick={sendNotification} disabled={sending || !message.trim()}
          className="h-9 px-4 text-xs bg-primary text-primary-foreground font-bold gap-1.5">
          {sending ? <><Loader2 size={11} className="animate-spin" /> Sending...</> : <><Bell size={11} /> Send to All Users</>}
        </Button>
      </div>
    </div>
  );
}

// ─── Referral History Panel (inline in Users tab) ──────────────────────
function UserReferralHistory({ token, userEmail }: { token: string; userEmail: string }) {
  const [referrals, setReferrals] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    adminGetData({ tab: 'referrals_for_user', adminToken: token, userEmail }).then(r => {
      setReferrals(r.data as any[]);
    }).catch(() => {}).finally(() => setLoading(false));
  }, [token, userEmail]);

  if (loading) return <div className="py-2 text-center"><Loader2 size={12} className="animate-spin text-muted-foreground mx-auto" /></div>;

  return (
    <div className="mt-2 bg-muted/30 border border-border rounded-xl overflow-hidden">
      <div className="px-3 py-1.5 bg-muted/50 border-b border-border flex items-center gap-1.5">
        <GitBranch size={10} className="text-primary" />
        <p className="text-[10px] font-bold">Referral History ({referrals.length} invites)</p>
      </div>
      {referrals.length === 0 ? (
        <p className="text-[10px] text-muted-foreground text-center py-3">No referrals yet</p>
      ) : (
        <div className="max-h-36 overflow-y-auto divide-y divide-border/40">
          {referrals.map((r: any) => (
            <div key={r.id} className="px-3 py-2 grid grid-cols-3 gap-1 text-[9px]">
              <div className="min-w-0">
                <p className="font-medium truncate">{r.referredName || r.referredEmail}</p>
                <p className="text-muted-foreground truncate">{r.referredEmail}</p>
              </div>
              <div className="text-center">
                <p className="text-green-400 font-bold">${(r.commissionUsd ?? 0).toFixed(4)}</p>
                <p className="text-muted-foreground">commission</p>
              </div>
              <div className="text-right text-muted-foreground">
                {r.joinedAt ? new Date(r.joinedAt).toLocaleDateString('en-PK', { day: '2-digit', month: 'short' }) : '—'}
              </div>
            </div>
          ))}
        </div>
      )}
      {referrals.length > 0 && (
        <div className="px-3 py-1.5 border-t border-border/40 bg-muted/20">
          <p className="text-[9px] text-muted-foreground">
            Total commission: <span className="text-green-400 font-bold">
              ${referrals.reduce((s, r) => s + (r.commissionUsd ?? 0), 0).toFixed(4)}
            </span>
          </p>
        </div>
      )}
    </div>
  );
}

// ─── Supabase Config Tab ──────────────────────────────────────────
function SupabaseConfigSection({ token }: { token: string }) {
  const [configs, setConfigs] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [formOpen, setFormOpen] = useState(false);
  const [migrationResults, setMigrationResults] = useState<Record<string, any>>({});
  const [activeMigrationId, setActiveMigrationId] = useState<string | null>(null);
  const [showSql, setShowSql] = useState(false);
  const [copiedSql, setCopiedSql] = useState(false);
  const [busy, setBusy] = useState<string | null>(null);

  const [form, setForm] = useState({
    id: '', projectName: '', projectUrl: '', anonKey: '', serviceRoleKey: '', notes: '',
  });

  const load = useCallback(async () => {
    setLoading(true);
    try {
      const r = await supabaseMigrate({ action: 'get_config', adminToken: token });
      setConfigs((r.data as any[]) ?? []);
    } catch (e: any) { toast.error(e?.message); }
    finally { setLoading(false); }
  }, [token]);

  useEffect(() => { load(); }, [load]);

  const resetForm = () => setForm({ id: '', projectName: '', projectUrl: '', anonKey: '', serviceRoleKey: '', notes: '' });

  const saveConfig = async () => {
    if (!form.projectUrl || !form.serviceRoleKey) { toast.error('Project URL and Service Role Key are required'); return; }
    setBusy('save');
    try {
      await supabaseMigrate({ action: 'save_config', adminToken: token, data: form });
      toast.success('✅ Supabase config saved!');
      resetForm(); setFormOpen(false); load();
    } catch (e: any) { toast.error(e?.message); }
    finally { setBusy(null); }
  };

  const runMigration = async (id: string) => {
    setBusy('migrate_' + id);
    setActiveMigrationId(id);
    setMigrationResults(prev => ({ ...prev, [id]: null }));
    try {
      const r = await supabaseMigrate({ action: 'run_migration', adminToken: token, data: { id } });
      setMigrationResults(prev => ({ ...prev, [id]: r }));
      if (r.data?.autoExecuted) toast.success('🚀 ' + (r.message ?? 'Migration complete!'));
      else toast.info('📋 Auto-SQL failed — use options below to connect manually');
      load();
    } catch (e: any) { toast.error(e?.message); }
    finally { setBusy(null); }
  };

  const verifyTables = async (id: string) => {
    setBusy('verify_' + id);
    setActiveMigrationId(id);
    try {
      const r = await supabaseMigrate({ action: 'verify_tables', adminToken: token, data: { id } });
      setMigrationResults(prev => ({ ...prev, [id]: r }));
      if (r.data?.autoExecuted) {
        toast.success('✅ All tables verified — connection marked as ACTIVE!');
        load();
      } else {
        toast.warning('⚠️ Some tables missing — run the SQL first');
      }
    } catch (e: any) { toast.error(e?.message); }
    finally { setBusy(null); }
  };

  const forceConnect = async (id: string) => {
    setBusy('force_' + id);
    try {
      const r = await supabaseMigrate({ action: 'force_connect', adminToken: token, data: { id } });
      setMigrationResults(prev => ({ ...prev, [id]: r }));
      toast.success('✅ Status set to CONNECTED!');
      load();
    } catch (e: any) { toast.error(e?.message); }
    finally { setBusy(null); }
  };

  const deleteConfig = async (id: string) => {
    setBusy('del_' + id);
    try {
      await supabaseMigrate({ action: 'delete_config', adminToken: token, data: { id } });
      toast.success('Deleted');
      load();
    } catch (e: any) { toast.error(e?.message); }
    finally { setBusy(null); }
  };

  const copySql = (sql: string) => {
    navigator.clipboard.writeText(sql);
    setCopiedSql(true); toast.success('SQL copied!');
    setTimeout(() => setCopiedSql(false), 2500);
  };

  return (
    <div className="space-y-3">
      {/* Header */}
      <div className="rounded-2xl border-2 border-sky-500/30 bg-sky-950/20 p-4 space-y-2">
        <div className="flex items-center gap-2">
          <div className="w-8 h-8 rounded-xl bg-sky-500/15 border border-sky-500/30 flex items-center justify-center shrink-0">
            <Database size={16} className="text-sky-400" />
          </div>
          <div className="flex-1 min-w-0">
            <p className="font-black text-sm">🗄️ Supabase Integration</p>
            <p className="text-[10px] text-muted-foreground">Isolated credential vault — zero mixing with operational tables</p>
          </div>
          <button onClick={() => { resetForm(); setFormOpen(f => !f); }}
            className="shrink-0 flex items-center gap-1 text-xs bg-sky-500/20 text-sky-400 border border-sky-500/30 rounded-xl px-3 py-1.5 font-bold hover:bg-sky-500/30 transition-colors">
            <Plus size={11} /> Add
          </button>
        </div>

        {/* How auto-migration works */}
        <div className="bg-sky-950/30 border border-sky-500/20 rounded-lg px-3 py-2 text-[9px] text-sky-300 space-y-1">
          <p className="font-bold text-sky-400">🔄 3-Step Auto-Migration Cascade:</p>
          <p>① exec_sql RPC → ② Supabase Management API → ③ Verify existing tables</p>
          <p className="text-muted-foreground">If you already ran the SQL manually, click <strong className="text-sky-400">"Verify Tables"</strong> or <strong className="text-sky-400">"Mark as Connected"</strong> below.</p>
        </div>

        {/* Security notice */}
        <div className="bg-green-950/30 border border-green-500/20 rounded-lg px-3 py-2 text-[9px] text-green-400 flex items-start gap-1.5">
          <span className="shrink-0">🔒</span>
          <span>Service Role Keys are stored encrypted in an isolated table. Never included in public-facing responses.</span>
        </div>
      </div>

      {/* Add Config Form */}
      {formOpen && (
        <div className="card-dark rounded-xl p-4 space-y-3 border border-sky-500/30">
          <p className="text-xs font-bold text-sky-400 flex items-center gap-1.5"><Server size={11} /> New Supabase Connection</p>
          <div className="space-y-2">
            {[
              { key: 'projectName',    label: '📛 Project Name',         placeholder: 'My Supabase Project',       type: 'text',     },
              { key: 'projectUrl',     label: '🌐 Project URL',          placeholder: 'https://abcxyz.supabase.co', type: 'url',      },
              { key: 'anonKey',        label: '🔑 Anon / Public Key',    placeholder: 'eyJhbG...',                 type: 'password', },
              { key: 'serviceRoleKey', label: '🛡️ Service Role Key',     placeholder: 'eyJhbG...',                 type: 'password', },
              { key: 'notes',          label: '📝 Notes (optional)',      placeholder: 'e.g. Production DB',        type: 'text',     },
            ].map(f => (
              <div key={f.key} className="space-y-0.5">
                <Label className="text-[10px] text-muted-foreground">{f.label}</Label>
                <Input
                  type={f.type as any}
                  value={(form as any)[f.key]}
                  onChange={e => setForm(p => ({ ...p, [f.key]: e.target.value }))}
                  placeholder={f.placeholder}
                  className="bg-muted border-border text-xs h-8 font-mono"
                />
              </div>
            ))}
          </div>
          <div className="flex gap-2">
            <Button size="sm" onClick={saveConfig} disabled={busy === 'save'}
              className="flex-1 h-8 text-xs bg-sky-600 hover:bg-sky-600/90 text-white gap-1">
              {busy === 'save' ? <Loader2 size={10} className="animate-spin" /> : <Database size={10} />} Save Config
            </Button>
            <Button size="sm" variant="ghost" onClick={() => setFormOpen(false)}
              className="h-8 text-xs text-muted-foreground">
              Cancel
            </Button>
          </div>
        </div>
      )}

      {/* Config list */}
      {loading ? (
        <Skeleton className="h-20 rounded-xl" />
      ) : configs.length === 0 ? (
        <div className="text-center py-8 text-muted-foreground">
          <Database size={28} className="mx-auto mb-2 opacity-30" />
          <p className="text-xs">No Supabase configurations yet. Add one above.</p>
        </div>
      ) : (
        <div className="space-y-3">
          {configs.map((cfg: any) => {
            const result = migrationResults[cfg.id];
            const isActive = cfg.status === 'Active';
            return (
              <div key={cfg.id} className={`card-dark rounded-xl p-3 space-y-2.5 border ${isActive ? 'border-green-500/30' : 'border-border'}`}>
                <div className="flex items-start justify-between gap-2">
                  <div className="min-w-0 flex-1">
                    <p className="text-xs font-bold truncate">{cfg.projectName || 'Unnamed Project'}</p>
                    <p className="text-[10px] text-muted-foreground font-mono truncate">{cfg.projectUrl}</p>
                    <p className="text-[10px] text-muted-foreground">Anon: {cfg.anonKey}</p>
                    <p className="text-[10px] text-muted-foreground">Key: ••••••••••••••••••••</p>
                    {cfg.lastSyncedAt && (
                      <p className="text-[9px] text-muted-foreground mt-0.5">
                        Last sync: {new Date(cfg.lastSyncedAt).toLocaleString()}
                      </p>
                    )}
                  </div>
                  <div className="flex flex-col items-end gap-1.5 shrink-0">
                    <span className={`text-[9px] font-bold px-2 py-0.5 rounded-full border ${
                      isActive ? 'bg-green-500/15 text-green-400 border-green-500/30' :
                      cfg.status === 'Error' ? 'bg-destructive/15 text-destructive border-destructive/30' :
                      'bg-yellow-500/15 text-yellow-400 border-yellow-500/30'
                    }`}>{cfg.status || 'Pending'}</span>
                    <button onClick={() => deleteConfig(cfg.id)} disabled={!!busy}
                      className="text-[9px] text-destructive/60 hover:text-destructive transition-colors">
                      Delete
                    </button>
                  </div>
                </div>

                {cfg.tablesCreated && (
                  <p className="text-[9px] text-emerald-400 font-mono">✅ Tables: {cfg.tablesCreated}</p>
                )}

                {/* Action buttons */}
                <div className="grid grid-cols-2 gap-1.5">
                  <Button size="sm" onClick={() => runMigration(cfg.id)} disabled={!!busy}
                    className="h-8 text-[10px] bg-sky-600/20 text-sky-400 border border-sky-500/30 hover:bg-sky-600/30 gap-1">
                    {busy === 'migrate_' + cfg.id
                      ? <><Loader2 size={9} className="animate-spin" /> Running...</>
                      : <><RefreshCcw size={9} /> Auto-Migrate</>}
                  </Button>
                  <Button size="sm" onClick={() => verifyTables(cfg.id)} disabled={!!busy}
                    className="h-8 text-[10px] bg-emerald-600/20 text-emerald-400 border border-emerald-500/30 hover:bg-emerald-600/30 gap-1">
                    {busy === 'verify_' + cfg.id
                      ? <><Loader2 size={9} className="animate-spin" /> Verifying...</>
                      : <><Check size={9} /> Verify Tables</>}
                  </Button>
                </div>

                {/* Force Connect — always visible for non-Active configs */}
                {!isActive && (
                  <div className="rounded-xl bg-yellow-950/20 border border-yellow-500/25 p-2.5 space-y-1.5">
                    <p className="text-[9px] text-yellow-400 font-bold flex items-center gap-1">
                      <AlertTriangle size={9} /> Already ran the SQL manually?
                    </p>
                    <p className="text-[9px] text-muted-foreground">
                      If you executed the migration SQL in Supabase SQL Editor and all 5 tables were created, click below to mark this connection as active.
                    </p>
                    <Button size="sm" onClick={() => forceConnect(cfg.id)} disabled={!!busy}
                      className="w-full h-7 text-[10px] bg-green-600/20 text-green-400 border border-green-500/30 hover:bg-green-600/30 gap-1 font-bold">
                      {busy === 'force_' + cfg.id
                        ? <><Loader2 size={9} className="animate-spin" /> Updating...</>
                        : <><Check size={9} /> ✅ Tables Already Created — Mark as CONNECTED</>}
                    </Button>
                  </div>
                )}

                {/* Per-config migration result */}
                {result && activeMigrationId === cfg.id && (
                  <div className={`rounded-xl border p-3 space-y-2 text-xs ${result.data?.autoExecuted ? 'border-green-500/30 bg-green-950/15' : 'border-yellow-500/30 bg-yellow-950/10'}`}>
                    <div className="flex items-start gap-1.5">
                      <span className="shrink-0">{result.data?.autoExecuted ? '✅' : '⚠️'}</span>
                      <p className="font-semibold flex-1 text-[10px]">{result.message}</p>
                    </div>

                    {result.data?.existingTables && (
                      <div className="text-[9px] text-emerald-400 font-mono">
                        Found: {result.data.existingTables.join(', ')}
                      </div>
                    )}
                    {result.data?.missingTables?.length > 0 && (
                      <div className="text-[9px] text-destructive font-mono">
                        Missing: {result.data.missingTables.join(', ')}
                      </div>
                    )}

                    {result.sql && !result.data?.autoExecuted && (
                      <>
                        <button onClick={() => setShowSql(s => !s)}
                          className="flex items-center gap-1 text-[10px] text-primary font-semibold">
                          {showSql ? <ChevronUp size={10} /> : <ChevronDown size={10} />}
                          {showSql ? 'Hide' : 'Show'} SQL ({result.data?.tablesCount} tables)
                        </button>
                        {showSql && (
                          <div className="space-y-1.5">
                            <div className="bg-muted/70 border border-border rounded-lg p-2.5 max-h-48 overflow-y-auto">
                              <pre className="text-[8px] font-mono text-muted-foreground whitespace-pre-wrap leading-relaxed">
                                {result.sql}
                              </pre>
                            </div>
                            <Button size="sm" onClick={() => copySql(result.sql)}
                              className="w-full h-7 text-[10px] bg-primary/20 text-primary border border-primary/30 hover:bg-primary/30 gap-1">
                              {copiedSql ? <><Check size={9} /> Copied!</> : <><Copy size={9} /> Copy SQL</>}
                            </Button>
                            <p className="text-[8px] text-muted-foreground text-center">
                              Supabase Dashboard → SQL Editor → New Query → Paste → Run → then click "Mark as CONNECTED"
                            </p>
                          </div>
                        )}
                      </>
                    )}
                  </div>
                )}
              </div>
            );
          })}
        </div>
      )}
    </div>
  );
}

// ─── Video API Keys Tab ──────────────────────────────────────────────
type VideoKeyInfo = GetVideoKeysOutputType['keys'][0];

const GATEWAY_META: Record<string, { emoji: string; color: string; desc: string }> = {
  huggingface_api_key: { emoji: '🟢', color: 'text-green-400',   desc: 'Priority 1 — HuggingFace — ByteDance / Stability / Alibaba engines' },
  stability_api_key:   { emoji: '🔵', color: 'text-blue-400',    desc: 'Priority 2 — Stability AI Engine — failover backup' },
  google_veo_key:      { emoji: '🔴', color: 'text-red-400',     desc: 'Priority 3 (Last Resort) — Legacy — currently locked/unpaid' },
};

// Force display order: HuggingFace → Stability → Google Veo
const GATEWAY_DISPLAY_ORDER = ['huggingface_api_key', 'stability_api_key', 'google_veo_key'];

// ─── Universal AI Gateway Card ──────────────────────────────────────
function UniversalGatewayCard({ token, keys, onRefresh }: { token: string; keys: any[]; onRefresh: () => void }) {
  const [uniKey, setUniKey] = useState('');
  const [endpointUrl, setEndpointUrl] = useState('');
  const [payloadJson, setPayloadJson] = useState('');
  const [showKey, setShowKey] = useState(false);
  const [saving, setSaving] = useState(false);
  const [loaded, setLoaded] = useState(false);

  // Load existing config from any key row that has universal fields
  useEffect(() => {
    if (loaded || keys.length === 0) return;
    const row = keys.find((k: any) => k.hasUniversalKey);
    if (row) {
      setEndpointUrl(row.modelEndpointUrl ?? '');
      setPayloadJson(row.payloadMappingJson ?? '');
      setUniKey('••••••••••••••••••••');
    }
    setLoaded(true);
  }, [keys, loaded]);

  const hasConfig = keys.some((k: any) => k.hasUniversalKey);

  const handleSave = async () => {
    setSaving(true);
    try {
      const payload: any = {
        adminToken: token,
        targetKeyIdentifier: 'huggingface_api_key',
        modelEndpointUrl: endpointUrl,
        payloadMappingJson: payloadJson,
      };
      if (uniKey && !uniKey.startsWith('•')) payload.universalApiKey = uniKey;
      const r = await saveUniversalGateway(payload);
      if (r.success) {
        toast.success(r.message);
        setUniKey('••••••••••••••••••••');
        onRefresh();
      } else {
        toast.error('Save failed');
      }
    } catch (e: any) { toast.error(e?.message ?? 'Save failed'); }
    finally { setSaving(false); }
  };

  return (
    <div className={`rounded-2xl border-2 overflow-hidden ${hasConfig ? 'border-green-500/40' : 'border-dashed border-primary/40'}`}>
      <div className={`px-4 py-3 flex items-center gap-2 ${hasConfig ? 'bg-green-500/10' : 'bg-primary/5'}`}>
        <span className="text-lg">🌐</span>
        <div className="flex-1 min-w-0">
          <span className="font-black text-sm">Universal AI Video Gateway</span>
          <p className="text-[9px] text-muted-foreground">Priority 0 — Self-Healing, Never-Fail — Lifetime model support</p>
        </div>
        {hasConfig ? (
          <span className="text-[9px] bg-green-500/15 text-green-400 border border-green-500/30 px-2 py-0.5 rounded-full font-bold flex items-center gap-1">
            <Check size={9} /> ARMED
          </span>
        ) : (
          <span className="text-[9px] bg-muted text-muted-foreground px-2 py-0.5 rounded-full font-semibold">NOT CONFIGURED</span>
        )}
      </div>

      <div className="p-4 space-y-3">
        <div className="bg-primary/5 border border-primary/15 rounded-xl px-3 py-2.5 text-[10px] text-muted-foreground space-y-1">
          <p className="font-bold text-foreground">🔗 How it works:</p>
          <p>This gateway fires <strong>BEFORE</strong> all other engines (Priority 0). Paste any AI model's API key and endpoint URL — Canva, OpenAI, Claude, Runway, Pika, or any future API. The self-healing engine catches all errors silently and falls through to existing gateways.</p>
          <div className="grid grid-cols-3 gap-1.5 mt-1.5">
            {[
              { icon: '🔑', label: 'Universal API Key', sub: 'Any model\'s key' },
              { icon: '🎯', label: 'Model Endpoint URL', sub: 'Dynamic target API' },
              { icon: '📦', label: 'Payload Mapping', sub: 'Custom JSON overrides' },
            ].map(m => (
              <div key={m.label} className="bg-muted/40 border border-border rounded-lg px-2 py-1.5 text-center">
                <span className="text-sm">{m.icon}</span>
                <p className="text-[8px] font-bold mt-0.5">{m.label}</p>
                <p className="text-[7px] text-muted-foreground">{m.sub}</p>
              </div>
            ))}
          </div>
        </div>

        {/* Universal API Key */}
        <div className="space-y-1.5">
          <Label className="text-[10px] text-muted-foreground">🔑 Universal API Key (any AI model)</Label>
          <div className="relative">
            <Key size={11} className="absolute left-2.5 top-1/2 -translate-y-1/2 text-muted-foreground" />
            <input
              type={showKey ? 'text' : 'password'}
              value={uniKey}
              onChange={e => setUniKey(e.target.value)}
              placeholder="Paste any AI model's API key..."
              className="w-full bg-muted border border-border rounded-lg pl-8 pr-8 py-1.5 text-xs font-mono focus:outline-none focus:ring-1 focus:ring-primary"
            />
            <button onClick={() => setShowKey(s => !s)} className="absolute right-2 top-1/2 -translate-y-1/2 text-muted-foreground hover:text-foreground">
              {showKey ? <EyeOff size={12} /> : <Eye size={12} />}
            </button>
          </div>
        </div>

        {/* Model Endpoint URL */}
        <div className="space-y-1.5">
          <Label className="text-[10px] text-muted-foreground">🎯 Model Endpoint URL</Label>
          <Input
            value={endpointUrl}
            onChange={e => setEndpointUrl(e.target.value)}
            placeholder="https://api.canva.com/v1/video/generate"
            className="bg-muted border-border text-xs h-8 font-mono"
          />
        </div>

        {/* Payload Mapping JSON */}
        <div className="space-y-1.5">
          <Label className="text-[10px] text-muted-foreground">📦 Payload Mapping JSON (optional — custom key-value overrides)</Label>
          <Textarea
            value={payloadJson}
            onChange={e => setPayloadJson(e.target.value)}
            placeholder={'{\n  "video_duration": "30s",\n  "resolution": "1080p",\n  "style": "cinematic"\n}'}
            className="bg-muted border-border text-xs font-mono resize-none"
            rows={4}
          />
          <p className="text-[9px] text-muted-foreground">These key-values are merged into the API payload alongside the prompt. Must be valid JSON.</p>
        </div>

        <Button onClick={handleSave} disabled={saving || (!uniKey.trim() && !endpointUrl.trim())}
          className={`w-full font-bold text-sm h-10 gap-2 ${hasConfig ? 'bg-green-600 hover:bg-green-600/90 text-white' : 'bg-primary text-primary-foreground'}`}>
          {saving ? <><Loader2 size={14} className="animate-spin" /> Saving...</> : hasConfig ? <><Check size={14} /> Update Universal Gateway</> : <><Zap size={14} /> Arm Universal Gateway</>}
        </Button>

        <div className="bg-green-950/20 border border-green-500/20 rounded-xl px-3 py-2 text-[9px] text-green-400 space-y-0.5">
          <p className="font-bold">🛡️ Self-Healing Protection:</p>
          <p>If the universal key fails, expires, or the endpoint is down, the system silently falls through to HuggingFace → Stability → Google Veo. The app NEVER crashes.</p>
        </div>
      </div>
    </div>
  );
}

function VideoApiKeysTab({ token }: { token: string }) {
  const [keys, setKeys] = useState<VideoKeyInfo[]>([]);
  const [loading, setLoading] = useState(true);
  const [inputs, setInputs] = useState<Record<string, string>>({});
  const [showKey, setShowKey] = useState<Record<string, boolean>>({});
  const [verifying, setVerifying] = useState<string | null>(null);

  const load = useCallback(async () => {
    setLoading(true);
    try {
      const r = await getVideoKeys({ adminToken: token });
      setKeys(r.keys);
    } catch (e: any) { toast.error(e?.message ?? 'Failed to load'); }
    finally { setLoading(false); }
  }, [token]);

  useEffect(() => { load(); }, [load]);

  const handleVerify = async (keyId: string) => {
    const val = inputs[keyId]?.trim();
    if (!val) { toast.error('Paste an API key first'); return; }
    setVerifying(keyId);
    try {
      const r = await verifyVideoKey({ adminToken: token, keyIdentifier: keyId as any, apiKey: val });
      if (r.success) {
        toast.success(r.message);
        setInputs(p => ({ ...p, [keyId]: '' }));
      } else {
        toast.error(r.message);
      }
      load();
    } catch (e: any) { toast.error(e?.message ?? 'Verification failed'); }
    finally { setVerifying(null); }
  };

  if (loading) return <div className="space-y-3">{[1,2,3,4].map(i => <Skeleton key={i} className="h-32 rounded-xl" />)}</div>;

  return (
    <div className="space-y-4">
      {/* Header */}
      <div className="rounded-2xl border-2 border-secondary/30 bg-secondary/5 p-4 space-y-2">
        <div className="flex items-center gap-2">
          <div className="w-8 h-8 rounded-xl bg-secondary/15 border border-secondary/30 flex items-center justify-center shrink-0">
            <Key size={16} className="text-secondary" />
          </div>
          <div>
            <p className="font-black text-sm">🎬 Video API Gateway Keys</p>
            <p className="text-[10px] text-muted-foreground">Isolated table — zero collision with Google/Gemini settings</p>
          </div>
          <button onClick={load} className="ml-auto text-xs text-muted-foreground hover:text-foreground flex items-center gap-1"><RefreshCw size={10} /></button>
        </div>

        <div className="bg-secondary/5 border border-secondary/15 rounded-xl px-3 py-2 text-[10px] text-muted-foreground space-y-1">
          <p className="font-bold text-foreground">🔗 Sequential Failover Chain (Waterfall):</p>
