      {/* Key Cards — sorted: HuggingFace → Stability → Google Veo */}
      {[...keys].sort((a, b) => (GATEWAY_DISPLAY_ORDER.indexOf(a.keyIdentifier) === -1 ? 99 : GATEWAY_DISPLAY_ORDER.indexOf(a.keyIdentifier)) - (GATEWAY_DISPLAY_ORDER.indexOf(b.keyIdentifier) === -1 ? 99 : GATEWAY_DISPLAY_ORDER.indexOf(b.keyIdentifier))).map((k, idx) => {
