            <div className="flex items-start justify-between gap-2">
              <div>
                <div className="flex items-center gap-2">
                  <span className="text-sm">{meta.emoji}</span>
                  <p className="text-sm font-bold">{k.gatewayName}</p>
                  <span className="text-[10px] bg-muted px-2 py-0.5 rounded-full text-muted-foreground">#{idx + 1} Priority</span>
                </div>
                <p className={`text-[10px] ${meta.color} mt-0.5`}>{meta.desc}</p>
