                    onChange={e => setInputs(p => ({ ...p, [k.keyIdentifier]: e.target.value }))}
                    placeholder={k.keyIdentifier === 'google_veo_key' ? 'AIza...' : k.keyIdentifier === 'huggingface_api_key' ? 'hf_xxxxxxxx' : 'sk-xxxxxxxx'}
