                  className="h-8 px-3 text-[10px] bg-secondary text-secondary-foreground font-bold gap-1 shrink-0"
                >
                  {verifying === k.keyIdentifier
                    ? <><Loader2 size={10} className="animate-spin" /> Verifying</>
                    : <><ShieldCheck size={10} /> Verify & Save</>}
                </Button>
              </div>
            </div>
          </div>
