      })}

      {/* Footer Info */}
      <div className="rounded-xl border border-secondary/20 bg-secondary/5 px-3 py-2.5 space-y-1 text-[10px] text-muted-foreground">
        <p className="font-bold text-foreground">⚡ How the Failover Pipeline Works:</p>
        <ul className="space-y-0.5 list-disc pl-4">
          <li>When user clicks "Generate Video", the engine tries <strong>Gateway 1 (HuggingFace)</strong> first</li>
          <li>HuggingFace rotates: <strong>ByteDance/AnimateDiff → Stability SVD → Alibaba text-to-video</strong> (5s timeout)</li>
          <li>If HuggingFace fails/overloaded → instantly routes to <strong>Gateway 2 (Stability AI)</strong></li>
          <li>If Stability fails → falls to <strong>Gateway 3 (Google Veo)</strong> as last resort</li>
          <li>Keys <strong>NEVER execute simultaneously</strong> — strict waterfall, zero collision</li>
          <li>Each key is stored in an <strong>isolated database table</strong> (not in Admin Settings)</li>
        </ul>
      </div>
    </div>
  );
}

// ─── System APK & Application Safety Control (Persistent, DB-backed) ─
function SystemSafetyControlPanel({ token }: { token: string }) {
  const [apkVersion, setApkVersion] = useState('');
  const [apkUrl, setApkUrl] = useState('');
  const [apkFilename, setApkFilename] = useState('');
  const [antiCrash, setAntiCrash] = useState(true);
  const [uploading, setUploading] = useState(false);
  const [loading, setLoading] = useState(true);
  const [copied, setCopied] = useState(false);
  const [togglingCrash, setTogglingCrash] = useState(false);
  const fileRef = useRef<HTMLInputElement>(null);

  // Load persisted state from DB on mount
  const load = useCallback(async () => {
    setLoading(true);
    try {
      const r = await systemSafety({ action: 'get' });
      if (r.success) {
        setApkUrl(r.apkUrl ?? '');
        setApkVersion(r.apkVersion ?? '');
        setApkFilename(r.apkFilename ?? '');
        setAntiCrash(r.antiCrashEnabled !== false);
      }
    } catch { /* silent */ }
    finally { setLoading(false); }
  }, []);

  useEffect(() => { load(); }, [load]);

  // Real APK upload via zite-file-upload-sdk
  const handleFileSelect = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    if (!file.name.endsWith('.apk')) {
      toast.error('Please select a valid .apk file');
      return;
    }
    setUploading(true);
    try {
      const { uploadFile } = await import('zite-file-upload-sdk');
      const { fileUrl } = await uploadFile({ data: file, filename: file.name });
      const ver = `v${new Date().getFullYear() % 100}.${new Date().getMonth() + 1}.${new Date().getDate()}`;
      // Persist to DB
      await systemSafety({
        action: 'save_apk',
        adminToken: token,
        apkUrl: fileUrl,
        apkVersion: ver,
        apkFilename: file.name,
      });
      setApkUrl(fileUrl);
      setApkVersion(ver);
      setApkFilename(file.name);
      toast.success(`✅ APK ${ver} uploaded & saved permanently!`);
    } catch (err: any) {
      toast.error(err?.message ?? 'Upload failed — please try again');
    } finally {
      setUploading(false);
      if (fileRef.current) fileRef.current.value = '';
    }
  };

  // Toggle anti-crash and persist
  const toggleAntiCrash = async () => {
    const newVal = !antiCrash;
    setTogglingCrash(true);
    try {
      await systemSafety({
        action: 'save_anti_crash',
        adminToken: token,
        antiCrashEnabled: newVal,
      });
      setAntiCrash(newVal);
      toast.success(newVal ? '✅ Anti-Crash guardrails enabled & saved' : '⚠️ Anti-Crash guardrails disabled & saved');
    } catch {
      toast.error('Failed to save anti-crash state');
    } finally { setTogglingCrash(false); }
  };

  const copyUrl = () => {
    if (!apkUrl) return;
    navigator.clipboard.writeText(apkUrl);
    setCopied(true);
    toast.success('📋 APK URL copied!');
    setTimeout(() => setCopied(false), 2500);
  };

  if (loading) return <Skeleton className="h-48 rounded-2xl" />;

  return (
    <div className="rounded-2xl border-2 border-accent/40 bg-accent/5 p-4 space-y-4">
      {/* Hidden file input */}
      <input ref={fileRef} type="file" accept=".apk" className="hidden" onChange={handleFileSelect} />

      {/* Header */}
      <div className="flex items-center gap-3">
        <div className="w-10 h-10 rounded-xl bg-accent/15 border border-accent/30 flex items-center justify-center shrink-0">
          <Shield size={20} className="text-accent" />
        </div>
        <div className="flex-1 min-w-0">
          <p className="font-black text-sm">🛡️ System APK & Application Safety Control</p>
          <p className="text-[10px] text-muted-foreground">Persistent — all states saved to database permanently</p>
        </div>
      </div>

      {/* Table */}
      <div className="rounded-xl border border-border overflow-hidden">
        {/* Row 1: APK Upload */}
        <div className="bg-card px-4 py-3.5 border-b border-border">
          <div className="flex items-center justify-between gap-3">
            <div className="flex items-center gap-3 min-w-0 flex-1">
              <div className="w-8 h-8 rounded-lg bg-primary/10 border border-primary/20 flex items-center justify-center shrink-0">
                <Upload size={14} className="text-primary" />
              </div>
              <div className="min-w-0 flex-1">
                <div className="flex items-center gap-2 flex-wrap">
                  <p className="text-xs font-bold">APK Upload File</p>
                  {apkVersion && <span className="text-[9px] bg-primary/15 text-primary border border-primary/25 rounded-full px-2 py-0.5 font-bold">{apkVersion}</span>}
                </div>
                {apkFilename ? (
                  <p className="text-[10px] text-muted-foreground mt-0.5 font-mono truncate">{apkFilename}</p>
                ) : (
                  <p className="text-[10px] text-muted-foreground mt-0.5 italic">No APK uploaded yet</p>
                )}
              </div>
            </div>
            <button
              onClick={() => fileRef.current?.click()}
              disabled={uploading}
              className="shrink-0 text-[10px] font-bold bg-primary text-primary-foreground px-3 py-2 rounded-lg hover:bg-primary/90 transition-colors disabled:opacity-50 flex items-center gap-1.5"
            >
              {uploading ? <><Loader2 size={10} className="animate-spin" /> Uploading...</> : <><Upload size={10} /> Upload Social App APK</>}
            </button>
          </div>

          {/* Live URL output */}
          {apkUrl && (
            <div className="mt-2.5 bg-green-500/5 border border-green-500/20 rounded-lg px-3 py-2 space-y-1">
              <p className="text-[9px] text-green-400 font-bold uppercase tracking-wide">✅ Permanent Live URL</p>
              <div className="flex items-center gap-2">
                <code className="text-[10px] text-primary font-mono bg-primary/10 px-2 py-1 rounded flex-1 truncate select-all">{apkUrl}</code>
                <button onClick={copyUrl} className="shrink-0 text-[10px] font-bold bg-primary/20 text-primary border border-primary/30 px-2 py-1 rounded-lg hover:bg-primary/30 transition-colors flex items-center gap-1">
                  {copied ? <><Check size={9} /> Copied!</> : <><Copy size={9} /> Copy</>}
                </button>
              </div>
            </div>
          )}
        </div>

        {/* Row 2: Anti-Crash Status */}
        <div className="bg-card/60 px-4 py-3.5">
          <div className="flex items-center justify-between gap-3">
            <div className="flex items-center gap-3 min-w-0 flex-1">
              <div className={`w-8 h-8 rounded-lg border flex items-center justify-center shrink-0 ${
                antiCrash ? 'bg-green-500/10 border-green-500/25' : 'bg-destructive/10 border-destructive/25'
              }`}>
                <ShieldCheck size={14} className={antiCrash ? 'text-green-500' : 'text-destructive'} />
              </div>
              <div className="min-w-0 flex-1">
