        <div className="flex-1 min-w-0">
          <p className="font-black text-sm">🔗 Social Media Links</p>
          <p className="text-[10px] text-muted-foreground">Isolated table — controls the floating social bar on the right side</p>
        </div>
        <button onClick={load} className="text-xs text-muted-foreground hover:text-foreground flex items-center gap-1 shrink-0"><RefreshCw size={10} /></button>
      </div>

      <div className="bg-secondary/5 border border-secondary/15 rounded-xl px-3 py-2 text-[10px] text-muted-foreground space-y-1">
        <p className="font-bold text-foreground">🛡️ Completely Isolated Data Store</p>
        <p>This section reads/writes ONLY to the <code className="text-secondary font-mono bg-secondary/10 px-1 rounded">social_links_config</code> table. Zero contact with Users, Admin Settings, or any other table.</p>
      </div>

      {loading ? (
        <div className="space-y-2">{[1,2,3].map(i => <Skeleton key={i} className="h-16 rounded-xl" />)}</div>
      ) : (
        <div className="space-y-3">
          {links.map((link, idx) => {
            const meta = PLATFORM_ICONS[link.platformName] ?? { emoji: '🔗', color: 'border-border', placeholder: 'https://...' };
            return (
              <div key={link.id} className={`rounded-xl border-2 ${meta.color} bg-card p-3 space-y-2`}>
                <div className="flex items-center justify-between">
                  <div className="flex items-center gap-2">
                    <span className="text-lg">{meta.emoji}</span>
                    <span className="font-bold text-sm">{link.platformName}</span>
