function toHijri(date: Date): string {
  const JD = Math.floor((date.getTime() / 86400000) + 2440587.5);
  let l = JD - 1948440 + 10632;
  const n = Math.floor((l - 1) / 10631);
  l = l - 10631 * n + 354;
  const j = Math.floor((10985 - l) / 5316) * Math.floor(50 * l / 17719)
    + Math.floor(l / 5670) * Math.floor(43 * l / 15238);
  l = l - Math.floor((30 - j) / 15) * Math.floor(17719 * j / 50)
    - Math.floor(j / 16) * Math.floor(15238 * j / 43) + 29;
  const month = Math.floor(24 * l / 709);
  const day = l - Math.floor(709 * month / 24);
  const year = 30 * n + j - 30;
  const HIJRI_MONTHS = [
    'محرم','صفر','ربیع الاول','ربیع الثانی','جمادی الاولیٰ','جمادی الثانیہ',
    'رجب','شعبان','رمضان','شوال','ذوالقعدہ','ذوالحجہ'
  ];
  const m = Math.min(Math.max(month - 1, 0), 11);
  return `${day} ${HIJRI_MONTHS[m]} ${year} ہجری`;
}

export default createEndpoint({
  description: 'ROOHANI GUIDE AI v6.0 — adaptive Gemini gateway, Photo Analyzer preserved, auto-shift on deprecation',
  inputSchema: z.object({
    rightHand: z.string().min(10),
    leftHand: z.string().min(10),
    face: z.string().min(10),
    currentTime: z.string().optional(),
    userLocation: z.string().optional(),
  }),
  outputSchema: z.object({ analysis: z.string(), model: z.string(), complete: z.boolean() }),
  execute: async ({ input }) => {
    const settings = await AdminSettings.findAll({ limit: 200 });
    const records = settings.records;
    const geminiKey = records.find(s => s.settingKey === 'gemini_api_key')?.settingValue;
    if (!geminiKey) {
      throw new ZiteError({ code: 'BAD_REQUEST', message: 'API key not configured. Please add Gemini API key in Admin Panel.' });
    }

    const now = new Date();
    const hijriDate = toHijri(now);

    let storedModel = records.find(s => s.settingKey === 'gemini_best_model')?.settingValue ?? 'gemini-2.0-flash';
    const visionModel = (storedModel.includes('1.0') || storedModel.includes('1-0')) ? 'gemini-2.0-flash' : storedModel;

    const prompt = buildAnalysisPrompt(input.currentTime, hijriDate, input.userLocation);

    const requestBody = {
      contents: [{
        role: 'user',
        parts: [
          { text: prompt },
          { inlineData: { mimeType: 'image/jpeg', data: input.rightHand } },
          { inlineData: { mimeType: 'image/jpeg', data: input.leftHand } },
          { inlineData: { mimeType: 'image/jpeg', data: input.face } },
        ],
      }],
      generationConfig: { maxOutputTokens: 8192, temperature: 0.7 },
      safetySettings: [
        { category: 'HARM_CATEGORY_HARASSMENT', threshold: 'BLOCK_ONLY_HIGH' },
        { category: 'HARM_CATEGORY_HATE_SPEECH', threshold: 'BLOCK_ONLY_HIGH' },
        { category: 'HARM_CATEGORY_DANGEROUS_CONTENT', threshold: 'BLOCK_ONLY_HIGH' },
        { category: 'HARM_CATEGORY_SEXUALLY_EXPLICIT', threshold: 'BLOCK_ONLY_HIGH' },
      ],
    };

    // ── Adaptive auto-shift for vision models ──────────────────────
    const discovered = await discoverNewModels(geminiKey);
    const chain = buildChain(visionModel, discovered);

    let usedModel = '';
    let resultData: any = null;

    for (const model of chain) {
      try {
        const res = await fetch(
          `https://generativelanguage.googleapis.com/v1beta/models/${model}:generateContent?key=${geminiKey}`,
          { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify(requestBody) }
        );
        if (res.status === 429 || res.status === 503) continue;
        if (!res.ok) {
          const errText = await res.text().catch(() => '');
          if (isGone(res.status, errText)) { console.log(`[PhotoAnalyzer] Model "${model}" gone, auto-shifting...`); continue; }
          continue;
        }
        resultData = await res.json();
        usedModel = model;
        break;
      } catch { continue; }
    }

    if (!resultData) {
      throw new ZiteError({ code: 'BAD_REQUEST', message: 'All vision models failed. Please try again.' });
    }

    let analysis = resultData.candidates?.[0]?.content?.parts?.[0]?.text ?? '';

    if (!analysis || analysis.length < 100) {
      throw new ZiteError({ code: 'BAD_REQUEST', message: 'تجزیہ حاصل نہ ہو سکا — دوبارہ کوشش کریں۔' });
    }

    // Check completeness — matches both چانڑ and چنڑ spellings
    const isComplete = analysis.includes('غلام حسین چانڑ') || analysis.includes('غلام حسین چنڑ');

    // If truncated, attempt continuation
    if (!isComplete && analysis.length > 200) {
      try {
        const contBody = {
          contents: [
            {
              role: 'user',
              parts: [
                { text: prompt },
                { inlineData: { mimeType: 'image/jpeg', data: input.rightHand } },
                { inlineData: { mimeType: 'image/jpeg', data: input.leftHand } },
                { inlineData: { mimeType: 'image/jpeg', data: input.face } },
              ],
            },
            { role: 'model', parts: [{ text: analysis }] },
            {
              role: 'user',
              parts: [{ text: 'آپ کا جواب ادھورا رہ گیا ہے۔ بالکل وہیں سے جاری رکھیں جہاں رک گئے تھے اور تمام باقی سیکشنز مکمل کریں۔ آخر میں لازمی لکھیں: "تجزیہ از: ROOHANI GUIDE AI — تعمیر کنندہ: غلام حسین چنڑ"' }],
            },
          ],
          generationConfig: { maxOutputTokens: 8192, temperature: 0.7 },
          safetySettings: [
            { category: 'HARM_CATEGORY_HARASSMENT', threshold: 'BLOCK_ONLY_HIGH' },
            { category: 'HARM_CATEGORY_HATE_SPEECH', threshold: 'BLOCK_ONLY_HIGH' },
          ],
        };

        // Use the same adaptive chain for continuation
        for (const model of buildChain(usedModel, discovered)) {
          try {
            const res = await fetch(
              `https://generativelanguage.googleapis.com/v1beta/models/${model}:generateContent?key=${geminiKey}`,
              { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify(contBody) }
            );
            if (!res.ok) continue;
            const contData = await res.json() as { candidates?: { content?: { parts?: { text?: string }[] } }[] };
            const continuation = contData.candidates?.[0]?.content?.parts?.[0]?.text ?? '';
            if (continuation.length > 50) {
              analysis = analysis + '\n\n' + continuation;
            }
            break;
          } catch { continue; }
        }
      } catch {}
    }

    // Strip markdown
    analysis = analysis
      .replace(/```[\s\S]*?```/g, '')
      .replace(/\*{1,3}([^*\n]+)\*{1,3}/gs, '$1')
      .replace(/^#{1,6}\s+/gm, '')
      .replace(/^[-•●▪]\s+/gm, '')
      .replace(/_{1,2}([^_\n]+)_{1,2}/gs, '$1')
      .replace(/\n{3,}/g, '\n\n')
      .trim();

    return {
      analysis,
      model: usedModel,
      complete: analysis.includes('غلام حسین چانڑ') || analysis.includes('غلام حسین چنڑ'),
    };
  },
});

import { z } from 'zod';
import { createEndpoint, Users } from 'zite-integrations-backend-sdk';

export default createEndpoint({
  description: 'Called by the frontend when the VIP countdown timer reaches zero — auto-revokes expired VIP',
  authenticated: true,
  inputSchema: z.object({}),
  outputSchema: z.object({ success: z.boolean(), revoked: z.boolean() }),
  execute: async ({ context }) => {
    const user = await Users.findOne({ id: context.user.id });
    if (!user) return { success: true, revoked: false };

    const isExpired = user.vipStatus === 'VIP' &&
      user.vipExpiresAt &&
      new Date(user.vipExpiresAt) < new Date();

    if (isExpired) {
      await Users.update({
        id: user.id,
        record: { vipStatus: 'Free', vipPlan: '', vipExpiresAt: new Date(0).toISOString() },
      });
      return { success: true, revoked: true };
    }

    return { success: true, revoked: false };
  },
});

