  outputSchema: z.object({
    imageUrl: z.string(),
    prompt: z.string(),
    remaining: z.number(),
    modelUsed: z.string(),
  }),
  execute: async ({ input, context }) => {
    // ── 1. SAFETY CHECK — hard block inappropriate content ─────────
    if (!isSafePrompt(input.prompt)) {
      throw new ZiteError({
        code: 'BAD_REQUEST',
        message: 'معذرت، غلام اے آئی پر صرف صاف اور فیملی تصاویر بنانے کی اجازت ہے۔',
      });
    }

    // ── 2. QUOTA / LIMIT ENFORCEMENT ──────────────────────────────
    const [user, settings] = await Promise.all([
      Users.findOne({ id: context.user.id }),
      AdminSettings.findAll({ limit: 50 }),
    ]);

    const cfg = Object.fromEntries(settings.records.map(r => [r.settingKey ?? '', r.settingValue ?? '']));
    const isVIP = user?.vipStatus === 'VIP' && (!user.vipExpiresAt || new Date(user.vipExpiresAt) > new Date());

    let remaining = 999;
    const today = new Date().toISOString().slice(0, 10);

    if (isVIP) {
      const vipDaily = parseInt(cfg['img_limit_vip'] ?? '0') || 0;
      if (vipDaily > 0) {
        const usage = await MediaGenerations.findAll({ filters: { userEmail: context.user.email, date: today, type: 'Image' }, limit: 50 });
        const used = usage.records.reduce((s, r) => s + (r.count ?? 0), 0);
        if (used >= vipDaily) {
          throw new ZiteError({ code: 'FORBIDDEN', message: `⏰ Today's VIP image limit of ${vipDaily} reached. Resets tomorrow!` });
        }
        remaining = vipDaily - used - 1;
      }
    } else {
      const freeLimits = [
        parseInt(cfg['img_limit_free_d1'] ?? '3') || 3,
        parseInt(cfg['img_limit_free_d2'] ?? '2') || 2,
        parseInt(cfg['img_limit_free_d3'] ?? '1') || 1,
      ];
      const joinedAt = user?.joinedAt ? new Date(user.joinedAt) : new Date();
      const daysSinceJoined = Math.floor((Date.now() - joinedAt.getTime()) / 86400000);
      const limit = daysSinceJoined < freeLimits.length ? freeLimits[daysSinceJoined] : 0;

      if (limit === 0) {
        throw new ZiteError({ code: 'FORBIDDEN', message: '🔒 Your free trial has ended. Get VIP membership for unlimited AI image generation!' });
      }

      const usage = await MediaGenerations.findAll({ filters: { userEmail: context.user.email, date: today, type: 'Image' }, limit: 50 });
      const used = usage.records.reduce((s, r) => s + (r.count ?? 0), 0);

      if (used >= limit) {
        throw new ZiteError({ code: 'FORBIDDEN', message: `⏰ Today's limit of ${limit} images reached (Day ${daysSinceJoined + 1} trial). Come back tomorrow or upgrade to VIP!` });
      }
      remaining = limit - used - 1;
    }

    // ── 3. LOG USAGE ──────────────────────────────────────────────
    await MediaGenerations.create({
      record: { userEmail: context.user.email, date: today, type: 'Image', count: 1 },
    });

    // ── 4. CLEAN PROMPT — strip any remaining unsafe modifiers ────
    let cleanPrompt = input.prompt.trim()
      .replace(/\b(nsfw|adult|explicit|18\+|xxx|nude|naked|porn)\b/gi, '')
      .replace(/\s{2,}/g, ' ')
      .trim();
    if (cleanPrompt.length < 3) cleanPrompt = 'beautiful landscape, golden hour, cinematic photography';

    // Append SFW tag to all prompts
    const safetyTag = ', family-friendly, clean composition, SFW';

    // ── 5. GENERATE IMAGE ─────────────────────────────────────────
    let imageUrl: string;
    const modelUsed = input.model;

    // All models via Pollinations — returns a URL (no binary proxy issues)
    const NEGATIVE = 'nudity, nsfw, kissing, intimate, romantic, inappropriate, cartoon, anime';
    const seed = Date.now();
    const pollinationsModel = POLLINATIONS_MODELS[input.model] ?? 'flux';

    // Model-specific prompt enhancement
    let fullPrompt: string;
    if (input.model === 'flux-schnell') {
      fullPrompt = cleanPrompt + ', hyper-realistic, detailed skin texture, sharp focus, professional portrait, cinematic lighting, 8K resolution' + safetyTag;
    } else if (input.model === 'sdxl') {
      fullPrompt = cleanPrompt + ', cinematic wide shot, grand scene, epic landscape, detailed environment, volumetric lighting, 8K UHD, masterpiece' + safetyTag;
    } else {
      fullPrompt = cleanPrompt + ', photorealistic, ultra-detailed, natural lighting, cinematic color grading' + safetyTag;
    }

    imageUrl = `https://image.pollinations.ai/prompt/${encodeURIComponent(fullPrompt)}?model=${pollinationsModel}&width=1024&height=1024&nologo=true&enhance=false&seed=${seed}&negative=${encodeURIComponent(NEGATIVE)}`;

    return { imageUrl, prompt: input.prompt, remaining, modelUsed };
  },
});

