const KNOWN_FALLBACK_CHAIN = [
  'gemini-2.5-flash',
  'gemini-2.5-pro',
  'gemini-2.0-flash',
  'gemini-1.5-pro',
  'gemini-1.5-flash',
];

const DEPRECATION_SIGNALS = ['not found', 'deprecated', 'decommissioned', 'does not exist', 'not supported'];
function isGone(status: number, body: string): boolean {
  if (status === 404) return true;
  if (status === 400) return DEPRECATION_SIGNALS.some(s => body.toLowerCase().includes(s));
  return false;
}

async function discoverNewModels(apiKey: string): Promise<string[]> {
  try {
    const res = await fetch(`https://generativelanguage.googleapis.com/v1beta/models?pageSize=200&key=${apiKey}`);
    if (!res.ok) return [];
    const data = await res.json() as { models?: { name: string; supportedGenerationMethods?: string[] }[] };
    return (data.models ?? [])
      .filter(m => (m.supportedGenerationMethods ?? []).includes('generateContent'))
      .map(m => m.name.replace('models/', ''))
      .filter(id => id.startsWith('gemini'))
      .sort((a, b) => b.localeCompare(a));
  } catch { return []; }
}

function buildChain(preferred: string, discovered: string[]): string[] {
  const seen = new Set<string>();
  const chain: string[] = [];
  const add = (m: string) => { if (!seen.has(m)) { seen.add(m); chain.push(m); } };
  add(preferred);
  for (const m of KNOWN_FALLBACK_CHAIN) add(m);
  for (const m of discovered) add(m);
  return chain;
}

// ── Simple Hijri Date Calculator ─────────────────────────────────
function toHijri(date: Date): string {
  const JD = Math.floor((date.getTime() / 86400000) + 2440587.5);
  let l = JD - 1948440 + 10632;
  const n = Math.floor((l - 1) / 10631);
  l = l - 10631 * n + 354;
  const j = Math.floor((10985 - l) / 5316) * Math.floor(50 * l / 17719)
    + Math.floor(l / 5670) * Math.floor(43 * l / 15238);
  l = l - Math.floor((30 - j) / 15) * Math.floor(17719 * j / 50)
    - Math.floor(j / 16) * Math.floor(15238 * j / 43) + 29;
  const month = Math.floor(24 * l / 709);
  const day = l - Math.floor(709 * month / 24);
  const year = 30 * n + j - 30;
  const HIJRI_MONTHS = [
    'محرم','صفر','ربیع الاول','ربیع الثانی','جمادی الاولیٰ','جمادی الثانیہ',
    'رجب','شعبان','رمضان','شوال','ذوالقعدہ','ذوالحجہ'
  ];
  const m = Math.min(Math.max(month - 1, 0), 11);
  return `${day} ${HIJRI_MONTHS[m]} ${year} ہجری`;
}

