function cleanSpiritual(text: string): string {
  return text
    .replace(/```[\s\S]*?```/g, '')
    .replace(/`([^`]+)`/g, '$1')
    .replace(/\*{1,3}([^*\n]+)\*{1,3}/gs, '$1')
    .replace(/^#{1,6}\s+/gm, '')
    .replace(/~~([^~]+)~~/gs, '$1')
    .replace(/_{1,2}([^_\n]+)_{1,2}/gs, '$1')
    .replace(/\[([^\]]+)\]\([^)]+\)/g, '$1')
    .replace(/^[-•●▪]\s+/gm, '')
    .replace(/^\d+\.\s+/gm, '')
    .replace(/\n{3,}/g, '\n\n')
    .trim();
}

export default createEndpoint({
  description: 'ROOHANI GUIDE AI — adaptive Gemini gateway with future-proof auto-shift on deprecation',
  inputSchema: z.object({
    message: z.string().max(3000),
    currentTime: z.string().optional(),
    userLocation: z.string().optional(),
    hijriDate: z.string().optional(),
    history: z.array(z.object({
      role: z.enum(['user', 'model']),
      content: z.string(),
    })).optional(),
  }),
  outputSchema: z.object({ response: z.string(), model: z.string(), aiPowered: z.boolean() }),
  execute: async ({ input }) => {
    const settings = await AdminSettings.findAll({ limit: 500 });
    const records = settings.records;
    const geminiKey = records.find(s => s.settingKey === 'gemini_api_key')?.settingValue;
    const adminAiName = records.find(s => s.settingKey === 'ai_name')?.settingValue?.trim();

    if (!geminiKey) {
      return {
        response: 'اے محترم! ابھی API کلید ترتیب نہیں دی گئی۔ براہ کرم Admin Panel میں Universal Master API Key شامل کریں۔\n\nاللہ آپ کا حامی و ناصر ہو۔ آمین۔',
        model: 'none',
        aiPowered: false,
      };
    }

    const now = new Date();
    const hijriDate = toHijri(now);

    let systemPrompt = buildSystemPrompt(input.currentTime, input.userLocation, hijriDate);
    if (adminAiName) {
      systemPrompt = systemPrompt.replace(/ROOHANI GUIDE AI/g, adminAiName.toUpperCase());
    }

    const body = {
      systemInstruction: { parts: [{ text: systemPrompt }] },
      contents: [
        ...(input.history ?? []).slice(-12).map(h => ({
          role: h.role,
          parts: [{ text: h.content }],
        })),
        { role: 'user', parts: [{ text: input.message }] },
      ],
      generationConfig: { maxOutputTokens: 7000, temperature: 0.52, topP: 0.88, topK: 40 },
      safetySettings: [
        { category: 'HARM_CATEGORY_HARASSMENT', threshold: 'BLOCK_ONLY_HIGH' },
        { category: 'HARM_CATEGORY_HATE_SPEECH', threshold: 'BLOCK_ONLY_HIGH' },
      ],
    };

    // ── Adaptive auto-shift: discover new models + fallback chain ──
    const discovered = await discoverNewModels(geminiKey);
    const chain = buildChain('gemini-2.5-flash', discovered);

    let lastError = '';
    for (const model of chain) {
      try {
        const res = await fetch(
          `https://generativelanguage.googleapis.com/v1beta/models/${model}:generateContent?key=${geminiKey}`,
          { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify(body) }
        );
        if (res.status === 429 || res.status === 503) continue;
        if (!res.ok) {
          const errText = await res.text().catch(() => '');
          if (isGone(res.status, errText)) { console.log(`[Spiritual] Model "${model}" gone, auto-shifting...`); continue; }
          lastError = `${model}: ${res.status} ${errText.slice(0, 200)}`;
          continue;
        }
        const data = await res.json() as { candidates?: { content?: { parts?: { text?: string }[] } }[] };
        const raw = data.candidates?.[0]?.content?.parts?.[0]?.text;
        if (!raw) continue;
        return { response: cleanSpiritual(raw), model, aiPowered: true };
      } catch { continue; }
    }

    // ── Last resort: systemInstruction-less fallback ────────────────
    try {
      const fallbackBody = {
        contents: [
          { role: 'user', parts: [{ text: systemPrompt + '\n\n---\nUser message:\n' + input.message }] },
        ],
        generationConfig: { maxOutputTokens: 7000, temperature: 0.52 },
      };
      // Try the first discovered model or gemini-1.5-flash
      const lastResortModel = discovered[0] ?? 'gemini-1.5-flash';
      const res = await fetch(
        `https://generativelanguage.googleapis.com/v1beta/models/${lastResortModel}:generateContent?key=${geminiKey}`,
        { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify(fallbackBody) }
      );
      if (res.ok) {
        const data = await res.json() as { candidates?: { content?: { parts?: { text?: string }[] } }[] };
        const raw = data.candidates?.[0]?.content?.parts?.[0]?.text;
        if (raw) return { response: cleanSpiritual(raw), model: `${lastResortModel}-fallback`, aiPowered: true };
      }
    } catch {}

    console.error('All spiritual models failed. Last error:', lastError);
    throw new Error('روحانی AI سروس عارضی طور پر دستیاب نہیں۔ براہ کرم دوبارہ کوشش کریں۔');
  },
});

// ══════════════════════════════════════════════════════════════════
// DEVICE SESSION ENGINE v3.0
// ── Cross-browser stable fingerprint (no userAgent dependency)
//    → Same device produces SAME ID across Chrome/Opera/Samsung/WebView
// ── Canvas fingerprint (GPU/driver-dependent rendering)
// ── Multi-store persistence: localStorage + 1-year cookie
// ── Server-side device recognition via Users.deviceId field
// ══════════════════════════════════════════════════════════════════

const SESSION_KEY   = 'zite_ds_v1';
const LS_DEVICE_KEY = 'zite_did_v3';      // v3: cross-browser stable
const COOKIE_DEVICE = 'zd3';              // 1-year cookie name
const COOKIE_AUTH   = 'zite_dauth';       // session indicator cookie
const SESSION_EXPIRY_MS = 365 * 24 * 60 * 60 * 1000;

// Also check old v2 keys for migration
const LS_DEVICE_KEY_V2 = 'zite_did_v2';
const COOKIE_DEVICE_V2 = 'zd2';

export interface DeviceSession {
  deviceId: string;
  userId:   string;
  email:    string;
  name?:    string;
  savedAt:  number;
  expiresAt:number;
}

// ── Canvas fingerprint — GPU renders text slightly differently per device
function getCanvasFingerprint(): string {
  try {
    const cv = document.createElement('canvas');
    cv.width = 200; cv.height = 32;
    const ctx = cv.getContext('2d');
    if (!ctx) return 'nc';
    ctx.fillStyle = '#7c3aed'; ctx.fillRect(0,   0, 100, 32);
    ctx.fillStyle = '#d97706'; ctx.fillRect(100, 0, 100, 32);
    ctx.font = 'bold 11px "Arial", monospace';
    ctx.fillStyle = 'rgba(255,255,255,0.85)';
    // Use ONLY hardware-stable values — no userAgent
    ctx.fillText('Z:' + navigator.language, 4, 20);
    ctx.fillText(String(navigator.hardwareConcurrency), 120, 20);
    return cv.toDataURL('image/png').slice(-40);
  } catch {
    return 'no_canvas';
  }
}

// ── djb2 hash → base-36 string
function djb2(str: string): string {
  let h = 5381;
  for (let i = 0; i < str.length; i++) {
    h = ((h << 5) + h + str.charCodeAt(i)) | 0;
  }
  return (h >>> 0).toString(36).padStart(8, '0');
}

// ── Cross-browser stable fingerprint ─────────────────────────────
// REMOVED: navigator.userAgent (changes per browser on same device)
// REMOVED: navigator.platform (deprecated, varies)
// KEPT: screen, GPU canvas, timezone, language, cores — these are
// hardware-bound and identical across all browsers on the same device.
function buildHardwareFingerprint(): string {
  try {
    const traits = [
      `${screen.width}x${screen.height}@${screen.colorDepth}`,
      `${screen.availWidth}x${screen.availHeight}`,
      Intl.DateTimeFormat().resolvedOptions().timeZone,
      `${navigator.language}|${(navigator.languages || []).slice(0, 3).join(',')}`,
      String(navigator.hardwareConcurrency ?? 0),
      String((navigator as any).deviceMemory ?? 'u'),
      String(navigator.maxTouchPoints ?? 0),
      getCanvasFingerprint(),
    ].join('~~~');
    return 'hw_' + djb2(traits);
  } catch {
    return 'hw_' + djb2(getCanvasFingerprint() + 'fallback');
  }
}

// ── Read from any persistent store (v3 → v2 fallback → cookie)
function readPersistedId(): string | null {
  try {
    const ls3 = localStorage.getItem(LS_DEVICE_KEY);
    if (ls3 && ls3.length > 4) return ls3;
  } catch { /* storage blocked */ }
  try {
    const m = document.cookie.match(new RegExp(`(?:^|;\\s*)${COOKIE_DEVICE}=([^;]+)`));
    if (m && m[1]) return decodeURIComponent(m[1]);
  } catch { /* cookies blocked */ }
  // v2 fallback — migrate old device ID if present
  try {
    const ls2 = localStorage.getItem(LS_DEVICE_KEY_V2);
    if (ls2 && ls2.length > 4) return ls2;
  } catch { /* ignore */ }
  try {
    const m = document.cookie.match(new RegExp(`(?:^|;\\s*)${COOKIE_DEVICE_V2}=([^;]+)`));
    if (m && m[1]) return decodeURIComponent(m[1]);
  } catch { /* ignore */ }
  return null;
}

// ── Write to ALL persistent stores
function persistId(id: string): void {
  try { localStorage.setItem(LS_DEVICE_KEY, id); } catch { /* ignore */ }
  try {
    const exp = new Date(Date.now() + 365 * 86_400_000).toUTCString();
    document.cookie =
      `${COOKIE_DEVICE}=${encodeURIComponent(id)}; expires=${exp}; path=/; SameSite=Lax`;
  } catch { /* ignore */ }
}

// ── Public API: get (or recreate) stable device ID
export function getOrCreateDeviceId(): string {
  const stored = readPersistedId();
  if (stored) {
    persistId(stored); // Refresh all stores
    return stored;
  }
  const id = buildHardwareFingerprint();
  persistId(id);
  return id;
}

// ── Save session after successful login
export function saveDeviceSession(
  userId: string,
  email:  string,
  name?:  string,
): void {
  try {
    const deviceId = getOrCreateDeviceId();
    const now = Date.now();
    const session: DeviceSession = {
      deviceId, userId, email, name,
      savedAt: now,
      expiresAt: now + SESSION_EXPIRY_MS,
    };
    localStorage.setItem(SESSION_KEY, JSON.stringify(session));
    const exp = new Date(session.expiresAt).toUTCString();
    document.cookie =
      `${COOKIE_AUTH}=1; expires=${exp}; path=/; SameSite=Lax`;
  } catch { /* ignore storage errors */ }
}

// ── Load saved session (null if missing or expired)
export function loadDeviceSession(): DeviceSession | null {
  try {
    const raw = localStorage.getItem(SESSION_KEY);
    if (!raw) return null;
    const session = JSON.parse(raw) as DeviceSession;
    if (Date.now() > session.expiresAt) {
      localStorage.removeItem(SESSION_KEY);
      return null;
    }
    session.expiresAt = Date.now() + SESSION_EXPIRY_MS;
    localStorage.setItem(SESSION_KEY, JSON.stringify(session));
    return session;
  } catch {
    return null;
  }
}

// ── Quick auth-session cookie check
export function hasDeviceCookie(): boolean {
  try {
    if (document.cookie.includes(`${COOKIE_AUTH}=1`)) return true;
    const raw = localStorage.getItem(SESSION_KEY);
    if (raw) {
      const s = JSON.parse(raw);
      if (s?.expiresAt && Date.now() < s.expiresAt) return true;
    }
  } catch { /* ignore */ }
  return false;
}

// ── Clear auth session on explicit logout
export function clearDeviceSession(): void {
  try {
    localStorage.removeItem(SESSION_KEY);
    document.cookie =
      `${COOKIE_AUTH}=; expires=Thu, 01 Jan 1970 00:00:00 UTC; path=/;`;
  } catch { /* ignore */ }
}

