  const { user, isLoading, loginWithRedirect } = useAuth();
  const { refreshCount } = useAppData();
  const [data, setData] = useState<GetWalletDataOutputType | null>(null);
  const [loading, setLoading] = useState(true);
  const [syncing, setSyncing] = useState(false);
  const [lastSync, setLastSync] = useState<Date | null>(null);
  const [showTeam, setShowTeam] = useState(false);
  const [showLevels, setShowLevels] = useState(false);
  const [showWithdraw, setShowWithdraw] = useState(false);
  const [ledgerRefresh, setLedgerRefresh] = useState(0);
  const lastRefreshCountRef = useRef(refreshCount);
  const liveTimerRef = useRef<ReturnType<typeof setInterval> | null>(null);

  const fetchWallet = useCallback(async (silent = false) => {
    if (!silent) setLoading(true);
    else setSyncing(true);
    try {
      const d = await getWalletData({});
      setData(d);
      setLastSync(new Date());
    } catch (e: any) {
      if (!silent) toast.error(e?.message ?? 'Failed to load wallet');
    } finally {
      if (!silent) setLoading(false);
      else setSyncing(false);
    }
  }, []);

  // Initial load
  useEffect(() => {
    if (!isLoading && !user) { loginWithRedirect({ redirectUrl: window.location.href }); return; }
    if (user) fetchWallet(false);
  }, [isLoading, user]);

  // ── REAL-TIME LIVE SYNC — polls every 30 seconds ──────────────
  useEffect(() => {
    if (!user) return;
    liveTimerRef.current = setInterval(() => {
      fetchWallet(true); // silent = no loading spinner
    }, LIVE_SYNC_INTERVAL_MS);
    return () => {
      if (liveTimerRef.current) clearInterval(liveTimerRef.current);
    };
  }, [user, fetchWallet]);

  // Re-sync when admin changes settings
  useEffect(() => {
    if (!user) return;
    if (refreshCount !== lastRefreshCountRef.current && refreshCount > 0) {
      lastRefreshCountRef.current = refreshCount;
      fetchWallet(true);
    }
  }, [refreshCount, user, fetchWallet]);

  const reload = () => fetchWallet(true);

  if (isLoading || !user) return null;

  if (loading) return (
    <div className="p-4 space-y-4">
      <Skeleton className="h-28 w-full rounded-2xl" />
      <Skeleton className="h-32 w-full rounded-2xl" />
      <Skeleton className="h-40 w-full rounded-2xl" />
      <Skeleton className="h-20 w-full rounded-2xl" />
    </div>
