  return (
    <>
      <div className="space-y-3 pb-6">
        {/* ── Live Sync Status Bar ── */}
        <div className="mx-4 flex items-center justify-between bg-muted/30 border border-border/50 rounded-xl px-3 py-1.5">
          <div className="flex items-center gap-1.5">
            <span className={`w-1.5 h-1.5 rounded-full ${syncing ? 'bg-yellow-400 animate-pulse' : 'bg-green-400'}`} />
            <Wifi size={10} className="text-muted-foreground" />
            <span className="text-[10px] text-muted-foreground">
              {syncing ? 'Syncing...' : 'Live sync active'}
            </span>
          </div>
          <div className="flex items-center gap-2">
            {lastSync && (
              <span className="text-[9px] text-muted-foreground/60">
