function clean(text: string): string {
  return text
    .replace(/\*{1,3}([^*\n]+)\*{1,3}/gs, '$1')
    .replace(/^#{1,6}\s+/gm, '')
    .replace(/~~([^~]+)~~/gs, '$1')
    .replace(/_{1,2}([^_\n]+)_{1,2}/gs, '$1')
    .replace(/```[\s\S]*?```/g, '')
    .replace(/`([^`]+)`/g, '$1')
    .replace(/\[([^\]]+)\]\([^)]+\)/g, '$1')
    .replace(/\n{3,}/g, '\n\n')
    .trim();
}

export default createEndpoint({
  description: 'TASKMASTER — adaptive Gemini gateway with future-proof auto-shift',
  inputSchema: z.object({
    message: z.string().max(2000),
    currentTime: z.string().optional(),
    history: z.array(z.object({
      role: z.enum(['user', 'model']),
      content: z.string(),
    })).optional(),
  }),
  outputSchema: z.object({ response: z.string(), model: z.string(), aiPowered: z.boolean() }),
  execute: async ({ input }) => {
    const settings = await AdminSettings.findAll({ limit: 500 });
    const records = settings.records;
    const geminiKey = records.find(s => s.settingKey === 'gemini_api_key')?.settingValue;
    const storedModel = records.find(s => s.settingKey === 'gemini_tasks_model')?.settingValue
      ?? records.find(s => s.settingKey === 'gemini_best_model')?.settingValue
      ?? 'gemini-2.5-flash';
    const adminAiName = records.find(s => s.settingKey === 'ai_name')?.settingValue?.trim();

    if (!geminiKey) {
      return { response: 'API key not configured. Please add your Gemini API key in Admin Panel → Settings.', model: 'none', aiPowered: false };
    }

    let systemPrompt = buildSystemPrompt(input.currentTime);
    if (adminAiName) {
      systemPrompt = systemPrompt.replace(/TASKMASTER/g, adminAiName.toUpperCase());
    }

    const body = {
      systemInstruction: { parts: [{ text: systemPrompt }] },
      contents: [
        ...(input.history ?? []).slice(-10).map(h => ({ role: h.role, parts: [{ text: h.content }] })),
        { role: 'user', parts: [{ text: input.message }] },
      ],
      generationConfig: { maxOutputTokens: 2000, temperature: 0.7, topP: 0.9 },
    };

    // ── Adaptive auto-shift ────────────────────────────────────────
    const discovered = await discoverNewModels(geminiKey);
    const chain = buildChain(storedModel, discovered);

    let lastError = '';
    for (const model of chain) {
      try {
        const res = await fetch(
          `https://generativelanguage.googleapis.com/v1beta/models/${model}:generateContent?key=${geminiKey}`,
          { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify(body) }
        );
        if (res.status === 429 || res.status === 503) continue;
        if (!res.ok) {
          const errText = await res.text().catch(() => '');
          if (isGone(res.status, errText)) { console.log(`[Tasks] Model "${model}" gone, auto-shifting...`); continue; }
          lastError = `${model}: ${res.status} ${errText.slice(0, 200)}`;
          continue;
        }
        const data = await res.json() as { candidates?: { content?: { parts?: { text?: string }[] } }[] };
        const raw = data.candidates?.[0]?.content?.parts?.[0]?.text;
        if (!raw) continue;
        return { response: clean(raw), model, aiPowered: true };
      } catch { continue; }
    }

    // ── Last resort: no systemInstruction ───────────────────────────
    try {
      const lastResortModel = discovered[0] ?? 'gemini-1.5-flash';
      const fallbackBody = {
        contents: [{ role: 'user', parts: [{ text: systemPrompt + '\n\n---\nUser message:\n' + input.message }] }],
        generationConfig: { maxOutputTokens: 2000, temperature: 0.7 },
      };
      const res = await fetch(
        `https://generativelanguage.googleapis.com/v1beta/models/${lastResortModel}:generateContent?key=${geminiKey}`,
        { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify(fallbackBody) }
      );
      if (res.ok) {
        const data = await res.json() as { candidates?: { content?: { parts?: { text?: string }[] } }[] };
        const raw = data.candidates?.[0]?.content?.parts?.[0]?.text;
        if (raw) return { response: clean(raw), model: `${lastResortModel}-fallback`, aiPowered: true };
      }
    } catch {}

    console.error('All task models failed. Last error:', lastError);
    throw new Error('AI temporarily unavailable. Please try again in a moment.');
  },
});

