async function verifyGoogleVeo(key: string): Promise<{ ok: boolean; message: string }> {
  try {
    const res = await fetch(`https://generativelanguage.googleapis.com/v1beta/models?key=${key}`, {
      signal: AbortSignal.timeout(10000),
    });
    if (!res.ok) return { ok: false, message: `HTTP ${res.status} — key rejected by Google API` };
    const data = await res.json() as { models?: { name: string }[] };
    const veoModels = (data.models ?? []).filter(m => m.name.includes('veo'));
    if (veoModels.length > 0) {
      return { ok: true, message: `🟢 100% Success: Route Verified — ${veoModels.length} Veo model(s) available` };
