// Removed: location & weatherApiKey from LiveMiniClock — location is shown in MagicCalendarStrip only

function useTheme() {
  const [theme, setTheme] = useState<'dark' | 'light'>(() => {
    if (typeof window !== 'undefined') {
      const saved = (localStorage.getItem('app_theme') as 'dark' | 'light') ?? 'dark';
      if (saved === 'light') document.documentElement.classList.add('light');
      else document.documentElement.classList.remove('light');
      return saved;
    }
    return 'dark';
  });

  useEffect(() => {
    const root = document.documentElement;
    if (theme === 'light') root.classList.add('light');
    else root.classList.remove('light');
    localStorage.setItem('app_theme', theme);
  }, [theme]);

  return { theme, toggle: () => setTheme(t => t === 'dark' ? 'light' : 'dark') };
}

// ── Live Mini Digital Clock — single clean ticking clock ──
function LiveMiniClock() {
  const [time, setTime] = useState('');

  useEffect(() => {
    const tick = () => {
      setTime(new Date().toLocaleTimeString('en-US', {
        hour: '2-digit', minute: '2-digit', second: '2-digit', hour12: true, timeZone: Intl.DateTimeFormat().resolvedOptions().timeZone,
      }));
    };
    tick();
    const id = setInterval(tick, 1000);
    return () => clearInterval(id);
  }, []);

  if (!time) return null;
  return (
    <span className="text-[10px] font-mono font-bold tracking-wider tabular-nums leading-none select-none clock-glow">
      ⏰ {time}
    </span>
  );
}

// ── Notification Bell ────────────────────────────────────────────────
function NotificationBell() {
  const { globalNotification } = useAppData();
  const [hasUnread, setHasUnread] = useState(false);
  const [showPopup, setShowPopup] = useState(false);

  useEffect(() => {
    if (!globalNotification) return;
    const lastSeen = localStorage.getItem('last_notification_seq') ?? '';
    if (lastSeen !== globalNotification.seq) setHasUnread(true);
  }, [globalNotification]);

  const handleBellClick = useCallback(() => {
    if (!globalNotification) { toast.info('No new notifications'); return; }
    setShowPopup(v => !v);
    if (hasUnread) {
      setHasUnread(false);
      localStorage.setItem('last_notification_seq', globalNotification.seq);
    }
  }, [globalNotification, hasUnread]);

  return (
    <div className="relative">
      <button
        onClick={handleBellClick}
        className="p-1.5 rounded-full hover:bg-muted transition-colors relative"
        title={hasUnread ? 'New notification' : 'Notifications'}
      >
        <Bell size={17} className={hasUnread ? 'text-primary' : 'text-muted-foreground'} />
        {hasUnread && (
          <span className="absolute top-1 right-1 w-2 h-2 bg-destructive rounded-full border-2 border-card animate-pulse" />
        )}
      </button>

      {showPopup && globalNotification && (
        <>
          <div className="fixed inset-0 z-40" onClick={() => setShowPopup(false)} />
          <div className="absolute right-0 top-11 z-50 w-72 bg-card border border-primary/30 rounded-2xl shadow-2xl overflow-hidden animate-in slide-in-from-top-2 duration-200">
            <div className="bg-primary/10 border-b border-primary/20 px-4 py-2.5 flex items-center gap-2">
              <Bell size={13} className="text-primary" />
              <span className="text-xs font-black text-primary">📢 Admin Notification</span>
            </div>
            <div className="px-4 py-3">
              <p className="text-sm leading-relaxed text-foreground">{globalNotification.message}</p>
            </div>
            <div className="px-4 pb-3">
              <button
                onClick={() => setShowPopup(false)}
                className="w-full text-xs text-muted-foreground bg-muted rounded-lg py-1.5 hover:text-foreground transition-colors"
              >
                Dismiss
              </button>
            </div>
          </div>
        </>
      )}
    </div>
  );
}

