import { z } from 'zod';
import { createEndpoint, Users, MediaGenerations, AdminSettings } from 'zite-integrations-backend-sdk';

// Read admin-configured limits (falls back to safe defaults if not set)
async function getImageLimits(): Promise<{ free: [number, number, number]; vipDaily: number }> {
  const settings = await AdminSettings.findAll({ limit: 50 });
  const cfg = Object.fromEntries(settings.records.map(r => [r.settingKey ?? '', r.settingValue ?? '']));
  return {
    free: [
      parseInt(cfg['img_limit_free_d1'] ?? '3') || 3,
      parseInt(cfg['img_limit_free_d2'] ?? '2') || 2,
      parseInt(cfg['img_limit_free_d3'] ?? '1') || 1,
    ],
    vipDaily: parseInt(cfg['img_limit_vip'] ?? '0') || 0, // 0 = unlimited
  };
}

export default createEndpoint({
  description: 'Check image generation limit status for the current user. Limits are admin-configurable.',
  authenticated: true,
  inputSchema: z.object({}),
  outputSchema: z.object({
    isVIP: z.boolean(),
    remaining: z.number(),
    daysSinceJoined: z.number(),
    limit: z.number(),
    locked: z.boolean(),
    trialDay: z.number(),
  }),
  execute: async ({ context }) => {
    const [user, limits] = await Promise.all([
      Users.findOne({ id: context.user.id }),
      getImageLimits(),
    ]);

    const isVIP = user?.vipStatus === 'VIP' && (!user.vipExpiresAt || new Date(user.vipExpiresAt) > new Date());

    if (isVIP) {
      // VIP daily limit: 0 = unlimited
      if (limits.vipDaily === 0) {
        return { isVIP: true, remaining: 999, daysSinceJoined: 0, limit: 999, locked: false, trialDay: 0 };
      }
      const today = new Date().toISOString().slice(0, 10);
      const usage = await MediaGenerations.findAll({ filters: { userEmail: context.user.email, date: today, type: 'Image' }, limit: 50 });
      const used = usage.records.reduce((s, r) => s + (r.count ?? 0), 0);
      return {
        isVIP: true,
        remaining: Math.max(0, limits.vipDaily - used),
        daysSinceJoined: 0,
        limit: limits.vipDaily,
        locked: used >= limits.vipDaily,
        trialDay: 0,
      };
    }

    // Free trial user
    const joinedAt = user?.joinedAt ? new Date(user.joinedAt) : new Date();
    const daysSinceJoined = Math.floor((Date.now() - joinedAt.getTime()) / 86400000);
    const trialDay = daysSinceJoined + 1;
    const limit = daysSinceJoined < limits.free.length ? limits.free[daysSinceJoined] : 0;

    if (limit === 0) {
      return { isVIP: false, remaining: 0, daysSinceJoined, limit: 0, locked: true, trialDay };
    }

    const today = new Date().toISOString().slice(0, 10);
    const usage = await MediaGenerations.findAll({ filters: { userEmail: context.user.email, date: today, type: 'Image' }, limit: 50 });
    const used = usage.records.reduce((s, r) => s + (r.count ?? 0), 0);

    return {
      isVIP: false,
      remaining: Math.max(0, limit - used),
      daysSinceJoined,
      limit,
      locked: used >= limit,
      trialDay,
    };
  },
});

