export default createEndpoint({
  description: 'Check video generation quota — admin-configurable daily limit per VIP plan',
  authenticated: true,
  inputSchema: z.object({}),
  outputSchema: z.object({
    isVIP: z.boolean(),
    canGenerate: z.boolean(),
    usedToday: z.number(),
    dailyLimit: z.number(),
    vipExpiresAt: z.string().nullable(),
    vipPlan: z.string().nullable(),
    daysLeft: z.number(),
    lockReason: z.string().nullable(),
    hasSmartRouter: z.boolean(),
  }),
  execute: async ({ context }) => {
    const [user, settings] = await Promise.all([
      Users.findOne({ id: context.user.id }),
      AdminSettings.findAll({ limit: 50 }),
    ]);

    const cfg = Object.fromEntries(settings.records.map(r => [r.settingKey ?? '', r.settingValue ?? '']));
    const now = new Date();

    const isVIPActive =
      user?.vipStatus === 'VIP' &&
      (!user.vipExpiresAt || new Date(user.vipExpiresAt) > now);

    if (!isVIPActive) {
      return {
        isVIP: false,
        canGenerate: false,
        usedToday: 0,
        dailyLimit: parseInt(cfg['vid_limit_vip'] ?? '1') || 1,
        vipExpiresAt: null,
        vipPlan: null,
        daysLeft: 0,
        lockReason: user?.vipStatus === 'Pending'
          ? '⏳ VIP payment under review. Video Creator unlocks after admin approval.'
          : '🔒 Video Creator is exclusively for VIP members. Upgrade now to unlock!',
        hasSmartRouter: false,
      };
    }

    // Admin-configurable daily video limit (default 1)
    const dailyLimit = parseInt(cfg['vid_limit_vip'] ?? '1') || 1;

    const expiresAt = user?.vipExpiresAt ? new Date(user.vipExpiresAt) : null;
    const daysLeft = expiresAt
      ? Math.max(0, Math.ceil((expiresAt.getTime() - now.getTime()) / 86400000))
      : 36500;

    const today = now.toISOString().slice(0, 10);
    const usageRes = await MediaGenerations.findAll({
      filters: { userEmail: context.user.email, date: today, type: 'Video' },
      limit: 10,
    });
    const usedToday = usageRes.records.reduce((s, r) => s + (r.count ?? 0), 0);
    const canGenerate = usedToday < dailyLimit;

    // Smart Router is exclusive to VIP 90 Days (Plan 4) and VIP UNLIMITED (Plan 5)
    const SMART_ROUTER_PLANS = ['VIP 90 Days', 'VIP UNLIMITED'];
    const hasSmartRouter = SMART_ROUTER_PLANS.some(p => (user?.vipPlan ?? '').includes(p));

    return {
      isVIP: true,
      canGenerate,
      usedToday,
      dailyLimit,
      vipExpiresAt: user?.vipExpiresAt ?? null,
      vipPlan: user?.vipPlan ?? null,
      daysLeft,
      lockReason: canGenerate
        ? null
        : `⏰ Daily limit reached! You've used your ${dailyLimit} video${dailyLimit > 1 ? 's' : ''} for today. Come back tomorrow!`,
      hasSmartRouter,
    };
  },
});

import { z } from 'zod';
import { createEndpoint, AdminSettings, SupabaseConfigs, ZiteError } from 'zite-integrations-backend-sdk';

// ── SQL that will be executed on the target Supabase project ──────────
const MIGRATION_SQL = `
-- Hussain AI: Auto-Migration v2.0
-- Run by the app automatically via the Admin Panel

-- 1. Users sync table
CREATE TABLE IF NOT EXISTS aep_users (
  id TEXT PRIMARY KEY,
  email TEXT UNIQUE NOT NULL,
  name TEXT,
  phone TEXT,
  referral_code TEXT UNIQUE,
