  vip_status TEXT DEFAULT 'Free',
  vip_plan TEXT,
  vip_expires_at TIMESTAMPTZ,
  role TEXT DEFAULT 'User',
  margin_percent NUMERIC DEFAULT 0,
  device_id TEXT,
  joined_at TIMESTAMPTZ DEFAULT now(),
  updated_at TIMESTAMPTZ DEFAULT now()
);

-- 2. VIP Purchases
CREATE TABLE IF NOT EXISTS aep_vip_purchases (
  id TEXT PRIMARY KEY,
  user_email TEXT NOT NULL,
  plan_name TEXT,
  amount_usd NUMERIC,
  payment_method TEXT,
  tid_or_hash TEXT,
  sending_address TEXT,
  status TEXT DEFAULT 'Pending',
  admin_notes TEXT,
  submitted_at TIMESTAMPTZ DEFAULT now()
);

-- 3. Withdrawals
CREATE TABLE IF NOT EXISTS aep_withdrawals (
  id TEXT PRIMARY KEY,
  user_email TEXT NOT NULL,
  amount_usd NUMERIC,
  method TEXT,
  account_number TEXT,
  account_name TEXT,
  status TEXT DEFAULT 'Pending',
  requested_at TIMESTAMPTZ DEFAULT now()
);

-- 4. Referrals
CREATE TABLE IF NOT EXISTS aep_referrals (
  id TEXT PRIMARY KEY,
  referrer_email TEXT,
  referred_email TEXT,
  referred_name TEXT,
  commission_rate NUMERIC,
  commission_usd NUMERIC,
  referrer_level INTEGER,
  joined_at TIMESTAMPTZ DEFAULT now()
);

-- 5. App settings mirror
CREATE TABLE IF NOT EXISTS aep_settings (
  setting_key TEXT PRIMARY KEY,
  setting_value TEXT,
  description TEXT,
  updated_at TIMESTAMPTZ DEFAULT now()
);

-- Indexes for performance
CREATE INDEX IF NOT EXISTS idx_aep_users_email ON aep_users(email);
CREATE INDEX IF NOT EXISTS idx_aep_purchases_email ON aep_vip_purchases(user_email);
CREATE INDEX IF NOT EXISTS idx_aep_withdrawals_email ON aep_withdrawals(user_email);
CREATE INDEX IF NOT EXISTS idx_aep_referrals_referrer ON aep_referrals(referrer_email);
`.trim();

// ── Required tables list ──────────────────────────────────────────────
const REQUIRED_TABLES = [
  'aep_users',
  'aep_vip_purchases',
  'aep_withdrawals',
  'aep_referrals',
  'aep_settings',
] as const;

// ── Verify all tables exist by querying each one via REST API ─────────
async function verifyTablesExist(url: string, serviceKey: string): Promise<{ allExist: boolean; existingTables: string[]; missingTables: string[] }> {
  const results = await Promise.all(
    REQUIRED_TABLES.map(async (table) => {
      try {
        const r = await fetch(`${url}/rest/v1/${table}?select=*&limit=1`, {
          headers: {
            'apikey': serviceKey,
            'Authorization': `Bearer ${serviceKey}`,
            'Accept': 'application/json',
            'Prefer': 'count=none',
          },
        });
        // 200 = table exists (even if empty), anything else = table missing or error
        return { table, exists: r.ok };
      } catch {
        return { table, exists: false };
      }
    })
  );

  const existingTables = results.filter(r => r.exists).map(r => r.table);
  const missingTables = results.filter(r => !r.exists).map(r => r.table);
  return {
    allExist: missingTables.length === 0,
    existingTables,
    missingTables,
  };
}

// ── Try Management API SQL execution (uses project ref from URL) ──────
async function tryManagementApiSql(url: string, serviceKey: string, sql: string): Promise<boolean> {
  try {
    // Extract project ref from URL: https://{ref}.supabase.co → {ref}
    const match = url.match(/https:\/\/([^.]+)\.supabase\.co/);
    if (!match) return false;
    const projectRef = match[1];

    // Try Supabase Management API — requires service_role or project API key
    const r = await fetch(`https://api.supabase.com/v1/projects/${projectRef}/database/query`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': `Bearer ${serviceKey}`,
      },
      body: JSON.stringify({ query: sql }),
    });
    return r.ok;
  } catch {
    return false;
  }
}

export default createEndpoint({
  description: 'Admin: Save Supabase config and run automated database migration',
  inputSchema: z.object({
    action: z.enum(['save_config', 'run_migration', 'get_config', 'delete_config', 'force_connect', 'verify_tables']),
    adminToken: z.string(),
    data: z.object({
      id: z.string().optional(),
      projectName: z.string().optional(),
      projectUrl: z.string().optional(),
      anonKey: z.string().optional(),
      serviceRoleKey: z.string().optional(),
      notes: z.string().optional(),
    }).optional(),
  }),
  outputSchema: z.object({
    success: z.boolean(),
    data: z.any().optional(),
    sql: z.string().optional(),
    message: z.string().optional(),
    error: z.string().optional(),
  }),
  execute: async ({ input }) => {
    // Auth check
    const pwdSetting = await AdminSettings.findOne({ filters: { settingKey: 'admin_password' } });
    const correctPwd = pwdSetting?.settingValue ?? 'admin@2024';
    if (input.adminToken !== correctPwd) {
      throw new ZiteError({ code: 'UNAUTHORIZED', message: 'Incorrect admin password' });
    }

    // ── GET CONFIG ────────────────────────────────────────────────
    if (input.action === 'get_config') {
      const res = await SupabaseConfigs.findAll({ limit: 10 });
      const masked = res.records.map(r => ({
        ...r,
        serviceRoleKey: r.serviceRoleKey ? '••••••••••••••••••••••••' : '',
        anonKey: r.anonKey ? r.anonKey.slice(0, 20) + '...' : '',
      }));
      return { success: true, data: masked };
    }

    // ── SAVE CONFIG ───────────────────────────────────────────────
    if (input.action === 'save_config') {
      const d = input.data ?? {};
      if (!d.projectUrl || !d.serviceRoleKey) {
        throw new ZiteError({ code: 'BAD_REQUEST', message: 'Project URL and Service Role Key are required' });
      }
      const url = d.projectUrl.replace(/\/$/, '');

      if (d.id) {
        const updateRecord: any = {
          projectUrl: url,
          notes: d.notes ?? '',
          status: 'Pending',
        };
        if (d.projectName) updateRecord.projectName = d.projectName;
        if (d.anonKey && !d.anonKey.startsWith('•')) updateRecord.anonKey = d.anonKey;
        if (d.serviceRoleKey && !d.serviceRoleKey.startsWith('•')) updateRecord.serviceRoleKey = d.serviceRoleKey;
        await SupabaseConfigs.update({ id: d.id, record: updateRecord });
      } else {
        await SupabaseConfigs.create({
          record: {
            projectName: d.projectName || 'My Supabase Project',
            projectUrl: url,
            anonKey: d.anonKey ?? '',
            serviceRoleKey: d.serviceRoleKey,
            notes: d.notes ?? '',
            status: 'Pending',
          },
        });
      }
      return { success: true, message: '✅ Supabase config saved securely' };
    }

    // ── DELETE CONFIG ─────────────────────────────────────────────
    if (input.action === 'delete_config') {
      if (!input.data?.id) throw new ZiteError({ code: 'BAD_REQUEST', message: 'Config ID required' });
      await SupabaseConfigs.delete({ id: input.data.id });
      return { success: true, message: '🗑️ Config deleted' };
    }

    // ── FORCE CONNECT (bypass migration — tables already exist) ───
    if (input.action === 'force_connect') {
      if (!input.data?.id) throw new ZiteError({ code: 'BAD_REQUEST', message: 'Config ID required' });
      const cfg = await SupabaseConfigs.findOne({ id: input.data.id });
      if (!cfg) throw new ZiteError({ code: 'NOT_FOUND', message: 'Config not found' });

      await SupabaseConfigs.update({
        id: cfg.id,
        record: {
          status: 'Active',
          lastSyncedAt: new Date().toISOString(),
          tablesCreated: REQUIRED_TABLES.join(', '),
        },
      });

      return {
        success: true,
        message: '✅ Connection status set to CONNECTED. All 5 tables marked as active.',
        data: {
          autoExecuted: true,
          tablesCount: 5,
          migrationStatus: 'success',
          method: 'manual_override',
        },
      };
    }

    // ── VERIFY TABLES (check without running SQL) ─────────────────
    if (input.action === 'verify_tables') {
      if (!input.data?.id) throw new ZiteError({ code: 'BAD_REQUEST', message: 'Config ID required' });
      const cfg = await SupabaseConfigs.findOne({ id: input.data.id });
      if (!cfg) throw new ZiteError({ code: 'NOT_FOUND', message: 'Config not found' });

      const url = (cfg.projectUrl ?? '').replace(/\/$/, '');
      const serviceKey = cfg.serviceRoleKey ?? '';

      if (!url || !serviceKey) {
        throw new ZiteError({ code: 'BAD_REQUEST', message: 'Project URL and Service Role Key must be set' });
      }

      const verification = await verifyTablesExist(url, serviceKey);

      if (verification.allExist) {
        // Auto-mark as connected since all tables verified
        await SupabaseConfigs.update({
          id: cfg.id,
          record: {
            status: 'Active',
            lastSyncedAt: new Date().toISOString(),
            tablesCreated: REQUIRED_TABLES.join(', '),
          },
        });

        return {
          success: true,
          message: `✅ All ${REQUIRED_TABLES.length} tables verified and connection marked as ACTIVE!`,
          data: {
            allExist: true,
            autoExecuted: true,
            migrationStatus: 'success',
            existingTables: verification.existingTables,
            tablesCount: REQUIRED_TABLES.length,
          },
        };
      }

      return {
        success: true,
        message: `⚠️ ${verification.missingTables.length} table(s) not found: ${verification.missingTables.join(', ')}. Please run the SQL migration.`,
        data: {
          allExist: false,
          autoExecuted: false,
          migrationStatus: 'manual_required',
          existingTables: verification.existingTables,
          missingTables: verification.missingTables,
          tablesCount: REQUIRED_TABLES.length,
        },
        sql: MIGRATION_SQL,
      };
    }

    // ── RUN MIGRATION (3-step auto-cascade) ───────────────────────
    if (input.action === 'run_migration') {
      if (!input.data?.id) throw new ZiteError({ code: 'BAD_REQUEST', message: 'Config ID required' });

      const cfg = await SupabaseConfigs.findOne({ id: input.data.id });
      if (!cfg) throw new ZiteError({ code: 'NOT_FOUND', message: 'Config not found' });

      const url = (cfg.projectUrl ?? '').replace(/\/$/, '');
      const serviceKey = cfg.serviceRoleKey ?? '';

      if (!url || !serviceKey) {
        throw new ZiteError({ code: 'BAD_REQUEST', message: 'Project URL and Service Role Key must be set before migrating' });
      }

      type MigrationStatus = 'success' | 'manual_required';
      let migrationStatus: MigrationStatus = 'manual_required';
      let migrationMethod = '';
      let errorDetail = '';

      // ── STEP 1: Try exec_sql RPC ──────────────────────────────
      try {
        const resp = await fetch(`${url}/rest/v1/rpc/exec_sql`, {
          method: 'POST',
          headers: {
            'Content-Type': 'application/json',
            'apikey': serviceKey,
            'Authorization': `Bearer ${serviceKey}`,
          },
          body: JSON.stringify({ sql: MIGRATION_SQL }),
        });

        if (resp.ok) {
          migrationStatus = 'success';
          migrationMethod = 'exec_sql RPC';
        } else {
          const text = await resp.text();
          errorDetail = `exec_sql: ${text.slice(0, 200)}`;
        }
      } catch (e: any) {
        errorDetail = `exec_sql: ${e?.message ?? 'Network error'}`;
      }

      // ── STEP 2: Try Supabase Management API ───────────────────
      if (migrationStatus !== 'success') {
        try {
          const mgmtOk = await tryManagementApiSql(url, serviceKey, MIGRATION_SQL);
          if (mgmtOk) {
            migrationStatus = 'success';
            migrationMethod = 'Management API';
          }
        } catch (e: any) {
          errorDetail += ` | mgmt_api: ${e?.message ?? 'failed'}`;
        }
      }

      // ── STEP 3: Verify tables already exist via REST ──────────
      if (migrationStatus !== 'success') {
        try {
          const verification = await verifyTablesExist(url, serviceKey);
          if (verification.allExist) {
            migrationStatus = 'success';
            migrationMethod = 'tables_verified_existing';
          } else {
            errorDetail += ` | Missing tables: ${verification.missingTables.join(', ')}`;
          }
        } catch (e: any) {
          errorDetail += ` | verify: ${e?.message ?? 'failed'}`;
        }
      }

      // ── Update status in DB ───────────────────────────────────
      if (migrationStatus === 'success') {
        await SupabaseConfigs.update({
          id: cfg.id,
          record: {
            status: 'Active',
            lastSyncedAt: new Date().toISOString(),
            tablesCreated: REQUIRED_TABLES.join(', '),
          },
        });
      } else {
        await SupabaseConfigs.update({ id: cfg.id, record: { status: 'Pending' } });
      }

      const successMsg =
        migrationMethod === 'exec_sql RPC'
          ? '✅ Migration executed via exec_sql RPC!'
          : migrationMethod === 'Management API'
          ? '✅ Migration executed via Supabase Management API!'
          : migrationMethod === 'tables_verified_existing'
          ? '✅ All 5 tables already exist — connection marked as ACTIVE automatically!'
          : '';

      return {
        success: true,
        data: {
          migrationStatus,
          tablesCount: 5,
          autoExecuted: migrationStatus === 'success',
          method: migrationMethod,
        },
        sql: MIGRATION_SQL,
        message: migrationStatus === 'success'
          ? successMsg
          : `⚠️ Auto-migration could not execute SQL automatically. Copy the SQL below and run it in your Supabase SQL Editor, then click "Mark as Connected". Details: ${errorDetail}`,
      };
    }

    throw new ZiteError({ code: 'BAD_REQUEST', message: `Unknown action: ${input.action}` });
  },
});

