import { z } from 'zod';
import { createEndpoint, AdminSettings } from 'zite-integrations-backend-sdk';

// ══════════════════════════════════════════════════════════════════
// ADAPTIVE GATEWAY — Fast model for hashtags with auto-shift
// ══════════════════════════════════════════════════════════════════
const KNOWN_FALLBACK_CHAIN = [
  'gemini-2.0-flash',
  'gemini-1.5-flash',
  'gemini-2.5-flash',
  'gemini-2.5-pro',
  'gemini-1.5-pro',
];

const DEPRECATION_SIGNALS = ['not found', 'deprecated', 'decommissioned', 'does not exist', 'not supported'];
function isGone(status: number, body: string): boolean {
  if (status === 404) return true;
  if (status === 400) return DEPRECATION_SIGNALS.some(s => body.toLowerCase().includes(s));
  return false;
}

async function discoverNewModels(apiKey: string): Promise<string[]> {
  try {
    const res = await fetch(`https://generativelanguage.googleapis.com/v1beta/models?pageSize=200&key=${apiKey}`);
    if (!res.ok) return [];
    const data = await res.json() as { models?: { name: string; supportedGenerationMethods?: string[] }[] };
    return (data.models ?? [])
      .filter(m => (m.supportedGenerationMethods ?? []).includes('generateContent'))
      .map(m => m.name.replace('models/', ''))
      .filter(id => id.startsWith('gemini'))
      .sort((a, b) => b.localeCompare(a));
  } catch { return []; }
}

function buildChain(preferred: string, discovered: string[]): string[] {
  const seen = new Set<string>();
  const chain: string[] = [];
  const add = (m: string) => { if (!seen.has(m)) { seen.add(m); chain.push(m); } };
  add(preferred);
  for (const m of KNOWN_FALLBACK_CHAIN) add(m);
  for (const m of discovered) add(m);
  return chain;
}

const STATIC_FALLBACK = [
  '#AIArt', '#DigitalArt', '#Viral', '#Trending', '#Creative',
  '#Aesthetic', '#Photography', '#AI', '#Design', '#Art',
  '#Beautiful', '#Amazing', '#Explore', '#Instagram', '#Pakistan',
  '#Reels', '#TikTok', '#Shorts',
];

export default createEndpoint({
  description: 'Generate viral hashtags — adaptive Gemini gateway with auto-shift',
  inputSchema: z.object({ prompt: z.string().min(3).max(500) }),
  outputSchema: z.object({ hashtags: z.array(z.string()) }),
  execute: async ({ input }) => {
    const settings = await AdminSettings.findAll({ limit: 200 });
    const records = settings.records;
    const geminiKey = records.find(s => s.settingKey === 'gemini_api_key')?.settingValue;
    const sectionModel = records.find(s => s.settingKey === 'gemini_fast_model')?.settingValue
      ?? records.find(s => s.settingKey === 'gemini_best_model')?.settingValue
      ?? 'gemini-2.0-flash';

    if (!geminiKey) {
      const words = input.prompt.split(/\s+/).filter(w => w.length > 3).slice(0, 6)
        .map(w => '#' + w.toLowerCase().replace(/[^a-z0-9]/g, ''));
      return { hashtags: [...words, ...STATIC_FALLBACK].slice(0, 18) };
    }

    const body = {
      contents: [{
        parts: [{
          text: `Generate exactly 18 viral social media hashtags for this content: "${input.prompt}"

Rules:
- Each hashtag starts with #
- Mix: 5 niche-specific, 5 broad trending, 4 community, 4 Pakistani/regional if applicable
- Return ONLY hashtags, one per line, no numbering or explanation`,
        }],
      }],
      generationConfig: { maxOutputTokens: 200, temperature: 0.9 },
    };

    const discovered = await discoverNewModels(geminiKey);
    const chain = buildChain(sectionModel, discovered);

    for (const model of chain) {
      try {
        const res = await fetch(
          `https://generativelanguage.googleapis.com/v1beta/models/${model}:generateContent?key=${geminiKey}`,
          { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify(body) }
        );
        if (res.status === 429 || res.status === 503) continue;
        if (!res.ok) {
          const errText = await res.text().catch(() => '');
          if (isGone(res.status, errText)) { console.log(`[Hashtags] Model "${model}" gone, auto-shifting...`); continue; }
          continue;
        }
        const data = await res.json() as { candidates?: { content?: { parts?: { text?: string }[] } }[] };
        const text = data.candidates?.[0]?.content?.parts?.[0]?.text ?? '';
        const hashtags = text
          .split('\n')
          .map((l: string) => l.trim())
          .filter((l: string) => l.startsWith('#') && l.length > 1)
          .slice(0, 20);
        if (hashtags.length >= 10) return { hashtags };
      } catch { continue; }
    }

    return { hashtags: STATIC_FALLBACK };
  },
});

// ══════════════════════════════════════════════════════════════════
// SETUP USER PROFILE v2.0
// • Generates referral code for new users
// • ATOMIC coin credit: merges referral bonus into the same DB update
//   that sets referralCode — no race condition between two updates
// • Credits BOTH referrer + referee in real-time during sign-up
// • Enforces ONE ACCOUNT PER DEVICE when deviceId is provided
// ══════════════════════════════════════════════════════════════════
import { z } from 'zod';
import { createEndpoint, Users, Referrals, AdminSettings, ZiteError } from 'zite-integrations-backend-sdk';

function makeCode(email: string): string {
  const base = email.split('@')[0].replace(/[^a-zA-Z0-9]/g, '').slice(0, 4).toUpperCase();
  const rand = Math.random().toString(36).slice(2, 6).toUpperCase();
  return (base + rand).slice(0, 8);
}

export default createEndpoint({
  description: 'Initialize new user: generate referral code, track referral chain, instantly credit bonus coins to BOTH referrer and referee atomically.',
  authenticated: true,
  inputSchema: z.object({
    name:           z.string().min(2).optional(),
    phone:          z.string().optional(),
    referredByCode: z.string().optional(),
    deviceId:       z.string().min(4).max(200).optional(),
  }),
  outputSchema: z.object({ referralCode: z.string(), coinsAwarded: z.number() }),
  execute: async ({ input, context }) => {
    const existing = await Users.findOne({ id: context.user.id });

    // ── If user already has a referral code, just update name/phone ──
    if (existing?.referralCode) {
      const updateFields: Record<string, unknown> = {};
      if (input.name)     updateFields.name     = input.name;
      if (input.phone)    updateFields.phone    = input.phone;
      if (input.deviceId) updateFields.deviceId = input.deviceId;
      if (Object.keys(updateFields).length) {
        await Users.update({ id: context.user.id, record: updateFields as any });
      }
      return { referralCode: existing.referralCode, coinsAwarded: 0 };
    }

    // ── NEW USER: enforce one-device-one-account ──────────────────
    if (input.deviceId) {
      const deviceOwner = await Users.findOne({
        filters: { deviceId: input.deviceId },
        fields: ['id', 'email'],
      });
      if (deviceOwner && deviceOwner.id !== context.user.id) {
        throw new ZiteError({
          code: 'CONFLICT',
          message:
            'Ek device per sirf ek account ban sakta hai. ' +
            'This device already has a registered account. ' +
            'Please use your original account to log in.',
        });
      }
    }

    // ── Build the SINGLE update record for the new user ──────────
    const refCode = makeCode(context.user.email);
    const updates: Record<string, unknown> = { referralCode: refCode };
    if (input.name)     updates.name     = input.name;
    if (input.phone)    updates.phone    = input.phone;
    if (input.deviceId) updates.deviceId = input.deviceId;

    let coinsAwarded = 0;
    const referredByCode = input.referredByCode?.trim() || existing?.referredByCode;

    if (referredByCode) {
      updates.referredByCode = referredByCode;

      const [referrer, rewardSetting] = await Promise.all([
        Users.findOne({ filters: { referralCode: referredByCode } }),
        AdminSettings.findOne({ filters: { settingKey: 'referral_reward_coins' } }),
      ]);

      if (referrer && referrer.email !== context.user.email) {
        const existingReferral = await Referrals.findOne({
          filters: { referredEmail: context.user.email },
        });

        if (!existingReferral) {
          const totalRewardCoins = parseInt(rewardSetting?.settingValue ?? '100') || 100;
          const halfCoins = Math.floor(totalRewardCoins / 2);

          // ── ATOMIC: Include referee coins IN the same updates object ──
          updates.coins = (existing?.coins ?? 0) + halfCoins;
          coinsAwarded = halfCoins;

          // Credit referrer + create referral record concurrently
          // The referee update happens below in the single Users.update call
          await Promise.all([
            Referrals.create({
              record: {
                referrerEmail: referrer.email,
                referredEmail: context.user.email,
                referredName:  input.name ?? existing?.name ?? context.user.email,
                commissionRate: 0.05,
                commissionUsd:  0,
                referrerLevel:  referrer.level ?? 1,
              },
            }),
            Users.update({
              id: referrer.id,
              record: {
                totalReferrals: (referrer.totalReferrals ?? 0) + 1,
                coins: (referrer.coins ?? 0) + halfCoins,
              },
            }),
          ]);
        }
      }
    }

    // ── SINGLE atomic update for the new user (includes coins if referral) ──
    await Users.update({ id: context.user.id, record: updates as any });
    return { referralCode: refCode, coinsAwarded };
  },
});

import { z } from 'zod';
import { createEndpoint, Withdrawals, Users, AdminSettings, ZiteError } from 'zite-integrations-backend-sdk';

export default createEndpoint({
  description: 'Submit withdrawal request and deduct from user balance (uses admin-defined minimum limit)',
  authenticated: true,
  inputSchema: z.object({
    amountUsd: z.number().min(0.01).max(100000),
    method: z.string(),
    accountNumber: z.string().min(3),
    accountName: z.string().min(2),
  }),
  outputSchema: z.object({ success: z.boolean() }),
  execute: async ({ input, context }) => {
    // Load admin-defined minimum withdrawal limit (default $1.00)
    const minSetting = await AdminSettings.findOne({ filters: { settingKey: 'min_withdraw_usd' } });
    const minWithdrawUsd = parseFloat(minSetting?.settingValue ?? '1') || 1;

    const user = await Users.findOne({ id: context.user.id });
    const balance = user?.usdBalance ?? 0;

    if (balance < minWithdrawUsd) {
      throw new ZiteError({
        code: 'BAD_REQUEST',
        message: `Minimum withdrawal is $${minWithdrawUsd.toFixed(2)}. Your balance is insufficient.`,
      });
    }
    if (input.amountUsd < minWithdrawUsd) {
      throw new ZiteError({
        code: 'BAD_REQUEST',
        message: `Minimum withdrawal amount is $${minWithdrawUsd.toFixed(2)}`,
      });
    }
    if (input.amountUsd > balance) {
      throw new ZiteError({ code: 'BAD_REQUEST', message: 'Insufficient balance' });
    }

    await Promise.all([
      Withdrawals.create({
        record: {
          userEmail: context.user.email,
          amountUsd: input.amountUsd,
          method: input.method as any,
          accountNumber: input.accountNumber,
          accountName: input.accountName,
          status: 'Pending',
        },
      }),
      Users.update({ id: context.user.id, record: { usdBalance: balance - input.amountUsd } }),
    ]);
    return { success: true };
  },
});

