  { url: 'https://api-inference.huggingface.co/models/ali-vilab/text-to-video-ms-1.7b',   label: 'Route A — DAMO-ViLab' },
  { url: 'https://api-inference.huggingface.co/models/ByteDance/AnimateDiff-Lightning',    label: 'Route B — AnimateDiff' },
  { url: 'https://api-inference.huggingface.co/models/camenduru/text2-video-zero',         label: 'Route C — Text2Video-Zero' },
  { url: 'https://api-inference.huggingface.co/models/PAIR/text2video-zero-controlnet',    label: 'Route D — ControlNet' },
];

// ── Watermark ────────────────────────────────────────────────────
const WATERMARK = 'Powered by Hussain AI';

export default createEndpoint({
  description: 'ISOLATED HuggingFace video engine — 4-route sequential failover. No cross-engine dependencies.',
  authenticated: true,
  inputSchema: z.object({
    prompt: z.string().min(5),
    durationSeconds: z.number().min(3).max(30).default(5),
  }),
  outputSchema: z.object({
    success: z.boolean(),
    videoUrl: z.string().optional(),
    videoBase64: z.string().optional(),
    mimeType: z.string().optional(),
    engine: z.string(),
    watermark: z.string().optional(),
    pipelineLog: z.array(z.string()),
  }),
  execute: async ({ input, context }) => {
    // ── Safety Guard ──
    if (!isSafe(input.prompt)) {
      throw new ZiteError({ code: 'BAD_REQUEST', message: 'یہ مواد پالیسی کے خلاف ہے! نامناسب مواد کی اجازت نہیں ہے۔' });
    }

    // ── VIP check ──
    const user = await Users.findOne({ id: context.user.id });
    const isVIP = user?.vipStatus === 'VIP' && (!user.vipExpiresAt || new Date(user.vipExpiresAt) > new Date());
    if (!isVIP) throw new ZiteError({ code: 'FORBIDDEN', message: '🔒 VIP membership required.' });

    // ── Daily quota ──
    const today = new Date().toISOString().slice(0, 10);
    const [usageRes, limitSetting] = await Promise.all([
      MediaGenerations.findAll({ filters: { userEmail: context.user.email, date: today, type: 'Video' }, limit: 10 }),
      AdminSettings.findOne({ filters: { settingKey: 'vid_limit_vip' } }),
    ]);
    const dailyLimit = parseInt(limitSetting?.settingValue ?? '3') || 3;
    const usedToday = usageRes.records.reduce((s, r) => s + (r.count ?? 0), 0);
    if (usedToday >= dailyLimit) throw new ZiteError({ code: 'RATE_LIMITED', message: '⏰ آج کی ویڈیو لمٹ پوری ہو گئی۔' });

    // ── Validate HF key exists ──
    if (!HF_TOKEN) {
      throw new ZiteError({ code: 'BAD_REQUEST', message: '⚙️ HuggingFace API key not configured. Set ZITE_HUGGING_FACE_API_KEY in environment.' });
    }

    // ── Build safe prompt ──
    const safePrompt = input.prompt.replace(/\b(nsfw|explicit|nude|naked)\b/gi, '').trim() + ', cinematic quality, SFW, family-friendly';

