// ── Keyword sets for routing ─────────────────────────────────────
const CINEMATIC_KEYWORDS = [
  'cinematic','photorealistic','movie','film','drone shot','aerial',
  'epic','slow motion','4k','8k','blockbuster','trailer','dramatic',
  'landscape','sunset','sunrise','timelapse','time lapse','nature',
  'realistic','hyper realistic','ultra realistic','hdr','filmic',
];

const AVATAR_KEYWORDS = [
  'avatar','talking','explainer','cartoon','animated','character',
  'anime','2d','3d character','mascot','spokesperson','narrator',
  'talking head','face','person speaking','instructor','teacher',
  'presentation','whiteboard','motion graphics',
];

// ── Eligible plan names (Plan 4 = VIP 90 Days) ──────────────────
const SMART_ROUTER_PLANS = ['VIP 90 Days', 'VIP UNLIMITED'];

// ── Content Safety Filter ────────────────────────────────────────
const BLOCKED = [
  'nude','nudity','naked','sexy','seductive','erotic','intimate','sensual',
  'undress','lingerie','bikini','provocative','obscene','porn','pornography',
  'nsfw','xxx','adult content','hentai','fetish','bondage','bdsm',
