  'extremist','riot','revolution against','overthrow','sedition',
  'kill','murder','assassination','genocide','ethnic cleansing',
  'racial slur','racist','bigot','supremacist',
];
function isSafe(prompt: string): boolean {
  const lower = prompt.toLowerCase();
  return !BLOCKED.some(w => lower.includes(w));
}

type RouteDecision = 'universal' | 'stability' | 'google-veo' | 'huggingface';

function detectRoute(prompt: string): { route: RouteDecision; reason: string } {
  const lower = prompt.toLowerCase();
  for (const kw of CINEMATIC_KEYWORDS) {
    if (lower.includes(kw)) return { route: 'google-veo', reason: `Keyword "${kw}" → Cinematic engine (Google Veo)` };
  }
  for (const kw of AVATAR_KEYWORDS) {
    if (lower.includes(kw)) return { route: 'huggingface', reason: `Keyword "${kw}" → Avatar/Explainer engine (HuggingFace)` };
  }
  return { route: 'google-veo', reason: 'No specific keywords → Default engine (Google Veo)' };
}

const WATERMARK = 'Powered by Hussain AI';

// ══════════════════════════════════════════════════════════════════
// UNIVERSAL AI GATEWAY — Priority 0 (Self-Healing, Never-Fail)
// ══════════════════════════════════════════════════════════════════
async function processUniversalGateway(
  prompt: string,
  pipelineLog: string[],
): Promise<{ hit: boolean; videoUrl?: string; videoBase64?: string; mimeType?: string; operationId?: string; engine: string }> {
  pipelineLog.push('🌐 Universal AI Gateway — Scanning for active universal config...');

  const { records } = await VideoApiKeys.findAll({ limit: 10 });
  const universalRow = records.find(r => r.universalApiKey && r.universalApiKey.length > 5);

  if (!universalRow) {
    pipelineLog.push('⏭ Universal Gateway — No universal key configured, skipping');
    return { hit: false, engine: 'none' };
  }

  const activeKey = universalRow.universalApiKey!;
  const targetUrl = universalRow.modelEndpointUrl || 'https://api.canva.com/v1/video/generate';
  const gatewayLabel = universalRow.gatewayName ?? 'Universal AI Gateway';

  if (!activeKey.trim()) {
    pipelineLog.push('🛡️ Shield Activated: Universal key is blank — routing to standby safe-mode');
    return { hit: false, engine: 'none' };
  }

  let customPayload: Record<string, unknown> = {};
  if (universalRow.payloadMappingJson) {
    try {
      customPayload = JSON.parse(universalRow.payloadMappingJson);
    } catch {
      pipelineLog.push('⚠️ Universal payload JSON parse error — using defaults');
    }
  }

  const payload = { prompt, ...customPayload };
  pipelineLog.push(`⏳ Trying Universal Gateway → ${targetUrl.slice(0, 60)}...`);

  try {
    const response = await fetch(targetUrl, {
      method: 'POST',
      headers: { 'Authorization': `Bearer ${activeKey}`, 'Content-Type': 'application/json' },
      body: JSON.stringify(payload),
      signal: AbortSignal.timeout(30000),
    });

    if (!response.ok) {
      pipelineLog.push(`⏭ Universal Gateway — HTTP ${response.status} (API Drop Intercepted)`);
      return { hit: false, engine: 'none' };
    }

    const ct = response.headers.get('content-type') ?? '';

    if (ct.includes('video') || ct.includes('octet-stream') || ct.includes('image')) {
      const buffer = await response.arrayBuffer();
      const bytes = new Uint8Array(buffer);
      let binary = '';
      for (let j = 0; j < bytes.length; j++) binary += String.fromCharCode(bytes[j]);
      const base64 = btoa(binary);
      const mime = ct.includes('video') ? 'video/mp4' : ct.includes('image') ? 'image/gif' : 'video/mp4';
      pipelineLog.push(`✅ Universal Gateway — Video/media received (${gatewayLabel})`);
      return { hit: true, videoBase64: base64, mimeType: mime, engine: gatewayLabel };
    }

    const data = await response.json() as any;
    const videoUrl = data.video_url ?? data.videoUrl ?? data.url ?? data.output?.url ?? data.result?.url;
    const opId = data.operation_id ?? data.operationId ?? data.id ?? data.name;
    const b64 = data.video ?? data.videoBase64 ?? data.output?.video;

    if (videoUrl) { pipelineLog.push(`✅ Universal Gateway — Video URL received (${gatewayLabel})`); return { hit: true, videoUrl, mimeType: 'video/mp4', engine: gatewayLabel }; }
    if (b64) { pipelineLog.push(`✅ Universal Gateway — Base64 video received (${gatewayLabel})`); return { hit: true, videoBase64: b64, mimeType: 'video/mp4', engine: gatewayLabel }; }
    if (opId) { pipelineLog.push(`✅ Universal Gateway — Async job submitted: ${opId} (${gatewayLabel})`); return { hit: true, operationId: String(opId), engine: gatewayLabel }; }

    pipelineLog.push(`⏭ Universal Gateway — Response had no recognized video fields`);
    return { hit: false, engine: 'none' };
  } catch (error) {
    pipelineLog.push(`🛡️ Self-Healing Circuit Triggered: Universal Gateway error caught — Lifetime Always-On Protection Active`);
    return { hit: false, engine: 'none' };
  }
}

