    if (route === 'google-veo' || route === 'stability') {
      const veoKeyRecord = await VideoApiKeys.findOne({ filters: { keyIdentifier: 'google_veo_key', status: 'Active' } });
      let veoKey = veoKeyRecord?.gatewayKey;
      if (!veoKey) {
        const geminiSetting = await AdminSettings.findOne({ filters: { settingKey: 'gemini_api_key' } });
        veoKey = geminiSetting?.settingValue;
      }

      if (veoKey) {
        const VEO_MODELS = ['veo-3.0-generate-preview', 'veo-3.0-fast-generate-preview', 'veo-2.0-generate-001'];
        for (const model of VEO_MODELS) {
          pipelineLog.push(`⏳ Trying ${model}...`);
          try {
            const res = await fetch(`https://generativelanguage.googleapis.com/v1beta/models/${model}:generateVideos?key=${veoKey}`, {
              method: 'POST',
              headers: { 'Content-Type': 'application/json' },
              body: JSON.stringify({ prompt: safePrompt, aspectRatio: input.aspectRatio, durationSeconds: input.durationSeconds, sampleCount: 1 }),
              signal: AbortSignal.timeout(25000),
            });
            if (res.status === 429 || res.status === 404 || res.status === 400) { pipelineLog[pipelineLog.length - 1] = `⏭ ${model} — Skip (${res.status})`; continue; }
            if (!res.ok) { pipelineLog[pipelineLog.length - 1] = `⏭ ${model} — HTTP ${res.status}`; continue; }
            const data = await res.json() as any;
            if (data.name) {
              await MediaGenerations.create({ record: { userEmail: context.user.email, date: today, type: 'Video', count: 1 } });
              pipelineLog[pipelineLog.length - 1] = `✅ ${model} — Job submitted`;
              return { success: true, routeDecision: route, routeReason: reason, operationId: data.name, engine: model, watermark: WATERMARK, pipelineLog };
            }
            const samples: any[] = data.videos ?? data.generatedSamples ?? [];
            if (samples.length > 0) {
              const vid = samples[0]?.video ?? samples[0];
              if (vid?.uri || vid?.encodedContent) {
                await MediaGenerations.create({ record: { userEmail: context.user.email, date: today, type: 'Video', count: 1 } });
                pipelineLog[pipelineLog.length - 1] = `✅ ${model} — Video ready`;
                return { success: true, routeDecision: route, routeReason: reason, videoUrl: vid.uri, videoBase64: vid.encodedContent, mimeType: vid.mimeType ?? 'video/mp4', engine: model, watermark: WATERMARK, pipelineLog };
              }
            }
            pipelineLog[pipelineLog.length - 1] = `⏭ ${model} — No video`;
          } catch { pipelineLog[pipelineLog.length - 1] = `⏭ ${model} — Error`; }
        }
      } else {
        pipelineLog.push('⚠️ Google Veo key not found — falling back to Stability AI');
      }

      // Stability AI fallback
      const STABILITY_KEY = process.env.ZITE_STABILITY_API_KEY;
      if (STABILITY_KEY) {
        pipelineLog.push('⏳ Trying Stability AI (fallback)...');
        try {
          const res = await fetch('https://api.stability.ai/v2beta/image-to-video', {
            method: 'POST',
            headers: { 'Authorization': 'Bearer ' + STABILITY_KEY, 'Content-Type': 'application/json' },
            body: JSON.stringify({ text_prompts: [{ text: safePrompt, weight: 1 }], cfg_scale: 2.5, motion_bucket_id: 127 }),
            signal: AbortSignal.timeout(25000),
          });
          if (res.ok) {
            const data = await res.json() as any;
            if (data.id) {
              await MediaGenerations.create({ record: { userEmail: context.user.email, date: today, type: 'Video', count: 1 } });
              pipelineLog[pipelineLog.length - 1] = '✅ Stability AI — Job submitted';
              return { success: true, routeDecision: route, routeReason: reason, operationId: `stability:${data.id}`, engine: 'Stability AI v2', watermark: WATERMARK, pipelineLog };
            }
            if (data.video) {
              await MediaGenerations.create({ record: { userEmail: context.user.email, date: today, type: 'Video', count: 1 } });
              pipelineLog[pipelineLog.length - 1] = '✅ Stability AI — Video ready';
              return { success: true, routeDecision: route, routeReason: reason, videoBase64: data.video, mimeType: 'video/mp4', engine: 'Stability AI v2', watermark: WATERMARK, pipelineLog };
            }
          }
          pipelineLog[pipelineLog.length - 1] = `❌ Stability AI — Failed (${res.status})`;
        } catch { pipelineLog[pipelineLog.length - 1] = '❌ Stability AI — Error'; }
      }
    }

    // ROUTE: HUGGINGFACE
    if (route === 'huggingface') {
      const HF_TOKEN = process.env.ZITE_HUGGING_FACE_API_KEY;
      if (!HF_TOKEN) { pipelineLog.push('❌ HuggingFace key not configured'); return { success: false, routeDecision: route, routeReason: reason, engine: 'none', pipelineLog }; }

      const HF_MODELS = [
        { url: 'https://api-inference.huggingface.co/models/ali-vilab/text-to-video-ms-1.7b', label: 'DAMO-ViLab' },
        { url: 'https://api-inference.huggingface.co/models/ByteDance/AnimateDiff-Lightning', label: 'AnimateDiff' },
        { url: 'https://api-inference.huggingface.co/models/camenduru/text2-video-zero', label: 'Text2Video-Zero' },
      ];
      for (const model of HF_MODELS) {
        pipelineLog.push(`⏳ Trying ${model.label}...`);
        try {
          const res = await fetch(model.url, {
            method: 'POST',
            headers: { 'Authorization': `Bearer ${HF_TOKEN}`, 'Content-Type': 'application/json' },
            body: JSON.stringify({ inputs: safePrompt }),
            signal: AbortSignal.timeout(25000),
          });
          if (res.status === 401 || res.status === 403) { pipelineLog[pipelineLog.length - 1] = `❌ ${model.label} — Auth failed`; return { success: false, routeDecision: route, routeReason: reason, engine: 'none', pipelineLog }; }
          if (!res.ok) { pipelineLog[pipelineLog.length - 1] = `⏭ ${model.label} — HTTP ${res.status}`; continue; }

          const ct = res.headers.get('content-type') ?? '';
          if (ct.includes('video') || ct.includes('octet-stream') || ct.includes('image')) {
            const buffer = await res.arrayBuffer();
            const bytes = new Uint8Array(buffer);
            let binary = ''; for (let j = 0; j < bytes.length; j++) binary += String.fromCharCode(bytes[j]);
            const base64 = btoa(binary);
            const mime = ct.includes('video') ? 'video/mp4' : 'image/gif';
            await MediaGenerations.create({ record: { userEmail: context.user.email, date: today, type: 'Video', count: 1 } });
            pipelineLog[pipelineLog.length - 1] = `✅ ${model.label} — Video ready`;
            return { success: true, routeDecision: route, routeReason: reason, videoBase64: base64, mimeType: mime, engine: model.label, watermark: WATERMARK, pipelineLog };
          }

          const text = await res.text();
          if (text.includes('loading') || text.includes('overloaded')) { pipelineLog[pipelineLog.length - 1] = `⏭ ${model.label} — Model loading`; continue; }
          try {
            const data = JSON.parse(text);
            const url = data.url ?? data[0]?.url;
            if (url) {
              await MediaGenerations.create({ record: { userEmail: context.user.email, date: today, type: 'Video', count: 1 } });
              pipelineLog[pipelineLog.length - 1] = `✅ ${model.label} — Video ready`;
              return { success: true, routeDecision: route, routeReason: reason, videoUrl: url, mimeType: 'video/mp4', engine: model.label, watermark: WATERMARK, pipelineLog };
            }
          } catch { /* not json */ }
          pipelineLog[pipelineLog.length - 1] = `⏭ ${model.label} — No video`;
        } catch { pipelineLog[pipelineLog.length - 1] = `⏭ ${model.label} — Error`; continue; }
      }
    }

    pipelineLog.push('❌ All engines exhausted. No video generated.');
    return { success: false, routeDecision: route, routeReason: reason, engine: 'none', pipelineLog };
  },
});

