const KNOWN_FALLBACK_CHAIN = [
  'gemini-2.5-flash',
  'gemini-2.0-flash',
  'gemini-2.5-pro',
  'gemini-1.5-flash',
  'gemini-1.5-pro',
];

const DEPRECATION_SIGNALS = ['not found', 'deprecated', 'decommissioned', 'does not exist', 'not supported'];
function isGone(status: number, body: string): boolean {
  if (status === 404) return true;
  if (status === 400) return DEPRECATION_SIGNALS.some(s => body.toLowerCase().includes(s));
  return false;
}

async function discoverNewModels(apiKey: string): Promise<string[]> {
  try {
    const res = await fetch(`https://generativelanguage.googleapis.com/v1beta/models?pageSize=200&key=${apiKey}`);
    if (!res.ok) return [];
    const data = await res.json() as { models?: { name: string; supportedGenerationMethods?: string[] }[] };
    return (data.models ?? [])
      .filter(m => (m.supportedGenerationMethods ?? []).includes('generateContent'))
      .map(m => m.name.replace('models/', ''))
      .filter(id => id.startsWith('gemini'))
      .sort((a, b) => b.localeCompare(a));
  } catch { return []; }
}

function buildChain(preferred: string, discovered: string[]): string[] {
  const seen = new Set<string>();
  const chain: string[] = [];
  const add = (m: string) => { if (!seen.has(m)) { seen.add(m); chain.push(m); } };
  add(preferred);
  for (const m of KNOWN_FALLBACK_CHAIN) add(m);
  for (const m of discovered) add(m);
  return chain;
}

const VIDEO_SYSTEM = `You are an elite social media video content strategist and scriptwriter. You create viral, algorithm-optimized video content with perfect hooks, retention arcs, and CTAs. Built by Ghulam Hussain Channar.
Always return pure JSON — no markdown, no code blocks, no explanation outside the JSON.`;

export default createEndpoint({
  description: 'Generate complete video scripts — adaptive Gemini gateway with auto-shift',
  authenticated: true,
  inputSchema: z.object({
    concept: z.string().min(5),
    style: z.enum(['educational', 'entertainment', 'promotional', 'shorts', 'vlog', 'tutorial']),
    platform: z.enum(['YouTube', 'TikTok', 'Instagram Reels', 'Facebook']),
  }),
  outputSchema: z.object({
    script: z.string(),
    scenes: z.array(z.object({ title: z.string(), duration: z.string(), description: z.string(), visuals: z.string() })),
    hashtags: z.array(z.string()),
    title: z.string(),
    description: z.string(),
  }),
  execute: async ({ input, context }) => {
    const user = await Users.findOne({ id: context.user.id });
    const isVIPActive =
      user?.vipStatus === 'VIP' &&
      (!user.vipExpiresAt || new Date(user.vipExpiresAt) > new Date());

    if (!isVIPActive) {
      throw new ZiteError({ code: 'FORBIDDEN', message: '🔒 Video Creator is exclusively for VIP members. Upgrade your plan to unlock this feature!' });
    }

    const today = new Date().toISOString().slice(0, 10);
    const [usageRes, videoLimitSetting] = await Promise.all([
      MediaGenerations.findAll({ filters: { userEmail: context.user.email, date: today, type: 'Video' }, limit: 10 }),
      AdminSettings.findOne({ filters: { settingKey: 'vid_limit_vip' } }),
    ]);
    const dailyVideoLimit = parseInt(videoLimitSetting?.settingValue ?? '1') || 1;
    const usedToday = usageRes.records.reduce((s, r) => s + (r.count ?? 0), 0);

    if (usedToday >= dailyVideoLimit) {
      throw new ZiteError({ code: 'RATE_LIMITED', message: `⏰ Daily limit reached! You can generate ${dailyVideoLimit} video${dailyVideoLimit > 1 ? 's' : ''} per day. Come back tomorrow!` });
    }

    const settings = await AdminSettings.findAll({ limit: 200 });
    const geminiKey = settings.records.find(s => s.settingKey === 'gemini_api_key')?.settingValue;
    const sectionModel = settings.records.find(s => s.settingKey === 'gemini_video_model')?.settingValue
      ?? settings.records.find(s => s.settingKey === 'gemini_best_model')?.settingValue
      ?? 'gemini-2.5-flash';

    const fallback = {
      title: `${input.concept} — ${input.style} video`,
      script: `[HOOK]\nStart with a powerful attention-grabbing hook about: ${input.concept}\n\n[INTRO]\nIntroduce the topic.\n\n[MAIN CONTENT]\nExpand on key points...\n\n[CTA]\nLike, Share & Subscribe!\n\n---\nAdd your Gemini API key in Admin Panel for AI-generated scripts.`,
      scenes: [
        { title: 'Opening Hook', duration: '0-5s', description: 'Attention-grabbing opening', visuals: 'Close-up or text animation' },
        { title: 'Intro', duration: '5-15s', description: 'Topic introduction', visuals: 'Face cam or b-roll' },
        { title: 'Main Content', duration: '15-90s', description: 'Core content delivery', visuals: 'Screen recording / graphics' },
        { title: 'CTA + Outro', duration: '90-120s', description: 'Call to action and closing', visuals: 'Subscribe animation' },
      ],
      hashtags: ['#YouTube', '#Viral', '#Trending', '#Content', '#Creator', '#Video', '#Shorts', '#Reels', '#Social', '#Digital'],
      description: `${input.concept} | ${input.style} content for ${input.platform}`,
    };

    // Record usage before generating
    const existingRecord = usageRes.records.find(r => r.date === today);
    if (existingRecord) {
      await MediaGenerations.update({ id: existingRecord.id, record: { count: (existingRecord.count ?? 0) + 1 } });
    } else {
      await MediaGenerations.create({ record: { userEmail: context.user.email, date: today, type: 'Video', count: 1 } });
    }

    if (!geminiKey) return fallback;

    const prompt = `Create a complete ${input.style} video for ${input.platform} about: "${input.concept}"

Return ONLY valid JSON (no markdown, no code blocks):
{
  "title": "Viral video title (max 60 chars)",
  "description": "SEO-optimized description (150 chars)",
  "script": "Full script with clear sections: [HOOK]\\n\\n[INTRO]\\n\\n[MAIN CONTENT]\\n\\n[CTA]\\n\\n[OUTRO]",
  "scenes": [
    {"title": "Scene name", "duration": "0-5s", "description": "What happens", "visuals": "Camera/visual description"}
  ],
  "hashtags": ["#hashtag1", ... exactly 18 viral hashtags]
}`;

    const body = {
      systemInstruction: { parts: [{ text: VIDEO_SYSTEM }] },
      contents: [{ role: 'user', parts: [{ text: prompt }] }],
      generationConfig: { maxOutputTokens: 3000, temperature: 0.8 },
    };

    // ── Adaptive auto-shift ────────────────────────────────────────
    const discovered = await discoverNewModels(geminiKey);
    const chain = buildChain(sectionModel, discovered);

    for (const model of chain) {
      try {
        const res = await fetch(
          `https://generativelanguage.googleapis.com/v1beta/models/${model}:generateContent?key=${geminiKey}`,
          { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify(body) }
        );
        if (res.status === 429 || res.status === 503) continue;
        if (!res.ok) {
          const errText = await res.text().catch(() => '');
          if (isGone(res.status, errText)) { console.log(`[Video] Model "${model}" gone, auto-shifting...`); continue; }
          continue;
        }
        const data = await res.json() as { candidates?: { content?: { parts?: { text?: string }[] } }[] };
        const raw = data.candidates?.[0]?.content?.parts?.[0]?.text ?? '';

        try {
          const parsed = JSON.parse(raw.replace(/```json|```/g, '').trim());
          return {
            title: parsed.title ?? fallback.title,
            script: parsed.script ?? fallback.script,
            scenes: Array.isArray(parsed.scenes) ? parsed.scenes : fallback.scenes,
            hashtags: Array.isArray(parsed.hashtags) ? parsed.hashtags : fallback.hashtags,
            description: parsed.description ?? fallback.description,
          };
        } catch {
          return { ...fallback, script: raw || fallback.script };
        }
      } catch { continue; }
    }

    return fallback;
  },
});

import { z } from 'zod';
import { createEndpoint, Users } from 'zite-integrations-backend-sdk';

export default createEndpoint({
  description: 'Increment wrongPromptCount for the user. On 4th wrong prompt, auto-block.',
  authenticated: true,
  inputSchema: z.object({}),
  outputSchema: z.object({
    wrongPromptCount: z.number(),
    blocked: z.boolean(),
