  }),
  execute: async ({ context }) => {
    const u = await Users.findOne({ id: context.user.id, fields: ['wrongPromptCount', 'status'] });
    if (!u) return { wrongPromptCount: 0, blocked: false, warning: false };

    // Already blocked
    if (u.status === 'Blocked') return { wrongPromptCount: u.wrongPromptCount ?? 0, blocked: true, warning: false };

    const newCount = (u.wrongPromptCount ?? 0) + 1;

    if (newCount >= 4) {
      // Auto-block on 4th wrong prompt
      await Users.update({ id: context.user.id, record: { wrongPromptCount: newCount, status: 'Blocked' } });
      return { wrongPromptCount: newCount, blocked: true, warning: false };
    }

    await Users.update({ id: context.user.id, record: { wrongPromptCount: newCount } });
    return {
      wrongPromptCount: newCount,
      blocked: false,
      warning: newCount === 3,
    };
  },
});

import { z } from 'zod';
import { createEndpoint, SocialLinksConfig, AdminSettings } from 'zite-integrations-backend-sdk';

export default createEndpoint({
  description: 'Isolated CRUD for Social Links Config table — zero touching of any other table',
  inputSchema: z.object({
    action: z.enum(['get', 'save']),
    adminToken: z.string().optional(),
    links: z.array(z.object({
      id: z.string().optional(),
      platformName: z.string(),
      urlLink: z.string(),
      isActive: z.boolean(),
    })).optional(),
  }),
  outputSchema: z.object({
    success: z.boolean(),
    links: z.array(z.object({
      id: z.string(),
      platformName: z.string(),
      urlLink: z.string(),
      isActive: z.boolean(),
    })),
  }),
  execute: async ({ input }) => {
    // GET — public read (floating bar needs this without admin auth)
    if (input.action === 'get') {
      const { records } = await SocialLinksConfig.findAll({});
      // Auto-seed defaults if table is empty
      if (records.length === 0) {
        const defaults = [
          { platformName: 'YouTube', urlLink: '', isActive: false },
          { platformName: 'Facebook', urlLink: '', isActive: false },
          { platformName: 'TikTok', urlLink: '', isActive: false },
        ];
        const { records: created } = await SocialLinksConfig.bulkCreate({ records: defaults });
        return {
          success: true,
          links: created.map(r => ({
            id: r.id,
            platformName: r.fields.platformName ?? '',
            urlLink: r.fields.urlLink ?? '',
            isActive: r.fields.isActive ?? false,
          })),
        };
      }
      return {
        success: true,
        links: records.map(r => ({
          id: r.id,
          platformName: r.platformName ?? '',
          urlLink: r.urlLink ?? '',
          isActive: r.isActive ?? false,
        })),
      };
    }

    // SAVE — admin-only write
    if (input.action === 'save') {
      // Verify admin token
      const pwdRec = await AdminSettings.findOne({ filters: { settingKey: 'admin_password' } });
      const expected = pwdRec?.settingValue ?? 'admin@2024';
      if (input.adminToken !== expected) {
        return { success: false, links: [] };
      }

      const incoming = input.links ?? [];
      for (const link of incoming) {
        if (link.id) {
          await SocialLinksConfig.update({
            id: link.id,
            record: {
              platformName: link.platformName,
              urlLink: link.urlLink,
              isActive: link.isActive,
            },
          });
        } else {
          await SocialLinksConfig.create({
            record: {
              platformName: link.platformName,
              urlLink: link.urlLink,
              isActive: link.isActive,
            },
          });
        }
      }

      const { records } = await SocialLinksConfig.findAll({});
      return {
        success: true,
        links: records.map(r => ({
          id: r.id,
          platformName: r.platformName ?? '',
          urlLink: r.urlLink ?? '',
          isActive: r.isActive ?? false,
        })),
      };
    }

    return { success: false, links: [] };
  },
});

