import { z } from 'zod';
import { createEndpoint, AdminSettings, ZiteError } from 'zite-integrations-backend-sdk';

// ══════════════════════════════════════════════════════════════════
// GEMINI KEY VALIDATOR v7.0 — ADAPTIVE FUTURE-PROOF GATEWAY
// Never throws 500 on model string changes. Discovers new models
// dynamically and assigns per-section routing from whatever is live.
// ══════════════════════════════════════════════════════════════════

const TIER_MAP = [
  { model: 'gemini-2.5-pro',       tier: 'Ultra',      tierLevel: 5, label: 'Gemini 2.5 Pro'     },
  { model: 'gemini-2.5-flash',     tier: 'Premium',    tierLevel: 4, label: 'Gemini 2.5 Flash'   },
  { model: 'gemini-2.0-flash',     tier: 'Standard',   tierLevel: 2, label: 'Gemini 2.0 Flash'   },
  { model: 'gemini-1.5-pro',       tier: 'Standard+',  tierLevel: 3, label: 'Gemini 1.5 Pro'     },
  { model: 'gemini-1.5-pro-002',   tier: 'Standard+',  tierLevel: 3, label: 'Gemini 1.5 Pro'     },
  { model: 'gemini-1.5-flash',     tier: 'Standard',   tierLevel: 2, label: 'Gemini 1.5 Flash'   },
  { model: 'gemini-1.5-flash-002', tier: 'Standard',   tierLevel: 2, label: 'Gemini 1.5 Flash'   },
  { model: 'gemini-1.0-pro',       tier: 'Basic',      tierLevel: 1, label: 'Gemini 1.0 Pro'     },
];

// Models to live-test in priority order
const LIVE_TEST_ORDER = [
  'gemini-2.5-flash',
  'gemini-2.5-pro',
  'gemini-2.0-flash',
  'gemini-1.5-flash',
  'gemini-1.5-pro',
  'gemini-1.5-flash-002',
  'gemini-1.5-pro-002',
  'gemini-1.0-pro',
];

function pickSectionModels(available: string[], confirmed: string) {
  const has = (m: string) => available.includes(m);

  // SPIRITUAL: locked to 2.5-flash, fallback to pro then older
  const spiritualModel =
    has('gemini-2.5-flash') ? 'gemini-2.5-flash'  :
    has('gemini-2.5-pro')   ? 'gemini-2.5-pro'    :
    has('gemini-2.0-flash') ? 'gemini-2.0-flash'  :
    has('gemini-1.5-pro')   ? 'gemini-1.5-pro'    :
    has('gemini-1.5-flash') ? 'gemini-1.5-flash'  :
    confirmed;

  // GENERAL/MAIN CHAT: locked to 2.5-flash for speed
  const generalModel =
    has('gemini-2.5-flash') ? 'gemini-2.5-flash'  :
    has('gemini-2.0-flash') ? 'gemini-2.0-flash'  :
    has('gemini-1.5-flash') ? 'gemini-1.5-flash'  :
    has('gemini-2.5-pro')   ? 'gemini-2.5-pro'    :
    has('gemini-1.5-pro')   ? 'gemini-1.5-pro'    :
    confirmed;

  // CODING: locked to 1.5-pro (3.5 series), fallback to 2.5-pro
  const codingModel =
    has('gemini-1.5-pro')   ? 'gemini-1.5-pro'    :
    has('gemini-1.5-pro-002') ? 'gemini-1.5-pro-002' :
    has('gemini-2.5-pro')   ? 'gemini-2.5-pro'    :
    has('gemini-2.5-flash') ? 'gemini-2.5-flash'  :
    confirmed;

  // VIDEO SCRIPTS: creativity + structured output
  const videoModel =
    has('gemini-2.5-flash') ? 'gemini-2.5-flash'  :
    has('gemini-2.5-pro')   ? 'gemini-2.5-pro'    :
    has('gemini-2.0-flash') ? 'gemini-2.0-flash'  :
    has('gemini-1.5-pro')   ? 'gemini-1.5-pro'    :
    has('gemini-1.5-flash') ? 'gemini-1.5-flash'  :
    confirmed;

  // FAST (hashtags/image prompts): pure speed
  const fastModel =
    has('gemini-2.0-flash') ? 'gemini-2.0-flash'  :
    has('gemini-1.5-flash') ? 'gemini-1.5-flash'  :
    has('gemini-2.5-flash') ? 'gemini-2.5-flash'  :
    confirmed;

  return { spiritualModel, generalModel, codingModel, videoModel, fastModel };
}

async function upsertSetting(
  records: { id: string; settingKey?: string; settingValue?: string }[],
  key: string, value: string,
) {
  const existing = records.find(s => s.settingKey === key);
  if (existing) {
    await AdminSettings.update({ id: existing.id, record: { settingValue: value } });
  } else {
    await AdminSettings.create({ record: { settingKey: key, settingValue: value } });
  }
}

async function liveTest(key: string, model: string): Promise<boolean> {
  try {
    const res = await fetch(
      `https://generativelanguage.googleapis.com/v1beta/models/${model}:generateContent?key=${key}`,
      {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          contents: [{ role: 'user', parts: [{ text: 'ACTIVE' }] }],
          generationConfig: { maxOutputTokens: 3, temperature: 0 },
        }),
      }
    );
    return res.ok;
  } catch { return false; }
}

export default createEndpoint({
  description: 'Validate Gemini API key — adaptive future-proof discovery, never throws 500 on model deprecation',
  inputSchema: z.object({ apiKey: z.string().min(1), adminToken: z.string() }),
  outputSchema: z.object({
    valid: z.boolean(),
    tier: z.string().optional(),
    tierLevel: z.number().optional(),
    bestModel: z.string().optional(),
    bestModelLabel: z.string().optional(),
    availableModels: z.array(z.string()).optional(),
    sectionModels: z.object({
      spiritual: z.string(), general: z.string(), coding: z.string(), video: z.string(), fast: z.string(),
    }).optional(),
    error: z.string().optional(),
  }),
  execute: async ({ input }) => {
    // ── Auth check ─────────────────────────────────────────────────
    const allSettings = await AdminSettings.findAll({ limit: 200 });
    const records = allSettings.records;
    const storedPwd = records.find(s => s.settingKey === 'admin_password')?.settingValue ?? 'admin@2024';
    if (input.adminToken !== storedPwd) throw new ZiteError({ code: 'UNAUTHORIZED', message: 'Invalid admin token' });

    const key = input.apiKey.trim();

    // ── Step 1: Discover ALL models on this key (future-proof) ─────
    let discoveredModelIds: string[] = [];
    try {
      const listRes = await fetch(
        `https://generativelanguage.googleapis.com/v1beta/models?pageSize=200&key=${key}`
      );
      if (listRes.status === 400 || listRes.status === 401 || listRes.status === 403) {
        const body = await listRes.json().catch(() => ({})) as any;
        return { valid: false, error: `API key rejected: ${body?.error?.message ?? listRes.status}` };
      }
      if (listRes.ok) {
        const listData = await listRes.json() as { models?: { name: string; supportedGenerationMethods?: string[] }[] };
        discoveredModelIds = (listData.models ?? [])
          .filter(m => (m.supportedGenerationMethods ?? []).includes('generateContent'))
          .map(m => m.name.replace('models/', ''))
          .filter(id => id.startsWith('gemini'));
      }
    } catch {
      // Network error — continue to live testing
    }

    // ── Step 2: Build combined test list (known + discovered) ──────
    const allCandidates = [...new Set([...LIVE_TEST_ORDER, ...discoveredModelIds])];

    // ── Step 3: Live-test models ───────────────────────────────────
    let confirmedModel = '';
    for (const modelId of allCandidates) {
      const ok = await liveTest(key, modelId);
      if (ok) { confirmedModel = modelId; break; }
    }

    if (!confirmedModel) {
      return {
        valid: false,
        error: 'API key is valid but no Gemini model responds. Enable the Gemini API in Google Cloud Console.',
      };
    }

    // ── Step 4: Resolve tier metadata ─────────────────────────────
    const tierEntry = TIER_MAP.find(e => e.model === confirmedModel) ?? {
      model: confirmedModel, tier: 'Next-Gen', tierLevel: 6, label: confirmedModel,
    };

    // Build available list from live-testable + discovered
    const knownAvailable = [...new Set([...discoveredModelIds, confirmedModel])]
      .filter(id => id.startsWith('gemini'));

    // ── Step 5: Pick per-section models ────────────────────────────
    const { spiritualModel, generalModel, codingModel, videoModel, fastModel } = pickSectionModels(knownAvailable, confirmedModel);

    // ── Step 6: Persist ────────────────────────────────────────────
    await upsertSetting(records, 'gemini_api_key',           key);
    await upsertSetting(records, 'gemini_tier',              tierEntry.tier);
    await upsertSetting(records, 'gemini_tier_level',        String(tierEntry.tierLevel));
    await upsertSetting(records, 'gemini_best_model',        confirmedModel);
    await upsertSetting(records, 'gemini_best_model_label',  tierEntry.label);
    await upsertSetting(records, 'gemini_spiritual_model',   spiritualModel);
    await upsertSetting(records, 'gemini_general_model',     generalModel);
    await upsertSetting(records, 'gemini_coding_model',      codingModel);
    await upsertSetting(records, 'gemini_tasks_model',       generalModel);
    await upsertSetting(records, 'gemini_video_model',       videoModel);
    await upsertSetting(records, 'gemini_fast_model',        fastModel);

    return {
      valid: true,
      tier: tierEntry.tier,
      tierLevel: tierEntry.tierLevel,
      bestModel: confirmedModel,
      bestModelLabel: tierEntry.label,
      availableModels: knownAvailable,
      sectionModels: { spiritual: spiritualModel, general: generalModel, coding: codingModel, video: videoModel, fast: fastModel },
    };
  },
});

