import { z } from 'zod';
import { createEndpoint, AdminSettings, ZiteError } from 'zite-integrations-backend-sdk';

const API_BASE = 'https://generativelanguage.googleapis.com/v1beta';

type PollResult = {
  operationId: string;
  status: 'pending' | 'processing' | 'complete' | 'failed';
  progressPercent?: number;
  videoUrl?: string;
  videoBase64?: string;
  mimeType?: string;
  error?: string;
};

// ─── Extract video from all known Veo response shapes ─────────────────────
function extractVideoFromResponse(resp: Record<string, any>): { videoUrl?: string; videoBase64?: string; mimeType: string } | null {
  let videoUrl: string | undefined;
  let videoBase64: string | undefined;
  let mimeType = 'video/mp4';

  // Shape A: resp.generateVideoResponse.generatedSamples[].video  (LRO done)
  const samples: any[] =
    resp.generateVideoResponse?.generatedSamples ??
    resp.generatedSamples ??
    resp.videos ??
    [];

  if (samples.length > 0) {
    const vid = samples[0]?.video ?? samples[0];
    videoUrl    = vid?.uri ?? vid?.url ?? vid?.fileUri ?? undefined;
    videoBase64 = vid?.encodedContent ?? vid?.data ?? undefined;
    mimeType    = vid?.mimeType ?? 'video/mp4';
  }

  // Shape B: Gemini-style candidates[].content.parts[].inlineData
  if (!videoUrl && !videoBase64) {
    const parts: any[] = resp.candidates?.[0]?.content?.parts ?? [];
    for (const part of parts) {
      if (part?.inlineData?.mimeType?.startsWith('video/')) {
        videoBase64 = part.inlineData.data;
        mimeType    = part.inlineData.mimeType;
        break;
      }
      if (part?.fileData?.fileUri) {
        videoUrl = part.fileData.fileUri;
        break;
      }
    }
  }

  // Shape C: top-level videoUri / uri
  if (!videoUrl && !videoBase64) {
    videoUrl = resp.videoUri ?? resp.uri ?? undefined;
  }

  if (videoUrl || videoBase64) return { videoUrl, videoBase64, mimeType };
  return null;
}

// ─── Poll a single Veo LRO ────────────────────────────────────────────────
async function pollVeoOperation(operationId: string, geminiKey: string): Promise<PollResult> {

  // ── Special case: inline result from generateVideo (no polling needed) ──
  if (operationId.startsWith('ready:')) {
    return { operationId, status: 'complete' };
  }

  // Normalise to the full path the API expects
  const opPath = operationId.startsWith('operations/')
    ? operationId
    : `operations/${operationId}`;

  // The Gemini Developer API exposes LRO status at two paths — try both
  const pollUrls = [
    `${API_BASE}/${opPath}?key=${geminiKey}`,                    // Standard path
    `https://generativelanguage.googleapis.com/v1/${opPath}?key=${geminiKey}`, // v1 fallback
  ];

  for (const url of pollUrls) {
    let res: Response;
    try {
      res = await fetch(url, { method: 'GET', headers: { 'Content-Type': 'application/json' } });
    } catch (e: any) {
      console.log(`[VeoPoll] Network error ${url}: ${String(e)}`);
      continue;
    }

    const text = await res.text();
    console.log(`[VeoPoll] ${opPath} → HTTP ${res.status}: ${text.substring(0, 300)}`);

    if (res.status === 404) {
      return { operationId, status: 'failed', error: 'Operation not found — may have expired or key changed' };
    }
    if (!res.ok) continue; // try next URL

    let data: Record<string, any>;
    try { data = JSON.parse(text); } catch {
      return { operationId, status: 'failed', error: 'Invalid JSON from poll endpoint' };
    }

    // ── Explicit error ─────────────────────────────────────────────────────
    if (data.error) {
      const msg = data.error?.message ?? JSON.stringify(data.error);
      console.log(`[VeoPoll] Error response: ${msg}`);
      return { operationId, status: 'failed', error: msg };
    }

    // ── Still processing ───────────────────────────────────────────────────
    if (!data.done) {
      const progress: number =
        data.metadata?.progressPercent ??
        data.metadata?.videoGenerationProgress?.progressPercent ??
        (data.metadata ? 25 : 10);
      return { operationId, status: 'processing', progressPercent: progress };
    }

    // ── Done — extract video ───────────────────────────────────────────────
    const resp: Record<string, any> = data.response ?? data;
    const video = extractVideoFromResponse(resp);

    if (video) {
      return {
        operationId,
        status: 'complete',
        videoUrl:    video.videoUrl,
        videoBase64: video.videoBase64,
        mimeType:    video.mimeType,
      };
    }

    console.log(`[VeoPoll] done=true but no video data found in response: ${text.substring(0, 200)}`);
    return { operationId, status: 'failed', error: 'Operation done but no video data returned — may need Veo API access enabled' };
  }

  return { operationId, status: 'failed', error: 'All poll URLs failed' };
}

// ═══════════════════════════════════════════════════════════════════════════
// ENDPOINT
// ═══════════════════════════════════════════════════════════════════════════
export default createEndpoint({
  description: 'Poll Veo LRO operation status — called every 6s from frontend until allComplete',
  authenticated: true,

  inputSchema: z.object({
    operationIds: z.array(z.string()).min(1).max(12),
  }),

  outputSchema: z.object({
    results: z.array(z.object({
      operationId:     z.string(),
      status:          z.enum(['pending', 'processing', 'complete', 'failed']),
      progressPercent: z.number().optional(),
      videoUrl:        z.string().optional(),
      videoBase64:     z.string().optional(),
      mimeType:        z.string().optional(),
      error:           z.string().optional(),
    })),
    allComplete:            z.boolean(),
    anyFailed:              z.boolean(),
    completedCount:         z.number(),
    processingCount:        z.number(),
    overallProgressPercent: z.number(),
  }),

  execute: async ({ input }) => {
    const settings = await AdminSettings.findAll({ limit: 100 });
    const geminiKey = settings.records.find(s => s.settingKey === 'gemini_api_key')?.settingValue;
    if (!geminiKey) throw new ZiteError('No Gemini API key configured.');

    const results = await Promise.all(
      input.operationIds.map(opId => pollVeoOperation(opId, geminiKey)),
    );

    const completedCount  = results.filter(r => r.status === 'complete').length;
    const failedCount     = results.filter(r => r.status === 'failed').length;
    const processingCount = results.filter(r => r.status === 'processing').length;
    const total           = results.length;

    const avgProgress =
      results.reduce((sum, r) =>
        sum + (r.progressPercent ?? (r.status === 'complete' ? 100 : r.status === 'failed' ? 0 : 15)), 0,
      ) / total;

    return {
      results,
      allComplete:            completedCount + failedCount === total,
      anyFailed:              failedCount > 0,
      completedCount,
      processingCount,
      overallProgressPercent: Math.round(avgProgress),
    };
  },
});

import { useAppData } from '@/contexts/AppDataContext';

const SEGMENT_STYLES = [
  { text: 'text-yellow-400',  dot: '⚡' },
  { text: 'text-emerald-400', dot: '🌟' },
  { text: 'text-sky-400',     dot: '💧' },
  { text: 'text-violet-400',  dot: '🔮' },
  { text: 'text-pink-400',    dot: '🌸' },
  { text: 'text-orange-400',  dot: '🔥' },
  { text: 'text-teal-400',    dot: '💎' },
  { text: 'text-rose-400',    dot: '❤️' },
];

// speed 1 (fastest=8s) → speed 10 (slowest=78s)
const speedToDuration = (speed: number) => 8 + (speed - 1) * 7.7;

export default function NewsTicker() {
  const { tickers, tickerEnabled, tickerColorPreset, tickerSpeed } = useAppData();

  if (!tickerEnabled || !tickers.length) return null;

  const bgStyle: React.CSSProperties =
    tickerColorPreset && tickerColorPreset !== 'gradient'
      ? { background: tickerColorPreset }
      : {
          background:
            'linear-gradient(90deg, hsl(var(--primary)/0.06) 0%, hsl(var(--secondary)/0.08) 35%, hsl(var(--primary)/0.06) 70%, hsl(var(--secondary)/0.06) 100%)',
        };

  // Admin-controlled speed (1–10) overrides auto-calculated duration
  const duration = Math.round(speedToDuration(tickerSpeed ?? 5));

  const buildItems = (pass: number) =>
    tickers.map((t, i) => {
      const style = SEGMENT_STYLES[(i + pass) % SEGMENT_STYLES.length];
      return (
        <span key={`t${pass}-${t.id}-${i}`} className="inline-flex items-center flex-shrink-0 px-1">
          <span className={`${style.text} font-bold`}>{style.dot}&nbsp;{t.content}</span>
          <span className="text-muted-foreground/30 mx-5">◆◆◆</span>
        </span>
      );
    });

  return (
    <div
      className="border-b border-border h-8 flex items-center relative select-none shrink-0"
      style={{ ...bgStyle, overflow: 'hidden' }}
      aria-label="News ticker"
    >
      <div
        className="ticker-infinite text-xs font-semibold"
        style={{ '--ticker-dur': `${duration}s` } as React.CSSProperties}
      >
        {buildItems(0)}
        {buildItems(1)}
        {buildItems(2)}
        {buildItems(3)}
      </div>
    </div>
  );
}

