export default function SocialShare({ open, onClose, referralCode }: Props) {
  const { aiName } = useAppData();
  const [copied, setCopied] = useState(false);

  const appName = aiName || 'Hussain AI - Master Engine';

  // ── SECURITY: Only clean origin + referral param. Never include:
  //   - current path (could expose /admin)
  //   - search params (could leak session/token data)
  //   - hash fragments
  //   - any sessionStorage / localStorage values
  const cleanOrigin = window.location.origin; // app origin — NO path
  // Referral code is purely alphanumeric (safe to embed)
  const safeRef = referralCode ? referralCode.replace(/[^a-zA-Z0-9_-]/g, '') : '';
  const shareUrl = safeRef ? `${cleanOrigin}?ref=${safeRef}` : cleanOrigin;

  const shareMsg = `🚀 ${appName} — AI tools + Real Earning! Join now:`;
  const fullMsg = `${shareMsg} ${shareUrl}`;

  const copyLink = () => {
    navigator.clipboard.writeText(shareUrl).then(() => {
      setCopied(true);
      toast.success('✅ Link copied!');
      setTimeout(() => setCopied(false), 2500);
    });
  };

  const openShare = (url: string) => window.open(url, '_blank', 'noopener,noreferrer');

  const whatsapp = () => openShare(`https://wa.me/?text=${encodeURIComponent(fullMsg)}`);
  const facebook = () => openShare(`https://www.facebook.com/sharer/sharer.php?u=${encodeURIComponent(shareUrl)}&quote=${encodeURIComponent(shareMsg)}`);
  const twitter  = () => openShare(`https://twitter.com/intent/tweet?text=${encodeURIComponent(shareMsg)}&url=${encodeURIComponent(shareUrl)}`);
  const telegram = () => openShare(`https://t.me/share/url?url=${encodeURIComponent(shareUrl)}&text=${encodeURIComponent(shareMsg)}`);

  const nativeShare = () => {
    if (navigator.share) {
      navigator.share({ title: appName, text: shareMsg, url: shareUrl }).catch(() => {});
    } else {
      copyLink();
    }
  };

  return (
    <Dialog open={open} onOpenChange={v => !v && onClose()}>
      <DialogContent className="bg-card/98 backdrop-blur border-border max-w-[280px] p-4 gap-3 rounded-2xl shadow-2xl">
        {/* Header */}
        <div className="flex items-center justify-between pb-2 border-b border-border/50">
          <p className="text-sm font-black text-foreground">Share & Earn</p>
          <button onClick={onClose} className="text-muted-foreground hover:text-foreground p-1 rounded-lg hover:bg-muted transition-colors">
            <X size={14} />
          </button>
        </div>

        {/* Referral Link */}
        <div className="bg-gradient-to-br from-primary/10 to-secondary/10 border border-primary/20 rounded-xl p-2.5 space-y-0.5">
          <p className="text-[10px] font-bold text-primary truncate">{appName}</p>
          <p className="text-[9px] font-mono text-muted-foreground/80 truncate">{shareUrl}</p>
        </div>

        {/* Share Grid */}
        <div className="grid grid-cols-4 gap-1.5">
          <ShareBtn icon="💬" label="WhatsApp" onClick={whatsapp} />
          <ShareBtn icon="📘" label="Facebook" onClick={facebook} />
          <ShareBtn icon="🐦" label="Twitter" onClick={twitter} />
          <ShareBtn icon="✈️" label="Telegram" onClick={telegram} />
        </div>

        {/* Native Share */}
        <button onClick={nativeShare}
          className="w-full bg-primary text-primary-foreground font-bold text-xs py-2 rounded-xl hover:bg-primary/90 transition-colors">
          📤 Share via Apps
        </button>

        {/* Copy Link */}
        <div className="flex gap-1.5">
          <div className="flex-1 bg-muted border border-border rounded-lg px-2 py-1.5 overflow-hidden">
            <p className="text-[9px] font-mono text-muted-foreground truncate">{shareUrl}</p>
          </div>
          <button onClick={copyLink}
            className="flex items-center gap-1 bg-muted border border-border hover:border-primary/40 rounded-lg px-2 py-1.5 text-[9px] font-bold transition-colors shrink-0">
            {copied ? <><Check size={10} className="text-primary" /> ✓</> : <><Copy size={10} /> Copy</>}
