import { z } from 'zod';
import { createEndpoint, VideoApiKeys, AdminSettings, ZiteError } from 'zite-integrations-backend-sdk';

export default createEndpoint({
  description: 'Save Universal AI Gateway config to an existing Video API Keys row (or the first gateway row)',
  inputSchema: z.object({
    adminToken: z.string(),
    targetKeyIdentifier: z.string().default('huggingface_api_key'),
    universalApiKey: z.string().optional(),
    modelEndpointUrl: z.string().optional(),
    payloadMappingJson: z.string().optional(),
  }),
  outputSchema: z.object({
    success: z.boolean(),
    message: z.string(),
  }),
  execute: async ({ input }) => {
    const pwdRow = await AdminSettings.findOne({ filters: { settingKey: 'admin_password' } });
    const pwd = pwdRow?.settingValue ?? 'admin@2024';
    if (input.adminToken !== pwd) {
      throw new ZiteError({ code: 'UNAUTHORIZED', message: 'Invalid admin token' });
    }

    // Validate JSON if provided
    if (input.payloadMappingJson && input.payloadMappingJson.trim()) {
      try {
        JSON.parse(input.payloadMappingJson);
      } catch {
        throw new ZiteError({ code: 'BAD_REQUEST', message: 'Payload Mapping JSON is not valid JSON' });
      }
    }

    // Find the target gateway row
    let row = await VideoApiKeys.findOne({ filters: { keyIdentifier: input.targetKeyIdentifier } });

    // If not found, try any row
    if (!row) {
      const { records } = await VideoApiKeys.findAll({ limit: 1 });
      row = records[0];
    }

    const updateData: Record<string, any> = {};
    if (input.universalApiKey !== undefined) updateData.universalApiKey = input.universalApiKey;
    if (input.modelEndpointUrl !== undefined) updateData.modelEndpointUrl = input.modelEndpointUrl;
    if (input.payloadMappingJson !== undefined) updateData.payloadMappingJson = input.payloadMappingJson;

    if (row) {
      await VideoApiKeys.update({ id: row.id, record: updateData });
    } else {
      // Create a new row for the universal gateway
      await VideoApiKeys.create({
        record: {
          gatewayName: 'Universal AI Gateway',
          keyIdentifier: 'universal_gateway',
          status: 'Active',
          priorityOrder: 0,
          ...updateData,
        },
      });
    }

    return { success: true, message: '✅ Universal AI Gateway config saved! Self-healing engine is active.' };
  },
});

