  return (
    <>
      <button onClick={() => setOpen(true)}
        className="flex items-center gap-1 text-[9px] text-secondary border border-secondary/30 bg-secondary/10 px-2 py-0.5 rounded-md hover:bg-secondary/20 transition-colors">
        Preview
