// ── Mic Hook ──────────────────────────────────────────────────────
// ── Clean STT output: strip *, #, ~, stray symbols ──────────────
const cleanStt = (text: string): string =>
  text.replace(/[*#~_`^\\|<>{}[\]]/g, '').replace(/\s{2,}/g, ' ').trim();

function useMic(defaultLang: string) {
  const [listening, setListening] = useState(false);
  const [lang, setLang] = useState(defaultLang);
  const rRef = useRef<any>(null);

  const start = useCallback((onResult: (text: string) => void) => {
    const SR = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (!SR) { toast.error('Voice input not supported. Use Chrome browser.'); return; }
    if (listening) { rRef.current?.stop(); return; }
    const r = new SR();
    // language: "auto" — do NOT set r.lang so the browser auto-detects
    // the spoken language dynamically (Urdu, Punjabi, Saraiki, Sindhi, Hindi, English, etc.)
    r.continuous = true; r.interimResults = false; r.maxAlternatives = 1;
    r.onresult = (e: any) => {
      const raw = e.results[e.results.length - 1][0].transcript;
      const cleaned = cleanStt(raw);
      if (cleaned) onResult(cleaned);
    };
    r.onerror = (e: any) => {
      if (e.error !== 'aborted') {
        const msgs: Record<string, string> = {
          'no-speech': 'No speech detected. Speak clearly and try again.',
          'not-allowed': 'Mic blocked! Allow microphone access in browser settings.',
          'audio-capture': 'Microphone not found.',
          'network': 'Network error. Check connection.',
        };
        toast.error(msgs[e.error] ?? `Mic error: ${e.error}`);
      }
      setListening(false);
    };
    r.onend = () => setListening(false);
    rRef.current = r;
    try { r.start(); setListening(true); } catch { toast.error('Could not start microphone.'); }
  }, [listening]);

  const stop = useCallback(() => { rRef.current?.stop(); setListening(false); }, []);
  return { listening, lang, setLang, start, stop };
}

// ── Mobile-Optimized Copy Button ─────────────────────────────────
function CopyBtn({ text, className, mobile }: { text: string; className?: string; mobile?: boolean }) {
  const [copied, setCopied] = useState(false);
  const handleCopy = () => {
    navigator.clipboard.writeText(text).catch(() => {
      // Fallback for Android WebView
      const ta = document.createElement('textarea');
      ta.value = text; ta.style.position = 'fixed'; ta.style.opacity = '0';
      document.body.appendChild(ta); ta.focus(); ta.select();
      document.execCommand('copy'); document.body.removeChild(ta);
    });
    setCopied(true); setTimeout(() => setCopied(false), 2000);
    toast.success('📋 Copied!');
  };
  if (mobile) {
    return (
      <button onClick={handleCopy}
        className={cn(
          'flex items-center gap-2 text-xs font-bold rounded-xl border transition-all active:scale-95',
          'min-h-[40px] px-4 py-2',
          copied
            ? 'bg-primary/20 text-primary border-primary/40'
            : 'bg-muted/60 text-foreground border-border hover:bg-primary/10 hover:border-primary/30',
          className
        )}>
        {copied ? <Check size={14} className="text-primary" /> : <Copy size={14} />}
        {copied ? 'Copied!' : 'Copy Code'}
      </button>
    );
  }
  return (
    <button onClick={handleCopy}
      className={cn('p-1 rounded text-muted-foreground hover:text-foreground transition-colors', className)}>
      {copied ? <Check size={11} className="text-primary" /> : <Copy size={11} />}
    </button>
  );
}

