export default function PaymentModal({ open, onClose, planId, planName, priceUsd, usdToPkr, paymentInfo, usdBalance = 0, onSuccess }: Props) {
  const [step, setStep] = useState<'method' | 'proof'>('method');
  const [method, setMethod] = useState('');
  const [tid, setTid] = useState('');
  const [address, setAddress] = useState('');
  const [screenshot, setScreenshot] = useState<File | null>(null);
  const [uploading, setUploading] = useState(false);
  const [loading, setLoading] = useState(false);
  const fileRef = useRef<HTMLInputElement>(null);

  const methodInfo = METHODS.find(m => m.id === method);
  const infoKey = methodInfo?.infoKey ?? '';

  const paymentDetails: { label: string; value: string; copyable: boolean }[] = infoKey ? [
    { label: 'Account Number / Address', value: paymentInfo[`${infoKey}_number`] || paymentInfo[`${infoKey}_address`] || '', copyable: true },
    { label: 'Account Name', value: paymentInfo[`${infoKey}_name`] || '', copyable: false },
    { label: 'Bank Name', value: paymentInfo[`${infoKey}_bank`] || '', copyable: false },
  ].filter(d => d.value) : [];

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) setScreenshot(file);
  };

  const handleSubmit = async () => {
    if (!screenshot && method !== 'App Wallet') { toast.error('Please upload payment screenshot'); return; }
    if (!tid.trim() && method !== 'App Wallet') { toast.error('Enter TID / Transaction Hash'); return; }
    if (!address.trim() && method !== 'App Wallet') { toast.error('Enter your sending number/address'); return; }
    if (method === 'App Wallet' && usdBalance < priceUsd) { toast.error(`Insufficient wallet balance. Need $${priceUsd}`); return; }

    setLoading(true);
    try {
      let screenshotUrl = 'app_wallet_payment';
      if (screenshot) {
        setUploading(true);
        const { fileUrl } = await uploadFile({ data: screenshot, filename: screenshot.name });
        screenshotUrl = fileUrl;
        setUploading(false);
      }
      await submitVIPPurchase({ planId, paymentMethod: method, tidOrHash: tid.trim() || 'APP_WALLET', sendingAddress: address.trim() || 'APP_WALLET', screenshotUrl });
      toast.success('✅ VIP request submitted! Admin will verify within 24hrs.');
      onSuccess();
      onClose();
    } catch (err: any) {
      toast.error(err?.message ?? 'Submission failed');
    } finally {
      setLoading(false); setUploading(false);
