        <DialogHeader>
          <DialogTitle className="text-center">Buy {planName}</DialogTitle>
          <p className="text-center text-sm text-muted-foreground">
            <span className="font-bold text-primary text-base">${priceUsd}</span>
            <span className="text-xs ml-1 text-muted-foreground">≈ ₨{Math.round(priceUsd * usdToPkr).toLocaleString()}</span>
          </p>
        </DialogHeader>

        {step === 'method' ? (
          <div className="space-y-2 mt-2">
            <p className="text-xs text-muted-foreground text-center mb-3">Select your payment method</p>
            {METHODS.map(m => (
              <button key={m.id} onClick={() => { setMethod(m.id); setStep('proof'); }}
                className="w-full flex items-center gap-3 p-3 card-dark rounded-xl hover:border-primary/40 transition-colors text-left group">
                <span className="text-xl">{m.icon}</span>
                <span className={`flex-1 text-sm font-semibold ${m.color}`}>{m.label}</span>
                <ChevronRight size={14} className="text-muted-foreground group-hover:text-primary transition-colors" />
