            <button onClick={() => setStep('method')} className="text-xs text-primary flex items-center gap-1 hover:underline">
              ← Change method
            </button>

            {/* Payment Details Card */}
            <div className="rounded-xl border border-border overflow-hidden">
              <div className={`px-3 py-2 bg-muted/50 border-b border-border flex items-center gap-2`}>
                <span className="text-base">{methodInfo?.icon}</span>
                <p className={`text-sm font-bold ${methodInfo?.color ?? 'text-foreground'}`}>
                  {method} Payment Details
                </p>
