                <div className="space-y-1.5">
                  <Label className="text-xs">TID / Transaction Hash <span className="text-destructive">*</span></Label>
                  <Input placeholder="Transaction ID or Hash..." value={tid} onChange={e => setTid(e.target.value)} className="bg-muted border-border text-sm" />
                </div>
                <div className="space-y-1.5">
                  <Label className="text-xs">Your Sending Number / Address <span className="text-destructive">*</span></Label>
                  <Input placeholder="The number/address you sent from..." value={address} onChange={e => setAddress(e.target.value)} className="bg-muted border-border text-sm" />
                </div>
                <div className="space-y-1.5">
                  <Label className="text-xs">Payment Screenshot <span className="text-destructive">*</span></Label>
                  <div onClick={() => fileRef.current?.click()} className="border-2 border-dashed border-border rounded-xl p-4 text-center cursor-pointer hover:border-primary/40 transition-colors">
                    {screenshot
                      ? <div className="flex items-center justify-center gap-2 text-green-400"><CheckCircle2 size={16} /><span className="text-sm font-medium">{screenshot.name}</span></div>
                      : <div className="flex flex-col items-center gap-1"><Upload size={20} className="text-muted-foreground" /><span className="text-xs text-muted-foreground">Tap to upload screenshot</span></div>}
                  </div>
                  <input ref={fileRef} type="file" accept="image/*" onChange={handleFileChange} className="hidden" />
                </div>
              </>
            )}

            <Button onClick={handleSubmit} disabled={loading || uploading} className="w-full bg-primary text-primary-foreground font-bold glow-gold text-sm">
              {uploading ? '⏫ Uploading...' : loading ? '⏳ Submitting...' : '✅ Submit VIP Request'}
            </Button>
            <p className="text-[10px] text-muted-foreground text-center">
              Your request will be reviewed within 24 hours. VIP status remains Pending until verified.
            </p>
          </div>
        )}
      </DialogContent>
    </Dialog>
  );
}

