                      isConnected ? 'bg-green-500/15 text-green-400 border-green-500/30' :
                      isError ? 'bg-destructive/15 text-destructive border-destructive/30' :
                      'bg-yellow-500/15 text-yellow-400 border-yellow-500/30'
                    }`}>{cfg.status || 'Pending'}</span>
                    {cfg.lastTestedAt && (
                      <p className="text-[8px] text-muted-foreground">
                        {new Date(cfg.lastTestedAt).toLocaleString('en-PK', { month: 'short', day: '2-digit', hour: '2-digit', minute: '2-digit' })}
