                    className="flex-1 h-7 text-[10px] bg-violet-600/20 text-violet-400 border border-violet-500/30 hover:bg-violet-600/30 gap-1">
                    {busy === 'test_' + cfg.id ? <><Loader2 size={9} className="animate-spin" /> Testing...</> : <><Zap size={9} /> Test Connection</>}
