                    <Trash2 size={9} /> Remove
                  </Button>
                </div>
              </div>
            );
          })}
        </div>
      )}

      {/* Architecture Info */}
      <div className="bg-violet-950/20 border border-violet-500/15 rounded-xl px-3 py-2.5 space-y-1 text-[9px] text-muted-foreground">
        <p className="font-bold text-foreground">⚙️ How Multi-DB Routing Works:</p>
        <ul className="space-y-0.5 list-disc pl-4">
          <li>Configs stored in isolated <code className="text-violet-400 font-mono bg-violet-500/10 px-1 rounded">AdminSettings</code> rows — zero mixing with app data</li>
          <li>Firebase & MongoDB Atlas testable via REST API — PostgreSQL via Supabase REST</li>
          <li>MySQL & Oracle require REST API proxy for edge runtime compatibility</li>
