        </ul>
      </div>
    </div>
  );
}

import { useState, useRef } from 'react';
import { Send, Mic, MicOff, Sparkles } from 'lucide-react';
import { useAuth } from 'zite-auth-sdk';
import { useNavigate } from 'react-router-dom';
import { toast } from 'sonner';

interface Props { onSend: (msg: string) => void; loading?: boolean; }

export default function ChatInputBar({ onSend, loading }: Props) {
  const [input, setInput] = useState('');
  const [listening, setListening] = useState(false);
  const { user, loginWithRedirect } = useAuth();
  const navigate = useNavigate();
  const recognitionRef = useRef<any>(null);

  const handleSend = () => {
    const msg = input.trim();
    if (!msg || loading) return;
    setInput('');
    onSend(msg);
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) { e.preventDefault(); handleSend(); }
  };

  // ── Clean STT output: strip *, #, ~, stray symbols ──
  const cleanStt = (text: string): string =>
    text.replace(/[*#~_`^\\|<>{}[\]]/g, '').replace(/\s{2,}/g, ' ').trim();

  const toggleMic = () => {
    const SR = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (!SR) { toast.error('Speech recognition not supported in this browser'); return; }
    if (listening) { recognitionRef.current?.stop(); setListening(false); return; }
    const r = new SR();
    // language: "auto" — do NOT set r.lang so the browser auto-detects
    // the spoken language (Urdu, English, Punjabi, Hindi, Sindhi, etc.)
    r.continuous = true;
    r.interimResults = false;
    r.maxAlternatives = 1;
    r.onresult = (e: any) => {
      const transcript = cleanStt(e.results[e.results.length - 1][0].transcript);
      if (transcript) setInput(prev => prev + (prev ? ' ' : '') + transcript);
    };
    r.onerror = () => { setListening(false); };
    r.onend = () => setListening(false);
    recognitionRef.current = r;
    try { r.start(); setListening(true); } catch { toast.error('Could not start microphone'); }
  };

  const handleMedia = () => {
    if (!user) { loginWithRedirect({ redirectUrl: `${window.location.origin}/media` }); return; }
    navigate('/media');
  };

  return (
    <div className="border-t border-border bg-card/95 backdrop-blur-md p-3">
      <div className="flex items-end gap-2 bg-muted rounded-2xl px-3 py-2 border border-border focus-within:border-primary/50 transition-colors">
        <textarea
          className="flex-1 bg-transparent resize-none text-sm outline-none placeholder:text-muted-foreground min-h-[20px] max-h-32 leading-5 py-1"
          placeholder="Yahan likhein..."
          value={input}
          onChange={e => setInput(e.target.value)}
          onKeyDown={handleKeyDown}
          rows={1}
          disabled={loading}
        />
        <div className="flex items-center gap-1 shrink-0 pb-0.5">
          <button onClick={toggleMic} className={`p-1.5 rounded-xl transition-colors ${listening ? 'text-destructive bg-destructive/10' : 'text-muted-foreground hover:text-foreground'}`} title="Voice input">
            {listening ? <MicOff size={18} /> : <Mic size={18} />}
          </button>
          <button onClick={handleMedia} className="p-1.5 rounded-xl text-secondary hover:text-secondary/80 transition-colors hover:bg-secondary/10" title="AI Media Lab">
            <Sparkles size={18} />
          </button>
          <button
            onClick={handleSend}
            disabled={!input.trim() || loading}
            className="p-1.5 rounded-xl bg-primary text-primary-foreground disabled:opacity-40 transition-opacity hover:bg-primary/90"
          >
            <Send size={16} />
          </button>
        </div>
      </div>
    </div>
  );
}

