  const alertFiredRef = useRef<string>('');
  const phaseRef = useRef<Phase>('hidden');
  phaseRef.current = phase;

  // Recalculate prayer times every 30s
  useEffect(() => {
    if (!coords) return;
    const calc = () => {
      const now = new Date();
      const tzOffset = -now.getTimezoneOffset() / 60;
      setSchedule(calculatePrayerTimes(coords.lat, coords.lon, now, tzOffset));
    };
    calc();
    const id = setInterval(calc, 30000);
    return () => clearInterval(id);
  }, [coords]);

  // Check 5-min trigger
  useEffect(() => {
    if (!schedule) return;
    const check = () => {
      if (!schedule.nextPrayer) return;
      const now = Date.now();
      const prayerTime = schedule.nextPrayer.time.getTime();
      const diffMin = (prayerTime - now) / 60000;
      const alertKey = `${schedule.nextPrayer.name}-${schedule.nextPrayer.time.toISOString().slice(0, 16)}`;

      if (diffMin <= 5 && diffMin > -2 && alertFiredRef.current !== alertKey && phaseRef.current === 'hidden') {
        alertFiredRef.current = alertKey;
        setActivePrayer(schedule.nextPrayer.name);
        setShowSlimRow(true);
        setVisible(true);
        setPhase('bismillah');
      }
    };
    check();
    const id = setInterval(check, 10000);
    return () => clearInterval(id);
  }, [schedule]);

  // Sequential audio phase player
  const playPhase = useCallback((p: Phase) => {
    if (muted || p === 'hidden' || p === 'done') {
      if (p === 'done') {
        setTimeout(() => {
          setVisible(false);
          setShowSlimRow(false);
          setPhase('hidden');
        }, 3000);
      }
      return;
    }

    setIsSpeaking(true);
    let text = '';
    let ttsLang = lang === 'ur' ? 'ar-SA' : 'en-US';

    switch (p) {
      case 'bismillah': text = lang === 'ur' ? BISMILLAH_AR : BISMILLAH_EN; break;
      case 'durood':    text = lang === 'ur' ? DUROOD_AR : DUROOD_EN; break;
      case 'azan':      text = lang === 'ur' ? AZAN_TEXT_AR : AZAN_TEXT_EN; break;
      case 'dua':       text = lang === 'ur' ? POST_AZAN_DUA_AR : POST_AZAN_DUA_EN; break;
      case 'blessing':
        text = lang === 'ur'
          ? `اللہ تعالیٰ آپ کی ${activePrayer} کی نماز قبول فرمائیں۔ آمین`
          : `May Allah accept your ${activePrayer} prayer. Ameen.`;
        ttsLang = lang === 'ur' ? 'ur-PK' : 'en-US';
        break;
    }

    speakText(text, ttsLang, () => {
      setIsSpeaking(false);
      const sequence: Phase[] = ['bismillah', 'durood', 'azan', 'dua', 'blessing', 'done'];
      const idx = sequence.indexOf(p);
      if (idx >= 0 && idx < sequence.length - 1) {
        setTimeout(() => setPhase(sequence[idx + 1]), 800);
      }
    });
  }, [muted, lang, activePrayer]);

  useEffect(() => {
    if (phase !== 'hidden') playPhase(phase);
  }, [phase, playPhase]);

  const handleDismiss = () => {
    stopTTS();
    setIsSpeaking(false);
    setVisible(false);
    setShowSlimRow(false);
    setPhase('hidden');
  };

  const toggleMute = () => {
    if (isSpeaking) stopTTS();
    setMuted(m => !m);
    setIsSpeaking(false);
  };

  // ══════════════════════════════════════════════════════════════
  // 100% HIDDEN when not active — returns nothing
  // ══════════════════════════════════════════════════════════════
  if (!showSlimRow && !visible) return null;

  // ── Ultra-slim prayer row (only visible during 5-min window) ──
  const slimRow = schedule ? (
    <div className="shrink-0 bg-primary/5 border-b border-primary/20 flex items-center gap-1 px-2 overflow-x-auto scrollbar-hide select-none animate-in slide-in-from-top-1 duration-300" style={{ height: '20px' }}>
      <span className="text-[7px] font-black text-primary shrink-0">🕌</span>
      {[schedule.fajr, schedule.dhuhr, schedule.asr, schedule.maghrib, schedule.isha, schedule.tahajjud].map(p => {
        const isNext = schedule.nextPrayer?.name === p.name;
        const timeStr = `${p.hours % 12 || 12}:${String(p.minutes).padStart(2, '0')}`;
        return (
          <span
            key={p.name}
            className={`text-[7px] font-mono shrink-0 px-1 rounded ${isNext ? 'bg-primary/20 text-primary font-black' : 'text-muted-foreground/70'}`}
          >
            {p.nameUr} {timeStr}
          </span>
        );
      })}
      {schedule.nextPrayer && schedule.minutesUntilNext > 0 && (
        <span className="text-[7px] font-black text-secondary shrink-0 ml-auto">
          ⏱{schedule.minutesUntilNext > 60 ? `${Math.floor(schedule.minutesUntilNext / 60)}h${schedule.minutesUntilNext % 60}m` : `${schedule.minutesUntilNext}m`}
        </span>
      )}
      {isSpeaking && (
        <span className="flex items-center gap-px shrink-0 ml-1">
          {[1,2,3,4,5].map(i => (
            <span key={i} className="w-[2px] bg-primary rounded-full" style={{ height: `${4 + Math.random() * 6}px`, animation: `prayer-wave 0.5s ${i * 0.08}s ease-in-out infinite alternate` }} />
          ))}
        </span>
      )}
    </div>
  ) : null;

  const phaseInfo = PHASE_LABELS[phase];

  return (
    <>
      {/* Ultra-slim top row */}
      {slimRow}

      {/* Full overlay when audio is playing */}
      {visible && phase !== 'hidden' && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-background/85 backdrop-blur-xl animate-in fade-in duration-500">
          <div className="w-full max-w-sm mx-4 bg-card border border-primary/30 rounded-3xl shadow-2xl overflow-hidden">
            <div className="bg-primary/10 border-b border-primary/20 px-5 py-4 flex items-center justify-between">
              <div className="flex items-center gap-3">
                <div className="w-10 h-10 rounded-2xl bg-primary/20 flex items-center justify-center text-lg">🕌</div>
                <div>
                  <p className="text-sm font-black text-foreground">{activePrayer} Prayer Alert</p>
                  <p className="text-[10px] text-muted-foreground">
                    {lang === 'ur' ? `${activePrayer} کی نماز کا وقت` : `Time for ${activePrayer} prayer`}
                  </p>
                </div>
              </div>
              <button onClick={handleDismiss} className="p-2 rounded-full hover:bg-muted transition-colors">
                <X size={18} className="text-muted-foreground" />
              </button>
            </div>

            <div className="px-5 py-6 text-center space-y-4">
              <div className="text-4xl">{phaseInfo.icon}</div>
              <div>
                <p className="text-lg font-black text-foreground">{phaseInfo.en}</p>
                <p className="text-base font-bold text-primary/80 mt-1" dir="rtl">{phaseInfo.ur}</p>
              </div>

              {isSpeaking && (
                <div className="flex items-center justify-center gap-1 h-8">
                  {Array.from({ length: 12 }).map((_, i) => (
                    <div
                      key={i}
                      className="w-1 bg-primary rounded-full"
                      style={{
                        height: `${12 + Math.random() * 20}px`,
                        animation: `prayer-wave 0.6s ${i * 0.05}s ease-in-out infinite alternate`,
                      }}
                    />
                  ))}
                </div>
              )}

              <div className="flex items-center gap-1 justify-center">
                {['bismillah', 'durood', 'azan', 'dua', 'blessing'].map((p, i) => (
                  <div
                    key={p}
                    className={`h-1.5 rounded-full transition-all duration-500 ${
                      phase === p ? 'w-8 bg-primary' :
                      ['bismillah', 'durood', 'azan', 'dua', 'blessing'].indexOf(phase) > i ? 'w-4 bg-primary/50' :
                      'w-4 bg-muted'
                    }`}
                  />
                ))}
              </div>
            </div>

            <div className="px-5 pb-5 flex items-center gap-3">
              <button
                onClick={toggleMute}
                className={`flex-1 flex items-center justify-center gap-2 py-2.5 rounded-xl text-sm font-bold transition-all ${
                  muted ? 'bg-muted text-muted-foreground' : 'bg-primary/10 text-primary border border-primary/20'
                }`}
              >
                {muted ? <VolumeX size={16} /> : <Volume2 size={16} />}
                {muted ? 'Unmute' : 'Audio On'}
              </button>
              <button
                onClick={handleDismiss}
                className="flex-1 py-2.5 rounded-xl text-sm font-bold bg-muted text-muted-foreground hover:text-foreground transition-colors"
              >
                Dismiss
              </button>
            </div>
          </div>
        </div>
      )}
    </>
  );
}

