// MULTI-LINGUAL TTS VOICE BUTTON
// Reusable component — drops in anywhere text needs to be spoken
// Supports: English, Urdu (اردو), Arabic (عربي), Hindi, Punjabi
// ══════════════════════════════════════════════════════════════════
import { useState, useCallback, useRef } from 'react';
import { Volume2, VolumeX, Loader2, ChevronDown } from 'lucide-react';
import {
  speakText, stopTTS, detectLangFromText, ttsClean, isTTSSupported,
  TTSLanguage, TTS_LANGUAGE_LABELS,
} from '@/lib/tts';

interface Props {
  text: string;
  /** Optional forced language. If omitted, auto-detects from text */
  lang?: TTSLanguage;
  /** Show language selector dropdown */
  showLangSelector?: boolean;
  /** Button size variant */
  size?: 'sm' | 'md' | 'lg';
  className?: string;
  /** Called when speech starts */
  onStart?: () => void;
  /** Called when speech ends */
  onEnd?: () => void;
}

const LANGUAGES: TTSLanguage[] = ['en-US', 'ur-PK', 'ar-SA', 'hi-IN'];

export default function MultiLingualTTSButton({
  text,
  lang,
  showLangSelector = false,
  size = 'md',
  className = '',
  onStart,
  onEnd,
}: Props) {
  const [playing, setPlaying] = useState(false);
  const [preparing, setPreparing] = useState(false);
  const [showLangs, setShowLangs] = useState(false);
  const [manualLang, setManualLang] = useState<TTSLanguage | null>(null);
  const idRef = useRef(Math.random().toString(36));

  const activeLang = manualLang ?? lang ?? detectLangFromText(text);
  const langMeta = TTS_LANGUAGE_LABELS[activeLang];

  const handleSpeak = useCallback(() => {
    if (!isTTSSupported()) return;

    if (playing) {
      stopTTS();
      setPlaying(false);
      setPreparing(false);
      return;
    }

    const clean = ttsClean(text);
    if (!clean.trim()) return;

    setPreparing(true);
    speakText(
      clean,
      activeLang,
      () => { setPlaying(false); setPreparing(false); onEnd?.(); },
      () => { setPlaying(true); setPreparing(false); onStart?.(); },
    );
  }, [playing, text, activeLang, onStart, onEnd]);

  const sizeClass = size === 'sm'
    ? 'w-7 h-7 text-[10px]'
    : size === 'lg'
    ? 'w-11 h-11 text-sm'
    : 'w-9 h-9 text-xs';

  if (!isTTSSupported()) return null;

  return (
    <div className={`relative inline-flex items-center gap-1 ${className}`}>
      {/* Main play/stop button */}
      <button
        onClick={handleSpeak}
        title={playing ? 'Stop voice' : `Listen in ${langMeta.label}`}
        className={`${sizeClass} rounded-xl flex items-center justify-center transition-all border
          ${playing
            ? 'bg-primary text-primary-foreground border-primary shadow-lg shadow-primary/25 scale-105'
            : 'bg-muted/80 text-muted-foreground border-border hover:bg-primary/15 hover:text-primary hover:border-primary/40'
          }`}
      >
        {preparing ? (
          <Loader2 size={size === 'sm' ? 11 : size === 'lg' ? 17 : 14} className="animate-spin" />
        ) : playing ? (
          <VolumeX size={size === 'sm' ? 11 : size === 'lg' ? 17 : 14} />
        ) : (
          <Volume2 size={size === 'sm' ? 11 : size === 'lg' ? 17 : 14} />
        )}
      </button>

      {/* Language selector toggle */}
      {showLangSelector && (
        <button
          onClick={() => setShowLangs(v => !v)}
          className="flex items-center gap-0.5 text-[9px] text-muted-foreground hover:text-primary transition-colors px-1 py-0.5 rounded bg-muted/50 border border-border"
        >
          <span>{langMeta.flag}</span>
          <ChevronDown size={8} className={`transition-transform ${showLangs ? 'rotate-180' : ''}`} />
        </button>
      )}

      {/* Language dropdown */}
      {showLangSelector && showLangs && (
        <div className="absolute top-full left-0 mt-1 z-50 bg-card border border-border rounded-xl shadow-lg overflow-hidden min-w-[140px]">
          {LANGUAGES.map(l => {
            const meta = TTS_LANGUAGE_LABELS[l];
            return (
              <button
                key={l}
                onClick={() => { setManualLang(l); setShowLangs(false); }}
                className={`w-full flex items-center gap-2 px-3 py-2 text-xs text-left hover:bg-muted/60 transition-colors
                  ${activeLang === l ? 'bg-primary/10 text-primary font-semibold' : 'text-foreground'}`}
              >
                <span>{meta.flag}</span>
                <span>{meta.label}</span>
                <span className="text-muted-foreground ml-auto">{meta.native}</span>
              </button>
            );
          })}
          {manualLang && (
            <button
              onClick={() => { setManualLang(null); setShowLangs(false); }}
              className="w-full px-3 py-1.5 text-[10px] text-muted-foreground hover:text-primary text-center border-t border-border"
            >
              ↺ Auto-detect
            </button>
          )}
        </div>
      )}

      {/* Playing wave indicator */}
      {playing && (
        <span className="flex gap-0.5 items-end h-4">
          {[0, 1, 2].map(i => (
            <span
              key={i}
              className="w-0.5 bg-primary rounded-full animate-pulse"
              style={{
                height: `${8 + i * 3}px`,
                animationDelay: `${i * 150}ms`,
                animationDuration: '600ms',
              }}
            />
          ))}
        </span>
      )}
    </div>
  );
}

