// BOX 2: Referral Coin Exchange Engine
// ریفرل کوائن آٹو ایکسچینج ٹائم باکس
// Isolated admin card — manual & timed coin→USD conversion
// ══════════════════════════════════════════════════════════════════
import { useState, useEffect, useCallback } from 'react';
import { coinExchange } from 'zite-endpoints-sdk';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Skeleton } from '@/components/ui/skeleton';
import { toast } from 'sonner';
import {
  Coins, Timer, Zap, Loader2, Check, RefreshCw,
  ArrowRightLeft, Clock, DollarSign, Users, AlertTriangle,
} from 'lucide-react';

const HOUR_PRESETS = [1, 2, 6, 12, 24, 48, 72, 168];
const HOUR_LABELS: Record<number, string> = {
  1: '1 Hour', 2: '2 Hours', 6: '6 Hours', 12: '12 Hours',
  24: '24 Hours', 48: '2 Days', 72: '3 Days', 168: '7 Days',
};

export default function CoinExchangeCard({ token }: { token: string }) {
  const [intervalHours, setIntervalHours] = useState(24);
  const [customInterval, setCustomInterval] = useState('');
  const [coinRate, setCoinRate] = useState(1000);
  const [lastRun, setLastRun] = useState('');
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [converting, setConverting] = useState(false);
  const [stats, setStats] = useState<{ totalUsersProcessed: number; totalCoinsConverted: number; totalUsdCredited: number } | null>(null);
  const [conversionResult, setConversionResult] = useState<string | null>(null);

  const load = useCallback(async () => {
    setLoading(true);
    try {
      const [cfg, statsRes] = await Promise.all([
        coinExchange({ action: 'get_config' }),
        coinExchange({ action: 'get_stats', adminToken: token }),
      ]);
      setIntervalHours(cfg.intervalHours ?? 24);
      setLastRun(cfg.lastConvertedAt ?? '');
      setCoinRate(cfg.coinRate ?? 1000);
      if (statsRes.stats) setStats(statsRes.stats);
    } catch (e: any) { toast.error(e?.message ?? 'Failed to load'); }
    finally { setLoading(false); }
  }, [token]);

  useEffect(() => { load(); }, [load]);

  const saveInterval = async (hours?: number) => {
    const h = hours ?? (customInterval ? parseInt(customInterval) : intervalHours);
    if (!h || h < 1 || h > 720) { toast.error('Enter 1-720 hours'); return; }
    setSaving(true);
    try {
      await coinExchange({ action: 'save_interval', adminToken: token, intervalHours: h });
      setIntervalHours(h);
      setCustomInterval('');
      toast.success(`✅ Interval set to ${h} hours`);
    } catch (e: any) { toast.error(e?.message); }
    finally { setSaving(false); }
  };

  const forceConvert = async () => {
    setConverting(true);
    setConversionResult(null);
    try {
      const r = await coinExchange({ action: 'force_convert', adminToken: token });
      setConversionResult(r.message ?? 'Conversion complete');
      if (r.stats) setStats(r.stats);
      if (r.lastConvertedAt) setLastRun(r.lastConvertedAt);
      toast.success(r.message ?? '✅ Coins converted!');
    } catch (e: any) { toast.error(e?.message); }
    finally { setConverting(false); }
  };

  // Calculate next run time
  const nextRunTime = lastRun
    ? new Date(new Date(lastRun).getTime() + intervalHours * 3600000).toLocaleString('en-PK', {
        month: 'short', day: '2-digit', hour: '2-digit', minute: '2-digit',
      })
    : 'Not scheduled yet';

  if (loading) return <Skeleton className="h-64 rounded-2xl" />;

  return (
    <div className="rounded-2xl border-2 border-amber-500/30 bg-amber-950/10 p-4 space-y-4">
      {/* Header */}
      <div className="flex items-center gap-3">
        <div className="w-10 h-10 rounded-xl bg-amber-500/15 border border-amber-500/30 flex items-center justify-center shrink-0">
          <ArrowRightLeft size={20} className="text-amber-400" />
        </div>
        <div className="flex-1 min-w-0">
          <p className="font-black text-sm">💰 Referral Coin Exchange Engine</p>
          <p className="text-[10px] text-muted-foreground">ریفرل کوائن آٹو ایکسچینج — Coins → USD Conversion</p>
        </div>
        <button onClick={load} className="shrink-0 text-muted-foreground hover:text-foreground p-1"><RefreshCw size={12} /></button>
      </div>

      {/* Live Stats Dashboard */}
      <div className="grid grid-cols-3 gap-2">
        <div className="bg-card border border-border rounded-xl p-2.5 text-center">
          <div className="flex items-center justify-center gap-1 mb-1">
            <Users size={10} className="text-primary" />
          </div>
          <p className="text-sm font-black text-primary">{stats?.totalUsersProcessed ?? 0}</p>
          <p className="text-[8px] text-muted-foreground">Users w/ Coins</p>
        </div>
        <div className="bg-card border border-border rounded-xl p-2.5 text-center">
          <div className="flex items-center justify-center gap-1 mb-1">
            <Coins size={10} className="text-amber-400" />
          </div>
          <p className="text-sm font-black text-amber-400">{(stats?.totalCoinsConverted ?? 0).toLocaleString()}</p>
          <p className="text-[8px] text-muted-foreground">Pending Coins</p>
        </div>
        <div className="bg-card border border-border rounded-xl p-2.5 text-center">
          <div className="flex items-center justify-center gap-1 mb-1">
            <DollarSign size={10} className="text-green-400" />
          </div>
          <p className="text-sm font-black text-green-400">${(stats?.totalUsdCredited ?? 0).toFixed(4)}</p>
          <p className="text-[8px] text-muted-foreground">≈ USD Value</p>
        </div>
      </div>

      {/* Exchange Rate Info */}
      <div className="bg-amber-500/5 border border-amber-500/15 rounded-xl px-3 py-2 flex items-center justify-between">
        <div className="flex items-center gap-2">
          <span className="text-sm">🔄</span>
          <div>
            <p className="text-[10px] font-bold text-foreground">Exchange Rate</p>
            <p className="text-[9px] text-muted-foreground">{coinRate.toLocaleString()} coins = $1.00 USD</p>
          </div>
        </div>
        <div className="text-right">
          <p className="text-[10px] font-bold text-foreground">Current Interval</p>
          <p className="text-[9px] text-amber-400 font-bold">{HOUR_LABELS[intervalHours] ?? `${intervalHours}h`}</p>
        </div>
      </div>

      {/* Interval Timer Setter */}
      <div className="space-y-2.5">
        <div className="flex items-center gap-2">
          <Timer size={12} className="text-amber-400" />
          <p className="text-xs font-bold">Auto-Convert Interval (In Hours)</p>
        </div>

        {/* Quick Presets */}
        <div className="grid grid-cols-4 gap-1.5">
          {HOUR_PRESETS.map(h => (
            <button key={h} onClick={() => { setIntervalHours(h); saveInterval(h); }}
              className={`rounded-lg py-2 text-[10px] font-bold border transition-all text-center ${
                intervalHours === h
                  ? 'bg-amber-500/20 text-amber-400 border-amber-500/40'
                  : 'border-border text-muted-foreground hover:border-amber-500/30 hover:text-amber-300'
              }`}>
              {HOUR_LABELS[h]}
            </button>
          ))}
        </div>

        {/* Custom Input */}
        <div className="flex gap-2">
          <Input value={customInterval}
            onChange={e => setCustomInterval(e.target.value)}
            placeholder="Custom hours (1-720)..."
            type="number" min={1} max={720}
            className="bg-muted border-border text-xs h-8 font-mono flex-1" />
          <Button size="sm" onClick={() => saveInterval()} disabled={saving || !customInterval}
            className="h-8 px-3 text-xs bg-amber-600/20 text-amber-400 border border-amber-500/30 hover:bg-amber-600/30 font-bold gap-1">
            {saving ? <Loader2 size={10} className="animate-spin" /> : <Check size={10} />}
            Set
          </Button>
        </div>
      </div>

      {/* Schedule Status */}
      <div className="bg-card border border-border rounded-xl px-3 py-2.5 space-y-1.5">
        <div className="flex items-center justify-between">
          <div className="flex items-center gap-2">
            <Clock size={10} className="text-amber-400" />
            <p className="text-[10px] font-bold">Schedule Status</p>
          </div>
          <span className="text-[9px] font-bold bg-amber-500/15 text-amber-400 border border-amber-500/30 px-2 py-0.5 rounded-full">
            Every {intervalHours}h
          </span>
        </div>
        <div className="grid grid-cols-2 gap-2 text-[10px]">
          <div>
            <p className="text-muted-foreground">Last Conversion:</p>
            <p className="font-bold text-foreground">
              {lastRun ? new Date(lastRun).toLocaleString('en-PK', {
                month: 'short', day: '2-digit', hour: '2-digit', minute: '2-digit',
              }) : 'Never'}
            </p>
          </div>
          <div>
            <p className="text-muted-foreground">Next Scheduled:</p>
            <p className="font-bold text-amber-400">{nextRunTime}</p>
          </div>
        </div>

        {/* Upgrade notice */}
        <div className="bg-amber-500/5 border border-amber-500/15 rounded-lg px-2.5 py-2 text-[9px] text-amber-300 flex items-start gap-1.5 mt-1">
          <AlertTriangle size={10} className="shrink-0 mt-0.5" />
          <span>Auto-scheduling requires a Business plan upgrade. Use the <strong>"Force Convert"</strong> button below to convert manually at any time.</span>
        </div>
      </div>

      {/* Force Convert Button */}
      <Button onClick={forceConvert} disabled={converting}
        className="w-full h-11 bg-gradient-to-r from-amber-600 to-amber-700 hover:from-amber-500 hover:to-amber-600 text-white font-black text-sm gap-2 rounded-xl">
        {converting ? (
          <><Loader2 size={15} className="animate-spin" /> Converting All Pending Coins...</>
        ) : (
          <><Zap size={15} /> ⚡ Force Convert Pending Coins Now</>
        )}
      </Button>

      {/* Conversion Result */}
      {conversionResult && (
        <div className="bg-green-500/10 border border-green-500/25 rounded-xl px-3 py-3 text-center animate-in fade-in duration-300">
          <p className="text-sm font-black text-green-400">{conversionResult}</p>
          {stats && (
            <div className="grid grid-cols-3 gap-2 mt-2">
              <div className="text-center">
                <p className="text-xs font-black text-primary">{stats.totalUsersProcessed}</p>
                <p className="text-[8px] text-muted-foreground">Users</p>
              </div>
              <div className="text-center">
                <p className="text-xs font-black text-amber-400">{stats.totalCoinsConverted.toLocaleString()}</p>
                <p className="text-[8px] text-muted-foreground">Coins</p>
              </div>
              <div className="text-center">
                <p className="text-xs font-black text-green-400">${stats.totalUsdCredited.toFixed(4)}</p>
                <p className="text-[8px] text-muted-foreground">USD</p>
              </div>
            </div>
          )}
        </div>
      )}

