// ══════════════════════════════════════════════════════════════════
// Islamic TTS hook — uses the unified Multi-Lingual TTS engine
// Auto-detects Urdu / Arabic from message content
// ══════════════════════════════════════════════════════════════════
import { useState, useCallback } from 'react';
import { speakText, stopTTS, detectLangFromText, ttsClean } from '@/lib/tts';

export interface IslamicTTSState {
  isPlaying: boolean;
  isPreparing: boolean;
  activeId: string | null;
  speak: (text: string, id: string) => void;
  stop: () => void;
}

export function useIslamicTTS(): IslamicTTSState {
  const [isPlaying, setIsPlaying] = useState(false);
  const [isPreparing, setIsPreparing] = useState(false);
  const [activeId, setActiveId] = useState<string | null>(null);

  const stop = useCallback(() => {
    stopTTS();
    setIsPlaying(false);
    setIsPreparing(false);
    setActiveId(null);
  }, []);

  const speak = useCallback((text: string, id: string) => {
    if (!('speechSynthesis' in window)) return;

    // Toggle: stop if same message is playing
    if (activeId === id && (isPlaying || isPreparing)) { stop(); return; }

    stop();
    setIsPreparing(true);
    setActiveId(id);

    const cleaned = ttsClean(text);
    if (!cleaned.trim()) { setIsPreparing(false); setActiveId(null); return; }

    // Auto-detect Urdu vs Arabic from text content
    const lang = detectLangFromText(text);

    speakText(
      cleaned,
      lang,
      () => { setIsPlaying(false); setIsPreparing(false); setActiveId(null); },
      () => { setIsPlaying(true); setIsPreparing(false); },
    );
  }, [activeId, isPlaying, isPreparing, stop]);

  return { isPlaying, isPreparing, activeId, speak, stop };
}

