        <div className="flex items-center gap-2 bg-primary/5 border border-primary/20 rounded-xl px-3 py-2">
          <Info size={12} className="text-primary shrink-0" />
          <p className="text-[11px] text-muted-foreground">
            Minimum withdrawal: <span className="text-primary font-bold">${minUsd.toFixed(2)}</span>
            {' '}· 1,000 Coins = $1 USD
          </p>
        </div>

        {!canWithdraw ? (
          <div className="text-center py-4 space-y-2">
            <p className="text-sm text-muted-foreground">
              You need at least <span className="text-primary font-bold">${minUsd.toFixed(2)}</span> to withdraw.
            </p>
            <p className="text-xs text-muted-foreground">Keep earning through referrals to reach the minimum!</p>
