        <Clock size={12} className="text-white/80 shrink-0 mt-0.5 animate-pulse" />
        <div className="flex-1">
          <p className="text-[9px] text-white/60 uppercase tracking-wide font-semibold mb-1">Post Timestamp</p>
          <LiveClock />
