// ── Hijri calculator (client-side) ───────────────────────────────
function toHijri(date: Date): string {
  const JD = Math.floor((date.getTime() / 86400000) + 2440587.5);
  let l = JD - 1948440 + 10632;
  const n = Math.floor((l - 1) / 10631);
  l = l - 10631 * n + 354;
  const j = Math.floor((10985 - l) / 5316) * Math.floor(50 * l / 17719)
    + Math.floor(l / 5670) * Math.floor(43 * l / 15238);
  l = l - Math.floor((30 - j) / 15) * Math.floor(17719 * j / 50)
    - Math.floor(j / 16) * Math.floor(15238 * j / 43) + 29;
  const month = Math.floor(24 * l / 709);
  const day = l - Math.floor(709 * month / 24);
  const year = 30 * n + j - 30;
  const MONTHS = [
    'محرم','صفر','ربیع الاول','ربیع الثانی','جمادی الاولیٰ','جمادی الثانیہ',
    'رجب','شعبان','رمضان','شوال','ذوالقعدہ','ذوالحجہ'
  ];
  return `${day} ${MONTHS[Math.min(Math.max(month - 1, 0), 11)]} ${year} ہجری`;
}

// ── Image compression ──────────────────────────────────────────────
async function compressToBase64(file: File): Promise<string> {
  return new Promise(resolve => {
    const canvas = document.createElement('canvas');
    const img = new Image();
    img.onload = () => {
      const MAX = 700;
      const scale = Math.min(1, MAX / Math.max(img.width, img.height));
      canvas.width = Math.round(img.width * scale);
      canvas.height = Math.round(img.height * scale);
      canvas.getContext('2d')!.drawImage(img, 0, 0, canvas.width, canvas.height);
      resolve(canvas.toDataURL('image/jpeg', 0.80).split(',')[1]);
    };
    img.src = URL.createObjectURL(file);
  });
}

