// ── Hijri calculator (client-side) ─────────────────────────────
function toHijri(date: Date): string {
  const JD = Math.floor((date.getTime() / 86400000) + 2440587.5);
  let l = JD - 1948440 + 10632;
  const n = Math.floor((l - 1) / 10631);
  l = l - 10631 * n + 354;
  const j = Math.floor((10985 - l) / 5316) * Math.floor(50 * l / 17719)
    + Math.floor(l / 5670) * Math.floor(43 * l / 15238);
  l = l - Math.floor((30 - j) / 15) * Math.floor(17719 * j / 50)
    - Math.floor(j / 16) * Math.floor(15238 * j / 43) + 29;
  const month = Math.floor(24 * l / 709);
  const day = l - Math.floor(709 * month / 24);
  const year = 30 * n + j - 30;
  const MONTHS = [
    'محرم','صفر','ربیع الاول','ربیع الثانی','جمادی الاولیٰ','جمادی الثانیہ',
    'رجب','شعبان','رمضان','شوال','ذوالقعدہ','ذوالحجہ'
  ];
  return `${day} ${MONTHS[Math.min(Math.max(month - 1, 0), 11)]} ${year} ہجری`;
}

// ── Live Context Header Block ─────────────────────────────────────
function LiveContextBar({ locationCtx }: { locationCtx: string }) {
  const [now, setNow] = useState(() => new Date());
  useEffect(() => {
    const t = setInterval(() => setNow(new Date()), 30_000);
    return () => clearInterval(t);
  }, []);

  const userTz = Intl.DateTimeFormat().resolvedOptions().timeZone;
  const gregorian = now.toLocaleDateString('ur-PK', {
    weekday: 'long', month: 'long', day: 'numeric', year: 'numeric',
    timeZone: userTz,
  });
  const timeStr = now.toLocaleTimeString('ur-PK', {
    hour: '2-digit', minute: '2-digit', hour12: true, timeZone: userTz,
  });
  const hijri = toHijri(now);
  const loc = locationCtx || 'پاکستان';

  return (
    <div className="shrink-0 px-3 py-2 bg-emerald-950/40 border-b border-emerald-900/20">
      {/* Row 1: Date + Time */}
      <div className="flex items-center justify-between gap-2">
