          <Sparkles size={8} className="text-emerald-400" />
          <span className="text-[8px] text-emerald-500/60 truncate">باریک تجزیہ • 1,24,000 انبیاء</span>
        </div>
      </div>
      {/* Row 2: Hijri + Location */}
