          {message.content}
        </div>

        {/* Action buttons — assistant only */}
        {!isUser && (
          <div className="flex items-center gap-2 px-1 flex-wrap">
            {/* ── AUDIO PLAY BUTTON — HIGH-FIDELITY, PROMINENT ── */}
            <Button
              size="sm"
              variant="ghost"
              className={`h-10 px-4 gap-2 text-sm font-bold rounded-xl border transition-all active:scale-95 ${
                isThisPlaying
                  ? 'bg-emerald-500/20 text-emerald-400 border-emerald-500/40 shadow-emerald-500/20 shadow-md'
                  : isThisPreparing
                  ? 'bg-emerald-900/30 text-emerald-500 border-emerald-700/40'
                  : 'text-emerald-500 border-emerald-700/30 bg-emerald-950/30 hover:bg-emerald-900/40 hover:border-emerald-600/40 hover:text-emerald-300'
              }`}
              onClick={() => tts.speak(message.content, message.id)}
              disabled={isThisPreparing}
